REPLACE INTO `master_data_barang` (`id_data_barang`, `id_subjenis_barang`, `id_satuan`, `kode_data_barang`, `nama_barang`, `deskripsi`, `upload_foto`, `foto_barang`, `created_at`, `updated_at`) VALUES
	(1, 1, 1, '132050101001', 'Mesin Ketik Manual Portable (11-13 Inci)', 'Alat elektronik dengan sebuah set tombol-tombol yang, apabila ditekan, menyebabkan huruf dicetak pada dokumen, biasanya kertas. dengan ukuran 11-13 inch', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(2, 1, 1, '132050101002', 'Mesin Ketik Manual Standard (14-16 Inci)', 'Mesin tik manual yaitu mesin tik yang cara kerjanya sepenuhnya manual dengan tenaga manusia dengan  ukuran 14-16 inch', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(3, 1, 1, '132050101003', 'Mesin Ketik Manual Langewagon (18-27 Inci)', 'Mesin tik atau mesin ketik adalah mesin, atau alat elektronik dengan sebuah set tombol-tombol yang, apabila ditekan, menyebabkan huruf dicetak pada dokumen, biasanya kertas.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(4, 1, 1, '132050101004', 'Mesin Ketik Listrik', 'Mesin ketik yang ditenagai oleh listrik, yang membedakannya dari mesin ketik manual yang ditenagai oleh tangan pengguna. Mesin ketik listrik umumnya digunakan pada era sebelum komputer pribadi dan penggunaan umum komputer.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(5, 1, 1, '132050101005', 'Mesin Ketik Listrik Potable (11-13 Inci)', 'Mesin ketik yang sistem kerjanya secara elektronis dan menggunakan daya atau sumber arus listrik. Mesin tik elektronik ini disebut juga electronic typewriter , dimana mesin ini mempunyai keistimewaan dan dapat meningkatkan produktifitas dari pengerjaan pengetikan, mesin ketik ini berukuran 11-13 Inci', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(6, 1, 1, '132050101006', 'Mesin Ketik Listrik Standard (14-16 Inci)', 'Mesin ketik yang sistem kerjanya secara elektronis dan menggunakan daya atau sumber arus listrik. Mesin tik elektronik ini disebut juga electronic typewriter , dimana mesin ini mempunyai keistimewaan dan dapat meningkatkan produktifitas dari pengerjaan pengetikan, mesin ketik ini berukuran 14-16 Inci', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(7, 1, 1, '132050101007', 'Mesin Ketik Listrik Langewagon (18-27 Inci)', 'Mesin ketik yang sistem kerjanya secara elektronis dan menggunakan daya atau sumber arus listrik. Mesin tik elektronik ini disebut juga electronic typewriter , dimana mesin ini mempunyai keistimewaan dan dapat meningkatkan produktifitas dari pengerjaan pengetikan, mesin ketik ini berukuran 18 - 27 Inci', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(8, 1, 1, '132050101008', 'Mesin Ketik Elektronik/Selektrik', 'Mesin yang saat digunakan menggunakan listrik. Dan pada saat salah dalam penulisan atau pengetikan dapat dihapus.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(9, 1, 1, '132050101009', 'Mesin Ketik Braille', 'Mesin ketik ini dipakai penyandang disabilitas yang berfungsi untuk membuat huruf braille', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(10, 1, 1, '132050101011', 'Mesin Cetak Stereo Piper (Braille)', 'Mesin cetak braille dengan fitur voice untuk penyandang disabilitas. Memiliki fitur voice pada tombol mesin cetak braille, daya rendah (hemat energi), suku cadang dan komponen lokal, kemudahan dalam mengoperasikan dan pemeliharaan, mudah dioperasikan oleh TUNANETRA dan dilengkapi software terkini (up to date) yang kompatible dengan sistem operasi modern.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(11, 1, 1, '132050102001', 'Mesin Hitung Manual', 'Mesin yang dapat menghitung perkalian yang sederhana tetapi cara menghitung seperti penjumlahan sehingga untuk mencapai hasilnya relatif lama', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(12, 1, 1, '132050102002', 'Mesin Hitung Listrik', 'Mesin yang membantu untuk menghitung uang kertas dan logam dengan akurat sehingga bisa mengurangi resiko salah hitung', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(13, 1, 1, '132050102003', 'Mesin Hitung Elektronik/Calculator', 'Alat elektronik yang digunakan untuk melakukan perhitungan dasar', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(14, 1, 1, '132050102004', 'Mesin Kas Register', 'Mesin kasir atau mesin daftar tunai (bahasa Inggris: cash register) merupakan sebuah perangkat mekanik atau elektronik untuk menghitung dan menghimpun transaksi penjualan serta dilengkapi laci tunai untuk menyimpan uang. Selain itu, ia juga mencetak bukti pembayaran kepada pelanggan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(15, 1, 1, '132050102005', 'Abakus (Alat Hitung)', 'Alat bantu sederhana yang digunakan untuk melakukan peroses berhitung', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(16, 1, 1, '132050102006', 'Blokycs (Mesin Hitung Braille)', 'Alat bantu sederhana yang digunakan untuk melakukan peroses berhitung khusus penyandang disabilitas tuna netra', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(17, 1, 1, '132050102007', 'Mesin Penghitung Uang', 'alat bantu yang digunakan untuk menghitung jumlah uang kertas', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(18, 1, 1, '132050102008', 'Mesin Pembukuan', 'Mesin untuk membukukan rekening dengan cara memasukkan angka, baik secara manual maupun elektronik', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(19, 1, 1, '132050102009', 'Mesin Penghitung Kertas/Pita Cukai', 'Alat yang berfungsi untuk melakukan penghitungan pada total jumlah kertas secara cepat dan akurat dan bersifat otomastis', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(20, 1, 1, '132050102010', 'Mesin Absen (Time Recorder)', 'Alat ini merupakan mesin absensi manual dan dapat berfungsi merekam waktu tugas pada kartu absensi.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(21, 1, 1, '132050102011', 'Mesin Kontrol Jaga', 'Mesin ini berfungsi untuk memonitor Satpam dalam melakukan Tugas Jaga Keliling.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(22, 1, 1, '132050102012', 'Mesin Penghitung Uang', 'Alat yang bertujuan untuk melakukan penghitungan jumah uang kertas yang bergerak secara manual dioperasikan menggunakan tangan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(23, 1, 1, '132050103001', 'Mesin Stensil Manual Folio', 'Mesin Stensil manual memiliki fungsi untuk menggandakan warkat/surat, undangan, soal dengan menggunakan kertas HVS dengan pembantu master. dalam proses pencetakannya hampir sama saja dengan mesin fotocopy', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(24, 1, 1, '132050103002', 'Mesin Stensil Manual Double Folio', 'mesin yang dapat digunakan untuk menggandakan warkat/surat dengan jenis kertas seperti HVS, duplicator, roneo dan sebagainya.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(25, 1, 1, '132050103003', 'Mesin Stensil Listrik Folio', 'Mesin Stensil listrik memiliki fungsi untuk menggandakan warkat/surat, undangan, soal dengan menggunakan kertas HVS dengan pembantu master. dalam proses pencetakannya hampir sama saja dengan mesin fotocopy', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(26, 1, 1, '132050103004', 'Mesin Stensil Listrik Double Folio', 'Mesin penghasil dokumen berbentuk lembaran dalam jumlah banyak dengan menggunakan pembantu “kertas master” yang disebut dengan stensil sheet atau sheet stensil.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(27, 1, 1, '132050103006', 'Mesin Stensil Spiritus Listrik', 'Mesin pengganda proses langsung (direct proses) atau ada juga yang menyebutnya sebagai mesin pengganda cairan (liquide duplicator).', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(28, 1, 1, '132050103007', 'Mesin Fotocopy Folio', 'Alat teknologi yang berfungsi untuk membuat salinan ke atas kertas dari dokumen, buku, maupun sumber lain. Mesin ini memiliki ukuran untuk kertas folio dalam satuan milimeter sebesar 210 mm x 330 mm. Dalam satuan centimeter, kertas F4 memiliki ukuran 21 cm x 33 cm.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(29, 1, 1, '132050103008', 'Mesin Fotocopy Double Folio', 'Alat teknologi yang berfungsi untuk membuat salinan ke atas kertas dari dokumen, buku, maupun sumber lain. Mesin  ini dapat membuat satu kertas terdapat lebih dari satu hasil fotocopy yang ada di kedua sisi kertas', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(30, 1, 1, '132050103009', 'Mesin Fotocopy Electronic', 'Alat teknologi yang berfungsi untuk membuat salinan ke atas kertas dari dokumen, buku, maupun sumber lain.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(31, 1, 1, '132050103011', 'Mesin Fotocopy Lainnya', 'Alat mesin yang dapat menciptakan salinan dengan media kertas dari berbagai media seperti dokumen, buku, hingga foto', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(32, 1, 1, '132050103012', 'Risograf', 'Risograf adalah merek dan jenis mesin pencetak yang digunakan untuk mencetak jumlah sedang hingga besar dokumen dengan cepat dan efisien. Mesin Risograf bekerja dengan prinsip duplikator stencil, di mana gambar atau teks dicetak dengan menggunakan master stencil yang diproduksi oleh mesin.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(33, 1, 1, '132050103013', 'Mesin Perekam Stensil Folio', 'Mesin cetak dokumen yang berbentuk lembaran dalam jumlah yang banyak.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(34, 1, 1, '132050103014', 'Mesin Perekam Stensil Double Folio', 'Mesin cetak dokumen yang berbentuk lembaran dalam jumlah yang banyak serta dapat mencetak dalam dua sisi secara langsung', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(35, 1, 1, '132050103016', 'Mesin Plate Double Folio', 'mesin cetak dengan teknik cetakan yang hasil cetakannya dicetak terlebih dulu di satu plate, lalu dipindahkan ke lapisan karet yang dinamakan rubber blanket, terakhir dipindahkan ke media cetak yang dikehendaki', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(36, 1, 1, '132050104001', 'Lemari Besi/Metal', 'Alat yang bertujuan untuk dapat menyimpan alat atau berkas serta perlengkapan kantor yang terbuat dari bahan besi atau metal', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(37, 1, 1, '132050104002', 'Lemari Kayu', 'Alat yang bertujuan untuk dapat menyimpan alat atau berkas serta perlengkapan kantor yang terbuat dari bahan Kayu', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(38, 1, 1, '132050104003', 'Rak Besi', 'alat berbentuk rak yang berfungsi untuk menyimpan perlengkapan atau alat kerja yang terbuat dari bahan Besi', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
