	(40, 1, 1, '132050104005', 'Filing Cabinet Besi', 'Alat yang berfungsi untuk tempat penyimpanan berkas atau dokumen pada kantor yang berbahan besi dan memiliki beberapa laci yang dapat ditarik', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
