	(46, 1, 1, '132050104011', 'Rotary Filling', 'Alat yang berguna untuk menyimpan berkas dengan bentuk lingkaran agar lebih mudah untuk melakukan penyimpanan dokumen', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(47, 1, 1, '132050104013', 'Buffet', 'salah satu furniture yang biasanya digunakan untuk melengkapi interior di beberapa ruangan rumah. Umumnya bahan yang sering digunakan untuk membuat sebuah bufet adalah bahan kayu. Bentuk dasarnya terdiri dari struktur persegi panjang dengan ukuran yang dapat disesuaikan dengan kebutuhan masing-masing ruangan.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(48, 1, 1, '132050104014', 'Mobile File', 'tempat penyimpanan dokumen dalam bentuk beberapa Lemari Arsip tanpa pintu yang dirangkai menjadi satu kesatuan agar mempermudah proses pengarsipan dokumen.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(49, 1, 1, '132050104015', 'Locker', 'Alat yang digunakan untuk peawai menyimpan alat atau barang yang berharga yang dapat di kunci setiap lacinya agar lebih terjaga', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(50, 1, 1, '132050104016', 'Roll Opek', 'Lemari arsip dorong untuk menyimpan dokumen dengan kapasitas besar yang dapat digerakkan dengan manual atau dengan penggerak mekanik', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(51, 1, 1, '132050104017', 'Tempat Menyimpan Gambar', 'Alat yang digunakan untuk menyimpan kertas yang sudah terdapat sebuah gambar', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(52, 1, 1, '132050104018', 'Kontainer', 'Alat yang berbahan dari plastik yang digunakan untuk menyimpan segala berkas atau alat yang berkapasitas besar dan dapat dibawa kemana mana', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
