	(55, 1, 1, '132050104022', 'Folding Container Box', 'alat yang bertujuan untuk menyimpan barang atau alat yang berkapasitas besar dan mudah dibawa kemana saja, serta alat tersebut dapat dilipat agar lebih efisien saat tidak digunakan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
