	(63, 1, 1, '132050105002', 'CCTV - Camera Control Television System', 'Alat yang digunakan untuk dapat merekam dan memantau sebuah ruangan atau tempat dari tempat yang jauh', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(64, 1, 1, '132050105003', 'Papan Visual/Papan Nama', 'Bisa merujuk pada berbagai jenis papan yang digunakan untuk menampilkan informasi, pesan, atau gambar. Jenis papan ini dapat digunakan di berbagai tempat dan memiliki tujuan yang beragam. Berikut adalah beberapa jenis papan visual yang umum:', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(65, 1, 1, '132050105004', 'Movitex Board', 'Papan yang terbuat dari rangkaian panel berlubang untuk menempatkan huruf, angka dan tanda termasuk garis garis.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
