	(68, 1, 1, '132050105007', 'Alat Detektor Barang Terlarang/X Ray', 'Alat yang digunakan untuk memindai barang-barang yang berada didalam tas atau koper yang menggunakan sinar X ray agar memudahkan melakukan pengecekan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(69, 1, 1, '132050105008', 'Copy Board/Elektric White Board', 'berbeda dengan white board pada umumnya. white board electric mempunyai fitur yang dapat menyimpan hasil yang di tuliskan pada white board yang kemudian disalinkan kepada kertas secara otomatis', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(70, 1, 1, '132050105009', 'Peta', 'Peta adalah gambaran permukaan bumi yang ditampilkan pada suatu bidang datar dengan skala tertentu.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(71, 1, 1, '132050105010', 'Alat Penghancur Kertas', 'alat yang bertugas untuk menyobek atau menghacurkan kertas secara banyak, cepat dan rapih untuk mempermudah dalam melakukan penghacuran dokumen-dokumen yang sudah tidak digunakan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(72, 1, 1, '132050105011', 'Globe', 'Gambaran bumi yang diperkecil dengan bentuk yang hampir sama dengan bentuk bumi', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(73, 1, 1, '132050105012', 'Mesin Absensi', 'alat yang dilakukan untuk absen pegawai dengan fitur sidik jari dan dapat mengetahui pegawai tersebut telah hadir pada pukul berapa', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(74, 1, 1, '132050105013', 'Dry Seal', 'Jenis perangkat penyegelan yang dirancang untuk memberikan segel yang andal dan kuat tanpa perlu pelumasan cairan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(75, 1, 1, '132050105014', 'Fergulator', 'Voltage regulator adalah suatu perangkat atau sistem yang digunakan untuk mengontrol dan mempertahankan tingkat tegangan listrik dalam suatu sistem atau perangkat elektronik. Fungsi utamanya adalah untuk menjaga agar tegangan listrik tetap pada level yang diinginkan, terlepas dari fluktuasi tegangan yang mungkin terjadi dalam sumber daya listrik atau beban.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(76, 1, 1, '132050105015', 'Cream Polisher', 'penggosok krim bebas asid & tidak beracun.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(77, 1, 1, '132050105018', 'Numerator', 'Alat untuk menambahkan nomor atau angka berurutan secara otomatis pada lembaran dokumen.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(78, 1, 1, '132050105019', 'Alat Pemotong Kertas', 'alat yang memudahkan orang untuk melakukan pemotongan kertas secara banyak', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(79, 1, 1, '132050105020', 'Headmachine Besar', 'Alat untuk menyatukan kertas dengan menggunakan staples dalam jumlah besar', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(80, 1, 1, '132050105022', 'Alat Pencetak Label', 'mesin otomatis yang bertujuan untuk melakukan pencetakan label secara cepat dan banyak dengan design yang bisa di tentukan oleh masing-masing individu', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(81, 1, 1, '132050105023', 'Overhead Projector', 'Alat yang digunakan untuk memproyeksikan gambar atau tulisan pada transparancy film yang diletakkan di atas OHP dan diproyeksikan ke layar, sehingga diperoleh gambar/tulisan yang lebih besar dari aslinya', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
