	(83, 1, 1, '132050105025', 'Walkman Detector', 'Alat pemutar audio kaset portabel', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(84, 1, 1, '132050105026', 'Panel Pameran', 'Panel yang digunakan sebagai media untuk menampilkan karya-karya seni yang dipamerkan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
