	(86, 1, 1, '132050105028', 'Board Modulux', 'papan modul yang dapat digunakan untuk membangun berbagai macam produk elektronik. Papan ini terdiri dari berbagai macam komponen elektronik, seperti resistor, kapasitor, dioda, transistor, dan IC.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(87, 1, 1, '132050105031', 'Megashow', NULL, NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(88, 1, 1, '132050105032', 'White Board Electronic', 'Papan tulis elektronik yang memungkinkan untuk menulis atau menggambar dalam bentuk digital', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(89, 1, 1, '132050105033', 'Laser Pointer', 'perangkat portabel yang menghasilkan cahaya laser yang sangat terfokus, biasanya dalam warna merah, hijau, biru, atau violet. Cahaya laser yang dihasilkan biasanya sangat terang dan dapat terlihat pada permukaan yang jauh, membuat laser pointer menjadi alat yang umum digunakan dalam berbagai situasi.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(90, 1, 1, '132050105034', 'Display', 'Untuk membuat simulasi papan mesin antrian dalam bentuk teks, kita dapat menampilkan informasi nomor antrian yang sedang dipanggil dan nomor-nomor antrian yang masih menunggu dengan tata letak yang sesuai untuk menciptakan nuansa seperti di tempat umum atau bank', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(91, 1, 1, '132050105035', 'Exhauster Form', 'Exhaust fan berfungsi untuk menghisap udara di dalam ruangan ke luar ruangan, sehingga udara yang terkontaminasi polutan, bakteri, hingga bau tak sedap menjadi terbuang keluar ruangan.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(92, 1, 1, '132050105036', 'Rubu Mujayyab', 'instrumen klasik seperempat lingkaran dengan fungsi logaritma dan trigonometri yang terdiri dari busur yang terbagi kepada 90 derajat. Pada bagian tengahnya terdapat garis lurus-lengkung saling menyilang dan memotong. Alat ini berfungsi mengukur ketinggian benda langit, navigasi, menentukan waktu Zuhur dan Asar, alat hitung, dan lain-lain.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(93, 1, 1, '132050105039', 'Mesin Laminating', 'Alat yang digunakan untuk melaminasi (melapisi) produk agar lebih aman', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(94, 1, 1, '132050105040', 'Penangkal Petir', 'Rangkaian jalur yang difungsikan sebagai jalan bagi petir menuju ke permukaan bumi, tanpa merusak benda-benda yang dilewatinya.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(95, 1, 1, '132050105041', 'Stempel Timbul/Bulat', 'Alat cetak tinggi yang memberikan efek timbul pada bagian tertentu di permukaan kertas', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(96, 1, 1, '132050105042', 'Lampu-lampu Kristal', 'Lampu gantung atau chandelier kristal sudah sejak lama digunakan tak hanya sebagai penerangan di rumah, namun juga sebagai elemen dekorasi. Chandelier kristal mampu memberikan nuansa mewah dan elegan pada rumah.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(97, 1, 1, '132050105043', 'LCD Projector/Infocus', 'Perangkat yang mengintegrasikan sumber cahaya, sistem optik, elektronik dan display dengan tujuan untuk memproyeksikan gambar atau video ke dinding atau layar.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(98, 1, 1, '132050105044', 'Flip Chart', 'Kumpulan ringkasan, skema, gambar, tabel yang dibuka secara berurutan berdasarkan topik materi pembelajaran. Bahan flipchart biasanya kertas yang mudah dibuka–buka, mudah ditulisi, dan berwarna cerah.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(99, 1, 1, '132050105045', 'Binding Machine', 'Alat yang digunakan untuk proses menjilid buku', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(100, 1, 1, '132050105046', 'Softboard', 'Papan yang terbuat dari bahan kayu olahan dengan kepadatan serat panel yang rendah sehingga mudah diatur, ringan dan tahan lama. Biasanya digunakan untuk peredam suara atau bahan papan pengumuman', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(101, 1, 1, '132050105047', 'Alat Perekam Suara (Voice Pen)', 'Memungkinkan pembaca mendengarkan konten dalam banyak bahasa hanya dengan menyentuhkan pena ke buku, bagan, dan label. PENpal portabel, tahan lama, dan mudah digunakan, memungkinkan konten audio berdurasi lebih dari 250 jam.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(102, 1, 1, '132050105048', 'Acces Control System', 'Door Access Control adalah sebuah sistem mengatur akses ke suatu ruangan/tempat dengan menempatkan sistem perangkat kontrol pada pintu tersebut.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(103, 1, 1, '132050105049', 'Intruction Detector', NULL, NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(104, 1, 1, '132050105050', 'Monitor Panel With Mimic Board', 'layar monitor yang digunakan bersama dengan papan mimic untuk memberikan informasi visual tentang suatu sistem atau proses.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(105, 1, 1, '132050105051', 'Panic Button System, Alarm Indicator', 'Tombol yang digunakan untuk memantau dan memberi peringatan apabila terjadi kejadian darurat atau berbahaya', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(106, 1, 1, '132050105052', 'Pintu Elektrik (yang Memakai Akses)', 'Kunci pintu elektronik yang menggunakan password tertentu untuk dapat membuka pintu', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(107, 1, 1, '132050105053', 'Focusing Screen/Layar LCD Projector', 'Layar tempat memantulkan hasil dari data yang diterima oleh proyektor sehingga bisa dilihat dengan pandangan mata', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(108, 1, 1, '132050105054', 'Alat Detektor Barang Terlarang', 'Peralatan pendeteksi terhadap barang-barang berbahaya yang meliputi senjata api, senjata tajam, benda dari logam yang dianggap berbahaya, obat-obat terlarang serta bahan peledak', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(109, 1, 1, '132050105055', 'Proyector Spider Bracket', 'Alat terbuat dari besi yang digunakan untuk menggantung proyektor', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(110, 1, 1, '132050105056', 'Papan Gambar', 'Alas kertas gambar', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(111, 1, 1, '132050105057', 'Bel', 'Alat penghasil bunyi yang digunakan untuk berkomunikasi atau memberi kode', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(112, 1, 1, '132050105058', 'Electric Pressing Machine', 'mechanical press ini berfungsi untuk melakukan penekanan, baik untuk proses drawing, punching, blanking, fiting, shearing, bending, forging ataupun yang lainnya.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(113, 1, 1, '132050105062', 'Conservation Tools', 'alat atau metode yang digunakan untuk mendukung praktik konservasi sumber daya, efisiensi energi, dan pengurangan dampak lingkungan di lingkungan perkantoran.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(114, 1, 1, '132050105063', 'Board Stan', 'A Stand atau bisa juga disebut "Sandwich Board" merupakan tipe papan informasi yang dapat dilipat. A Stand memiliki rangka kokoh dan berkualitas sehingga Anda pun tak perlu khawatir jika roboh.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(115, 1, 1, '132050105064', 'Vacum Freeze Dry Chamber', 'salah satu jenis alat yang digunakan untuk melakukan pengeringan dengan cara menurunkan tekanan di sekitar benda yang dikeringkan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(116, 1, 1, '132050105065', 'Kotak Surat', 'wadah atau tempat di mana surat-surat, pos, atau korespondensi lainnya dapat ditempatkan atau disimpan. Kotak surat dapat ditemukan di rumah, kantor, atau tempat umum lainnya', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(117, 1, 1, '132050105066', 'Gembok', 'alat keamanan yang digunakan untuk mengunci pintu, brankas, atau objek lainnya untuk mencegah akses yang tidak diinginkan.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(118, 1, 1, '132050105067', 'Compact Hand Projector', 'Proyektor ringkas adalah perangkat elektronik yang digunakan untuk menampilkan gambar, teks, atau video dari suatu sumber (seperti komputer, perangkat media, atau kamera) ke permukaan datar, seperti layar, dinding, atau permukaan yang lebih besar yang mudah dibawa kemana saja dan berukuran lebih ramping', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(119, 1, 1, '132050105068', 'Alat Sidik Jari', 'Alat yang menerapkan teknologi biometrik menggunakan metode pendeteksian melalui sidik jari', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(120, 1, 1, '132050105069', 'Alat Penghancur Jarum', 'Alat penghancur jarum yang sudah tidak terpakai dengan tujuan untuk menghindari penggunaan ulang jarum dari penggunaan yang tidak semestinya', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(121, 1, 1, '132050105070', 'Walkthrough/ Portal Metal Detector', 'Alat untuk mengidentifikasi benda-benda berbahaya seperti senjata api atau bahan peledak lainnya', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(122, 1, 1, '132050105071', 'Handheld Trace Detector', 'perangkat portabel yang dirancang untuk mendeteksi jejak atau partikel mikroskopis zat tertentu yang bisa bersifat bahan peledak, narkotika, atau zat-zat lain yang dapat membahayakan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(123, 1, 1, '132050105073', 'Mesin Packing/ Starpping Machine', 'Alat yang digunakan untuk mengemas suatu produk dengan kemasan plastik, kertas atau pouch yang dikemas secara otomatis', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(124, 1, 1, '132050105074', 'Television Control Operasional Lift', 'Mungkin merujuk pada sistem kontrol operasional lift yang dilengkapi dengan layar televisi atau monitor untuk tujuan pengawasan, pemantauan, atau memberikan informasi kepada pengguna lift.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(125, 1, 1, '132050105075', 'Mesin Antrian', 'Mesin yang berfungsi untuk manajemen antrian pada layanan massyarakat agar mempermudah dalam memperoleh hak nya untuk dilayani', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(126, 1, 1, '132050105076', 'Papan Nama Instansi', 'Pada umumnya digunakan untuk menginformasikan nama perusahaan atau kantor', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(127, 1, 1, '132050105077', 'Papan Pengumuman', 'Salah satu media komunikasi sebagai sarana penyampaian informasi kepada publik atau masyarakat', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(128, 1, 1, '132050105078', 'Papan Tulis', 'Papan tulis adalah suatu permukaan datar yang dilapisi dengan bahan yang memungkinkan tulisan atau gambar dapat dihapus.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(129, 1, 1, '132050105079', 'Papan Absen', 'merupakan Papan yang memperlihatkan total absensi pegawai atau siswa secara detail', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(130, 1, 1, '132050105080', 'Mesin Fogging', 'Alat yang digunakan untuk sanitasi dari mulai hama, jamur, hingga virus', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(131, 1, 1, '132050105081', 'Teralis', 'Sebuah kontruksi besi dalam bentuk bingkai yang berfungsi sebagai pengaman dekorasi', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(132, 1, 1, '132050105082', 'Alat Penerjemah', 'Alat ini bisa memfasilitasi percakapan dengan puluhan bahasa sekaligus, termasuk enam bahasa internasional resmi yang diakui Perserikatan Bangsa-Bangsa (PBB) serta bahasa Indonesia.\nAlat yang bisa menjadi penerjemah percakapan lisan ini bernama Smart Translator.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(133, 1, 1, '132050105083', 'Alat Penghancur Plastik', 'Alat yang digunakan untuk mengubah plastik ukuran besar menjadi potongan kecil', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(134, 1, 1, '132050105085', 'Pakaian Toga', 'Pakaian toga adalah jenis pakaian seragam yang sering dipakai dalam konteks upacara formal, seperti wisuda, upacara akademis, atau acara khusus lainnya', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(135, 1, 1, '132050105086', 'Sirine', 'alat penghasil suara keras dan khas yang digunakan sebagai sinyal peringatan atau tanda darurat.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(136, 1, 1, '132050105087', 'Tongkat Pedel', 'pedel atau tongkat yang digunakan oleh rektor pada kegiatan wisuda suatu universitas ataupun sekolah. Kami memproduksi pedel terbuat dari bahan logam kuningan yang dilapisi chrome emas sehingga menghasilkan pedel yang mengkilap pastinya tidak cepat pudar dan tahan lama.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(137, 2, 1, '132050201001', 'Meja Kerja Besi/Metal', 'Area tempat seseorang bekerja yang terbuat dari besi atau metal', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(138, 2, 1, '132050201002', 'Meja Kerja Kayu', 'Area tempat seseorang bekerja yang terbuat dari kayu', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(139, 2, 1, '132050201003', 'Kursi Besi/Metal', 'Tempat duduk yang memiliki struktur tulangan menggunakan material Besi. Material tersebut lebih banyak dari seluruh material lainya (>60%)  , Kursi ini biasanya menggunakan tambahan busa pada penampang untuk duduk maupun pada tempat bersandar untuk menambah kenyamanan ataupun keseluruhand menggunakan bahan besi tanpa ada tambahan busa', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(140, 2, 1, '132050201004', 'Kursi Kayu', 'Tempat duduk yang memiliki struktur tulangan menggunakan material Kayu. Material tersebut lebih banyak dari seluruh material lainya (>60%)  , Kursi ini biasanya menggunakan tambahan busa pada penampang untuk duduk maupun pada tempat bersandar untuk menambah kenyamanan ataupun keseluruhan menggunakan bahan kayu tanpa ada tambahan busa.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(141, 2, 1, '132050201005', 'Sice', 'meja yang memiliki mekanisme peluncuran atau geser untuk memperpanjang atau menyembunyikan bagian dari meja tersebut.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(142, 2, 1, '132050201006', 'Bangku Panjang Besi/Metal', 'Sebuah mebel tempat duduk berkaki serupa kursi dengan dudukan lebih panjang terbuat dari besi atau metal', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(143, 2, 1, '132050201007', 'Bangku Panjang Kayu', 'Sebuah mebel tempat duduk berkaki serupa kursi dengan dudukan lebih panjang terbuat dari kayu', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(144, 2, 1, '132050201008', 'Meja Rapat', 'Salah satu meja yang dirancang untuk mengakomodasi sejumlah orang yang disesuaikan dengan kondisi ruang rapat dimana orang-orang tersebut berkumpul', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(145, 2, 1, '132050201009', 'Tempat Tidur Besi', 'Suatu mebel atau tempat yang digunakan sebagai tempat tidur atau beristirahat terbuat dari bahan besi', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(146, 2, 1, '132050201010', 'Tempat Tidur Kayu', 'Suatu mebel atau tempat yang digunakan sebagai tempat tidur atau beristirahat terbuat dari bahan kayu', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(147, 2, 1, '132050201011', 'Meja Ketik', 'Meja yang dimaksudkan untuk memegang mesin tik pada ketinggian yang sesuai untuk tangan juru ketik namun tetap memungkinkan ketinggian tempat duduk yang cukup rendah agar nyaman bagi kaki juru ketik.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(148, 2, 1, '132050201012', 'Meja Telepon', 'Perabot rumah tangga yang ditempatkan untuk menyimpan telepon', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(149, 2, 1, '132050201013', 'Meja Podium', 'Tempat untuk berdirinya orang yang berpidato', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(150, 2, 1, '132050201014', 'Meja Resepsionis', 'Meja yang digunakan untuk menerima tamu perusahaan ataupun tempat mengetahui informasi yang berhubungan dengan perusahaan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(151, 2, 1, '132050201015', 'Meja Marmer', 'meja yang menampilkan permukaan atau lempengan marmer sebagai alas atau berada di atasnya.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(152, 2, 1, '132050201016', 'Meja Tambahan', 'Mebel atau perabotan yang memiliki permukaan datar dan kaki-kaki sebagai penyangga yang bertujuan untuk menambah luas meja', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(153, 2, 1, '132050201017', 'Meja Panjang', 'Mebel atau perabotan yang memiliki permukaan datar dan kaki-kaki sebagai penyangga yang berukuran panjang', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(154, 2, 1, '132050201018', 'Meja Bundar', 'Mebel atau perabotan yang memiliki permukaan datar dan kaki-kaki sebagai penyangga dengan bentuk lingkaran', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(155, 2, 1, '132050201019', 'Meja Periksa Pasien', 'Mebel atau perabotan yang digunakan pada Klinik untuk melakukan pengecekan kepada pasien', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(156, 2, 1, '132050201020', 'Meja Obat', 'Mebel atau perabotan yang digunakan oleh apoteker untuk meracik obat atau menakar obat-obatan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(157, 2, 1, '132050201021', 'Meja Kartu', 'Mebel atau perabotan yang memiliki permukaan datar dan kaki-kaki sebagai penyangga', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(158, 2, 1, '132050201022', 'Meja Bayi', 'Mebel atau perabotan yang memiliki beralaskan kasur tipis yang digunakan untuk menidurkan bayi atau balita untuk menggantikan pampers atau mengganti baju', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(159, 2, 1, '132050201023', 'Meja Sekolah', 'Mebel atau perabotan yang memiliki permukaan datar dan kaki-kaki sebagai penyangga. Biasa digunakan di ruang kelas sekolah.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(160, 2, 1, '132050201024', 'Meja 1/2 Biro', 'meja kerja yang memiliki ukuran meja lebih kecil dari ukuran 150 cm. Meja kantor 1/2 biro lebih sering tidak terdapat laci gantung atau laci dorong di mejanya. Meja kantor setengah biro biasanya memiliki ukuran meja kerja kurang lebih 120 cm panjang, lebar 75cm dan tinggi 75 cm.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(161, 2, 1, '132050201025', 'Kasur/Spring Bed', 'Alas besar yang biasanya berbentuk persegi panjang yang berfungsi sebagai alas orang tidur atau berbaring', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(162, 2, 1, '132050201026', 'Sketsel', 'Sebuah furnitur penyekat ruangan yang sering kali memiliki desain terbuka atau transparan. Sketsel penyekat dapat digunakan untuk membagi ruangan menjadi bagian-bagian yang berbeda tanpa sepenuhnya membatasi cahaya atau pandangan.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(163, 2, 1, '132050201027', 'Meja Makan Besi', 'jenis meja makan yang memiliki rangka atau konstruksi utama terbuat dari besi atau baja. Ini dapat memberikan tampilan yang kokoh dan tahan lama, sementara desainnya dapat bervariasi dari yang sederhana hingga yang lebih dekoratif.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(164, 2, 1, '132050201028', 'Meja Makan Kayu', 'jenis meja makan yang memiliki top atau permukaan utama yang terbuat dari kayu. Ini adalah pilihan yang umum dan populer karena kayu memberikan tampilan alami, hangat, dan beragam.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(165, 2, 1, '132050201029', 'Kursi Fiber Glas/Plastik', 'Tempat duduk yang memiliki struktur tulangan menggunakan material fiber/plastik. Material tersebut lebih banyak dari seluruh material lainya (>60%)  , Kursi ini biasanya menggunakan tambahan busa pada penampang untuk duduk maupun pada tempat bersandar untuk menambah kenyamanan ataupun keseluruhan menggunakan bahan fiber/plastik tanpa ada tambahan busa', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(166, 2, 1, '132050201030', 'Kursi Rapat', 'jenis kursi yang dirancang khusus untuk digunakan selama pertemuan, konferensi, atau rapat. Desain kursi rapat umumnya mencakup kenyamanan untuk jangka waktu yang lebih lama, serta fitur yang mendukung interaksi dan partisipasi selama sesi rapat', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(167, 2, 1, '132050201031', 'Kursi Tamu', 'jenis kursi yang dirancang khusus untuk digunakan di ruang tamu atau ruang santai dalam rumah. Desain kursi tamu sering kali lebih fokus pada kenyamanan dan estetika, menciptakan tempat duduk yang ramah dan menarik.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(168, 2, 1, '132050201032', 'Kursi Putar', 'jenis kursi yang memiliki kemampuan untuk berputar sekitar sumbu tertentu. Fitur ini biasanya diintegrasikan dengan mekanisme putar yang ada pada dasar kursi.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(169, 2, 1, '132050201033', 'Kursi Biasa', 'kursi standar atau konvensional yang umumnya digunakan di berbagai konteks sehari-hari. Ini adalah kursi yang tidak memiliki fitur khusus seperti mekanisme putar, roda, atau fitur ergonomis yang lebih canggih', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(170, 2, 1, '132050201034', 'Bangku Sekolah', 'kursi khusus yang digunakan di lingkungan pendidikan, terutama di ruang kelas sekolah. Desainnya sering kali sederhana dan praktis, disesuaikan dengan kebutuhan dan kondisi di lingkungan belajar.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(171, 2, 1, '132050201035', 'Bangku Tunggu', 'kursi atau tempat duduk yang ditempatkan di area umum atau lobi untuk memberikan tempat kepada orang-orang yang menunggu, seperti di bandara, stasiun kereta, klinik, kantor, atau tempat umum lainnya. Kursi jenis ini berisikan beberapa tempat duduk pada satu tempat', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(172, 2, 1, '132050201036', 'Kursi Lipat', 'sebuah perlengkapan rumah tangga yang digunakan sebagai tempat duduk yang dapat dilipat', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(173, 2, 1, '132050201037', 'Bangku Injak', 'Bangku berbahan kayu yang biasanya digunakan untuk mengambil sesuatu dengan letak yang lebih tinggi', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(174, 2, 1, '132050201038', 'Meja Cetakan', 'Meja cetakan adalah peralatan atau perabotan yang digunakan dalam industri percetakan, khususnya dalam proses cetak offset, cetak flekso, atau proses cetak lainnya', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(175, 2, 1, '132050201039', 'Meja Komputer', 'Meja yang menopang alat elektronik seperti komputer pribadi yang ditujukan untuk penggunaan secara umum di lokasi yang tetap', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(176, 2, 1, '132050201040', 'Pot Bunga', 'Sebuah wadah di mana bunga atau tanaman lain ditanam dan dibesarkan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(177, 2, 1, '132050201041', 'Partisi', 'Partisi ruangan adalah elemen desain interior yang digunakan untuk membagi atau memisahkan ruang menjadi bagian-bagian yang berbeda. Partisi ini dapat memiliki berbagai fungsi, seperti memberikan privasi, menciptakan area yang terpisah, atau menambah elemen estetika pada suatu ruangan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(178, 2, 1, '132050201042', 'Publik Astari (Pembatas Antrian)', 'Tiang pembatas antrian adalah elemen yang digunakan untuk mengatur atau membatasi antrian dalam suatu tempat, seperti di depan kasir, pintu masuk, atau area layanan. Ini membantu menciptakan keteraturan, mengarahkan lalu lintas pelanggan, dan menghindari kekacauan.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(179, 2, 1, '132050201043', 'Rak Sepatu ( Almunium )', 'Salah satu produk rumah tangga yang berfungsi sebagai tempat meletakan sepatu dan sandal agar rapi dan tidak berserakan.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(180, 2, 1, '132050201044', 'Gantungan Jas', 'Salah satu produk peralatan rumah tangga yang digunakan sebagai alat bantu atau perangkat penunjang untuk menggantungkan atau menyangkutkan pakaian', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(181, 2, 1, '132050201045', 'Nakas', 'Furniture untuk menyimpan barang seperti dokumen atau barang-barang kecil lainnya yang berada https://e-katalog.lkpp.go.id/katalog/produk/download/gambar/946660665?file_name=11312245287837154.jpg&v=3&file_sub_location=produk_gambar%2F2023%2F03%2F04', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(182, 2, 1, '132050201046', 'Cubikal', 'meja tempat kerja pegawai yang diberi sekat pembatas agar pegawai bisa mengkonsep tempat kerjanya sebebas mungkin', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(183, 2, 1, '132050201047', 'Workstation', 'meja tempat para pegawai bekerja yang ukurannya luas serta memanjang agar pegawai bekerja bersebelahan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(184, 2, 1, '132050201048', 'Sofa', 'Kursi sofa adalah salah satu jenis furnitur yang umum digunakan untuk duduk di ruang tamu atau ruang keluarga. Sofa biasanya memiliki bingkai yang terbuat dari kayu atau logam, dilengkapi dengan bantalan yang empuk dan dilapisi kain atau kulit untuk kenyamanan. Fungsi utama sofa adalah sebagai tempat duduk yang nyaman, namun banyak sofa juga memiliki fitur tambahan seperti ruang penyimpanan atau kemampuan untuk diubah menjadi tempat tidur (sofa bed).', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(185, 2, 1, '132050201049', 'Meja Rias', 'meja khusus yang dirancang untuk kegiatan berias atau berdandan. Meja ini biasanya terletak di kamar tidur atau ruang pribadi, dan fungsinya utamanya adalah menyediakan tempat untuk menyimpan dan menggunakan produk kecantikan, seperti makeup, perhiasan, dan peralatan perawatan pribadi.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(186, 2, 1, '132050202001', 'Jam Mekanis', 'jam yang menggunakan perangkat mekanis untuk mengukur waktu seperti jam dinding', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(187, 2, 1, '132050202002', 'Jam Listrik', 'alat untuk menghitung waktu yang bekerja secara otomatis dan menunjukan waktu secara digital', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(188, 2, 1, '132050202003', 'Jam Elektronik', 'alat yang dapat menampilkan waktu baik jam, menit, detik dan juga dapat digunakan sebagai timer sebagai penanda waktu.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(189, 2, 1, '132050202004', 'Control Clock', 'Alat yang digunakan untuk mengetahui waktu yang sudah atau sedang digunakan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(190, 2, 1, '132050203001', 'Mesin Penghisap Debu/Vacuum Cleaner', 'Mesin penghisap debu, atau sering disebut vakum, adalah perangkat yang dirancang untuk membersihkan debu, kotoran, dan partikel lain dari berbagai permukaan. Mesin ini bekerja dengan menghasilkan aliran udara yang kuat untuk menarik dan menangkap partikel-partikel tersebut ke dalam wadah penyimpanan atau kantong penyaring.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(191, 2, 1, '132050203002', 'Mesin Pel/Poles', 'Mesin poles biasanya merujuk pada perangkat mekanis yang digunakan untuk membersihkan, menggosok, atau mengkilap permukaan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(192, 2, 1, '132050203003', 'Mesin Pemotong Rumput', 'alat untuk memotong tumbuhan liar dan untuk merawat tumbuhan agar terlihat lebih rapih', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(193, 2, 1, '132050203004', 'Mesin Cuci', 'alat rumah tangga yang berguna untuk mencuci pakaian atau kain kotor yang bekerja secara otomatis dan praktis', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(194, 2, 1, '132050203005', 'Air Cleaner', 'alat rumah tangga yang berguna untuk membersihkan udara pada suatu ruangan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(195, 2, 1, '132050203006', 'Alat Pembersih Salju', 'alat yang menggunakan sikat rol baja elastis yang tinggi dan tahan karat yang tinggi, yang memiliki efek pengaburan yang baik, dan dapat menghilangkan es tipis dan salju yang tipis di permukaan jalan, serta kecepatan pembuangan salju sangat cepat.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(196, 2, 1, '132050203007', 'Tempat Sampah', 'wadah atau kontainer yang dirancang untuk menampung dan mengumpulkan sampah atau limbah.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(197, 2, 1, '132050203008', 'Drain Cleaner Machine', 'mesin yang digunakan untuk membersihkan pipa yang mengalami macet karena tersumbat . Drain cleaner ini bekerja dengan cara mekanik membersihkan kotoran yang menyumbat saluran pipa.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(198, 2, 1, '132050203009', 'Mesin Pemangkas Tanaman Taman/Pagar', 'alat yang berguna untuk menghias sebuah tanaman dengan cara di potong secara rapih', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(199, 2, 1, '132050204001', 'Lemari Es', 'benda elektronik yang berguna untuk mendinginkan bahan makanan dan minuman', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(200, 2, 1, '132050204002', 'A.C. Sentral', 'alat yang berukuran besar yang menempal pada ceiling ruangan yang bertujuan untuk mengeluarkan udara segar dan dingin', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(201, 2, 1, '132050204003', 'A.C. Window', 'alat yang bertujuan untuk mengeluarkan udara dingin pada sebuah ruangan yang dapat di simpan pada jendela ruangan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(202, 2, 1, '132050204004', 'A.C. Split', 'alat yang berguna untuk mengeluarkan udara dingin pada sebuah ruangan yang dipasang pada dinding', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(203, 2, 1, '132050204005', 'Portable Air Conditioner (Alat Pendingin)', 'alat yang berguna untuk mengeluarkan udara dingin pada sebuah ruangan yang dapat dibawa kemana-mana dan disimpan dimana saja', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(204, 2, 1, '132050204006', 'Kipas Angin', 'alat yang berguna untuk mengeluarkan udara dingin yang cara bekerjanya memutarkan sebuah baling secara cepat agar udara yang di keluarkannya berasa lebih sejuk', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(205, 2, 1, '132050204007', 'Exhause Fan', 'exhaust fan merupakan alat penyedot udara yang membantu mengeluarkan udara yang lembap atau terkontaminasi untuk keluar.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(206, 2, 1, '132050204008', 'Cold Storage (Alat Pendingin)', 'fasilitas penyimpanan yang dirancang khusus untuk menjaga suhu rendah atau dingin, biasanya digunakan untuk menyimpan barang-barang yang memerlukan suhu terkendali, seperti makanan, obat-obatan, atau bahan-bahan kimia tertentu.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(207, 2, 1, '132050204009', 'Reach In Frezzer', 'jenis lemari es yang dirancang untuk menyimpan dan membekukan makanan pada suhu rendah. Ini umumnya digunakan di restoran, katering, atau bisnis makanan lainnya', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(208, 2, 1, '132050204010', 'Reach In Chiller', 'jenis lemari pendingin yang dirancang untuk menyimpan dan menjaga suhu dingin pada produk-produk tertentu, terutama makanan dan minuman', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(209, 2, 1, '132050204011', 'Up Right Chiller/Frezzer', 'alat yang memiliki fitur untuk membekukan bahan makan dan menjaga makanan serta minuman tetap segar', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(210, 2, 1, '132050204012', 'Cold Room Frezzer', 'sebuah alat yang berukuran besar seperti ruangan yang digunakan untuk menyimpan semua bahan makanan dengan kapasitas besar dan menjaga suhu didalam ruangan tersebut tetap dingin agar bahan-bahan makanan tersebut tetap terjaga', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(211, 2, 1, '132050204013', 'Air Curtain', 'penyekat udara luar dan udara dalam ruang. Fungsi lainnya, alat ini bisa jadi tirai pembatas udara dingin, hangat, dan bersih di dalam ruang; serta menghalau udara panas/dingin, gas beracun, debu, asap, serta beragam jenis polusi udara dari luar ruang.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(212, 2, 1, '132050204014', 'Air Handling Unit', 'peralatan standar yang bertanggung jawab untuk menyediakan udara segar ke berbagai area bangunan.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(213, 2, 1, '132050204015', 'A.C. Floor Standing', 'alat yang berguna untuk mendinginkan sebuah ruangan yang berukuran besar dan memerlukan daya listrik yang besar dalam penggunaannya', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(214, 2, 1, '132050205001', 'Kompor Listrik (Alat Dapur)', 'alat yang praktis untuk memasak makanan dan kebutuhan lainnya dengan menggunakan daya listrik.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(215, 2, 1, '132050205002', 'Kompor Gas (Alat Dapur)', 'alat yang digunakan untuk memasak dan alat tersebut akan bekerja menggunakan tabung gas sebagai daya utama dalam melakukan pembakaran', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(216, 2, 1, '132050205003', 'Kompor Minyak', 'alat dasar untuk memasak yang bahan utama dalam pembakarannya menggunakan minyak tanah', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(217, 2, 1, '132050205004', 'Teko Listrik', 'alat yang berukuran sekitar 1 liter yang bertujuan untuk memanaskan air dengan sumber daya berupa listrik', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(218, 2, 1, '132050205005', 'Rice Cooker (Alat Dapur)', 'alat yang bertujuan untuk menanak beras agar menjadi nasi yang siap untuk dimakan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(219, 2, 1, '132050205006', 'Oven Listrik', 'alat yang berguna untuk memanggang atau memanaskan makanan secara menyeluruh dengan sumber daya listrik', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(220, 2, 1, '132050205007', 'Rice Warmer', 'alat yang berkapasitas besar dan berguna untuk menjaga nasi tetap hangat dalam waktu yang lama', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(221, 2, 1, '132050205008', 'Kitchen Set', 'tempat untuk menyimpan alat-alat rumah tangga, khususnya perlengkapan memasak. Saat ini banyak ditemukan berbagai macam desain kabinet yang dapat dipilih sesuai selera dan keinginan.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(222, 2, 1, '132050205009', 'Tabung Gas', 'alat untuk menyimpan gas yang mudah terbakar dan digunakan untuk menjadi bahan utama dalam melakukan pembakaran pada kompor', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(223, 2, 1, '132050205010', 'Mesin Giling Bumbu', 'alat elektronik yang digunakan untuk menggiling bahan yang dijadikan sebagai bumbu makanan hingga menjadi halus', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(224, 2, 1, '132050205011', 'Treng Air/Tandon Air', 'alat yang digunakan untuk menyimpan pasokan air bersih dengan kapasitas yang sangat besar yang pada umumnya digunakan disetiap rumah', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(225, 2, 1, '132050205012', 'Mesin Parutan Kelapa', 'alat yang bekerja secara otomatis untuk memudahkan kita memarut buah kelapa', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(226, 2, 1, '132050205013', 'Kompor Kompresor', 'Alat yang digunakan untuk memasak dengan cara terhubung ke saluran gas dan bekerja dengan menyalakan bahan bakar yang mudah terbakar untuk menghasilkan nyala api', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(227, 2, 1, '132050205014', 'Alat Pemanggang Roti/Sate', 'alat yang bertujuan untuk memanggang makanan dengan ukuran yang lebih kecil dan praktis untuk dibawa kemana-mana', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(228, 2, 1, '132050205015', 'Rak Piring Alumunium', 'alat yang bebahan alumunium yang berguna untuk menyimpan perabotan dapur seperti piring, gelas, sendok dan garpu', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(229, 2, 1, '132050205016', 'Alat Penyimpan Beras', 'wadah atau perangkat yang dirancang khusus untuk menyimpan beras dengan aman dan menjaga kebersihan serta kualitas beras', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(230, 2, 1, '132050205017', 'Panci', 'perangkat masak yang digunakan untuk memasak berbagai jenis makanan, seperti sup, rebusan, atau hidangan berkuah. Panci umumnya terbuat dari logam, seperti aluminium, baja tahan karat, atau besi, dan memiliki tutup', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(231, 2, 1, '132050205018', 'Blender', 'alat elektronik yang digunakan menggiling bahan bahan makanan atau minuman agar tergabung menjadi satu secara merata', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(232, 2, 1, '132050205019', 'Mixer', 'alat elektronik yang digunakan menggiling bahan bahan makanan atau minuman agar tergabung menjadi satu secara merata dengan bahan yang lengket  seperti adonan kue', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(233, 2, 1, '132050205020', 'Oven Gas', 'alat yang digunakan untuk memanggang roti atau bahan makanan lainnya sumber bahan bakarnya menggunakan gas', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(234, 2, 1, '132050205021', 'Presto Cooker', 'alat elektronik yang berguna untuk melunakan sebuah makanan', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(235, 2, 1, '132050205022', 'Wonder Pan', 'Wonder Pan BIMA merupakan panci untuk mengukus kue dengan design yang elegant dan dilengkapi jendela untuk memudahkan melihat hasil kue', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(236, 2, 1, '132050205023', 'Mesin Giling Daging', 'alat manual yang digunakan untuk menggiling atau menghaluskan bahan olahan daging', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(237, 2, 1, '132050205024', 'Heating Set', 'penghangat makanan adalah mesin yang bisa di gunakan untuk penyimpanan ataupun untuk menghangatkan berbagai jenis makanan. Tidak hanya daging, tapi makan yang lainnya seperti kuah ataupun bahkan roti bisa di simpan di dalam food warmer.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(238, 2, 1, '132050205025', 'Thermos Air', 'Termos biasa digunakan untuk menyimpan air panas. Dengan dinding dalam termos yang dirancang seperti kaca, maka kalor yang terdapat pada air panas tersebut tidak bisa berpindah dengan cepat.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(239, 2, 1, '132050205026', 'Exhaust Hood', 'alat penghisap asap yang memiliki fungsi utama untuk menyedot bau, udara kotor, dan panas karena proses memasak di area tertentu.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(240, 2, 1, '132050206001', 'Radio', 'teknologi yang digunakan untuk pengiriman sinyal dengan cara modulasi dan radiasi elektromagnetik (gelombang elektromagnetik). Radio juga merujuk pada media penyiaran yang menggunakan gelombang radio untuk menyampaikan siaran audio. Stasiun radio mengudara melalui gelombang radio dan dapat diakses oleh pendengar melalui penerima radio.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(241, 2, 1, '132050206002', 'Televisi', 'salah satu media publik yang memiliki tiga fungsi sebagai alat komunikasi massa. Fungsi tersebut adalah fungsi informasi, Fungsi Pendidikan dan Fungsi Hiburan.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(242, 2, 1, '132050206003', 'Video Cassette', 'alat perekam video analog yang merekam dan memutar video yang biasanya menggunakan pita magnetik untuk penyimpanan.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(243, 2, 1, '132050206004', 'Tape Recorder (Alat Rumah Tangga Lainnya ( Home Use )', 'Perekam kaset atau mesin pita kaset (bahasa Inggris: tape recorder, tape deck) adalah alat perekam suara yang merekam dan memutar suara yang biasanya menggunakan pita magnetik untuk penyimpanan.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(244, 2, 1, '132050206005', 'Amplifier', 'komponen elektronik untuk menghasilkan stereo yang cukup jernih. Dengan alat ini, suara yang dari sumber akan diinput dan diubah menjadi arus listrik berfluktuasi. Faktor itulah yang menyebabkan Mengapa sinyal keluaran yang diproduksi Akan menghasilkan audio yang jelas.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
