	(248, 2, 1, '132050206009', 'Compact Disc', 'Cakram padat atau piringan padat (bahasa Inggris: compact disc, sering disingkat CD) adalah cakram optik digital yang digunakan untuk menyimpan data. Sejak diperkenalkan secara resmi pada tahun 1982, CD memperoleh puncak penjualan pada tahun 2000 yang mencapai 2.445 juta keping.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(249, 2, 1, '132050206010', 'Laser Disc', 'Cakram laser atau piringan laser (bahasa Inggris: laserdisc, disingkat LD) adalah sebuah piringan optikal berdiameter 11.81 inchi (30 cm) dan dapat digunakan pada kedua sisinya untuk menyimpan video atau film dan dapat diputar kembali dengan laser, dan merupakan media penyimpan data pada cakram optik komersial pertama.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(250, 2, 1, '132050206011', 'Karaoke', 'sebuah musik orkestra yang kosong atau tidak dilengkapi dengan suara vokal.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
