	(326, 2, 1, '132050207010', 'Pakaian Panas/Lengkap', 'Baju Pemadam Kebakaran (Fire Jacket) lengkap dengan Celana yang terbuat dari bahan tahan api Aluminium Foil tebal yang digunakan dalam Pemadaman Kebakaran yang dilengkapi dengan Penutup Kepala berlapis Kaca Bening, Sepatu Pemadam, Senter, Tabung Oksigen dan Sarung tangan.', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
	(327, 2, 1, '132050207011', 'Topeng (masker) Oxigen', 'Alat medis untuk membantu menyalurkan gas pernafasan oksigen dari tabung oksigen ke paru-paru', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
