	(329, 2, 1, '132050207013', 'Alat Pelencur Kebakaran', 'alat pemadam kebakaran yang dapat dijinjing/dibawa, dioperasikan oleh satu orang,', NULL, NULL, '2026-04-30 03:15:47', '2026-04-30 03:15:47'),
