	(388, 3, 1, '132050307006', 'Lemari Buku Untuk Perpustakaan', 'Lemari Buku Untuk Perpustakaan dengan Spesifikasi\nUkuran : Lebar 300 cm, Dalam 40 cm, Tinggi 180 cm\nBahan : Kayu dan Kaca\nPERATURAN MENTERI PENDAYAGUNAAN APARATUR NEGARA\n\nDAN REFORMASI BIROKRASI REPUBLIK INDONESIA \n\nNOMOR 1 TAHUN 2021\n\nTENTANG \n\nSTANDAR SARANA DAN PRASARANA KANTOR DI LINGKUNGAN\n\nKEMENTERIAN PENDAYAGUNAAN APARATUR NEGARA DAN  \n\nREFORMASI BIROKRASI', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(389, 3, 1, '132050307007', 'Lemari Buku Arsip Untuk Arsip Dinamis', 'Lemari Arsip untuk Arsip Dinamis dengan Spesifikasi\nUkuran : Lebar 95 cm, Dalam 50 cm, Tinggi 184 cm\nBahan : Kayu Jati/ Besi/ Yang Setara\nPERATURAN MENTERI PENDAYAGUNAAN APARATUR NEGARA\n\nDAN REFORMASI BIROKRASI REPUBLIK INDONESIA \n\nNOMOR 1 TAHUN 2021\n\nTENTANG \n\nSTANDAR SARANA DAN PRASARANA KANTOR DI LINGKUNGAN\n\nKEMENTERIAN PENDAYAGUNAAN APARATUR NEGARA DAN  \n\nREFORMASI BIROKRASI', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(390, 3, 1, '132050307008', 'Buffet Kayu', 'Bufet kayu sangat cocok dimanfaatkan untuk menyimpan benda-benda seperti hiasan rumah. Misalnya seperti guci kecil, hiasan piring, dan lain sebagainya. Biasanya bufet ini diletakkan pada ruangan yang sering digunakan seperti ruang untuk menerima tamu dan ruang berkumpul keluarga.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(391, 3, 1, '132050307009', 'Buffet Kaca', 'Memiliki desain elegan membuat buffet ini tidak hanya digunakan sebagai lemari penyimpanan. Penggunaan kaca pada buffet ini memberikan kesan minimalis untuk memberikan nuansa modern pada ruangan Anda.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
