	(404, 4, 1, '132070101001', 'Sterilisator', 'merupakan peralatan pendukung dalam dunia medis yang berfungsi sebagai penyeteril peralatan medis', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(405, 4, 1, '132070101002', 'Minor Surgical Set (Alat Kedokteran Umum)', 'merupakan alat yang di gunakan dalam bedah minor atau operasi kecil.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(406, 4, 1, '132070101003', 'Diagnostik Set', 'merupakan satu set peralatan dan perlengkapan medis untuk diagnosa suatu penyakit, khususnya pada daerah THT (Telinga, Hidung, Tenggorokan) dan juga mata', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(407, 4, 1, '132070101004', 'Stetoscope (Alat Kedokteran Umum)', 'merupakan alat bantu pemeriksaan yang umum digunakan oleh dokter. Alat ini berfungsi untuk mendengarkan suara dari dalam tubuh, salah satunya untuk mendengar suara detak jantung dan mendeteksi kelainannya', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(408, 4, 1, '132070101005', 'Tensimeter', 'merupakan alat ukur yang dibuat untuk mengukur tekanan darah', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(409, 4, 1, '132070101007', 'Head Lamp (Alat Kedokteran Umum)', 'merupakan alat bantu penerangan yang digunakan di kepala yang berfungsi sebagai lampu periksa pasien', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(410, 4, 1, '132070101008', 'Waskom', 'wadah waskom berbentuk cekung seperti mangkuk untuk digunakan berbagai keperluan.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(411, 4, 1, '132070101009', 'Timbangan Badan (Alat Kedokteran Umum)', 'merupakan alat yang digunakan untuk mengukur bobot berat pada seseorang.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(412, 4, 1, '132070101010', 'Timbangan Bayi', 'merupakan alat yang digunakan untuk mengukur berat badan bayi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(413, 4, 1, '132070101011', 'Kocher', 'merupakan instrumen bedah berbentuk gunting yang berfungsi untuk menjepit/memegang jaringan keras seperti, fasia dan jaringan lunak seperti peritonium.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(414, 4, 1, '132070101012', 'Metal Chatheeter', 'merupakan alat untuk mengeluarkan urine / BAK / kencing yang terbuat dari metal / besi stainless steel', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(415, 4, 1, '132070101014', 'Anaromische Pinset', 'merupakan pinset dengan gigi anatomi untuk penjepit jaringan dalam proses operasi digunakan untuk memegang jaringan, alat dan bahan medis.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(416, 4, 1, '132070101015', 'Chirurgical Pinset', 'merupakan pinset berbentuk bilah tajam pada kedua sisinya, digunakan untuk menjepit jaringan pada waktu diseksi dan penjahitan luka dan memberi tanda pada kulit sebelum memulai insisi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(417, 4, 1, '132070101016', 'Naalvoeder', 'merupakan alat medis yang digunakan untuk memegang dan memanipulasi jarum bedah selama prosedur bedah.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(418, 4, 1, '132070101017', 'Arteriklem', 'merupakan alat untuk menjepit (memegang/menekan) sesuatu benda. Biasanya klem ini digunakan untuk memasang karet behel oleh dokter gigi atau ahli gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(419, 4, 1, '132070101018', 'Instrumen Cabinet', 'merupakan lemari untuk menyimpan berbagai peralatan kesehatan seperti, gunting, jarum, dan peralatan lainnya.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(420, 4, 1, '132070101020', 'Gunting Bengkok', 'merupakan instrumen utama dalam debridement / pembersihan luka. Gunting necrotomy ini juga digunakan dalam instrument bedah (khitan , bersihkan luka dll) / obgyn yang digunakan untuk untuk menggunting benang, menggunting jaringan dan menggunting balutan .', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(421, 4, 1, '132070101021', 'Gunting Lurus', 'merupakan salah satu instrumen atau alat yang dibutuhkan saat operasi atau pembedahan di rumah sakit.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(422, 4, 1, '132070101022', 'Lemari Steriil', 'merupakan lemari untuk memastikan sterilisasi, kebersihan, dan ketersediaan peralatan yang diperlukan selama prosedur medis.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(423, 4, 1, '132070101023', 'Air Viva', 'merupakan suatu bentuk pernapasan buatan yang menggunakan kantong pernapasan untuk membantu pasien dalam bernapas.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(424, 1, 1, '132050105059', 'Encapsulator (Jarasonic welder)', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(425, 4, 1, '132070101025', 'Ambubag', 'merupakan alat bantu pernafasan yang berfungsi untuk memompa udara masuk ke dalam paru – paru melalui hidung / mulut.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(426, 1, 1, '132050105060', 'Deacidificator Unit (Non Aquas)', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(427, 4, 1, '132070101026', 'Tabung 02', 'merupakan perangkat medis penting yang digunakan untuk membantu pasien yang mengalami masalah pernapasan atau memiliki kebutuhan oksigen tambahan.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(428, 1, 1, '132050105061', 'Full Automatic Leaf Caster', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(429, 4, 1, '132070101027', 'Aplanation Termometer', 'merupakan alat diagnostik yang digunakan dalam bidang oftalmologi untuk mengukur tekanan intraokular atau tekanan di dalam bola mata.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(430, 4, 1, '132070101028', 'Autoclave Table', 'merupakan alat sterilisasi yang dapat ditempatkan diatas meja. Sterilisasi ini memiliki tekanan tinggi dan diperlukan uap sebagai media sterilisasi yang cepat, aman dan ekonomis. Sterilisasi tipe ini digunakan untuk bidang stomatologi, oftalmologi, ruang operasi dan CSSD untuk sterilisasi instrumen yang dibungkus atau tidak terbungkus kain, peralatan, media kultur, cairan yang tidak disegel dan lainnya.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(431, 4, 1, '132070101029', 'Automatic Chart Proyektor', 'merupakan alat yang digunakan pada pemeriksaan prosedur refraksi (ketajaman mata) dengan cara pemberian tes untuk mengenali beberapa obyek, warna ataupun huruf dengan ukuran yang bermacam-macam seperti halnya yang terdapat pada Snellen Chart.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(432, 4, 1, '132070101032', 'Bak Instrument (Stainles,Kaca,Email)', 'merupakan wadah atau tempat yang digunakan untuk meletakkan intrumen medis seperti gunting, klem, pinset, dan keperluan tindakan medis lainnya.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(433, 4, 1, '132070101033', 'Bak Korentang (Stainles)', 'merupakan wadah berbentuk tabung dengan lubang di bagian atas dan pemberat di bagian bawah untuk menyimpan/meletakkan korentang.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(434, 4, 1, '132070101036', 'Bantal Angin/Wind Ring', 'merupakan alat yang dibuat dari karet berbentuk lingkaran seperti ban dalam mobil. Alat ini digunakan sebagai alas duduk penderita ambeien/wasir agar lebih nyaman saat duduk.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(435, 4, 1, '132070101037', 'Basic Diagnostic Kit (Alat Kedokteran Umum)', 'merupakan seperangkat peralatan medis dasar yang digunakan untuk melakukan diagnosis awal atau pemeriksaan dasar terhadap kondisi kesehatan seseorang. Kit ini sering digunakan oleh profesional kesehatan, seperti dokter, perawat, atau petugas kesehatan lainnya, untuk menilai gejala, mengukur parameter vital, dan melakukan pemeriksaan sederhana.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(436, 4, 1, '132070101038', 'Bed Side Monitor', 'merupakan  alat yang digunakan untuk memonitor tanda- tanda vital pasien, berupa nadi, tekanan darah, temperature, kadar oksigen dan frekuensi pernapasan secara terus menerus.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(437, 4, 1, '132070101039', 'Bed Skreen/Sherm', 'merupakan pembatas ruangan yang digunakan diruangan rawat inap rumah sakit, berfungsi sebagai penyekat atau memisahkan satu pasien dengan pasien lainnya dalam satu ruangan rawat inap.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(438, 4, 1, '132070101040', 'Blass Spuit (Glass,Metal)', 'merupakan alat suntik yang terbuat dari kaca.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(439, 4, 1, '132070101041', 'Blood Exchange Set (Alat Kedokteran Umum)', 'merupakan selang yang digunakan untuk melakukan transfusi darah.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(440, 1, 1, '132050105072', 'Alat Deteksi Pita Cukai Palsu/ Video Spectral Comparator', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(441, 4, 1, '132070101042', 'Brancard', 'merupakan digunakan untuk keperluan rumah sakit, puskesmas, klinik guna memindahkan pasien dari satu ruangan ke ruangan lainnya.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(442, 4, 1, '132070101045', 'Canula Rectal', 'merupakan alat medis yang berupa selang atau tabung fleksibel yang dimasukkan ke dalam rektum (saluran usus besar yang berakhir di anus) untuk berbagai keperluan medis. Fungsinya dapat bervariasi tergantung pada kebutuhan medis tertentu.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(443, 4, 1, '132070101047', 'Centrifuge (Alat Kedokteran Umum)', 'merupakan alat yang digunakan untuk memisahkan suatu senyawa yang memiliki berat molekul yang berbeda dengan memanfaatkan gaya sentrifugal.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(444, 4, 1, '132070101048', 'Chytologi Bantal', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(445, 4, 1, '132070101049', 'Clinical Thermometer (Alat Kedokteran Umum)', 'merupakan alat yang digunakan untuk mengukur suhu tubuh manusia.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(446, 4, 1, '132070101050', 'Co2 Analyzer (Alat Kedokteran Umum)', 'merupakan suatu alat instrumentasi penganalisa kandungan karbon dioksida dalam suatu sampel gas.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(447, 4, 1, '132070101053', 'Corn Image Interserver', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(448, 4, 1, '132070101056', 'Desk Suction System', 'merupakan sistem penyedot cairan atau penghisap yang digunakan di meja operasi atau tempat pemeriksaan medis. Ini biasanya digunakan untuk menghilangkan cairan selama prosedur bedah atau perawatan medis.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(449, 4, 1, '132070101057', 'Digital Oscamolis', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(450, 4, 1, '132070101060', 'Electro Cardiography (Alat Kedokteran Umum)', 'merupakan alat yang digunakan untuk merekam aktivitas listrik jantung. Proses ini melibatkan pemasangan elektroda pada kulit pasien, biasanya di dada, lengan, dan kaki. Elektroda ini mengukur perubahan arus listrik yang terjadi selama kontraksi dan relaksasi otot jantung.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(451, 4, 1, '132070101061', 'Elektro Counter', 'merupakan alat yang digunakan untuk membuat potongan dan sayatan pada jaringan kulit pasien dalam proses pembedahan menggunakan energi listrik.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(452, 4, 1, '132070101062', 'Ergometer Sensor', 'merupakan komponen atau perangkat yang digunakan pada alat ergometer untuk mengukur dan merekam data seputar aktivitas fisik, seperti detak jantung, kecepatan, jarak, dan laju metabolisme.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(453, 1, 1, '132050105084', 'Proteksi Petir Terpadu', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(454, 4, 1, '132070101064', 'Examination Lamp', 'merupakan lampu berintentitas tinggi dan berfungsi untuk menyinari tubuh pasien yang digunakan oleh para ahli medis.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(455, 4, 1, '132070101065', 'Examination Table', 'merupakan tempat tidur yang dibuat untuk menunjang pemeriksaan pasien di rumah sakit, klinik, puskesmas, maupun penunjang kesehatan lainnya.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(456, 4, 1, '132070101067', 'Film Viewer', 'merupakan  alat yang memiliki fungsi untuk melihat hasil dari pemeriksaan Rontgen dengan lebih jernih, jelas dan terang.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(457, 4, 1, '132070101068', 'Flow Meter (Alat Kedokteran Umum)', 'merupakan sebuah alat yang memiliki fungsi untuk mengukur jumlah/ volume aliran fluida. Di mana fluida tersebut bisa berupa cairan, gas, atau uap. Pada praktiknya, flow meter membantu mengkalkulasikan jumlah aliran fluida yang melewatinya.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(458, 4, 1, '132070101069', 'Flow Meter 02', 'merupakan alat untuk mengatur aliran oksigen dari sumbernya (outlet oksigen di dinding rumah sakit) sesuai dengan kebutuhan pasien dewasa.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(459, 4, 1, '132070101071', 'Forcep Neagle/Kieland/Piper', 'merupakan alat yang digunakan untuk mengeluarkan bayi dari jalan lahir saat persalinan. Bentuknya menyerupai sepasang sendok besar yang digunakan untuk menjepit kepala bayi dan mengeluarkan bayi dari vagina ibu.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(460, 4, 1, '132070101074', 'Gilycerin Spuit', 'merupakan alat yang berfungsi untuk menyemprotkan lavement/clysma melalui rectal atau anus.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(461, 4, 1, '132070101075', 'Giving Set (Alat Kedokteran Umum)', 'merupakan alat yang digunakan untuk mengatur dan memberikan infus atau cairan intravena (IV) kepada pasien. Alat ini terdiri dari berbagai komponen yang dirancang untuk menyuntikkan atau mengalirkan cairan dari kantong atau botol infus ke dalam pembuluh darah pasien melalui saluran intravena.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(462, 4, 1, '132070101079', 'Ice Cup', 'RICE merupakan singkatan dari Rest, Ice, Compression dan Elevation. Metode pengobatan ini biasanya dilakukan untuk cedera akut, khususnya cedera jaringan lunak (sprain maupun strain).  Ice artinya memberikan efek dingin untuk membantu menurunkan suhu di sekitar jaringan yang mengalami cedera. Secara umum, tujuan pemberian es pada jaringan yang cedera adalah mengatasi pembengkakan dengan membuat penyempitan pembuluh darah, mengurangi nyeri, melalui efek sedative deingin dan selanjutnya mengurangi spasme otot. Pemberian es sesegera mungkin setelah cedera selama 15 – 20 menit secara berkala.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(463, 4, 1, '132070101080', 'Infusion Pump', 'merupakan alat medis yang digunakan untuk memberikan cairan atau obat ke dalam tubuh pasien melalui pembuluh intravena.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(464, 4, 1, '132070101081', 'Instrument Tray', 'merupakan alat untuk menyimpan instrument set atau untuk wadah saat instrument set akan di setilkan menggunakan sterilisasi kering.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(465, 4, 1, '132070101085', 'Kom Kompres (Alat Kedokteran Umum)', 'merupakan alat untuk membantu mengatur suhu tubuh dengan memberi paparan suhu yang dikehendaki secara langsung pada area kontak.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(466, 4, 1, '132070101086', 'Kom Stainles (Drain,Gaas,Tampon)', 'tempat untuk menaruh, kasa, obat luka, dahak, air  untuk menyeka luka pada pasien', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(467, 4, 1, '132070101087', 'Korentang', 'merupakan alat untuk memegang atau mengambil alat dan bahan medis steril supaya tetap terjaga dalam kondisi steril, jika diambil dengan tangan kemungkinan menjadi tidak steril.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(468, 4, 1, '132070101088', 'Laundry Tuch', 'Secara umum, dalam lingkungan kedokteran atau perawatan kesehatan, tekstil seperti kain atau linen digunakan untuk berbagai tujuan, termasuk pembuatan linen bedah, seprai bedah, baju pasien, dan tekstil medis lainnya. Peralatan tekstil ini harus memenuhi standar kebersihan dan sterilisasi tertentu untuk memastikan keamanan pasien dan staf medis', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(469, 4, 1, '132070101089', 'Laser Unit', 'Unit Laser dalam Peralatan Medis: Di dunia kedokteran, "Laser Unit" dapat merujuk pada perangkat laser yang digunakan untuk prosedur bedah, perawatan kulit, atau terapi medis lainnya.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(470, 4, 1, '132070101091', 'Low Presure Continous', '"Low Pressure Continuous" mungkin merujuk pada sistem atau perangkat yang dirancang untuk beroperasi pada tekanan rendah secara terus-menerus. Ini bisa mencakup berbagai jenis peralatan atau sistem, seperti pompa air, sistem pendingin, atau peralatan industri lainnya.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(471, 4, 1, '132070101092', 'Magil Tang (Dewasa,Anak)', 'alat yg digunakan untuk memasang intubasi atau alat bantu saluran nafas atau mengambil benda asing dari saluran napas bagian atas korban/pasien.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(472, 4, 1, '132070101093', 'Mangkok/Kom Betadin (Stainless,Keramik/China)', 'merupakan wadah untuk menaruh iodine/betadine saat melakukan tindak medis.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(473, 4, 1, '132070101095', 'Meja Suntik Beroda', 'merupakan alat bantu meja kecil yang umumnya digunakan di ruangan medis untuk membawa aneka instrumen atau kebutuhan medis lainnya pada saat tindakan', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(474, 4, 1, '132070101096', 'Lemari Obat (Kaca)', 'merupakan lemari khusus yang sengaja dirancang untuk digunakan oleh para ahli medis atau ditempatkan di ruangan medis seperti klinik, tempat praktek dokter, rumah sakit dan lain-lain yang biasanya berfungsi sebagai wadah berbagai macam obat atau instrumen medis.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(475, 4, 1, '132070101100', 'Nebulizer Perimeter (Anesthesi)', 'merupakan alat yang digunakan untuk mengubah obat cair menjadi uap agar bisa dihirup masuk ke dalam paru-paru.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(476, 4, 1, '132070101101', 'Needle Holder', 'merupakan alat instrumen yang memiliki fungsi sebagai penjepit atau pemegang jarum jahit.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(477, 4, 1, '132070101104', 'Nierbekhen', 'merupakan alat yang digunakan sebagai wadah atau penampung muntahan pasien. Alat ini juga digunakan untuk membuang kapas bekas pakai, nanah.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(478, 4, 1, '132070101105', 'Neonatal Monitor (Alat Kedokteran Umum)', 'merupakan alat yang memiliki fungsi untuk memberikan kita informasi mengenai keadaan pasien.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(479, 4, 1, '132070101107', 'Operating Lamp', 'merupakan lampu operasi adalah peralatan bedah yang digunakan untuk penerangan pada saat pembedahan dikamar operasi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(480, 4, 1, '132070101108', 'Oxygen Therapy Set Lengkap', 'merupakan perangkat atau sistem yang digunakan untuk memberikan suplai oksigen tambahan kepada seseorang yang memerlukannya, biasanya dalam konteks perawatan medis.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(481, 4, 1, '132070101113', 'Pispot Dewasa', 'merupakan alat seperti mangkuk atau bejana bertangkai terkadang juga menggunakan tutup, yang digunakan sebagai tempat pembuangan urine atau air seni', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(482, 4, 1, '132070101115', 'Prape For Memory Dan Typloid', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(483, 4, 1, '132070101118', 'Pulse Oximeter', 'merupakan alat untuk mengukur kadar oksigen (saturasi oksigen) di dalam darah.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(484, 4, 1, '132070101119', 'Reflex Hammer (Alat Kedokteran Umum)', 'merupakan alat yang digunakan untuk memeriksa kemampuan reflesi dari bagian-bagian tertentu tubuh kita, biasanya lutut kita.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(485, 4, 1, '132070101120', 'Respirator (Alat Kedokteran Umum)', 'merupakan alat pelindung yang digunakan untuk melindungi pernapasan Anda dari kontaminan udara.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(486, 4, 1, '132070101121', 'Resusitasi Dewasa', 'merupakan perangkat medis yang digunakan untuk memberikan ventilasi buatan pada pasien dewasa yang mengalami kesulitan atau kegagalan pernapasan.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(487, 4, 1, '132070101122', 'Resusitasi Anak', 'merupakan perangkat medis yang dirancang khusus untuk memberikan ventilasi buatan pada pasien anak-anak yang mengalami kesulitan pernapasan atau kegagalan pernapasan', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(488, 4, 1, '132070101123', 'Resusitasi Bayi', 'merupakan perangkat medis yang digunakan untuk memberikan pertolongan pertama pada bayi yang mengalami kesulitan pernapasan atau kegagalan pernapasan.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(489, 4, 1, '132070101125', 'Rolling Seal Type', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(490, 4, 1, '132070101126', 'Kursi Dorong', 'merupakan kursi roda yang dirancang dengan roda yang dapat didorong oleh seseorang atau ditenagai oleh orang lain untuk membantu seseorang yang kesulitan berjalan atau bergerak sendiri.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(491, 4, 1, '132070101132', 'Seven Solar Duble Midel', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(492, 4, 1, '132070101133', 'Suction Pump', 'merupakan alat medis yang dapat menghisap cairan berupa darah, air liur, nanah, lendir atau berbaga jenis cairan yang terbentuk dari proses sekresi tubuh yang dalam kondisi tertentu perlu untuk dihilangkan atau dibersihkan pada saat proses operasi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(493, 4, 1, '132070101134', 'Sonde Uterus (Alat Kedokteran Umum)', 'merupakan alat yang digunakan untuk mengukur panjang rahim pada proses persalinan.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(494, 4, 1, '132070101135', 'Spatel Lidah', 'merupakan alat yang digunakan dalam pemeriksaan lidah yang digunakan dengan cara menekan lidah pada pasien serta dapat melihat tenggorokan dengan jelas.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(495, 4, 1, '132070101137', 'Sputum Bak/Pot', 'merupakan wadah steril yang yang digunakan untuk menampung dahak atau cairan pasien TB.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(496, 4, 1, '132070101138', 'Standar Infus', 'merupakan alat yang berfungsi untuk menempatkan cairan infuse yang terhubung dengan pasien.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(497, 4, 1, '132070101139', 'Standar Waskom', 'merupakan alat yang berfungsi untuk menempatkan waskom.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(498, 4, 1, '132070101142', 'Stimulator (Alat Kedokteran Umum)', 'perangkat medis yang digunakan untuk merangsang atau memodulasi aktivitas fisik atau biologis dan terdiri dari berbagai jenis', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(499, 4, 1, '132070101143', 'Syringe Pump (Alat Kedokteran Umum)', 'merupakan peralatan medis yang digunakan untuk memberikan suatu cairan yang pekat yang diinjeksikan ke dalam tubuh pasien dalam jumlah tertentu melalui vena.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(500, 4, 1, '132070101144', 'Temperatur Monitor', 'Temperature monitor atau pemantau suhu merupakan perangkat yang digunakan untuk mengukur dan memantau suhu pada pasien, peralatan medis, atau lingkungan kesehatan', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(501, 4, 1, '132070101145', 'Termometer Mercury Untuk Suhu Badan', 'merupakan alat pengukur suhu tubuh manual menggunakan air raksa atau zat merkuri.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(502, 4, 1, '132070101150', 'Tromol Has', 'merupakan alat untuk menyimpan kasa pembalut yang telah disterilisasikan. Alat ini juga dapat digunakan untuk mensterilkan kasa pembalut yang sudah di potong-potong.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(503, 4, 1, '132070101151', 'Urinal', 'merupakan wadah untuk menampung urin.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(504, 4, 1, '132070101152', 'U S G', 'merupakan suatu metoda diagnostik dengan menggunakan gelombang ultrasonik, untuk mempelajari struktur jaringan berdasarkan gambaran echo dari gelombang ultrasonik yang dipantulkan oleh jaringan.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(505, 4, 1, '132070101153', 'Utility Trolly', 'merupakan sejenis troli atau kereta yang dirancang untuk digunakan dalam berbagai konteks dan lingkungan, terutama di sektor layanan kesehatan, rumah sakit, fasilitas perawatan, serta sektor industri dan komersial lainnya. Troli ini memiliki berbagai fungsi dan dapat digunakan untuk membawa dan menyimpan berbagai peralatan, bahan, atau barang.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(506, 4, 1, '132070101154', 'UV Sterilizer', 'Merupakan alat untuk mendesinfeksi bakteri dengan menggunakan sinar Ultraviolet', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(507, 4, 1, '132070101157', 'Vena Sectie Set', 'merupakan instrumen yang digunakan untuk operasi pembuluh darah dan biasa digunakan juga untuk pemasangan saluran cuci darah, pemasangan infus yang susah, memasukkan catheter jantung, dan lain-lain.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(508, 4, 1, '132070101158', 'Wall Rail System', 'merupakan sistem dinding yang dirancang untuk memberikan fleksibilitas dalam pemasangan dan penyesuaian berbagai peralatan atau aksesori di dalam lingkungan kesehatan, rumah sakit, atau fasilitas perawatan kesehatan lainnya.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(509, 4, 1, '132070101161', 'Senter', 'merupakan lampu periksa atau senter berbentuk pulpen. yang kegunaannya untuk keperluan medis alat ini biasanya digunakan untuk memeriksa mata, telinga dan hidung pasien.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(510, 4, 1, '132070101162', 'Refloton', 'merupakan sistem analisis kimia klinis portabel yang digunakan untuk melakukan tes darah di tempat.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(511, 4, 1, '132070101163', 'Meja Fisiotherapie', 'merupakan meja khusus yang digunakan dalam praktik fisioterapi atau rehabilitasi fisik. Meja ini dirancang untuk memberikan dukungan dan kenyamanan kepada pasien selama sesi terapi fisik.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(512, 4, 1, '132070101165', 'Pinset Anatomi', 'merupakan pinset dengan gigi anatomi bahan stainless untuk menjepit jaringan dalam operasi digunakan untuk memegang jaringan, alat dan bahan medis', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(513, 4, 1, '132070101167', 'Tong Spatel', 'merupakan instrumen yang biasanya digunakan untuk pemeriksaan rongga mulut seperti pemeriksaan amandel.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(514, 4, 1, '132070101168', 'The Sun Ancom Oxigen Exer', 'merupakan suatu perangkat kesehatan yang dirancang untuk memberikan pijatan dan gerakan pada tubuh dengan tujuan meningkatkan kesehatan. Perangkat ini kemudian melakukan gerakan ayunan dari sisi ke sisi, meniru gerakan serupa yang dapat ditemui dalam latihan seperti berjalan atau berenang.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(515, 4, 1, '132070101169', 'Oxygen Mixer/Blender', 'merupakan perangkat medis yang digunakan untuk mengatur dan menggabungkan aliran oksigen dan udara. Tujuannya adalah untuk menciptakan campuran gas dengan konsentrasi oksigen yang tepat untuk memenuhi kebutuhan pasien.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(516, 4, 1, '132070102001', 'Dental Chair', 'merupakan alat yang dipakai oleh dokter gigi untuk membantu pemeriksaan dan menentukan terapi yang dapat diberikan kepada pasien.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(517, 4, 1, '132070102002', 'Dental Unit', 'merupakan alat yang dipakai oleh dokter gigi untuk membantu pemeriksaan dan kemudian menentukan terapi apa yang dapat diberikan kepada pasien, dimana dental unit ini mempunyai 3 sumber tenaga yaitu tenaga listrik, tenaga udara/angin dan tenaga air.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(518, 4, 1, '132070102003', 'Dental X-Ray Unit', 'merupakan alat yang digunakan untuk mendapatkan gambar dari gigi, tulang, dan jaringan lunak di sekitarnya, juga untuk membantu menemukan masalah pada gigi, mulut dan rahang.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(519, 4, 1, '132070102004', 'Air Set Airomatik', 'Air Set Airomatik adalah perangkat elektronik yang digunakan untuk menyebarkan aroma ke udara. Air Set Airomatik biasanya digunakan di rumah, kantor, atau ruang publik lainnya untuk menciptakan suasana yang nyaman dan menenangkan', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(520, 4, 1, '132070102005', 'Dental Hand Instruments Set', 'merupakan seperangkat instrumen kedokteran yang digunakan untuk membantu perawatan Gigi dan Mulut', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(521, 4, 1, '132070102006', 'Oral Surgical Set', 'merupakan seperangkat instrumen dan peralatan bedah yang dirancang khusus untuk prosedur bedah mulut atau oral. Set ini digunakan oleh dokter gigi atau ahli bedah mulut selama prosedur bedah gigi, mulut, atau rahang.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(522, 4, 1, '132070102008', 'Aero Sterisator', 'merupakan perangkat atau sistem yang digunakan untuk memastikan kebersihan dan kesterilan udara di suatu lingkungan', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(523, 4, 1, '132070102009', 'Operating Chair', 'merupakan jenis kursi khusus yang dirancang untuk keperluan operasi atau prosedur medis.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(524, 4, 1, '132070102010', 'Infra Red', 'penggunaan teknologi inframerah atau sinar inframerah dalam praktek kedokteran gigi, Berikut adalah beberapa aplikasi umum dari teknologi inframerah dalam kedokteran gigi; Pendeteksian Karies, Pemantauan Kesehatan Gusi, Pemindaian Termal Gigi', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(525, 4, 1, '132070102011', 'Sendok Cetak', 'merupakan intrumen kedokteran gigi yang berfungsi untuk mencetak kondisi gigi rahang atas dan rahang bawah pasien.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(526, 4, 1, '132070102012', 'Clinical Chair', 'merupakan jenis kursi yang digunakan di lingkungan klinis atau medis seperti kebutuhan pemeriksaan klinis, konsultasi dokter, atau prosedur medis lainnya yang dilakukan di lingkungan klinis.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(527, 4, 1, '132070102013', 'Dosator', 'merupakan perangkat yang digunakan untuk memberikan dosis obat atau zat medis dalam jumlah yang tepat kepada pasien.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(528, 4, 1, '132070102014', 'Minor Surgical Set (Alat Kedokteran Gigi)', 'merupakan instrumen/alat yang digunakan dalam tindakan bedah minor atau operasi kecil.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(529, 4, 1, '132070102015', 'Dental Sergion Set', 'merupakan instrumen/alat untuk melakukan tindakan atau operasi yang berkaitan dengan mulut dan gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(530, 4, 1, '132070102016', 'Polish Motor', 'merupakan alat yang digunakan oleh profesional kesehatan gigi, terutama dokter gigi atau ahli pembersih gigi, untuk membersihkan dan membuat permukaan gigi mengkilap.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(531, 4, 1, '132070102017', 'Gavitron Generator', 'perangkat pembersih gigi ultrasonik yang banyak digunakan dalam praktik gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(532, 4, 1, '132070102019', 'Portable Dental Unit', 'merupakan sistem peralatan gigi yang dirancang dapat diangkut, mudah dipindahkan dan diatur di lokasi tertentu untuk memberikan pelayanan kesehatan gigi di luar lingkungan klinik atau praktek gigi tetap.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(533, 4, 1, '132070102020', 'Dental Ultra Sonic', 'merupakan allat yang berfungsi untuk membersihkan karang gigi atau plak gigi dengan menggunakan getaran ultrasonik.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(534, 4, 1, '132070102021', 'U.V. Lamp (Alat Kedokteran Gigi)', 'merupakan adalah perangkat medis yang digunakan dalam prosedur perawatan gigi untuk mengeraskan atau mengentalkan bahan tambal yang berbasis resin, seperti resin komposit.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(535, 4, 1, '132070102022', 'Amalgamator', 'merupakan alat yang digunakan dalam prosedur kedokteran gigi untuk mencampur bahan tambalan gigi yang disebut amalgam.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(536, 4, 1, '132070102025', 'Amalgam Pistol/Stoper (Alat Kedokteran Gigi)', 'merupakan alat dental yang memiliki fungsi untuk memasukan amalgam kedalam kavita dan menekan amalgam dalam kavita supaya padat.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(537, 4, 1, '132070102026', 'Articulator Free Place', 'merupakan alat yang digunakan dalam kedokteran gigi untuk mereplikasi gerakan rahang pasien secara akurat.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(538, 4, 1, '132070102027', 'Bend Pusher', 'merupakan instrumen kedokteran gigi yang digunakan dalam proses pemasangan bracket ortodontik atau bracket gigi pada perawatan kawat gigi. Alat ini membantu dalam menempatkan dan mendorong bracket ortodontik ke posisi yang diinginkan pada permukaan gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(539, 4, 1, '132070102029', 'Bistal End Cutter', 'merupakan instrumen pemotong kawat yg dapat di gunakan di dalam mulut pasien, sehingga tidak perlu membuka karet gigi untuk memotong kawat yg berlebih saat pemasangan kawat Gigi (Behel).', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(540, 4, 1, '132070102031', 'Boor Gigi', 'merupakan alat bor berukuran kecil dan berkecepatan tinggi yang digunakan dalam kedokteran gigi untuk membuang bagian gigi yang membusuk sebelum pemberian isi gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(541, 4, 1, '132070102032', 'Bracket Holder', 'merupakan alat atau instrumen kedokteran gigi yang digunakan untuk menahan bracket ortodontik (bracket gigi) dalam posisi tertentu selama proses pemasangan bracket pada gigi pasien.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(542, 4, 1, '132070102033', 'Burnisher', 'merupakan instrumen tangan gigi yang biasanya digunakan pada akhir prosedur atau operasi restorasi gigi', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(543, 4, 1, '132070102034', 'Hand Piece', 'merupakan alat yang digunakan oleh dokter gigi saat prakter berupa mesin pemutar mata bor gigi yang biasa digunakan untuk mengikis gigi/lubang gigi saat proses penambalan atau pemeriksaan gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(544, 4, 1, '132070102036', 'Cirto Jec', 'untuk anastesi poli gigi', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(545, 4, 1, '132070102037', 'Contra Angel', 'merupakan alat yang digunakan oleh dokter gigi saat prakter berupa mesin pemutar mata bor gigi yang mempunyai sudut yang biasa digunakan untuk mengikis gigi/lubang gigi saat proses penambalan atau pemeriksaan gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(546, 4, 1, '132070102038', 'Crown Remover', 'merupakan alat yang digunakan dalam kedokteran gigi untuk melepaskan atau mengangkat mahkota gigi atau prostetik yang melekat pada gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(547, 4, 1, '132070102039', 'Cryer', 'merupakan instrumen bedah yang digunakan dalam kedokteran gigi. Instrumen ini diklasifikasikan sebagai elevator gigi, yang berfungsi untuk mencabut atau mengangkat gigi dari akarnya selama prosedur pencabutan gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(548, 4, 1, '132070102041', 'Curret Lurus/Bengkok', 'merupakan instrumen bedah kedokteran gigi yang digunakan untuk membersihkan atau mengambil jaringan gusi, plak gigi, atau kalkulus dari permukaan gigi atau area di sekitar gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(549, 4, 1, '132070102044', 'Electro Lyte Polisher', 'merupakan alat untuk memberikan hasil akhir yang halus pada bahan-bahan seperti logam porselen atau paduan logam yang digunakan dalam restorasi gigi atau kerangka gigi tiruan.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(550, 4, 1, '132070102045', 'Engine Machine', 'yang dimaksud adalah Engine Dental. perangkat yang digunakan dalam kedokteran gigi untuk menggerakkan berbagai alat dan instrumen yang digunakan selama perawatan gigi. Perangkat ini berfungsi sebagai mesin atau motor untuk menghasilkan tenaga yang diperlukan untuk mengoperasikan bor gigi, pisau bedah, atau alat kecil lainnya yang digunakan oleh dokter gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(551, 4, 1, '132070102046', 'Engine Portable Lengkap', 'Gigi MicroMotor Listrik Portabel MINI Tanpa Sikat 50 Rpm Motor Pemoles', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(552, 4, 1, '132070102047', 'Exkavator', 'Dalam kedokteran gigi, dental excavator adalah instrumen yang digunakan untuk menghilangkan jaringan karies atau bahan tambalan yang rusak dari gigi sebelum melakukan restorasi atau penambalan', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(553, 4, 1, '132070102048', 'Finger Protector', 'merupakan alat untuk melindungi jari tangan dari gigitan pasien pada waktu melakukan tindakan atau perawatan gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(554, 4, 1, '132070102049', 'Hand Stuk/Hand Pice', 'merupakan alat yang digunakan untuk pengeboran gigi berlubang dan plak pada kavitas gigi, serta menghapus sebagian besar enamel.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(555, 4, 1, '132070102052', 'Hendpiece Airbin 400.000 Rpm', 'merupakan alat yang digunakan untuk pengeboran gigi berlubang dan plak pada kavitas gigi, serta menghapus sebagian besar enamel.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(556, 4, 1, '132070102053', 'Hoestuk (Mikrometer)', 'merupakan alat ukur yang digunakan untuk mengukur ketebalan gigi dan lain-lain pada ilmu kedokteran gigi', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(557, 4, 1, '132070102055', 'Intra Olral', 'merupakan alat dengan kamera kecil yang dapat digunakan di dalam mulut, untuk melihat seluruh kondisi di dalam rongga mulut dengan jelas.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(558, 4, 1, '132070102056', 'Jangka', 'merupakan alat yang digunakan untuk mengukur implan gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(559, 4, 1, '132070102058', 'Kaca Mulut/Spigel', 'merupakan kaca kecil berbentuk bundar dan diberi gagang yang dimasukan ke dalam mulut untuk melihat untuk kondisi di dalam rongga mulut.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(560, 4, 1, '132070102059', 'Kikir Gigi', 'merupakan instrumen kedokteran gigi yang digunakan untuk menghilangkan atau merapikan bagian gigi yang tidak diinginkan, misalnya, untuk mengorek, merapikan, atau menghaluskan tepi gigi selama prosedur pembersihan atau perawatan gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(561, 4, 1, '132070102060', 'Knabel Tang (Alat Kedokteran Gigi)', 'merupakan alat untuk memotong tulang tajam/ujung akar pada radix perforasi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(562, 4, 1, '132070102061', 'Knope Sonda', 'fungsi untuk mencari lubang halus pada gigi yang akan dilakukan penambalan', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(563, 4, 1, '132070102065', 'Light Curing Unit', 'Light Curing merupakan alat kedokteran gigi yang menghasilkan cahaya tampak dengan panjang gelombang 400-500 nm. Light Curing sendiri digunakan untuk mengeraskan bahan tambal gigi. Penambalan pada gigi tersebut dilakukan karena terjadinya kerusakan pada struktur gigi (Karies', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(564, 4, 1, '132070102067', 'Mouth Piece', 'merupakan alat medis yang digunakan untuk membantu mempertahankan akses dan visibilitas di dalam mulut pasien selama pemeriksaan atau prosedur kedokteran gigi atau bedah mulut.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(565, 4, 1, '132070102068', 'Motor Gigi Fora Tanpa Handpiece', 'motor gigi tanpa handpiece kecepatan rendah sudut kontra', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(566, 4, 1, '132070102069', 'Mouth Retraktor', 'merupakan alat pembuka mulut yang digunakan untuk menahan mulut dan bibir agar mulut pasien dapat terbuka lebar.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(567, 4, 1, '132070102071', 'Odner Bending', 'Alat bending gigi atau alat lentur gigi digunakan dalam kedokteran gigi untuk membentuk kawat ortodontik atau logam lainnya yang digunakan dalam perawatan ortodontik. Proses pembentukan ini penting untuk menyesuaikan dan menata gigi pasien sehingga mencapai posisi yang diinginkan', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(568, 4, 1, '132070102073', 'Palishing Motor', 'Perangkat ini biasanya berupa handpiece listrik yang digunakan oleh profesional kedokteran gigi untuk melakukan proses pemolesan gigi selama pembersihan gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(569, 4, 1, '132070102075', 'Physiodispenser Implant + Microsurgery', 'merupakan instrumen yang digunakan untuk mengebor dan mempersiapkan situs untuk penempatan implan gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(570, 4, 1, '132070102077', 'Pinset Dental', 'merupakan alat dental instrumen yang berfungsi untuk menjepit kassa, kapas, tampon dan cotton roll', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(571, 4, 1, '132070102079', 'Plastik Instrument', 'merupakan alat instrumen dental yang berfungsi untuk mengambil dan membawa bahan tambalan ke dalam cavita.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(572, 4, 1, '132070102080', 'Press Untuk Dua Kafet', 'merupakan alat yang digunakan untuk mempress kuvet dalam kedokteran gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(573, 4, 1, '132070102083', 'Raspatorium', 'merupakan instrumen kedokteran gigi yang digunakan untuk menghilangkan plak dan karang gigi, terutama dari akar gigi dan permukaan gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(574, 4, 1, '132070102084', 'Semen Stoper', 'merupakan alat instrumen dental yang berfungsi untuk mengambil dan membawa bahan tambalan ke dalam cavita.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(575, 4, 1, '132070102085', 'Shade Guide', 'merupakan alat ukur untuk menentukan warna gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(576, 4, 1, '132070102088', 'Speculum Gigi', 'merupakan alat atau instrumen yang dirancang untuk membuka atau memegang suatu area sehingga memungkinkan pemeriksaan atau intervensi medis. "Gigi" merujuk pada struktur gigi atau daerah di sekitarnya.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(577, 4, 1, '132070102091', 'Tang Ektrasi (Dewasa,Anak)', 'merupakan instrumen yang berperan untuk melakukan pencabutan gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(578, 4, 1, '132070102094', 'Tang Rahang Bawah', 'merupakan instrumen yang berperan untuk melakukan pencabutan gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(579, 4, 1, '132070102095', 'Tang Removable Appliance', 'perangkat ortodontik yang dapat dilepas. Perangkat ini dirancang untuk membantu dalam koreksi gigi atau rahang dan biasanya dapat dipasang atau dilepas oleh pasien.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(580, 4, 1, '132070102096', 'Tang Serba Guna', 'Alat ini dirancang untuk menangani berbagai tugas di bidang kedokteran gigi, termasuk pemeriksaan, perawatan, dan prosedur-prosedur lainnya. contoh Tang Renggang (Explorer),Tang Kuarsa (Scaler),Tang Potong (Excavator) dan lainya', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(581, 4, 1, '132070102097', 'Tang Set', 'merupakan sekelompok instrumen yang terdiri dari berbagai jenis tang yang dirancang untuk tugas-tugas khusus selama perawatan gigi yang digunakan oleh dokter gigi selama berbagai prosedur kedokteran gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(582, 4, 1, '132070102098', 'Tang Spatel/Kawat', 'merupakan alat penekan lidah saat pemeriksaan rongga mulut.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(583, 4, 1, '132070102100', 'Tang Tulang', 'merupakan untuk memotong dan mengembalikan tulang alveolar dan pembuangan jaringan kotor.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(584, 4, 1, '132070102102', 'Vacuum Mixer', 'merupakan peralatan penting untuk mencampur dan menggetarkan bahan investasi dan bahan cetakan di laboratorium gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(585, 4, 1, '132070102106', 'Infus Standard Mac High 2 M', 'merupakan alat yang berfungsi untuk menempatkan cairan infuse yang terhubung dengan pasien.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(586, 4, 1, '132070102107', 'Kompresor Jun Air', 'merupakan alat untuk menghasilkan udara tekan yang disimpan dalam tangki bertekanan tinggi sehingga dapat digunakan setiap saat.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(587, 4, 1, '132070102109', 'Compresor Gigi', 'merupakan alat untuk menghasilkan udara tekan yang disimpan dalam tangki bertekanan tinggi sehingga dapat digunakan setiap saat.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(588, 4, 1, '132070102110', 'Scaller', 'merupakan instrumen kedokteran gigi yang digunakan untuk menghilangkan plak, karang gigi, dan residu makanan dari permukaan gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(589, 4, 1, '132070102112', 'Matrix', 'merupakan perangkat atau alat yang digunakan selama prosedur restorasi gigi untuk membentuk dan memberikan bentuk pada bahan restoratif, seperti resin komposit atau amalgame, ketika dokter gigi sedang memperbaiki gigi yang rusak atau berlubang.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(590, 2, 1, '132050206030', 'Lambang Korpri/Dharma Wanita', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(591, 4, 1, '132070102113', 'Mortir and B Stamper', 'merupakan suatu alat digunakan untuk menghancurkan padatan/ memperkecil ukuran partikel suatu padatan.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(592, 4, 1, '132070102114', 'Pisau Operasi/Scapel', 'merupakan pisau berbilah kecil dan sangat tajam terbuat dari baja karbon berkualitas tinggi yang digunakan untuk pembedahan , pembedahan anatomi , podiatri , dan berbagai seni dan kerajinan, Pisau bedah dapat digunakan sekali pakai atau dapat digunakan kembali.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(593, 4, 1, '132070102115', 'Pisau Crown/Lecron', 'Lecron Dental sering digunakan oleh profesional kedokteran gigi dalam prosedur-prosedur seperti pengisian gigi, pembuatan cetakan gigi untuk restorasi gigi, dan berbagai tindakan lainnya yang memerlukan bahan dan peralatan berkualitas tinggi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(594, 4, 1, '132070102116', 'Bein', 'merupakan alat dental yang berfungsi untuk extraksi gigi yaitu proses pencabutan gigi dari dalam soket dari tulang alveolar.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(595, 4, 1, '132070102118', 'Tang Incicivus Atas Susu', 'merupakan instrumen yang berperan untuk melakukan pencabutan gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
