	(599, 4, 1, '132070102122', 'Tang Incicivus Atas', 'merupakan instrumen yang berperan untuk melakukan pencabutan gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(600, 4, 1, '132070102123', 'Tang Radix Posterior Atas', 'merupakan instrumen bedah gigi yang dirancang khusus untuk menghilangkan atau menangani akar gigi yang tersisa setelah pencabutan gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(601, 4, 1, '132070102124', 'Tang Radix Anterior Atas', 'merupakan instrumen yang berperan untuk melakukan pencabutan gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(602, 4, 1, '132070102125', 'Tang Molar Atas Kiri', 'merupakan jenis tang atau forceps yang dirancang khusus untuk digunakan pada gigi molar (geraham) bagian atas sebelah kiri dalam rahang atas pasien.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(603, 4, 1, '132070102126', 'Tang Molar Atas Kanan', 'merupakan jenis tang atau forceps yang dirancang khusus untuk digunakan pada gigi molar (geraham) bagian atas sebelah kanan dalam rahang atas pasien.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(604, 4, 1, '132070102127', 'Tang Molar Bawah', 'merupakan jenis tang atau forceps yang dirancang khusus untuk digunakan pada gigi molar (geraham) di rahang bawah pasien.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(605, 4, 1, '132070102128', 'Tang Incicivus/Anterir Bawah', 'merupakan Tang ini memiliki desain khusus untuk menggenggam dan memudahkan proses pencabutan gigi incisivus atau anterior bawah.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(606, 4, 1, '132070102129', 'Tang Radix Bawah', 'merupakan jenis tang atau forceps yang digunakan untuk mencabut akar gigi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(607, 4, 1, '132070102130', 'Tang Molar Tiga Atas/Modifikasi', 'merupakan jenis tang atau forceps yang dirancang khusus untuk menggenggam dan mengeluarkan gigi molar ketiga atas pada rahang atas pasien.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(608, 4, 1, '132070102131', 'Alat Espe Eliper', 'merupakan alat yang digunakan dalam prosedur perawatan gigi untuk mengeras dan mengerasakan bahan restoratif seperti resin komposit.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(609, 4, 1, '132070102133', 'Carving Amalgam', 'merupakan salah satu alat yang digunakan dalam melakukan tambalan amalgam.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(610, 4, 1, '132070102134', 'Needle Halder', 'merupakan alat instrumen yang memiliki fungsi sebagai penjepit atau pemegang jarum jahit.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(611, 4, 1, '132070102135', 'Dental Aerosol Suction', 'merupakan alat yang berguna untuk menghisap sisa aerosol gigi yang terhambur setelah menggunakan saliva ejector.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(612, 4, 1, '132070103001', 'Genekologi Tabel', 'jenis meja khusus yang digunakan dalam praktik kedokteran ginekologi untuk menyediakan tempat yang nyaman dan sesuai untuk melakukan pemeriksaan ginekologi pada pasien perempuan.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(613, 4, 1, '132070103002', 'Tromol Gaas', 'merupakan sebuah wadah atau tabung tertutup yang digunakan untuk sterilisasi dan penyimpanan alat-alat medis, seperti perban, kain steril, atau instrumen bedah. Drum ini biasanya terbuat dari logam seperti stainless steel dan memiliki penutup yang dapat ditutup rapat.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(614, 2, 1, '132050206053', 'Rader', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(615, 4, 1, '132070103003', 'Service Model Kit', 'Fungsinya buat latihan resusitasi bayi (merupakan manekin baby CPR, resusitasi jantung paru)', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(616, 4, 1, '132070103004', 'Speculum Model Kit', 'merupakan instrumen medis yang digunakan untuk membuka dan mempertahankan akses ke suatu tubuh atau rongga tertentu. Dalam konteks kedokteran ginekologi, speculum digunakan untuk membuka dinding vagina sehingga dokter dapat melakukan pemeriksaan.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(617, 4, 1, '132070103005', 'Uterin Dressing', 'merupakan alat yang digunakan untuk membantu pemasangan perban atau bahan khusus di dalam rahim (uterus), biasanya setelah tindakan bedah atau intervensi medis seperti pengguguran atau prosedur lainnya.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(618, 4, 1, '132070103006', 'Speculum', 'merupakan instrumen medis yang digunakan untuk membuka dan mempertahankan akses ke suatu tubuh atau rongga tertentu. Dalam konteks kedokteran ginekologi, speculum digunakan untuk membuka dinding vagina sehingga dokter dapat melakukan pemeriksaan.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(619, 4, 1, '132070103007', 'Instrumen Tray', 'merupakan wadah bak injeksi untuk meletakkan spuit / syringe / jarum suntik yang telah berisi obat.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(620, 4, 1, '132070103008', 'Uterin Zone', 'instrumen OB / GYN terbuat dari stainless steel yang digunakan untuk memeriksa dan melebarkan rahim serta mengukur panjang.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(621, 4, 1, '132070103009', 'Extraktur IUD', 'merupakan adalah instrumen penjepit menyerupai gunting dengan gagang panjang dan penjepit kecil pada ujungnya.\n\nAligator atau capit buaya merupakan alat yang digunakan untuk mencabut IUD pada saat IUD sulit untuk dicabut atau benang tidak terlihat.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(622, 4, 1, '132070103010', 'Model Implan', 'merupakan alat yang digunakan untuk membantu dalam pemasangan KB model implan atau susuk.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(623, 4, 1, '132070103011', 'Pengait IUD', 'merupakan alat yang biasa digunakan untuk mengaitkan iud dalam tindakan kebidanan atau obgyn.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(624, 4, 1, '132070103012', 'Trocar Implan', 'merupakan instrumen medis yang digunakan dalam prosedur pembedahan untuk membuat akses ke dalam rongga tubuh atau organ tertentu. Ini biasanya terdiri dari tabung logam yang dilengkapi dengan ujung yang tajam yang dapat menembus kulit dan jaringan.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(625, 4, 1, '132070103014', 'Vasektomi Kit Fix Ing Clam', 'merupakan alat yang digunakan untuk menjepit/memegang saluran sperma (vas deferens) pada saat melakukan prosedur Vasektomi atau operasi(pemotongan) saluran sperma.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(626, 4, 1, '132070104001', 'Minor Surgeri Set', 'merupakan alat yang di gunakan dalam bedah minor atau operasi kecil.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(627, 4, 1, '132070104002', 'Mayor Surgeri Set', 'merupakan instrumen atau peralatan medis lengkap yang digunakan untuk operasi atau pembedahan.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(628, 2, 1, '132050206066', 'Mesin Pedding', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(629, 4, 1, '132070104003', 'Nephrectomy Set', 'merupakan seperangkat instrumen dan peralatan bedah yang dirancang khusus untuk digunakan dalam prosedur nefrektomi. Nefrektomi adalah prosedur bedah untuk mengangkat satu atau kedua ginjal.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(630, 4, 1, '132070104004', 'Circumsision Set', 'merupakan set peralatan/instrumen yang digunakan untuk sunat atau khitan.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(631, 4, 1, '132070104005', 'Orthopedy Set', 'merupakan peralatan atau instrumen yang digunakan oleh dokter dalam melalukan tindakan bedah atau operasi dalam bidang ortopedi (bedah tulang).', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(632, 4, 1, '132070104007', 'Tractheotomy Set', 'merupakan alat yang digunakan pada pasien kondisi darurat medis atau penyakit tertentu yang menyebabkan hambatan jalan nafas atau gagal nafas.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(633, 4, 1, '132070104008', 'Gastro Instestinal Set', 'merupakan peralatan atau instrumen yang digunakan oleh dokter dalam melalukan tindakan bedah organ pencernaan (gastrointestinal) sesuai dengan indikasi medis.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(634, 4, 1, '132070104009', 'Blas And Urology Set', 'merupakan perlatan yang digunakan oleh kedokteran dalam bidang   gangguan yang terkait dengan saluran kemih dan sistem reproduksi pria.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(635, 2, 1, '132050206072', 'Gendola', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(636, 4, 1, '132070104010', 'Thyroidectomy Set', 'merupakan instrument yang digunakan untuk melakukan operasi pada tiroid atau biasa disebut gondok.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(637, 4, 1, '132070104011', 'Anaesthesi App', 'alat yang digunakan untuk menyalurkan gas atau campuran gas anastetik yang aman ke rangkaian sirkuit anestesi yang kemudian dihisap oleh pasien dan membuang sisa gas dari pasien', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(638, 4, 1, '132070104012', 'Operating Table Bedah', 'merupakan meja khusus pasien yang dirancang untuk digunakan selama prosedur bedah atau operasi medis.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(639, 4, 1, '132070104013', 'Electro Surgery Unit', 'merupakan perangkat medis yang digunakan dalam prosedur bedah untuk memotong, mengkoagulasi, atau menghancurkan jaringan menggunakan energi listrik.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(640, 4, 1, '132070104014', 'Endoscopy Unit', 'merupakan alat berbentuk selang yang dilengkapi dengan senter dan kamera di bagian ujungnya yang kemudian dimasukkan ke dalam tubuh guna mendeteksi masalah kesehatan di dalam tubuh.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(641, 4, 1, '132070104015', 'Operating Microscope (Alat Kedokteran Bedah)', 'merupakan alat optik yang digunakan dalam prosedur bedah untuk memberikan pandangan yang diperbesar dan detail pada area operasi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(642, 4, 1, '132070104016', 'Cryo Surgery', 'Unit bedah krio adalah perangkat yang menggunakan suhu dingin atau beku ekstrem dalam pembedahan untuk mengobati jaringan yang sakit atau abnormal dengan melibatkan penerapan teknik krioablasi dalam pembedahan.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(643, 4, 1, '132070104017', 'Ultra Sound Cleaner', 'merupakan alat pembersih yang memanfaatkan gelombang ultrasonic untuk memecah partikel yang menempel.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(644, 4, 1, '132070104018', 'Colposcope (Alat Kedokteran Bedah)', 'merupakan mikroskop listrik besar dengan cahaya terang yang memungkinkan dokter melihat serviks lebih jelas dan dengan pembesaran.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(645, 4, 1, '132070104019', 'Echotonometer', 'Metode Non-Kontak (hembusan udara) mesin automatis yang digerakkan komputer untuk mengukur tekanan bola mata, jenis tonometri ini dilakukan oleh dokter mata dan dokter spesialis mata dan tidak diperlukan obat bius tetes. Dalam metode ini pasien meletakkan dagu pada perangkat dan menatap lurus ke perangkat penguji', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(646, 4, 1, '132070104020', 'Instalasi Gas Medik', 'IGVM adalah sebuah sistem jaringan pipa tembaga untuk menyalurkan medical gas dari ruang sentral gas medis ke ruang pasien di rumah sakit.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(647, 4, 1, '132070104021', 'Laser Coagulator', 'suatu perangkat medis yang menggunakan teknologi laser untuk melakukan koagulasi. Proses koagulasi melibatkan pembekuan jaringan atau darah untuk menghentikan pendarahan atau mencapai tujuan medis lainnya. Dalam konteks medis, laser coagulator umumnya digunakan dalam prosedur bedah atau tindakan medis yang memerlukan kontrol perdarahan', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(648, 4, 1, '132070104022', 'Mobile Operating Lamp', 'merupakan lampu operasi yang dirancang untuk dapat dipindahkan atau dipasang dengan mudah dan digunakan dalam berbagai situasi, terutama di ruang operasi atau fasilitas medis di mana pencahayaan yang baik sangat penting selama prosedur bedah.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(649, 4, 1, '132070104024', 'Mobile X-Ray C-Arm', 'merupakan alat radiologi yang berbentuk seperti huruf C. Penggunaannya dibutuhkan dalam proses operasi untuk melihat gambar atau objek, yang dapat dilihat langsung dengan cara fluoroskopi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(650, 4, 1, '132070104025', 'Abdomal Surgery Set', 'merupakan seperangkat peralatan medis dan instrumen bedah yang khusus digunakan dalam prosedur pembedahan abdomen atau bedah perut', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(651, 4, 1, '132070104026', 'Abdominal Spatulas', 'merupakan jenis instrumen bedah yang digunakan dalam prosedur pembedahan abdomen atau bedah perut. digunakan untuk menggeser, mengangkat, atau memindahkan organ dalam rongga perut dengan hati-hati tanpa merusak jaringan.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(652, 4, 1, '132070104027', 'Instrument Bedah Syaraf', 'merupakan set instrumen bedah yang dirancang khusus untuk digunakan dalam bidang bedah saraf atau neurosurgery.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(653, 4, 1, '132070104029', 'Amputation Surgery Set', 'merupakan seperangkat peralatan bedah yang dirancang khusus untuk prosedur amputasi, yaitu pengangkatan sebagian atau seluruh anggota tubuh, seperti lengan atau kaki.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(654, 4, 1, '132070104031', 'Anuscopy Set', 'merupakan seperangkat peralatan medis yang dirancang khusus untuk melakukan prosedur pemeriksaan anus dan rektum.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(655, 4, 1, '132070104032', 'Operating Teaches Light Strestes', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(656, 4, 1, '132070104033', 'Appendectomy Instrumen Set', 'merupakan seperangkat peralatan bedah yang dirancang khusus untuk digunakan dalam prosedur pembedahan apendektomi/prosedur bedah yang dilakukan untuk mengangkat apendiks, organ kecil yang terletak di ujung usus buntu.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(657, 4, 1, '132070104035', 'Arthroscopy', 'prosedur operasi ortopedi menggunakan metode Minimally Invasive Surgery (pembedahan dengan meminimalkan terjadinya perdarahan) yang dilakukan oleh dokter ahli bedah ortopedi untuk memvisualisasikan, mendiagnosis, merawat dan mengobati masalah di dalam sendi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(658, 4, 1, '132070104036', 'Basic Surgical Instrument', 'merupakan instrumen bedah yang umumnya digunakan dalam berbagai prosedur bedah umum.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(659, 4, 1, '132070104037', 'Biopsi Forceps TB.100 (Olympus)', 'merupakan alat medis yang digunakan dalam prosedur biopsi untuk mengambil sampel jaringan dari organ atau daerah tertentu dalam tubuh.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(660, 4, 1, '132070104038', 'Biopsi Tang', 'merupakan instrumen bedah yang digunakan untuk mengambil sampel jaringan dari tubuh untuk keperluan biopsi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(661, 4, 1, '132070104039', 'Boor Listrik', 'merupakan perangkat medis yang dirancang khusus untuk melakukan prosedur pembedahan di mana pengeboran atau pengukuran diperlukan. Bor listrik medis sering digunakan dalam berbagai bidang bedah, termasuk bedah ortopedi, bedah tulang belakang, dan bedah tengkorak.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(662, 4, 1, '132070104046', 'Ceiling Operating Lamp 7 M Halogen', 'merupakan lampu operasi yang posisinya terpasang di langit-langit ruang operasi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(663, 4, 1, '132070104047', 'Child Basic Instrument Set', 'merupakan instrument yang digunakan untuk operasi bedah khusus pada anak anak.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(664, 4, 1, '132070104048', 'Choledofiberscope', 'merupakan alat endoskopi yang dirancang khusus untuk digunakan dalam pemeriksaan saluran empedu dan kandung empedu.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(665, 4, 1, '132070104050', 'Clips Forcep', 'merupakan alat bedah yang membantu ahli bedah dalam prosedur penjepitan', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(666, 4, 1, '132070104051', 'Colone Fiberscope', 'Merupakan  Alat pemeriksaan kolonoskopi yang digunakan untuk melakukan evaluasi gejala gastrointestinal kedalam usus besar dan rektum', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(667, 4, 1, '132070104055', 'Cutting Mikro Spacement', 'alat untuk pengambilan dan penanganan sampel jaringan mikroskopis untuk pemeriksaan lebih lanjut', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(668, 4, 1, '132070104057', 'Czerny Gall Stone Forceps', 'merupakan alat bedah yang digunakan untuk mengangkat batu empedu (gallstone) selama prosedur pembedahan yang berkaitan dengan kantong empedu atau saluran empedu.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(669, 4, 1, '132070104059', 'Debaky Aortile Aneorysm Clamp', 'merupakan alat bedah yang digunakan untuk menahan aliran darah melalui bagian yang melebar dari aorta sehingga ahli bedah dapat memperbaiki atau menggantikan sebagian aorta yang rusak.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(670, 4, 1, '132070104060', 'Debaky Cardiovascular Scissors', 'merupakan alat bedah yang digunakan untuk memotong jaringan atau struktur dalam prosedur kardiovaskular, seperti memotong jahitan atau melakukan pemotongan presisi pada pembuluh darah.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(671, 4, 1, '132070104068', 'Electric Suction Pump', 'merupakan alat untuk menghisap cairan yang tidak dibutuhkan pada tubuh manusia.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(672, 4, 1, '132070104069', 'Electric Table', 'merupakan meja operasi atau meja pembedahan yang dilengkapi dengan sistem listrik untuk menyesuaikan posisi dan tinggi meja. Meja operasi ini dirancang untuk memberikan fleksibilitas dan kemudahan dalam melakukan berbagai prosedur medis, terutama prosedur pembedahan.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(673, 4, 1, '132070104070', 'Electric Cauter', 'merupakan perangkat medis yang digunakan dalam prosedur bedah untuk menghentikan perdarahan atau mengontrol pendarahan dengan menggunakan panas atau listrik. Alat ini juga dapat digunakan untuk menghilangkan atau merapihkan jaringan tubuh dengan cara mengkoagulasi (menggumpalkan) atau memotongnya.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(674, 4, 1, '132070104071', 'Emergency Trolley', 'merupakan perangkat bergerak yang berisi berbagai peralatan dan obat-obatan yang diperlukan untuk memberikan perawatan medis darurat segera di lokasi kejadian.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(675, 4, 1, '132070104073', 'Examination Light', 'merupakan lampu sorot yang berfungsi untuk menerangi pasien atau objek yang akan diperiksa.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(676, 4, 1, '132070104075', 'Gagang Bisturi/Handput Pisau/Scapel', 'merupakan bagian dari instrumen bedah yang digunakan untuk memegang pisau bedah atau blade (mata pisau).', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(677, 4, 1, '132070104078', 'Gergaji Gips Biasa', 'merupakan perangkat yang dirancang khusus untuk memotong atau memotong dengan tenaga listrigips atau plaster cast yang dipasang pada anggota badan pasien secara cepat dan aman.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(678, 4, 1, '132070104079', 'Gergaji Gips Listrik', 'merupakan perangkat yang dirancang khusus untuk memotong atau memotong dengan tenaga listrigips atau plaster cast yang dipasang pada anggota badan pasien secara cepat dan aman.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(679, 4, 1, '132070104080', 'Gynaecologi Operating Set', 'merupakan seperangkat peralatan bedah yang dirancang khusus untuk digunakan dalam prosedur pembedahan atau tindakan medis di bidang ginekologi. Set ini mencakup berbagai instrumen dan peralatan yang diperlukan untuk melakukan operasi atau intervensi bedah pada organ reproduksi wanita atau masalah kesehatan ginekologis.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(680, 4, 1, '132070104083', 'Heacting Set', 'merupakan satu set instrumen yang digunakan untuk menjahit atau merawat luka.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(681, 4, 1, '132070104084', 'Hend Surgical Set', 'merupakan instrumen bedah yang dirancang khusus untuk digunakan dalam prosedur pembedahan pada tangan. Set ini mencakup berbagai alat yang diperlukan untuk melakukan operasi atau tindakan bedah pada struktur tangan, seperti tulang, sendi, jaringan lunak, atau saraf.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(682, 4, 1, '132070104085', 'Herniotomi Set', 'merupakan seperangkat peralatan bedah yang dirancang khusus untuk melakukan herniotomi', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(683, 4, 1, '132070104086', 'Hernia Instrumen Set', 'seperangkat peralatan bedah yang dirancang khusus untuk digunakan dalam prosedur pembedahan hernia.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(684, 4, 1, '132070104090', 'Intestinal Instrument', 'merupakan instrumen yang dirancang untuk membantu dokter atau ahli bedah dalam melakukan berbagai tugas selama operasi pada saluran pencernaan', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(685, 4, 1, '132070104096', 'Klem Jaringan', 'Klem jaringan atau hemostat adalah alat medis yang dirancang untuk memegang atau menjepit jaringan vaskular atau jaringan lainnya guna menghentikan perdarahan selama prosedur bedah. Hemostat juga dapat digunakan untuk memegang benda-benda kecil atau untuk memanipulasi jaringan selama operasi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(686, 4, 1, '132070104097', 'Klem Pangkal', 'klem yang digunakan dalam prosedur bedah untuk menjepit atau menggenggam jaringan atau struktur tertentu selama operasi. Klem ini membantu dalam memegang jaringan, mengontrol perdarahan, atau memberikan akses yang lebih baik ke area operasi. Klem pangkal juga dapat digunakan untuk menahan atau memanipulasi organ internal selama prosedur bedah.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(687, 4, 1, '132070104098', 'Knabel Tang (Alat Kedokteran Bedah)', 'merupakan alat untuk memotong tulang tajam/ujung akar pada radix perforasi.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(688, 4, 1, '132070104104', 'Kursi Zeis', 'Kursi yang digunakan dokter bedah dalam ruang operasi bedah', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(689, 4, 1, '132070104105', 'Laminectomy Set', 'merupakan seperangkat peralatan bedah yang dirancang khusus untuk melakukan prosedur pembedahan laminectomy yang melibatkan pengangkatan sebagian atau seluruh lamin vertebra (bagian tulang belakang) untuk mengakses dan mengatasi masalah pada sumsum tulang belakang atau saraf spinal.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(690, 4, 1, '132070104106', 'Langen Back Retractor', 'merupakan alat yang digunakan untuk memegang dan menggeser jaringan lunak, memungkinkan ahli bedah untuk melihat dan bekerja pada organ atau struktur yang terletak di bawahnya.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(691, 4, 1, '132070104107', 'Laparatomi Set', 'merupakan seperangkat peralatan bedah yang dirancang khusus untuk digunakan dalam prosedur bedah laparotomi yang melibatkan pembukaan dinding perut untuk mendapatkan akses ke organ-organ di dalam rongga perut.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(692, 4, 1, '132070104108', 'Laparoscopy Cholecystectomy', 'merupakan alat medis yang digunakan dalam prosedur laparoskopi, suatu teknik bedah minimal invasif di mana dokter melakukan operasi dengan memasukkan laparoskop ke dalam tubuh melalui sayatan kecil.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(693, 4, 1, '132070104109', 'Laringecetomi Set', 'Laringektomi adalah prosedur bedah di mana laring (kantung suara) diangkat sebagian atau sepenuhnya.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(694, 4, 1, '132070104112', 'Mainzlo Scisor', 'Instrument yang digunakan untuk instrumen bedah untuk memotong jaringan', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(695, 4, 1, '132070104115', 'Masquito Klem', 'merupakan suatu alat yang digunakan untuk mengontrol pendarahan dari pembuluh darah arteri.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(696, 4, 1, '132070104116', 'Mayo Blake Galls Tone Forceps', 'merupakan pinset bedah yang digunakan untuk pengangkatan batu empedu (gallstones) selama prosedur bedah.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(697, 4, 1, '132070104117', 'Mayo Table Stand Mobile, Stainles Steel', 'merupakan meja yang digunakan sebagai meja untuk meletakkan berbagai instrumen medis saat operasi', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(698, 4, 1, '132070104120', 'Meja Gynokologie', 'merupakan peralatan medis yang dirancang khusus untuk mendukung pemeriksaan dan prosedur medis yang berkaitan dengan kesehatan reproduksi wanita.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(699, 4, 1, '132070104122', 'Meja Operasi Minor', 'merupakan meja bedah yang dirancang khusus untuk mendukung prosedur bedah minor atau tindakan medis kecil yang tidak memerlukan fasilitas operasi besar.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(700, 4, 1, '132070104123', 'Mesh Graft Dermatome', 'merupakan perangkat medis yang digunakan dalam bedah kulit untuk mengambil lapisan tipis kulit atau graft dengan cara tertentu.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(701, 4, 1, '132070104125', 'Micro Surgery Set', 'merupakan alat yang digunakan dalam melakukan tindakan pembedahan mikro.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(702, 4, 1, '132070104128', 'Milculica Pertal Full Cvd', 'Alat Untuk Menjepit Peritoneum Klem Mikulik', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(703, 4, 1, '132070104129', 'Minor Anesthetic Apparatus', 'merupakan perangkat yang digunakan untuk memberikan anestesi pada pasien selama prosedur bedah minor atau tindakan medis kecil.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(704, 4, 1, '132070104130', 'Minor Basic Set', 'merupakan alat yang digunakan dalam tindakan bedah minor atau operasi kecil.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(705, 4, 1, '132070104132', 'Multipurpose Operating Table With Standard Accessories', 'merupakan meja operasi serbaguna yang dilengkapi dengan aksesori standar yang diperlukan untuk mendukung berbagai jenis prosedur bedah.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(706, 4, 1, '132070104136', 'Orthopedi Instrument Set', 'merupakan peralatan atau instrumen yang digunakan oleh dokter dalam melalukan tindakan bedah atau operasi dalam bidang ortopedi (bedah tulang).', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(707, 4, 1, '132070104137', 'Osteotomi Knife (Lengkung,Lurus)', 'merupakan jenis pisau bedah yang dirancang khusus untuk melakukan osteotomi, yaitu prosedur pembedahan yang melibatkan pemotongan atau pemecahan tulang.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(708, 4, 1, '132070104140', 'Perforator 50 Electric', 'Alat yang digunakan petugas medis untuk membuat lubang pada tengkorak kepala saat melakukan tindakan operasi  bedah syaraf', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(709, 4, 1, '132070104141', 'Pinset Bayonet (Alat Kedokteran Bedah)', 'merupakan jenis pinset bedah yang dirancang khusus untuk tujuan tertentu dalam prosedur bedah. Pinset ini memiliki ciri khas ujung yang melengkung atau bengkok, mirip dengan bentuk pisau bayonet. Bentuk ini memberikan pinset keunggulan dalam mengakses area yang sulit dijangkau atau yang memerlukan presisi ekstra.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(710, 4, 1, '132070104142', 'Pinset Klem', 'instrumen bedah yang umum digunakan untuk menahan atau menggenggam jaringan, benda asing, atau bahan bedah selama prosedur medis. Ini merupakan bagian penting dari instrumen bedah dan hadir dalam berbagai jenis dan bentuk, masing-masing dirancang untuk tujuan spesifik.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(711, 3, 1, '132050306006', 'Kursi Tamu di Ruangan Tunggu Menteri/Gubernur/Bupati/Walikota', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(712, 4, 1, '132070104144', 'Plastic Surgery', 'Alat yang digunakan petugas medis untuk melakukan tindakan bedah plastik yang bertujuan untuk memperbaiki, memodifikasi, atau merekonstruksi bagian tubuh tertentu', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(713, 3, 1, '132050306007', 'Meja Tamu Ruangan Tunggu Pejabat Eselon I/Wakil Gubernur/Wakil Bupati/Wakil Walikota', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(714, 4, 1, '132070104145', 'Probe', 'merupakan perangkat yang digunakan untuk menyelidiki atau memeriksa suatu area atau objek tertentu.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(715, 3, 1, '132050306008', 'Kursi Tamu di Ruangan Tunggu Ketua/Wakil Ketua DPRD', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(716, 4, 1, '132070104149', 'Resectoscope Set', 'merupakan seperangkat instrumen bedah yang digunakan dalam prosedur yang disebut reseksi transuretral.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(717, 3, 1, '132050306009', 'Kursi Tamu di Ruangan Tunggu Pejabat Eselon I', NULL, NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
	(718, 4, 1, '132070104150', 'Retractor', 'merupakan alat yang digunakan untuk menjaga jaringan tubuh atau organ agar tetap terpisah dan terbuka selama prosedur bedah.', NULL, NULL, '2026-04-30 03:15:48', '2026-04-30 03:15:48'),
