	(799, 4, 1, '132070105086', 'Forceps Neagle/Kieland/Piper', 'merupakan insstrumen yang digunakan untuk menarik kepala bayi saat proses persalinan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
