	(801, 4, 1, '132070105089', 'HPP Set', 'merupakan alat instrument set yang digunakan dalam tindakan bedah Obstetrik dan ginekologi oleh petugas medis', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(802, 4, 1, '132070105090', 'Hysteroscope', 'merupakan alat yang tersambung ke layar monitor ini dimasukkan ke dalam rahim melalui vagina sehingga dokter bisa memeriksa kondisi bagian dalam rahim melalui layar.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(803, 4, 1, '132070105092', 'Instrument Trolley, Stainless Steel', 'merupakan trolley yang banyak di gunakan di dlaam rumah sakit untuk meletakkan berbagai alat/instrumen medis di klinik/RS/tempat praktek para ahli medis lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(804, 4, 1, '132070105093', 'Kogel Tang', 'merupakan salah satu alat operasi kebidanan atau kandungan yang digunakan untuk menjepit serviks atau leher rahim sesuai dengan posisi yang diinginkan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(805, 4, 1, '132070105095', 'Lampu Gynaecologi', 'merupakan lampu medis yang dirancang khusus untuk memberikan pencahayaan yang optimal selama pemeriksaan atau prosedur medis di bidang ginekologi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(806, 4, 1, '132070105097', 'Longtissu Forcep', 'klem medis yang dirancang untuk menangani jaringan atau organ dalam tubuh manusia atau hewan selama prosedur medis.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(807, 4, 1, '132070105098', 'Mayor Vaginal', 'Sebagai Alat bantu tindakan bedah pada operasi perbaikan organ genital wanita ( Vagina )', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(808, 4, 1, '132070105099', 'Minilaparatomy Instrument Set', 'merupakan alat medis yang dipergunakan untuk membuat sayatan di dinding perut, alat ini juga dipakai untuk mendiagnosis serta mengobati masalah pada organ didalam perut.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(809, 4, 1, '132070105104', 'Oxygen Therapy Set', 'merupakan perangkat yang digunakan untuk memberikan oksigen tambahan kepada pasien yang mengalami kesulitan bernapas atau memiliki kebutuhan oksigen tambahan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(810, 4, 1, '132070105105', 'Partus Instrument Set', 'merupakan set alat bedah yang digunakan oleh petugas medis untuk persalinan normal.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(811, 4, 1, '132070105109', 'Resusitator Untuk Baby Ambu', 'alat untuk memompa oksigen udara bebas yg digunakan untuk memperbaiki fungsi ventilasi dengan cara memberikan pernafasan buatan untuk menjamin kebutuhan oksigen dan pengeluaran gas CO2.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(812, 4, 1, '132070105111', 'Sendok Curret', 'merupakan salah satu instrumen yang digunakan untuk membersihkan sisa janin pada ibu hamil yang keguguran.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(813, 4, 1, '132070105112', 'Sonde Lurus', 'merupakan alat instrument gigi yang digunakan untuk mencari caries serta mengukur kedalamannya, selain itu juga difungsikan untuk memeriksa debrisc, calculus dan memeriksa adanya ferforasi atap pulpa.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(814, 4, 1, '132070105113', 'Sonde Uterus (Alat Kesehatan Kebidanan Dan Penyakit Kandungan)', 'merupakanalat yang biasa digunakan untuk mengukur panjang rahim dalam tindakan kebidanan atau obgyn.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(815, 4, 1, '132070105114', 'Stainless Steel Ware Set', 'set peralatan medis atau instrumen bedah yang terbuat dari stainless steel. Stainless steel digunakan dalam pembuatan instrumen medis karena sifatnya yang tahan karat, tahan terhadap korosi, dan memiliki kekuatan mekanik yang baik. Set peralatan kebidanan atau instrumen bedah stainless steel dapat mencakup berbagai jenis instrumen yang digunakan dalam prosedur kebidanan, operasi, atau perawatan pasien lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(816, 4, 1, '132070105117', 'Tampon Tang', 'merupakan alat yang digunakan untuk memegang sponge dan pembalut, memegang atau mengambil jaringan, dan berbagai kegiatan bedah lain.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(817, 4, 1, '132070105119', 'U S G For Obsgyn', 'merupakan alat yang menggunakan gelombang suara untuk merekam gambar yang ada di dalam tubuh.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(818, 4, 1, '132070105120', 'Uterial Clamp', 'Digunakan untuk penjepit bagian rahim pada tindakan bedah ginekologi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(819, 4, 1, '132070105121', 'Uterine Dressing Forceps 23 Cm Stainless Steel', 'merupakan jenis forceps atau penjepit yang dirancang khusus untuk menangani perban atau kasa yang ditempatkan di dalam atau di sekitar rahim selama prosedur bedah ginekologi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(820, 4, 1, '132070105122', 'Vasikal Vaginal Petrolarepair Set', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(821, 4, 1, '132070105124', 'Alat Periksa Kehamilan', 'merupakan alat untuk mendeteksi kehamilan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(822, 4, 1, '132070105125', 'Scherm', 'pembatas ruangan portabel yang digunakan di ruangan rawat inap rumah sakit. Instrumen tersebut berfungsi sebagai penyekat atau memisahkan satu pasien dengan pasien lainnya di dalam ruangan rawat inap', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(823, 4, 1, '132070105126', 'Toples', 'pada wadah atau tempat penyimpanan yang digunakan untuk menyimpan dan mengorganisir alat-alat kebidanan. Toples ini dapat dirancang untuk menyimpan instrumen kecil, bahan medis, atau perlengkapan kebidanan lainnya. Desain dan ukuran toples dapat bervariasi tergantung pada kebutuhan spesifik dari setiap bidang kebidanan atau praktek medis.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(824, 4, 1, '132070105127', 'Pinset Chirurigris', 'merupakan jenis pinset atau forceps yang digunakan dalam prosedur bedah untuk menangani jaringan, organ, atau bahan bedah lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(825, 4, 1, '132070105129', 'Klem (Alat Kesehatan Kebidanan Dan Penyakit Kandungan)', 'beberapa jenis klem yang digunakan selama prosedur persalinan atau tindakan kebidanan lainnya. Klem ini dirancang untuk membantu mengontrol perdarahan dan memfasilitasi manipulasi tali pusat atau kabel tali pusat selama prosedur persalinan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(826, 4, 1, '132070105133', 'Ekg Manual', 'alat pemantauan kardiotokografi (CTG), yang melibatkan perekaman aktivitas jantung janin dan kontraksi rahim ibu.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(827, 4, 1, '132070106001', 'Ear Diagnosis Set', 'merupakan seperangkat peralatan medis yang dirancang khusus untuk melakukan pemeriksaan atau diagnosis pada telinga.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(828, 4, 1, '132070106002', 'Nose Diagnosis Set', 'merupakan seperangkat peralatan medis yang dirancang khusus untuk melakukan pemeriksaan atau diagnosis pada hidung.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(829, 4, 1, '132070106004', 'Mastoidectomy Set', 'merupakan instrument yang digunakan untuk melakukan operasi untuk mengeluarkan sel-sel diruang berongga, berisi udara ditengkorak belakang telinga', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(830, 4, 1, '132070106005', 'Tonsilectomy Set', 'merupakan seperangkat instrumen bedah yang dirancang khusus untuk melakukan tonsilektomi, yaitu pengangkatan amandel (tonsil).', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(831, 4, 1, '132070106006', 'Audiometer (Alat Kedokteran Tht)', 'merupakan alat medis yang digunakan untuk mengukur ambang pendengaran seseorang.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(832, 4, 1, '132070106007', 'Portable Diagnostic (Alat Kedokteran THT)', 'merupakan peralatan dan perlengkapan medis untuk diagnosa suatu penyakit khususnya pada daerah THT', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(833, 4, 1, '132070106008', 'Soundprocibox (Alat Kedokteran Tht)', 'Box Audiometri untuk tes pendengaran pasien', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(834, 4, 1, '132070106009', 'Diagnostic Lamp (Alat Kedokteran Tht)', 'merupakan senter untuk pemeriksaan pasien berbentuk pulpen. Alat ini biasanya digunakan untuk memeriksa mata, telinga dan hidung pasien.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(835, 4, 1, '132070106010', 'Othoscope', 'merupakan perangkat pemeriksa telinga yang memiliki cahaya dan juga lensa pembesar pada ujungnya, sehingga dapat melihat bagian dalam telinga.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(836, 4, 1, '132070106011', 'ENT Treatment', 'merupakan alat penunjang medis di Poli THT untuk memeriksa bagian telinga, Hidung dan Tenggorokan menggunakan Film Viewer, Head lamp, Spayer, dan Suction Cannula serta kelengkapan lainnnya seperti monitor dan endoscopy system.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(837, 4, 1, '132070106012', 'Sinuscope', 'merupakan alat endoskopi yang digunakan untuk pemeriksaan visual dari saluran hidung dan sinus.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(838, 4, 1, '132070106013', 'Rhinoscope', 'Adalah alat prosedur untuk memeriksa rongga hidung', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(839, 4, 1, '132070106015', 'Laryngoscope', 'merupakan alat medis yang digunakan untuk memeriksa tenggorokan atau laring.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(840, 4, 1, '132070106017', 'Respiration Apparatus', 'beberapa perangkat yang digunakan dalam diagnosis atau pengobatan masalah pernapasan yang melibatkan saluran napas atas. Berikut beberapa perangkat yang umumnya digunakan dalam kedokteran THT:', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(841, 4, 1, '132070106019', 'Evoke Response Potensial (Alat Kedokteran THT)', 'alat untuk pemeriksaan yang mengukur sinyal listrik yang timbul di korteks visual (pusat penglihatan di otak) terhadap rangsangan cahaya', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(842, 4, 1, '132070106020', 'Adenoid Curretes', 'merupakan instrumen bedah yang digunakan untuk mengambil atau mengorek adenoid.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(843, 4, 1, '132070106021', 'Applicator Farrel', 'merupakan alat khusus yang digunakan untuk membawa atau meilit kapas.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(844, 4, 1, '132070106023', 'Audiometer Unit', 'merupakan alat yang digunakan untuk mengetahui tingkat/ambang batas pendengaran seseorang dan jenis gangguannya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(845, 4, 1, '132070106025', 'Basic Ent Instrument Set', 'merupakan seperangkat instrumen bedah yang dirancang khusus untuk digunakan dalam bidang THT (Telinga, Hidung, Tenggorokan) atau Otorhinolaryngology.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(846, 4, 1, '132070106027', 'Binocular Loupe', 'merupakan alat optik yang memberikan pandangan yang lebih rinci dan tajam pada objek atau area tertentu.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(847, 4, 1, '132070106029', 'Bronchoscoop', 'merupakan alat untuk memeriksa paru-paru dan saluran udara', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(848, 4, 1, '132070106033', 'Canule Hidung', 'merupakan perangkat medis yang digunakan untuk memberikan oksigen tambahan kepada pasien. Ini adalah saluran plastik yang terdiri dari dua saluran yang bercabang dan melekat pada hidung pasien.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(849, 4, 1, '132070106039', 'Cap Forcep', 'Forceps adalah sebuah alat berbentuk seperti dua sendok besar yang digunakan untuk menjepit kepala bayi dan menariknya keluar dari vagina', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(850, 4, 1, '132070106047', 'Dessecting Forceps Standar', 'merupakan instrumen bedah yang digunakan untuk memotong, memisahkan, atau mengangkat jaringan saat melakukan disseksi atau pembedahan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(851, 4, 1, '132070106048', 'Diagnostic Audio Meter', 'merupakan alat medis yang digunakan untuk mengukur ambang pendengaran seseorang.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(852, 4, 1, '132070106051', 'Ear Dresing Forcep', 'merupakan instrumen yang digunakan dalam situasi di mana perawatan atau perbanan diperlukan pada telinga, seperti setelah prosedur pembedahan pada telinga atau untuk mengatasi kondisi medis tertentu.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(853, 4, 1, '132070106058', 'Endoscopy Set', 'merupakan kumpulan peralatan dan instrumen medis yang digunakan dalam prosedur endoskopi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(854, 4, 1, '132070106065', 'Head Lamp (Alat Kedokteran THT)', 'merupakan alat bantu penerangan yang digunakan di kepala yang berfungsi sebagai lampu periksa pasien.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(855, 4, 1, '132070106068', 'Kaca Larynx', 'merupakan instrumen medis yang digunakan dalam pemeriksaan laring atau tenggorokan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(856, 4, 1, '132070106069', 'Kidney Tary Inok', 'merupakan alat untuk menempatkan instrumen-instrumen kecil seperti gunting, penjepit, jarum, atau alat lainnya yang mungkin dibutuhkan selama prosedur. Selain itu, tray ini juga dapat digunakan untuk menampung cairan atau bahan yang dihasilkan selama prosedur, seperti darah atau cairan steril', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(857, 4, 1, '132070106078', 'Mikro Laringoscopy', 'merupakan alat kedokteran yang digunakan untuk pemeriksaan visual pada laring, bagian tenggorokan yang berada di bawah faring dan di atas trakea.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(858, 4, 1, '132070106080', 'Modulas Monitoring System', 'merupakan sistem monitor modular yang dirancang untuk memonitor parameter-parameter vital dan data kesehatan pasien secara keseluruhan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(859, 4, 1, '132070106081', 'Mough Gags/With Head', 'merupakan instrumen bedah yang dirancang untuk menjaga mulut pasien terbuka selama prosedur bedah atau pemeriksaan medis di area mulut atau kepala.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(860, 4, 1, '132070106084', 'Myringotomy Set', 'merupakan seperangkat instrumen dan alat bedah yang digunakan untuk melakukan prosedur medis yang disebut myringotomy atau bedah yang melibatkan pembuatan sayatan kecil atau lubang pada gendang telinga.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(861, 4, 1, '132070106085', 'Nasal Canule Adsen', 'merupakan perangkat medis yang umum digunakan untuk memberikan aliran oksigen ke pasien melalui hidung.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(862, 4, 1, '132070106086', 'Nasal Polypus Snare', 'merupakan instrumen bedah yang digunakan untuk mengangkat atau menghilangkan polip hidung.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(863, 4, 1, '132070106087', 'Nasal Specula Sederhana', 'merupakan alat medis yang digunakan untuk memeriksa atau membersihkan saluran hidung.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(864, 4, 1, '132070106088', 'Nasal Speculum', 'merupakan alat medis yang digunakan untuk memeriksa atau membersihkan saluran hidung.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(865, 4, 1, '132070106091', 'Neus Speculum', 'merupakan alat medis yang digunakan untuk memeriksa atau membersihkan saluran hidung.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(866, 4, 1, '132070106092', 'Oesephaguscopy', 'merupakan adalah tabung panjang yang dilengkapi dengan kamera di ujungnya. Alat ini dapat dimasukkan melalui mulut pasien untuk mencapai esofagus.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(867, 4, 1, '132070106094', 'Otoscope Halogen Lamp', 'merupakan alat medis yang digunakan untuk memeriksa telinga dan saluran pendengaran yang dilengkapi dengan lampu halogen, sebuah sumber cahaya yang menggunakan filamen halogen untuk menghasilkan cahaya terang dan intens.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(868, 4, 1, '132070106097', 'Pinset Hidung', 'merupakan pinset yang digunakan untuk mengeluarkan kotoran atau benda di dalam rongga hidung.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(869, 4, 1, '132070106098', 'Pinset Telinga', 'merupakan pinset dengan gigi anatomi untuk penjepit benda asing dalam proses pengeluaran benda asing di telinga.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(870, 4, 1, '132070106100', 'Portable Microwave Therapy', 'Microwave diathermy (MWD) merupakan suatu alat terapi yang bertujuan meningkatkan vasodilatasi pembuluh darah, yang diikuti dengan perbaikan sirkulasi dan metabolisme serta membuat otot-otot menjadi rileksasi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(871, 4, 1, '132070106110', 'Septum Forcep', 'alat medis yang digunakan dalam prosedur bedah hidung untuk memanipulasi atau mengendalikan septum hidung. Septum adalah dinding yang memisahkan rongga hidung menjadi dua bagian. Alat ini memiliki desain yang khusus untuk menjangkau dan memegang septum hidung selama prosedur medis.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(872, 4, 1, '132070106123', 'Telescope (Alat Kedokteran Tht)', 'alat medis yang digunakan oleh profesional kesehatan, termasuk dokter atau perawat, untuk memeriksa telinga dan saluran pendengaran. Otoskop biasanya dilengkapi dengan lampu kecil dan lensa untuk membantu melihat dengan jelas ke dalam telinga.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(873, 4, 1, '132070106124', 'THT Examination Set For Tl Hindra Laringos Cape 847635', 'merupakan seperangkat alat medis yang digunakan untuk memeriksa tenggorokan atau laring (bagian atas saluran pernapasan dan organ berbicara) dengan cara memperkenalkan alat ini melalui mulut pasien.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(874, 4, 1, '132070106125', 'Mangisco 445057 Sicope Biner 845901 (Walf)', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(875, 4, 1, '132070106126', 'Tonsil Artery Forcep', 'merupakan alat yang digunakan untuk pemotongan atau pengankatan tonsil serta untuk memegang/menggenggam tonsil yang akan diangkat selama tonsilektomi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(876, 4, 1, '132070106128', 'Tonsil Dissector/Henke', 'merupakan instrumen bedah tersebut adalah jenis tertentu yang dapat digunakan dalam prosedur pengangkatan amandel (tonsilectomy) atau pembedahan di daerah tonsil.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(877, 4, 1, '132070106130', 'Tonsil Knife', 'merupakan instrumen bedah yang digunakan dalam prosedur pengangkatan amandel (tonsilectomy) atau pembedahan di daerah tonsil. untuk memotong, mengangkat, atau menghilangkan amandel yang membesar atau menyebabkan masalah kesehatan tertentu.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(878, 4, 1, '132070106131', 'Tonsil Seizing Forcep', 'merupakan instrumen bedah yang digunakan dalam prosedur pengangkatan amandel (tonsilectomy) atau pembedahan di daerah tonsil.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(879, 4, 1, '132070106132', 'Tonsil Snare/EVES', 'merupakan instrumen medis yang digunakan dalam prosedur bedah tenggorokan untuk menangkap dan mengangkat tonsil atau amandel', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(880, 4, 1, '132070106133', 'Tonsil Suction Tube', 'merupakan instrumen bedah yang digunakan selama prosedur pengangkatan amandel (tonsilectomy) atau pembersihan area tonsil. Instrumen ini dirancang untuk menghilangkan darah atau cairan lainnya dari area operasi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(881, 4, 1, '132070106136', 'Trachea Retractor Bergigi (1,2,3,4,5,6)', 'merupakan instrumen bedah yang digunakan untuk menjaga agar trakea (tenggorokan) tetap terbuka dan ekspos selama prosedur bedah di daerah leher atau tenggorokan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(882, 4, 1, '132070106137', 'Tracheal Tubes Luer', 'merupakan alat yang digunakan untuk memasukkan saluran udara ke dalam trakea pasien selama ventilasi mekanis atau prosedur bedah.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(883, 4, 1, '132070106138', 'Tracheotomy Set (Alat Kedokteran Tht)', 'merupakan seperangkat instrumen dan peralatan yang digunakan dalam prosedur medis yang disebut trakeotomi. Trakeotomi adalah pembuatan sayatan pada trakea (saluran udara utama yang menghubungkan tenggorokan dengan paru-paru) untuk menciptakan akses langsung ke dalam trakea.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(884, 4, 1, '132070106140', 'Troicart (Alat Kedokteran Tht)', 'merupakan alat medis yang umumnya digunakan dalam bedah untuk membuat akses ke dalam suatu ruang tubuh', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(885, 4, 1, '132070106141', 'Tuning Fork', 'merupakan instrumen musik atau alat ukur getaran yang terdiri dari dua garpu atau tine yang ditempatkan di ujung batang logam.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(886, 4, 1, '132070106143', 'Tympanogram', 'Alat kedokteran THT untuk tes pendengaran', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(887, 4, 1, '132070106146', 'X-Ray Viewer', 'merupakan alat untuk mengamati hasil film X-Ray menggunakan penerangan sinar.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(888, 4, 1, '132070107001', 'Eye Operation Set', 'merupakan seperangkat instrumen dan peralatan medis yang digunakan selama operasi mata atau prosedur bedah mata.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(889, 4, 1, '132070107002', 'Skiascopy Lamp', 'merupakan alat diagnostik yang digunakan oleh profesional mata, terutama optometris dan oftalmologis, untuk mengukur refraksi mata.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(890, 4, 1, '132070107004', 'Ophthalmometer', 'merupakan alat diagnostik yang digunakan dalam bidang optometri dan oftalmologi untuk mengukur kelengkungan kornea mata.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(891, 4, 1, '132070107008', 'Keeler Retinoscope', 'merupakan alat diagnostik yang digunakan untuk menilai refraksi mata dan membantu menentukan resep kacamata atau lensa kontak yang dibutuhkan oleh pasien.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(892, 4, 1, '132070107009', 'Lens Magnifier 15 DPTR', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(893, 4, 1, '132070107010', 'Set Of Trial Lensess In Case With Trial Frame', 'merupakan seperangkat lensa uji yang disajikan dalam suatu kotak (case) dan dilengkapi dengan bingkai uji (trial frame).', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(894, 4, 1, '132070107011', 'Lensometer', 'merupakan alat optik yang digunakan untuk mengukur atau mengetahui kekuatan dioptri pada lensa, titik fokus pada lensa serta power silindris.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(895, 4, 1, '132070107012', 'Bio Microscope (Slit Lamp)', 'merupakan alat diagnostik yang digunakan oleh profesional mata, termasuk optometris dan oftalmologis, untuk memeriksa mata secara mendetail. Alat ini memungkinkan pemeriksaan struktur mata anterior (bagian depan mata), seperti kornea, iris, lensa, dan bagian depan dari vitreous (gel dalam mata).', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(896, 4, 1, '132070107022', 'Maddox With Handle', 'merupakan alat pemeriksaan mata, biasanya terdiri dari batang transparan dengan garis hitam atau filter yang digunakan untuk mengevaluasi dan mengukur kejelasan penglihatan, terutama dalam konteks astigmatisme.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(897, 4, 1, '132070107024', 'Examination Table Adjustable Headrest', 'merupakan meja pemeriksaan yang dilengkapi dengan headrest/sandaran kepala yang dapat disesuaikan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(898, 4, 1, '132070107025', 'Cautery Light Transformer With Handle And 3 Cautery Needles.', 'merupakan alat yang digunakan untuk menghentikan pendarahan, mengangkat jaringan yang tidak diinginkan, atau merapikan luka bedah dengan menggunakan tenaga panas atau listrik.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(899, 4, 1, '132070107028', 'Opthalmoscope Binocyular Indirect Vision', 'merupakan alat diagnostik yang umum digunakan dalam oftalmologi untuk pemeriksaan mata secara menyeluruh, terutama pada bagian belakang mata atau dikenal sebagai fundus.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(900, 4, 1, '132070107030', 'Refractometer (Alat Kedokteran Mata)', 'merupakan alat diagnostik yang digunakan untuk mengukur refraksi mata, yaitu kemampuan mata untuk memfokuskan cahaya pada retina. Alat ini membantu dalam menentukan kekuatan lensa yang diperlukan untuk koreksi mata pasien, terutama dalam meresepkan kacamata atau lensa kontak.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(901, 4, 1, '132070107031', 'Retinoscope', 'alat pemeriksaan mata yang digunakan untuk menentukan kondisi refraksi mata bayi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(902, 4, 1, '132070107032', 'Opthalmoscope', 'suatu alat yang dipakai untuk memeriksa bagian dalam mata', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(903, 4, 1, '132070107033', 'Slit Lamp (Alat Kedokteran Mata)', 'merupakan  alat pemeriksaan yang sering digunakan untuk mendiagnosis penyakit mata', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(904, 4, 1, '132070107034', 'Lensa Meter', 'alat optik yang digunakan untuk mengukur atau mengetahui kekuatan dioptri pada lensa, titik fokus pada lensa serta power silindris', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(905, 4, 1, '132070107035', 'Trial Lens & Frame Set', 'berguna untuk mengukur mata dengan lensa minus, lensa plus, lensa prisma dan lensa cylinder mata yang yang akan di periksa', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(906, 4, 1, '132070107036', 'Opthalmic Laser (Alat Kedokteran Mata)', 'Alat laser treatment untuk mengurangi tekanan intraokular pada pasien glaukoma.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(907, 4, 1, '132070107038', 'Opthalmic Coagulator (Alat Kedokteran Mata)', 'alat medis yang digunakan dalam bidang oftalmologi. Coagulator dapat digunakan untuk prosedur bedah mata untuk melakukan koagulasi atau pembekuan jaringan di area mata tertentu. Ini dapat berguna dalam pengendalian perdarahan atau dalam prosedur pembedahan mata lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(908, 4, 1, '132070107039', 'Operating Microscope (Alat Kedokteran Mata)', 'Alat yang digunakan untuk melihat objek yang terlalu kecil untuk dilihat secara kasat mata dalam fungsinya melihat bagian struktur dalam bola mata seperti anterior dan posterior', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(909, 4, 1, '132070107040', 'Photo Fundus Unit (Alat Kedokteran Mata)', 'digunakan untuk pengambilan gambar pada bagian fundus mata. Tindakan foto fundus mata dapat menangkap gambaran pada daerah di belakang mata yang meliputi retina, saraf mata (saraf optikus), makula, dan pembuluh darah retina', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(910, 4, 1, '132070107041', 'Synoptophore (Alat Kedokteran Mata)', 'sejenis peralatan pemeriksaan dan pelatihan multifungsi yang biasa digunakan dalam oftalmologi dan optometri', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(911, 4, 1, '132070107042', 'Eye Magnet', 'alat untuk mengangkat percikan logam yang mengenai mata', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(912, 4, 1, '132070107043', 'Keratometer', 'salah satu alat pemeriksaan mata yang berguna untuk mengetahui kelengkungan kornea pasien secara detail karena mencangkup kekuatan refraksi dan axis pada kelengkungan kornea pada area tertentu', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(913, 4, 1, '132070107045', 'Tonometer', 'Tonometri adalah tes diagnostik yang mengukur tekanan di dalam mata yang disebut tekanan intraokular (IOP)', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(914, 4, 1, '132070107046', 'Tonograph', 'teknologi pemindaian medis yang digunakan untuk menghasilkan gambar detail tinggi dari struktur internal mata', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(915, 4, 1, '132070107047', 'Kaca Mata Frenzel', 'alat diagnostik yang digunakan dalam bidang kedokteran otolaringologi untuk mengevaluasi gangguan keseimbangan dan gerakan mata', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(916, 4, 1, '132070107049', 'Alloca Camera Multioristhal Swaner With Digital Concane Venteven', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(917, 4, 1, '132070107050', 'Allyn 69-695 Coloscope Fiber Optic', 'perangkat medis yang digunakan untuk memeriksa dengan cermat leher rahim, vagina, dan vulva untuk mendeteksi perubahan abnormal atau tanda-tanda penyakit tertentu, seperti kanker serviks. Fiber optik pada colposcope biasanya digunakan untuk memberikan sumber cahaya yang terang dan fokus pada area yang diperiksa.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(918, 4, 1, '132070107053', 'Binoculair Loupe', 'alat optik yang digunakan untuk memperbesar gambar atau objek. Loupe sendiri adalah jenis kacamata pembesar yang sering digunakan untuk melihat detail kecil pada objek atau permukaan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(919, 4, 1, '132070107054', 'Cataract Instrument Set', 'seperangkat instrumen bedah yang khusus dirancang untuk melakukan operasi pengangkatan katarak, yang disebut juga dengan istilah "cataract surgery.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(920, 4, 1, '132070107055', 'Chalazion Instrument Set', 'alat yang digunakan untuk operasi chalazion pada mata', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(921, 4, 1, '132070107056', 'Chartprojector', 'merupakan alat standar pemeriksaan tajam penglihatan saat ini, namun tidak semua pusat kesehatan memiliki alat ini karena alasan biaya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(922, 4, 1, '132070107058', 'Compact Refraction Unit', 'perangkat atau sistem yang digunakan dalam pemeriksaan mata atau refraksi mata. Refraksi mata adalah proses mengukur dan menentukan kesalahan refraksi mata, seperti miopi (rabun dekat), hipermetropi (rabun jauh), astigmatisme, dan presbiopia (rabun dekat akibat penuaan).', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(923, 4, 1, '132070107060', 'Echoscan, Usg Mata', 'Untuk mengukur kekuatan / power lensa yang akan di pasang pada operasi katarak,mengukur ketebalan kornea dan untuk melihat gambaran retina dengan USG.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(924, 4, 1, '132070107062', 'Fiber Optic Operating', 'alat untuk membantu dokter memperoleh visualisasi yang akurat dan memberikan perlakukan yang lebih tepat. Namun, pastikan untuk selalu berkonsultasi dengan profesional medis untuk informasi lebih lanjut dan pemahaman yang lebih mendalam mengenai penggunaan alat-alat ini dalam konteks kedokteran mata.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(925, 4, 1, '132070107063', 'Fibral Optic Coacial', 'jenis kabel transmisi yang terdiri dari dua konduktor berbeda yang berbagi sumbu yang sama. Kabel koaksial digunakan untuk mentransmisikan sinyal elektrik, dan sering digunakan dalam sistem komunikasi, termasuk televisi kabel, Internet kabel, dan jaringan komunikasi lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(926, 4, 1, '132070107067', 'Head Loupe Halogen', 'digunakan untuk merujuk pada sistem lupa kepala yang dilengkapi dengan sumber cahaya halogen. Penggunaan kombinasi ini mungkin umum dalam berbagai konteks, seperti bedah mikroskopis, pemeriksaan medis, atau pekerjaan presisi di berbagai bidang.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(927, 4, 1, '132070107071', 'Ishihara Blind Test Plate', 'metode yang digunakan untuk mendeteksi gangguan persepsi warna, berupa tabel warna khusus berupa lembaran pseudoisokromatik (plate) yang disusun oleh titik-titik dengan kepadatan warna berbeda yang dapat dilihat dengan mata normal, tapi tidak bisa dilihat oleh mata yang mengalami defisiensi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(928, 4, 1, '132070107073', 'Laser Diode Photocoagulator', 'Aplikasi umum dari Laser Diode Photocoagulator termasuk dalam bidang oftalmologi (mata), di mana alat ini sering digunakan untuk mengobati penyakit mata seperti retinopati diabetik dan glaukoma.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(929, 4, 1, '132070107074', 'Laser Yag Opthamic System', 'YAG laser adalah salah satu jenis laser padat yang menggunakan kristal Yttrium Aluminum Garnet sebagai medium laser.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(930, 4, 1, '132070107075', 'Medication Trally', 'Medication trolley adalah troli atau kereta yang dirancang khusus untuk menyimpan dan mengelola obat-obatan di lingkungan perawatan kesehatan, seperti rumah sakit, klinik, atau fasilitas perawatan jangka panjang.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(931, 4, 1, '132070107076', 'Ocutome Basic System', 'merupakan alat instruments yang digunakan oleh petugas medis untuk melakukan tindakan bedah mata dan perbaikan retina', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(932, 4, 1, '132070107077', 'Direct Optalmoscope (Allyn)', 'Direct Ophthalmoscope adalah instrumen medis yang digunakan oleh dokter mata (oftalmologis) untuk memeriksa bagian dalam mata, khususnya bagian belakang mata seperti retina, saraf optik, dan pembuluh darah. Alat ini memungkinkan pemeriksa untuk melihat bagaimana cahaya memantul atau diserap oleh struktur-struktur dalam mata.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(933, 4, 1, '132070107078', 'In Direct Optamoscope (Allyn)', 'Indirect Ophthalmoscope adalah instrumen yang digunakan dalam pemeriksaan mata oleh dokter mata (oftalmologis) untuk melihat bagian belakang mata secara menyeluruh, terutama area retina dan saraf optik.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(934, 4, 1, '132070107080', 'Opthalmic Operating Set (Alat Kedokteran Mata)', 'Ophthalmic Operating Set bisa merujuk pada kumpulan peralatan bedah yang digunakan dalam prosedur operasi mata. Set ini biasanya dirancang khusus untuk keperluan oftalmologi dan dapat mencakup berbagai instrumen bedah yang diperlukan selama operasi mata', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(935, 4, 1, '132070107081', 'Perimeter', 'Perimeter mata adalah perangkat medis yang digunakan untuk melakukan uji penglihatan perifer atau lapangan pandang. Alat ini digunakan oleh dokter mata atau teknisi optometri untuk mengevaluasi sejauh mana pasien dapat melihat objek atau cahaya di berbagai lokasi dalam lapangan pandang mereka.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(936, 4, 1, '132070107082', 'Phacoemulsi Fication', 'suatu teknik bedah mata yang digunakan untuk mengobati katarak. Katarak adalah kondisi di mana lensa alami mata menjadi keruh, menyebabkan penglihatan kabur atau buruk. Phacoemulsification adalah prosedur pembedahan modern yang umumnya lebih aman dan membutuhkan pemulihan yang lebih cepat dibandingkan dengan metode pembedahan katarak tradisional.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(937, 4, 1, '132070107083', 'Pterium Instrument Set', 'yang digunakan untuk operasi Pytergium pada mata', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(938, 4, 1, '132070107087', 'Snellen Chard', 'adalah sebuah alat atau media optotype yang digunakan dalam pemeriksaan refraksi mata', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(939, 4, 1, '132070107088', 'Sonometri', 'alat yang terdiri dari sebuah kotak kayu yang pada bagian atasnya terdapat seutas senar dan dua buah tahanan geser/sisir geser. Jika senar pada sonometer digetarkan, maka akan terjadi interferensi gelombang (gelombang datang dan gelombang pantul).', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(940, 4, 1, '132070107095', 'Vitrectomy Unit', 'salah satu prosedur operasi pembedahan pada area mata untuk memperbaiki retina rusak.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(941, 4, 1, '132070107096', 'Walter Monitoring Complete Resaring', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(942, 4, 1, '132070107097', 'Retinometer', 'Alat yang digunakan dalam pemeriksaan retinometri dinamakan retinometer. Retinometer sudah biasa digunakan pada pasien dengan kekeruhan lensa seperti katarak, di mana pemeriksaan retinometri dapat memprediksi tajam penglihatan pasien setelah dilakukan operasi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(943, 4, 1, '132070108001', 'Cardiologi Bed Uk 200X60X90', 'tempat tidur atau ranjang yang dirancang khusus untuk pasien dengan masalah kesehatan jantung atau kondisi kardiologis. Tempat tidur ini dirancang untuk memberikan perawatan yang optimal dan memenuhi kebutuhan pasien dengan gangguan jantung.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(944, 4, 1, '132070108002', 'Cholera Set With Cup', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(945, 4, 1, '132070108003', 'Giving Set (Alat Kedokteran Bagian Penyakit Dalam)', 'Infusion Set / infus set adalah peralatan medis untuk memberikan cairan infus ke dalam tubuh pasien melalui intravena untuk memenuhi kebutuhan cairan dan elektrolit serta sebagai tindakan pengobatan dan pemberian makanan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(946, 4, 1, '132070108004', 'Solution Administration Set', 'suatu perangkat medis yang digunakan untuk mengadministrasikan cairan, seperti obat, larutan infus, atau cairan lainnya, ke dalam tubuh pasien. Set administrasi solusi ini sering digunakan dalam berbagai pengaturan perawatan kesehatan, termasuk rumah sakit, klinik, dan fasilitas perawatan kesehatan lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(947, 4, 1, '132070108005', 'Venasectie Set In Metal Case', 'alat pengeluaran darah dari vena, yang biasanya dilakukan untuk keperluan diagnostik atau terapeutik. Sementara itu yang tersimpan dalam kotak metal (besi)', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(948, 4, 1, '132070108006', 'Oxygen Therapy', 'perawatan medis di mana pasien menerima suplai tambahan oksigen untuk meningkatkan kadar oksigen dalam darah. Terapi oksigen digunakan untuk mengatasi atau mengurangi hipoksia, kondisi di mana tubuh tidak mendapatkan cukup oksigen.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(949, 4, 1, '132070108008', 'Needle Punction Sternal/Spinal', 'jarum atau alat punction yang digunakan untuk melakukan tusukan (punction) pada tulang dada (sternal) atau tulang belakang (spinal). Proses ini umumnya berkaitan dengan tindakan medis tertentu, seperti mendapatkan akses ke sumsum tulang belakang (pungsi spinal) atau untuk tujuan tertentu yang melibatkan tulang dada.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(950, 4, 1, '132070108009', 'Urometer', 'perangkat medis yang digunakan untuk mengukur jumlah urine yang dihasilkan oleh seseorang selama periode waktu tertentu. Alat ini biasanya digunakan di lingkungan klinis, rumah sakit, atau pusat perawatan kesehatan untuk memantau output urine pasien.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(951, 4, 1, '132070108010', 'Mag Sonde Rubber', 'Selang nasogastrik atau Nasogastric Tube (NGT), atau biasa dikenal dengan istilah sonde adalah selang khusus yang dimasukkan melalui hidung melewati tenggorokan lalu kerongkongan dan menuju ke dalam perut (lambung). Untuk memastikan posisi selang tidak bergeser, selang diplester di sisi wajah dekat dengan hidung', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(952, 4, 1, '132070108012', 'Metal Catheter', 'Tabung tipis yang dimasukkan ke dalam tubuh untuk mengeluarkan atau memasukkan cairan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(953, 4, 1, '132070108016', 'Elektrocardiograph (ECG) 1 Chanel', 'alat yang digunakan untuk merekam aktivitas listrik jantung dalam satu saluran atau satu lead. Elektrokardiograf adalah alat medis yang umumnya digunakan untuk mendiagnosis gangguan jantung dan mengevaluasi fungsi jantung. Elektrokardiogram menghasilkan grafik yang disebut elektrokardiogram (ECG atau EKG), yang merekam perubahan tegangan listrik di permukaan tubuh sepanjang waktu.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(954, 4, 1, '132070108017', 'Reflek Hammer Stainless Steel', 'suatu alat medis yang digunakan oleh dokter atau profesional kesehatan untuk menguji refleks tendon dan saraf pada pasien. Reflek hammer, juga dikenal sebagai reflex hammer atau tendon hammer, umumnya digunakan dalam pemeriksaan neurologis untuk mengevaluasi respons otot dan sistem saraf perifer.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(955, 4, 1, '132070108018', 'Sterelisator For Instrument Portable', 'alat yang digunakan untuk sterilisasi alat-alat medis atau instrumen di lokasi yang portabel atau berpindah-pindah. Sterilisasi adalah proses untuk menghilangkan atau membunuh semua bentuk mikroorganisme, termasuk bakteri, virus, dan spora bakteri, dari permukaan suatu objek atau instrumen medis.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(956, 4, 1, '132070108020', 'Spirometer (Alat Kedokteran Bagian Penyakit Dalam)', 'digunakan untuk mengukur volume udara yang dihirup dan diekspirasikan oleh paru-paru seseorang. Alat ini umumnya digunakan dalam bidang kedokteran paru-paru dan penyakit dalam untuk mengevaluasi fungsi paru-paru pasien. Pengukuran yang dilakukan dengan spirometer dapat memberikan informasi penting tentang kapasitas paru-paru, laju aliran udara, dan pola pernapasan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(957, 4, 1, '132070108021', 'Suction Thorax', 'prosedur penggunaan alat penyedot (suction) pada rongga dada atau thorax. Suction thorax dapat menjadi bagian dari tindakan medis darurat atau perawatan pasien dengan kondisi tertentu yang memerlukan pengeluaran cairan atau udara dari rongga dada.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(958, 4, 1, '132070108022', 'Stool Fixed Height', 'bangku atau kursi yang memiliki tinggi yang tetap atau tidak dapat diatur. Ini berbeda dengan jenis kursi yang memiliki ketinggian yang dapat disesuaikan atau diatur sesuai kebutuhan pengguna.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(959, 4, 1, '132070108023', 'Bronchoscope (Alat Kedokteran Bagian Penyakit Dalam)', 'alat medis yang digunakan dalam praktik kedokteran bagian penyakit dalam dan kedokteran paru-paru untuk memeriksa dan memeriksa saluran pernapasan bagian dalam. Alat ini dimasukkan melalui hidung atau mulut pasien dan diteruskan melalui trakea (pipa udara) ke bronkus (cabang-cabang saluran udara yang masuk ke paru-paru).', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(960, 4, 1, '132070108024', 'Nebulizer', 'alat medis yang digunakan untuk mengubah obat cair menjadi bentuk kabut halus yang dapat dihirup langsung ke dalam saluran pernapasan. Nebulizer digunakan untuk memberikan obat-obatan ke saluran pernapasan, terutama ke paru-paru, dalam bentuk aerosol atau kabut, sehingga obat dapat dengan mudah diabsorpsi oleh jaringan paru-paru.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(961, 4, 1, '132070108025', 'Ultrasonic Nebulizer', 'nebulizer yang menggunakan gelombang ultrasonik untuk mengubah cairan obat menjadi kabut halus yang dapat dihirup. Alat ini sering digunakan untuk menyampaikan obat-obatan ke saluran pernapasan, terutama ke paru-paru, dalam bentuk aerosol. Nebulizer ultrasonik bekerja dengan memanfaatkan getaran ultrasonik untuk menghasilkan partikel-partikel kecil yang mudah dihirup.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(962, 4, 1, '132070108029', 'Endotracheal Tube', 'tabung fleksibel yang dimasukkan ke dalam saluran napas melalui mulut atau hidung pasien dan ditempatkan di dalam trakea (pipa udara). Prosedur pemasangan endotracheal tube dikenal sebagai intubasi endotrakea dan umumnya dilakukan oleh profesional kesehatan yang terlatih, seperti dokter atau perawat, selama situasi medis tertentu.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(963, 4, 1, '132070108030', 'Ultra Sono Graphy (USG) Internal Medicine', 'teknik pencitraan medis menggunakan gelombang ultrasonik untuk menghasilkan gambar organ dan struktur dalam tubuh manusia. Ini juga dikenal sebagai ultrasonografi atau sonografi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(964, 4, 1, '132070108031', 'Endoscopy, With Cold Light Source', 'ENDO LED cold light source, EI-LS merupakan peralatan endoskopi yang dapat memberikan sumber cahaya yang baik dan jelas secara klinis, memberikan penerangan yang baik, ketika dokter memeriksa, memotret, merekam video organ rongga tubuh.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(965, 4, 1, '132070108033', 'Ventilator Internal Medicine', 'peralatan medis yang digunakan untuk memberikan dukungan pernapasan mekanis kepada pasien yang mengalami kesulitan bernapas atau kegagalan pernapasan. Alat ini juga dikenal sebagai respirator atau mesin ventilasi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(966, 4, 1, '132070108035', 'Ultrasonic Pachymeter (Alat Kedokteran Bagian Penyakit Dalam)', 'alat medis yang digunakan untuk mengukur ketebalan kornea mata menggunakan gelombang ultrasonik. Kornea adalah lapisan transparan di depan mata yang memiliki peran penting dalam pembiasan cahaya ke dalam mata. Pengukuran ketebalan kornea dapat memberikan informasi penting dalam diagnosis dan manajemen beberapa kondisi mata.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(967, 4, 1, '132070108036', 'Duadeno Fiberscope', 'jenis endoskop khusus yang digunakan untuk memeriksa dan memprosedur pada bagian atas saluran pencernaan, khususnya pada duodenum (sebagian dari usus halus yang terletak setelah lambung). Endoskop ini dapat dimasukkan melalui mulut pasien dan diteruskan melalui lambung ke dalam duodenum.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(968, 4, 1, '132070108037', 'Co2 & O2 Monitor', 'perangkat medis yang digunakan untuk mengukur dan memantau konsentrasi gas karbon dioksida dan oksigen dalam pernapasan pasien. Monitor ini umumnya digunakan dalam pengaturan medis, seperti unit perawatan intensif (ICU), ruang operasi, atau unit perawatan pascaoperasi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(969, 4, 1, '132070108038', 'Couch Examination Urology (Alat Kedokteran Bagian Penyakit Dalam)', 'digunakan untuk merujuk pada meja pemeriksaan medis atau tempat tidur pemeriksaan yang digunakan dalam berbagai disiplin ilmu kedokteran untuk melakukan pemeriksaan fisik dan evaluasi pasien. Namun, dalam konteks spesifik penyakit dalam, istilah "Couch Examination" mungkin tidak merujuk pada alat tertentu dalam penyakit dalam.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(970, 4, 1, '132070108039', 'Stool Fixed Hight', 'biasanya digunakan dalam berbagai pengaturan medis atau laboratorium, di mana tinggi kursi yang konsisten dibutuhkan untuk tujuan tertentu, seperti prosedur pemeriksaan atau pengambilan sampel', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(971, 4, 1, '132070108041', 'Suction Unit For Endoscopy', 'dirancang khusus untuk menghilangkan cairan, lendir, atau benda asing dari area pemeriksaan selama prosedur endoskopi. Endoskopi melibatkan penggunaan endoskop untuk memeriksa organ atau saluran dalam tubuh manusia.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(972, 4, 1, '132070108042', 'ESWL', 'prosedur non-invasif yang digunakan untuk menghancurkan batu ginjal atau batu empedu dengan menggunakan gelombang kejut. Prosedur ini memungkinkan pasien untuk menghindari pembedahan konvensional yang lebih invasif.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(973, 4, 1, '132070108045', 'Bed Side Monitor Complete', 'sistem pemantauan medis yang ditempatkan di sekitar tempat tidur pasien di ruang perawatan rumah sakit atau unit perawatan intensif. Sistem ini dirancang untuk memantau parameter vital dan fungsi tubuh pasien secara terus-menerus, memberikan informasi real-time kepada tim perawatan kesehatan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(974, 4, 1, '132070108052', 'Chair For Treadment Unit 4417 Taiju', 'jenis kursi yang dirancang khusus untuk memberikan kenyamanan dan aksesibilitas saat melakukan berbagai jenis prosedur medis atau perawatan. Kursi semacam ini biasanya digunakan dalam pengaturan medis, termasuk di ruang perawatan dokter, klinik, atau fasilitas medis lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(975, 4, 1, '132070108054', 'Cold Light Fontain', 'sistem pencahayaan dingin yang digunakan untuk memberikan pencahayaan pada area tertentu selama prosedur medis atau bedah. Pencahayaan dingin ini membantu memastikan bahwa cahaya yang dihasilkan tidak menghasilkan panas yang dapat merugikan pasien atau peralatan medis.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(976, 4, 1, '132070108055', 'Coaxial Head Light', 'pada lampu kepala yang digunakan dalam berbagai prosedur medis, terutama dalam bedah. Lampu kepala ini dirancang untuk memberikan pencahayaan langsung pada area kerja tanpa membutuhkan tangan tambahan untuk menahan atau mengarahkan sumber cahaya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(977, 4, 1, '132070108057', 'Combibag', 'ventilasi manual yang digunakan dalam resusitasi pasien atau dalam situasi kegawatan medis. Perangkat ini biasanya digunakan oleh tenaga medis terlatih seperti paramedis, petugas ambulans, atau petugas kesehatan darurat lainnya. CombiBag membantu menyediakan ventilasi buatan dengan memberikan aliran udara yang dikontrol ke paru-paru pasien.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(978, 4, 1, '132070108065', 'Defibrilator', 'stimulator detak jantung yang menggunakan listrik dengan tegangan tinggi untuk memulihkan korban serangan jantung.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(979, 4, 1, '132070108068', 'Desinfction Unit', 'suatu fasilitas atau sistem yang dirancang khusus untuk melakukan proses desinfeksi. Desinfeksi adalah tindakan atau proses untuk mengurangi atau menghilangkan mikroorganisme patogen seperti bakteri, virus, dan jamur dari suatu permukaan atau lingkungan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(980, 4, 1, '132070108072', 'Elektrik Sity Protektation Rach', 'sistem perlindungan atau rak yang digunakan dalam lingkungan listrik untuk melindungi peralatan elektronik atau listrik dari berbagai masalah atau bahaya seperti lonjakan tegangan, gangguan arus, atau kelebihan panas.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(981, 4, 1, '132070108074', 'Endoscope P A Vidio Optima', 'alat yang disebut endoskop untuk memeriksa dan memeriksa organ dalam tubuh manusia atau hewan. Endoskop umumnya memiliki kamera di ujungnya yang memungkinkan gambar internal organ ditransmisikan ke layar monitor untuk evaluasi oleh dokter.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(982, 4, 1, '132070108075', 'Endoscope Trolly', 'suatu perangkat beroda yang dirancang untuk menyimpan dan membawa peralatan endoskopi, termasuk endoskop dan aksesori terkait, di sepanjang fasilitas medis seperti rumah sakit atau pusat perawatan kesehatan. Trolley ini dirancang untuk memudahkan transportasi peralatan endoskopi dari satu tempat ke tempat lain dengan aman dan efisien.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(983, 4, 1, '132070108076', 'Endotracheal Set', 'tabung yang dimasukkan ke dalam trakea (pipa udara) melalui mulut atau hidung untuk membantu ventilasi pasien. Endotracheal intubation adalah prosedur medis yang umum dilakukan di ruang gawat darurat atau di ruang operasi untuk menyediakan saluran udara dan mendukung pernapasan pasien. Set endotracheal biasanya mencakup tabung endotracheal, balon penggembung (pada ujung tabung), dan berbagai komponen yang terkait dengan penggunaan dan pemeliharaan tabung tersebut', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(984, 4, 1, '132070108080', 'Find Aid Resusisater For Table Type', 'alat yang digunakan untuk memberikan pertolongan pertama pada pasien yang kesulitan untuk bernafas', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(985, 4, 1, '132070108081', 'Finger Exercise', 'serangkaian latihan atau aktivitas yang dirancang untuk meningkatkan kekuatan, fleksibilitas, dan koordinasi jari-jari tangan. Latihan ini seringkali digunakan untuk pengembangan keterampilan motorik halus, yang melibatkan gerakan-gerakan kecil dan presisi, terutama pada jari-jari.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(986, 4, 1, '132070108088', 'Gastrocape For Wech Allyn Vidio Endoscope', 'jenis endoskop khusus yang digunakan untuk memeriksa saluran pencernaan bagian atas, terutama lambung dan esofagus. Endoskop ini biasanya digunakan dalam prosedur medis seperti esofagogastroduodenoskopi (EGD) untuk mendeteksi kelainan atau kondisi medis di dalam sistem pencernaan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(987, 4, 1, '132070108089', 'Gastroscope & Light Source', 'alat endoskopi yang dirancang khusus untuk memeriksa bagian dalam lambung dan usus halus. Gastroscope memiliki kamera kecil di ujungnya yang memungkinkan dokter atau profesional medis melihat gambar internal organ-organ tersebut. Prosedur pemeriksaan dengan menggunakan gastroscope disebut gastroskopi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(988, 4, 1, '132070108091', 'Glucometer Complete With Glucostic', 'perangkat medis yang digunakan untuk mengukur kadar glukosa (gula) dalam darah. Alat ini umumnya digunakan oleh orang dengan diabetes untuk memantau dan mengelola kadar gula darah mereka. Glucometer bekerja dengan mengambil sampel kecil darah, biasanya dari ujung jari, dan mengukur konsentrasi glukosa dalam darah.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(989, 4, 1, '132070108095', 'Hemodialisis Unit', 'fasilitas atau ruang khusus di rumah sakit atau pusat perawatan kesehatan di mana prosedur hemodialisis dilakukan. Hemodialisis adalah salah satu bentuk pengobatan untuk menggantikan fungsi ginjal yang tidak berfungsi secara optimal. Prosedur ini digunakan untuk membersihkan darah dari limbah dan zat berbahaya ketika ginjal tidak mampu melakukan tugas ini dengan baik.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(990, 4, 1, '132070108096', 'High Speed Stater Type ZS-SUS', 'perangkat yang digunakan untuk memulai atau mengaktifkan peralatan medis yang membutuhkan kecepatan tinggi dalam prosedur medis', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(991, 4, 1, '132070108098', 'Hyper Hypothermia System (Alat Kedokteran Bagian Penyakit Dalam)', 'alat untuk memeriksa kondisi ketika suhu tubuh seseorang melebihi batas normal. Ini bisa terjadi karena berbagai alasan, termasuk demam, dehidrasi, atau paparan panas yang berlebihan. Peralatan atau sistem yang terkait dengan hipertermia mungkin dirancang untuk mengontrol suhu tubuh dan mencegah kenaikan suhu yang berlebihan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(992, 4, 1, '132070108100', 'Infusion Warmer For Blood', 'perangkat yang dirancang khusus untuk menghangatkan darah atau cairan infus yang akan diberikan kepada pasien melalui selang infus. Suhu darah yang masuk ke tubuh pasien harus sesuai dengan suhu tubuh normal agar tidak menyebabkan efek samping atau ketidaknyamanan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(993, 4, 1, '132070108103', 'Lano Premansi Sitimulator Adipraktek EF 502', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(994, 4, 1, '132070108109', 'Medical TV System Welch Allyn Vidio', 'Medical TV System sering digunakan di berbagai lingkungan medis, termasuk ruang operasi, ruang perawatan intensif, atau fasilitas kesehatan lainnya. Tujuan utamanya adalah menyediakan visualisasi yang akurat dan berkualitas tinggi untuk mendukung diagnosis dan perawatan pasien', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(995, 4, 1, '132070108113', 'NVS Vital Sign Monitor (Alat Kedokteran Bagian Penyakit Dalam)', 'perangkat medis yang dirancang untuk mengukur dan memantau parameter vital pasien. Parameter vital umumnya mencakup detak jantung, tekanan darah, suhu tubuh, dan kadar oksigen dalam darah (oksigenasi). Perangkat ini sering digunakan di berbagai lingkungan perawatan kesehatan, termasuk rumah sakit, klinik, atau ruang gawat darurat, untuk memberikan informasi yang penting dalam pemantauan pasien', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(996, 4, 1, '132070108116', 'Pasien Cable Monitoring Kecil Sistem Siscan BST', 'alat berupa kabel yang digunakan khusus untuk alat monitoring siscan bst', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(997, 4, 1, '132070108122', 'Prector Prable Model Ust 507 EP 35', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(998, 4, 1, '132070108124', 'Presual Modul', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(999, 4, 1, '132070108125', 'Proyektor Romad Complet', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1000, 4, 1, '132070108126', 'Pulmonary Exercise Computerized', 'sistem atau perangkat lunak komputer yang digunakan untuk mengukur dan menganalisis fungsi paru-paru dan performa fisik selama latihan. Sistem ini sering digunakan dalam pengujian fungsi paru-paru dan penilaian kebugaran fisik, terutama pada pasien dengan penyakit paru-paru atau kondisi medis tertentu.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1001, 4, 1, '132070108127', 'Pulse Oxymetry', 'metode non-invasif yang digunakan untuk mengukur kadar oksigen dalam darah seseorang. Alat yang disebut "pulsoksimeter" biasanya digunakan untuk melakukan pengukuran ini. Pulsoksimeter sering digunakan di berbagai pengaturan kesehatan, termasuk rumah sakit, klinik, dan bahkan dapat tersedia dalam bentuk perangkat portable untuk digunakan sendiri di rumah.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1002, 4, 1, '132070108136', 'Static/Kinetik Projection Perimeter', 'perangkat yang mengukur lapangan pandang mata dengan memanfaatkan gerakan atau perubahan pada stimulus visual selama pengukuran. Metode ini dapat memberikan informasi tambahan tentang sejauh mana seseorang dapat mendeteksi objek yang bergerak atau perubahan visual di berbagai bagian lapangan pandangnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1003, 4, 1, '132070108140', 'Syringe Pump (Alat Kedokteran Bagian Penyakit Dalam)', 'perangkat medis yang digunakan untuk memberikan dosis obat atau cairan lainnya secara presisi dan terkendali ke dalam tubuh pasien. Alat ini bekerja dengan menggunakan sebuah atau beberapa siring (syringe) yang terhubung ke pompa. Syringe Pump umumnya digunakan di berbagai setting kesehatan, termasuk rumah sakit, pusat perawatan intensif, atau unit perawatan gawat darurat.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1004, 4, 1, '132070108143', 'Temperatur Modul', 'kombinasi sensor suhu dan perangkat keras atau modul pengukuran yang digunakan untuk mengukur suhu dalam suatu sistem. Modul ini mungkin terhubung ke perangkat pengukuran atau pengendalian yang lebih besar', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1005, 4, 1, '132070108147', 'TP.9900Rj - 9900 Trolly Emergency', 'trolley yang berisi peralatan dan obat-obatan untuk keadaan gawat darurat, dimana terjadi perburukan keadaan klinis pasien secara mendadak dan tidak diperkirakan sebelumnya yang dapat segera menyebabkan kematian atau menimbulkan kesehatan jangka panjang sehingga diperlukan intervensi segera', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1006, 4, 1, '132070108149', 'Vital Sign Monitor', 'perangkat medis yang digunakan untuk mengukur dan memantau parameter vital atau tanda-tanda kehidupan seseorang secara terus-menerus. Parameter vital ini memberikan informasi penting tentang fungsi dasar tubuh dan membantu petugas kesehatan dalam pemantauan pasien.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1007, 4, 1, '132070108153', 'Vacum Ectrator (AB)', 'perangkat medis yang digunakan dalam bidang kebidanan dan ginekologi. Vacuum extractor digunakan untuk membantu kelahiran bayi saat proses persalinan. Alat ini bekerja dengan cara memberikan tekanan vakum pada kepala bayi melalui bagian atas kepala yang lebih datar (caput) untuk membantu penarikan bayi keluar selama kontraksi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1008, 4, 1, '132070108155', 'Walker Polding', 'alat bantu berjalan yang dirancang untuk memberikan dukungan dan stabilitas kepada individu yang mungkin mengalami kesulitan berjalan atau mempertahankan keseimbangan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1009, 4, 1, '132070108156', 'Wall Rail Unit', 'Pegangan atau pegangan khusus dapat dipasang di tempat-tempat tertentu di ruang perawatan pasien untuk membantu pasien bergerak, transfer, atau untuk memberikan dukungan saat berdiri atau berjalan. Pegangan ini dapat terpasang di dinding atau lantai.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1010, 4, 1, '132070108157', 'Wright Respirometer', 'perangkat medis yang digunakan untuk mengukur kecepatan aliran udara saat seseorang menghembuskan nafas dengan maksimal. Alat ini sering digunakan untuk memonitor fungsi paru-paru, terutama pada pasien dengan asma atau penyakit paru obstruktif kronis (COPD)', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1011, 4, 1, '132070109001', 'Autopsy Table', 'peralatan khusus yang digunakan untuk melakukan pembedahan mayat atau autopsi. Meja ini dirancang untuk memberikan lingkungan kerja yang efisien dan higienis bagi ahli patologi atau tenaga medis yang melakukan pemeriksaan mayat. Pemilihan desain dan material meja autopsi didasarkan pada kebutuhan kebersihan, sterilisasi, dan kenyamanan selama proses autopsi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1012, 4, 1, '132070109002', 'Motuary Refrigerator', 'perangkat atau peralatan yang dirancang khusus untuk menyimpan jenazah dalam suhu rendah, mencegah pembusukan, dan mempertahankan kondisi mayat selama proses penyelidikan forensik, autopsi, atau persiapan pemakaman. Mortuary refrigerator biasanya ditempatkan di mortuarium atau ruang jenazah di fasilitas kesehatan atau rumah duka.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1013, 4, 1, '132070109003', 'Operating Lamp', 'Lampu khusus yang dirancang untuk memberikan pencahayaan intensif dan fokus selama prosedur bedah di ruang operasi atau bedah. Tujuan utama lampu operasi adalah untuk memberikan pencahayaan yang optimal di area operasi sehingga tim medis dapat melihat dengan jelas dan melakukan prosedur bedah dengan presisi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1014, 4, 1, '132070109004', 'Autopsi Set', 'peralatan khusus yang digunakan dalam proses autopsi, yang juga dikenal sebagai pemeriksaan post mortem. Autopsi adalah prosedur pemeriksaan yang dilakukan pada mayat untuk menentukan penyebab kematian dan untuk memahami lebih lanjut tentang kondisi fisik internal organ dan jaringan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1015, 4, 1, '132070109005', 'Mortuary Racks', 'peralatan yang digunakan di ruang jenazah atau mortuarium untuk menyusun dan menyimpan jenazah. Tujuan utama dari mortuary racks adalah untuk menyediakan tempat yang sesuai dan terorganisir untuk menyimpan jenazah dalam kondisi yang terkendali.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1016, 5, 1, '132070110001', 'Intravenous & Transfusion Needle', 'Alat khusus yang dirancang untuk digunakan dalam penyuntikan intravena (IV) atau transfusi darah. Jarum ini memiliki karakteristik tertentu yang memungkinkannya digunakan dengan aman dan efektif untuk menyuntikkan cairan langsung ke dalam pembuluh darah pasien.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1017, 5, 1, '132070110004', 'Syrnge Case-Syringe Container 2Cc/5cc', 'kontainer atau wadah khusus yang dirancang untuk menyimpan atau membuang jarum suntik (syringe) yang memiliki kapasitas 2cc atau 5cc. Ini termasuk dalam kategori peralatan pengelolaan limbah medis dan dirancang untuk memastikan pembuangan aman dan penyimpanan syringe bekas yang digunakan, terutama yang mengandung bahan berbahaya seperti darah atau obat-obatan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1018, 5, 1, '132070110006', 'Suction Hand Pump', 'alat medis yang dapat menghisap cairan berupa darah, air liur, nanah, lendir atau berbaga jenis cairan yang terbentuk dari proses sekresi tubuh yang dalam kondisi tertentu perlu untuk dihilangkan atau dibersihkan pada saat proses operasi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1019, 5, 1, '132070110007', 'Tangue Depressor Stainless Steel', 'alat yang digunakan oleh tenaga medis, terutama dokter dan perawat, untuk menjaga agar lidah pasien tetap terjepit selama pemeriksaan oral atau prosedur medis tertentu. Ini membantu memudahkan pemeriksaan lidah, langit-langit mulut, dan tenggorokan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1020, 5, 1, '132070110009', 'Premature Infant Incubator', 'perangkat medis yang dirancang khusus untuk merawat dan memberikan perawatan intensif kepada bayi yang lahir prematur atau dengan berat badan rendah. Inkubator ini menciptakan lingkungan yang terkontrol dan stabil untuk membantu bayi prematur berkembang dan tumbuh, menyediakan suhu tubuh yang sesuai, perlindungan terhadap infeksi, dan pengelolaan lingkungan lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1021, 5, 1, '132070110010', 'Waskom 400 Meter Stainless', 'wadah atau tempat cuci tangan yang sering digunakan di berbagai tempat, seperti rumah sakit, laboratorium, atau fasilitas medis lainnya. Waskom biasanya terbuat dari bahan yang tahan terhadap korosi dan mudah dibersihkan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1022, 5, 1, '132070110011', 'Neirbekken Stainless Steel', 'alat untuk mengumpulkan cairan tubuh seperti darah, lendir, atau cairan lainnya selama prosedur medis atau pemeriksaan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1023, 5, 1, '132070110013', 'Water Seal Drainage Set', 'alat yang digunakan untuk berbagai kondisi, termasuk pengelolaan drenase pascaoperasi, pengelolaan pleuritis (peradangan selaput paru-paru), atau dalam pengelolaan cairan di rongga perut (seperti dalam kasus drainase peritoneal).', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1024, 5, 1, '132070110015', 'Lumbal Puncture Needle', 'jenis jarum yang digunakan dalam prosedur lumbar puncture atau spinal tap. Prosedur ini melibatkan penyisipan jarum ke dalam ruang subarachnoid di sekitar sumsum tulang belakang (medulla spinalis) untuk mengambil sampel cairan serebrospinal (CSF) atau untuk memberikan obat-obatan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1025, 5, 1, '132070110016', 'Vanasectie Set', 'alat yang digunakan dalam prosedur pengerokan vena, juga dikenal sebagai venesection atau phlebotomy. Prosedur ini melibatkan pengambilan sejumlah kecil darah dari pembuluh darah vena, biasanya untuk keperluan diagnostik atau terapeutik.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1026, 5, 1, '132070110017', 'Syringe 2cc, 5cc, 10cc, 100cc', 'alat medis yang digunakan untuk mengukur dan menginjeksikan atau menarik cairan dari dalam tubuh. Ukuran syringe diukur dalam mililiter (cc) dan dapat bervariasi sesuai dengan kebutuhan aplikasi spesifik. Berikut adalah beberapa jenis syringe yang umum digunakan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1027, 5, 1, '132070110018', 'Insrumen Tray Stainless Steel 36X30X5 cm', 'Sebuah wadah atau nampan instrumen yang terbuat dari bahan stainless steel dengan ukuran panjang 36 cm, lebar 30 cm, dan kedalaman 5 cm. Wadah ini dirancang khusus untuk menyimpan dan mengatur instrumen medis, seperti pisau bedah, gunting, penjepit, atau instrumen kecil lainnya selama prosedur medis atau pembedahan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1028, 5, 1, '132070110022', 'Ice Compress Cup', 'Cangkir atau wadah yang dirancang khusus untuk mengaplikasikan kompres es pada area tubuh yang memerlukan pendinginan, misalnya untuk meredakan pembengkakan atau mengurangi nyeri.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1029, 5, 1, '132070110024', 'Portable ECG AC/DC 1 Chanel', 'alat Elektrokardiogram (ECG) yang dirancang untuk memberikan pemantauan jantung portabel dengan satu saluran', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1030, 5, 1, '132070110025', 'Pulscoxy Meter', 'Pulse oximetry adalah alat untuk mengukur kadar oksigen (saturasi oksigen) di dalam darah. Alat ini dapat menggambarkan seberapa baik oksigen dikirim ke bagian tubuh yang terjauh dari jantung seseorang', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1031, 5, 1, '132070110026', 'Blood Sedimentation Rate Count Set', 'salah satu metode yang paling umum digunakan untuk mengukur ESR. Proses pengukuran ESR melibatkan pengamatan seberapa cepat sel darah merah mengendap dalam tabung tertentu selama satu jam.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1032, 5, 1, '132070110027', 'Test Tube Box', 'wadah yang dirancang khusus untuk menyimpan dan mengorganisir tabung reaksi. Tabung reaksi adalah tabung silinder kecil yang digunakan dalam laboratorium untuk menampung, mengaduk, atau mereaksikan bahan kimia. Test tube box dirancang untuk memberikan tempat yang aman dan teratur untuk menyimpan tabung reaksi selama penggunaan atau penyimpanan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1033, 5, 1, '132070110030', 'Urinometer (Alat Kedokteran Anak)', 'alat pengukur kepadatan urin atau berat jenis urin. Alat ini digunakan untuk mengukur kepadatan urin, yang dapat memberikan petunjuk tentang konsentrasi zat-zat dalam urin dan dapat membantu dalam evaluasi kondisi kesehatan pasien. Meskipun secara umum digunakan di berbagai pengaturan medis, seperti rumah sakit dan laboratorium, urinometer bukanlah alat yang eksklusif untuk anak-anak saja.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1034, 5, 1, '132070110031', 'Urinoir Salbuminometer', 'tempat pembuangan air seni apat merujuk pada alat yang digunakan untuk mengukur konsentrasi protein albumin dalam suatu cairan, termasuk dalam urin. Albuminometer adalah instrumen laboratorium yang dapat memberikan perkiraan jumlah albumin dalam sampel urin.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1035, 5, 1, '132070110033', 'HB Meter', 'alat yang digunakan untuk mengukur kadar hemoglobin dalam darah. Pengukuran kadar hemoglobin dapat memberikan informasi penting tentang kesehatan darah dan dapat digunakan untuk menilai kondisi seperti anemia atau masalah kesehatan lainnya', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1036, 5, 1, '132070110035', 'Measuring Rods Infat With Rail', 'alat yang digunakan untuk mengukur tinggi bayi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1037, 5, 1, '132070110036', 'Measuring Tape', 'Dalam praktik medis, pengukur panjang sering digunakan untuk mengukur panjang badan pasien, lingkar kepala bayi, atau lingkar perut. Pengukuran ini dapat memberikan informasi penting untuk pemantauan pertumbuhan dan perkembangan pasien.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1038, 5, 1, '132070110037', 'Weight Scale Capacity 120 Kg', 'alat yang digunakan untuk mengukur berat badan seseorang atau pasien', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1039, 5, 1, '132070110038', 'Ascites Trocar', 'alat yang digunakan khusus untuk melakukan prosedur pengeluaran cairan ascites dari rongga peru', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1040, 5, 1, '132070110039', 'Blood Type Viewer Illuminated', 'alat atau perangkat yang digunakan untuk melihat atau mengidentifikasi golongan darah seseorang.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1041, 5, 1, '132070110040', 'Blood Visiting Kit', 'peralatan yang dibutuhkan untuk pengambilan sampel darah, seperti jarum, tabung pengambilan darah, pembalut alkohol, kapas, dan mungkin juga formulir atau label untuk mengidentifikasi sampel. Kit semacam ini biasanya digunakan oleh perawat atau petugas kesehatan bergerak yang melakukan kunjungan ke rumah pasien untuk pengambilan sampel darah', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1042, 5, 1, '132070110041', 'Blood Donor Set', 'perangkat medis yang digunakan dalam proses donor darah. Set ini dirancang untuk menyediakan saluran yang aman dan steril untuk mengambil darah dari donor dan memasukkannya ke dalam kantong darah atau wadah penyimpanan lainnya. Berikut adalah beberapa komponen umum dari Blood Donor Set:', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1043, 5, 1, '132070110043', 'Liver Biopsy Needle', 'jarum yang digunakan dalam prosedur biopsi hati. Biopsi hati adalah prosedur medis di mana sejumlah kecil jaringan hati diambil untuk dianalisis di laboratorium. Ini dapat membantu dokter dalam mendiagnosis berbagai kondisi hati, termasuk penyakit hati kronis, peradangan hati, atau masalah hati lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1044, 5, 1, '132070110044', 'Doek Klem-Towel Forceps', 'sebuah instrumen medis yang digunakan untuk menggenggam atau menahan kain atau handuk selama prosedur medis atau bedah. Instrumen ini dapat digunakan untuk menjaga kebersihan dan kebersihan selama prosedur atau memegang bahan penyerap seperti kain atau handuk untuk menyerap cairan atau menjaga area operasi tetap kering.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1045, 5, 1, '132070110045', 'Small Instrument Sterelizes', 'alat untuk melakukan pembersihan atau penstrelisasian alat2 untuk melakukan operasi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1046, 5, 1, '132070110046', 'Alcohol Cotton Case', 'wadah untuk menyimpan alkohol swab atau kapas yang berisikan alkkohol', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1047, 5, 1, '132070110048', 'Stethoscope Duplex Untuk Anak', 'Alat yang dirancang khusus untuk digunakan pada anak-anak. Stetoskop adalah alat diagnostik yang digunakan oleh profesional kesehatan untuk mendengarkan suara internal tubuh, seperti suara jantung dan pernapasan, dengan lebih jelas. Desain khusus untuk anak-anak memperhitungkan ukuran tubuh dan anatomi anak yang berbeda.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1048, 5, 1, '132070110049', 'Meja Periksa 200X90X100 cc', 'Alat digunakan untuk melakukan pemeriksaan fisik pasien atau prosedur medis di berbagai setting kesehatan, seperti klinik, rumah sakit, atau fasilitas perawatan kesehatan lainnya. Meja periksa dirancang untuk memberikan tempat yang nyaman dan fungsional untuk dokter atau tenaga kesehatan dalam melakukan pemeriksaan pasien.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1049, 5, 1, '132070110050', 'Pocket Lamp Complete With Battery', 'sebuah lampu saku yang dilengkapi dengan baterai. Lampu saku ini dirancang untuk memberikan sumber cahaya portabel yang dapat dibawa dengan mudah di saku atau tas', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1050, 5, 1, '132070110051', 'Combination Weight And Height Scale', 'alat pengukur yang menggabungkan fungsi pengukuran berat badan dan tinggi badan dalam satu perangkat. Alat ini umumnya digunakan di fasilitas kesehatan, pusat kebugaran, atau tempat lain di mana pengukuran berat badan dan tinggi badan secara rutin dilakukan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1051, 5, 1, '132070110052', 'Measuring Infant Baby With Rail', 'alat pengukur yang menggabungkan fungsi pengukuran berat badan dan tinggi badan dalam satu perangkat.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1052, 5, 1, '132070110053', 'Pneumatic Torniquite', 'alat medis yang digunakan untuk memberikan tekanan external pada anggota tubuh, seperti lengan atau kaki, untuk sementara waktu. Fungsinya adalah untuk menghentikan aliran darah ke atau dari suatu area spesifik selama prosedur medis atau bedah.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1053, 5, 1, '132070110054', 'Tubercolusis Diagnostic Kit', 'Alat POCT (Rapid) yang digunakan untuk mengetahui apakah seseorang terindikasi menderita penyakit TBC dengan mengukur antibodi terhadap kuman TBC', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1054, 5, 1, '132070110055', 'Vaccination Needle Set', 'suatu set atau paket yang berisi jarum-jarum yang digunakan untuk memberikan vaksin. Jarum ini dirancang khusus untuk tujuan vaksinasi atau pemberian injeksi imunisasi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1055, 5, 1, '132070110056', 'Vacinating Instrumen Kit', 'suatu set atau paket yang berisi jarum-jarum yang digunakan untuk memberikan vaksin. Jarum ini dirancang khusus untuk tujuan vaksinasi atau pemberian injeksi imunisasi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1056, 5, 1, '132070110057', 'Anuscope', 'alat kedokteran yang digunakan untuk memeriksa atau memeriksa anus dan rektum pasien. Alat ini dirancang untuk memberikan pandangan langsung ke dalam anus dan saluran rektum untuk membantu dalam diagnosis berbagai kondisi medis yang terkait dengan daerah tersebut. Beberapa kondisi yang dapat diidentifikasi atau dinilai melalui penggunaan anuscope meliputi hemoroid, fisura anal, polip, atau tanda-tanda peradangan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1057, 5, 1, '132070110059', 'Nasal Speculum Set', 'kumpulan peralatan medis yang digunakan untuk memeriksa atau menginspeksi saluran hidung', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1058, 5, 1, '132070110062', 'Stomach Evacuator', 'alat yang berfungsi sebagai Cateter untuk menyedot cairan dan eksudat(nanah) pasca operasi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1059, 5, 1, '132070110064', 'Tuberculosis Diagnostic Outfit', 'Alat POCT (Rapid) yang digunakan untuk mengetahui apakah seseorang terindikasi menderita penyakit TBC dengan mengukur antibodi terhadap kuman TBC', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1060, 5, 1, '132070110065', 'Baby Incubator (Alat Kedokteran Anak)', 'perangkat medis yang dirancang untuk memberikan lingkungan yang terkendali, hangat, dan aman bagi bayi yang baru lahir yang mungkin membutuhkan perawatan intensif atau bantuan pernapasan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1061, 5, 1, '132070110066', 'Blue Light', 'terapi cahaya biru yang digunakan untuk mengobati kondisi kesehatan tertentu pada bayi, terutama bayi yang lahir prematur atau memiliki masalah dengan tingkat bilirubin yang tinggi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1062, 5, 1, '132070110067', 'Pediatric/Infant Ventilator (Alat Kedokteran Anak)', 'perangkat medis yang dirancang khusus untuk menyediakan bantuan pernapasan pada bayi atau anak-anak kecil yang mungkin mengalami kesulitan bernapas atau memerlukan dukungan pernapasan tambahan. Alat ini merupakan bagian penting dari peralatan di ruang perawatan intensif neonatal (NICU) atau unit perawatan intensif anak (PICU) di rumah sakit', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1063, 5, 1, '132070110068', 'Pediatric Surveillance Monitor (Alat Kedokteran Anak)', 'perangkat medis yang dirancang khusus untuk memantau parameter vital dan kondisi kesehatan anak-anak. Monitor ini sering digunakan di unit perawatan intensif neonatal (NICU), unit perawatan intensif anak (PICU),', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1064, 5, 1, '132070110069', 'Baby Examination', 'pemeriksaan atau penilaian kesehatan yang dilakukan pada bayi. Pemeriksaan ini biasanya dilakukan oleh profesional kesehatan seperti dokter anak atau perawat khusus untuk memantau pertumbuhan, perkembangan, dan kesehatan bayi secara menyeluruh.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1065, 5, 1, '132070110070', 'Baby Measuring Device', 'alat yang digunakan untuk mengukur berbagai parameter fisik pada bayi, seperti panjang tubuh, berat badan, dan lingkar kepala. Tujuan dari pengukuran ini adalah untuk memantau pertumbuhan dan perkembangan bayi, serta untuk memastikan bahwa mereka berkembang dengan baik sesuai dengan standar kesehatan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1066, 5, 1, '132070110071', 'Ecg Recorder Single Channel', 'perangkat yang digunakan untuk merekam sinyal elektrokardiogram (ECG) pada satu saluran. Elektrokardiogram adalah grafik yang merekam aktivitas listrik jantung selama satu siklus detak jantung. Perekaman ini mencatat perubahan-pengubahan dalam arus listrik yang dihasilkan oleh jantung.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1067, 5, 1, '132070110072', 'Electric Sterilisator', 'perangkat yang digunakan untuk melakukan sterilisasi alat atau barang dengan menggunakan panas atau uap listrik. Sterilisasi adalah proses penghilangan atau inaktivasi semua jenis mikroorganisme, termasuk bakteri, virus, dan spora bakteri', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1068, 5, 1, '132070110074', 'Incubator Transport', 'jenis inkubator yang dirancang khusus untuk memindahkan bayi yang baru lahir, terutama bayi prematur atau bayi yang memerlukan perawatan intensif, dari satu lokasi ke lokasi lain dalam kondisi keamanan dan suhu yang terkendali.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1069, 5, 1, '132070110075', 'Infant Care Unit With Servocontrole', 'alat untuk mempertahankan kondisi suhu lingkungan yang sesuai untuk neonatus (bayi baru lahir)', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1070, 5, 1, '132070110076', 'Infant Incubator Mobile', 'inkubator yang dirancang untuk mobilitas dan portabilitas, khususnya digunakan untuk merawat bayi yang baru lahir. Inkubator bayi adalah perangkat medis yang menciptakan lingkungan yang terkontrol untuk membantu merawat bayi yang lahir prematur atau dengan masalah kesehatan lainnya', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1071, 5, 1, '132070110077', 'Infantcare Centre', 'Fasilitas atau tempat yang menyediakan perawatan dan pengasuhan untuk bayi dan anak-anak prasekolah. Fasilitas ini biasanya dirancang untuk merawat anak-anak dari usia beberapa bulan hingga sekitar dua tahun, yang merupakan periode', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1072, 5, 1, '132070110078', 'Maag Sonde Premature For Baby', 'alat dimasukkan melalui hidung dan turun ke perut. Ini adalah prosedur non-invasif yang umum digunakan pada bayi prematur.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1073, 5, 1, '132070110079', 'Mercurial Sphymamometer With Baby Cuff', 'tensimeter digital alat yang digunakan untuk mengukur tekanan darah secara otomatis, tidak perlu menggunakan stetoskop untuk mendengarkan nadi dah hasil lebih akurat dibandingkan yang manual', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1074, 5, 1, '132070110080', 'Pulseoxy Meter', 'alat yang di gunakan untuk mengukur denyut nadi pasien', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1075, 5, 1, '132070110082', 'Refflex Hammer', 'alat yang digunakan untuk mengetes reflesisifitas dari si pasien', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1076, 5, 1, '132070110083', 'Stethoscope For Infant/Baby', 'alat medis yang dirancang khusus untuk mendengarkan suara dari organ dalam tubuh bayi atau anak kecil. Stetoskop ini memiliki ukuran yang lebih kecil dan kadang-kadang dilengkapi dengan fitur khusus untuk memudahkan pemeriksaan pada pasien bayi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1077, 5, 1, '132070110084', 'Swaddling Table', 'meja yang digunakan utnuk menempatkan bayi pada posisi tidur secara sempurna tidak miring', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1078, 5, 1, '132070111001', 'Basin Kidly, Stainless, Length 25 cm', 'wadah atau basin tertentu yang memiliki bentuk yang mirip dengan ginjal manusia. Basin ini biasanya digunakan dalam konteks perawatan kesehatan atau prosedur medis, terutama dalam lingkungan rumah sakit atau fasilitas kesehatan lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1079, 5, 1, '132070111002', 'Bed Pan For Child', 'alat yang dirancang khusus untuk membantu anak-anak yang tidak dapat menggunakan toilet secara mandiri karena alasan kesehatan atau keadaan tertentu', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1080, 5, 1, '132070111003', 'Bed Pan For Adult 310 mm Complete', 'alat yang dirancang khusus untuk membantu orang dewasa yang tidak dapat menggunakan toilet secara mandiri karena alasan kesehatan atau keadaan tertentu', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1081, 5, 1, '132070111005', 'Hammer Reffex', 'alat dalam menilai integritas dan respons sistem saraf. Pemeriksaan refleks martil umumnya melibatkan beberapa lokasi, termasuk lutut, siku, pergelangan tangan, dan lainnya', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1082, 5, 1, '132070111006', 'Thermometer Oral, Air Raksa', 'alat yang digunakan untuk mengukur suhu tubuh manusia melalui mulut (oral). Ini termasuk dalam kategori termometer tradisional yang menggunakan air raksa sebagai zat termometer.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1083, 5, 1, '132070111007', 'Thermometer Rectal, Air Raksa', 'Termometer rektal digunakan untuk mengukur suhu tubuh dengan menyisipkan termometer ke dalam rektum. Metode ini seringkali lebih akurat untuk mengukur suhu inti tubuh', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1084, 5, 1, '132070111008', 'Diagnostic Set In Case Metal Stainless Steel', 'peralatan diagnostik yang terbuat dari logam stainless steel dan disusun dalam suatu kotak atau casing. Set ini biasanya digunakan oleh profesional medis, seperti dokter atau perawat, untuk melakukan pemeriksaan fisik dan diagnostik pada pasien.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1085, 5, 1, '132070111009', 'Blood Pressure Meter With Pump Raksa', 'Alat Pengukur Tekanan Darah dengan Pompa Raksa" mengacu pada alat pengukur tekanan darah tradisional yang menggunakan raksa (merkuri) sebagai medium pengukuran. Alat ini juga dikenal sebagai sphygmomanometer raksa atau tensiometer raksa', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1086, 5, 1, '132070111011', 'Hypodermic Needle (Alat Kedokteran Poliklinik)', 'jarum medis yang digunakan untuk menyuntikkan cairan ke dalam tubuh atau menarik cairan dari tubuh. Jarum ini digunakan dalam berbagai prosedur medis, seperti pemberian obat, pengambilan sampel darah, atau penyuntikan untuk tujuan diagnostik atau terapeutik.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1087, 5, 1, '132070111016', 'Leather Case For Metal Container', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1088, 5, 1, '132070111019', 'Spiritus Burner', 'alat yang digunakan untuk membakar atau menghasilkan nyala api dengan menggunakan bahan bakar berupa spiritus (alkohol etil). Alkohol etil atau spiritus umumnya digunakan sebagai sumber bahan bakar karena mudah terbakar dan memberikan nyala api yang cukup stabil.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1089, 5, 1, '132070111020', 'Sterilizer For Spirit Heating', 'alat yang dirancang untuk memanaskan spiritus (alkohol etil) sebagai metode untuk melakukan sterilisasi pada alat atau peralatan medis, laboratorium, atau barang-barang lain yang memerlukan kondisi steril.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1090, 5, 1, '132070111021', 'Dressing Forceps', 'penjepit yang dirancang khusus untuk digunakan dalam prosedur perawatan luka atau pemakaian dressing (pembalutan). Forceps ini membantu tenaga medis atau perawat untuk memegang dan menangani perban, kasa medis, atau dressing lainnya dengan presisi selama perawatan luka.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1091, 5, 1, '132070111022', 'Stirilizer For Syringe', 'peralatan yang dirancang khusus untuk melakukan proses sterilisasi pada alat penyuntik atau jarum suntik (syringe).', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1092, 5, 1, '132070111024', 'Khocer Heam Forceps 10,5 cm', 'Alat yang digunakan dalam prosedur bedah untuk mengontrol perdarahan dari pembuluh darah kecil.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1093, 5, 1, '132070111025', 'Halsread Mosquito Forceps 12,5 cm', 'Alat untuk mengklip, memegang, dan menghentikan perdarahan dari pembuluh darah kecil selama berbagai prosedur medis, terutama dalam pembedahan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1094, 5, 1, '132070111026', 'Rocherter Pean Forceps 10,5 cm', 'Alat yang digunakan dalam prosedur medis, terutama untuk mengendalikan perdarahan dari pembuluh darah kecil selama pembedahan atau tindakan medis lainnya', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1095, 5, 1, '132070111028', 'Hegar Mayo\'S Needle Holder 15 cm', 'alat bedah yang penting dalam menjahit dan menangani jarum selama prosedur pembedahan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1096, 5, 1, '132070111029', 'Burning Tongue Pressure', 'alat untuk mengukur  kumpulan gejala dengan karakteristik rasa panas dan sakit pada satu atau beberapa struktur mulut dengan mukosa', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1097, 5, 1, '132070111030', 'Operating Scissors Blunt Sharp', 'Alat  yang digunakan dalam prosedur medis dan bedah. Scissors ini memiliki satu mata yang tumpul (blunt) dan satu mata yang tajam (sharp). Mereka umumnya digunakan untuk memotong jaringan lunak, seperti kulit, kain, atau jaringan organ selama prosedur bedah.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1098, 5, 1, '132070111031', 'Knife Handle', 'Pegangan pisau bedah memiliki desain yang memungkinkan pengguna untuk melakukan pemotongan atau tindakan bedah dengan kontrol yang baik.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1099, 5, 1, '132070111032', 'Scalpels Blades', 'komponen yang dapat dilepas dari pisau bedah dan digunakan untuk melakukan pemotongan atau insisi selama prosedur medis atau bedah', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1100, 5, 1, '132070111033', 'Foster Sponge Holding', 'jenis klem yang digunakan dalam bidang bedah untuk menahan spon atau kasa medis selama prosedur', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1101, 5, 1, '132070111034', 'Scissors Gips', 'gunting yang dirancang khusus untuk memotong atau memotong bahan gips atau bahan penyangga yang sering digunakan dalam penataan tulang atau perlakuan cedera ortopedi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1102, 5, 1, '132070111035', 'Universal Scissors', 'Gunting ini biasanya memiliki desain yang serbaguna dan dapat digunakan dalam berbagai situasi, seperti keperluan rumah tangga, kantor, atau laboratorium.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1103, 5, 1, '132070111036', 'Tray Plain 250X1 30X30 Ml', 'nampan medis sederhana atau nampan steril yang digunakan dalam prosedur medis atau bedah.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1104, 5, 1, '132070111037', 'Mayo Hegar\'S Holder', 'Alat untuk memegang jarum atau instrumen lain yang digunakan dalam jahitan pada prosedur bedah, terutama dalam bidang obstetri dan ginekologi. Alat ini dirancang untuk memberikan pegangan yang stabil dan nyaman kepada operator selama tindakan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1105, 5, 1, '132070111038', 'Retractor Langeback', 'Alat yang digunakan untuk membuka dan mempertahankan akses ke daerah operasi selama prosedur bedah. Retractor ini dinamai dari ahli bedah Jerman bernama Bernhard von Langenbeck yang memainkan peran penting dalam perkembangan bedah.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1106, 5, 1, '132070111042', 'Cheron Sponge Forceps', 'alat medis yang digunakan dalam prosedur bedah untuk menahan dan membersihkan spons atau kasa medis dari area operasi. Alat ini biasanya memiliki pegangan yang panjang dan runcing, dengan rahang yang melengkung untuk memungkinkan pegangan yang kuat dan akurat pada spons atau kasa medis.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1107, 5, 1, '132070111043', 'Dissecting Forceps', 'alat bedah yang digunakan untuk memegang dan memanipulasi jaringan, organ, atau benda lain selama prosedur pembedahan atau diseksi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1108, 5, 1, '132070111044', 'Suture Mochel Set', 'alat untuk menjahit luka bekas operasi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1109, 5, 1, '132070111045', 'Tape Measure', 'pita pengukur yang digunakan untuk mengukur panjang atau dimensi bagian tubuh atau area tertentu selama pemeriksaan fisik, penilaian klinis, atau prosedur medis.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1110, 5, 1, '132070111046', 'Bowl Solution', 'alat yang di gunakan untuk menaruh beberapa alat bekas operasi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1111, 5, 1, '132070111047', 'Sheating Plastic', 'alat yang di gunakan untuk menutup atau mengcover tempat tidur pasien', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1112, 5, 1, '132070111049', 'Suture Cotton Sice', 'alat yang digunakan untuk mengelap pasca operasi atau sedang dilakukan operasi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1113, 5, 1, '132070111051', 'Scissors Bandage', 'alat yang di gunkan untuk menggunting perban pasien', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1114, 5, 1, '132070111053', 'Head Mirror', 'perangkat medis yang digunakan oleh profesional kesehatan, khususnya dokter, untuk mengarahkan cahaya ke area yang sedang diperiksa', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1115, 5, 1, '132070111057', 'Dressing Jar', 'wadah yang digunakan untuk menyimpan dan menyediakan larutan antiseptik atau cairan lainnya yang digunakan dalam perawatan luka atau perban.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1116, 5, 1, '132070111058', 'Lodin Cup', 'wadah khusus yang digunakan untuk menyimpan dan menyediakan larutan iodin (iodine solution), seperti tincture of iodine, povidone-iodine, atau larutan iodin lainnya', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1117, 5, 1, '132070112001', 'Crude', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1118, 5, 1, '132070112002', 'Wheel Chair (Alat Kesehatan Rehabilitasi Medis)', 'alat kesehatan rehabilitasi medis yang dirancang untuk membantu individu yang memiliki keterbatasan mobilitas atau kesulitan berjalan. Kursi roda menyediakan sarana transportasi yang aman dan nyaman bagi orang-orang yang tidak dapat berjalan atau memiliki keterbatasan gerak yang signifikan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1119, 5, 1, '132070112006', 'Hardstock', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1120, 5, 1, '132070112007', 'Tiang Keseimbangan', 'alat yang di gunakan untuk melatih keseimbangan pasien pasca operasi ata penyembuhan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1121, 5, 1, '132070112009', 'Audio Treater Portable', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1122, 5, 1, '132070112010', 'Balance Beam Set', 'seperangkat peralatan atau alat yang digunakan untuk melatih keseimbangan dan koordinasi tubuh. Balance beam, atau balok keseimbangan, adalah perangkat yang umumnya digunakan di dunia olahraga, kebugaran, atau terapi fisik untuk mengembangkan keterampilan motorik dan keseimbangan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1123, 5, 1, '132070112011', 'Bath Wirl Pool', 'bak mandi yang dilengkapi dengan sistem pancuran air yang mampu menciptakan pusaran air di dalamnya. Sistem ini menciptakan efek pusaran atau gerakan berputar pada air di sekitar tubuh pengguna. Bath whirlpool biasanya digunakan untuk memberikan pengalaman mandi yang relaks dan juga memiliki beberapa manfaat kesehatan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1124, 5, 1, '132070112012', 'Compression Therapy', 'bentuk perawatan medis yang melibatkan penggunaan tekanan terkontrol pada bagian tertentu dari tubuh, terutama pada kaki atau lengan. Tujuan utama dari compression therapy adalah untuk meningkatkan aliran darah, mengurangi edema (pembengkakan), dan mendukung pemulihan dari berbagai kondisi kesehatan, terutama yang terkait dengan masalah peredaran darah.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1125, 5, 1, '132070112013', 'Electro Stimulation & Analgesia', 'bentuk terapi elektrostimulasi yang bertujuan untuk meredakan nyeri. Terapi ini melibatkan penggunaan arus listrik untuk merangsang saraf atau otot sebagai metode pengelolaan nyeri.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1126, 5, 1, '132070112014', 'Electro Tilt Table', 'meja kemiringan elektro adalah perangkat medis yang digunakan untuk merangsang perubahan posisi tubuh secara bertahap dari posisi horizontal ke posisi vertikal. Meja ini dilengkapi dengan sistem motor atau elektromekanis yang memungkinkan pengaturan kemiringan secara otomatis. Posisi vertikal dapat diatur sesuai dengan kebutuhan pasien atau tujuan tertentu.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1127, 5, 1, '132070112015', 'Ergocycle', 'istilah yang sering digunakan untuk menyebut sepeda latihan atau sepeda statis yang dirancang khusus untuk penggunaan dalam konteks rehabilitasi fisik atau pengukuran kinerja olahraga. Ergocycle sering digunakan dalam pengaturan medis dan terapeutik untuk membantu pemulihan pasien atau untuk melakukan pengukuran dan penilaian kinerja dalam pengaturan olahraga atau kebugaran.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1128, 5, 1, '132070112016', 'Exercise Bicysles', 'alat kebugaran yang dirancang untuk mensimulasikan pengalaman bersepeda tanpa perlu bergerak ke lokasi tertentu. Ada beberapa jenis sepeda latihan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1129, 5, 1, '132070112017', 'Exercise Equipment', 'alat-alat yang dirancang khusus untuk digunakan dalam berbagai jenis latihan fisik dan kebugaran. Peralatan kebugaran ini dirancang untuk membantu orang berlatih, meningkatkan kekuatan, daya tahan, fleksibilitas, dan kesehatan secara umum.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1130, 5, 1, '132070112018', 'Exercise Pulley Weight', 'metode latihan kebugaran yang melibatkan penggunaan katrol untuk mengangkat beban atau hantaran tertentu. Sistem katrol memungkinkan pemakai untuk merasakan beban yang lebih berat daripada yang mereka dapatkan secara langsung.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1131, 5, 1, '132070112019', 'Exercise Treadmil', 'alat kebugaran atau mesin olahraga yang dirancang untuk mensimulasikan berjalan atau berlari di tempat. Treadmill adalah perangkat yang umum digunakan di pusat kebugaran, rumah, atau fasilitas kesehatan untuk memberikan latihan kardiovaskular yang efektif dan dapat dilakukan secara dalam ruangan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1132, 5, 1, '132070112020', 'Faradic-Galvanic Therapy', 'kombinasi arus faradic dan galvanic dapat memberikan manfaat yang berbeda, seperti merangsang otot (faradic) dan meredakan nyeri atau merangsang penyembuhan (galvanic).', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1133, 5, 1, '132070112023', 'Finger Muscle Therapy', 'serangkaian latihan atau terapi yang dirancang khusus untuk memperkuat, meningkatkan fleksibilitas, atau memulihkan otot-otot di sekitar jari dan tangan. Terapi ini dapat direkomendasikan untuk berbagai kondisi, termasuk cedera, gangguan saraf, atau untuk meningkatkan kinerja olahraga dan fungsi sehari-hari.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1134, 5, 1, '132070112024', 'Hydro Therapy', 'latihan fisik yang melibatkan penggunaan air untuk mempromosikan kesehatan dan pemulihan. Terapi ini dapat dilakukan di berbagai lingkungan, termasuk kolam renang, bak mandi, atau dengan menggunakan berbagai bentuk perangkat air.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1135, 5, 1, '132070112025', 'Infra Red & Ultraviolet', 'Alat digunakan untuk meredakan nyeri otot, meningkatkan sirkulasi darah, dan mempromosikan penyembuhan jaringan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1136, 5, 1, '132070112027', 'Laser Therapy', 'bentuk terapi fisik yang menggunakan cahaya laser atau cahaya koheren yang terfokus untuk merawat atau meredakan kondisi medis tertentu. Teknik ini juga dikenal dengan sebutan Low-Level Laser Therapy (LLLT) atau Cold Laser Therap', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1137, 5, 1, '132070112028', 'Lymphatic Physiotherapy', 'bentuk fisioterapi khusus yang difokuskan pada sistem limfatik. contoh Manual Lymphatic Drainage,Manajemen Edema,Pemulihan Pascaoperasi dan lainya', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1138, 5, 1, '132070112029', 'L.F. Electro Therapy', 'alat terapi dengan memberikan arus bolak-balik pada tubuh manusia yang frekuensinya lebih dari 500.000 putaran per detik, akan tetapi tidak memberikan rangsangan terhadap saraf sensorik dan motorik', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1139, 5, 1, '132070112030', 'Micro Wave Diathermy', 'suatu bentuk terapi diatermi yang menggunakan gelombang mikro dalam spektrum frekuensi radio untuk menghasilkan panas dalam jaringan tubuh. Terapi diatermi sendiri merupakan metode yang digunakan untuk meningkatkan suhu jaringan tubuh dengan menghasilkan panas melalui energi elektromagnetik.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1140, 5, 1, '132070112031', 'Modular Electro Therapy', 'Sistem terapi elektro ini dapat digunakan dalam berbagai pengaturan klinis atau rumah sakit untuk tujuan rehabilitasi, meredakan nyeri, atau perawatan kesehatan lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1141, 5, 1, '132070112032', 'Parafin Bath', 'metode terapeutik yang menggunakan parafin wax (lilin parafin) untuk merawat tangan, kaki, atau area tubuh lainnya. Ini adalah bentuk perawatan panas yang digunakan dalam fisioterapi dan perawatan kesehatan untuk beberapa tujuan, termasuk meredakan nyeri, meningkatkan sirkulasi darah, dan meningkatkan fleksibilitas.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1142, 5, 1, '132070112034', 'Quadricerps Table', 'Latihan Pergelangan Tangan Rotary" adalah jenis latihan yang dirancang untuk memperkuat dan meningkatkan fleksibilitas pergelangan tangan dan otot-otot sekitarnya. Latihan semacam ini dapat bermanfaat bagi orang yang ingin meningkatkan kekuatan, koordinasi, dan rentang gerak pergelangan tangan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1143, 5, 1, '132070112035', 'Rotary Wrist Exercise', 'jenis latihan yang dirancang untuk memperkuat dan meningkatkan fleksibilitas pergelangan tangan dan otot-otot sekitarnya. Latihan semacam ini dapat bermanfaat bagi orang yang ingin meningkatkan kekuatan, koordinasi, dan rentang gerak pergelangan tangan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1144, 5, 1, '132070112036', 'Rowing Machine', 'Alat ini berguna untuk melatih jantung layaknya treadmill. Akan tetapi, fungsinya bisa lebih luas, yaitu meningkatkan masa otot pada bagian lengan, paha, kaki, dan massa betis.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1145, 5, 1, '132070112037', 'Short Wave Diathermy', 'suatu metode fisioterapi yang menggunakan gelombang elektromagnetik berfrekuensi tinggi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1146, 5, 1, '132070112038', 'Shoulder Whell Exercise', 'rehabilitasi yang sering digunakan untuk memperbaiki rentang gerak dan kekuatan otot pada sendi bahu. Latihan ini dapat bermanfaat bagi orang yang mengalami cedera bahu, operasi bahu, atau kondisi lain yang memerlukan pemulihan fungsi bahu.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1147, 5, 1, '132070112040', 'Therapeutical Nerve & Muscle Situmulation', 'Stimulasi saraf dan otot terapeutik adalah pendekatan terapeutik yang menggunakan aliran listrik untuk merangsang saraf dan otot. Tujuannya adalah untuk mempengaruhi sistem saraf dan otot dengan cara tertentu untuk mendapatkan manfaat terapeutik.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1148, 5, 1, '132070112041', 'Traction Unit', 'fisioterapi yang digunakan untuk memberikan terapi traksi. Terapi traksi adalah metode yang digunakan untuk merenggangkan tulang belakang atau sendi lainnya dengan menarik atau memperpanjang bagian tubuh tertentu.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1149, 5, 1, '132070112042', 'Tread Mill Treatment', 'Pemeriksaan treadmill, atau yang juga dikenal dengan sebutan stress test, merupakan pemeriksaan yang dilakukan guna melihat kinerja jantung .', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1150, 5, 1, '132070112043', 'Ultra Saound Theraphy', 'Alat yang menggunakan gelombang suara frekuensi tinggi untuk meningkatkan produksi panas jaringan dalam sehinga dapat mengurangi rasa nyeri', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1151, 5, 1, '132070112044', 'Ultrasonic Theraphy Unit', 'perangkat medis yang dirancang untuk memberikan terapi ultrasonik kepada pasien sebagai bagian dari perawatan fisioterapi atau rehabilitasi. Terapi ultrasonik menggunakan gelombang suara frekuensi tinggi (ultrasonik) untuk merangsang jaringan dalam tubuh dan mempromosikan proses penyembuhan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1152, 5, 1, '132070113001', 'Electro Encephalograph (Alat Kedokteran Neurologi (syaraf))', 'alat medis yang digunakan untuk merekam aktivitas listrik otak. Alat ini mencatat sinyal-sinyal listrik yang dihasilkan oleh sel-sel saraf di otak, dan hasilnya disebut elektroensefalogram.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1153, 5, 1, '132070113003', 'Electro Myograph', 'perangkat medis yang digunakan untuk merekam aktivitas listrik otot. Ini adalah alat diagnostik yang membantu dalam mengevaluasi aktivitas otot, mengukur respons otot terhadap rangsangan, dan membantu dalam diagnosis kondisi neuromuskular.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1154, 5, 1, '132070113004', 'Electro Stimulator (Alat Kedokteran Neurologi (syaraf))', 'perangkat medis yang menggunakan arus listrik untuk merangsang atau merespons sistem saraf. Dalam konteks kedokteran neurologi, stimulator elektrik dapat digunakan untuk berbagai tujuan, termasuk pengelolaan nyeri, terapi fisik, rehabilitasi, dan penanganan kondisi neurologis tertentu.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1155, 5, 1, '132070113005', 'Patient Monitor', 'perangkat medis yang digunakan untuk memantau parameter vital pasien secara terus-menerus. Perangkat ini dirancang untuk memberikan informasi tentang kondisi kesehatan pasien kepada tim medis.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1156, 5, 1, '132070113007', 'Electro Surgery (Alat Kedokteran Neurologi (syaraf))', 'metode bedah yang menggunakan arus listrik untuk memotong, menghancurkan, atau mengkoagulasi jaringan. Ini adalah teknik umum yang digunakan dalam berbagai spesialisasi kedokteran, termasuk dalam bidang neurologi atau kedokteran syaraf', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1157, 5, 1, '132070114001', 'Electrocardiograph', 'perangkat medis yang digunakan untuk merekam aktivitas listrik jantung. Prosedur ini dikenal sebagai elektrokardiografi. Elektrokardiogram (EKG atau ECG) adalah grafik atau rekaman visual dari aktivitas listrik jantung selama satu siklus detak jantung', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1158, 5, 1, '132070114002', 'Operating Table Jantung', 'meja operasi yang dirancang khusus untuk prosedur bedah jantung. Meja operasi ini memiliki fitur dan fungsionalitas yang dirancang untuk mendukung kebutuhan unik dari operasi jantung dan prosedur kardiovaskular lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1159, 5, 1, '132070114003', 'Oxygen Tank', 'perangkat penyimpanan gas oksigen yang digunakan untuk menyediakan suplai oksigen tambahan kepada individu yang mengalami kesulitan bernapas atau membutuhkan dukungan oksigen selama periode waktu tertentu.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1160, 5, 1, '132070114004', 'Central Gas', 'sistem distribusi gas medis yang dirancang untuk menyediakan sumber gas medis ke berbagai area dalam fasilitas kesehatan seperti rumah sakit atau pusat perawatan kesehatan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1161, 5, 1, '132070114005', 'Central Suction (Alat Kedokteran Jantung)', 'Alat yang digunakan untuk menyedot cairan atau bahan lainnya dari berbagai area dalam fasilitas kesehatan. Central suction biasanya terdiri dari pompa penyedot utama yang terhubung dengan jaringan pipa dan terminal penyedot di berbagai lokasi, seperti kamar operasi atau ruang perawatan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1162, 5, 1, '132070114006', 'Heart Rate Monitor', 'sistem yang digunakan untuk mengukur dan memonitor detak jantung seseorang dalam waktu nyata. Tujuan utama dari Heart Rate Monitor adalah memberikan informasi tentang tingkat detak jantung atau denyut nadi seseorang selama berbagai kegiatan fisik atau kondisi tertentu. Pemantauan detak jantung dapat memberikan informasi penting tentang kesehatan dan tingkat kebugaran seseorang.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1163, 5, 1, '132070114007', 'Repiration Monitor (Alat Kedokteran Jantung)', 'alat yang digunakan untu memmonitor pernapasan digunakan untuk memantau dan merekam pola pernapasan seseorang selama periode waktu tertentu', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1164, 5, 1, '132070114008', 'Blood Pressure Monitor (Alat Kedokteran Jantung)', 'Perangkat medis yang digunakan untuk mengukur tekanan darah seseorang. Tekanan darah adalah ukuran kekuatan yang diberikan oleh darah terhadap dinding pembuluh darah, dan pengukurannya memberikan informasi penting tentang kesehatan kardiovaskular seseorang.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1165, 5, 1, '132070114011', 'Blood Gas Analyzer (Alat Kedokteran Jantung)', 'perangkat medis yang digunakan untuk mengukur konsentrasi gas dalam darah arteri. Pemantauan gas darah membantu memberikan informasi penting tentang fungsi pernapasan dan keseimbangan asam-basa dalam tubuh', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1166, 5, 1, '132070114012', 'Cabinet AC & DC Defibrilator Cardioc And Recorder Seward', 'defibrilator adalah perangkat yang digunakan untuk mengembalikan irama jantung yang tidak normal dengan memberikan lompatan listrik atau rangsangan ke jantung', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1167, 5, 1, '132070114016', 'Cardiac Chair', 'kursi khusus yang dirancang untuk memberikan kenyamanan dan dukungan kepada pasien yang menderita penyakit jantung atau menjalani prosedur medis terkait jantung.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1168, 5, 1, '132070114017', 'Cardiac Massage Unit', 'alat bantu atau perangkat otomatis yang membantu dalam melaksanakan pemijatan jantung secara efektif selama prosedur CPR. Ini bisa termasuk defibrilator otomatis eksternal (AED) yang dilengkapi dengan fitur pemijatan jantung otomatis atau perangkat serupa.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1169, 5, 1, '132070114018', 'Cardiac Output', 'jumlah volume darah yang dipompa oleh jantung dalam satu menit. Untuk mengukur Cardiac Output, digunakan beberapa alat yang dikenal sebagai alat pengukur atau monitor Cardiac Output. Salah satu metode umum untuk mengukur Cardiac Output adalah menggunakan teknik thermodilution atau metode bioimpedansi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1170, 5, 1, '132070114019', 'Cardiac Recorder', 'perekam jantung merupakan perangkat medis yang digunakan untuk merekam dan memonitor aktivitas listrik jantung secara terus-menerus atau dalam periode waktu tertentu', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1171, 5, 1, '132070114020', 'Cardiac Resuscitator', 'perangkat medis yang digunakan untuk menyediakan bantuan atau intervensi dalam situasi kegawatan kesehatan, khususnya pada keadaan henti jantung atau gagal napas.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1172, 5, 1, '132070114021', 'Defibrilator Phisiocontrol', 'perangkat medis yang dirancang untuk memberikan kejutan listrik kepada pasien dengan aritmia jantung serius, seperti fibrilasi ventrikel atau takikardia ventrikel yang menentukan. Defibrillator adalah perangkat yang sangat penting dalam upaya resusitasi kardiovaskular darurat dan dapat digunakan di rumah sakit, ambulans, fasilitas kesehatan, dan lingkungan medis lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1173, 5, 1, '132070114022', 'ECG 3 Channel', 'perangkat jenis perekaman elektrokardiografi yang melibatkan tiga saluran atau derivasi dalam proses pengukuran aktivitas listrik jantung. Elektrokardiogram adalah tes non-invasif yang merekam impuls listrik yang dihasilkan oleh jantung selama siklus detak jantung', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1174, 5, 1, '132070114023', 'Echo Cardiograph System', 'sistem yang digunakan dalam pemeriksaan medis yang dikenal sebagai echocardiography atau echo cardiogram. Echocardiography adalah teknik pencitraan medis yang menggunakan gelombang suara (ultrasound) untuk menghasilkan gambar struktur dan fungsi jantung', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1175, 5, 1, '132070114024', 'Echo Cateter Isolation', 'kateter yang digunakan dalam prosedur diagnostik atau intervensi yang melibatkan teknologi ultrasonografi, seperti echocardiography (echo jantung). Kateter ini dapat digunakan untuk mendapatkan gambaran ultrasonik dari organ dalam tubuh, seperti jantung, pembuluh darah, atau organ lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1176, 5, 1, '132070114025', 'Echocolor Doppler', 'perangkat medis yang digunakan untuk memperoleh gambaran visual tentang pergerakan aliran darah di dalam tubuh manusia dengan menggunakan teknologi Doppler ultrasonik', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1177, 5, 1, '132070114026', 'EKG Elektro Photo Cardiograph For Recording Elektro And', 'alat yang digunakan untuk mendeteksi gangguan irama jantung, kerusakan jantung, dan masalah kardiovaskular lainnya. Ini adalah alat diagnostik penting dalam bidang kardiologi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1178, 5, 1, '132070114027', 'EKG Monitor', 'tes diagnostik yang merekam aktivitas listrik jantung sepanjang periode waktu tertentu menggunakan elektroda yang ditempatkan pada kulit. EKG memberikan gambaran tentang bagaimana impuls listrik bergerak melalui jantung selama siklus detak jantung', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1179, 5, 1, '132070114028', 'EKG Simulation', 'perangkat yang digunakan untuk mensimulasikan sinyal elektrokardiogram (ECG) seperti yang ditemukan dalam aktivitas listrik jantung manusia. Alat ini digunakan untuk melatih dan mendidik para profesional kesehatan, teknisi, atau mahasiswa dalam membaca dan menafsirkan hasil ECG tanpa harus menggunakan sinyal nyata dari pasien', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1180, 5, 1, '132070114029', 'Electrolyt Analyzer', 'perangkat medis yang digunakan untuk mengukur konsentrasi elektrolit dalam sampel darah, serum, atau plasma. Elektrolit adalah ion bermuatan listrik yang terlibat dalam berbagai fungsi fisiologis dalam tubuh, termasuk regulasi tekanan osmotik, keseimbangan asam-basa, dan fungsi otot dan saraf.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1181, 5, 1, '132070114030', 'Exercise Treadmil Test', 'uji fungsional yang dilakukan untuk mengevaluasi bagaimana jantung seseorang bereaksi terhadap latihan fisik atau stre', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1182, 5, 1, '132070114032', 'Holter Monitor', 'Perangkat medis berukuran kecil yang digunakan untuk memantau aktivitas jantung seseorang selama periode waktu tertentu, biasanya 24 hingga 48 jam.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1183, 5, 1, '132070114035', 'Mobile X-Ray & Image Int.', 'Sistem pencitraan medis yang dapat dipindahkan atau dibawa ke tempat tidur pasien atau ke lokasi di mana pasien berada. Sistem ini memungkinkan pemeriksaan sinar-X dilakukan secara portabel, yang sangat berguna dalam situasi darurat, di unit perawatan intensif (ICU), atau ketika pasien tidak dapat dipindahkan ke departemen radiologi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1184, 5, 1, '132070114037', 'Pace Maker', 'Perangkat medis yang ditanamkan ke dalam tubuh untuk membantu mengendalikan irama jantung. Fungsinya adalah memberikan impuls listrik ke jantung untuk memastikan bahwa detak jantung tetap teratur dan sesuai dengan kebutuhan tubuh.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1185, 5, 1, '132070114038', 'Phonocardiograph', 'Perangkat atau alat medis yang digunakan untuk merekam suara atau bunyi jantung dan pembuluh darah. Alat ini menghasilkan grafik yang disebut phonocardiogram (PCG) yang merepresentasikan getaran suara yang dihasilkan oleh aktivitas jantung.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1186, 5, 1, '132070114041', 'Temporay Fase Maker', 'Alat untuk membuat frekuensi denyut jantung menjadi normal baik yang disebabkan jantung pasien tersebut kurang baik', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1187, 5, 1, '132070114042', 'Treadmill Spedroge 2-4 16 KMA Elektrical System Walking', 'peralatan kebugaran yang dirancang untuk mensimulasikan berjalan atau berlari di tempat.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1188, 5, 1, '132070114043', 'Treadmill/On (Giken)', 'peralatan olahraga yang digunakan untuk berjalan atau berlari di tempat. Mesin ini umumnya dilengkapi dengan conveyor belt yang dapat diatur kecepatannya', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1189, 5, 1, '132070114044', 'Tunturi Sepeda', 'sepeda latihan atau sepeda statis yang dirancang untuk digunakan di dalam ruangan dan biasanya tidak bergerak dari tempatnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1190, 5, 1, '132070115001', 'Angiography Unit', 'perangkat medis yang digunakan untuk prosedur angiografi. Angiografi adalah teknik diagnostik yang digunakan untuk memvisualisasikan pembuluh darah dan sirkulasi darah dalam tubuh, khususnya arteri dan vena.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1191, 5, 1, '132070115002', 'Apron', 'mantel yang dirancang khusus untuk dipakai oleh tenaga medis, termasuk dokter, perawat, atau profesional kesehatan lainnya, sebagai bagian dari pakaian kerja mereka', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1192, 5, 1, '132070115003', 'Automatic Film Processing Unit', 'perangkat yang digunakan dalam radiografi medis untuk mengembangkan dan memproses film radiografi secara otomatis setelah pemotretan sinar-X.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1193, 5, 1, '132070115004', 'Bucky Table/Tomography', 'perangkat di dalam ruang radiologi yang dirancang untuk menopang dan menyediakan permukaan yang stabil untuk pasien selama pemotretan radiografi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1194, 5, 1, '132070115005', 'Bucky Stand', 'perangkat di dalam ruang radiologi yang dirancang untuk menopang pasien tegak lurus berdiri dan menyediakan permukaan yang stabil untuk pasien selama pemotretan radiografi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1195, 5, 1, '132070115006', 'Cassete Film (Alat Kedokteran Radiodiagnostic)', 'medium tradisional yang digunakan untuk merekam gambar internal tubuh, yang dihasilkan oleh sinar-X atau sumber radiasi lainnya', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1196, 5, 1, '132070115008', 'General Purpose X-Ray Unit', 'perangkat medis yang digunakan untuk memproduksi gambar sinar-X untuk berbagai keperluan diagnostik medis. Unit ini dirancang untuk menyediakan gambar radiografi umum dari berbagai bagian tubuh manusia, membantu dalam diagnosis dan evaluasi kondisi kesehatan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1197, 5, 1, '132070115009', 'X-Ray Tomography Unit', 'Alat untuk melakukan tomografi sinar-X. Tomografi sinar-X, atau CT (Computed Tomography), adalah teknik pencitraan medis yang menghasilkan gambar potongan tubuh manusia atau bagian tubuh tertentu dalam bentuk potongan tipis.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1198, 5, 1, '132070115010', 'Grid', 'perangkat yang digunakan dalam radiografi untuk meningkatkan kualitas gambar radiografi dengan mengurangi efek penyebaran radiasi yang tidak diinginkan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1199, 5, 1, '132070115011', 'Inten Sifying Screen', 'perangkat yang dipasang dalam kaset yang berfungsi untuk mengubah berkas sinar x yang menembus objek menjadi cahaya tampak dan akan berinteraksi dengan film membentuk  bayangan laten', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1200, 5, 1, '132070115012', 'MRI (Magnitic Resonanse/Imaging)', 'teknik pencitraan medis yang menggunakan medan magnet dan gelombang radio untuk membuat gambar yang sangat rinci dari struktur internal tubuh manusia. MRI tidak melibatkan sinar-X dan merupakan teknologi pencitraan yang non-ionisasi, sehingga tidak memerlukan paparan radiasi ionisasi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1201, 5, 1, '132070115014', 'X-Ray Mobile Unit', 'pemindai sinar-X yang dirancang untuk mobilitas dan portabilitas. Unit ini memungkinkan pemeriksaan sinar-X di berbagai lokasi, termasuk di luar ruangan atau di tempat-tempat di mana akses ke fasilitas radiologi tetap tidak mungkin atau tidak praktis.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1202, 5, 1, '132070115015', 'Radiology Unit (Rongent)', 'untuk melakukan pemeriksaan radiografi atau rontgen. Radiografi, atau pemeriksaan rontgen, adalah metode pencitraan medis yang menggunakan sinar-X untuk menghasilkan gambaran internal tubuh manusia atau objek lainnya', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1203, 5, 1, '132070115016', 'Basic Radiography System', 'suatu sistem atau perangkat dalam bidang radiografi yang dirancang untuk melakukan pemeriksaan radiografi atau rontgen dasar. Sistem ini mencakup berbagai komponen yang diperlukan untuk menghasilkan dan memproses gambar radiografi dari berbagai bagian tubuh manusia atau objek lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1204, 5, 1, '132070115017', 'General Examination', 'pemeriksaan fisik menyeluruh yang dilakukan oleh seorang dokter atau profesional kesehatan untuk mengevaluasi kesehatan dan kondisi umum pasien', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1205, 5, 1, '132070115020', 'Mamography X-Ray Unit', 'Perangkat khusus yang dirancang untuk melakukan pemeriksaan mammografi. Mammografi adalah teknik pencitraan medis yang menggunakan sinar-X untuk menghasilkan gambar payudara', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1206, 5, 1, '132070115021', 'Tomograph Unit', 'teknik pencitraan medis yang menghasilkan gambar potongan tubuh dalam tiga dimensi. Pencitraan tomografi memungkinkan visualisasi yang lebih rinci dan mendalam dari struktur internal tubuh.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1207, 5, 1, '132070115022', 'Angiography', 'teknik pencitraan untuk menghasilkan gambaran struktur pembuluh darah di dalam tubuh manusia. Prosedur ini biasanya digunakan untuk mengevaluasi kondisi pembuluh darah, termasuk arteri dan vena, dan dapat memberikan informasi tentang aliran darah, penyempitan, atau penyumbatan yang mungkin terjadi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1208, 5, 1, '132070115024', 'CT-Scan', 'teknik pencitraan medis yang menggunakan sinar-X dan komputer untuk membuat gambar potongan-potongan tubuh yang sangat rinci. Proses ini memungkinkan visualisasi internal tubuh dalam tiga dimensi, membantu dokter mendiagnosis kondisi medis, mengevaluasi cedera, dan merencanakan pengobatan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1209, 5, 1, '132070115025', 'Magnetic Resonanie Imaging', 'teknik pencitraan medis yang menggunakan medan magnet dan gelombang radio untuk menghasilkan gambaran yang sangat rinci dari struktur internal tubuh manusia.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1210, 5, 1, '132070115027', 'Dental Panaromic', 'Jenis pemeriksaan radiografi yang memberikan gambaran lengkap dari seluruh struktur mulut dan gigi dalam satu gambar. Gambar ini mencakup gigi, rahang atas dan bawah, persendian temporomandibular (TMJ), dan tulang rahang.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1211, 5, 1, '132070115028', 'Automatic Film Processing', 'Pengembangan film radiografi setelah dilakukan eksposur sinar-X pada pasien. Proses ini melibatkan serangkaian tahapan otomatis yang menghasilkan gambar radiografi dari film yang terpapar.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1212, 5, 1, '132070115029', 'X-Ray Contect Therapy', 'Bentuk terapi radiasi yang melibatkan pemberian dosis radiasi langsung ke tumor atau area yang memerlukan perawatan dengan menggunakan sumber sinar-X yang ditempatkan dalam kontak langsung dengan kulit atau jaringan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1213, 5, 1, '132070115030', 'X-Ray Superficial Therapy', 'bentuk terapi radiasi yang menggunakan sinar-X dengan energi rendah untuk merawat kanker atau kondisi kulit tertentu. Terapi ini umumnya ditujukan untuk pengobatan kanker kulit dan beberapa kondisi kulit non-kanker, seperti penyakit kulit atau lesi yang memerlukan perawatan radiasi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1214, 5, 1, '132070115031', 'Deep Therapy', 'deep therapy mungkin dapat diartikan secara berbeda tergantung pada konteksnya. Beberapa kemungkinan interpretasi termasuk:Terapi Psikologis ,Terapi Fisik Mendalam,Terapi Alternatif atau Holistik dan jenis lainya', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1215, 5, 1, '132070115035', 'Treatment Plan Computer', 'perangkat lunak atau sistem komputer yang digunakan oleh profesional kesehatan untuk merencanakan dan mengelola perawatan pasien. Sistem perencanaan pengobatan ini dapat digunakan dalam berbagai bidang, termasuk kedokteran, radioterapi, dan bidang kesehatan lainnya', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1216, 5, 1, '132070115036', 'Localizer/Stimulator', 'perangkat medis yang digunakan dalam bidang kedokteran, terutama dalam konteks pembedahan atau prosedur bedah minimal invasi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1217, 5, 1, '132070115037', 'ID Printer', 'pencetak khusus yang dirancang untuk mencetak kartu identifikasi. Pencetakan ID sering digunakan dalam berbagai konteks, termasuk keamanan kantor, akses pintu, kartu pengenal karyawan, kartu akses, dan kartu identifikasi lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1218, 5, 1, '132070116001', 'Automatic Rotary Microtome', 'perangkat laboratorium yang digunakan untuk memotong sampel biologis dengan presisi tinggi dalam bentuk potongan tipis. Alat ini dirancang khusus untuk menghasilkan irisan tipis dari spesimen jaringan biologis, seperti jaringan organ, sel, atau struktur biologis lainnya', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1219, 5, 1, '132070116004', 'Binoculer Microscope (Alat Kedokteran Patologi Anatomy)', 'jenis mikroskop yang dilengkapi dengan dua lensa okuler (ocular) sehingga dua mata dapat melihat objek yang diamati secara bersamaan. Ini memungkinkan pengamat mendapatkan gambar tiga dimensi dari objek yang diamati. Mikroskop binokuler sering digunakan dalam berbagai bidang ilmu, termasuk kedokteran patologi dan anatomi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1220, 5, 1, '132070116008', 'Hotplate', 'Hotplate biasanya digunakan dalam berbagai aplikasi laboratorium untuk pemanasan sampel atau larutan dengan suhu yang diatur dan dijaga', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1221, 5, 1, '132070116010', 'Laminari Air Flow', 'memberikan aliran udara yang bersih dan teratur ke atas atau ke bawah di dalam ruang kerja. Aliran ini dirancang untuk meminimalkan kontaminasi udara dan debu, sehingga cocok digunakan di lingkungan yang memerlukan kebersihan tinggi, seperti laboratorium dan fasilitas kesehatan. Pemahaman tentang laminar air flow dapat bervariasi tergantung pada konteks penggunaannya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1222, 5, 1, '132070116013', 'Timbangan Halus', 'jenis timbangan dengan tingkat ketelitian dan sensitivitas tinggi. Timbangan ini dirancang untuk memberikan hasil yang sangat akurat dalam pengukuran berat', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1223, 5, 1, '132070116014', 'Universal Microscope', 'alat optik yang digunakan untuk memperbesar dan memeriksa objek atau struktur yang tidak dapat dilihat dengan mata telanjang. Mikroskop dapat digunakan di berbagai bidang, seperti biologi, kedokteran, ilmu material, dan banyak lagi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1224, 5, 1, '132070116015', 'Microtome (Alat Kedokteran Patologi Anatomy)', 'alat yang digunakan dalam laboratorium patologi anatomi untuk memotong tipis potongan-potongan jaringan atau sampel biologis agar dapat diamati di bawah mikroskop', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1225, 5, 1, '132070116016', 'Sonography Unit', 'sistem yang digunakan untuk melakukan pemeriksaan ultrasonografi atau sonografi. Sonografi, juga dikenal sebagai ultrasonografi, adalah teknik pencitraan medis yang menggunakan gelombang suara ultrasonik untuk menghasilkan gambar struktur internal tubuh manusia atau hewan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1226, 5, 1, '132070116017', 'Pediatric Unit', 'unit di fasilitas kesehatan, seperti rumah sakit atau pusat medis, yang khusus menangani pasien anak-anak atau bayi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1227, 5, 1, '132070116018', 'CT Scanner', 'CT Scanner adalah alat pencitraan medis yang menggunakan kombinasi sinar-X dan komputer untuk menghasilkan gambar penampang tubuh.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1228, 5, 1, '132070117001', 'Blood Bank', 'alat untuk mengumpulkan, menyimpan, dan mendistribusikan komponen darah yang diberikan oleh para donor', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1229, 5, 1, '132070117003', 'Centrifuge Sera', 'Fungsinya untuk memisahkan partikel padat dari satu benda cair suspensi atau dengan kata lain memisahkan benda cair dari partikel padatan yang ada di dalamnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1230, 5, 1, '132070117004', 'Centrifuge Sorval', 'Alat yang digunakan untuk memisahkan zat-zat dalam sampel berdasarkan perbedaan kerapatan mereka menggunakan gaya sentrifugal. Salah satu model yang mungkin dimaksud adalah "Sorvall Centrifuge," namun pastikan untuk memeriksa model atau jenis tertentu karena Sorvall memiliki berbagai model centrifuge dengan fitur dan kapabilitas yang berbeda.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1231, 5, 1, '132070118002', 'Bed Instrubator', 'alat yang digunakan atau tempat tidur pasien untuk pemeriksaan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1232, 5, 1, '132070118003', 'Blitz Lamp', 'Lampu Blitz, adalah lampu yang menghasilkan cahaya terang dalam waktu singkat. Lampu ini biasanya digunakan dalam fotografi untuk menghasilkan efek pencahayaan yang dramatis.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1233, 5, 1, '132070118005', 'Cassete Film (Alat Kedokteran Radioterapy)', 'konteks radioterapi merujuk pada suatu perangkat yang digunakan untuk menahan dan melindungi film radiografi selama proses pengambilan gambar medis menggunakan sinar-X. Sinar-X melewati pasien dan kemudian menciptakan gambar di film radiografi, yang terletak di dalam kaset tersebut.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1234, 5, 1, '132070118007', 'Cobalt 60', 'alat yang menggunakan sinar gamma yang dihasilkan oleh isotop radioaktif Cobalt-60 dalam prosedur radioterapi untuk mengobati kanker.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1235, 5, 1, '132070118008', 'Conection Cable 23 Linght 3 mm', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1236, 5, 1, '132070118009', 'Counetring Cable', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1237, 5, 1, '132070118010', 'Stimulator (Alat Kedokteran Radioterapy)', 'Perangkat ini menciptakan medan elektromagnetik yang dirancang untuk mengganggu pertumbuhan sel kanker pada tingkat seluler. Terapi ini terutama digunakan dalam pengobatan glioblastoma multiforme, jenis kanker otak tertentu.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1238, 5, 1, '132070118012', 'Dosimeter', 'perangkat yang digunakan untuk mengukur dosis paparan radiasi yang diterima oleh individu atau objek selama periode waktu tertentu. Tujuan utama dosimeter adalah untuk memantau tingkat paparan radiasi dan memastikan bahwa tingkat tersebut tetap dalam batas aman yang ditetapkan untuk melindungi kesehatan manusia.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1239, 5, 1, '132070118013', 'Film Dryer', 'perangkat yang digunakan untuk mengeringkan film fotografi setelah proses pengembangan. Film fotografi tradisional mengandung emulsi gelatin yang sensitif terhadap cahaya dan bahan kimia pengembang. Setelah film diolah melalui proses kimia, film tersebut perlu dikeringkan agar dapat dipegang dan digunakan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1240, 5, 1, '132070118016', 'Film Pass Box', 'sistem yang digunakan di lingkungan laboratorium atau industri, terutama di bidang farmasi, untuk memindahkan objek atau bahan antara dua area yang berbeda tanpa mempengaruhi kondisi kebersihan atau sterilitas keduanya', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1241, 5, 1, '132070118018', 'Flush Immanted (Siemens)', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1242, 5, 1, '132070118019', 'Head Hunidifier', 'perangkat yang dirancang untuk menambah kelembaban ke udara di dalam ruangan. Fungsi utamanya adalah untuk meningkatkan tingkat kelembaban di lingkungan dalam ruangan, terutama pada saat cuaca kering atau di musim dingin ketika sistem pemanas dapat mengurangi kelembaban udara.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1243, 5, 1, '132070118020', 'Lead Apron', 'peralatan pelindung yang digunakan dalam radiologi dan prosedur-prosedur medis yang melibatkan paparan radiasi. Apron ini terbuat dari bahan timbal atau bahan lain yang dapat menyerap atau meminimalkan paparan radiasi pada tubuh, terutama pada area organ vital seperti kelenjar tiroid, payudara, dan organ reproduksi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1244, 5, 1, '132070118027', 'Minitor Carese Siemens', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1245, 5, 1, '132070118031', 'Peac Flw Mater Imniright', 'eak flow meter adalah alat yang digunakan untuk mengukur peak expiratory flow rate (PEFR), atau disebut juga dengan aliran puncak. PEFR adalah tes untuk mengukur seberapa cepat seseorang bisa mengembuskan napas.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1246, 5, 1, '132070118033', 'Survey Meter (Alat Kedokteran Radioterapy)', 'mengukur tingkat paparan radiasi atau dosis radiasi di berbagai lingkungan, termasuk dalam bidang radioterapi. Alat ini penting dalam memastikan bahwa tingkat radiasi yang diterima oleh individu atau lingkungan tetap dalam batas-batas keamanan yang ditetapkan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1247, 5, 1, '132070118036', 'X-Ray Contect Therapy', 'peralatan yang dirancang untuk terapi kontak atau terapi dengan fokus pada area yang lebih dekat dengan permukaan tubuh.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1248, 5, 1, '132070118037', 'X-Ray Superficial Therapy', 'suatu bentuk perawatan radiasi yang digunakan dalam pengobatan kanker atau kondisi kulit tertentu', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1249, 5, 1, '132070119001', 'Auto Bed Washer', 'peralatan khusus atau teknologi otomatis untuk membersihkan tempat tidur pasien secara efisien dan higienis.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1250, 5, 1, '132070119009', 'Dehumidifier (Alat Kedokteran Nuklir)', 'perangkat yang digunakan untuk mengurangi kelembaban udara di suatu ruangan atau lingkungan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1251, 5, 1, '132070119014', 'Hand Foot And Clotes Monitor', 'alat yang digunakan memonitor untuk mengetahui pakaian kita terkontaminasi atau tidak', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1252, 5, 1, '132070119020', 'Nuclear Medicine Data Processor', 'perangkat keras atau perangkat lunak yang dirancang khusus untuk memproses data yang dihasilkan dalam bidang kedokteran nuklir. Kedokteran nuklir adalah cabang ilmu kedokteran yang menggunakan bahan radioaktif untuk mendiagnosis dan mengobati penyakit. Data yang dihasilkan dalam prosedur nuklir perlu diproses dengan cermat untuk mendapatkan informasi yang berguna tentang kondisi pasien.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1253, 5, 1, '132070119022', 'Personal Digital Dosimeter', 'Alat ini digunakan untuk mengukur dosis radiasi secara akumulasi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1254, 5, 1, '132070119023', 'Qurimeter + Printer', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1255, 5, 1, '132070119024', 'Refrigated Centrifuge', 'sentrifugasi yang dilengkapi dengan sistem pendingin atau refrigerasi. Sentrifugasi adalah metode pemisahan partikel berdasarkan berat jenis atau kepadatan menggunakan gaya sentrifugal yang dihasilkan oleh rotasi berkecepatan tinggi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1256, 5, 1, '132070119027', 'Shaker Bath', 'digunakan untuk menggabungkan gerakan getar dengan pemanasan untuk mengaduk atau mencampur sampel dalam wadah tertutup, seperti tabung reaksi atau botol erlenmeyer', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1257, 5, 1, '132070119031', 'Therminal Transfer Color Printer', 'jenis printer yang menggunakan metode thermal transfer untuk mentransfer tinta atau pigmen warna dari pita pita termal ke media cetak. Proses ini melibatkan pemanasan pita termal untuk melelehkan tinta atau pigmen, yang kemudian diaplikasikan ke media cetak untuk membentuk gambar atau teks berwarna.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1258, 5, 1, '132070119033', 'Uninterupted Power System', 'Sistem Daya Terus-menerus adalah perangkat atau sistem yang dirancang untuk memberikan daya listrik sementara pada saat terjadi pemadaman listrik atau ketidakstabilan daya', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1259, 5, 1, '132070119039', 'Hand Microtome', 'alat yang digunakan untuk memotong tipis sampel jaringan biologis atau material biologis lainnya sehingga dapat diamati di bawah mikroskop.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1260, 5, 1, '132070119040', 'Rotary Microtome', 'digunakan untuk memotong potongan tipis dari sampel jaringan biologis atau material biologis lainnya untuk analisis di bawah mikroskop. Microtome ini memiliki fitur rotasi yang memungkinkan pemotongan terus menerus dari sampel secara presisi dan konsisten.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1261, 5, 1, '132070119044', 'Fisher Bridge Warmer', 'alat yang digunakan sebagai penghangat bayi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1262, 5, 1, '132070119046', 'Steam Sterilizer (Alat Kedokteran Nuklir)', 'perangkat yang digunakan untuk melakukan sterilisasi dengan menggunakan uap air panas di bawah tekanan tinggi. Sterilisasi adalah proses untuk menghilangkan atau membunuh semua bentuk mikroorganisme seperti bakteri, jamur, dan virus dari suatu objek atau permukaan, sehingga objek tersebut menjadi bebas mikroba dan steril.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1263, 5, 1, '132070119047', 'Instrument Sterilizer', 'perangkat yang digunakan untuk menyterilkan instrumen medis dan alat-alat lainnya sehingga bebas dari mikroorganisme patogen seperti bakteri, virus, dan jamur.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1264, 5, 1, '132070119049', 'Hot Air Sterilizer', 'perangkat yang menggunakan panas tanpa kelembaban untuk menyterilkan instrumen medis, alat laboratorium, atau barang-barang lainnya. Metode sterilisasi ini menggunakan suhu tinggi untuk membunuh atau menginaktivasi mikroorganisme patogen seperti bakteri, virus, dan spora.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1265, 5, 1, '132070119050', 'High Pressure Sterilizer', 'perangkat yang digunakan untuk melakukan proses sterilisasi dengan menggunakan tekanan tinggi. Sterilisasi adalah suatu proses untuk menghilangkan atau membunuh semua bentuk mikroorganisme, termasuk bakteri, virus, dan spora bakteri, untuk mencegah pertumbuhan atau reproduksi yang dapat menyebabkan penyakit atau kerusakan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1266, 5, 1, '132070119052', 'ultrasonic Cleaning Bath', 'Ultrasonic Cleaning Bath, atau kadang disebut Ultrasonic Cleaner, adalah perangkat yang menggunakan gelombang ultrasonik untuk membersihkan benda atau sampel dengan cara menghasilkan getaran ultrasonik di dalam cairan pembersih.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1267, 5, 1, '132070119054', 'Roller Tube Culture Apparatus', 'Perangkat yang dirancang untuk menumbuhkan sel atau mikroorganisme dalam tabung reaksi berputar. Ini mungkin mencakup perangkat yang dirancang untuk memberikan gerakan putar atau goncangan yang lembut pada tabung reaksi selama inkubasi, mirip dengan konsep Roller Tube Incubator yang telah dibahas sebelumnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1268, 5, 1, '132070119055', 'Roller Tube Incubator', 'perangkat laboratorium yang dirancang untuk menumbuhkan sel-sel atau mikroorganisme dalam tabung reaksi berputar. Alat ini memberikan kondisi inkubasi yang optimal dengan memberikan gerakan putar atau goncangan yang lembut pada tabung reaksi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1269, 5, 1, '132070119057', 'Reffigerated Incubator', 'perangkat laboratorium yang menggabungkan kemampuan inkubasi dengan pendinginan. Ini dirancang untuk menumbuhkan dan memelihara sampel biologis atau kultur sel pada suhu yang terkendali dan seringkali di bawah suhu ruangan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1270, 5, 1, '132070119058', 'Anaerobic Culture Incubator', 'perangkat laboratorium yang dirancang khusus untuk menumbuhkan mikroorganisme dalam kondisi lingkungan bebas oksigen atau anaerobik. Mikroorganisme anaerobik adalah organisme yang dapat hidup atau berkembang biak dalam lingkungan yang tidak mengandung oksigen bebas.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1271, 5, 1, '132070119059', 'Cell Culture Incubator', 'perangkat laboratorium yang dirancang khusus untuk menumbuhkan dan memelihara sel-sel hidup dalam kondisi lingkungan yang terkontrol. Incubator ini menyediakan suhu, kelembaban, dan konsentrasi gas yang tepat untuk mendukung pertumbuhan dan perkembangan sel-sel dalam budaya sel.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1272, 5, 1, '132070119060', 'Shaking incubator', 'Perangkat laboratorium yang dirancang untuk memberikan kondisi lingkungan yang terkontrol, seperti suhu dan kelembaban, sambil memberikan gerakan getar atau goncangan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1273, 5, 1, '132070119061', 'Isotemp Dry Heat Incubator', 'jenis inkubator yang dirancang khusus untuk menyediakan kondisi lingkungan yang stabil dengan suhu tinggi menggunakan sumber panas kering. Inkubator ini digunakan dalam berbagai aplikasi laboratorium, termasuk kultur sel, uji stabilitas obat, dan berbagai percobaan biologis yang memerlukan suhu yang konstan dan tinggi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1274, 5, 1, '132070119062', 'Gravity Convection Incubator', 'Jenis inkubator yang menggunakan konveksi gravitasi untuk mendistribusikan panas secara merata di dalam ruang inkubasi. Inkubator adalah perangkat laboratorium yang dirancang untuk menciptakan lingkungan yang terkendali, termasuk suhu dan kelembaban, untuk mendukung pertumbuhan dan perkembangan sel atau mikroorganisme.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1275, 5, 1, '132070119064', 'Bacterial Colony Counter', 'alat laboratorium yang digunakan untuk menghitung jumlah koloni bakteri pada sebuah medium agar setelah suatu sampel telah ditanam dan dibiakkan dalam kondisi yang sesuai. Pada medium agar, bakteri dapat tumbuh dan membentuk koloni yang terlihat. Perhitungan jumlah koloni bakteri ini sering kali penting dalam penelitian mikrobiologi, diagnostik laboratorium, atau dalam memonitor kualitas mikrobiologis suatu sampel', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1276, 5, 1, '132070119066', 'Blood Conting Instrument', 'alat yang digunakan untuk menghitung jumlah sel darah dalam sampel darah. Ini sering kali merujuk pada Hematology Analyzer atau perangkat serupa yang secara otomatis melakukan penghitungan dan analisis jumlah sel darah, termasuk sel darah merah, sel darah putih, dan trombosit.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1277, 5, 1, '132070119068', 'Blood Investigation Set', 'alat atau peralatan yang digunakan dalam proses pemeriksaan darah di laboratorium medis. Pemeriksaan darah merupakan bagian penting dari diagnosis medis dan pemantauan kondisi kesehatan pasien. Berbagai jenis tes darah dapat memberikan informasi tentang fungsi organ, tingkat gula darah, tingkat lipid, dan banyak parameter kesehatan lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1278, 5, 1, '132070119069', 'Sahli Haemometer', 'alat yang digunakan untuk mengukur konsentrasi hemoglobin dalam sampel darah. Hemoglobin adalah protein yang mengandung zat besi dan bertanggung jawab untuk mengangkut oksigen dari paru-paru ke seluruh tubuh.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1279, 5, 1, '132070119070', 'Blood Presure Meter/Tensimeter', 'Alat medis yang digunakan untuk mengukur tekanan darah seseorang. Alat ini umumnya digunakan di rumah sakit, klinik, atau bahkan di rumah sebagai alat mandiri untuk memonitor tekanan darah', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1280, 5, 1, '132070119072', 'Blood Gas Analyzer (Alat Kedokteran Nuklir)', 'perangkat medis yang digunakan untuk mengukur berbagai parameter gas dalam darah arteri, seperti oksigen (O2), karbon dioksida (CO2), pH, dan konsentrasi ion hidrogen (H+)', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1281, 5, 1, '132070119075', 'Blood Sodium Potasium Analyzer', 'alat laboratorium yang dirancang khusus untuk mengukur kadar natrium (sodium) dan kalium dalam sampel darah. Kedua elektrolit ini adalah komponen penting dalam menjaga keseimbangan cairan dan fungsi normal sel dalam tubuh.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1282, 5, 1, '132070119076', 'Haemotology Analyzer', 'alat laboratorium otomatis yang digunakan untuk menganalisis komponen darah, seperti sel darah merah, sel darah putih, dan trombosit, serta mengukur berbagai parameter darah lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1283, 5, 1, '132070119077', 'Erithroyte Sedimentation Pate (ESR) Recorder', 'perangkat yang digunakan untuk merekam laju sedimentasi eritrosit (tingkat sedimentasi eritrosit) selama uji Erythrocyte Sedimentation Rate atau ESR.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1284, 5, 1, '132070119078', 'Defferential Blood Cell Counter', 'alat laboratorium medis yang digunakan untuk menghitung dan membedakan jenis-jenis sel darah yang terdapat dalam sampel darah. Pemeriksaan darah diferensial memberikan gambaran tentang proporsi relatif berbagai jenis sel darah, seperti sel darah merah, sel darah putih, dan jenis-jenis sel darah putih tertentu.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1285, 5, 1, '132070119079', 'Electro Cardiograph', 'alat medis yang digunakan untuk merekam dan memvisualisasikan aktivitas listrik yang dihasilkan oleh jantung. Alat ini merekam sinyal elektrokardiografi yang merepresentasikan impuls listrik yang menggerakkan otot jantung selama siklus detak jantung', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1286, 5, 1, '132070119080', 'Electro Encephalograph (Alat Kedokteran Nuklir)', 'alat yang digunakan untuk merekam aktivitas listrik otak. Aktivitas listrik ini dihasilkan oleh sel-sel saraf di otak yang berkomunikasi satu sama lain. EEG dapat digunakan untuk mendiagnosis berbagai kondisi neurologis, termasuk epilepsi, tumor otak, dan ensefalitis.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1287, 5, 1, '132070119081', 'Cardio Vascular Instrument', 'instrumen medis yang digunakan dalam bidang kardiologi atau spesialisasi kedokteran yang berkaitan dengan penyakit dan gangguan kardiovaskular, yang melibatkan jantung dan pembuluh darah. Instrumen ini digunakan untuk diagnosis, tindakan medis, dan intervensi bedah pada sistem kardiovaskular.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1288, 5, 1, '132070119082', 'Urine Meter', 'perangkat medis yang digunakan untuk mengukur dan mengumpulkan volume urin yang dihasilkan oleh pasien selama periode waktu tertentu. Alat ini sering digunakan di lingkungan perawatan kesehatan, terutama di rumah sakit atau unit perawatan intensif.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1289, 5, 1, '132070119083', 'Stetoscope (Alat Kedokteran Nuklir)', 'alat medis yang digunakan untuk mendengarkan suara dari dalam tubuh, seperti detak jantung, pernapasan, dan suara usus', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1290, 5, 1, '132070119084', 'Reflex Hammer (Alat Kedokteran Nuklir)', 'Alat yang digunakan dalam pemeriksaan fisik dan neurologi, sedangkan Kedokteran Nuklir berhubungan dengan cabang ilmu kedokteran yang menggunakan zat radioaktif untuk diagnosis dan pengobatan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1291, 5, 1, '132070119085', 'Diagnostic Set', 'seperangkat peralatan medis yang digunakan untuk melakukan pemeriksaan fisik dan diagnosis pada pasien. Set ini umumnya digunakan oleh profesional kesehatan seperti dokter, perawat, atau praktisi kesehatan lainnya selama pemeriksaan rutin atau pemeriksaan khusus.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1292, 5, 1, '132070119086', 'Ben Pan (For Child Adult)', 'alat yang digunakan untuk menampung BAB atau BAK. Alat ini sangat dibutuhkan bagi seseorang yang sakit dan sangat susah untuk jalan menuju toilet atau kamar mandi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1293, 5, 1, '132070119088', 'Geneocology Table', 'Alat yang digunakan dalam praktek obstetri dan ginekologi (obstetrics and gynecology) untuk melakukan pemeriksaan dan prosedur medis pada pasien wanita. Meja ini dirancang untuk memberikan kenyamanan dan akses yang optimal selama pemeriksaan ginekologi dan obstetri.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1294, 5, 1, '132070119090', 'Renography Sistem', 'Alat yang digunakan untuk mengevaluasi fungsi ginjal. Alat renografi umumnya terdiri dari beberapa komponen utama, dan ini dapat mencakup:', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1295, 5, 1, '132070119093', 'Syringe', 'alat medis yang digunakan untuk menyuntikkan atau menarik cairan dari dalam tubuh.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1296, 5, 1, '132070119094', 'Lead Syringe', 'peralatan medis yang digunakan untuk memberikan suatu cairan yang pekat yang diinjeksikan ke dalam tubuh pasien dalam jumlah tertentu .', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1297, 5, 1, '132070119097', 'Micro Tic Kit', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1298, 5, 1, '132070119098', 'Minor Sugry Set', 'Seperangkat instrumen dan peralatan bedah yang dirancang untuk mendukung berbagai jenis operasi kecil atau prosedur bedah minor yang biasanya dilakukan di bawah anestesi lokal. Prosedur bedah minor mencakup tindakan yang kurang kompleks dan tidak melibatkan organ atau struktur tubuh yang dalam.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1299, 5, 1, '132070119099', 'Major Sugry Set', 'Seperangkat instrumen, perangkat, dan peralatan bedah yang lengkap dan dirancang untuk mendukung berbagai jenis operasi besar atau prosedur bedah yang kompleks. Set ini mencakup berbagai instrumen bedah dan peralatan yang dibutuhkan oleh ahli bedah dan tim medis selama prosedur pembedahan yang melibatkan organ atau struktur internal tubuh yang penting.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1300, 5, 1, '132070119100', 'Nephecto Set', NULL, NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1301, 5, 1, '132070119101', 'Circumcion Set', '"Circumcision Set" atau dalam bahasa Indonesia disebut "Peralatan Khitan" adalah seperangkat alat bedah khusus yang digunakan untuk melakukan prosedur sunat atau khitan. Peralatan ini biasanya dikemas dalam wadah steril dan terdiri dari berbagai instrumen kecil dan tajam yang diperlukan untuk melakukan prosedur secara aman dan efisien.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1302, 5, 1, '132070119102', 'Orthopae Set', 'peralatan medis yang digunakan oleh dokter ortopedi dan tim medis dalam prosedur ortopedi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1303, 5, 1, '132070119105', 'Gastorlistinal Set', 'seperangkat instrumen dan perangkat medis yang digunakan dalam pemeriksaan, diagnosis, atau tindakan medis yang berkaitan dengan saluran pencernaan atau sistem gastrointestinal (GI).', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1304, 5, 1, '132070119106', 'Metal Catcher', 'Alat medis yang digunakan untuk memasukkan atau mengalirkan cairan ke dalam atau keluar dari tubuh manusia atau hewan. Kateter ini terbuat dari bahan logam, yang dapat melibatkan stainless steel, platinum, atau paduan logam lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1305, 5, 1, '132070119108', 'Urology Set', 'merujuk pada seperangkat instrumen medis yang digunakan dalam pemeriksaan, diagnosis, atau tindakan medis yang terkait dengan sistem kemih, termasuk ginjal, ureter, kandung kemih, dan uretra.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1306, 5, 1, '132070119109', 'Thyroid Set', 'merujuk pada berbagai jenis set atau alat medis yang digunakan dalam pemeriksaan atau tindakan terkait kelenjar tiroid. Kelenjar tiroid terletak di leher dan berperan penting dalam mengatur metabolisme tubuh', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1307, 5, 1, '132070119110', 'Operation Lamp', 'lampu yang dirancang khusus untuk memberikan pencahayaan yang optimal selama prosedur bedah atau tindakan medis di ruang operasi. Lampu operasi dirancang untuk memberikan cahaya yang terang dan seragam ke area operasi sehingga dokter dan tim medis dapat melihat dengan jelas selama prosedur.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1308, 6, 1, '132070120001', 'Dermatology Laser', 'teknologi laser dalam praktik dermatologi, cabang kedokteran yang fokus pada diagnosis, pengobatan, dan perawatan berbagai kondisi kulit, rambut, dan kuku. Laser dermatologi melibatkan penggunaan sinar laser untuk merawat masalah kulit tertentu dengan presisi tinggi. Berikut adalah beberapa aplikasi umum dari dermatology laser', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1309, 6, 1, '132070120002', 'Electro Surgery Treatment', 'prosedur medis yang menggunakan energi listrik untuk memotong, menghancurkan, atau mengkoagulasi jaringan biologis. Prosedur ini umumnya dilakukan oleh dokter atau ahli bedah yang terlatih menggunakan perangkat elektrokirurgi khusus.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1310, 6, 1, '132070120003', 'Skin Drafting', 'prosedur bedah di mana sepotong kulit atau lapisan kulit diambil dari satu area tubuh dan dipindahkan (dipencangkan) ke area yang rusak atau terluka. Tujuan dari skin grafting adalah untuk memperbaiki atau menutupi area yang kehilangan jaringan kulit karena luka bakar, cedera, atau bedah yang mengangkat kulit.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1311, 6, 1, '132070120004', 'Tissue Incubator', 'perangkat laboratorium yang digunakan untuk mengatur dan mempertahankan kondisi lingkungan yang optimal untuk pertumbuhan dan kultur jaringan biologis', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1312, 6, 1, '132070120007', 'Fluorescense Mikroscope', 'jenis mikroskop khusus yang memungkinkan pengamatan objek yang diberi pewarna fluoresen atau yang secara alami mengeluarkan cahaya fluoresen. Pewarna fluoresen yang digunakan pada sampel dapat menyala atau memancarkan cahaya saat terkena radiasi cahaya ultraviolet atau cahaya sinar-X.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1313, 6, 1, '132070120009', 'Ice Cryostat Microtome', 'alat laboratorium yang digunakan dalam pengambilan potongan tipis dari sampel biologis yang telah dibekukan (frozen). Alat ini memungkinkan pengguna untuk memotong potongan tipis dari jaringan atau sampel biologis yang telah dibekukan untuk kemudian dianalisis di bawah mikroskop.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1314, 6, 1, '132070120010', 'Kursi Gynecologi', 'kursi yang dirancang khusus untuk memfasilitasi pemeriksaan ginekologi atau pemeriksaan kesehatan reproduksi wanita.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1315, 6, 1, '132070120011', 'Kasur Anti Decubitus', 'kasur yang dirancang khusus untuk membantu mencegah terjadinya dekubitus atau luka tekan pada kulit.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1316, 6, 1, '132070120012', 'Mikroscope Labophot', 'model mikroskop yang diproduksi oleh perusahaan Nikon. Nikon Labophot adalah salah satu seri mikroskop yang populer dan banyak digunakan di berbagai laboratorium.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1317, 6, 1, '132070121002', 'Automatic Film Processor', 'pengolahan film yangdilajukan secara otomatis dengan menggunakan mesin pengolahan film untuk melakukan pekerjaan pengolahan film yang biasanya dilakukan oleh manusia.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1318, 6, 1, '132070121003', 'Basic Appendectomy Set', 'alat yang dirancang khusus untuk mendukung pelaksanaan appendectomy, suatu prosedur bedah yang melibatkan pengangkatan usus buntu atau appendix. Appendectomy umumnya dilakukan sebagai respons terhadap radang usus buntu atau apendisitis.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1319, 6, 1, '132070121004', 'Basic Craniotomy Set', 'instrumen bedah yang dirancang khusus untuk mendukung pelaksanaan craniotomy, yaitu suatu prosedur bedah yang melibatkan pembukaan tengkorak untuk mengakses otak. Craniotomy dilakukan untuk berbagai tujuan, termasuk pengangkatan tumor otak, pengobatan epilepsi, pengobatan aneurisma, atau pengangkatan sebagian tulang tengkorak yang rusak.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1320, 6, 1, '132070121006', 'Basic Thoracic Set', 'set atau kumpulan instrumen bedah yang dirancang khusus untuk digunakan dalam prosedur bedah thoraks atau dada. Bedah thoraks berkaitan dengan prosedur-prosedur yang melibatkan organ-organ di dalam rongga dada, seperti paru-paru, jantung, dan struktur lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1321, 6, 1, '132070121007', 'Bath Tub For Hydrotherapy', 'metode perawatan yang menggunakan air untuk meredakan gejala, meningkatkan kesehatan, dan memfasilitasi pemulihan fisik. Bak mandi untuk hidroterapi biasanya memiliki beberapa fitur khusus untuk mendukung pengalaman terapi air yang efektif', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1322, 6, 1, '132070121008', 'Blanket Roll', 'gulungan selimut atau kain selimut. Gulungan ini bisa terdiri dari selimut atau kain berbentuk tabung yang digulung dan dikemas dengan rapi. Blanket Rolls sering digunakan di berbagai lingkungan, termasuk rumah sakit, fasilitas perawatan kesehatan, dan tempat-tempat lain.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1323, 6, 1, '132070121009', 'Blood Bank Refrigerator (Alat Kedokteran Gawat Darurat)', 'perangkat khusus yang dirancang untuk menyimpan dan menjaga suhu darah serta produk-produk darah seperti komponen darah, plasma, dan trombosit. Kulkas ini memiliki fitur-fitur tertentu untuk memastikan bahwa produk-produk darah disimpan pada suhu yang tepat untuk menjaga keamanan dan kualitasnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1324, 6, 1, '132070121010', 'Blood Pressure Monitor (Alat Kedokteran Gawat Darurat)', 'alat medis yang digunakan untuk mengukur tekanan darah seseorang. Alat ini merupakan perangkat penting dalam pemantauan kesehatan dan diagnosis kondisi medis tertentu', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1325, 6, 1, '132070121011', 'Bronshoscope', 'Alat medis yang digunakan untuk pemeriksaan visual dari saluran napas bagian atas, khususnya bronkus dan trakea.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1326, 6, 1, '132070121012', 'Centrifuge Haematocrit', 'Alat untuk melakukan pengukuran hematokrit. Hematokrit adalah rasio volume sel darah merah terhadap volume total darah, dan pengukuran hematokrit membantu dalam menentukan persentase volume sel darah merah dalam sampel darah.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1327, 6, 1, '132070121015', 'Cyto Urethroscope', 'Alat yang dirancang untuk pengambilan sampel sel (cytology) dari uretra untuk pemeriksaan mikroskopis.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1328, 6, 1, '132070121016', 'Deionizing Unit', 'perangkat atau sistem yang dirancang untuk menghilangkan ion-ion dari air atau cairan lainnya, sehingga menghasilkan air deionisasi atau air bebas ion. Proses deionisasi melibatkan penghilangan ion-ion positif (kation) dan ion-ion negatif (anion) dari air, meninggalkan air yang sangat murni atau bebas dari ion-ion bermuatan listrik.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1329, 6, 1, '132070121017', 'Dermatome And Mesh', 'Alat untuk mengambil potongan tipis kulit atau lapisan epidermis dan dermis dari area tertentu pada tubuh. Potongan kulit yang diambil oleh dermatome ini kemudian dapat digunakan sebagai graft kulit dalam prosedur bedah rekonstruktif. Dermatome membantu menciptakan lapisan kulit yang dapat ditransplantasikan ke area yang membutuhkan perbaikan atau penutupan kulit. Ada berbagai jenis dermatome, termasuk dermatome otomatis dan dermatome manual.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1330, 6, 1, '132070121019', 'Electro Surgery (Alat Kedokteran Gawat Darurat)', 'penggunaan energi listrik frekuensi tinggi untuk melakukan pemotongan, koagulasi (penggumpalan darah), atau pengangkatan jaringan dalam prosedur bedah. Ini adalah teknik bedah yang canggih yang melibatkan penggunaan alat yang dikenal sebagai elektrokauter atau elektrokoagulator.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1331, 6, 1, '132070121020', 'Electrolyte Analyzer', 'Perangkat laboratorium yang digunakan untuk mengukur konsentrasi elektrolit dalam sampel darah atau cairan tubuh lainnya. Elektrolit adalah ion bermuatan listrik yang terlibat dalam berbagai fungsi fisiologis dalam tubuh, termasuk fungsi selular, keseimbangan air, dan fungsi sistem saraf dan otot.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1332, 6, 1, '132070121022', 'Emergency Kit', 'kumpulan peralatan, peralatan medis, dan barang-barang penting lainnya yang disusun secara sistematis untuk digunakan dalam situasi darurat atau kegawatdaruratan. Tujuan utama dari emergency kit adalah memberikan dukungan segera dan bantuan pertama kepada individu atau keluarga saat terjadi keadaan darurat, seperti bencana alam, kecelakaan, atau kejadian mendesak lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1333, 6, 1, '132070121023', 'ENT Operating Set', 'kumpulan peralatan bedah yang dirancang khusus untuk digunakan dalam prosedur bedah pada area telinga, hidung, dan tenggorokan (ENT atau Ear, Nose, and Throat). Peralatan ini digunakan oleh ahli bedah THT (Telinga, Hidung, dan Tenggorokan) atau dokter spesialis THT dalam rangka melakukan diagnosis dan perawatan bedah pada pasien dengan kondisi atau gangguan di daerah tersebut.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1334, 6, 1, '132070121024', 'ENT Treatment Unit', 'alat penunjang medis di Poli THT untuk memeriksa bagian telinga, Hidung dan Tenggorokan menggunakan Film Viewer', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1335, 6, 1, '132070121025', 'Hemacyrometer', 'suatu alat yang dapat digunakan untuk melakukan perhitungan sel secara cepat dan dapat digunakan untuk konsentrasi sel yang rendah', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1336, 6, 1, '132070121027', 'Hysteroscope & Light Source', 'perangkat medis yang digunakan dalam prosedur diagnostik dan bedah pada kavitas rahim. Ini adalah alat yang dimasukkan melalui vagina dan serviks untuk memberikan visualisasi langsung dari dinding dalam rahim. Hysteroscope biasanya terdiri dari tabung tipis yang dilengkapi dengan kamera kecil di ujungnya dan sistem pencahayaan untuk memungkinkan dokter melihat dan mengevaluasi kondisi rahim.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1337, 6, 1, '132070121028', 'Infant Ventilator', 'Alat bantu pernapasan yang dirancang khusus untuk digunakan pada bayi atau neonatus (bayi baru lahir). Ventilator ini dirancang untuk memberikan dukungan pernapasan dan memastikan suplai oksigen yang adekuat untuk bayi yang mungkin memiliki masalah pernapasan atau kondisi medis lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1338, 6, 1, '132070121029', 'Inhalation Unit', 'unit atau layanan di fasilitas kesehatan yang menyediakan terapi inhalasi. Ini melibatkan administrasi obat-obatan atau udara yang dihirup untuk mengobati kondisi seperti asma, penyakit paru obstruktif kronis (COPD), atau gangguan pernapasan lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1339, 6, 1, '132070121030', 'Laparotomy Set', 'peralatan bedah yang dirancang khusus untuk digunakan dalam prosedur bedah laparotomi. Laparotomi adalah jenis operasi bedah yang melibatkan pembukaan lapisan perut (abdomen) untuk mendapatkan akses ke organ-organ di dalamnya. Set ini berisi instrumen-instrumen khusus yang diperlukan selama prosedur laparotomi untuk melakukan pembedahan dan intervensi bedah yang mungkin diperlukan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1340, 6, 1, '132070121031', 'Manual Resuscitatian Set Adult & Child', 'seperangkat peralatan yang dirancang untuk memberikan bantuan pernapasan dan resusitasi jantung pada pasien dewasa dan anak-anak dalam situasi kegawatdaruratan. Set ini biasanya mencakup berbagai komponen yang diperlukan untuk melakukan teknik resusitasi, terutama teknik CPR (Cardiopulmonary Resuscitation) dan ventilasi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1341, 6, 1, '132070121032', 'Meja Obat', 'meja atau lemari yang digunakan untuk menyimpan obat-obatan di rumah atau fasilitas kesehatan. Meja obat ini biasanya memiliki beberapa laci atau rak untuk menyimpan obat-obatan dengan rapi dan mudah diakses.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1342, 6, 1, '132070121035', 'Neurosurgery Operating Set', 'kumpulan peralatan bedah yang dirancang khusus untuk digunakan dalam prosedur bedah saraf (neurosurgery). Bedah saraf melibatkan intervensi bedah pada sistem saraf, termasuk otak, sumsum tulang belakang, dan saraf perifer. Peralatan dalam set ini dirancang untuk memberikan keakuratan dan keamanan selama prosedur bedah kompleks ini.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1343, 6, 1, '132070121036', 'Obsgyn Operating Set', 'kumpulan peralatan bedah yang dirancang khusus untuk digunakan dalam prosedur operasi obstetri dan ginekologi (obsgyn), yang melibatkan perawatan medis pada sistem reproduksi wanita dan kehamilan. Peralatan ini digunakan dalam berbagai prosedur, termasuk operasi caesar (caesarean section), operasi pengangkatan uterus (histerektomi), dan prosedur ginekologi lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1344, 6, 1, '132070121037', 'Obstetric Stethoscope', 'jenis stetoskop khusus yang dirancang untuk mendengarkan suara detak jantung janin selama kehamilan. Alat ini memungkinkan para profesional kesehatan, seperti bidan atau dokter kandungan, untuk mendengarkan detak jantung janin dan memantau kesehatan janin dalam rahim ibu', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1345, 6, 1, '132070121038', 'Opthalmic Operating Set (Alat Kedokteran Gawat Darurat)', 'kumpulan peralatan medis yang dirancang khusus untuk digunakan dalam prosedur operasi mata atau pembedahan oftalmologi. Prosedur ini dapat mencakup berbagai jenis intervensi bedah mata, seperti operasi katarak, pembedahan kornea, atau prosedur bedah refraktif lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1346, 6, 1, '132070121039', 'Opthalmic Set', 'peralatan yang digunakan untuk pemeriksaan kesehatan mata', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1347, 6, 1, '132070121040', 'Osmometer (Alat Kedokteran Gawat Darurat)', 'digunakan dalam situasi gawat darurat medis. Osmometer adalah perangkat laboratorium yang digunakan untuk mengukur osmolalitas suatu cairan, yaitu konsentrasi partikel terlarut dalam cairan tersebut. Osmostat adalah istilah yang mengacu pada sistem fisiologis tubuh yang mengatur keseimbangan konsentrasi osmolalitas.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1348, 6, 1, '132070121042', 'Patient Strecher', 'perangkat medis yang dirancang untuk memindahkan pasien dari satu lokasi ke lokasi lain dengan aman dan nyaman. Brankar pasien biasanya digunakan di lingkungan rumah sakit, ambulans, pusat perawatan, atau dalam keadaan darurat medis.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1349, 6, 1, '132070121044', 'Slit Lamp (Alat Kedokteran Gawat Darurat)', 'Slit lamp adalah perangkat diagnostik yang umumnya digunakan oleh dokter mata dan ahli optometri untuk memeriksa mata secara rinci. Meskipun bukan peralatan gawat darurat, slit lamp memiliki peran penting dalam mendiagnosis dan memantau berbagai kondisi mata.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1350, 6, 1, '132070121045', 'Suture Episiotomy Set', 'kumpulan instrumen dan alat yang dirancang khusus untuk melakukan jahitan setelah prosedur episiotomi. Episiotomi adalah tindakan bedah di mana perineum (area antara vagina dan anus) diperpanjang dengan membuat sayatan pada saat persalinan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1351, 6, 1, '132070121046', 'Temperature Monitor (Alat Kedokteran Gawat Darurat)', 'perangkat medis yang digunakan untuk mengukur dan memonitor suhu tubuh pasien. Pemantauan suhu tubuh sangat penting dalam konteks perawatan kesehatan, terutama di lingkungan gawat darurat, ruang operasi, ruang perawatan intensif, atau di berbagai unit perawatan kesehatan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1352, 6, 1, '132070121047', 'Tracheotomy Instrument Set', 'kumpulan peralatan medis yang dirancang khusus untuk melakukan trakeotomi. Trakeotomi adalah prosedur medis yang melibatkan pembuatan sayatan pada trakea (saluran udara) di leher untuk membuat akses langsung ke saluran napas. Tracheotomy sering dilakukan dalam situasi medis darurat atau untuk memberikan bantuan pernapasan pada pasien yang mengalami kesulitan bernapas.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1353, 6, 1, '132070121048', 'Verban Set', 'set perban atau peralatan perawatan luka. Set perban umumnya mencakup berbagai jenis perban, plester, dan bahan penutup luka lainnya yang digunakan untuk membersihkan, melindungi, dan merawat luka atau cedera.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1354, 6, 1, '132070121049', 'Wheel Chair (Alat Kedokteran Gawat Darurat)', 'alat kesehatan rehabilitasi medis yang dirancang untuk membantu individu yang memiliki keterbatasan mobilitas atau kesulitan berjalan. Kursi roda menyediakan sarana transportasi yang aman dan nyaman bagi orang-orang yang tidak dapat berjalan atau memiliki keterbatasan gerak yang signifikan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1355, 6, 1, '132070122001', 'Electro Shock Therapy', 'prosedur medis yang melibatkan pemberian aliran listrik ke otak untuk menginduksi serangan kejang terkontrol. ECT digunakan sebagai metode pengobatan dalam beberapa kondisi mental, terutama ketika kondisi tersebut tidak merespons terhadap pengobatan lain atau ketika respons yang cepat diperlukan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1356, 6, 1, '132070122002', 'Electro Stimulator (Alat Kedokteran Jiwa)', 'alat stimulasi elektrik yang digunakan dalam bidang fisioterapi dan rehabilitasi, dan khusus dalam bidang kedokteran jiwa.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1357, 6, 1, '132070122003', 'EMG', 'sebuah teknik diagnostik yang digunakan untuk memeriksa aktivitas listrik otot. Prosedur ini melibatkan pemasangan elektroda ke dalam otot atau di permukaan kulit di atas otot tertentu. Elektroda mengukur sinyal listrik yang dihasilkan oleh aktivitas kontraksi otot. Data ini kemudian dianalisis untuk mengevaluasi fungsi otot dan saraf yang terkait', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1358, 6, 1, '132070122004', 'Stroboscope (Alat Kedokteran Jiwa)', 'perangkat yang digunakan dalam bidang ilmu pengetahuan, teknik fotografi, dan industri untuk menghasilkan kilatan cahaya yang berulang dengan frekuensi tertentu,dan digunakan untuk dokter kejiwaan', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1359, 6, 1, '132070123002', 'Bone', 'Alat bedah yang digunakan untuk memodifikasi atau membentuk tulang selama prosedur bedah ortopedi. Alat ini umumnya terbuat dari baja tahan karat atau logam lainnya yang kokoh dan tahan terhadap sterilisasi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1360, 6, 1, '132070123003', 'Boor Reamer', 'alat yang digunakan untuk memperluas atau meratakan lubang yang sudah ada. Ini bisa digunakan untuk memastikan dimensi yang akurat, kehalusan permukaan, atau untuk menyesuaikan diameter lubang dengan persyaratan tertentu.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1361, 6, 1, '132070123004', 'Brown Spalk', 'Alat yang digunakan untuk menyanggah tulang yang patah', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1362, 6, 1, '132070123007', 'Elevator (Alat Kedokteran Bedah Orthopedi)', 'alat yang digunakan untuk mengangkat atau menggeser tulang, jaringan, atau struktur lainnya selama prosedur bedah. Elevator dapat memiliki berbagai bentuk dan ukuran tergantung pada tujuan dan spesifikasinya. Ini adalah salah satu instrumen bedah yang membantu dalam mengangkat atau memisahkan jaringan di sekitar area operasi tanpa merusak struktur yang ada.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1363, 6, 1, '132070123008', 'Gunting Gips', 'alat yang digunakan untuk memotong gips', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1364, 6, 1, '132070123009', 'Hand Driil Feet Contrak', 'alat yang digunakan untuk mengebor atau mengoperasi pada bagian tulang', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1365, 6, 1, '132070123012', 'Reduction Forceps', 'alat bedah yang digunakan untuk membantu dalam mengurangkan atau memposisikan tulang atau fragmen tulang ke posisi yang diinginkan selama prosedur bedah. Prosedur ini disebut sebagai "reduksi," dan reduction forceps adalah alat penting yang membantu dokter bedah dalam memanipulasi dan menstabilkan tulang selama prosedur tersebut.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1366, 6, 1, '132070123014', 'Set AO', 'alat yang digunakan pada bedah orthopedi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1367, 6, 1, '132070123018', 'Stille/Pemotong Gip', 'alat medis yang dirancang khusus untuk memotong atau memotong gip yang digunakan dalam pembalutan medis. Gip sering digunakan untuk memberikan penstabilan dan perlindungan pada tulang yang patah atau mengalami cedera serius. Ketika gip harus dihapus, pemotong gips digunakan oleh profesional kesehatan untuk memotong gip dengan aman dan efisien tanpa merusak kulit atau jaringan di bawahnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1368, 6, 1, '132070123019', 'Tissue Prosessor', 'perangkat atau sistem yang digunakan dalam laboratorium patologi untuk memproses jaringan biologis sebelum diambil potongan tipis untuk pemeriksaan mikroskopis. Proses ini biasanya disebut sebagai pengolahan jaringan. Tujuannya adalah untuk mengawetkan dan memproses jaringan sehingga dapat dihasilkan potongan tipis yang dapat diperiksa di bawah mikroskop untuk diagnosis medis.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1369, 6, 1, '132070123020', 'Traksi Set + Gantungan Beban', 'merupakan alat terapi yang berfungsi untuk memberi terapi khusus bagi pasien yang mengalami gangguan otot maupun tulang guna merelaksasikan otot- otot', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1370, 6, 1, '132070123021', 'Wire Lighting Plier', 'alat digunakan untuk memotong dalam pembedahan orthopedi', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1371, 6, 1, '132070124001', 'Automatic Blood Pressure', 'alat pengukur tekanan darah otomatis dan digital serta memberikan pembacaan yang sangat akurat. Alat pengukur tekanan darah otomatis dan digital serta memberikan pembacaan yang sangat akurat', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1372, 6, 1, '132070124002', 'Blood Gas Analyzer (Alat Kedokteran I C U)', 'perangkat medis yang digunakan untuk mengukur konsentrasi gas dalam darah, khususnya gas-gas seperti oksigen (O2), karbon dioksida (CO2), dan kadang-kadang nitrogen (N2). Alat ini digunakan untuk menganalisis parameter-parameter gas dalam sampel darah arteri atau vena untuk memberikan informasi penting tentang fungsi pernapasan dan keseimbangan asam-basa dalam tubuh.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1373, 6, 1, '132070124003', 'Co2 Analyzer (Alat Kedokteran I C U)', 'alat atau perangkat yang dirancang untuk mengukur konsentrasi karbon dioksida (CO2) dalam suatu sampel udara atau gas. Pengukuran konsentrasi CO2 sering digunakan dalam berbagai konteks, termasuk di bidang industri, lingkungan, kesehatan, dan penelitian ilmiah', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1374, 6, 1, '132070124004', 'Icu Bed Electric', 'pada tempat tidur yang digunakan di Unit Perawatan Intensif (ICU) yang dilengkapi dengan sistem pengaturan listrik. Tempat tidur ICU yang dilengkapi dengan sistem pengaturan listrik memungkinkan para profesional medis untuk menyesuaikan posisi tempat tidur, termasuk bagian kepala dan kaki, dengan menggunakan kendali listrik.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1375, 6, 1, '132070125001', 'Bedside Monitor', 'alat yang digunakan untuk memonitor tanda- tanda vital pasien, berupa nadi, tekanan darah, temperature, kadar oksigen dan frekuensi pernapasan secara terus menerus.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1376, 6, 1, '132070125002', 'Central Oxygen', 'sistem distribusi oksigen, memiliki beberapa jenis sumber oksigen, yaitu diantaranya adalah Tangki Liquid, VGL, Oxgen Generator Plant, Tabung Oksigen Refill yang terpusat dan digunakan oleh fasilitas kesehatan seperti rumah sakit, klinik, puskesmas atau pusat perawatan medis lainnya.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1377, 6, 1, '132070125003', 'Central Suction (Alat Kedokteran I C C U)', 'sistem hisap sentral adalah untuk menghilangkan cairan, lendir, atau zat lainnya dari area operasi atau tempat perawatan. Sistem ini terdiri dari perangkat penyedot sentral yang terhubung dengan saluran pipa dan terminal hisap yang dapat ditempatkan di berbagai tempat di ruang perawatan atau operasi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1378, 6, 1, '132070125004', 'Pulseoxymeter', 'alat berbentuk klip yang berfungsi untuk mengukur saturasi oksigen darah dan denyut nadi ...', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1379, 6, 1, '132070126001', 'Continous Suction Unit', 'perangkat medis yang dirancang untuk memberikan penghisapan atau penyedotan kontinu pada cairan atau bahan di dalam tubuh pasien. Sistem ini biasanya digunakan di fasilitas kesehatan seperti rumah sakit, klinik, atau pusat perawatan untuk berbagai prosedur medis di mana penghisapan berkelanjutan diperlukan.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1380, 6, 1, '132070126004', 'Hyper Hypothermia System (Alat Kedokteran Bedah Jantung)', 'Pengatur suhu pasien dengan media air untuk memanaskan dan mendinginkan pasien.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1381, 6, 1, '132070126005', 'Mesin Jantung Paru', 'bantuan hidup jantung-paru (heart-lung bypass machine) yang digunakan untuk menyediakan dukungan pernapasan dan sirkulasi darah di luar tubuh pada pasien yang mengalami kegagalan pernapasan atau kegagalan sirkulasi.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1382, 6, 1, '132070126006', 'Multi Purpose Operating Table', 'merupakan alat penunjang medis di Poli Kebidanan digunakan untuk Operasi besar, seperti : operasi bedah mata dan operasoi besar lain nya', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1383, 6, 1, '132070126007', 'NVS Vital Sign Monitor (Alat Kedokteran Bedah Jantung)', 'alat kesehatan yang digunakan untuk mengukur dan menmonitoring keadaan dari tanda-tanda vital yang ada pada tubuh manusia.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1384, 6, 1, '132070126008', 'Pressure Transducer For NIBP', 'Alat yang digunakan dalam NIBP (Non-Invasive Blood Pressure) atau pengukuran tekanan darah tanpa invasif. Teknologi ini umumnya digunakan dalam peralatan medis seperti monitor tekanan darah otomatis yang digunakan di rumah sakit, klinik, atau bahkan di rumah pasien.', NULL, NULL, '2026-04-30 03:15:49', '2026-04-30 03:15:49'),
	(1385, 6, 1, '132070126009', 'Pulse Oxymeter', 'alat untuk mengukur kadar oksigen (saturasi oksigen) di dalam darah', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1386, 6, 1, '132070127001', 'DF 22 Multipurpose Akupuntur Aparatus', 'alat terapi akupuntur gelombang elektro yang multifungsi buat dengan menggabungkan pengetahuan alat akupuntur', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1387, 6, 1, '132070127004', 'Timer (Alat Kedokteran Traditional Medicine)', 'Alat yang digunakan untuk mengatur alur kejadian atau proses.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1388, 6, 1, '132070128001', 'Anesthesi Apparatus', 'alat yang digunakan untuk menyalurkan gas atau campuran gas anastetik yang aman ke rangkaian sirkuit anestesi yang kemudian dihisap oleh pasien dan membuang sisa gas dari pasien', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1389, 7, 1, '132070201003', 'Audio/Vidio Comunication', 'Terdapat berbagai alat kesehatan yang memanfaatkan teknologi audio dan video untuk komunikasi, berikut adalah beberapa contoh: Telemedicine Platforms, Video Conferencing untuk Konsultasi Medis:, Alat Pemantauan Jarak Jauh, Rehabilitasi Virtual, Pelatihan dan Edukasi Medis Online', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1390, 7, 1, '132070201005', 'Chiller System Equipment', 'sistem pendinginan (chiller system) yang digunakan di kapal atau instalasi maritim. Sistem pendinginan ini berfungsi untuk mengatur suhu di dalam kapal dan menjaga kondisi lingkungan yang nyaman untuk kru serta melindungi peralatan atau muatan yang memerlukan kondisi suhu tertentu.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1391, 7, 1, '132070201006', 'Compressor', 'alat yang digunakan dalam sistem medis, seperti kompresor udara untuk penyediaan oksigen atau peralatan lainnya', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1392, 7, 1, '132070201007', 'Compressor High Pressure', 'alat yang digunakan untuk menghisap dan menekan udara untuk dikompresikan sehingga suhu dan tekanan dari udara tersebut akan dialirkan ke dalam bejana udara. alat ini berfungsi bagi pasien yang memiliki sensitivitas oksigen tinggi', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1393, 7, 1, '132070201008', 'Compressor Low Pressure', 'peralatan untuk pasien yg membutuhkan udara medis yang sangat bersih untuk dikirim ke ruang operasi dan ruang rawat rumah sakit dengan keandalan absolut.  alat ini merupakan layanan pendukung yang vital bagi rumah sakit, menjaga pernapasan pasien yang sakit kritis selama ventilasi mekanis', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1394, 7, 1, '132070201010', 'Ergo Cycle', 'alat kebugaran yang dirancang khusus untuk melakukan latihan fisik, terutama latihan kardiovaskular, di lingkungan yang terkendali. Ergo Cycle biasanya terdiri dari sepeda stasioner yang dapat digunakan di dalam ruangan', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1395, 7, 1, '132070201011', 'Fire Extinghuizer', 'alat yang digunakan untuk memadamkan api atau mengendalikan kebakaran kecil. Alat Pemadam Api Ringan (APAR) pada umumnya berbentuk tabung yang diisikan dengan bahan pemadam api yang bertekanan tinggi', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1396, 7, 1, '132070201012', 'Mixed Gas Central Equipment', 'alat untuk menghasilkan dan mengelola campuran gas yang digunakan dalam berbagai prosedur medis. Campuran gas ini dapat digunakan, misalnya, untuk memberikan anestesi atau untuk keperluan perawatan pasien di rumah sakit atau fasilitas kesehatan lainnya', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1397, 7, 1, '132070201014', 'O 2, N 2 Blood Analyzer', 'alat ini berfungsi untuk mengukur jumlah sel darah, kadar oksigen (terutama melalui parameter seperti saturasi oksigen atau PaO2), kadar karbon dioksida (PaCO2), pH darah, dan lainnya', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1398, 7, 1, '132070201015', 'O 2 Gas Analyzer', 'perangkat yang dirancang untuk mengukur atau menganalisis konsentrasi oksigen (O2) dalam suatu medium, seperti udara atau gas lainnya. Dalam konteks perawatan kesehatan, O2 Gas Analyzer dapat digunakan untuk memonitor konsentrasi oksigen dalam udara yang dihirup oleh pasien, seperti dalam rumah sakit atau fasilitas perawatan kesehatan. Ini membantu memastikan pasien mendapatkan tingkat oksigen yang cukup.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1399, 7, 1, '132070201016', 'O 2 Masker', 'masker oksigen, yang digunakan dalam konteks perawatan medis. Masker oksigen menyediakan suplai oksigen tambahan kepada pasien yang mungkin mengalami kesulitan bernapas atau memiliki tingkat oksigen dalam darah yang rendah.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1400, 7, 1, '132070201017', 'Scrubber Equipment', 'peralatan pembersih udara atau sistem penyaringan udara yang digunakan di kapal laut. Pada kapal, scrubber dapat digunakan untuk menghilangkan polutan dari gas buang, terutama sulfur dioksida (SO2) yang dihasilkan oleh pembakaran bahan bakar fosil.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1401, 7, 1, '132070201018', 'Scuba Closed Circuit', 'peralatan penyelaman mandiri yang digunakan oleh penyelam untuk bernapas di dalam air.  memiliki sistem berbeda dgn scuba konvesional, scuba closed circuit, udara yang telah dihirup oleh penyelam tidak langsung dikeluarkan ke lingkungan, melainkan diproses kembali untuk dihirup kembali setelah melewati sejumlah perangkat.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1402, 7, 1, '132070201019', 'Sound Level Meter (Alat Kesehatan Matra Laut)', 'alat yang digunakan untuk mengukur tingkat kebisingan atau tekanan suara di lingkungan', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1403, 7, 1, '132070201025', 'Vision Screneer', 'Alat yang dipakai untuk membuat grafik ketajaman penglihatan dan menemukan efektivitasnya dalam menyaring defisit ketajaman penglihatan', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1404, 7, 1, '132070201028', 'Walk In Chamb Multicomp', 'sistem atau infrastruktur komunikasi yang terintegrasi di rumah sakit', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1405, 7, 1, '132070202001', 'Auto Spirometer', 'alat kesehatan yang digunakan untuk mengukur volume udara yang masuk dan keluar dari paru-paru seseorang selama pernapasan. Alat ini dapat memberikan informasi tentang fungsi paru-paru, termasuk kapasitas paru-paru, volume udara, dan laju aliran udara. Spirometer sering digunakan dalam pengukuran fungsi paru-paru, evaluasi penyakit paru-paru, serta pemantauan dan pengelolaan kondisi pernapasan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1406, 7, 1, '132070202002', 'Decompression Chamber', 'alat yg digunakan untuk mensimulasikan kondisi tekanan tinggi atau rendah seperti yang dapat ditemui dalam penerbangan antariksa. alat ini juga digunakan untuk pengujian peralatan dan pelatihan awak pesawat mengenai tanggapan terhadap perubahan tekanan kabin.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1407, 7, 1, '132070202003', 'Ejection Seat Trainter', 'sebuah alat pelatihan yang dirancang untuk melatih pilot atau personel militer dalam penggunaan kursi lontar (ejection seat) dalam keadaan darurat', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1408, 7, 1, '132070202004', 'Human Centrifuge', 'berbagai instrumen vital untuk memastikan keamanan dan kinerja optimal. Beberapa instrumen yang sangat penting dalam latihan pilot pesawat tempur', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1409, 7, 1, '132070203001', 'Airpolution Test Equip', 'Alat kesehatan yang umumnya digunakan untuk mengukur kualitas udara, terdiri dari beberapa instrumen merujuk pada alat deteksi polusi udara atau alat pengukur kualitas udara yang digunakan oleh berbagai pihak, termasuk lembaga kepolisian, untuk memantau tingkat polusi udara.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1410, 7, 1, '132070203002', 'Anthropometer Set', 'Alat pengukuran fisik manusia, seperti tinggi badan, berat badan, panjang lengan, lebar bahu, dan dimensi tubuh lainnya. Ini melibatkan pengukuran dan analisis proporsi tubuh serta variasi dalam ukuran tubuh manusia.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1411, 7, 1, '132070203003', 'Boneka', 'Boneka yang digunakan untuk pelatihan atau latihan penyelamatan, terutama di bidang seperti penyelamatan dan operasi darurat. Boneka semacam itu dapat dirancang untuk mensimulasikan situasi kecelakaan atau bencana tertentu sehingga petugas atau tim penyelamat dapat berlatih dengan kondisi yang mirip dengan situasi sebenarnya', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1412, 7, 1, '132070203004', 'Boneka Anatomi', 'Boneka anatomi biasanya digunakan untuk memberikan pelatihan praktis dalam bidang kedokteran, keperawatan, atau penegakan hukum. Mereka memiliki struktur tubuh yang mirip manusia dan dapat digunakan untuk mempraktikkan prosedur medis atau forensik. Dalam konteks kepolisian, boneka anatomi mungkin digunakan untuk melatih petugas dalam penanganan kejadian kecelakaan atau forensik.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1413, 7, 1, '132070203005', 'Boneka Resucitasi Anne', 'Boneka yang digunakan dalam latihan pemberian pertolongan pertama berupa CPR.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1414, 7, 1, '132070203006', 'Boneka Resucitasi Anne Rec', 'Boneka yang digunakan dalam latihan pemberian pertolongan pertama berupa CPR.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1415, 7, 1, '132070203007', 'Emergency Adult', 'Beberapa peralatan kesehatan yang digunakan untuk memberikan pertolongan pertama dalam situasi darurat.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1416, 7, 1, '132070203009', 'Infition Trainer', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1417, 7, 1, '132070203010', 'Intubation Trainer', 'Alat pelatihan yang digunakan untuk melatih petugas kepolisian atau personel kesehatan dalam teknik intubasi. Intubasi adalah prosedur medis di mana tabung endotrakeal dimasukkan ke dalam saluran napas untuk membantu ventilasi pasien.\n\nAlat pelatihan ini biasanya mencakup manekin atau model yang dirancang dengan detail anatomi yang realistis, termasuk rongga mulut, tenggorokan, dan saluran napas.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1418, 7, 1, '132070204001', 'Sepeda Statis', 'alat olahraga yang bisa menjadi alternatif bersepeda bagii yang tidak memiliki banyak waktu luang, atau tidak ingin ke luar ruangan, dan terkena polusi udara apalagi saat kondisi dan cuaca tidak mendukung', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1419, 7, 1, '132070204002', 'Track Sendo', 'Alat ini berguna untuk membentuk otot tangan dan bahu. Membantu membentuk dada, punggung dan bahu. Menjadikan dada dan bahu terlihat lebih lebar dan bidang', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1420, 7, 1, '132070205002', 'Aim Tester', 'Aim Tester dapat merujuk pada berbagai jenis perangkat atau perangkat lunak yang dirancang untuk menguji atau melatih keterampilan bidikan atau akurasi dalam berbagai konteks. Berikut adalah beberapa kemungkinan interpretasi untuk istilah ini:', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1421, 7, 1, '132070205005', 'Block Assembly Tester', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1422, 7, 1, '132070205012', 'Tapping Tester', 'Tap density tester bukanlah alat kesehatan dalam pengertian tradisional atau medis. Sebaliknya, alat ini umumnya digunakan dalam industri farmasi atau industri lainnya untuk mengukur densitas dan sifat aliran dari bubuk atau granulat. Proses ini membantu dalam pengembangan dan produksi tablet, kapsul, dan formulasi farmasi lainnya.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1423, 7, 1, '132070205015', 'Buku Buta Warna', 'Buku yang digunakan untuk test buta warna, yaitu sebuah uji untuk mengetahui apakah seseorang mengidap buta warna atau tidak.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1424, 7, 1, '132070205016', 'Genaral Aptitude Tester Battery (MNOP)', 'suatu alat tes yang berhu- bungan dengan jabatan yang ber- orientasi pada beberapa tes bakat baterai yang mengukur sembilan bakat dalam delapan tes tulis serta empat perangkat tes', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1425, 7, 1, '132070205018', 'Timbangan Badan (Alat Kesehatan Umum Lain)', 'alat pengukur berat badan yang umumnya digunakan untuk memonitor dan mengukur berat tubuh seseorang', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1426, 7, 1, '132070205019', 'Grip Dinamo Meter', 'alat yang digunakan untuk melihat kekuatan otot tangan pasien pasca stroke', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1427, 7, 1, '132070205020', 'Ukur Tinggi Badan', 'perangkat yang digunakan untuk mengukur tinggi badan seseorang. Alat ini umumnya digunakan di berbagai konteks, termasuk fasilitas kesehatan, sekolah, pusat kebugaran, dan tempat lainnya', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1428, 7, 1, '132070205022', 'Audiometer (Alat Kesehatan Umum Lain)', 'alat medis yang digunakan untuk mengukur ambang pendengaran seseorang', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1429, 7, 1, '132070205024', 'Alat Jarak Pandang', 'perangkat yang digunakan untuk mengukur jarak atau jarak pandang antara dua atau lebih titik. Dalam konteks pengukuran jarak pandang, terdapat beberapa jenis alat yang sering digunakan', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1430, 7, 1, '132070205025', 'Scrub Station', 'Tempat Cuci Tangan Higienis untuk Keperluan Medis', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1431, 8, 1, '132080101001', 'Conductivity Meter (Alat Laboratorium Kimia Air Teknik Penyehatan', 'alat yang digunakan untuk mengukur konduktivitas suatu larutan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1432, 8, 1, '132080101002', 'Hellege Comperator', 'alat laboratorium berbentuk wadah yang digunakan untuk memanaskan', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1433, 8, 1, '132080101003', 'Hellege Turbidity Meter', 'salah satu alat umum yang biasa digunakan untuk keperluan analisa kekeruhan air atau larutan. Turbidity meter merupakan alat pengujian kekeruan dengan sifat optik akibat dispersi sinar dan dapat dinyatakan sebagai perbandingan cahaya yang dipantulkan terhadap cahaya yang datang.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1434, 8, 1, '132080101004', 'Spectro Photo Meter', 'alat laboratorium yang digunakan untuk mengukur sejauh mana suatu zat menyerap atau menghantarkan cahaya pada berbagai panjang gelombang', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1435, 8, 1, '132080101005', 'Discicator/Eksicator', 'Desiccator (Eksikator) adalah perangkat laboratorium yang digunakan untuk menyimpan bahan kimia atau benda-benda lain dengan cara mengurangi kelembaban di sekitarnya. Desiccator sering terdiri dari sebuah wadah kaca yang kedap udara dengan penutup kaca dan bagian bawah yang dapat diisi dengan bahan pengering, seperti gel silika.\n\nDesiccator digunakan untuk menjaga agar suatu zat atau benda tidak terkena kelembaban, yang dapat memengaruhi sifat kimia atau fisiknya. Ini umumnya digunakan di laboratorium kimia dan biologi.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1436, 8, 1, '132080101007', 'In Off, Cone & Standar', 'Disebut juga sebagai Corong Sedimentasi adalah sebuah tabung kaca atau plastik berbentuk kerucut,  digunakan untuk mempermudah terjadinya pengendapan atau sedimentasi.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1437, 8, 1, '132080101009', 'Timbangan Elektronik', 'alat ukur berat yang menggunakan teknologi elektronik untuk memberikan pembacaan berat yang akurat dan tepat. Berbeda dengan timbangan mekanik yang menggunakan sistem pegas atau pengaturan lainnya, timbangan elektronik mengandalkan sensor beban atau sel beban untuk mendeteksi dan mengukur berat benda.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1438, 8, 1, '132080101010', 'Alat Penguji Daya Tembus Air', '"alat uji ketahanan air" atau "alat uji kedap air." Fungsinya adalah untuk mengukur sejauh mana suatu bahan atau produk dapat menahan atau menahan penetrasi air', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1439, 8, 1, '132080101011', 'Alat Pengukur Kadar Air', 'alat yang digunakan untuk mengukur kadar air dalam suatu bahan atau substansi. Pemilihan alat ini tergantung pada jenis bahan yang diukur dan sejauh mana akurasi yang diperlukan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1440, 8, 1, '132080101012', 'Alat Pengukur Kelembaban', 'Hygrometer adalah alat yang dipakai dalam pengukur kelembaban relatif udara, atau jumlah uap air tak terlihat dalam suatu lingkungan tertentu.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1441, 8, 1, '132080101013', 'Alat Penguji Penerapan Udara Air', 'Jika mengacu pada alat untuk mengukur penerapan atau penyebaran air pada suatu permukaan, maka beberapa alat yang umum digunakan seperti Tes Penyerapan Air (Water Absorption Test, atau Densitometer atau Penetrometer Air', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1442, 8, 1, '132080101014', 'Alat Penguji Tembus Udara', 'perangkat yang digunakan untuk mengukur tingkat permeabilitas udara dari bahan tekstil atau material lainnya. Pengukuran permeabilitas udara penting dalam industri tekstil untuk mengevaluasi kualitas dan kinerja bahan, terutama dalam hal sirkulasi udara, kenyamanan, dan kecocokan untuk aplikasi tertentu.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1443, 8, 1, '132080101016', 'Drat Chamber', 'Alat yang digunakan untuk tempat proses pendorongan noda oleh eluen dalam proses kromatografi lapis tipis. Terbuat dari gelas/kaca yang tahan bahan kimia yang korosif dengan berbagai ukuran volume.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1444, 8, 1, '132080101018', 'Drat Chamber', 'Alat yang digunakan untuk tempat proses pendorongan noda oleh eluen dalam proses kromatografi lapis tipis. Terbuat dari gelas/kaca yang tahan bahan kimia yang korosif dengan berbagai ukuran volume.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1445, 8, 1, '132080102001', 'Autoclave Unit (Alat Lab. Micro Biologi Tehnik Penyehatan)', 'perangkat atau sistem yang digunakan untuk melakukan proses sterilisasi dengan menggunakan uap panas di bawah tekanan tinggi. Autoclave digunakan untuk membunuh atau menginaktivasi mikroorganisme, termasuk bakteri, virus, dan spora bakteri, serta untuk menghancurkan zat patogen dalam alat-alat medis, media kultur mikroba, dan bahan lainnya yang mungkin terkontaminasi', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1446, 8, 1, '132080102002', 'Plate Count Chambre', 'perangkat yang digunakan dalam mikrobiologi untuk menghitung jumlah bakteri atau mikroorganisme lain dalam suatu cairan, biasanya sampel air atau suspensi mikroorganisme', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1447, 8, 1, '132080102003', 'Alat Pengambil Sample Air', 'Alat pengambil sampel air adalah perangkat yang dirancang khusus untuk mengumpulkan sampel air dari berbagai sumber dengan cara yang tepat dan representatif. Dan terdiri dari beberapa jenis alat', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1448, 8, 1, '132080102004', 'Alat Dekantansi', 'Alat yg digunakan dalam laboratorium dan proses industri untuk memisahkan dua fase cairan yang tidak bercampur, seperti air dan minyak. Dekantansi dapat merujuk pada alat tertentu atau metode umum yang melibatkan proses pemisahan cairan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1449, 8, 1, '132080103001', 'Portable Elektro Sounding Test', 'Tes laboratorium hidrokimia berkaitan dengan analisis kimia air dan dapat melibatkan penggunaan instrumen atau metode laboratorium untuk mengukur parameter kimia dalam sampel air, seperti pH, konsentrasi ion, dan parameter hidrokimia lainnya.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1450, 8, 1, '132080103002', 'Elektronik Thermometer', 'perangkat pengukur suhu yang menggunakan komponen elektronik, seperti sensor suhu dan sirkuit terkait, untuk mengukur dan menampilkan suhu secara digital', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1451, 8, 1, '132080103003', 'Mikroscop Dengan Camera', 'mikroskop yang dilengkapi dengan sistem kamera, memungkinkan pengguna untuk merekam dan mendokumentasikan gambar yang diamati di bawah mikroskop.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1452, 8, 1, '132080103004', 'Macnetic Stiner', 'perangkat laboratorium yang digunakan untuk mencampur larutan dengan cara menggerakkan secara otomatis sebuah batang magnet di dalam wadah yang berisi cairan', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1453, 8, 1, '132080103005', 'Bacteri Colorimeter', 'alat untuk untuk mengidentifikasi, mengukur, dan memahami sifat-sifat mikroorganisme', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1454, 8, 1, '132080103006', 'Fitting Plat', 'Dalam laboratorium hidrokimia, fitting dapat merujuk pada berbagai jenis sambungan, klep, atau konektor yang digunakan untuk menghubungkan peralatan analisis air, seperti alat pengukur pH, spektrofotometer, atau alat analisis lainnya, seperti Fitting untuk Peralatan Analisis Air, Fitting pada Alat Pengambil Sampel, Fitting pada Sistem Pengolahan Sampel, Fitting pada Sistem Pemurnian Air', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1455, 8, 1, '132080103007', 'Water Test', 'proses pengujian atau analisis yang dilakukan pada sampel air untuk menentukan kualitas dan komposisi air tersebut dan memiliki beberapa parameter; kimia, fisika, mikrobiologis, organik dan zat kimia lainnya', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1456, 8, 1, '132080103009', 'Visuil Acumulation Jump', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1457, 8, 1, '132080103011', 'Fire Lab Turbidity', 'Turbidity Meter, juga dikenal sebagai Nephelometer, adalah alat yang dirancang khusus untuk mengukur kekeruhan suatu larutan dengan cara mengukur intensitas cahaya yang dipantulkan atau diserap oleh partikel-partikel yang terlarut dalam larutan. Prinsip kerjanya didasarkan pada hukum penyebaran cahaya oleh partikel-partikel kecil yang ada dalam larutan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1458, 8, 1, '132080103013', 'Pott Maker', 'tempat untuk melarutkan cairan atau zat kimia laboratorium', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1459, 8, 1, '132080103014', 'D.O. Meter', 'Alat yang digunakan untuk menunjukkan kadar oksigen terlarut dalam air yang kemudian dapat menjadi acuan dasar untuk menyimpulkan baik atau tidaknya kualitas air yang ada di kolam atau tambak.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1460, 8, 1, '132080103015', 'Sediment Sampler', 'alat yang digunakan untuk mengambil sampel sedimen dari dasar perairan, seperti sungai, danau, atau laut. Sampel sedimen ini kemudian dianalisis untuk memahami komposisi, struktur, dan sifat fisik atau kimianya. Sediment sampler dapat digunakan dalam berbagai konteks, termasuk penelitian lingkungan, pemantauan kualitas air, dan penelitian geologi', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1461, 8, 1, '132080103016', 'Destiling Apparaat', 'perangkat atau alat yang digunakan untuk melakukan proses penyulingan atau destilasi. Proses destilasi umumnya digunakan untuk memisahkan komponen-komponen suatu campuran berdasarkan perbedaan titik didihnya.\n\nDistilling apparatus umumnya terdiri dari beberapa komponen utama, seperti Kolom Distilasi (Distillation Column), Alat Pemanas (Heating Device), dll', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1462, 8, 1, '132080103019', 'Water Current Meter (Alat Laboratorium Hidrokimia)', 'alat pengukur arus air, adalah perangkat yang digunakan untuk mengukur kecepatan dan arah aliran air di suatu lokasi tertentu. Alat ini penting dalam pemahaman dinamika pergerakan air di perairan seperti sungai, danau, laut, atau saluran air lainnya', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1463, 8, 1, '132080103022', 'E L E K T R O D A', 'benda konduktif yang digunakan untuk menyambungkan suatu rangkaian listrik dengan suatu elektrolit, semikonduktor, atau ruang hampa\n\nAda dua jenis elektroda utama: Elektroda Kerja (Working Electrode) dan Elektroda Referensi (Reference Electrode),  Contoh elektroda yang umum digunakan meliputi:\nElektroda Kaca (Glass Electrode) , Elektroda Platinum (Platinum Electrode)', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1464, 8, 1, '132080103023', 'Automatic Burete', 'Laboratorium yang digunakan untuk mengukur volume larutan dengan presisi tinggi. Burette sendiri adalah alat yang digunakan untuk menambahkan volume larutan secara bertahap ke dalam larutan lain selama suatu proses percobaan atau analisis.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1465, 8, 1, '132080103027', 'Fisher Arst Gas Apparatus', 'sebuah alat yang menghasilkan gas api terbuka berganda, digunakan untuk pemanasan, sterilisasi, dan pembakaran. Alat ini digunakan ketika pekerjaan laboratorium membutuhkan nyala api yang lebih panas daripada yang bisa dicapai menggunakan pembakar Bunsen, atau digunakan ketika nyala api berdiameter lebih besar diinginkan, seperti dengan loop inokulasi atau dalam peniupan kaca.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1466, 8, 1, '132080104004', 'Water Level Meter', 'alat yang digunakan untuk mengukur kedalaman air di sumur atau sumbat air tanah. Alat ini umumnya digunakan dalam pekerjaan hidrogeologi, pemantauan kualitas air tanah, dan kegiatan terkait air tanah lainnya. Tujuan utama dari Water Level Meter adalah untuk menentukan kedalaman air di sumur atau piezometer pada titik tertentu.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1467, 8, 1, '132080104007', 'Water Level Recorder', 'perangkat atau alat yang digunakan untuk secara otomatis merekam data tingkat air dalam sumur, sungai, danau, atau sumber air lainnya selama periode waktu tertentu. Alat ini berfungsi untuk memantau fluktuasi tingkat air secara kontinu dan memberikan catatan historis yang dapat digunakan untuk analisis hidrologi, pemodelan hidrogeologi, dan pemantauan kualitas air', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1468, 8, 1, '132080104011', 'Tools', 'Deskripis masih terlalu umum', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1469, 8, 1, '132080105001', 'Diamond Rock Saw', 'alat pemotong berbasis intan yang dirancang khusus untuk memotong atau membelah batuan, mineral, atau material keras lainnya. Alat ini menggunakan mata pisau atau mata gergaji yang dilapisi dengan intan sintetis atau intan industri.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1470, 8, 1, '132080105002', 'Geological Hammert', 'alat yang digunakan oleh geolog untuk memeriksa dan mengumpulkan sampel dari batuan atau material geologi. Geological hammer merupakan alat yang penting dalam lapangan geologi dan eksplorasi.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1471, 8, 1, '132080105004', 'Tripod Compass', 'kompas yang terpasang pada tripod atau statif, memberikan kestabilan dan akurasi yang lebih baik saat digunakan dalam pengukuran atau pemetaan di lapangan', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1472, 8, 1, '132080105005', 'Car Compass', 'perangkat yang digunakan untuk menunjukkan arah mata angin dalam kendaraan. Ini membantu pengemudi menentukan arah utara, selatan, timur, dan barat saat mereka berada di dalam mobil.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1473, 4, 1, '132070101006', 'Wickham', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1474, 8, 1, '132080105007', 'Camero Photo Micrograph', 'kamera khusus yang dirancang untuk mengambil gambar dengan resolusi tinggi dan kualitas yang baik dari sampel mikroskopis. Kamera ini sering terhubung atau terintegrasi dengan mikroskop dan dilengkapi dengan sensor canggih serta perangkat lunak pengolahan gambar untuk menghasilkan foto mikrograf yang akurat', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1475, 8, 1, '132080105008', 'Curve Meter/MAO Measure', 'alat yang digunakan dalam survei tanah dan konstruksi jalan untuk mengukur atau menentukan elevasi atau ketinggian suatu titik di atas atau di bawah referensi tertentu. Alat ini umumnya digunakan untuk membuat profil lengkung atau garis tinggi pada suatu trase, seperti trase jalan atau rel kereta api.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1476, 8, 1, '132080105009', 'Photo Micrograph Camera', 'kamera yang dirancang khusus untuk mengambil gambar mikrograf, yaitu gambar dari objek atau struktur yang sangat kecil yang diperbesar menggunakan mikroskop. Kamera ini digunakan dalam berbagai konteks ilmiah dan laboratorium, di mana pemahaman dan dokumentasi visual dari sampel mikroskopis sangat penting.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1477, 8, 1, '132080105010', 'Polarizing Micrograph', 'gambar mikroskopis yang diambil dengan menggunakan mikroskop polarisasi cahaya\n\nteknik ini melibatkan penggunaan cahaya polarisasi untuk menghasilkan gambar yang mengungkapkan informasi tambahan tentang struktur dan sifat material. Dengan menggabungkan mikroskopi polarisasi dengan kamera, para peneliti dapat merekam dan mendokumentasikan gambar-gambar ini untuk analisis lebih lanjut.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1478, 8, 1, '132080105016', 'Rock Toughness Tester', 'alat yang mampu mengukur tingkat kekasaran permukaan. Setiap permukaan komponen dari suatu benda mempunyai beberapa bentuk dan variasi yang berbeda baik menurut strukturnya maupun dari hasil proses produksinya.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1479, 8, 1, '132080105017', 'Hand Compression Falker', 'Sarung tangan kompresi dapat mendukung sirkulasi dan mengatasi kesemutan dan nyeri di tangan, Jika dlm konteks geologi, sarung tangan ini untuk melindungi tangan dari batuan \n\nJika dlm konteks geologi, sarung tangan ini untuk melindungi tangan dari batuan', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1480, 8, 1, '132080105018', 'Rock Masonry Felker', 'konstruksi menggunakan batuan alam sebagai bahan utama untuk membentuk struktur. Dalam masonry, batuan-batuan ini diatur atau diikat bersama menggunakan berbagai metode atau adukan untuk membentuk dinding, pondasi, atau struktur lainnya', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1481, 4, 1, '132070101013', 'Sluf Zone', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1482, 8, 1, '132080105020', 'Electrik Compression Tester', 'alat uji tekanan kompresi yang mencakup elemen listrik atau teknologi elektronik', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1483, 8, 1, '132080105024', 'Safety Goggles', 'jenis perlengkapan pelindung pribadi yang dirancang untuk melindungi mata penggunanya dari potensi bahaya atau cedera. Goggles ini memiliki desain khusus untuk menutupi mata secara menyeluruh dan memberikan pelindungan tambahan dibandingkan dengan kacamata biasa', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1484, 8, 1, '132080105025', 'Micrometer Eyefece', 'perangkat yang digunakan dalam mikroskop untuk mengukur objek atau mikroorganisme yang dilihat di bawah lensa mikroskop. Perangkat ini sering digunakan dalam mikroskopi untuk keperluan pengukuran dan estimasi.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1485, 8, 1, '132080105027', 'Rock Masonry Saw', 'jenis gergaji yang dirancang khusus untuk memotong batu alam atau material masonry lainnya. Gergaji ini memiliki fitur dan kekuatan khusus untuk menangani kekerasan dan ketebalan batu yang mungkin tidak dapat dipotong dengan gergaji konvensional.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1486, 8, 1, '132080106003', 'Drill Machine', 'perangkat mesin yang digunakan untuk membuat lubang pada suatu benda atau material dengan cara memutar pahat atau mata bor. Drill machine biasanya digunakan dalam berbagai industri, konstruksi, dan proyek pembuatan barang. Alat ini dapat digunakan untuk berbagai macam material, termasuk kayu, logam, plastik, dan beton, tergantung pada jenis mata bor yang digunakan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1487, 8, 1, '132080106004', 'Hot Press', 'sebuah proses atau mesin yang digunakan dalam pengolahan material, terutama untuk pemadatan atau pengeringan bahan tertentu dengan menerapkan panas dan tekanan tinggi. Proses ini umumnya digunakan dalam industri kayu, pengolahan kertas, dan industri lainnya untuk membuat produk yang lebih padat dan kokoh', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1488, 4, 1, '132070101019', 'Agraat', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1489, 8, 1, '132080106008', 'Crusher Saw Dust', 'mesin penghancur atau pemroses yang dirancang khusus untuk menghancurkan serbuk gergaji atau serbuk kayu. Serbuk gergaji atau serbuk kayu, yang disebut juga sawdust, merupakan hasil samping dari proses pengolahan kayu, baik dalam bentuk penggergajian kayu atau pemrosesan kayu lainnya. Crusher saw dust digunakan untuk mengubah serbuk gergaji tersebut menjadi ukuran partikel yang lebih kecil atau bahkan menjadi serbuk halus, yang kemudian dapat digunakan dalam berbagai aplikasi.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1490, 8, 1, '132080106012', 'Test Press/Strenght Test', 'proses pengujian yang digunakan untuk menilai sejauh mana suatu bahan atau struktur dapat menahan tekanan atau beban tertentu sebelum mengalami deformasi atau kegagalan. Ujian kekuatan ini umumnya dilakukan pada berbagai jenis material, mulai dari logam dan beton hingga plastik dan bahan-bahan komposit.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1491, 8, 1, '132080106017', 'Hardness Test Machine', 'peralatan yang digunakan untuk mengukur tingkat kekerasan suatu material', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1492, 8, 1, '132080106020', 'Frais Machine', 'sebuah peralatan mesin yang digunakan untuk menghasilkan bentukan yang kompleks pada suatu benda kerja dengan menggunakan pemotongan atau pembentukan material dengan peralatan pemotong berputar. Proses ini melibatkan penggerakan benda kerja dan pemotongan yang dilakukan oleh alat pemotong yang dapat diatur dalam berbagai posisi dan sudut', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1493, 8, 1, '132080106027', 'Compaction', 'alat  yg digunakan untuk meratakan dan memadatkan tanah atau material konstruksi seperti tanah liat, pasir, kerikil, atau material dasar jalan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1494, 4, 1, '132070101024', 'Alat Ganti YKBS', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1495, 8, 1, '132080106031', 'Bending Press', 'alat/mesin pengepres untuk menekuk lembaran dan bahan logam, paling sering lembaran plat. Mesin ini membentuk sudut yang telah ditentukan dengan menjepit benda kerja antara punch dan dies yang cocok.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1496, 8, 1, '132080106032', 'Universal Test Machine (Alat Laboratorium Bahan Bangunan Konstruksi)', 'alat uji yang digunakan di laboratorium untuk melakukan pengujian kekuatan dan sifat mekanis berbagai bahan konstruksi dan material lainnya. UTM dapat mengukur berbagai parameter mekanis seperti kekuatan tarik, kekuatan tekan, kekuatan lentur, elastisitas, dan lainnya.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1497, 8, 1, '132080106033', 'Water Impermeability', 'sifat suatu material atau struktur untuk tidak membiarkan air atau cairan lainnya melewati permukaannya atau ketidaktembusan air', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1498, 8, 1, '132080106034', 'Cancrete Boring', 'proses dimana inti silinder (core) diambil dari struktur beton menggunakan mesin bor khusus', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1499, 8, 1, '132080106036', 'Grooting', 'proses injeksi material grout dengan tekanan dirongga atau pori rekahan pada batuan. Ada beberapa cara dalam melaksanakan grouting, yakni grouting tunggal dan grouting bertingkat', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1500, 8, 1, '132080106037', 'Mesin Penumbuk', 'Alat yg digunakan untuk meratakan dan memadatkan tanah di lokasi konstruksi.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1501, 4, 1, '132070101030', 'Automatic Spray Gonometer', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1502, 8, 1, '132080106038', 'Concreta Mixer/Penumbuk Beton', 'peralatan yang digunakan untuk mencampur atau menghancurkan beton', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1503, 4, 1, '132070101031', 'Bak Catheter', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1504, 8, 1, '132080106040', 'Abration Machine', 'Mesin yg digunakan dalam uji material untuk mengukur resistensi aus atau abrasi suatu bahan. Pada umumnya, uji abrasi dilakukan untuk menentukan sejauh mana suatu bahan dapat bertahan terhadap gesekan dan penggunaan yang berulang.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1505, 8, 1, '132080106042', 'Stone Crusher', 'mesin yang digunakan untuk menghancurkan batu besar menjadi ukuran yang lebih kecil atau menjadi kerikil, pasir, atau debu batu. Mesin ini sering digunakan dalam industri konstruksi, pertambangan, metalurgi, dan industri material lainnya.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1506, 8, 1, '132080106043', 'Instrument Strain Gauge', 'sensor yang digunakan untuk mengukur deformasi atau regangan pada suatu objek. Regangan adalah perubahan panjang atau dimensi suatu benda sebagai respons terhadap gaya yang bekerja padanya. Strain gauge bekerja dengan cara mengukur perubahan panjang atau regangan dan mengubahnya menjadi sinyal listrik yang dapat diukur.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1507, 4, 1, '132070101034', 'Bak Spuit', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1508, 8, 1, '132080106046', 'Mortar (Alat Laboratorium Bahan Bangunan Konstruksi)', 'campuran bahan yang digunakan untuk mengikat dan menyatukan bahan-bahan bangunan seperti batu bata atau blok beton. Mortar dapat berbentuk pasta atau bubuk dan biasanya terdiri dari campuran semen, pasir, dan air.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1509, 4, 1, '132070101035', 'Balon Spray', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1510, 8, 1, '132080106047', 'Termometer For Coumpound', 'Termometer industri biasanya digunakan untuk mengukur suhu benda atau alat-alat manufaktur, seperti panas air, mesin, AC atau pendingin ruangan, kolam renang, trafo, dan lain-lain. Tujuannya untuk memonitor suhu material cair guna menjaga kualitas pada proses manufaktur.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1511, 8, 1, '132080106048', 'Alat Pemeriksa Agrigat', 'Dalam industri konstruksi dan pengujian material, terdapat berbagai alat pemeriksa agregat yang digunakan untuk mengukur dan memeriksa sifat-sifat fisik dan mekanis dari agregat, yang merupakan bahan utama dalam pembuatan beton dan aspal.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1512, 8, 1, '132080106049', 'Sample Splitter Set', 'seperangkat peralatan yang digunakan untuk membagi atau memisahkan sampel material menjadi bagian yang lebih kecil dan representatif. Peralatan ini umumnya digunakan di laboratorium atau lapangan untuk mengambil sampel dari bahan padat seperti tanah, batuan, agregat, atau material konstruksi lainnya, dan membaginya menjadi bagian yang dapat diuji atau dianalisis.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1513, 8, 1, '132080106051', 'Alat Pemeriksa SP Gavity Air', 'alat yang digunakan untuk mengukur berat jenis udara (specific gravity of air). Meskipun pengukuran berat jenis udara tidak seumum pengukuran berat jenis bahan padat atau cair, alat ini mungkin digunakan dalam konteks tertentu seperti pengujian kebocoran atau perhitungan volume gas.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1514, 8, 1, '132080106054', 'Straight Edge', 'papan atau alat yang dirancang untuk memeriksa ketegakan atau dataran suatu permukaan. Ini digunakan untuk memastikan bahwa permukaan datar, lurus, dan bebas dari ketidakrataan', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1515, 8, 1, '132080106055', 'Alat Pemeriksa Beton', 'Ada berbagai alat pemeriksa beton yang digunakan dalam industri konstruksi dan pengujian bahan bangunan. Alat-alat ini membantu untuk memastikan kualitas dan kekuatan beton, serta untuk melakukan pemantauan kondisi struktur beton.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1516, 8, 1, '132080106057', 'Air Content Of Freckly Miced Concrette', 'Kandungan udara dalam beton yang baru dicampur (freshly mixed concrete) merujuk pada jumlah udara yang terperangkap atau tercampur dalam campuran beton sebelum proses pengerasan. Kandungan udara ini memiliki pengaruh penting terhadap sifat-sifat beton, terutama ketahanan terhadap perubahan suhu, tahan terhadap beban beku, dan ketahanan terhadap serangan siklus pembekuan dan pencairan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1517, 8, 1, '132080106058', 'Standard Spesial Spatula', 'Terdiri dari beberapa jenis spatula seperti spatula bergigi, spatula permukaan lebar. Memiliki beberapa fungsi seperti menyebarkan dan meratakan adukan semen, memperbaiki permukaan, atau mengaplikasikan bahan bangunan tertentu. Beberapa jenis spatula konstruksi memiliki bentuk dan ukuran yang berbeda untuk menangani tugas-tugas tertentu', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1518, 4, 1, '132070101043', 'Buli-Buli Panas', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1519, 8, 1, '132080106059', 'Tempat Benda Uji', 'lokasi atau struktur di mana benda uji atau sampel material konstruksi diuji untuk mengukur sifat-sifatnya. Tempat ini dirancang dan dilengkapi sesuai dengan kebutuhan uji dan metode pengujian tertentu. \nBeberapa tempat benda uji konstruksi umum melibatkan Laboratorium Struktur dan Material, Laboratorium Beton.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1520, 4, 1, '132070101044', 'Butomous P 02 Modul', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1521, 8, 1, '132080106060', 'Basic Cylinder Capping Set', 'seperangkat peralatan yang digunakan dalam laboratorium konstruksi untuk menutup atau membubut ujung silinder beton yang diuji. Proses capping ini penting untuk memastikan bahwa ujung silinder beton memiliki permukaan yang rata dan datar, sehingga dapat diuji secara akurat untuk menentukan kekuatan tekan beton.\n\nSet capping silinder beton umumnya mencakup beberapa komponen dasar. Berikut adalah beberapa komponen yang mungkin ada dalam Basic Cylinder Capping Set: Capping Compound,Melting Pot:', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1522, 8, 1, '132080106062', 'Concrette Hammer Set', 'seperangkat peralatan yang digunakan dalam pengujian beton atau material konstruksi untuk mengukur berbagai sifat seperti kekerasan atau kekuatan.\n\nBeberapa jenis peralatan yang mungkin termasuk dalam "Concrete Hammer Set" adalah, Rebound Hammer (Schmidt Hammer , Concrete Test Hammer', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1523, 4, 1, '132070101046', 'Capagati 3 L', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1524, 8, 1, '132080106063', 'Asbes Cosst', 'suatu kelompok mineral serat alami yang terdiri dari serat-serat yang kuat dan tahan panas. Asbes memiliki sifat-sifat fisik yang membuatnya berguna dalam berbagai aplikasi industri, terutama karena daya tahan panas, kekuatan, dan sifat isolasi termalnya.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1525, 8, 1, '132080106065', 'Beaker Low', 'alat kaca kimia yang digunakan untuk menakar secara semi-kuantitatif dan cenderung digunakan untuk memindahkan cairan dari satu tempat ke tempat yang lain', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1526, 8, 1, '132080106069', 'Trianle With Vorcelen Pipe Stems', 'peralatan laboratorium non-gelas yang digunakan sebagai penyangga atau penahan wadah seperti menahan krus saat proses pemanasan api langsung.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1527, 8, 1, '132080106070', 'Burrete & Standres', 'alat laboratorium yang digunakan untuk mengukur volume cairan dengan tingkat akurasi yang tinggi. Burette biasanya digunakan dalam titrasi, proses kimia di mana volume suatu larutan yang dikenal ditambahkan secara bertahap ke larutan lain hingga reaksi kimia mencapai kesetimbangan. Burette memiliki tingkat dan keran yang dapat diatur untuk mengontrol aliran cairan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1528, 8, 1, '132080106072', 'Analytical Balance (Alat Laboratorium Bahan Bangunan Konstruksi)', 'alat timbang analitik" adalah sebuah alat laboratorium yang digunakan untuk mengukur massa benda dengan tingkat ketelitian yang sangat tinggi. Alat ini biasanya digunakan dalam lingkungan laboratorium kimia, farmasi, dan penelitian ilmiah di mana ketelitian dan akurasi dalam pengukuran massa sangat penting.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1529, 4, 1, '132070101051', 'Colonofibers Cape', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1530, 8, 1, '132080106073', 'Aggregate Scale', 'alat atau perangkat yang digunakan untuk mengukur atau menimbang agregat sebelum dicampur dengan bahan lain dalam suatu konstruksi, seperti campuran beton. Skala ini membantu dalam mengontrol proporsi dan kualitas bahan yang digunakan dalam proyek konstruksi', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1531, 4, 1, '132070101052', 'Combilag', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1532, 8, 1, '132080106078', 'Flash Filtering', 'proses penyaringan atau filtrasi yang dilakukan dengan cepat atau dalam waktu singkat. Filtrasi adalah proses pemisahan padatan dari cairan menggunakan media penyaring, dan istilah "flash" mungkin merujuk pada kecepatan atau efisiensi proses tersebut.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1533, 8, 1, '132080106081', 'Sumber Daya Hydrolik', 'Sumber daya hidrolik adalah jenis energi yang dihasilkan dari fluida atau cairan, seperti minyak', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1534, 4, 1, '132070101054', 'Dale Dagion (Alat Kedokteran Umum)', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1535, 8, 1, '132080106083', 'Mesin Uji Hidrolik', 'peralatan uji yang menggunakan kekuatan hidrolik untuk mengaplikasikan beban atau tekanan pada benda uji dalam rangka mengukur sifat mekanisnya. Mesin ini sering digunakan untuk melakukan uji tarik, uji tekan, atau uji lentur pada berbagai jenis material seperti logam, beton, kayu, dan bahan-bahan lainnya.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1536, 4, 1, '132070101055', 'Defision Sehafulla Telector', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1537, 8, 1, '132080106084', 'Mesin Uji Listrik', 'peralatan yang dirancang untuk mengukur dan menguji sifat-sifat listrik dari berbagai komponen atau sistem. Mesin ini digunakan untuk memastikan bahwa peralatan listrik atau elektronik memenuhi standar tertentu dan berfungsi seperti yang diinginkan.\n\nBerikut adalah beberapa jenis mesin uji listrik yang umum digunakan adalah: Multimeter: Oscilloscope, Generator Fungsi, dll', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1538, 8, 1, '132080106085', 'Mesin Uji Mekanik(Manual)', 'perangkat atau sistem yang digunakan untuk melakukan berbagai jenis uji pada bahan atau komponen guna mengukur sifat-sifat mekaniknya. Mesin ini dirancang untuk memberikan pemahaman yang mendalam tentang karakteristik material, seperti kekuatan, elastisitas, kekerasan, keuletan, dan lain sebagainya.\n\nmemiliki beberapa jenis; Universal Testing Machine (UTM), Hardness Tester,', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1539, 8, 1, '132080106087', 'Pompa Hidrolik', 'perangkat mekanis yang digunakan untuk menggerakkan fluida hidrolik, biasanya minyak hidrolik, dari satu tempat ke tempat lainnya. Fluida hidrolik ini dapat digunakan untuk mentransmisikan daya dan mengendalikan gerakan dalam sistem hidrolik. Pompa hidrolik memiliki peran kunci dalam menghasilkan tekanan yang diperlukan untuk memindahkan fluida dan menggerakkan komponen hidrolik lainnya.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1540, 4, 1, '132070101058', 'Direct Reading Desimeter', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1541, 8, 1, '132080106088', 'Organic Impuriestest Set', 'digunakan untuk mendeteksi bahan organik berbahaya dalam agregat halus, sebuah pengujian yang sederhana dan banyak digunakan. Sampel dicampur dalam botol kaca khusus tak berwarna dengan larutan natrium hidroksida 3%, kemudian didiamkan selama 24 jam. Jika warna cairan supernatan di atas sampel uji lebih gelap dari warna referensi standar, mungkin terdapat senyawa organik dan pengujian lebih lanjut harus dilakukan sebelum disetujui.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1542, 4, 1, '132070101059', 'Dressing Card', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1543, 8, 1, '132080106089', 'Mesin Parkir', 'perangkat atau sistem otomatis yang dirancang untuk memfasilitasi dan mengatur proses parkir kendaraan secara efisien. Tujuan utama mesin parkir adalah mengoptimalkan penggunaan ruang parkir dan memudahkan manajemen lalu lintas kendaraan di area parkir.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1544, 8, 1, '132080107001', 'Oven Loss Onheating', 'suatu metode pengujian laboratorium yang digunakan untuk menentukan jumlah persentase berat dari suatu sampel yang hilang sebagai hasil pemanasan pada suhu tinggi, seringkali dengan mengukur perubahan massa. Prosedur ini umumnya digunakan dalam analisis kimia, terutama pada sampel-sampel yang mengandung bahan organik atau air.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1545, 8, 1, '132080107003', 'Viscosimeter (Alat Laboratorium Aspal,cat Dan Kimia)', 'Viskosimeter adalah alat laboratorium yang digunakan untuk mengukur viskositas suatu cairan. Viskositas mengukur sejauh mana suatu cairan mengalir atau resisten terhadap aliran. Dalam konteks aspal, cat, dan kimia, viskosimeter sering digunakan untuk mengukur viskositas bahan-bahan tersebut', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1546, 8, 1, '132080107004', 'Dustility Engler', 'salah satu parameter yang digunakan untuk mengukur kekenyalan atau keplastisan aspal atau bitumen. Engler Ductility memberikan gambaran tentang sejauh mana aspal dapat meregang atau membentang sebelum patah.\n\nEngler Ductility diukur dengan cara mengukur panjang maksimum yang dapat dicapai oleh sampel aspal saat ditarik sejajar pada suhu tertentu dan dalam kondisi uji tertentu. Sampel aspal ditarik dengan kecepatan tertentu hingga sampel tersebut patah. Panjang yang dicapai oleh sampel tersebut selama proses ini diukur dan dinyatakan dalam satuan milimeter.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1547, 4, 1, '132070101063', 'Esche Palce', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1548, 8, 1, '132080107007', 'Polarimeter (Alat Laboratorium Aspal,cat Dan Kimia)', 'instrumen laboratorium yang digunakan untuk mengukur rotasi bidang cahaya terpolarisasi saat melewati senyawa sampel yang menunjukkan aktivitas optik', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1549, 8, 1, '132080107008', 'Microskop Binacular', 'jenis mikroskop optik yang dilengkapi dengan dua lensa okuler (eyepiece) sehingga memungkinkan kedua mata digunakan untuk melihat sampel. Ini memberikan pengalaman pengamatan yang lebih nyaman dan alami dibandingkan dengan mikroskop monokular, di mana hanya satu mata yang digunakan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1550, 8, 1, '132080107010', 'Ring Ball Sparepart', 'metode pengujian viskositas aspal untuk menentukan titik lelehnya. Beberapa bagian atau sparepart yang umumnya terkait dengan uji ini dapat mencakup; Ring Ball Apparatus, Heating System, Termometer,Stirrer', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1551, 4, 1, '132070101066', 'Fantex Mark', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1552, 8, 1, '132080107014', 'Pesawat Kip', 'metode pengujian untuk menentukan kestabilan campuran aspal panas. Metode ini digunakan untuk mengukur sifat keretakan dan deformasi plastis campuran aspal ketika dikenai beban lalu lintas.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1553, 8, 1, '132080107015', 'Pinggan Uap', 'salah satu jenis alat laboratorium yang digunakan dalam uji agregat dan campuran aspal. Uji ini biasanya dilakukan untuk menilai sifat-sifat fisik dan mekanis dari campuran aspal panas. Uji "Pinggan Uap" termasuk dalam prosedur pengujian untuk menentukan kestabilan campuran aspal.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1554, 8, 1, '132080107016', 'Destilasi Aspal', 'metode pengolahan aspal untuk memisahkan komponen-komponennya berdasarkan perbedaan suhu pemanasan. Proses ini digunakan untuk mengukur fraksi berat aspal yang mudah menguap pada berbagai suhu. Destilasi aspal memberikan informasi tentang karakteristik volatilitas aspal, yang penting dalam mengevaluasi kinerja campuran aspal dan desain bahan jalan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1555, 8, 1, '132080107017', 'Corong Pemisah', 'peralatan laboratorium yang digunakan dalam ekstraksi cair-cair untuk memisahkan komponen-komponen dalam suatu campuran antara dua fase pelarut dengan densitas berbeda yang tak bercampur.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1556, 4, 1, '132070101070', 'Flurecent Lamp Komplit', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1557, 8, 1, '132080107019', 'Labu Syabolt Furol', 'metode pengukuran viskositas cairan, terutama produk minyak bumi, menggunakan viskometer Saybolt. Metode ini umumnya digunakan untuk mengukur viskositas aspal, minyak berat, dan zat cair kental lainnya.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1558, 8, 1, '132080107020', 'Rubber Mallet Atgentyler', 'alat yang digunakan untuk memberi gaya pada benda lain, sering kali terbuat dari karet atau terkadang kayu, yang lebih kecil dari maul atau kumbang, dan biasanya memiliki kepala yang relatif besar.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1559, 4, 1, '132070101072', 'Freakter EF 502', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1560, 8, 1, '132080107022', 'Density Basket', 'alat yang digunakan dalam pengujian laboratorium untuk menentukan berat jenis atau densitas agregat dan bahan lainnya dalam bentuk butiran. Pengukuran densitas ini penting dalam industri konstruksi, geoteknik, dan pengujian bahan untuk memastikan bahwa bahan memenuhi standar tertentu.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1561, 4, 1, '132070101073', 'Gantungan Urin Bag', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1562, 8, 1, '132080107023', 'Sand Equivalent', 'metode laboratorium yang digunakan untuk mengevaluasi sejauh mana partikel halus dalam tanah atau agregat mengandung material lembek atau silt yang mungkin mempengaruhi kinerja bahan dalam konstruksi. Metode ini umumnya digunakan dalam industri konstruksi dan teknik sipil.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1563, 8, 1, '132080107025', 'Talang CBR', 'alat yang digunakan untuk mengukur nilai California Bearing Ratio (CBR) dari agregat. Nilai CBR adalah ukuran ketahanan agregat terhadap beban. Semakin tinggi nilai CBR, semakin kuat agregat tersebut.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1564, 8, 1, '132080107026', 'Cylinder', 'pada "laboratory asphalt cylinder" atau "cylinder untuk laboratorium aspal." Biasanya, dalam konteks pengujian aspal atau bahan pengeras jalan di laboratorium, digunakan berbagai jenis silinder atau wadah untuk mengukur dan mengevaluasi berbagai properti fisik dan mekanis dari aspal.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1565, 4, 1, '132070101076', 'Groses Shalt Mogoglo Pamator', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1566, 8, 1, '132080107027', 'Dial Gauge LC.13', 'digunakan untuk mengukur berbagai parameter, seperti kekakuan, deformasi, atau perubahan dimensi pada sampel aspal atau bahan terkait lainnya selama pengujian. Alat ini dapat digunakan dalam berbagai uji, seperti uji kekakuan Marshall, uji kekakuan modulus dinamis, atau uji-ujian lainnya yang melibatkan pengukuran deformasi atau perubahan dimensi', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1567, 4, 1, '132070101077', 'Hypeal Carter', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1568, 8, 1, '132080107028', 'Cbr Lab. Set Cl.284', 'Indeks Daya Dukung California Bearing Ratio (CBR) adalah ukuran kekuatan tanah dan dapat digunakan untuk mengevaluasi daya dukung tanah di bawah permukaan jalan atau landasan lainnya. Uji CBR melibatkan pemasangan silinder atau plunger pada tanah dan mengukur tekanan yang diperlukan untuk menembus tanah pada kedalaman tertentu. Nilai CBR dinyatakan sebagai persentase tekanan yang dibutuhkan untuk menembus tanah di bawah kondisi uji tertentu dibandingkan dengan tekanan yang dibutuhkan untuk menembus tanah standar.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1569, 4, 1, '132070101078', 'Ice Crag', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1570, 8, 1, '132080107029', 'Sample Spliter Set Cl.284', 'alat ini dirancang khusus untuk mengelola sampel aspal sehingga dapat dipecah menjadi bagian yang representatif untuk uji laboratorium.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1571, 8, 1, '132080107031', 'Extraction Filter', 'filter yang digunakan dalam proses pengujian ekstraksi aspal dari campuran aspal-agregat. Proses ekstraksi ini biasanya melibatkan pemisahan aspal dari campuran agar kemudian aspal tersebut dapat diuji lebih lanjut atau dianalisis.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1572, 8, 1, '132080107033', 'Filed Leveset Cl.320', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1573, 8, 1, '132080107047', 'Bending Tester (Alat Laboratorium Aspal,cat Dan Kimia)', 'perangkat laboratorium yang digunakan untuk mengukur kekuatan lentur atau fleksibilitas dari berbagai bahan, termasuk aspal, cat, dan bahan kimia lainnya. Alat ini dapat memberikan informasi penting tentang sifat mekanis dan kinerja material ketika dikenakan beban lentur.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1574, 4, 1, '132070101082', 'IPPO', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1575, 8, 1, '132080107048', 'Fund Cryptometer', 'Alat ukur yang digunakan untuk mengukur daya tutup cat', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1576, 4, 1, '132070101083', 'Irrigator', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1577, 8, 1, '132080107052', 'Pycnometer', 'alat laboratorium yang digunakan untuk mengukur massa jenis atau densitas suatu zat. dimana alat yang digunakan untuk menentukan massa jenis dari suatu cairan. Sebuah piknometer biasanya terbuat dari kaca, dengan penyumbat ketat dengan pipa kapiler yang melaluinya, sehingga gelembung udara dapat lolos dari alat tersebut.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1578, 4, 1, '132070101084', 'Kariek Half Lazer', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1579, 8, 1, '132080108002', 'Sieve', 'Sieve atau saringan adalah salah satu alat laboratorium yang umum digunakan dalam bidang mekanika tanah dan batuan. Alat ini digunakan untuk memisahkan butiran atau partikel dari suatu sampel tanah atau batuan berdasarkan ukuran atau distribusi ukuran partikelnya. Pengujian dengan menggunakan saringan ini membantu dalam menentukan distribusi ukuran butiran dalam suatu sampel, yang dapat memberikan informasi penting tentang sifat fisik material tanah atau batuan', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1580, 8, 1, '132080108005', 'Triaxal For Sample', 'alat uji triaksial atau alat triaksial untuk sampel. Alat ini digunakan dalam uji mekanika tanah untuk mengevaluasi sifat-sifat geoteknis dan perilaku sampel tanah atau batuan dalam kondisi triaksial.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1581, 8, 1, '132080108008', 'Jack CBR', 'perangkat yang digunakan dalam uji CBR (California Bearing Ratio). Uji CBR adalah salah satu uji laboratorium yang umum digunakan untuk mengukur daya dukung tanah di bawah kondisi tertentu. Jack CBR adalah komponen penting dalam uji CBR dan digunakan untuk menerapkan beban axial pada sampel tanah', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1582, 8, 1, '132080108010', 'Diract Shear', 'salah satu uji mekanika tanah yang umum digunakan untuk mengevaluasi sifat geser tanah di bawah berbagai kondisi tekanan dan deformasi. Alat laboratorium yang digunakan untuk melakukan uji geser langsung ini disebut alat uji geser langsung atau "Direct Shear Apparatus', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1583, 8, 1, '132080108013', 'Konsolidasi', 'salah satu uji laboratorium yang digunakan dalam mekanika tanah untuk mengevaluasi perilaku deformasi tanah pada saat diberikan beban dan kondisi pemadatan. Alat laboratorium yang digunakan untuk melakukan uji konsolidasi dikenal sebagai "Consolidation Apparatus" atau "Consolidometer."', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1584, 8, 1, '132080108015', 'Proctor Standard', 'salah satu uji laboratorium yang umum digunakan dalam mekanika tanah untuk menentukan parameter konsolidasi dan karakteristik pemadatan tanah. Alat laboratorium yang digunakan untuk melakukan uji ini dikenal sebagai "Standard Proctor Compaction Apparatus" atau "Standard Proctor Test Apparatus."', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1585, 4, 1, '132070101090', 'Lono Premansi Stimulator Adi', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1586, 8, 1, '132080108018', 'Safe Card', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1587, 8, 1, '132080108020', 'Soil Test', 'Uji tanah merupakan bagian integral dari mekanika tanah dan batuan di bidang rekayasa sipil dan geoteknik. Sejumlah alat laboratorium digunakan dalam uji tanah untuk mengevaluasi berbagai sifat fisik dan mekanik tanah.\n\nterdiri dari beberapa alat laboratorium mekanika tanah yang umum digunakan dalam uji tanah', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1588, 8, 1, '132080108021', 'Camera Atterberg', 'serangkaian pengujian laboratorium yang mengukur sifat-sifat plastis tanah dan memberikan informasi tentang perilaku tanah pada berbagai kondisi kelembaban. Beberapa alat dan perangkat yang umum digunakan dalam pengujian batas Atterberg melibatkan pengukuran konsistensi tanah.\nBeberapa alat tersebut meliputi: Cone Penetrometer (Alat Penetrasi Cone), Cup and Grooving Tool (Cangkir dan Alat Pembentukan Rongga), Rolling Dish Method (Metode Piringan Bergulir', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1589, 8, 1, '132080108022', 'Comodifier', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1590, 4, 1, '132070101094', 'Mark Biotazer', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1591, 8, 1, '132080108023', 'Mobile Laboratorium Set', 'set peralatan laboratorium yang dirancang dan dibuat untuk dapat dipindahkan atau digunakan secara mobile. Mobile laboratorium set biasanya dilengkapi dengan peralatan dan instrumen laboratorium yang diperlukan untuk melakukan pengujian dan analisis di lapangan atau lokasi proyek.\nMobile laboratorium set biasanya diintegrasikan ke dalam kendaraan atau trailer yang dapat dipindahkan ke lokasi proyek atau area di mana pengujian diperlukan. Ini memungkinkan insinyur dan peneliti untuk melakukan evaluasi langsung di lapangan tanpa harus membawa sampel ke laboratorium pusat. Mobile laboratorium ini sering digunakan dalam proyek konstruksi, eksplorasi geoteknik, dan pemantauan lingkungan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1592, 8, 1, '132080108024', 'Liquid Limit', 'Liquid Limit (LL) adalah batas air di mana tanah berubah dari keadaan plastis menjadi keadaan cair. Pada batas ini, tanah memiliki kekuatan geser yang sangat rendah dan mudah mengalir.  \n Liquid Limit biasanya ditentukan dengan menggunakan alat Cassagrande. Alat ini terdiri dari sebuah tabung berbentuk silinder dengan diameter 50 mm dan tinggi 100 mm. Di bagian bawah tabung terdapat piring kecil dengan diameter 10 mm.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1593, 8, 1, '132080108026', 'Modified Mold', 'metode laboratorium untuk menentukan eksperimental kadar air yang optimal dimana suatu jenis tanah tertentu akan menjadi paling padat dan mencapai kepadatan kering maksimum.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1594, 4, 1, '132070101097', 'Module Parabeden Trandezer', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1595, 8, 1, '132080108027', 'Allon Box', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1596, 4, 1, '132070101098', 'Nasal Clip', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1597, 8, 1, '132080108028', 'Propping Ring', 'Alat ini digunakan untuk mengukur gaya yang dihasilkan oleh tanah ekspansif pada saat pembasahan. Tanah akan mengembang dan mendorong ke atas yang diterima oleh luasan piringan. Besarnya gaya dapat dibaca pada dial gauge.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1598, 4, 1, '132070101099', 'Natrilisangfas Fas Instal', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1599, 8, 1, '132080108029', 'Triple Beam Balance Cent Gram', 'alat pengukur berat yang digunakan untuk menimbang massa suatu benda. "Centi-gram" menunjukkan bahwa skala pada triple beam balance tersebut dibagi dalam satuan gram, dan "centi" menunjukkan bahwa skala ini kemungkinan besar memiliki pembagian skala dalam bentuk centi-gram.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1600, 8, 1, '132080108030', 'Heavy Duty Solution Balance', 'tiimbangan untuk menangani beban berat atau kondisi penggunaan yang lebih berat dibandingkan dengan timbangan standar. Timbangan jenis ini sering digunakan dalam lingkungan industri atau laboratorium yang membutuhkan ketahanan dan keandalan tinggi.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1601, 8, 1, '132080108031', 'Balance (Alat Laboratorium Mekanika Tanah Dan Batuan)', 'Timbangan adalah alat yang umum digunakan dalam laboratorium mekanika tanah dan batuan untuk menimbang massa benda atau sampel. Timbangan ini memainkan peran krusial dalam mengukur dan menganalisis sifat-sifat fisik dan mekanik tanah serta batuan. Berbagai jenis timbangan digunakan tergantung pada kebutuhan spesifik dari pengujian atau eksperimen yang dilakukan.\nBerikut adalah beberapa jenis timbangan yang umum digunakan di laboratorium mekanika tanah dan batuan; Timbangan Analitik, Timbangan Presisi, Timbangan Mekanik.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1602, 4, 1, '132070101102', 'Netlin', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1603, 8, 1, '132080108032', 'Thermolyne', 'merek yang dikenal dalam industri peralatan laboratorium, terutama dalam bidang pemanasan dan peralatan pengadukan. Beberapa diantaranya yaitu Pengaduk Magnetik Thermolyne, Pemanas Mantel Thermolyne, Furnas dan Pemanas Listrik.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1604, 4, 1, '132070101103', 'Nichulis', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1605, 8, 1, '132080108033', 'Torab Sieve Shaker', 'alat laboratorium yang digunakan untuk mengayak atau menyaring material seperti tanah, agregat, atau bahan lainnya dalam berbagai ukuran partikel. Alat ini umumnya digunakan dalam analisis granulometri untuk menentukan distribusi ukuran partikel dalam suatu sampel.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1606, 8, 1, '132080108034', 'Modified Field Compaction Mold', 'metode laboratorium untuk menentukan eksperimental kadar air yang optimal dimana suatu jenis tanah tertentu akan menjadi paling padat dan mencapai kepadatan kering maksimum.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1607, 8, 1, '132080108037', 'Drilling', 'metode pemboran yang menggunakan aksi putaran untuk melakukan penetrasi terhadap batuan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1608, 4, 1, '132070101106', 'One Compartement Warrobe (Alat Kedokteran Umum)', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1609, 8, 1, '132080108040', 'Aggregates', 'Aggregates dapat merujuk pada batuan yang terdiri dari partikel-partikel yang lebih kecil dan dapat digunakan dalam konstruksi atau pembangunan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1610, 8, 1, '132080108043', 'Electric Stop Watch', 'sebuah alat yang digunakan untuk mengukur waktu dengan menggunakan teknologi listrik atau elektronik. Berbeda dengan stop watch mekanis yang menggunakan roda gigi dan pergerakan mekanis, electric stop watch biasanya menggunakan sirkuit elektronik untuk menghasilkan dan mengukur waktu', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1611, 8, 1, '132080108044', 'Lightweight Concrete Test Hammer', 'alat uji yang digunakan untuk mengukur kekerasan beton ringan atau beton bermassa rendah. Alat ini dapat digunakan dalam pengujian non-destruktif untuk mengevaluasi kekuatan beton dan dapat memberikan perkiraan nilai kekerasan beton di permukaan struktur.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1612, 4, 1, '132070101109', 'Pathologi Equipment', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1613, 8, 1, '132080108046', 'Asphalt Stability Testing Machine', 'peralatan laboratorium yang digunakan untuk mengukur stabilitas campuran aspal. Stabilitas adalah salah satu parameter penting dalam menilai kualitas campuran aspal, terutama dalam konstruksi jalan. Peralatan ini membantu menentukan sejauh mana campuran aspal dapat menahan beban dan tekanan serta mempertahankan integritas strukturnya', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1614, 4, 1, '132070101110', 'Pereksimea Fondus', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1615, 8, 1, '132080108049', 'Penetrasi Asphalt (Universal Penetrometer)', 'salah satu metode pengujian yang digunakan untuk mengukur kelembutan atau kekenyalan aspal pada berbagai suhu. Universal Penetrometer adalah alat laboratorium yang umum digunakan untuk melakukan pengujian ini. Pengukuran ini penting dalam industri konstruksi jalan karena kelembutan aspal dapat mempengaruhi performa dan daya tahan campuran aspal.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1616, 4, 1, '132070101111', 'Perfin Disposseri', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1617, 8, 1, '132080108050', 'Air Circulationpan', 'peralatan atau sistem yang digunakan untuk menciptakan sirkulasi udara dalam suatu ruang atau area tertentu. Peralatan ini umumnya digunakan di laboratorium, industri, atau lingkungan lain di mana sirkulasi udara yang baik diperlukan untuk tujuan tertentu.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1618, 4, 1, '132070101112', 'Pispot Anak', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1619, 8, 1, '132080108053', 'Vicat Apparatus', 'alat yang digunakan dalam industri konstruksi dan laboratorium untuk mengukur waktu pengaturan semen hidraulis dan mortir. Metode pengujian ini dikenal sebagai Pengujian Penetrasi Vicat atau Vicat Needle Test. Pengujian ini memberikan informasi tentang waktu yang dibutuhkan semen untuk mencapai konsistensi tertentu setelah dicampur dengan air, yang merupakan indikator pengaturan awal semen.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1620, 8, 1, '132080108054', 'Flow Table (Alat Laboratorium Mekanika Tanah Dan Batuan)', 'alat yang digunakan dalam laboratorium mekanika tanah untuk mengukur kekentalan atau konsistensi tanah plastis atau campuran tanah dan air. Alat ini umumnya digunakan untuk menentukan indeks kekentalan tanah, yang merupakan salah satu parameter penting dalam karakterisasi tanah dari segi sifat-sifat plastisnya.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1621, 4, 1, '132070101114', 'Plase Phone Doples', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1622, 8, 1, '132080108056', 'Analytical Balance (Alat Laboratorium Mekanika Tanah Dan Batuan)', 'Timbangan adalah alat yang umum digunakan dalam laboratorium mekanika tanah dan batuan untuk menimbang massa benda atau sampel. Timbangan ini memainkan peran krusial dalam mengukur dan menganalisis sifat-sifat fisik dan mekanik tanah serta batuan. Berbagai jenis timbangan digunakan tergantung pada kebutuhan spesifik dari pengujian atau eksperimen yang dilakukan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1623, 8, 1, '132080108057', 'Stump Test T', 'pengujian umum yang digunakan dalam industri konstruksi untuk mengukur kemampuan kerja atau konsistensi beton yang baru dicampur. Ini menilai tingkat fluiditas dan kekompakan campuran beton, memberikan indikasi kemudahan penempatan dan potensi konsolidasi. Huruf "T" dalam "Slump Test T" dapat merujuk pada modifikasi atau variasi tertentu dari prosedur pengujian slump standar.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1624, 4, 1, '132070101116', 'Presatre Module', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1625, 8, 1, '132080108059', 'Switch Backer', 'Switch jaringan dapat digunakan sebagai penghubung komputer atau perute pada satu area yang terbatas, pengalih juga bekerja pada lapisan taut data, cara kerja pengalih hampir sama seperti jembatan, tetapi switch memiliki sejumlah porta sehingga sering dinamakan jembatan pancaporta', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1626, 4, 1, '132070101117', 'Primatik Nidel', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1627, 8, 1, '132080108060', 'Air Compressor (Alat Laboratorium Mekanika Tanah Dan Batuan)', 'Di laboratorium medis, air compressor digunakan untuk menyediakan udara bertekanan yang dibutuhkan dalam berbagai proses dan peralatan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1628, 8, 1, '132080108062', 'Gravity Core Sediment Sampler', 'jenis alat yang digunakan untuk mengambil sampel sedimen dari dasar laut atau badan air lainnya. Alat ini mengandalkan gaya gravitasi untuk menembus lapisan sedimen dan mengambil inti sedimen yang tidak terganggu untuk dianalisis. Gravity Core Sediment Sampler umumnya digunakan dalam penelitian kelautan, sedimentologi, dan studi lingkungan untuk mempelajari komposisi, struktur, dan sejarah sedimen.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1629, 8, 1, '132080109002', 'Test For Temperature', 'Pengujian temperatur di laboratorium batuan dapat mencakup beberapa metode untuk mengevaluasi respons batuan terhadap perubahan suhu. Pengujian temperatur ini penting untuk memahami perilaku batuan di berbagai kondisi lingkungan, terutama di bidang geoteknik dan rekayasa sipil.\nBeberapa metode umum untuk menguji temperatur di laboratorium batuan termasuk; Thermal Conductivity Test, Thermal Expansion Test:Freeze-Thaw Test.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1630, 8, 1, '132080109008', 'Micronaire (Alat Laboratorium Cocok Tanam)', 'salah satu parameter yang digunakan dalam menentukan kualitas serat kapas. Ini adalah ukuran dari kehalusan serat kapas yang dihasilkan oleh tanaman kapas. Micronaire diukur dalam satuan angka dan digunakan untuk menilai kecocokan serat kapas untuk keperluan industri tekstil.\nMicronaire Tester" atau "Micronaire Meter". Alat ini dirancang khusus untuk mengukur diameter, kehalusan, dan kepadatan serat kapas yang diperoleh dari sampel kapas tertentu.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1631, 9, 1, '132080110001', 'Wheel Balancer', 'alat penyeimbang roda adalah perangkat yang digunakan untuk menyeimbangkan roda dan ban kendaraan. Tujuan utama dari penyeimbangan roda adalah untuk memastikan bahwa berat distribusi di sekitar roda dan ban adalah merata. Penyeimbangan yang baik dapat menghindari getaran yang tidak diinginkan pada kendaraan dan meningkatkan kenyamanan serta stabilitas saat berkendara', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1632, 9, 1, '132080110002', 'Speed Band Tester', 'penguji telekomunikasi canggih yang mudah digunakan dan dipegang tangan yang digunakan untuk pemasangan, pemeliharaan, dan pengukuran layanan ADSL2 +. Mendukung fungsi pengujian seperti parameter, kesalahan, DMM, PING yang terkait dengan layanan ADSL2 +, otentikasi daftar pengguna di sisi jalur pengguna ADSL2 +. Ini juga secara langsung memungkinkan para insinyur untuk memverifikasi, memecahkan masalah dan mengevaluasi layanan ADSL2 +', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1633, 9, 1, '132080110003', 'Speed Meter Tester', 'perangkat atau alat yang digunakan untuk mengukur kecepatan suatu objek atau aliran. Pengukuran kecepatan dapat dilakukan dalam berbagai konteks, termasuk pengukuran kecepatan kendaraan, kecepatan angin, atau kecepatan aliran fluida.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1634, 4, 1, '132070101124', 'Rinnon Miliable Resaftor', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1635, 9, 1, '132080110004', 'Engine Dinamo Meter', 'sistem yang mencakup penggunaan dinamometer dan perangkat elektronik lainnya untuk mengukur kinerja mesin, termasuk torsi dan daya, di lingkungan yang dikendalikan', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1636, 9, 1, '132080110005', 'Head Light Tester', 'alat pengukur cahaya lampu depan adalah perangkat yang digunakan untuk mengukur intensitas cahaya yang dipancarkan oleh lampu depan kendaraan, seperti mobil atau sepeda motor. Pengukuran ini penting untuk memastikan bahwa lampu depan kendaraan memenuhi standar keselamatan jalan raya dan tidak menyebabkan gangguan atau bahaya bagi pengendara lain.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1637, 9, 1, '132080110006', 'Wheel Aligment Tester', 'alat pengukur sejajar roda adalah perangkat yang digunakan untuk memeriksa dan mengukur sejajar roda kendaraan. Proses pengecekan sejajar roda diperlukan untuk memastikan bahwa roda kendaraan berada dalam posisi yang tepat dan sejajar sesuai dengan spesifikasi pabrik. Pengecekan dan penyesuaian sejajar roda penting untuk menjaga keseimbangan, stabilitas, dan keamanan kendaraan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1638, 4, 1, '132070101127', 'R-HER Coacgulator', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1639, 9, 1, '132080110007', 'Camber Caster King Pin Gauge', 'alat yang digunakan dalam proses pengukuran dan penyesuaian sejajar roda pada kendaraan. Setiap parameter memiliki peran penting dalam menjaga keseimbangan, stabilitas, dan kinerja kendaraan', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1640, 4, 1, '132070101128', 'Saeperingsystem', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1641, 9, 1, '132080110008', 'Toe In Gauge', 'alat yang berguna untuk mengukur jarak toe in dan toe out pada roda kendaraan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1642, 4, 1, '132070101129', 'Schates', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1643, 9, 1, '132080110009', 'Rough Load Tester', 'pengujian beban pada permukaan kasar atau tidak rata untuk mengevaluasi sifat gesekan dan pelumasan dalam kondisi yang sulit', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1644, 4, 1, '132070101130', 'Screm Holder Red', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1645, 9, 1, '132080110011', 'Axle Load Tester', 'perangkat yang digunakan untuk mengukur beban pada setiap sumbu kendaraan. Sistem ini berguna untuk memastikan bahwa kendaraan mematuhi batasan beban yang ditetapkan oleh peraturan lalu lintas dan regulasi keamanan jalan raya. Pengukuran beban pada setiap sumbu kendaraan membantu mencegah beban berlebih, yang dapat merusak jalan raya dan infrastruktur, serta meningkatkan keselamatan lalu lintas.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1646, 4, 1, '132070101131', 'Setum Adrenalin', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1647, 9, 1, '132080110012', 'Steering Angle Tester', 'perangkat yang digunakan untuk mengukur sudut kemudi pada kendaraan. Pengukuran sudut kemudi ini penting dalam menentukan apakah sistem kemudi kendaraan berfungsi dengan baik dan apakah sudut kemudi berada dalam batasan yang diperbolehkan', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1648, 9, 1, '132080110013', 'Diesel Injection Pump Tester', 'perangkat atau alat yang digunakan untuk menguji dan memeriksa kinerja pompa bahan bakar diesel pada kendaraan bermesin diesel. Pompa bahan bakar diesel memainkan peran krusial dalam menyuntikkan bahan bakar ke dalam ruang bakar mesin dengan tekanan yang tepat dan pada waktu yang sesuai. Pengujian menggunakan Diesel Injection Pump Tester membantu memastikan bahwa pompa bahan bakar berfungsi dengan baik, sehingga mesin dapat bekerja secara efisien.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1649, 9, 1, '132080110014', 'Nozle Tester', 'alat yang digunakan untuk menguji dan memeriksa kinerja injector nozzle pada sistem bahan bakar diesel. Injector nozzle adalah komponen kritis dalam sistem bahan bakar, yang bertanggung jawab untuk menyemprotkan bahan bakar ke dalam ruang bakar mesin dengan tekanan dan pola penyemprotan yang tepat. Pengujian dengan Nozzle Tester membantu memastikan bahwa injector nozzle berfungsi dengan baik, sehingga penyemprotan bahan bakar dapat dilakukan secara efisien.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1650, 9, 1, '132080110015', 'Engine Running In Tester', 'perangkat yang digunakan untuk menjalankan dan menguji mesin kendaraan secara khusus selama proses "running in" atau tahap pemakaian awal mesin. Proses running-in biasanya dilakukan pada mesin baru atau setelah perbaikan besar untuk mengoptimalkan performa dan umur pakai mesin', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1651, 9, 1, '132080110016', 'Diesel Smoke Tester', 'perangkat yang digunakan untuk mengukur dan menilai tingkat asap yang dihasilkan oleh mesin diesel. Pemeriksaan tingkat asap penting untuk memastikan bahwa kendaraan mematuhi regulasi emisi dan untuk menilai kinerja mesin. Tingkat asap yang tinggi dapat menunjukkan adanya masalah pada pembakaran atau sistem bahan bakar.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1652, 4, 1, '132070101136', 'Spoon Oxigen Correction', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1653, 9, 1, '132080110017', 'Hidraulik System Tester', 'perangkat yang digunakan untuk mengukur dan memantau tekanan dalam sistem hidrolik. Sistem hidrolik banyak digunakan dalam berbagai aplikasi, termasuk di bidang otomotif, industri, dan peralatan berat. Hydraulic System Tester membantu dalam melakukan pengujian dan pemeliharaan pada sistem hidrolik untuk memastikan bahwa tekanan dalam sistem berada dalam rentang yang aman dan sesuai dengan spesifikasi.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1654, 9, 1, '132080110018', 'Valve Spring Tester', 'alat yang digunakan untuk mengukur tekanan yang dihasilkan oleh pegas katup (valve spring) pada mesin kendaraan. Pegas katup adalah komponen kritis dalam sistem katup mesin, dan tekanan yang dihasilkan oleh pegas tersebut memainkan peran penting dalam fungsi mesin, khususnya dalam mengontrol gerakan katup.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1655, 9, 1, '132080110019', 'Tune Up Tester (Alat Laboratorium Logam, Mesin Dan Listrik)', 'perangkat yang digunakan dalam proses penyetelan atau pemeliharaan rutin pada mesin atau sistem listrik. Penyetelan atau tune-up pada mesin umumnya melibatkan pemeriksaan, penyesuaian, atau penggantian beberapa komponen kritis untuk memastikan kinerja optimal. Sementara itu, dalam konteks listrik, tune-up bisa merujuk pada pemeriksaan dan perbaikan pada sistem listrik.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1656, 9, 1, '132080110020', 'Universal Test', 'sebuah mesin yang telah dikembangkan berdasarkan pengetahuan sensor tekanan dan teknologi pengatur hitungan yang berguna untuk menguji ketahanan, kekuatan tarik, dan mengetahui struktur suatu bahan maupun material sebuah produk', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1657, 4, 1, '132070101140', 'Standard Colector For Table', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1658, 9, 1, '132080110021', 'Generator Test', 'prosedur pengujian atau pemeriksaan generator listrik untuk memastikan kinerjanya yang optimal. Ini mungkin melibatkan pengujian keandalan, kapasitas, dan fungsi keamanan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1659, 4, 1, '132070101141', 'Steritionoscope Transpometer', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1660, 9, 1, '132080110022', 'Auto Analyser Unit', 'alat atau sistem otomatis yang digunakan dalam laboratorium untuk melakukan analisis kimia otomatis pada sampel cair. Alat ini digunakan untuk mengukur berbagai parameter kimia, seperti konsentrasi zat tertentu dalam larutan. AutoAnalyzer sangat efisien dalam pengujian rutin dan memproses sejumlah besar sampel dengan cepat.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1661, 9, 1, '132080110023', 'Timing Advancetester', 'alat yang digunakan untuk mengukur dan menilai sudut pengapian pada sistem pengapian mesin kendaraan. Sudut pengapian mengacu pada waktu ketika busi dinyalakan selama siklus pembakaran dalam silinder mesin. Pengaturan sudut pengapian yang tepat penting untuk mengoptimalkan efisiensi pembakaran dan kinerja mesin.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1662, 9, 1, '132080110025', 'Combustion Tester', 'alat yang digunakan untuk mengukur dan mengevaluasi proses pembakaran di dalam ruang bakar mesin. Ini membantu dalam memeriksa kualitas pembakaran dan sejumlah parameter yang terkait dengan efisiensi mesin dan emisi gas buang.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1663, 9, 1, '132080110028', 'Volt Ampere Tester', 'V-A Tester atau Power Meter, adalah alat yang digunakan untuk mengukur tegangan (Volt) dan arus (Ampere) pada suatu sistem listrik atau perangkat listrik. Alat ini membantu dalam menilai daya listrik yang dikonsumsi atau dihasilkan oleh suatu perangkat atau sirkuit.\nBeberapa fitur umum dari Volt-Ampere Tester meliputi:', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1664, 9, 1, '132080110029', 'Distributor Tester', 'alat yang digunakan untuk menguji dan memeriksa kinerja distributor pada sistem pengapian kendaraan bermesin konvensional. Distributor adalah bagian penting dari sistem pengapian yang bertanggung jawab untuk mengatur waktu pengapian, memastikan busi menyala pada waktu yang tepat selama siklus pembakaran dalam mesin.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1665, 4, 1, '132070101146', 'The Newsillerstration Of Acpint', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1666, 9, 1, '132080110030', 'Voltage Regulator Tester', 'alat yang digunakan untuk menguji dan mengevaluasi kinerja regulator tegangan pada sistem listrik kendaraan. Regulator tegangan adalah komponen yang mengontrol tegangan keluaran dari generator atau alternator, memastikan bahwa tegangan yang dihasilkan sesuai dengan kebutuhan sistem listrik kendaraan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1667, 4, 1, '132070101147', 'Timer Ekolo', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1668, 9, 1, '132080110031', 'Diode Tester', 'Diode Checker atau Diode Test Mode pada multimeter digital, adalah alat yang digunakan untuk menguji dioda dan menentukan apakah dioda tersebut masih berfungsi dengan baik. Dioda adalah komponen elektronik yang mengizinkan arus listrik mengalir hanya ke satu arah.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1669, 4, 1, '132070101148', 'Tre Chanel Extra Cardiografi', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1670, 9, 1, '132080110034', 'Alat Penguji Tegangan (Tarik Tekan)', 'alat pengujian yang berfungsi untuk menguji tegangan tarik (tensile test), uji tekan (compression test) dan uji lengkung (bending test) suatu material agar dapat mengetahui karakteristik atau seberapa kuat material tersebut.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1671, 4, 1, '132070101149', 'Trigatus', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1672, 9, 1, '132080110035', 'Alat Penguji Kekerasan (Hardness Tester)', 'alat penguji kekerasan adalah sebuah alat yang digunakan untuk mengukur nilai kekerasan atau kekakuan suatu material. Nilai kekerasan tersebut didapat dengan menekan indentor ke permukaan benda uji', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1673, 9, 1, '132080110037', 'Alat Penguji Jenis Logam', 'perangkat atau metode yang digunakan untuk mengidentifikasi atau menguji jenis logam', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1674, 9, 1, '132080110038', 'Abrations Srength Tester (Alat Penguji Tahan Aus)', 'Alat Penguji Tahan Aus, adalah alat yang digunakan untuk mengukur ketahanan suatu material terhadap gesekan dan abrasi', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1675, 9, 1, '132080110039', 'Bursting Srength Tester (Alat Penguji Letup)', 'perangkat yang digunakan untuk mengukur kekuatan perlawanan suatu bahan atau kemasan terhadap tekanan atau kekuatan mekanis yang dapat menyebabkan "letup" atau pecah. Alat ini umumnya digunakan dalam industri pengemasan, tekstil, dan kertas untuk memastikan kekuatan dan daya tahan bahan terhadap tekanan internal.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1676, 9, 1, '132080110041', 'Finish Head Resistance Tester', 'sebuah alat pengukur digital yang digunakan untuk mengukur nilai resistansi / tahanan dari grounding', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1677, 9, 1, '132080110042', 'Sastra Adhesion Tester', 'mengukur daya rekat atau kelekatan antara dua material, seperti lapisan cat pada permukaan logam atau bahan perekat pada substrat tertentu. Metode pengujian dapat bervariasi tergantung pada aplikasi dan kebutuhan spesifik, dan alat ini sering digunakan dalam industri cat, lapisan, dan perekat untuk memastikan kualitas dan daya rekat yang memadai.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1678, 4, 1, '132070101155', 'Cool Light', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1679, 9, 1, '132080110044', 'Stiff Ness Tester', 'Alat ini digunakan untuk mengukur kekakuan atau kekakuan suatu bahan, biasanya dalam bentuk lembaran atau kertas. Pengukuran kekakuan sangat penting dalam berbagai industri, termasuk industri kertas, tekstil, dan bahan kemasan.\nStiffness Tester umumnya dapat mengukur kekakuan secara dua arah, yaitu MD (Mesin Direction) dan CD (Cross Direction) pada kertas atau material lainnya. Pengukuran kekakuan dapat membantu menentukan karakteristik mekanis dan kemampuan penanganan material, serta dapat berpengaruh pada performa produk akhir.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1680, 4, 1, '132070101156', 'Vegdes Labry Splyt Genotpone', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1681, 9, 1, '132080110045', 'Folding Endurance Tester', 'alat pengujian yang digunakan untuk mengukur ketahanan tarik atau kekuatan robek suatu bahan, khususnya kertas atau bahan fleksibel lainnya. Alat ini membantu menentukan sejauh mana bahan tersebut tahan terhadap robekan atau tarikan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1682, 9, 1, '132080110047', 'Falling Dart Impact Tester', 'alat pengujian yang digunakan untuk menilai ketahanan terhadap dampak pada suatu bahan atau produk, terutama pada bahan kemasan plastik. Pengujian ini memberikan informasi tentang sejauh mana bahan dapat menahan kerusakan atau retak akibat pukulan atau benturan yang tiba-tiba.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1683, 9, 1, '132080110048', 'Rubber Compresion Tester', 'alat pengujian yang digunakan untuk mengukur sifat kompresi atau perubahan dimensi yang dialami oleh bahan karet ketika dikenakan tekanan. Pengujian ini memberikan informasi tentang elastisitas dan kemampuan bahan karet untuk kembali ke bentuk aslinya setelah diberikan tekanan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1684, 4, 1, '132070101159', 'Holter Panthon (RM)', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1685, 9, 1, '132080110050', 'BOD Tester', 'alat yang digunakan untuk mengukur Biochemical Oxygen Demand (BOD) dalam suatu sampel air. BOD adalah parameter yang digunakan untuk menilai tingkat pencemaran organik dalam air. Pengukuran BOD memberikan indikasi tentang jumlah oksigen yang dibutuhkan oleh mikroorganisme untuk mendekomposisi bahan organik dalam air.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1686, 4, 1, '132070101160', 'Went Allyn Apthacape', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1687, 9, 1, '132080110053', 'Upper Meterial Flexing', 'pengujian kekuatan dan ketahanan material yang digunakan pada bagian atas (upper) sepatu atau produk sejenis. Pengujian lentur untuk bahan upper umumnya melibatkan pengukuran seberapa baik bahan tersebut dapat menahan atau menyesuaikan diri dengan gerakan fleksibel, seperti gerakan kaki saat berjalan atau berlari. Pengujian ini membantu menilai kenyamanan, daya tahan, dan performa umum dari material yang digunakan pada bagian atas sepatu.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1688, 9, 1, '132080110056', 'Alfa Laboratory Sample Cutter', 'alat atau perangkat yang digunakan untuk memotong sampel dalam konteks laboratorium atau pengujian material. Perangkat ini digunakan untuk memotong sampel material dengan presisi untuk keperluan pengujian atau analisis laboratorium. Penggunaan pemotong sampel dapat bervariasi tergantung pada jenis bahan yang diuji dan jenis pengujian yang dilakukan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1689, 9, 1, '132080110057', 'Shobury Corumeter', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1690, 9, 1, '132080110060', 'Tensile Head Distortion (Alat Laboratorium Logam, Mesin Dan Listrik)', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1691, 4, 1, '132070101164', 'Aeskular', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1692, 9, 1, '132080110061', 'Ultrasonic Flow Detector (Alat Laboratorium Logam, Mesin Dan Listrik)', 'perangkat yang digunakan untuk mengukur laju aliran fluida menggunakan prinsip gelombang ultrasonik. Perangkat ini sering digunakan dalam berbagai aplikasi industri, termasuk industri logam, mesin, dan listrik, untuk mengukur aliran fluida seperti air, minyak, gas, dan cairan lainnya.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1693, 9, 1, '132080110062', 'Dinamic Signal Analizer', 'perangkat atau sistem yang digunakan untuk menganalisis dan mengukur sinyal dinamis pada berbagai aplikasi, termasuk dalam bidang industri, laboratorium, dan penelitian. Alat ini dapat digunakan untuk memantau, menganalisis, dan merekam sinyal-sinyal dinamis yang bervariasi seiring waktu', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1694, 4, 1, '132070101166', 'Fris Ard', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1695, 9, 1, '132080110063', 'Pressure Gauge (Alat Laboratorium Logam, Mesin Dan Listrik)', 'alat pengukur yang digunakan untuk mengukur tekanan dalam suatu sistem tertentu. Tekanan diukur dalam unit tekanan seperti pascal (Pa), kilopascal (kPa), psi (pound per square inch), atau bar. Pressure gauges digunakan dalam berbagai aplikasi di industri logam, mesin, dan listrik untuk memantau dan mengontrol tekanan dalam sistem.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1696, 9, 1, '132080110066', 'Thermohygrometer (Alat Laboratorium Logam, Mesin Dan Listrik)', 'alat pengukur yang digunakan untuk mengukur suhu dan kelembaban relatif di suatu area atau lingkungan. Alat ini umumnya digunakan dalam berbagai aplikasi, termasuk di laboratorium, industri logam, mesin, dan listrik, serta di lingkungan lain di mana kontrol suhu dan kelembaban penting.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1697, 9, 1, '132080110069', 'Thickness Tester For Coating', 'coating thickness gauge, adalah perangkat atau alat pengukur yang digunakan untuk mengukur ketebalan lapisan atau pelapisan pada suatu substrat. Alat ini umumnya digunakan di berbagai industri, termasuk industri otomotif, aerospace, konstruksi, dan manufaktur, di mana ketebalan lapisan sangat penting untuk memastikan kualitas dan keberlanjutan suatu produk atau konstruksi', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1698, 9, 1, '132080110070', 'Vierner & Micrometer', 'Vernier caliper adalah alat pengukur presisi yang digunakan untuk mengukur panjang atau ketebalan suatu objek dengan akurasi yang tinggi. Vernier caliper adalah alat pengukur presisi yang digunakan untuk mengukur panjang atau ketebalan suatu objek dengan akurasi yang tinggi. Kedua alat ini, vernier caliper dan micrometer, sering digunakan di laboratorium, industri manufaktur, dan bidang lain yang memerlukan pengukuran yang akurat dan presisi. Vernier caliper cocok untuk pengukuran yang lebih umum, sementara micrometer sering digunakan untuk pengukuran yang memerlukan ketelitian tinggi.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1699, 9, 1, '132080110071', 'Dial & Test Indikator', 'dua jenis alat pengukur presisi yang digunakan untuk mengukur perpindahan atau variasi kecil dalam suatu objek, Dial Indicator (Indikator Dial):  adalah alat pengukur presisi yang digunakan untuk mengukur perpindahan linear atau variasi kecil dalam suatu objek. Test indicator, juga dikenal sebagai lever-type test indicator atau plunger dial indicator, adalah alat pengukur presisi yang sering digunakan untuk mengukur ketidaksejajaran, keunggulan permukaan, atau toleransi dimensi yang sangat kecil.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1700, 9, 1, '132080110072', 'Alat Ukur Kelurusan', 'Alat ukur kelurusan atau straightness measurement tools digunakan untuk menentukan sejauh mana suatu permukaan atau garis pada suatu objek mengikuti lintasan yang lurus.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1701, 9, 1, '132080110073', 'Alat Ukur Ketegaklurusan', 'perangkat yang digunakan untuk mengukur sejauh mana suatu objek atau permukaan bersifat tegak lurus terhadap garis horizontal atau vertikal. Ada beberapa alat yang dapat digunakan untuk mengukur ketegaklurusan, dan pilihan alat ini tergantung pada tingkat akurasi yang dibutuhkan dan jenis objek yang diukur.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1702, 9, 1, '132080110074', 'Alat Ukur Sudut', 'alat ukur sudut yang digunakan untuk mengukur sudut dalam berbagai konteks, termasuk konstruksi, surveying, dan laboratorium', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1703, 9, 1, '132080110075', 'Data Processor', 'merupakan proses pencetakan dengan cara digital pada plat untuk keperluan pada mesin cetak offset. Proses ini dikerjakan pada saat persiapan cetak atau “prepress” CTP', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1704, 9, 1, '132080110076', 'Mesin Bubut Presisi', 'mesin perkakas yang memutar benda kerja pada sumbu rotasi untuk melakukan berbagai proses seperti pemotongan, pengamplasan, knurling, pengeboran, deformasi, pembubutan muka, dan pemutaran, dengan alat yang diterapkan pada benda kerja untuk membuat objek dengan simetri terhadap sumbunya', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1705, 4, 1, '132070102007', 'Apdent Juster', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1706, 9, 1, '132080110077', '60 Mesin Milling Precesi', 'proses permesinan yang menggunakan bidang datar serta menghasilkan bidang datar pada benda kerja dengan menggunakan tools atau mata pisau (cutter)', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1707, 9, 1, '132080110079', 'Low Level Scanner', 'Pemindai tingkat rendah biasanya mengacu pada perangkat keras atau perangkat lunak yang dirancang untuk memindai dan menangkap data pada tingkat abstraksi rendah, seringkali pada tingkat kode biner atau sinyal listrik. Istilah tersebut dapat diterapkan dalam berbagai konteks, seperti di bidang ilmu komputer, elektronik, dan keamanan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1708, 9, 1, '132080110080', 'High Voltage Meter', 'alat ukur yang berfungsi untuk mengukur besar tegangan listrik yang ada di suatu rangkaian listrik dalam besaran dan satuan tertentu. Batas ukur dalam voltmeter dinyatakan dalam milivolt (mV), voltmeter (V), mikrovolt, atau kilovolt (kV).', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1709, 9, 1, '132080110081', 'Cutting & Welding Kit', 'Kit ini dirancang untuk portabilitas dan sering digunakan di lapangan atau lokasi kerja yang berpindah-pindah. Ini bisa mencakup peralatan portabel untuk pemotongan dan pengelasan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1710, 9, 1, '132080110082', 'Heavy Duty Hidraulic Cylender', 'komponen dalam sistem hidrolik yang dirancang khusus untuk menangani beban berat dan memberikan gaya linear melalui fluida hidrolik. Silinder ini digunakan dalam berbagai aplikasi industri, konstruksi, pertanian, dan lainnya di mana diperlukan kekuatan hidrolik untuk menggerakkan atau menahan beban yang besar.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1711, 9, 1, '132080110083', 'Alat Uji Bakteri', 'perangkat atau instrumen yang digunakan untuk mendeteksi dan menganalisis keberadaan bakteri dalam suatu sampel. Pengujian bakteri penting dalam berbagai konteks, termasuk di bidang kesehatan, keamanan pangan, dan lingkungan', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1712, 9, 1, '132080110084', 'Portable Polishing Equipment', 'peralatan penggosok atau poles yang dapat dipindahkan dengan mudah dari satu tempat ke tempat lain. Peralatan ini dirancang untuk memberikan kemudahan dalam melakukan pekerjaan penggosokan atau poles di berbagai lokasi. Proses penggosokan atau poles ini dapat mencakup berbagai jenis permukaan, seperti logam, kayu, plastik, atau bahkan permukaan cat.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1713, 9, 1, '132080110086', 'Esab Tig Welding Machine', 'ESAB (Elektriska Svetsnings-Aktiebolaget) adalah produsen peralatan pengelasan terkemuka di dunia, dan mereka menyediakan berbagai mesin pengelasan, termasuk mesin pengelasan Tungsten Inert Gas (TIG). Mesin TIG welding dari ESAB dirancang untuk memberikan kualitas pengelasan tinggi dan dapat digunakan dalam berbagai aplikasi, termasuk pengelasan logam aluminium, baja, dan stainless steel.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1714, 9, 1, '132080110087', 'Magnetic Particle (Alat Laboratorium Logam, Mesin Dan Listrik)', 'pengujian partikel magnetik adalah salah satu metode pengujian non-destruktif yang digunakan dalam industri logam, mesin, dan listrik untuk mendeteksi retak, cacat, atau ketidaksempurnaan pada permukaan material yang dapat menjadi penyebab kegagalan struktural. Metode ini terutama digunakan pada bahan yang mudah diperiksa secara magnetik, seperti logam ferromagnetik.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1715, 9, 1, '132080110088', 'Radiographis Equipment', 'perangkat yang digunakan untuk menghasilkan gambar atau citra yang didasarkan pada radiasi. Peralatan ini umumnya digunakan dalam berbagai bidang, termasuk kedokteran, industri, dan keamanan, untuk mendapatkan informasi visual tentang struktur internal suatu objek atau organisme.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1716, 9, 1, '132080110089', 'Alat Uji Tekan Hydrotastic', 'uji tekan hidrostatik atau hydrotastic compression test biasanya melibatkan penggunaan cairan (seperti air atau hidraulik fluid) untuk menghasilkan tekanan yang diterapkan pada suatu benda atau sistem. Alat uji tekan ini umumnya digunakan untuk memeriksa kekuatan dan integritas struktural dari material atau komponen tertentu.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1717, 4, 1, '132070102018', 'Niva Lite', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1718, 9, 1, '132080110092', 'Alat Electrolisa', 'proses kimia di mana listrik digunakan untuk menyebabkan reaksi redoks non-spontan antara dua elektroda yang terendam dalam larutan elektrolit. Proses ini dapat digunakan untuk memisahkan unsur-unsur kimia dari senyawa mereka', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1719, 9, 1, '132080110093', 'Hand Roll', 'Alat yg berfungis untuk pembentukan logam di mana stok logam dilewatkan melalui satu atau lebih pasang gulungan untuk mengurangi ketebalan, membuat ketebalan seragam, dan/atau untuk memberikan sifat mekanik yang diinginkan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1720, 9, 1, '132080110094', 'Iron Tester', 'Iron tester atau proses  oengujian logam adalah pemeriksaan bahan-bahan untuk diketahui sifat dan karakteristiknya yang meliputi sifat mekanik, sifat fisik, bentuk struktur, dan komposisi unsur-unsur yang terdapat di dalamnya.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1721, 9, 1, '132080110095', 'Perspiration', 'proses penguapan, jika mnegacu pada proses penguapan', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1722, 9, 1, '132080110098', 'Alat Uji Pukul Bola Bulutangkis', 'perangkat yang dirancang untuk mengukur tingkat kecepatan pukulan dan karakteristik penerbangan bola bulu tangkis. Alat ini membantu dalam menilai kualitas bola bulu tangkis dan memastikan bahwa bola tersebut memenuhi standar yang ditetapkan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1723, 4, 1, '132070102023', 'Terminator', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1724, 9, 1, '132080110099', 'Temperatur & Humudity Tester', 'alat pengukur kelembaban adalah perangkat yang digunakan untuk mengukur kadar kelembaban dalam udara atau bahan tertentu. Kelembaban adalah jumlah uap air yang terkandung dalam udara, dan dapat menjadi parameter penting dalam berbagai aplikasi, termasuk laboratorium, industri, dan lingkungan lainnya. Alat pengukur kelembaban membantu memantau dan mengukur tingkat kelembaban untuk memastikan kondisi yang sesuai dengan kebutuhan spesifik.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1725, 4, 1, '132070102024', 'Airimatik 205 Dental Unit', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1726, 9, 1, '132080110100', 'Alat Uji Diameter', 'perangkat yang digunakan untuk mengukur atau memeriksa diameter suatu objek atau benda', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1727, 9, 1, '132080110101', 'Digital Melting Point', 'perangkat laboratorium yang digunakan untuk menentukan titik leleh suatu zat atau sampel secara presisi dan dengan metode yang lebih canggih dibandingkan metode tradisional. Titik leleh adalah suhu di mana suatu zat berubah dari keadaan padat menjadi cair.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1728, 9, 1, '132080110102', 'Alat Uji Gas Buang', 'perangkat yang digunakan untuk mengukur dan menganalisis komposisi gas buang yang dihasilkan oleh mesin pembakaran, seperti mesin kendaraan bermotor, mesin industri, atau sistem pemanas. Pengukuran gas buang penting untuk memantau emisi gas berbahaya dan memastikan bahwa kendaraan atau peralatan mematuhi standar emisi yang ditetapkan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1729, 9, 1, '132080110103', 'Xyclo Crack Detector Kit', 'alat yg digunakan untuk mendeteksi retak atau cacat permukaan pada logam atau bahan lainnya tanpa merusak integritas strukturalnya. Teknik ini penting dalam inspeksi kualitas dan pemeliharaan struktural pada berbagai industri, termasuk manufaktur, otomotif, dan penerbangan', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1730, 4, 1, '132070102028', 'Berge Fail', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1731, 9, 1, '132080110104', 'Digital Indicator (Alat Laboratorium Logam, Mesin Dan Listrik)', 'alat ukur yang digunakan untuk menampilkan dan mengukur suatu nilai atau parameter dengan menggunakan tampilan digital. Alat ini umumnya digunakan dalam berbagai aplikasi, termasuk dalam industri manufaktur, laboratorium, dan pemeliharaan peralatan', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1732, 9, 1, '132080110105', 'Techometer Digital Multimeter', 'alat yang menggabungkan fungsi multimeter dan tachometer dalam satu perangkat. Multimeter adalah alat yang digunakan untuk mengukur berbagai parameter listrik, seperti tegangan, arus, dan resistansi, sementara tachometer digunakan untuk mengukur kecepatan rotasi atau frekuensi putaran suatu objek, seringkali dalam bentuk RPM (Rotations Per Minute)', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1733, 4, 1, '132070102030', 'Bond Seater', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1734, 9, 1, '132080110107', 'Ultrasonic Thickness Meter', 'alat pengukur ketebalan ultrasonik adalah perangkat yang menggunakan gelombang ultrasonik untuk mengukur ketebalan suatu bahan. Alat ini umumnya digunakan untuk mengukur ketebalan material tanpa merusak atau merusak permukaan bahan. Aplikasinya melibatkan berbagai jenis material, seperti logam, plastik, kaca, dan komposit.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1735, 9, 1, '132080110108', 'Torque Wrench With Socket Head', 'jenis kunci momen atau alat yang digunakan untuk memberikan torsi atau gaya putar yang spesifik pada suatu baut atau mur. Socket head pada kunci momen ini merujuk pada kepala yang dapat menerima berbagai ukuran soket (socket) yang dapat dilepas-pasang untuk menyesuaikan dengan ukuran baut atau mur yang berbeda.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1736, 9, 1, '132080110109', 'Mega Ohm Meter', 'alat yang digunakan untuk mengukur resistansi listrik dengan rentang ukuran dalam megohm, yang setara dengan satu juta ohm. Megaohm meter juga dikenal sebagai "insulation resistance tester" atau "insulation megohmmeter," dan biasanya digunakan untuk mengukur resistansi isolasi pada kabel, peralatan listrik, dan perangkat elektronik lainnya', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1737, 9, 1, '132080110110', 'Vernier Caliper Height Gauge', 'alat pengukur yang menggabungkan fungsi vernier caliper dan height gauge (pengukur tinggi) dalam satu perangkat. Alat ini digunakan untuk mengukur dimensi dan tinggi objek dengan tingkat presisi yang tinggi. Ini sangat berguna dalam berbagai aplikasi, terutama dalam proses manufaktur, rekayasa, dan inspeksi.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1738, 9, 1, '132080110111', 'Precicion Bevel Protector', 'alat pengukur presisi yang digunakan untuk mengukur sudut pada suatu objek dengan tingkat akurasi yang tinggi. Alat ini terutama digunakan dalam pekerjaan presisi dan pembuatan perkakas di berbagai industri. Bevel protractor dirancang untuk mengukur sudut secara tepat dan dapat membaca sudut hingga fraksi dari derajat.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1739, 4, 1, '132070102035', 'Chisel', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1740, 9, 1, '132080110112', 'Engineers Combination Square Set', 'seperangkat alat yang digunakan oleh insinyur, tukang kayu, dan profesional lainnya dalam bidang teknik dan konstruksi untuk melakukan pengukuran, pemarisan, dan penandaan yang akurat. Combination square set umumnya terdiri dari beberapa alat yang dapat digunakan untuk berbagai tugas.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1741, 9, 1, '132080110113', 'Drying Oven', 'perangkat laboratorium atau industri yang digunakan untuk mengeringkan atau menghilangkan kelembaban dari berbagai jenis bahan atau sampel. Oven ini bekerja dengan memanaskan bahan atau sampel pada suhu yang diatur untuk mengurangi kadar air atau pelarut dalam bahan tersebut.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1742, 9, 1, '132080110115', 'Measuring Instrument', 'Measuring Instrument adalah alat ukur, jika kaitannya dengan lab logam maka yg dimaksud adalah perlatan atau alat ukur yang ada di lab logam, tentunya memilik jenis dan bentuk beragam', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1743, 9, 1, '132080110116', 'Permanent Magnet Kit', 'alat yang berfungsi untuk untuk memperoleh angkat beban berat dengan cepat dan efisien, sehingga memindahkan beban berat seperti benda bermaterial baja akan lebih cepat dan juga mudah pastinya. Tetapi, sama dengan alat lifter lainnya, permanent magnet juga perlu diusahakan agar lifter bisa presisi tepat, sehingga tidak terjadi masalah atau kerusakan pada alat tersebut.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
