	(1746, 9, 1, '132080110124', 'Disturtion Factor Tester For Mirror', 'alat ukur elektronik yang menampilkan jumlah distorsi yang ditambahkan ke sinyal asli oleh rangkaian elektronik.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
