	(1751, 9, 1, '132080110127', 'Step Up/Down (Alat Laboratorium Logam, Mesin Dan Listrik)', 'alat yang berfungsi untuk berfungsi untuk menurunkan atau menaikkan tegangan AC dari 0 volt dan 250 volt ( maksimal )', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1752, 9, 1, '132080110128', 'Xray Unit', 'peralatan sinar-X yang digunakan dalam konteks pengujian bahan atau analisis logam di laboratorium', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1753, 9, 1, '132080110130', 'Mufle Furnace', 'alat laboratorium yang digunakan sebagai pemanas (pembakar) mekanis bersuhu sangat tinggi yang mengubah media analis atau bahan sampel menjadi material abu atau arang dalam waktu yang relatif cepat', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1754, 9, 1, '132080110132', 'Anemometer Portable Digital', 'alat yang digunakan untuk mengukur kecepatan angin. Ini adalah versi digital dari alat tradisional yang disebut anemometer, yang biasanya digunakan dalam berbagai aplikasi, termasuk meteorologi, navigasi, pengujian kecepatan udara, dan pemantauan lingkungan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1755, 9, 1, '132080110133', 'Tensile Tester', 'mesin uji tarik atau mesin uji ketegangan, adalah perangkat yang digunakan untuk mengukur sifat mekanis material saat dikenakan tegangan atau tarikan. Peralatan ini biasanya digunakan dalam pengujian material untuk menentukan kekuatan tarik, kekuatan leleh, elastisitas, dan sifat mekanis lainnya.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1756, 9, 1, '132080110135', 'Alat Uji Untuk Kerja Radiator', 'alat untuk menguji kinerja radiator, memiliki banyak jenis', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1757, 9, 1, '132080110136', 'Alat Uji Tekan Hidrostatic Impact Test', 'Alat pengujian ini dirancang untuk mengukur ketahanan material agar tidak terjadi kegagalan pada material atau bahan yang akan digunakan nantinya.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
