	(1759, 9, 1, '132080110137', 'Alat Uji Tarik Sederhana', 'alat untuk menguji sifat mekanika bahan dengan cara melakukan pengujian tarik atau Tensile Test', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
