	(1762, 9, 1, '132080110140', 'Electrometer (Alat Laboratorium Logam, Mesin Dan Listrik)', 'alat pengukur muatan listrik atau beda potensial listrik', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
