	(1765, 9, 1, '132080110146', 'Mosses Oiml', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1766, 9, 1, '132080110149', 'Alat Uji Ultrasonic', 'perangkat yang menggunakan gelombang ultrasonik untuk mendeteksi atau mengukur sifat-sifat material atau objek tertentu', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1767, 9, 1, '132080110150', 'Alat Uji Korosi', 'Alat uji korosi digunakan untuk mengukur atau memantau tingkat korosi pada material, terutama logam. Korosi adalah proses degradasi material yang disebabkan oleh reaksi kimia antara material tersebut dan lingkungan di sekitarnya.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
