	(1769, 9, 1, '132080110151', 'Alat Uji Struktur Kimia Logam', 'proses untuk mengevaluasi dan memverifikasi sifat logam, paduan, komposit, dan semua bahan lainnya', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1770, 9, 1, '132080110152', 'Vacum Coating', 'alat yang digunakan dalam proses pelapisan (coating) yang menggunakan proses vakum dengan mekanisme pemompaan pada mesin vakum', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1771, 9, 1, '132080110154', 'Scattered Light Polariscope', 'sistem atau perangkat optik yang digunakan untuk menganalisis dan memvisualisasikan distribusi tegangan dalam suatu objek atau bahan transparan. Metode ini umumnya digunakan dalam bidang inspeksi dan pengujian bahan untuk memahami distribusi tegangan dan deformasi.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1772, 9, 1, '132080110155', 'Lateral Extensometer', 'alat pengukur yang digunakan untuk mengukur perubahan lebar atau deformasi lateral suatu bahan atau struktur selama pengujian atau pembebanan. Extensometer secara umum digunakan dalam bidang uji material untuk memahami perilaku dan sifat mekanis dari bahan tertentu', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1773, 9, 1, '132080110156', 'Proyektion Polariscope', 'alat atau instrumen optik yang digunakan untuk menganalisis dan mengamati distribusi tegangan dalam suatu bahan atau objek transparan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
