	(1775, 9, 1, '132080110157', 'Ultrasonic Testes', 'alat penting dalam industri untuk memastikan bahwa material yang digunakan dalam konstruksi atau produksi memenuhi standar keamanan dan kualitas yang diperlukan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1776, 4, 1, '132070102063', 'Laring Suprane Dental Unit Shimatic 20 cc/Fontell', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1777, 9, 1, '132080110158', 'Magnetic Powder Crack Detector', 'metode non-destruktif yang digunakan untuk mendeteksi retakan, cacat, atau ketidaksempurnaan pada permukaan dan di bawah permukaan bahan logam. Metode ini sering digunakan dalam industri untuk inspeksi komponen logam dan memastikan keamanan struktural dan integritas suatu material.\nalat yang sangat berguna dalam menjaga integritas struktural komponen logam, mencegah kegagalan struktural, dan memastikan keamanan dalam berbagai aplikasi industri.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1778, 4, 1, '132070102064', 'Laring Supreme Dental Unit', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1779, 9, 1, '132080110161', 'Electro Plating/Pelapisan Metal', 'proses pelapisan logam memanfaatkan arus listrik melalui media larutan elektrolit. Material mesh stainless steel (SS) 304 dipilih mudah diperoleh dan relatif murah dan memiliki ketahanan pada suhu relatif tinggi', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1780, 9, 1, '132080110162', 'Perangkat CAD/CAE/Cam', 'termasuk Rhino, SolidWorks, SurfCAM, dan MasterCAM, Pro/E, Unigraphic, dan DELCAM. Merupakan salah satu software CAM yang khusus diperuntukkan dalam pembuatan PCB.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1781, 4, 1, '132070102066', 'LIP Retraktor', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1782, 9, 1, '132080110164', 'Vernier Calliper (Alat Laboratorium Logam, Mesin Dan Listrik)', 'alat pengukur yang digunakan untuk mengukur dimensi linear suatu objek dengan tingkat presisi yang tinggi. Alat ini terutama digunakan di laboratorium logam, mesin, dan listrik untuk mengukur dimensi benda-benda kecil dengan akurasi yang tinggi.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1783, 9, 1, '132080110166', 'Surface Plate/Graplate', 'alat ukur presisi yang digunakan dalam berbagai aplikasi industri, manufaktur, dan laboratorium untuk memeriksa, mengukur, dan mengkalibrasi alat ukur lainnya serta untuk menentukan datar atau tidaknya suatu permukaan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1784, 9, 1, '132080110168', 'Out Side Micrometer (ratchel Stop)', 'alat ukur presisi yang digunakan untuk mengukur dimensi eksternal suatu objek dengan tingkat akurasi yang tinggi.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1785, 9, 1, '132080110170', 'Dial Indicator', 'alat pengukur presisi yang digunakan untuk mengukur perpindahan atau jarak linear kecil dalam proses mekanikal dan manufaktur. Alat ini juga sering disebut sebagai "gauge indicator" atau "dial gauge."', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1786, 4, 1, '132070102070', 'Mouth Speder', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1787, 9, 1, '132080110173', 'Diesel Engine', 'sejenis pembakaran dalam, lebih spesifik lagi sebuah mesin pemicu kompresi, dimana bahan bakar dinyalakan oleh suhu tinggi gas yang dikompresi, dan bukan oleh alat berenergi lain.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1788, 9, 1, '132080110176', 'PLC', 'singkatan dari programmable logic controller. perangkat elektronik yang digunakan untuk mengontrol dan mengotomatisasi proses di berbagai aplikasi industri. PLC dirancang untuk menggantikan pengendali logika kawat (relay logic) yang lebih kuno dan menyediakan fleksibilitas serta kemampuan pemrograman yang lebih tinggi.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
