	(1790, 9, 1, '132080110181', 'Emergency Supply', 'Beberapa item yang mungkin termasuk dalam emergency supply laboratorium logam melibatkan keamanan, penanganan bahan kimia, dan langkah-langkah keselamatan lainnya.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
