	(1794, 9, 1, '132080111001', 'Centrifuge (Alat Laboratorium Umum)', 'alat laboratorium yang digunakan untuk memisahkan komponen dalam sampel berdasarkan berat jenis atau massa partikel dalam suatu larutan. Prinsip kerjanya melibatkan memutar cepat suatu wadah atau tabung yang berisi sampel, menciptakan gaya sentrifugal yang memisahkan komponen-komponen berdasarkan massa atau densitas mereka.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1795, 4, 1, '132070102076', 'PIK Hak Gigi', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1796, 9, 1, '132080111002', 'Water Bath (Alat Laboratorium Umum)', 'alat laboratorium yang digunakan untuk memanaskan atau mendinginkan sampel dalam air yang dikendalikan suhunya. Alat ini sering digunakan di laboratorium untuk berbagai aplikasi, termasuk pemanasan reagen, inkubasi sel kultur, atau pengaturan suhu tepat untuk reaksi kimia atau biologis.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1797, 9, 1, '132080111003', 'Incubator (Alat Laboratorium Umum)', 'perangkat yang digunakan di laboratorium untuk memberikan kondisi lingkungan yang terkontrol, seperti suhu dan kelembaban, untuk pertumbuhan dan perkembangan mikroorganisme, sel, atau kultur biologis lainnya', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1798, 4, 1, '132070102078', 'Pisau Lilin/Wasmess/Wax Knife', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1799, 9, 1, '132080111004', 'Mortar (Alat Laboratorium Umum)', 'perangkat yang digunakan untuk menghancurkan atau menggiling bahan-bahan padat menjadi serbuk halus. Mortar umumnya terbuat dari bahan yang keras dan tahan aus, seperti keramik, porselen, atau batu alam. Mortar sering digunakan bersama dengan alat yang disebut pestle (tumbukan), yang digunakan untuk menggiling', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1800, 9, 1, '132080111005', 'Oven (Alat Laboratorium Umum)', 'alat laboratorium umum yang digunakan untuk memanaskan atau mengeringkan bahan-bahan dalam kondisi kontrol suhu', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1801, 9, 1, '132080111006', 'Compressor Unit', 'sistem atau unit kompresor udara yang digunakan untuk menyediakan pasokan udara bertekanan dalam aplikasi laboratorium. Unit kompresor udara dapat digunakan untuk menyediakan udara bertekanan yang dibutuhkan dalam berbagai alat dan peralatan di laboratorium.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
