	(1803, 9, 1, '132080111009', 'Burete', 'alat laboratorium yang digunakan untuk mengukur volume larutan dengan tingkat ketelitian yang tinggi. Buret biasanya terbuat dari kaca dan memiliki skala terukir untuk membaca volume larutan yang ditransfer. Alat ini sering digunakan dalam titrasi, sebuah teknik laboratorium yang digunakan untuk menentukan konsentrasi suatu larutan dengan mengukur volume larutan yang ditambahkan secara berangsur-angsur ke dalam larutan lain yang bereaksi.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1804, 4, 1, '132070102082', 'Prostetic Engine', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1805, 9, 1, '132080111010', 'Microscope', 'alat yg digunakan untuk memeriksa objek atau sampel dalam skala mikroskopis', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1806, 9, 1, '132080111011', 'Autoclave (Alat Laboratorium Umum)', 'alat laboratorium umum yang digunakan untuk sterilisasi bahan-bahan dengan pemanasan di atas titik didih air pada tekanan tinggi. Prinsip dasar dari autoclave adalah menggunakan kombinasi panas dan tekanan untuk membunuh mikroorganisme, spora bakteri, dan berbagai bentuk kehidupan mikroba lainnya. Autoclave sering digunakan di laboratorium, klinik, dan industri untuk memastikan bahwa instrumen, media kultur, dan barang-barang lainnya steril sebelum digunakan', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1807, 9, 1, '132080111012', 'Blender', 'perangkat yang digunakan untuk mencampur atau homogenisasi bahan kimia atau biologis dalam lingkungan laboratorium. Blender ini dapat digunakan dalam berbagai aplikasi, termasuk preparasi sampel, penelitian biologi molekuler, atau pemrosesan bahan kimia.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1808, 9, 1, '132080111013', 'Timbangan/Neraca', 'alat laboratorium yang digunakan untuk mengukur massa suatu zat, baik zat berbentuk padat maupun cair.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1809, 4, 1, '132070102086', 'Slip Join', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1810, 9, 1, '132080111014', 'Axial Plunger Pump', 'jenis pompa hidrolik yang menggunakan plunger atau piston yang bergerak sejajar dengan sumbu pompa untuk menghasilkan aliran fluida.\nAxial plunger pump merupakan elemen penting dalam sistem hidrolik modern dan berperan dalam mentransfer energi hidrolik untuk menggerakkan berbagai komponen mekanis.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1811, 4, 1, '132070102087', 'Spatel Gips', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1812, 9, 1, '132080111015', 'Dry Klim', 'perangkat yang digunakan untuk mengamankan atau menahan alat-alat laboratorium seperti tabung reaksi, gelas kimia, atau alat lainnya. Klem ini biasanya terbuat dari bahan yang tahan terhadap bahan kimia atau korosi. Fungsi klem laboratorium melibatkan pemegangan dan penahanan alat-alat laboratorium agar tetap stabil dan aman selama eksperimen atau pengujian.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1813, 9, 1, '132080111016', 'Universal Test Machine (Alat Laboratorium Umum)', 'Alat untuk mengukur sifat mekanis material, seperti kekuatan tarik, kekuatan tekan, dan kekerasan. UTM sering digunakan dalam pengujian material dan struktur.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1814, 4, 1, '132070102089', 'Spoot Welder', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1815, 9, 1, '132080111017', 'Engenerring Test Equipment', 'berbagai perangkat atau peralatan uji yang digunakan dalam dunia rekayasa atau teknik. Peralatan uji ini dirancang untuk melakukan pengukuran, analisis, atau pengujian pada berbagai komponen, sistem, atau perangkat teknik untuk memastikan kinerja yang diinginkan atau memecahkan masalah teknis.\nBerikut adalah beberapa contoh umum dari engineering test equipment; Oscilloscope, Signal Generator, Power Supply, Universal Testing Machine (UTM):', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1816, 4, 1, '132070102090', 'Tang Clamer', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1817, 9, 1, '132080111018', 'Vacum Pump', 'alat yang memiliki fungsi untuk meningkatkan kecepatan terjadinya kondensasi untuk berubah menjadi air kembali melalui komponen kondensor. Selain itu, mesin ini juga bermanfaat untuk membuat uap yang turun serta mengenai kondensor bagian luar.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1818, 9, 1, '132080111019', 'Bearing Stand', 'perangkat atau konstruksi yang dirancang untuk mendukung dan mempertahankan bantalan atau sistem penggulung. Bantalan ini bisa digunakan dalam berbagai eksperimen atau pengujian di laboratorium, seperti dalam bidang mekanika atau penelitian material', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1819, 4, 1, '132070102092', 'Tang Omega', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1820, 9, 1, '132080111020', 'Stop Watch', 'alat untuk mengukur waktu. Ini dapat digunakan untuk mengukur durasi suatu kejadian atau aktivitas dengan akurasi tinggi, baik itu dalam hitungan detik, menit, atau jam.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1821, 4, 1, '132070102093', 'Tang Pengukur Bracket Depan/Belakang', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1822, 9, 1, '132080111021', 'S C R E E N', 'Dalam eksperimen atau penelitian laboratorium, "screen" mungkin digunakan untuk merujuk pada proses seleksi atau pemisahan sampel berdasarkan kriteria tertentu, seperti ukuran partikel, komposisi kimia, atau sifat fisik lainnya.\nDalam konteks laboratorium, "screen" bisa merujuk pada beberapa hal tergantung pada jenis laboratorium dan tujuan penggunaan', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1823, 9, 1, '132080111022', 'Alat Destilasi Air', 'perangkat yang digunakan untuk memurnikan air melalui proses destilasi, yang melibatkan pemanasan air hingga mendidih, menguapkan uap air, dan kemudian mengembalikannya menjadi air cair dengan kondensasi. Proses ini membantu menghilangkan zat-zat terlarut dan kontaminan lainnya dari air, menghasilkan air yang lebih bersih dan lebih murni.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1824, 9, 1, '132080111025', 'Manometer', 'alat pengukur tekanan, yang digunakan untuk mengukur perbedaan tekanan antara dua titik dalam sistem tertutup atau terbuka.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1825, 9, 1, '132080111026', 'Hydrometer', 'alat laboratorium yang digunakan untuk mengukur kerapatan relatif atau berat jenis suatu cairan. Alat ini umumnya digunakan dalam berbagai bidang, termasuk kimia, fisika, dan teknik, untuk menentukan konsentrasi zat terlarut dalam larutan atau mengukur tingkat kepadatan cairan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1826, 9, 1, '132080111027', 'Counter Meter', 'alat yang umum digunakan di berbagai industri untuk menghitung jumlah putaran atau pergerakan dalam suatu proses produksi. Alat ini sangat penting untuk memastikan efisiensi dan akurasi produksi.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1827, 9, 1, '132080111028', 'Caliper & Micrometer', 'Caliper dan micrometer adalah dua jenis alat ukur yang umum digunakan di laboratorium untuk mengukur dimensi objek dengan tingkat presisi yang tinggi.\nCaliper adalah alat pengukur yang digunakan untuk mengukur panjang, ketebalan, atau diameter suatu objek dengan tingkat presisi tinggi. Micrometer, juga dikenal sebagai mikrometer sekrup atau sekrup mikrometer, adalah alat ukur yang digunakan untuk mengukur dimensi objek dengan tingkat presisi yang sangat tinggi, seringkali hingga beberapa mikrometer.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1828, 4, 1, '132070102099', 'Tang Sporasi', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1829, 9, 1, '132080111029', 'M I X E R', 'perangkat atau peralatan di laboratorium yang digunakan untuk mencampur atau mengaduk bahan kimia atau sampel dalam berbagai aplikasi eksperimental. Mixer lab dapat memiliki berbagai jenis dan fitur tergantung pada kebutuhan dan tujuan penggunaan.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1830, 9, 1, '132080111030', 'Thermometer (Alat Laboratorium Umum)', 'alat umum yang digunakan dalam laboratorium untuk mengukur suhu suatu benda atau lingkungan. Ada berbagai jenis thermometer yang digunakan dalam konteks laboratorium, dan pilihan bergantung pada kebutuhan spesifik eksperimen atau pengukuran suhu.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1831, 4, 1, '132070102101', 'Tastim Instrument Manual', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1832, 9, 1, '132080111031', 'Corong', 'perangkat yang umum digunakan dalam laboratorium untuk mentransfer cairan dari satu wadah ke wadah lainnya tanpa tumpah atau kebocoran. Corong memiliki bentuk kerucut yang memungkinkan aliran cairan yang terkendali.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1833, 9, 1, '132080111032', 'Lampu Natrium', 'memberikan sumber cahaya dengan spektrum warna yang khas dari emisi natrium. Lampu natrium sering kali digunakan dalam beberapa percobaan dan penelitian, terutama di bidang kimia dan fisika, di mana sifat cahaya atau analisis spektrum diperlukan.\nLampu Natrium dapat dibagi menjadi dua jenis utama berdasarkan warna cahaya yang dihasilkan:', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1834, 4, 1, '132070102103', 'Wang Hak', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1835, 9, 1, '132080111034', 'Raw Water Kit', 'seperangkat peralatan atau kit pengambilan sampel air mentah (raw water). Kit ini mungkin mencakup botol pengambilan sampel, alat ukur parameter air, dan instruksi pengambilan sampel.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1836, 4, 1, '132070102104', 'Yudir Klem', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1837, 9, 1, '132080111036', 'Water Absorb Tester', 'perangkat atau alat yang dirancang untuk mengukur kemampuan suatu bahan atau material dalam menyerap air. Pengukuran ini dapat memberikan informasi penting tentang sifat-sifat hidrofilik (mudah menyerap air) atau hidrofobik (tahan terhadap air) dari suatu bahan. Alat ini sering digunakan dalam industri tekstil, pembuatan pakaian olahraga, industri kertas, dan berbagai bidang lainnya di mana respons terhadap kelembaban atau air adalah faktor penting.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1838, 4, 1, '132070102105', 'Zuig Kanule', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1839, 9, 1, '132080111037', 'B O D Meter', 'alat yang digunakan untuk mengukur Biological Oxygen Demand dalam suatu sampel air. BOD meter digunakan untuk menentukan jumlah oksigen yang dikonsumsi oleh mikroorganisme selama proses penguraian bahan organik di dalam air.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1840, 9, 1, '132080111038', 'Biologikal Oxigen Demand', 'parameter yang mengukur jumlah oksigen yang dibutuhkan oleh mikroorganisme dalam suatu sistem air untuk menguraikan bahan organik yang terkandung dalam air tersebut. BOD sering digunakan sebagai indikator pencemaran organik dalam air.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1841, 9, 1, '132080111039', 'Tabung Gas Ho', 'wadah atau tabung yang berisi gas hidrogen (H2). Gas hidrogen digunakan dalam berbagai aplikasi di laboratorium, industri, dan bidang lainnya.\nfungsi gas ini pada lab, Gas hidrogen dapat digunakan dalam berbagai eksperimen dan proses laboratorium. Misalnya, sebagai gas yang mudah terbakar, hidrogen dapat digunakan dalam reaksi kimia atau percobaan yang melibatkan pembakaran.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1842, 4, 1, '132070102108', 'Prisma Life System (Sinar Halogen)', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1843, 9, 1, '132080111040', 'Tabung Gas N2', 'wadah yang berisi gas nitrogen (N2). Nitrogen adalah gas di atmosfer yang melibatkan sekitar 78% dari total atmosfer bumi. Gas nitrogen dapat diisolasi dan disimpan dalam tabung untuk berbagai keperluan, terutama di dalam laboratorium, industri, dan aplikasi lainnya.\nDalam laboratorium, gas nitrogen dapat digunakan untuk menghindari kontaminasi oksigen dalam berbagai proses kimia yang memerlukan kondisi tanpa oksigen.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1844, 9, 1, '132080111042', 'Bak Fiberglass', 'tempat penampungan kimia atau bahan berbahaya. Fiberglass tahan terhadap korosi dan reaktif terhadap sebagian besar zat kimia, sehingga cocok untuk keperluan penyimpanan bahan kimia di laboratorium.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1845, 9, 1, '132080111043', 'Crusible Penyaring', 'jenis crucible yang khusus dirancang untuk keperluan penyaringan. Mereka memiliki saringan atau retak di bagian bawah atau sampingnya yang memungkinkan filtrasi zat', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1846, 4, 1, '132070102111', 'Scaller Callat Scalling', NULL, NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1847, 9, 1, '132080111044', 'Iodine Plass', 'salah satu alat gelas laboratorium yang terbuat dari kuarsa/silikat oksida, boron oksida, aluminium oksida dan natrium oksida.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1848, 9, 1, '132080111045', 'Thermostate', 'perangkat yang digunakan untuk mengontrol suhu. Fungsi utama thermostat adalah memantau suhu lingkungan atau suatu sistem dan mengatur perangkat pemanas atau pendingin untuk menjaga suhu pada tingkat yang diinginkan atau diatur.', NULL, NULL, '2026-04-30 03:15:50', '2026-04-30 03:15:50'),
	(1849, 9, 1, '132080111046', 'Spray Gun', 'perangkat yang digunakan untuk menyemprotkan cairan, biasanya cat atau bahan semprot lainnya, ke permukaan. Alat ini umumnya digunakan dalam berbagai industri, seperti otomotif, perbengkelan, manufaktur, dan lukisan. Spray gun memungkinkan penyemprotan yang merata dan presisi dari cairan ke berbagai permukaan, yang dapat mencakup logam, kayu, plastik, dan material lainnya.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1850, 9, 1, '132080111047', 'Furnace', 'perangkat yang digunakan di lingkungan laboratorium, baik itu di bidang penelitian ilmiah maupun industri, untuk memanaskan material pada suhu tinggi untuk berbagai tujuan. Furnace laboratorium umumnya dirancang untuk memberikan kontrol suhu yang presisi dan dapat digunakan dalam berbagai jenis aplikasi', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1851, 9, 1, '132080111049', 'Lumpang Pengeram', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1852, 9, 1, '132080111052', 'Pipa U', 'Pipa "U" adalah salah satu bentuk pipa laboratorium yang umum digunakan. Pipa ini memiliki bentuk seperti huruf "U" dan dapat digunakan untuk berbagai tujuan dalam pengaturan laboratorium. Berikut adalah beberapa penggunaan umum dan jenis pipa "U" dalam konteks laboratorium:\n\n\n\n1. Pipa U untuk Pengukuran Tekanan:\n\n\n\nPipa U sering digunakan sebagai manometer, yang dapat digunakan untuk mengukur perbedaan tekanan antara dua titik dalam suatu sistem. Perubahan tinggi air dalam kedua lengan pipa U memberikan indikasi perbedaan tekanan.\n\n\n2. Pipa U untuk Percobaan Fisika:\n\n\n\nDalam beberapa percobaan fisika, pipa U dapat digunakan untuk memperlihatkan prinsip-prinsip hidrostatika atau untuk mengukur perbedaan tinggi air pada kedua lengan.\n\n\n3. Pipa U untuk Analisis Gas:\n\n\n\nPipa U dapat digunakan sebagai bagian dari alat untuk menangkap atau mengukur volume gas dalam beberapa analisis kimia atau biologi.\n\n4. Pipa U untuk Penggunaan Umum:\n\n\n\nSelain itu, pipa U dapat digunakan dalam banyak pengaturan laboratorium untuk tujuan yang lebih umum, seperti membandingkan tekanan atmosfer atau menunjukkan efek kapiler.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1853, 4, 1, '132070102117', 'Alat Ra Foto', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1854, 9, 1, '132080111053', 'Lempeng Tetes', 'Plat Tetes adalah wadah atau pelat yang dirancang untuk menangkap atau menampung tumpahan atau tetesan dari proses atau percobaan yang dilakukan di laboratorium. Ini membantu mencegah kontaminasi lintas percobaan, melindungi permukaan meja atau benchtop, dan mempermudah proses pembersihan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1855, 9, 1, '132080111059', 'Crock Meter (Alat Laboratorium Umum)', 'alat laboratorium yang umumnya digunakan dalam industri tekstil dan pakaian untuk mengukur resistensi pewarnaan atau perpindahan warna dari kain atau tekstil ke permukaan lain selama gesekan. Alat ini memungkinkan penentuan sejauh mana pewarnaan atau warna pada tekstil dapat mentransfer atau luntur ke permukaan lain ketika terjadi gesekan atau geseran.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1856, 9, 1, '132080111061', 'Pengaduk', 'Perangkat yang digunakan untuk mencampur, mengaduk, atau memutar cairan atau larutan dalam konteks percobaan atau pengujian laboratorium. Pengaduk dapat berbagai bentuk dan ukuran tergantung pada kebutuhan spesifik aplikasi dan volume cairan yang diolah. Berikut adalah beberapa jenis pengaduk laboratorium yang umum digunakan:\n1. Vortex Mixer (Pengaduk Vortex):\n\nCocok untuk mencampur dalam tabung reaksi atau bejana kecil. Menghasilkan gerakan vortex dengan cepat untuk mencampur larutan.\n\n2. Mixer Homogenizer (Pengaduk Homogenizer):\n\nDigunakan untuk mencampur dan homogenisasi sampel biologis atau kimia. Memiliki kepala berputar atau pisau untuk memotong dan mencampur dengan baik.\n\n3. Propeller Stirrer (Pengaduk Baling-baling):\n\nMemiliki baling-baling atau propeller di ujung batang yang berputar untuk mencampur larutan dalam bejana atau tabung reaksi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1857, 9, 1, '132080111062', 'Crusses Tang', 'tang yang dirancang atau digunakan khusus untuk menangani atau memanipulasi krusibel, terutama ketika krusibel tersebut sedang dalam keadaan panas.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1858, 9, 1, '132080111063', 'Pendingin Lurus', 'alat yang digunakan untuk mendinginkan gas atau uap panas dengan berbagai metode kimia menjadi fasa zat cair. Kita dapat menggunakan alat ini bersamaan dengan alat destilasi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1859, 9, 1, '132080111067', 'Montle Heater', 'peralatan laboratorium yang digunakan untuk memanaskan larutan atau zat kimia dalam wadah kaca, seperti labu berbentuk bulat atau wadah kaca lainnya. Peralatan ini umumnya digunakan di laboratorium kimia, biologi, atau bidang ilmu lainnya yang memerlukan pemanasan kontrol untuk berbagai eksperimen atau proses.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1860, 9, 1, '132080111068', 'Motor Complit Bioxidation System', 'proses oksidasi sepenuhnya atau pembakaran suatu zat di mana zat tersebut bereaksi sepenuhnya dengan oksigen atau agen oksidasi lainnya, menghasilkan produk akhir yang stabil.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1861, 9, 1, '132080111069', 'Standard Klem Burete', 'Klem buret standar adalah alat yang digunakan untuk menjaga buret (suatu tabung transparan yang digunakan untuk mengukur volume cairan dengan ketelitian tertentu) agar tetap stabil dan terpasang dengan aman selama penggunaan dalam percobaan atau analisis laboratorium', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1862, 9, 1, '132080111070', 'Stress Cracking Tester With Thermometer Water Bath', 'Stress Cracking Tester with Thermometer Water Bath adalah instrumen uji yang digunakan untuk mengevaluasi ketahanan suatu bahan terhadap retakan atau pecah akibat paparan lingkungan tertentu dan pemberian tegangan (stres). Instrumen ini berguna untuk menguji kekuatan dan ketahanan bahan, khususnya plastik, terhadap fenomena retakan akibat tegangan dan pengaruh lingkungan tertentu.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1863, 9, 1, '132080111071', 'Alat Pengukur Luas Kulit', 'Alat ini digunakan dalam bidang medis atau penelitian kesehatan untuk mengukur luas permukaan tubuh manusia, yang sering dinyatakan dalam satuan luas seperti meter persegi (m²).', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1864, 9, 1, '132080111073', 'PH Meter (Alat Laboratorium Umum)', 'PH meter adalah alat laboratorium yang umum digunakan untuk mengukur tingkat keasaman atau kebasaan dari suatu larutan. Skala pH berkisar dari 0 hingga 14, di mana nilai 7 dianggap netral, nilai kurang dari 7 menunjukkan keasaman, dan nilai lebih dari 7 menunjukkan kebasaan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1865, 9, 1, '132080111075', 'Tangki Bahan Baku', 'wadah atau tangki yang digunakan untuk menyimpan bahan baku atau bahan kimia yang akan digunakan dalam percobaan atau proses di laboratorium. Tangki ini dirancang khusus untuk keperluan laboratorium dan dapat memiliki berbagai bentuk, ukuran, dan bahan tergantung pada jenis bahan yang disimpan dan kebutuhan aplikasi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1866, 9, 1, '132080111077', 'Salt Spray Test Chamber', 'suatu perangkat atau ruang uji laboratorium yang dirancang untuk mensimulasikan efek korosif lingkungan yang kaya garam pada material dan lapisan permukaan. Uji ini umumnya digunakan dalam industri otomotif, kedirgantaraan, dan kelautan untuk mengevaluasi ketahanan terhadap korosi dari material dan lapisan permukaan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1867, 9, 1, '132080111078', 'Corrosion Tester (Alat Laboratorium Umum)', 'alat laboratorium yang digunakan untuk mengevaluasi ketahanan material terhadap korosi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1868, 9, 1, '132080111087', 'Dialcaliter', 'alat pengukur yang digunakan untuk mengukur panjang, ketebalan, dan diameter suatu objek dengan tingkat ketelitian yang tinggi. Alat ini umumnya digunakan di berbagai industri, laboratorium, dan bidang lain di mana pengukuran yang akurat diperlukan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1869, 4, 1, '132070102132', 'Rasparaxtium', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1870, 9, 1, '132080111088', 'Dry Oven', 'peralatan laboratorium yang dirancang untuk melakukan proses pengeringan atau pemanasan bahan-bahan atau sampel di dalam lingkungan yang terkendali secara suhu. Oven ini sering digunakan di berbagai laboratorium di berbagai industri untuk aplikasi seperti pengeringan sampel, dekontaminasi peralatan, atau mempersiapkan sampel untuk analisis.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1871, 9, 1, '132080111089', 'Hydrolic Hand Press', 'Alat yang digunakan untuk memberikan tekanan atau kekuatan secara hidrolik menggunakan tangan manusia sebagai sumber tenaga. Alat ini umumnya digunakan dalam berbagai aplikasi, termasuk pekerjaan perakitan, pemadatan, dan pembentukan bahan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1872, 9, 1, '132080111090', 'Hair Dryer/Spray Dryer/Dryer', 'adalah alat yang digunakan untuk menghasilkan bubuk kering dari cairan dengan cara mengeringkannya dengan cepat menggunakan gas panas', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1873, 9, 1, '132080111093', 'Multi Unit Extraction', 'Multi Unit Extraction Heater adalah perangkat pemanas yang dirancang untuk digunakan dalam sistem ekstraksi dengan beberapa unit atau kolom ekstraksi yang dapat beroperasi secara bersamaan. Fungsi utama pemanas dalam konteks ini adalah untuk memanaskan pelarut atau fase pengambilan sampel, mendukung proses ekstraksi zat kimia atau senyawa tertentu dari matriks sampel.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1874, 9, 1, '132080111094', 'Plat Pemanas', 'perangkat pemanas yang digunakan di laboratorium untuk memanaskan cairan atau bahan kimia dalam bejana laboratorium seperti cawan penguap, erlenmeyer, atau gelas kimia. Alat ini umumnya memiliki permukaan datar dan tahan panas untuk menopang wadah yang berisi bahan yang akan dipanaskan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1875, 9, 1, '132080111095', 'Alat Pengukur Tebal', 'Alat Pengukur Tebal di laboratorium dapat merujuk pada beberapa perangkat yang berbeda tergantung pada konteks pengukuran dan jenis bahan yang diukur. Berikut adalah beberapa alat pengukur tebal yang umum digunakan di laboratorium:\n\nMicrometer Screw Gauge:\n\nMicrometer screw gauge digunakan untuk mengukur ketebalan benda tipis dengan presisi tinggi. Alat ini memiliki skala yang membaca ketebalan sampel dalam satuan mikrometer atau milimeter.\nMikrometer Berdasarkan Kedalaman (Depth Micrometer):\n\nDigunakan untuk mengukur kedalaman celah atau ketebalan bahan tertentu. Alat ini memiliki rahang khusus yang dirancang untuk mengukur parameter kedalaman.\nCaliper:\n\nCaliper dapat digunakan untuk mengukur ketebalan dengan cara yang sederhana. Caliper memiliki dua lengan yang dapat dibuka dan ditutup untuk mengukur jarak atau ketebalan suatu objek.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1876, 9, 1, '132080111096', 'Alat Ukur Kadar Air (Alat Laboratorium Umum)', 'perangkat yang digunakan untuk mengukur jumlah air yang terkandung dalam suatu bahan atau sampel. Pengukuran kadar air penting dalam berbagai aplikasi, termasuk di laboratorium, industri, dan pengolahan makanan. Alat ini membantu memastikan kualitas dan kecocokan suatu bahan untuk keperluan tertentu, seperti dalam bidang farmasi, pangan, atau ilmu material.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1877, 9, 1, '132080111098', 'Alat Tembus Udara', 'Alat ini digunakan untuk mengukur kebocoran udara atau untuk menentukan sejauh mana suatu material atau struktur dapat menahan tekanan udara.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1878, 9, 1, '132080111099', 'Alat Uji Kelembaban Udara', 'perangkat yang digunakan untuk mengukur kadar kelembaban dalam udara. Kadar kelembaban mengacu pada jumlah uap air yang terdapat dalam udara, dan alat ini memberikan pembacaan dalam bentuk persentase kelembaban relatif (%RH). Alat uji kelembaban udara dapat digunakan di berbagai lingkungan, termasuk dalam rumah, laboratorium, industri, atau tempat-tempat lain di mana kontrol kelembaban penting.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1879, 9, 1, '132080111100', 'Laminar Air Flow', 'sistem ventilasi yang dirancang untuk menyediakan aliran udara bersih dan bebas partikel di area kerja tertentu, seperti di laboratorium atau ruang bersih. Sistem ini dirancang untuk melindungi sampel atau pekerjaan dari kontaminasi oleh partikel seperti debu, bakteri, atau bahan-bahan lainnya yang dapat mengganggu keberlangsungan eksperimen atau proses.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1880, 9, 1, '132080111101', 'Microtome (Alat Laboratorium Umum)', 'alat laboratorium yang digunakan untuk memotong tipis atau potongan serangkaian tipis dari bahan biologis seperti jaringan atau blok parafin. Ini adalah alat yang penting dalam pemotongan dan penyiapan spesimen untuk analisis mikroskopis. Pemotongan yang presisi dan tipis dari bahan biologis memungkinkan penyelidikan detail struktur sel dan komponen jaringan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1881, 9, 1, '132080111103', 'Autoclave Unit (Alat Laboratorium Umum)', 'perangkat yang digunakan untuk sterilisasi bahan atau peralatan dengan menggunakan panas, tekanan uap air, dan uap air panas. Autoclave biasanya digunakan di laboratorium, rumah sakit, dan industri untuk menghilangkan atau membunuh mikroorganisme patogen, bakteri, virus, dan spora yang dapat menyebabkan kontaminasi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1882, 9, 1, '132080111104', 'Electrik Thermometer', 'Sebuah termometer listrik atau termometer digital adalah alat yang digunakan untuk mengukur suhu dan menghasilkan pembacaan dalam bentuk digital. Termometer ini umumnya memiliki sensor yang merespon terhadap perubahan suhu dan menampilkan hasil pengukuran pada layar digital.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1883, 9, 1, '132080111105', 'Flour Photometer', 'Fluorometer adalah alat laboratorium yang digunakan untuk mengukur fluoresensi dalam suatu sampel. Fluoresensi adalah emisi cahaya yang dihasilkan oleh molekul yang telah tereksitasi oleh radiasi yang diserap sebelumnya.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1884, 9, 1, '132080111106', 'Microscope Dengan Camera', 'mikroskop yang dilengkapi dengan kamera digital atau kamera terhubung untuk merekam atau menangkap gambar dan video dari objek yang diamati di bawah mikroskop. Penggunaan kamera pada mikroskop memungkinkan pengguna untuk merekam dan membagikan gambar mikroskopis, menyimpan dokumentasi, atau melakukan analisis lebih lanjut dengan bantuan perangkat lunak.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1885, 9, 1, '132080111107', 'System Pengendali Derajat Asam', 'sistem otomatis yang digunakan untuk memonitor dan mengendalikan derajat keasaman (pH) dalam suatu larutan atau proses. Pengendalian pH penting dalam banyak aplikasi, termasuk di laboratorium, industri kimia, produksi makanan dan minuman, serta pengolahan air.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1886, 4, 1, '132070103013', 'Vasektomi Dissecting Clam', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1887, 9, 1, '132080111108', 'Mesin Potong Jerami', 'peralatan pertanian yang digunakan untuk memotong jerami atau tumbuhan jerami setelah panen. Mesin ini membantu dalam proses pemotongan dan pengumpulan jerami dengan lebih efisien, memudahkan proses penanganan dan penggunaan jerami untuk berbagai tujuan, seperti pakan ternak, alas bokashi, atau bahan bakar biomassa.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1888, 9, 1, '132080111109', 'Mesin Pres Jerami', 'peralatan pertanian atau pengolahan biomassa yang digunakan untuk mengompres atau memadatkan jerami menjadi bal atau bale. Proses pemadatan ini memudahkan penyimpanan, transportasi, dan penggunaan jerami untuk berbagai keperluan, seperti pakan ternak, substrat kompos, atau bahan bakar biomassa.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1889, 9, 1, '132080111111', 'Alat Poleshing', 'Alat poles (polishing) digunakan untuk merapikan dan menghaluskan permukaan suatu benda kerja, baik itu logam, kayu, atau bahan lainnya. Alat ini memiliki berbagai bentuk dan ukuran tergantung pada jenis pekerjaan poles yang ingin dilakukan. Poles dapat dilakukan secara manual atau dengan menggunakan alat listrik.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1890, 9, 1, '132080111112', 'Alat Gerinda', 'alat atau peralatan laboratorium yang digunakan untuk proses pengolahan atau penggilingan sampel bahan, dengan menggunakan agate sebagai bahan gilingan dan memiliki tiga komponen yang terkait dengan proses penggerusan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1891, 9, 1, '132080111113', 'Refrigerator', 'perangkat pendingin khusus yang digunakan di laboratorium untuk menyimpan bahan-bahan yang memerlukan suhu rendah atau stabil. Refrigerator lab sering digunakan untuk menyimpan reagen, sampel biologis, obat-obatan, atau bahan-bahan lain yang perlu dijaga suhu dan kestabilannya untuk menjaga integritas dan kualitasnya.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1892, 9, 1, '132080111114', 'Freeze Dryer', 'alat laboratorium yang digunakan untuk proses pengeringan dengan memanfaatkan sublimasi. Proses sublimasi adalah perubahan fase langsung dari keadaan beku (padat) menjadi gas, tanpa melalui fase cair. Freeze dryer biasanya digunakan untuk mengeringkan bahan-bahan yang sensitif terhadap panas atau kelembaban, seperti bahan biologis, obat-obatan, atau bahan kimia laboratorium.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1893, 9, 1, '132080111115', 'Refractometer (Alat Laboratorium Umum)', 'alat laboratorium umum yang digunakan untuk mengukur indeks bias suatu cairan. Indeks bias adalah besaran yang menunjukkan seberapa besar cahaya dibiaskan ketika melewati suatu medium, dibandingkan dengan kecepatan cahaya di udara. Refraktometer biasanya digunakan untuk mengukur konsentrasi larutan dalam berbagai aplikasi, termasuk kimia, biologi, dan industr', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1894, 4, 1, '132070104006', 'Rectum Set', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1895, 9, 1, '132080111116', 'Vacuum Oven', 'alat laboratorium yang dirancang untuk melakukan proses pemanasan atau pengeringan pada sampel di dalam ruang hampa udara. Vacuum oven digunakan untuk mengurangi tekanan di dalam ruang oven, menciptakan kondisi vakum. Hal ini dapat membantu mengurangi titik didih cairan dalam sampel, mempercepat pengeringan, dan menghilangkan kelembaban dengan lebih efisien.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1896, 9, 1, '132080111117', 'Calorimeter', 'alat yang digunakan untuk mengukur jumlah panas yang dihasilkan atau diserap selama suatu reaksi kimia atau proses fisika. Pengukuran ini dapat memberikan informasi tentang entalpi reaksi atau perubahan energi panas dalam sistem. Calorimeter dapat digunakan dalam berbagai eksperimen termokimia dan termodinamika.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1897, 9, 1, '132080111118', 'Galvanometer', 'alat pengukur arus listrik yang sensitif, biasanya digunakan untuk mengukur arus kecil dalam suatu rangkaian. Prinsip kerja galvanometer didasarkan pada efek elektromagnetik yang ditemukan oleh Hans Christian Ørsted. Ketika arus listrik mengalir melalui kumparan yang ditempatkan di medan magnet, akan terjadi interaksi antara medan magnet dan arus, menyebabkan kumparan bergerak.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1898, 9, 1, '132080111119', 'Filter Press', 'peralatan yang digunakan dalam laboratorium untuk proses pemisahan padatan dan cairan. Ini merupakan alat filtrasi yang umum digunakan dalam pengujian laboratorium, penelitian, dan pengembangan proses. Filter press bekerja dengan menekan cairan yang mengandung padatan melalui media penyaring untuk memisahkan padatan dari cairan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1899, 9, 1, '132080111120', 'Higromoter', 'alat pengukur kelembaban udara dalam suatu ruangan atau lingkungan tertentu. Hygrometer digunakan untuk mengukur tingkat kelembaban relatif (RH) dalam persentase.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1900, 9, 1, '132080111121', 'Termocouple', 'sensor suhu yang terdiri dari dua logam yang berbeda yang dihubungkan pada satu ujung. Ketika terjadi perbedaan suhu di antara kedua ujung termokopel, akan terjadi perubahan potensial listrik yang dapat diukur. Prinsip kerja termokopel didasarkan pada efek termoelektrik atau efek Seebeck.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1901, 9, 1, '132080111123', 'Load Cell', 'suatu alat yang dirancang untuk mengukur gaya atau beban pada suatu objek. Load cell mengonversi gaya atau tekanan yang bekerja padanya menjadi sinyal listrik yang dapat diukur. Ini adalah perangkat yang umumnya digunakan dalam berbagai aplikasi, termasuk dalam pengukuran berat, pengendalian proses industri, uji material, dan banyak lagi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1902, 9, 1, '132080111125', 'Tripod', 'suatu rangkaian atau struktur tiga kaki yang digunakan untuk mendukung peralatan laboratorium seperti bejana gelas, alat pemanas, atau perangkat lain yang memerlukan penopang stabil. Tripod ini membantu menjaga kestabilan peralatan dan memungkinkan pemanasan atau proses lainnya berlangsung secara aman dan efisien.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1903, 9, 1, '132080111126', 'Spectrophotometer', 'instrumen laboratorium yang digunakan untuk mengukur intensitas cahaya pada berbagai panjang gelombang dalam spektrum elektromagnetik. Instrumen ini banyak digunakan dalam berbagai bidang ilmu, termasuk kimia, biologi, fisika, dan ilmu material, untuk melakukan analisis kuantitatif dan kualitatif.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1904, 9, 1, '132080111128', 'Induction Totor', 'Motor induksi laboratorium biasanya dipilih untuk keperluan eksperimen, pendidikan, dan pengembangan di lingkungan pendidikan atau penelitian.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1905, 9, 1, '132080111135', 'Digital Signal Procesor', 'jenis mikroprosesor khusus yang dirancang untuk memproses sinyal digital dalam aplikasi seperti pemrosesan sinyal audio, pemrosesan gambar, komunikasi nirkabel, dan aplikasi lain yang melibatkan manipulasi sinyal digital.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1906, 9, 1, '132080111136', 'Hand Saw Machine', 'mesin gergaji tangan yang digunakan untuk pemotongan material dengan menggunakan gergaji tangan atau gergaji mesin yang dioperasikan secara manual. Mesin ini biasanya digunakan untuk memotong kayu, logam, atau bahan lainnya dengan akurasi dan presisi tertentu. Pemotongan dapat dilakukan dalam berbagai sudut dan ukuran tergantung pada jenis gergaji yang digunakan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1907, 9, 1, '132080111138', 'Function Generator (Alat Laboratorium Umum)', 'perangkat yang menghasilkan sinyal gelombang pada berbagai bentuk, seperti gelombang sinus, gelombang persegi, atau gelombang segitiga. Perangkat ini umumnya digunakan di laboratorium elektronika, pendidikan teknik, dan pengembangan prototipe. Function generator memungkinkan pengguna untuk menghasilkan sinyal uji yang dapat digunakan dalam pengukuran, pengujian, atau eksperimen elektronik.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1908, 9, 1, '132080111139', 'Process Calibrator Fluke', 'alat yang digunakan untuk mengukur, mengkalibrasi, dan menguji instrumen-instrumen pengukuran dalam suatu proses atau sistem industri. Calibrator ini membantu memastikan bahwa instrumen pengukuran beroperasi dengan akurasi yang tinggi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1909, 9, 1, '132080111142', 'Cnc Milling Machine', 'mesin penggilingan yang dikendalikan oleh komputer dan dirancang untuk membuat atau menghasilkan produk dengan presisi tinggi. Mesin ini umumnya digunakan di laboratorium untuk berbagai aplikasi, termasuk penelitian, pengembangan prototipe, atau pembuatan komponen dengan toleransi yang ketat.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1910, 9, 1, '132080111143', 'Mesin Pengayak', 'peralatan yang digunakan untuk menyaring atau memisahkan bahan padat menjadi fraksi-fraksi berdasarkan ukuran partikel. Mesin ini umumnya digunakan dalam berbagai bidang laboratorium, termasuk kimia, ilmu material, dan biologi, di mana pemisahan partikel berdasarkan ukuran tertentu diperlukan untuk analisis atau penelitian.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1911, 9, 1, '132080111150', 'Core Bit', 'alat bor khusus yang dirancang untuk mengebor atau memotong inti silinder dari bahan keras seperti batuan, beton, atau bahan konstruksi lainnya. Inti yang dihasilkan oleh core bit ini biasanya memiliki diameter yang sesuai dengan diameter bit dan dapat digunakan untuk berbagai tujuan analisis dan evaluasi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1912, 4, 1, '132070104023', 'Polygraph', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1913, 9, 1, '132080111152', 'Universal Coring Machine', 'peralatan atau mesin yang digunakan untuk pengambilan inti atau contoh inti dari bahan padat seperti batuan, tanah, beton, atau bahan konstruksi lainnya. Pengambilan inti atau coring ini dapat dilakukan untuk keperluan penelitian, pemantauan kualitas material, atau evaluasi kekuatan struktural.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1914, 9, 1, '132080111154', 'Ayakan Gantung', 'peralatan laboratorium yang digunakan untuk proses penyaringan atau pemisahan bahan-bahan padat dalam ukuran partikel tertentu. Ayakan ini biasanya digunakan dalam bidang-bidang seperti kimia, biologi, atau ilmu material untuk memisahkan partikel atau sampel padat berdasarkan ukuran.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1915, 9, 1, '132080111156', 'Elektroda Spesifik', 'jenis elektroda yang dirancang khusus untuk mengukur parameter tertentu dalam lingkungan laboratorium. Elektroda ini memiliki kepekaan dan presisi yang tinggi terhadap parameter tertentu, memungkinkan pengukuran yang akurat dalam berbagai aplikasi laboratorium.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1916, 9, 1, '132080111158', 'Cuvet Cadangan Metachylate', 'wadah transparan yang digunakan dalam spektrofotometri dan fluorimetri untuk mengukur absorbansi atau fluoresensi sampel cair atau suspensi. Cuvet biasanya terbuat dari kaca atau plastik optik dengan dinding yang bening dan permukaan datar untuk memungkinkan cahaya melewati sampel dengan sedikit gangguan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1917, 9, 1, '132080111159', 'Digital Indicator LCD/Metric', 'perangkat yang digunakan dalam lingkungan laboratorium untuk mengukur dan menampilkan nilai numerik dari suatu parameter tertentu. Perangkat ini dilengkapi dengan layar LCD (Liquid Crystal Display) untuk menampilkan hasil pengukuran dengan jelas dan akurat.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1918, 4, 1, '132070104028', 'Allis Klem', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1919, 9, 1, '132080111164', 'Peralatan Homogenisasi', 'perangkat yang menggunakan tekanan tinggi atau gaya gesekan untuk memecah dan meratakan partikel dalam suatu cairan. Terdapat homogenizer mekanis dan homogenizer ultrasonik', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1920, 9, 1, '132080111173', 'Alat Procesing rumput', 'alat atau peralatan yang dapat terlibat dalam pengolahan atau analisis sampel rumput di laboratorium\n\nDigunakan untuk memisahkan bagian-bagian kasar dari sampel rumput (Alat Penyaring (Sieve), Pisau atau gunting laboratorium digunakan untuk memotong atau mencincang sampel rumput sehingga dapat diproses lebih lanjut (gunting lab)', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1921, 4, 1, '132070104030', 'Anuscope (Anak,Dewasa)', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1922, 9, 1, '132080111174', 'Bacteriological Colony Counter', 'perangkat atau alat laboratorium yang digunakan untuk menghitung koloni bakteri atau mikroorganisme lainnya yang tumbuh pada medium kultur. Pada dasarnya, perangkat ini membantu dalam mengidentifikasi dan mengukur jumlah koloni yang muncul setelah suatu sampel telah diinkubasi pada medium yang sesuai.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1923, 9, 1, '132080111176', 'Biocounter', 'perangkat atau sistem otomatis yang dirancang untuk menghitung jumlah sel dalam suatu sampel dengan cepat dan akurat. Pada umumnya, automated cell counter digunakan dalam laboratorium biologi sel, bioteknologi, atau laboratorium klinis untuk memudahkan dan mempercepat proses penghitungan sel.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1924, 9, 1, '132080111179', 'Cooling Water Circulator', 'perangkat yang digunakan untuk menyediakan aliran air dingin atau cairan pendingin lainnya ke perangkat atau sistem yang memerlukan pendinginan. Sirkulator ini umumnya digunakan dalam aplikasi laboratorium, industri, atau penelitian di mana peralatan atau proses memerlukan suhu yang terkendali atau pendinginan aktif', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1925, 9, 1, '132080111182', 'Disecting Apparatus (Alat Laboratorium Umum)', 'sekelompok alat laboratorium yang digunakan dalam proses disseksi, yaitu teknik pembedahan atau pemeriksaan struktur internal suatu organisme atau objek. Peralatan ini dirancang khusus untuk memfasilitasi pemisahan dan pengamatan struktur anatomi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1926, 4, 1, '132070104034', 'Approach Sinator', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1927, 9, 1, '132080111185', 'Electric Measuring Tape', 'perangkat sederhana yang digunakan untuk mengukur panjang atau jarak.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1928, 9, 1, '132080111191', 'Fluid Contamination Analysis Kit', 'alat analisis kontaminasi fluida umumnya dirancang untuk mendeteksi dan mengukur kontaminan dalam cairan, seperti minyak, partikel, atau zat kimia lainnya.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1929, 9, 1, '132080111192', 'Gene Amp Pcr System', 'alat yg digunakan untuk melakukan reaksi Polymerase Chain Reaction (PCR), sebuah metode yang digunakan untuk mengamplifikasi (melipatgandakan) fragmen DNA tertentu secara signifikan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1930, 9, 1, '132080111194', 'Hygrometer (Alat Laboratorium Umum)', 'alat yang digunakan untuk mengukur kelembaban atau kadar air dalam udara. Ini merupakan instrumen penting dalam berbagai konteks, termasuk laboratorium. Kelembaban udara dapat memengaruhi banyak proses dan eksperimen, sehingga pemantauan dan pengukuran kelembaban dapat menjadi faktor kunci dalam eksperimen laboratorium.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1931, 9, 1, '132080111195', 'Ice Maker (Alat Laboratorium Umum)', 'perangkat khusus yang dirancang untuk menghasilkan es dalam lingkungan laboratorium. Dalam banyak kasus, es laboratorium diproduksi dengan tingkat kemurnian dan kebersihan yang tinggi untuk memenuhi persyaratan eksperimen dan penelitian laboratorium yang memerlukan pendinginan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1932, 9, 1, '132080111198', 'Laminair Flow Cabinet', 'perangkat laboratorium yang dirancang untuk menyediakan lingkungan kerja bersih dengan aliran udara laminar yang terkontrol. Tujuannya adalah untuk melindungi sampel atau bahan yang sedang diproses dari kontaminasi oleh part', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1933, 4, 1, '132070104040', 'Bougie (Higar, Metal,Urethra)', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1934, 9, 1, '132080111200', 'Liquid Extractor', 'perangkat atau sistem yang digunakan untuk mengekstrak komponen tertentu dari suatu cairan atau larutan. Metode ini umumnya melibatkan perpindahan solut dari suatu fase cair ke fase cair lainnya, seringkali menggunakan pelarut tertentu.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1935, 4, 1, '132070104041', 'Buldog', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1936, 9, 1, '132080111207', 'Rotary Evaporator', 'perangkat laboratorium yang digunakan untuk menghilangkan pelarut dari sampel cair atau larutan melalui penguapan. Proses ini melibatkan memanaskan larutan di dalam wadah tertutup untuk menguapkan pelarut, dan kemudian mengumpulkan pelarut yang menguap kembali menjadi bentuk cairan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1937, 4, 1, '132070104042', 'Burn Tang Lengkap Dengan Lift', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1938, 9, 1, '132080112001', 'Autocleve', 'Autoclave adalah perangkat yang digunakan untuk sterilisasi berbagai benda, termasuk peralatan laboratorium, instrumen medis, dan media kultur mikrobiologi, dengan menggunakan uap air di bawah tekanan tinggi. Proses sterilisasi dengan autoclave dapat membunuh berbagai jenis mikroorganisme, termasuk bakteri, virus, dan spora bakteri.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1939, 4, 1, '132070104043', 'Busteustinal Clam Curved', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1940, 9, 1, '132080112002', 'Oven/Hot Air Sterilizer', 'perangkat yang digunakan untuk proses sterilisasi menggunakan panas kering. Metode sterilisasi ini efektif untuk menghilangkan mikroorganisme dari alat-alat laboratorium, peralatan medis, dan material lainnya.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1941, 4, 1, '132070104044', 'C B D', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1942, 9, 1, '132080112003', 'Pipette Washer', 'perangkat yang digunakan untuk membersihkan pipet laboratorium secara otomatis. Pipet merupakan alat yang umum digunakan dalam laboratorium untuk mengukur dan mentransfer volume cairan dengan akurasi tinggi. Setelah penggunaan, pipet perlu dibersihkan untuk mencegah kontaminasi silang antar-sampel atau bahan kimia.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1943, 4, 1, '132070104045', 'Canule', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1944, 9, 1, '132080112004', 'Pipette Dryer', 'perangkat yang dirancang khusus untuk mengeringkan pipet setelah dicuci atau disterilkan. Pipet adalah alat yang digunakan dalam laboratorium untuk mengukur dan mentransfer volume cairan dengan presisi. Setelah digunakan, pipet perlu dicuci dan dikeringkan sebelum dapat digunakan kembali.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1945, 9, 1, '132080112005', 'Santrifuge Biasa', 'alat laboratorium yang digunakan untuk memisahkan partikel dalam suatu larutan berdasarkan berat jenisnya menggunakan gaya sentrifugal. Prinsip kerja sentrifuge didasarkan pada penerapan gaya sentrifugal yang diciptakan oleh putaran berkecepatan tinggi, yang memaksa partikel-partikel dalam larutan untuk bergerak menjauh dari poros rotasi dan mendekati dinding tabung sentrifuge', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1946, 9, 1, '132080112006', 'Binoculer Microscope (Alat Laboratorium Microbiologi)', 'binocular compound microscope, adalah jenis mikroskop yang dilengkapi dengan dua lensa okuler (eyepiece) yang memungkinkan pengamat melihat objek dengan kedua mata. Mikroskop ini sering digunakan dalam berbagai bidang ilmu, termasuk mikrobiologi, biologi sel, dan bidang ilmu lain yang memerlukan pengamatan objek kecil atau struktur mikroskopis. Berikut adalah beberapa ciri umum dari binocular microscope:', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1947, 9, 1, '132080112007', 'Sentrifuge Untuk Microplate', 'perangkat yang dirancang khusus untuk memusatkan sampel dalam microplate (plate mikrotiter) dengan menggunakan prinsip sentrifugasi. Microplate adalah wadah datar dengan beberapa sumuran atau sumur kecil yang digunakan untuk mengadakan sampel dalam volume kecil, dan centrifuge untuk microplate memungkinkan pemisahan partikel atau cairan berdasarkan berat jenis mereka.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1948, 4, 1, '132070104049', 'Chromovision', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1949, 9, 1, '132080112008', 'Stereo Microscope (Alat Laboratorium Microbiologi)', 'jenis mikroskop yang dirancang untuk pengamatan objek dalam tiga dimensi (3D) dengan tingkat perbesaran rendah hingga sedang. Alat ini sering digunakan dalam bidang biologi, mikrobiologi, entomologi, dan bidang ilmu lainnya di mana pengamatan objek besar dengan kedalaman lapangan yang lebih besar diperlukan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1950, 9, 1, '132080112010', 'Magnetic Stirer & Rod With Hot Plate', 'perangkat laboratorium yang digunakan untuk mencampur larutan secara otomatis menggunakan pengaduk magnetik sambil menyediakan pemanasan melalui hot plate', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1951, 9, 1, '132080112011', 'Balance Electric', 'timbangan listrik atau timbangan elektrik. Timbangan listrik atau timbangan elektrik adalah alat yang menggunakan listrik untuk mengukur massa benda dengan akurasi tinggi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1952, 4, 1, '132070104052', 'Comiatun Set', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1953, 9, 1, '132080112013', 'Demineralizer (Alat Laboratorium Microbiologi)', 'proses penghilangan kadar garam dan mineral dalam air melalui proses pertukaran ion (ion exchange process) dengan menggunakan media resin/softener anion dan kation.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1954, 4, 1, '132070104053', 'Curve Long Rirtonal', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1955, 9, 1, '132080112014', 'Millipore Filter', 'Millipore filter umumnya digunakan untuk proses filtrasi di laboratorium dan industri. Produk ini dapat mencakup berbagai jenis filter, termasuk filter membran, filter tangki, filter serbuk, dan berbagai variasi filter lainnya', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1956, 4, 1, '132070104054', 'Cusa Cover', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1957, 9, 1, '132080112017', 'Pipette Filter', 'alat yang digunakan untuk mengisi dan mengeluarkan cairan dari pipet secara akurat. Pipet filter membantu mencegah kontaminasi silang antara pengguna dan sampel, serta memastikan pengisian dan pembuangan cairan yang tepat', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1958, 9, 1, '132080112018', 'Propipette', 'alat ini berguna untuk mengambil larutan pekat dengan jumlah volume tertentu, sedangkan propipet digunakan bersama pipet volume untuk memompa larutan agar masuk atau keluar pipet volume.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1959, 4, 1, '132070104056', 'Cystoscopy', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1960, 9, 1, '132080112019', 'Pipette Container', 'tempat penyimpanan untuk pipet di laboratorium mikrobiologi,  tempat penyimpanan untuk pipet di laboratorium mikrobiologi', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1961, 9, 1, '132080112020', 'Tube Container', 'tabung atau wadah yang digunakan untuk mengandung sampel mikrobiologis, media kultur, atau bahan biologis lainnya. Tube containers dapat hadir dalam berbagai bentuk, ukuran, dan materi, tergantung pada kebutuhan aplikasi dan metode laboratorium tertentu', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1962, 4, 1, '132070104058', 'Deaver Rectraktor', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1963, 9, 1, '132080112021', 'Wire Basket', 'keranjang berbahan dasar kawat yang digunakan untuk berbagai tujuan dalam laboratorium mikrobiologi. Keranjang ini biasanya terbuat dari logam yang tahan terhadap korosi dan mudah dibersihkan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1964, 9, 1, '132080112024', 'Stabilizer', 'bahan tambahan yang ditambahkan ke dalam medium kultur atau sampel mikrobiologis untuk menjaga kestabilan kondisi lingkungan atau karakteristik biologis tertentu. Fungsi stabilizer mikrobiologi dapat bervariasi tergantung pada aplikasinya. Berikut adalah beberapa contoh penggunaan stabilizer dalam konteks mikrobiologi:', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1965, 9, 1, '132080112025', 'Freezer 70 Derajat C Centrifuge With Accesories', 'freezer yang dirancang khusus untuk menyimpan sampel mikrobiologi, bahan biologis, atau produk farmasi pada suhu yang sangat rendah. Freezer ini merupakan bagian penting dari laboratorium mikrobiologi dan laboratorium biologi molekuler di mana konservasi sampel dan bahan biologis pada suhu rendah sangat kritis.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1966, 4, 1, '132070104061', 'Debaky Pean Forceps Cun', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1967, 9, 1, '132080112027', 'Analytic Balancer', 'timbangan analitis, adalah jenis timbangan yang digunakan untuk mengukur massa benda dengan tingkat akurasi yang sangat tinggi. Timbangan ini dirancang khusus untuk keperluan laboratorium di bidang ilmu kimia, biologi, farmasi, dan ilmu lainnya di mana keakuratan yang tinggi diperlukan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1968, 4, 1, '132070104062', 'Deower Retractor', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1969, 9, 1, '132080112030', 'Ice Crusher', 'perangkat atau mesin yang dirancang khusus untuk menghancurkan es menjadi serpihan atau kepingan lebih kecil', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1970, 4, 1, '132070104063', 'Desjardin Galls T Scoop Fig', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1971, 9, 1, '132080112032', 'Inculating Supplies', 'alat dan perlengkapan yang umumnya digunakan dalam pekerjaan kultur mikrobiologi dan kegiatan inokulasi', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1972, 4, 1, '132070104064', 'Dopscan', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1973, 9, 1, '132080112034', 'Peristalitic Pump', 'pompa peristaltik, adalah jenis pompa positif yang bekerja dengan prinsip peristalsis untuk memindahkan fluida dari satu tempat ke tempat lain. Prinsip dasar dari pompa peristaltik melibatkan pemampatan dan pemulihan periodik tabung elastis atau fleksibel oleh rol atau "shoe". Ini menciptakan aliran yang terus-menerus dari fluida dalam tabung, mengikuti pola gerakan peristaltik.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1974, 4, 1, '132070104065', 'Dual Temperature Steam Stirilizer', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1975, 9, 1, '132080112035', 'Tube For Centrifuge', 'Terdapat berbagai jenis tabung yang digunakan untuk centrifuge (sentrifuge tube) tergantung pada aplikasi dan kebutuhan spesifik laboratorium', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1976, 4, 1, '132070104066', 'Duck Klem (Besar,Kecil)', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1977, 9, 1, '132080112038', 'Test Tube Mixer', 'alat laboratorium yang digunakan untuk mencampur atau mengguncang sampel dalam tabung reaksi atau tabung uji. Alat ini membantu dalam mencampur zat kimia atau bahan biologis dalam tabung secara merata. Test tube mixer dapat digunakan dalam berbagai aplikasi laboratorium, termasuk di bidang kimia, biologi, dan analisis klinis.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1978, 4, 1, '132070104067', 'Dupal', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1979, 9, 1, '132080112040', 'Rotator Shaker (Alat Laboratorium Microbiologi)', 'alat laboratorium yang digunakan dalam bidang mikrobiologi dan biologi molekuler untuk mengguncang dan memutar sampel dalam tabung atau wadah tertentu. Alat ini berfungsi untuk menciptakan kondisi pengguncangan yang merata sehingga memfasilitasi pertumbuhan mikroorganisme dalam cairan atau melibatkan proses campuran zat kimia atau reaksi biokimia.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1980, 9, 1, '132080112041', 'Microscope Monocular', 'jenis mikroskop yang dilengkapi dengan satu ocular atau lensa okuler, memungkinkan satu mata pengamat untuk melihat objek mikroskopis pada satu waktu. Ini adalah jenis mikroskop yang umum digunakan untuk pengenalan dan pembelajaran dasar di banyak lingkungan pendidikan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1981, 9, 1, '132080112042', 'Microscope Binocular', 'jenis mikroskop yang dilengkapi dengan dua ocular atau lensa okuler, memungkinkan dua mata pengamat untuk melihat objek mikroskopis secara bersamaan. Mikroskop ini biasanya digunakan untuk pengamatan yang lebih nyaman dan alami, karena meniru cara mata manusia melihat dunia sekitarnya.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1982, 9, 1, '132080112043', 'Photo Microscope', 'mikroskop fotografi, adalah mikroskop yang dirancang khusus untuk memfasilitasi pengambilan gambar atau fotografi dari objek mikroskopis. Mikroskop ini dilengkapi dengan sistem optik dan fitur khusus yang memungkinkan pengguna untuk merekam gambar objek mikroskopis dengan kualitas tinggi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1983, 9, 1, '132080112044', 'Atomic Absorption Spectro', 'teknik analisis kimia yang digunakan untuk mengidentifikasi dan mengukur konsentrasi unsur logam dalam suatu sampel. Metode ini berdasarkan pada prinsip bahwa atom unsur logam dapat menyerap radiasi elektromagnetik pada panjang gelombang tertentu saat mereka berada dalam keadaan gas dan kemudian kembali ke keadaan dasar setelah penyerapan energ', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1984, 4, 1, '132070104072', 'Endophare', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1985, 9, 1, '132080112047', 'Chromatography Injection', 'proses penyuntikan sampel ke dalam kolom atau sistem chromatografi untuk analisis pemisahan. Teknik ini umumnya digunakan dalam kromatografi cair (liquid chromatography) dan kromatografi gas (gas chromatography), di mana sampel akan dipisahkan menjadi komponen-komponennya berdasarkan sifat fisikokimia mereka.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1986, 9, 1, '132080112048', 'Device (Alat Laboratorium Microbiologi)', 'Alat lab mikrobiologi terdiri dari banyak perlatan sesuai dengan jenis dan kebutuhan masing-masing', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1987, 4, 1, '132070104074', 'Fuged Air Lig And Diss Pcs', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1988, 9, 1, '132080112050', 'Microtome Unit', 'perangkat laboratorium yang digunakan untuk memotong potongan tipis dari spesimen biologis atau bahan material lainnya untuk tujuan analisis mikroskopis. Microtome unit terdiri dari berbagai komponen yang bekerja bersama-sama untuk menghasilkan potongan tipis yang seragam', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1989, 9, 1, '132080112051', 'Analitical Balance (Alat Laboratorium Microbiologi)', 'jenis timbangan presisi yang dirancang untuk memberikan pengukuran massa yang sangat akurat. Timbangan ini digunakan dalam berbagai aplikasi laboratorium, termasuk dalam bidang mikrobiologi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1990, 4, 1, '132070104076', 'Garpu/Rectractor', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1991, 9, 1, '132080112052', 'Precisions Balance', 'perangkat laboratorium yang digunakan untuk mengukur massa benda dengan akurasi yang tinggi. Timbangan presisi ini sangat penting dalam berbagai aplikasi laboratorium, terutama di bidang kimia, farmasi, biologi, dan penelitian ilmiah lainnya di mana ukuran yang akurat dan presisi diperlukan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1992, 4, 1, '132070104077', 'Gayon Renal Pedicle Clam', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1993, 9, 1, '132080112053', 'Washing Instrument (Alat Laboratorium Microbiologi)', 'alat atau peralatan yang digunakan untuk mencuci atau membersihkan instrumen laboratorium. Membersihkan instrumen dengan benar adalah langkah penting dalam menjaga kebersihan dan menghindari kontaminasi silang antar percobaan atau analisis', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1994, 9, 1, '132080112054', 'Microscope Fluoronsence', 'Mikroskop fluoresensi digunakan untuk mengamati objek atau spesimen yang telah diberi zat pewarna fluoresen. Mikroskop ini sangat berguna dalam bidang biologi seluler dan molekuler karena memungkinkan visualisasi dan analisis spesifik struktur sel atau molekul.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1995, 9, 1, '132080112057', 'Microtitation Plate Incubator', 'perangkat yang dirancang khusus untuk memberikan kondisi lingkungan yang sesuai untuk kultur mikroorganisme atau reaksi biokimia dalam mikrotiter plate. Mikrotiter plate adalah lempeng yang terdiri dari barisan sumuran-sumuran kecil (well) yang digunakan untuk mengadakan reaksi kimia, pertumbuhan mikroorganisme, atau pengujian lainnya.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1996, 9, 1, '132080112058', 'Automatic Micro Plate Laser', 'Mikroplak adalah perangkat berbentuk lempeng dengan sumuran-sumuran kecil (well) yang digunakan dalam berbagai eksperimen laboratorium, termasuk di bidang biologi molekuler, biokimia, dan mikrobiologi. Sistem otomatis ini membantu meningkatkan efisiensi, akurasi, dan reproduktibilitas dalam pengujian yang melibatkan mikroplak.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1997, 4, 1, '132070104081', 'Hak Langen Beck', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1998, 9, 1, '132080112059', 'Petri Dish', 'sebuah wadah yang bentuknya bundar dan terbuat dari plastik atau kaca yang digunakan untuk membiakkan sel', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(1999, 4, 1, '132070104082', 'Hak Pembuka Otot', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2000, 9, 1, '132080112060', 'Loop Sterilizer', 'perangkat yang digunakan dalam laboratorium mikrobiologi untuk sterilisasi loop atau alat pengambil sampel yang digunakan dalam teknik pembibitan bakteri atau kultur mikroorganisme lainnya. Fungsi utama dari loop sterilizer adalah untuk membunuh mikroorganisme yang mungkin ada pada loop atau alat serupa, sehingga mencegah kontaminasi silang antar sampel atau kultu', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2001, 9, 1, '132080112061', 'Reader Petri Dishas', 'alat untuk mengetahui warna koloni dan zona hambat dengan resolusi tinggi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2002, 9, 1, '132080112062', 'Reader Antibiotic', 'alat atauninstrumen lab baktereologi yang biasanya digunakan untuk mengetahui aktivitas bakteri', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2003, 9, 1, '132080112065', 'Miniature French Presure Cell 3,7 Ml Capasity, Presure Up To 20.', 'French Presure Cell adalah alat yang digunakan dalam eksperimen biologis untuk mengganggu membran plasma sel dengan melewatkannya melalui katup sempit di bawah tekanan tinggi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2004, 9, 1, '132080112067', 'Hematology Analyzer ( Blood Cell Counter )', 'alat laboratorium medis yang digunakan untuk menganalisis komponen-komponen sel darah dalam sampel darah', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2005, 4, 1, '132070104087', 'Hoesel', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2006, 9, 1, '132080112069', 'Microcentrifuge', 'Microcentrifuge merupakan centrifuge yang mampu menampung sampel dalam ukuran kecil dalam kecepatan tinggi. Umumnya, kegunaannya adalah mengendapkan sampel seperti asam nukleat dan protein.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2007, 4, 1, '132070104088', 'Instrument Pin', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2008, 9, 1, '132080112070', 'Stiring Hot Plat', 'Hotplate stirrer adalah alat laboratorium yang memiliki alas datar seperti piring yang digunakan untuk memanaskan atau mencampur bahan hingga homogen melalui proses pengadukan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2009, 4, 1, '132070104089', 'Instrument Lany', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2010, 9, 1, '132080112071', 'Micro Pippettes', 'Micropipette – adalah pipet yang dilengkapi dengan mesin sehingga memiliki akurasi dan presisi yang tinggi. Ukuran pipet ini berada pada skala mikroliter', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2011, 9, 1, '132080112072', 'Electromagnetic Current Meter', 'adalah suatu perangkat yang gunanya sebagai pengukur aliran fluida. Perangkat ini memanfaatkan prinsip gaya magnetik serta listrik sesuai dengan prinsip dasar pada hukum Faraday', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2012, 4, 1, '132070104091', 'Israel Retractor', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2013, 9, 1, '132080112077', 'Digital Storage Oscilloscope', 'Digital Storage Oscilloscope (sering disingkat DSO) adalah osiloskop yang menyimpan dan menganalisis sinyal secara digital daripada menggunakan teknik analog.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2014, 4, 1, '132070104092', 'Jacob Yuls Forceps', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2015, 9, 1, '132080112078', 'Detector', 'perangkat atau sistem yang digunakan untuk mendeteksi atau mengukur keberadaan atau aktivitas mikroorganisme dalam sampel atau lingkungan tertentu.\n\nBeberapa jenis detektor dalam laboratorium mikrobiologi meliputi:\n\nDetektor Bioluminesensi: Menggunakan reaksi kimia dalam mikroorganisme yang menghasilkan cahaya, sering digunakan untuk mendeteksi adanya mikroba dalam sampel.\n\nSpektrofotometer: Digunakan untuk membaca pertumbuhan mikroorganisme dalam budaya cair berdasarkan absorbansi cahaya atau warna yang dihasilkan oleh metabolisme mikroba.\n\nDetektor Gas: Untuk mendeteksi gas yang dihasilkan oleh mikroorganisme selama pertumbuhan, misalnya, gas yang dihasilkan oleh bakteri tertentu selama fermentasi.\n\nDetektor PCR (Polymerase Chain Reaction): Menggunakan teknologi amplifikasi DNA untuk mendeteksi dan mengidentifikasi keberadaan mikroba tertentu berdasarkan sekuensinya.\n\nSistem Analisis Flow Cytometry: Digunakan untuk analisis dan pemisahan sel mikroba berdasarkan sifat fisik dan kimia mereka.\n\nBiosensor: Alat yang menggunakan biologi molekuler untuk mendeteksi keberadaan atau aktivitas mikroba dalam sampel tertentu.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2016, 4, 1, '132070104093', 'Jening Mouth', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2017, 9, 1, '132080112080', 'Microscope Tringular', 'Mikroskop sendiri umumnya digunakan untuk memperbesar objek yang sangat kecil sehingga dapat diamati lebih detail', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2018, 4, 1, '132070104094', 'Kien Nail', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2019, 9, 1, '132080112082', 'Vacuum Manifold', 'perangkat laboratorium yang digunakan untuk memudahkan dan mengatur proses filtrasi secara paralel dengan menggunakan vakum', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2020, 4, 1, '132070104095', 'Kikir Osteotomi (Lengkung,Lurus)', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2021, 9, 1, '132080112083', 'Dispensing Pump', 'perangkat yang digunakan untuk mengatur dan mengeluarkan cairan atau zat dalam jumlah yang tepat dan terukur.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2022, 9, 1, '132080112084', 'DNA Analyzer', 'Penganalisis DNA adalah instrumen otomatis di mana pengurutan dan analisis fragmen DNA dilakukan dengan elektroforesis kapiler berdasarkan ukurannya.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2023, 9, 1, '132080112085', 'Bio Safety Cabinet', 'Biological safety cabinet (BSC) atau Kabinet biosafety adalah salah satu alat yang digunakan dalam ruang bidang mikrobiologi dan berfungsi untuk memberikan perlindungan bagi pengguna, meminimalisir terjadinya kontaminasi dari virus/bakteri yang bersifat patogen serta dapat menjaga lingkungan area kerja dengan merekayasa ventilasi udara', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2024, 9, 1, '132080112086', 'Nucleic Acid Extractor', 'perangkat medis laboratorium, yang mengintegrasikan teknologi baru seperti perangkat lunak mesin, listrik, dan komputer untuk memungkinkan ekstraksi asam nukleat otomatis dari 96 sampel secara maksimal dalam satu waktu.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2025, 4, 1, '132070104099', 'Kocher Atizu Intest Foceps', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2026, 9, 1, '132080113001', 'Analytical Balance Electric', 'Analytical Balance adalah sebuah instrument laboratorium yang digunakan untuk mengukur massa suatu zat.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2027, 4, 1, '132070104100', 'Kocher Rectraktor', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2028, 9, 1, '132080113006', 'Balance Kodek/Kilogram', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2029, 4, 1, '132070104101', 'Kocherpis Sonde', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2030, 9, 1, '132080113007', 'Fotometer', 'Fotometer adalah alat yang digunakan untuk mengukur pencahayaan atau penyinaran. Seperti penerapan di fotometry industri, suatu "fotometer" adalah kata umum yang meliputi alat-alat untuk mendeteksi intensitas cahaya hamburan, penyerapan, dan fluoresensi', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2031, 4, 1, '132070104102', 'Kom Kompres (Alat Kedokteran Bedah)', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2032, 9, 1, '132080113008', 'Flame Fotometer', 'Flame Photometer dapat digunakan untuk menentukan konsentrasi ion logam tertentu seperti natrium, kalium, litium, kalsium, dan cesium dll', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2033, 4, 1, '132070104103', 'Kom Novocain', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2034, 9, 1, '132080113009', 'Mercury Analyzer (Alat Laboratorium Kimia)', 'alat yang digunakan untuk menganalisis merkuri secara cepat, dengan sensitivitas yang tinggi, dan dapat menentukan jumlah merkuri pada sampel padat, cair, dan gas', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2035, 9, 1, '132080113011', 'Turbidimeter (Alat Laboratorium Kimia)', 'alat yang digunakan untuk mengukur kekeruhan air atau suatu larutan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2036, 9, 1, '132080113012', 'Conductometer', 'alat ukur kualitas air yang digunakan untuk mengetahui kemampuan Daya Hantar Listrik (DHL) atau nilai konduktivitas listrik suatu larutan atau air dalam suatu perairan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2037, 9, 1, '132080113013', 'Khromatographi Kertas', 'Kromatografi kertas merupakan metode analitik yang digunakan untuk memisahkan bahan kimia berwarna, terutama pigmen', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2038, 9, 1, '132080113017', 'Tintometer Kid', 'sebuah alat atau kit yang digunakan dalam laboratorium kimia untuk menganalisis atau mengukur kadar zat tertentu dalam sampel air, misalnya kandungan kimia tertentu, senyawa yang memberikan warna, atau parameter lainnya yang berkaitan dengan warna air', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2039, 9, 1, '132080113019', 'Desicator', 'Desiccator adalah alat laboratorium yang digunakan sebagai wadah untuk menghilangkan kadar air (pengering) pada media analis sekaligus fungsi sterilisasi melalui proses desikasi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2040, 9, 1, '132080113022', 'Buret/Peralatan Titrasi', 'Buret adalah sebuah peralatan gelas laboratorium berbentuk silinder yang memiliki garis ukur dan sumbat keran pada bagian bawahnya', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2041, 4, 1, '132070104110', 'Lawrece Disecting Forceps', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2042, 9, 1, '132080113023', 'Deep Freezer (Alat Laboratorium Kimia)', 'merupakan salah satu tipe frezer dengan suhu mencapai -85⁰C atau dapat disebut deep freezer. Jenis freezer ini biasa digunakan untuk menyimpan bahan medis dan bahan habis pakai lainnya untuk kebutuhan laboratorium', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2043, 4, 1, '132070104111', 'Life Care Pump', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2044, 9, 1, '132080113025', 'U.V. Lamp (Alat Laboratorium Kimia)', 'Lampu UV atau yang juga disebut ultraviolet adalah lampu yang menghasilkan sinar ultraviolet. Lampu ultra violet ini digunakan untuk melakukan sterilisasi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2045, 9, 1, '132080113026', 'Seperate Funnel', 'peralatan laboratorium yang digunakan untuk memisahkan dua macam pelarut yang tidak saling bercampur berdasarkan berat jenisnya melalui proses ekstraksi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2046, 4, 1, '132070104113', 'Manual Amprytation Set', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2047, 9, 1, '132080113029', 'High Performance Liquid Diromatography (HPLG)', 'sebuah teknik analisis kimia yang digunakan untuk memisahkan, mengidentifikasi, dan mengukur kandungan komponen dalam campuran larutan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
