	(2050, 9, 1, '132080113032', 'Electrophorese', 'sebuah teknik yang digunakan untuk memisahkan molekul-molekul berdasarkan ukuran, muatan listrik, atau struktur mereka dalam suatu medium dengan menggunakan medan listrik.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2051, 9, 1, '132080113034', 'Hot Plate (Alat Laboratorium Kimia)', 'sebuah perangkat yang umum digunakan dalam laboratorium kimia untuk memanaskan sampel-sampel secara langsung. Ini adalah sebuah alat pemanas yang memiliki permukaan datar yang terbuat dari logam yang tahan panas seperti aluminium atau baja tahan karat', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2052, 9, 1, '132080113035', 'Micro Burret', 'perangkat laboratorium yang digunakan untuk mengukur volume cairan dengan sangat akurat dalam jumlah kecil, biasanya dalam kisaran mililiter kecil hingga bahkan sebagian kecil dari mililiter (fraksi mililiter)', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
