	(2054, 9, 1, '132080113036', 'Tabung Nessler Pembanding Warna', 'tabung kolorimetri tanpa steker. Untuk penentuan amonia oleh nesslerisasi', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
