	(2057, 9, 1, '132080113042', 'Aqua Analyzer', 'Aqua Analyzer adalah alat yang digunakan untuk menganalisis kualitas air. Alat ini dapat digunakan untuk mengukur berbagai parameter air', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
