	(2060, 9, 1, '132080113050', 'Homogin Mixer', 'alat atau perangkat yang digunakan untuk mencampur, menggiling, atau memadatkan bahan-bahan yang umumnya tidak dapat bercampur secara homogen secara alami, seperti minyak dan air', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2061, 9, 1, '132080113052', 'Experimental Tanning Drum', 'sebuah perangkat atau alat yang digunakan dalam industri penyamakan kulit atau penelitian di bidang tersebut', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
