	(2064, 9, 1, '132080113055', 'Plat Aluminium Untuk Out Set', 'Aluminium adalah logam ringan yang sering digunakan dalam berbagai industri, termasuk laboratorium, karena sifatnya yang tahan korosi, tahan terhadap berbagai zat kimia, dan mudah dibentuk.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2065, 4, 1, '132070104126', 'Miiddledorff Rectraktor', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2066, 9, 1, '132080113057', 'Spec Tonic', 'Spectronic adalah merek terkenal dalam instrumen spektrofotometer yang digunakan di laboratorium. Spektrofotometer adalah perangkat yang digunakan untuk mengukur absorbansi atau transmitansi suatu substansi terhadap cahaya pada berbagai panjang gelombang.\n\nSpectronic atau instrumen spektrofotometer sering digunakan di laboratorium untuk berbagai aplikasi, seperti analisis kimia, biologi, dan penelitian ilmiah lainnya. Alat ini dapat memberikan informasi tentang jumlah substansi tertentu dalam sampel berdasarkan seberapa banyak cahaya yang diserap oleh sampel pada panjang gelombang tertentu.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2067, 4, 1, '132070104127', 'Mikulit', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
