	(2069, 9, 1, '132080113062', 'Filtration System', 'sekumpulan peralatan dan proses yang digunakan untuk memisahkan zat padat dari zat cair atau untuk membersihkan cairan dengan cara memisahkan partikel atau zat terlarut dari cairan tersebut.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2070, 9, 1, '132080113063', 'Water Distiling', 'proses pemurnian air dengan cara memanaskannya hingga mendidih, kemudian mengumpulkan uap air yang dihasilkan, dan akhirnya mengembalikannya ke dalam bentuk cairan dengan proses kondensasi. Proses ini bertujuan untuk memisahkan air dari zat-zat terlarut dan kontaminan lainnya yang mungkin terdapat dalam air.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
