	(2137, 9, 1, '132080114013', 'Blood Bank Incubator', 'perangkat yang digunakan dalam bank darah atau laboratorium medis untuk menyimpan dan mengatur suhu darah dan produk-produk darah lainnya', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
