	(2139, 9, 1, '132080114014', 'Microscope Monoculair', 'jenis mikroskop yang memiliki satu lensa okuler atau lensa yang digunakan untuk melihat objek yang diperbesar', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2140, 9, 1, '132080114015', 'Microscope Binoculair', 'jenis mikroskop yang dilengkapi dengan dua lensa okuler atau lensa yang memungkinkan pengguna menggunakan kedua mata untuk melihat objek yang diperbesar', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2141, 9, 1, '132080114016', 'Automatic Tissue Processor (Alat Laboratorium Patologi)', 'perangkat khusus yang digunakan dalam laboratorium patologi untuk memproses jaringan biologis sebelum mereka diambil contoh mikroskopis', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2142, 9, 1, '132080114017', 'Automatic Microtome Knife Sharpener', 'perangkat khusus yang digunakan dalam laboratorium patologi untuk mengasah pisau mikrotom otomatis', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2143, 4, 1, '132070104179', 'Trapomation Set', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2144, 9, 1, '132080114018', 'Automatic Slide Staining Machine', 'perangkat yang digunakan dalam laboratorium patologi untuk mewarnai dan menyiapkan slide mikroskopis secara otomatis', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2145, 4, 1, '132070104180', 'Tricar Jarum', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2146, 9, 1, '132080114019', 'Automatic Tissue Embedding Appatarus', 'perangkat otomatis yang digunakan dalam laboratorium patologi untuk memasukkan dan membenamkan potongan jaringan biologis ke dalam blok parafin dengan proses yang terkendali.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2147, 9, 1, '132080114021', 'Microslide Warmer', 'perangkat yang digunakan untuk memanaskan atau menjaga suhu slide mikroskopis secara konstan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2148, 4, 1, '132070104182', 'Turner Warwick Gall Ston Fcf', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2149, 9, 1, '132080114022', 'Slide Warmer', 'perangkat yang digunakan dalam laboratorium untuk menjaga suhu slide mikroskopis agar tetap konstan dan optimal selama proses analisis mikroskopis', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2150, 9, 1, '132080114024', 'Rotator', 'merupakan sebuah alat yang direkomendasikan yaitu untuk berbagai macam kebutuhan di laboratorium salah satunya yaitu agar segala proses yang berhubungan dengan homogenasi dapat berjalan dengan baik dan mendapatkan hasil penelitian yang valid dan dapat dipertanggungjawabkan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2151, 4, 1, '132070104184', 'Vaginal Hytrectomy', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2152, 9, 1, '132080114025', 'Shaker (Alat Laboratorium Patologi)', 'alat yang digunakan di laboratorium patologi untuk mengaduk, menggoncang, atau menggerakkan sampel dalam wadah tertentu', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2153, 9, 1, '132080114026', 'Plasma Extrator', 'alat yang digunakan untuk memisahkan plasma dari komponen darah lainnya, seperti sel darah merah atau platelet', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2154, 9, 1, '132080114028', 'Coagulation Meter', 'alat diagnostik medis yang digunakan untuk mengukur kemampuan darah untuk membeku atau proses koagulasi', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2155, 4, 1, '132070104187', 'Vesual Caesar', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2156, 9, 1, '132080114029', 'Platelet Mixer', 'perangkat yang digunakan dalam laboratorium medis untuk mencampur atau menggoyangkan trombosit atau platelet', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2157, 9, 1, '132080114030', 'Blood Pipet Shaker', 'alat laboratorium yang digunakan untuk mencampur sampel darah atau larutan dalam pipet secara otomatis', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2158, 9, 1, '132080114031', 'Billirubinometer', 'alat medis yang digunakan untuk mengukur kadar bilirubin dalam darah', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2159, 9, 1, '132080114032', 'Automatic Dispencer', 'Alat ini digunakan untuk mengotomatisasi proses dispensasi cairan, zat kimia, atau bahan lainnya dalam laboratorium patologi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2160, 9, 1, '132080114034', 'Automatic Pipet Set', 'alat yang digunakan untuk mengukur dan mentransfer volume cairan dengan tingkat presisi yang tinggi', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2161, 9, 1, '132080114035', 'Magnetic Stirer (Alat Laboratorium Patologi)', 'perangkat laboratorium yang menggunakan medan magnet untuk mengaduk cairan di dalam wadah', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2162, 9, 1, '132080114036', 'Hemathologi', 'Alat yang digunakan untuk memeriksa darah lengkap dengan cara menghitung dan mengukur sel darah secara otomatis berdasarkan impedansi aliran listrik atau berkas cahaya terhadap sel-sel yang dilewatkan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2163, 4, 1, '132070105005', 'Embryotomy Set', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2164, 9, 1, '132080114037', 'Hematology Staining Set', 'kumpulan zat-zat kimia dan pewarna yang digunakan dalam laboratorium patologi khususnya dalam proses pewarnaan pada sampel darah atau jaringan untuk tujuan analisis mikroskopis', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2165, 9, 1, '132080114038', 'Rh Typing Box', 'alat atau kit diagnostik yang digunakan dalam laboratorium untuk menentukan golongan darah Rh seseorang', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2166, 9, 1, '132080114039', 'B.U.N. Analyzer', 'alat yang digunakan untuk mengukur Blood Urea Nitrogen (BUN) dalam darah. BUN adalah produk sampingan dari metabolisme protein yang disaring oleh ginjal dan dikeluarkan melalui urine. Pengukuran BUN dapat membantu dokter menilai fungsi ginjal.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2167, 9, 1, '132080114040', 'Enzim Analyzer', 'alat laboratorium yang digunakan untuk mengukur aktivitas enzim dalam sampel biologis', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2168, 9, 1, '132080114042', 'Heating Bloet/Test Tube Heaters', 'alat laboratorium yang digunakan untuk memanaskan tabung uji atau wadah lain yang berisi sampel cair atau bahan kimia', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2169, 9, 1, '132080115001', 'Autosil (Double Distiled And Demineralized', 'Alat untuk mengukur imunology', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2170, 9, 1, '132080115002', 'Centrifuge Electric', 'alat laboratorium yang digunakan untuk memisahkan komponen-komponen dari suatu campuran berdasarkan perbedaan densitasnya dengan memanfaatkan gaya sentrifugal', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2171, 9, 1, '132080115003', 'Cryostat Microtome', 'perangkat yang digunakan dalam laboratorium untuk memotong sampel jaringan biologis menjadi potongan-potongan yang sangat tipis untuk pengamatan mikroskopis', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2172, 4, 1, '132070105013', 'Trubes Stethoscop', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2173, 9, 1, '132080115004', 'Dry Heat Oven Electrophoresis Kit, Consist Of', 'Sebuah kit elektroforesis untuk oven pemanas kering (dry heat oven electrophoresis kit) biasanya terdiri dari beberapa komponen yang digunakan untuk mempersiapkan dan menjalankan proses elektroforesis dalam kondisi suhu kering atau tanpa kelembaban. Beberapa komponen yang mungkin termasuk dalam kit tersebut adalah:\n\nGel Electrophoresis Chamber: Tempat untuk menempatkan gel yang akan digunakan untuk memisahkan sampel-sampel berdasarkan berat molekul atau ukuran fragmen.\n\nPower Supply: Sumber daya untuk memberikan arus listrik pada gel sehingga sampel-sampel dapat bergerak dalam elektroforesis.\n\nElectrodes: Elektroda positif dan negatif yang ditempatkan pada ujung-ujung gel untuk mengarahkan aliran arus listrik.\n\nBuffer Solutions: Larutan buffer yang diperlukan untuk menjaga kondisi pH yang stabil dan kondisi konduktifitas yang diperlukan untuk elektroforesis.\n\nSample Loading System: Sistem untuk memuat sampel-sampel yang akan dipisahkan pada gel.\n\nMarkers or Ladders: Standar berat molekul atau ukuran fragmen DNA atau protein yang digunakan sebagai patokan untuk mengukur ukuran sampel yang dipisahkan.\n\nInstruction Manual: Panduan atau petunjuk penggunaan untuk memandu pengguna dalam mengoperasikan kit dan menjalankan proses elektroforesis dengan oven pemanas kering.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2174, 4, 1, '132070105014', 'Irrigator Stand Single', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2175, 9, 1, '132080115006', 'Power Supply (Alat Laboratorium Immunologi)', 'perangkat atau sumber daya yang memberikan arus listrik untuk menjalankan elektroforesis gel, western blotting, atau teknik-teknik lain yang melibatkan pemisahan, transfer, atau analisis komponen biologis dalam konteks imunologi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2176, 4, 1, '132070105015', 'Irrigator Botlo Complete With Irrigating Tube', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2177, 9, 1, '132080115007', 'Sample Aplicator', 'alat atau perangkat yang digunakan untuk mengaplikasikan atau menempatkan sampel ke dalam wadah atau media tertentu dengan cara yang terkontrol dan akurat', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2178, 9, 1, '132080115009', 'Staining Trays', 'wadah khusus yang digunakan dalam laboratorium untuk proses pewarnaan dalam prosedur histologi atau preparasi sampel biologis untuk pengamatan mikroskopis', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2179, 4, 1, '132070105017', 'Nelaton Chateter Urethal Ruber Catheter 12-14-16-18FR', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2180, 9, 1, '132080115011', 'Non Serrated Forceps', 'jenis forceps (penjepit atau penselip) yang memiliki ujung yang rata atau tanpa serpihan yang tajam di permukaannya', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2181, 9, 1, '132080115012', 'Capillary Tubes', 'tabung tipis yang terbuat dari kaca atau plastik dengan diameter dalam yang sangat kecil', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2182, 9, 1, '132080115013', 'Freezer - 30 Derajat Celcius', 'tipe freezer yang dirancang khusus untuk menjaga suhu dalam ruang penyimpanan tetap pada -30 derajat Celsius', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2183, 9, 1, '132080115014', 'Immunodiffusion System', 'KEGUNAAN Sistem ARCHITECT i1000SR adalah sistem immunoassay yang sepenuhnya otomatis memungkinkan akses acak dan berkelanjutan serta prioritas dan pengolahan uji ulang otomatis. Sistem Architect i 1000SR untuk menganalisa immunologi darah. \n\nteknik laboratorium yang digunakan dalam analisis imunologi untuk mendeteksi atau mengukur konsentrasi antigen atau antibodi dalam sampel biologis', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2184, 9, 1, '132080115017', 'Punch', 'alat yang digunakan untuk mengambil sampel jaringan yang relatif kecil dengan cara memotong dengan presisi yang tinggi.\n\n"Punch" dalam konteks laboratorium immunologi mungkin merujuk pada alat yang disebut "punch biopsy" atau "punch tool."', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2185, 9, 1, '132080115018', 'Holder', 'Holder dalam konteks laboratorium immunologi bisa merujuk pada berbagai alat atau perangkat yang digunakan untuk menahan atau mendukung berbagai komponen yang digunakan dalam prosedur imunologi laboratorium.\n\nBeberapa contoh holder yang digunakan dalam laboratorium immunologi termasuk:\n\nSlide Holder: Digunakan untuk menahan dan memposisikan slide kaca selama prosedur pewarnaan, proses fiksasi, atau analisis mikroskopis pada teknik imunohistokimia atau immunofluorescence.\n\nTube Holder/Rack: Holder untuk menahan tabung-tabung reaksi atau tabung darah selama prosedur pemisahan, sentrifugasi, atau preparasi sampel imunologi lainnya.\n\nPlate Holder: Digunakan untuk menempatkan dan menahan mikroplate selama berbagai tahap proses imunologi yang melibatkan penggunaan mikroplate, seperti ELISA (Enzyme-Linked Immunosorbent Assay) atau teknik serologi lainnya.\n\nMembrane Holder: Alat untuk menahan membran yang digunakan dalam teknik immunoblotting atau Western blotting untuk analisis imunologi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2186, 9, 1, '132080115020', 'Immuno Frames', 'kerangka atau frame yang digunakan dalam berbagai prosedur atau teknik di laboratorium imunologi untuk mendukung atau menahan berbagai komponen yang terlibat dalam proses tersebut.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2187, 9, 1, '132080115026', 'Magnetic Stirles & Bars', 'alat dan komponen yang umum digunakan dalam laboratorium untuk mengaduk larutan cair dengan cara yang tidak konvensional', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2188, 4, 1, '132070105025', 'Indewaling Catheter Infan Feading', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2189, 9, 1, '132080115028', 'Micromixer', 'perangkat mikrofluida yang digunakan untuk mencampurkan dua atau lebih cairan dengan skala mikroskopis', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2190, 9, 1, '132080115032', 'Sealing Tape 72 yl, 50 ul', 'pita atau selotip yang digunakan untuk menutup rapat tabung reaksi atau wadah lainnya dalam konteks laboratorium. "Sealing Tape" untuk wadah atau tabung dengan volume sekitar 72 microliter (μl) atau 50 microliter (μl)', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2191, 9, 1, '132080115033', 'Tape Dispencer', 'alat yang digunakan untuk memudahkan dan mempercepat proses penyegelan (sealing) atau penempelan label pada tabung reaksi, mikroplate, atau wadah lainnya yang digunakan dalam eksperimen atau penelitian di laboratorium', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2192, 9, 1, '132080115034', 'Support Plates', 'jenis pelat atau plat yang digunakan sebagai pendukung atau platform untuk berbagai keperluan di laboratorium', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2193, 4, 1, '132070105029', 'Hiswivery Cufit Bag', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2194, 9, 1, '132080115037', 'Microdituter 25 ul, 50 ul', 'alat yang digunakan untuk menyiapkan sampel dengan volume yang sangat kecil, biasanya dalam rentang 25 μl hingga 50 μl', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2195, 4, 1, '132070105030', 'Intravenous Giving Set', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2196, 9, 1, '132080115039', 'Stand, Diluter/Pipet', 'perangkat atau alat yang dirancang khusus untuk menempatkan dan mendukung pipet-pipet atau alat-alat dilusi dalam laboratorium.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2197, 9, 1, '132080115040', 'Rack, Diluter/Pipet', 'perangkat yang digunakan untuk menahan dan mengorganisir pipet atau alat dilusi dengan rapi di laboratorium', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2198, 9, 1, '132080115041', 'Carrying Case', 'kotak khusus atau wadah yang dirancang untuk membawa dan menyimpan perangkat, alat, atau bahan-bahan yang terkait dengan eksperimen atau prosedur laboratorium di bidang imunologi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2199, 4, 1, '132070105033', 'Kresteler Vaginal Speculum', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2200, 9, 1, '132080115043', 'Centrifuge Carries', 'perangkat khusus yang digunakan untuk membawa atau menahan tabung reaksi atau wadah saat proses sentrifugasi', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2201, 9, 1, '132080115044', 'Carrying/Storage Case', 'wadah atau kotak khusus yang didesain untuk membawa, melindungi, dan menyimpan alat-alat, perangkat, atau bahan-bahan yang digunakan dalam eksperimen atau prosedur laboratorium di bidang imunologi', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2202, 9, 1, '132080115045', 'Shaking Waterbath', 'perangkat laboratorium yang digunakan untuk mempertahankan suhu tertentu dalam air sambil melakukan pengadukan atau getaran lembut pada sampel yang berada di dalamnya. Perangkat ini umumnya digunakan dalam berbagai aplikasi laboratorium, terutama dalam prosedur biokimia, biologi molekuler, atau kultur sel yang memerlukan suhu yang tepat dan pengadukan yang terkontrol', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2203, 4, 1, '132070105036', 'Dilator For Eclamsia Set Of 8 Pcs', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2204, 9, 1, '132080115047', 'Waterbath With Thermostat', 'alat laboratorium yang digunakan untuk menjaga suhu larutan atau sampel pada suhu yang konstan. Alat ini biasanya digunakan dalam laboratorium imunologi untuk menguji reaksi imun, seperti reaksi aglutinasi atau presipitasi.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2205, 9, 1, '132080115048', 'Viewer (Alat Laboratorium Immunologi)', 'laboratorium immunologi mungkin mencakup berbagai perangkat atau instrumen. Dalam konteks laboratorium immunologi, beberapa alat atau perangkat yang dapat disebut sebagai "viewer" melibatkan observasi atau analisis hasil eksperimen atau uji imunologi', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2206, 9, 1, '132080115049', 'Voltmeter', 'alat pengukur yang digunakan untuk mengukur tegangan listrik atau beda potensial antara dua titik dalam suatu rangkaian listrik', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2207, 9, 1, '132080115050', 'Reagent Aplication Device (Micro And Linier Stripper)', 'perangkat yang digunakan untuk mengaplikasikan reagen atau bahan kimia ke permukaan, biasanya pada strip uji diagnostik atau substrat lain untuk uji spesifik', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2208, 4, 1, '132070105040', 'Schroder Vulselum Forceps 13 Cm Stainless', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2209, 9, 1, '132080115051', 'Stripping Cutting Device', 'perangkat yang digunakan untuk melakukan dua fungsi utama: stripping (mengupas) dan cutting (memotong) pada kabel atau kawat elektrikal', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2210, 9, 1, '132080115052', 'Laminating Module With 4 Reels', 'perangkat yang digunakan dalam proses laminasi untuk melapisi dokumen atau bahan lain dengan lapisan pelindung', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2211, 9, 1, '132080115053', 'Staining Set', 'rangkaian bahan dan reagen yang digunakan dalam teknik pewarnaan di laboratorium, terutama dalam bidang biologi, mikrobiologi, histologi, dan cytologi. Teknik pewarnaan melibatkan penggunaan zat pewarna berwarna untuk meningkatkan visibilitas, membedakan struktur, dan memudahkan pemeriksaan mikroskopis pada spesimen biologis.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2212, 9, 1, '132080116002', 'Bunsen Burner & Kelengkapannya', 'alat yang digunakan dalam laboratorium untuk menghasilkan nyala api yang dapat diatur dan stabil untuk berbagai keperluan, seperti pemanasan, sterilisasi, atau reaksi kimia dalam skala kecil', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
