	(2217, 9, 1, '132080116005', 'Mikroskop Monokuler', 'jenis mikroskop yang memiliki satu lensa okuler (ocular) yang digunakan oleh pengamat untuk melihat sampel atau objek yang diperbesar.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2218, 9, 1, '132080116006', 'Mikroskop Binokuler', 'jenis mikroskop yang memiliki dua lensa okuler (ocular), memungkinkan pengamat untuk melihat sampel atau objek yang diperbesar menggunakan kedua mata secara bersamaan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2219, 9, 1, '132080116007', 'Dispencer Adjustable', 'perangkat yang digunakan untuk mengeluarkan volume cairan yang tepat dan diatur sesuai dengan kebutuhan spesifik dalam prosedur laboratorium yang melibatkan sampel darah atau komponen hematologi lainnya', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2220, 4, 1, '132070105049', 'Kielland Obsterical Forceps 38 Cm Stainless Steel', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2221, 9, 1, '132080116008', 'Sentrifus Elektrik', 'perangkat yang digunakan untuk memisahkan komponen-komponen dalam suatu larutan atau suspensi dengan memanfaatkan gaya sentrifugal', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2222, 9, 1, '132080116009', 'Sentrifus Hematokrit', 'jenis khusus dari sentrifuge yang dirancang khusus untuk mengukur hematokrit, yaitu persentase volume sel darah merah dalam darah', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2223, 4, 1, '132070105051', 'Naegle Perferator 27 Cm Stainless Steel', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2224, 9, 1, '132080116010', 'Timer (Alat Laboratorium Hematologi)', 'perangkat yang digunakan untuk mengukur waktu dalam berbagai prosedur laboratorium yang melibatkan penggunaan waktu yang tepat dan presisi', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2225, 9, 1, '132080116011', 'Urinometer (Alat Laboratorium Hematologi)', 'alat yang digunakan untuk mengukur berat jenis atau kerapatan relatif dari urin', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2226, 9, 1, '132080116013', 'Washer And Dryer,Pipet', 'perangkat yang dirancang khusus untuk membersihkan dan mengeringkan pipet laboratorium secara otomatis setelah digunakan dalam percobaan atau analisis', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2227, 4, 1, '132070105054', 'Kymograhy Hydro/Co2', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2228, 9, 1, '132080116014', 'Westergren Apparatus', 'alat yang digunakan untuk melakukan tes Westergren, yang merupakan metode standar untuk mengukur laju sedimentasi eritrosit dalam darah', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2229, 9, 1, '132080116015', 'Tips Pipet Sesuai Ukuran', 'Pipet hematologi adalah alat laboratorium yang digunakan untuk mengukur dan mengalikan volume kecil sampel darah atau larutan lainnya dengan presisi', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2230, 9, 1, '132080117002', 'Mesin Cuci B.W Positif', 'peralatan khusus yang digunakan untuk mencuci film fotografi berbasis gelap (black and white atau hitam putih) setelah proses pengembangan film selesai', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2231, 9, 1, '132080117006', 'Mesin Cetak Color', 'peralatan yang digunakan untuk mencetak film berwarna setelah proses pengembangan selesai', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2232, 9, 1, '132080117007', 'Mesin Vidio Color Analyzer', 'perangkat yang digunakan untuk menganalisis dan mengukur parameter-parameter warna dalam video atau gambar berwarna', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2233, 9, 1, '132080117008', 'Mesin Spesial Optical Effek Printer', 'perangkat khusus yang digunakan dalam industri film untuk menciptakan efek visual khusus dalam produksi film', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2234, 9, 1, '132080117009', 'Chemical Analisa', 'proses yang digunakan untuk menentukan komposisi kimia suatu substansi atau sampel. Analisis kimia dapat dilakukan untuk berbagai tujuan, termasuk identifikasi zat kimia, penentuan konsentrasi komponen tertentu, atau pemantauan reaksi kimia. Metode analisis kimia dapat mencakup berbagai teknik dan instrumen yang digunakan untuk menganalisis berbagai jenis sampel.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2235, 9, 1, '132080117010', 'Fotografic Analisa', 'berbagai metode atau teknik di mana fotografi digunakan sebagai alat untuk mengumpulkan, memproses, atau menganalisis informasi. Beberapa aplikasi umum dari analisis fotografi melibatkan penggunaan gambar atau foto untuk mendapatkan data atau pemahaman tambahan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2236, 9, 1, '132080117012', 'Ultrasonic Cleaner (Alat Laboratorium Film)', 'alat yang digunakan untuk membersihkan objek dengan menggunakan gelombang suara berfrekuensi tinggi', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2237, 4, 1, '132070105063', 'Angkat Agraf Set', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2238, 9, 1, '132080117015', 'Lemari Asam', 'perangkat yang digunakan di laboratorium kimia atau laboratorium film untuk penyimpanan bahan kimia yang bersifat korosif atau berbahaya', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2239, 9, 1, '132080117016', 'B.D. Meter', 'alat laboratorium yang umumnya digunakan dalam industri film untuk mengukur kepadatan optis atau kecerahan (brightness) dari film atau bahan cetak', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2240, 9, 1, '132080117018', 'Alat Pemanas', 'Barang belum spesifik Dalam konteks laboratorium film, alat pemanas bisa merujuk pada berbagai perangkat yang digunakan untuk berbagai tujuan, seperti:\n\nPemanas Air: Digunakan untuk menghangatkan air yang diperlukan dalam proses pengembangan film. Ini bisa berupa pemanas air berteknologi rendah hingga alat yang lebih canggih dengan kontrol suhu yang tepat.\n\nPemanas Ruangan: Dalam ruang pengolahan film atau laboratorium, pemanas ruangan dibutuhkan untuk menjaga suhu tetap stabil. Hal ini penting untuk kondisi yang tepat dalam pengembangan dan pengolahan film.\n\nPemanas Inkubator: Alat ini digunakan untuk mempertahankan suhu konstan dan lingkungan yang terkontrol untuk beberapa tahap dalam proses pembuatan film.\n\nPemanas untuk Pencairan Zat: Dalam beberapa proses pengembangan film atau percetakan film, terkadang diperlukan pemanas khusus untuk mencairkan atau menghangatkan zat tertentu untuk digunakan.\n\nPemanas untuk Pengeringan: Setelah proses pencucian film, penggunaan pemanas atau pengering khusus mungkin diperlukan untuk mengeringkan film secara efisien.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2241, 9, 1, '132080117019', 'Motor Mixer', 'alat yang digunakan dalam laboratorium film untuk mencampur atau mengaduk larutan kimia dengan tepat', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2242, 9, 1, '132080117020', 'Tangki Meter', 'Barang belum spesifik Tangki Pengukur Volume: Alat untuk mengukur jumlah cairan yang digunakan dalam proses pengolahan film secara tepat. Ini bisa berupa tangki ukur yang presisi untuk menambahkan jumlah cairan kimia yang benar untuk setiap batch film.\n\n\n\nTangki Penampung: Alat untuk menampung cairan pengolah film. Dalam proses pengembangan film, berbagai tangki digunakan untuk berbagai tahap pengolahan, mungkin ada yang disebut sebagai "tangki meter" karena mereka berfungsi sebagai wadah untuk mencampur atau mengontrol jumlah cairan yang digunakan dalam proses tersebut.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2243, 9, 1, '132080117021', 'Silver Recovery', 'perangkat yang digunakan untuk mengambil kembali atau mendaur ulang perak dari larutan limbah kimia yang dihasilkan selama proses pengembangan film fotografi', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2244, 4, 1, '132070105069', 'Bongil Cosophagles/Sewart', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
