	(2253, 9, 1, '132080118002', 'Wajan Teflon', 'peralatan memasak yang terbuat dari bahan non-stick yang biasanya digunakan di dapur rumah untuk menggoreng atau memasak makanan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
