	(2256, 9, 1, '132080118004', 'Alat Pembuat Mie', 'alat pembuat mie lebih berkaitan dengan peralatan yang digunakan untuk membuat mie dalam skala yang lebih kecil dan terkendali untuk tujuan pengujian dan eksperimen', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2257, 4, 1, '132070105077', 'Colposcope (Alat Kesehatan Kebidanan Dan Penyakit Kandungan)', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2258, 9, 1, '132080118005', 'Timbangan Kue', 'alat yang digunakan untuk mengukur berat bahan-bahan secara tepat dalam proses pembuatan kue dan produk roti lainnya', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
