	(2273, 9, 1, '132080118017', 'Cold Storage (Alat Laboratorium Makanan)', 'fasilitas atau ruang yang didesain khusus untuk menjaga suhu rendah yang stabil untuk penyimpanan bahan makanan dalam kondisi yang sesuai', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
