	(2284, 4, 1, '132070105096', 'Lead Sit With Recable Electric Mell', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2285, 9, 1, '132080118028', 'Alat Pembuat Keripik', 'perangkat yang digunakan untuk mengeringkan atau mendehidrasi makanan seperti buah, sayuran, atau daging untuk membuat keripik', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2286, 9, 1, '132080118029', 'Alat Pembuat Coklat', 'peralatan yang digunakan untuk membuat atau mempersiapkan sampel coklat dalam skala laboratorium. Meskipun dalam skala yang jauh lebih kecil daripada peralatan industri, beberapa peralatan yang mungkin digunakan di laboratorium makanan untuk mempersiapkan sampel coklat atau mengkaji sifat-sifatnya termasuk:\n\n\n\nHomogenizer: Digunakan untuk mencampur dan homogenisasi berbagai bahan yang digunakan dalam pembuatan sampel coklat untuk memastikan konsistensi dalam komposisi.\n\n\n\nPeralatan pencampur: Untuk mencampur berbagai bahan seperti cokelat bubuk, mentega kakao, gula, atau bahan lain yang digunakan dalam pembuatan sampel coklat.\n\n\n\nPengocok: Untuk proses pencampuran yang lebih intensif atau perubahan tekstur yang diperlukan dalam sampel coklat yang sedang dikaji.\n\n\n\nAlat pendingin: Untuk mengontrol suhu selama proses pencampuran atau pendinginan sampel coklat.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2287, 9, 1, '132080118030', 'Alat Penjernih Air', 'perangkat yang dirancang untuk membersihkan atau memurnikan air dengan cara menghilangkan kontaminan, partikel, atau zat-zat yang tidak diinginkan dari air. Ada beberapa jenis alat penjernih air yang berbeda, di antaranya:\n\nFilter Air: Filter air adalah perangkat yang paling umum digunakan untuk membersihkan air. Mereka menggunakan berbagai metode seperti karbon aktif, membran, atau teknologi lainnya untuk menyaring partikel, kotoran, bakteri, zat kimia, dan bahan pencemar lainnya dari air.\n\nPenyaring UV: Perangkat yang menggunakan sinar ultraviolet (UV) untuk membunuh atau menonaktifkan bakteri, virus, dan mikroorganisme lain dalam air tanpa menggunakan bahan kimia.\n\nDistilasi Air: Proses distilasi melibatkan pemanasan air hingga mendidih, kemudian mengumpulkan uap air yang sudah dimurnikan dan mengembalikannya menjadi bentuk cair. Ini adalah cara efektif untuk menghilangkan banyak kontaminan dari air.\n\nReverse Osmosis (RO): Sistem RO menggunakan tekanan untuk memaksa air melalui membran semi-permeabel yang memisahkan zat terlarut dan partikel dari air, menghasilkan air yang lebih murni.\n\nIon Exchange: Metode ini melibatkan pertukaran ion dalam air untuk menghilangkan ion-ion tertentu yang tidak diinginkan dan menggantinya dengan ion yang diinginkan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2288, 9, 1, '132080118031', 'Loyang Susun', 'rak penyimpanan atau wadah bertingkat yang digunakan untuk menyusun atau menyimpan berbagai alat, peralatan, atau bahan-bahan dalam laboratorium makanan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2289, 4, 1, '132070105100', 'Miswivery Outfitbag', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2290, 9, 1, '132080118033', 'Alat Penggiling Tahu', 'alat yang digunakan dalam pengolahan makanan untuk menggiling atau menghaluskan tahu, mengubahnya menjadi tekstur yang lebih halus atau berbeda sesuai dengan kebutuhan resep', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2291, 4, 1, '132070105101', 'More Lip Protesis', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2292, 9, 1, '132080118035', 'Alat Penutup Botol', 'perangkat yang digunakan untuk menutup botol dengan berbagai jenis penutup atau tutup botol', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2293, 4, 1, '132070105102', 'Nasinal Hytrektomi', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2294, 9, 1, '132080118036', 'Alat Penyangray Kopi', 'perangkat yang digunakan untuk mengubah biji kopi mentah menjadi biji kopi panggang yang siap diseduh', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2295, 4, 1, '132070105103', 'Obstetric Diagnostic Kit', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2296, 9, 1, '132080118037', 'Alat Kukus', 'perangkat yang digunakan untuk memasak makanan dengan cara mengukusnya di atas air mendidih', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2297, 9, 1, '132080118040', 'Alat Pencuci Botol', 'perangkat yang digunakan untuk membersihkan botol atau wadah secara efisien dan higienis', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2298, 9, 1, '132080118041', 'Tangki Penyimpan', 'wadah atau tangki khusus yang digunakan untuk menyimpan bahan-bahan makanan atau sampel dalam skala yang lebih besar', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2299, 4, 1, '132070105106', 'Pemecah Ketuban', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2300, 9, 1, '132080118042', 'Tempering', 'teknik khusus yang digunakan dalam pengolahan cokelat atau lemak tertentu', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2301, 4, 1, '132070105107', 'Pengait Brawn', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2302, 9, 1, '132080119001', 'Analytical Balance (Alat Laboratorium Farmasi)', 'digunakan untuk mengukur jumlah bahan kimia, obat-obatan, atau bahan lainnya dengan sangat akurat', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2303, 4, 1, '132070105108', 'Pengukur Panggul', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2304, 9, 1, '132080119003', 'Top Loading Balance (Alat Laboratorium Farmasi)', 'jenis timbangan yang umum digunakan dalam laboratorium farmasi memiliki kapasitas yang lebih besar dan cenderung digunakan untuk mengukur massa dalam jumlah yang lebih besar dengan tingkat presisi yang baik', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2305, 9, 1, '132080119004', 'Water Distilling Apparatus', 'alat yang digunakan untuk melakukan proses distilasi air', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2306, 4, 1, '132070105110', 'Retractor (Simon Vaginal Retractor)', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2307, 9, 1, '132080119005', 'Tablet Press Machine', 'alat yang digunakan dalam industri farmasi untuk mengompres bahan-bahan obat menjadi tablet atau pil', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2308, 9, 1, '132080119006', 'Strip Packing Machine', 'alat yang digunakan dalam industri farmasi untuk mengemas tablet atau kapsul dalam strip aluminium atau bahan film lainnya yang disegel untuk menjaga kesegaran dan keamanan produk', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2309, 9, 1, '132080119008', 'U V Sterilizer', 'perangkat yang menggunakan sinar ultraviolet (UV) untuk membunuh atau menonaktifkan mikroorganisme seperti bakteri, virus, jamur, dan spora', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2310, 9, 1, '132080119010', 'Mesin Campur Bubuk', 'perangkat yang digunakan untuk mencampur bahan-bahan dalam bentuk serbuk atau bubuk secara homogen', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2311, 9, 1, '132080119013', 'Mesin Pengisi Salep', 'Mesin pengisi salep adalah mesin yang digunakan untuk mengisi salep ke dalam wadah. Mesin ini biasanya digunakan dalam industri farmasi, kosmetik, dan makanan untuk mengisi salep ke dalam berbagai jenis wadah, termasuk tube, jar, dan botol.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2312, 4, 1, '132070105115', 'Stretur Wira', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2313, 9, 1, '132080119017', 'Mesin Penutup Botol', 'perangkat yang digunakan untuk menutup botol obat atau wadah farmasi dengan penutup atau tutup botol secara otomatis atau semi-otomatis', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2314, 4, 1, '132070105116', 'Sutere Episiotomi Set', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2315, 9, 1, '132080119020', 'Mesin Pencuci Wadah/Botol', 'perangkat yang dirancang khusus untuk membersihkan wadah atau botol dengan cara otomatis atau semi-otomatis', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2316, 9, 1, '132080119023', 'Mesin Penghitung Tablet', 'Mesin penghitung tablet adalah mesin yang digunakan untuk menghitung tablet secara otomatis. Mesin ini biasanya digunakan dalam industri farmasi, makanan, dan kosmetik untuk menghitung tablet dengan cepat dan akurat.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2317, 4, 1, '132070105118', 'Toraxis Catheter', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2318, 9, 1, '132080119025', 'Mesin Pembersih Kapsul', 'perangkat yang dirancang untuk membersihkan kapsul atau shell kapsul (cangkang kapsul) sebelum diisi dengan bahan obat atau suplemen tertentu', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2319, 9, 1, '132080119031', 'Mortars & Pastle', 'Mereka digunakan untuk menghancurkan, menggiling, atau menghaluskan bahan-bahan farmasi seperti tablet, kapsul, atau bahan-bahan lainnya menjadi bentuk yang lebih halus atau serbuk', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2320, 9, 1, '132080119033', 'Dial Balance', 'Dial balance merupakan salah satu peralatan laboratorium farmasi yang penting untuk mengukur massa dari bahan-bahan kimia atau obat-obatan dalam jumlah yang sangat kecil dengan tingkat akurasi yang tinggi. Ini digunakan dalam berbagai proses seperti pembuatan formulasi obat, penelitian, atau pengujian laboratorium', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2321, 9, 1, '132080119034', 'Anastistic Balance', 'perangkat yang sangat sensitif dan digunakan untuk menimbang massa bahan dalam jumlah yang sangat kecil dengan tingkat akurasi tinggi. Mereka dapat menimbang sampai pada level submiligram atau bahkan mikrogram, yang penting dalam banyak proses laboratorium farmasi seperti pengukuran bahan kimia untuk persiapan obat-obatan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2322, 9, 1, '132080119036', 'Medicine Can', 'wadah atau tabung yang digunakan untuk menyimpan bahan-bahan farmasi dalam bentuk tertentu seperti serbuk, granul, kapsul, atau tablet', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2323, 4, 1, '132070105123', 'Visical Vaginal Futula Repair Set', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2324, 9, 1, '132080119039', 'Spoon Set', 'digunakan untuk mengukur jumlah yang tepat dari bahan kimia atau bahan obat tertentu. Meskipun biasanya digunakan dalam ukuran kecil, sendok-sendok ini dirancang untuk memberikan presisi dalam mengambil atau mengukur jumlah bahan yang dibutuhkan dalam proses laboratorium.\n\n\n\nMereka terbuat dari bahan yang tidak bereaksi dengan bahan kimia yang diukur dan dapat membersihkan sendiri dengan mudah untuk mencegah kontaminasi silang antar bahan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2325, 9, 1, '132080119040', 'Wrapping Machine', 'peralatan yang digunakan untuk membungkus atau mengemas produk farmasi, seperti tablet, kapsul, atau bentuk dosis lainnya, dalam kemasan yang sesuai', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2326, 9, 1, '132080119043', 'Steril Bottle Witt, Cup', 'botol steril dengan penutup atau cup steril adalah wadah yang telah di-sterilisasi untuk digunakan dalam penyimpanan bahan-bahan farmasi yang memerlukan lingkungan steril', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2327, 9, 1, '132080119044', 'Droping Bottle', 'alat laboratorium yang digunakan untuk meneteskan atau mengatur aliran cairan dengan kontrol yang sangat tepat', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2328, 9, 1, '132080119045', 'Graduated Cylinder', 'alat laboratorium yang digunakan untuk mengukur volume cairan secara tepat', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2329, 4, 1, '132070105128', 'Nalfolder', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2330, 9, 1, '132080119046', 'Presceription Botle', 'wadah yang digunakan untuk menyimpan obat-obatan yang telah diresepkan oleh dokter kepada pasien. Ini adalah wadah yang umumnya diberikan kepada pasien di apotek untuk menyimpan obat-obatan yang diresepkan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2331, 9, 1, '132080119047', 'Medicine Cup', 'wadah berbentuk cangkir atau cup kecil yang digunakan untuk mengukur atau memberikan dosis obat dalam bentuk cair atau suspensi kepada pasien', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2332, 4, 1, '132070105130', 'Cardio Aid', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2333, 9, 1, '132080119048', 'Spatula', 'alat kecil yang digunakan untuk mengambil, mengaduk, atau mentransfer bahan kimia dalam bentuk serbuk atau bubuk secara presisi. Mereka biasanya terbuat dari logam atau plastik dan memiliki ujung yang datar dan lebar untuk memudahkan pengambilan bahan dari wadah dan pemindahannya ke tempat lain.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2334, 4, 1, '132070105131', 'Tabung Periksa Uric', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2335, 9, 1, '132080119049', 'Ointment Plate', 'Ointment Slab adalah permukaan datar yang digunakan untuk menggiling dan mencampur bahan-bahan yang digunakan dalam pembuatan salep atau krim.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2336, 4, 1, '132070105132', 'Koher Tang', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2337, 9, 1, '132080119054', 'Bottle Washer', 'perangkat yang digunakan dalam laboratorium farmasi untuk membersihkan botol, wadah, atau alat-alat lain yang digunakan dalam proses produksi obat', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2338, 9, 1, '132080119057', 'Capsule Filling Machine', 'alat yang digunakan dalam laboratorium farmasi untuk mengisi kapsul kosong dengan bahan aktif atau formula obat tertentu', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2339, 9, 1, '132080119059', 'Capsule Container', 'wadah atau tempat penyimpanan khusus yang dirancang untuk menyimpan kapsul obat dalam jumlah tertentu', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2340, 9, 1, '132080119060', 'Power Mixer', 'alat yang digunakan dalam laboratorium farmasi untuk mencampur bahan-bahan obat dengan menggunakan tenaga listrik atau mekanik', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2341, 4, 1, '132070106003', 'Throat Diagnosis Set', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2342, 9, 1, '132080119061', 'Stirer', 'peralatan laboratorium yang digunakan untuk mencampur atau mengaduk bahan-bahan dalam larutan atau cairan. Beberapa jenis stirrer yang umum digunakan meliputi:\n\nPengaduk Magnetik: Ini adalah salah satu jenis yang paling umum digunakan di laboratorium. Terdiri dari batang pengaduk yang ditempatkan dalam wadah, dan gerakannya diatur oleh medan magnet yang dihasilkan oleh alat pengaduk magnetik. Kecepatan dan kekuatan pengadukan dapat diatur sesuai kebutuhan.\n\nPengaduk Berputar: Jenis pengaduk ini menggunakan gerakan putaran untuk mencampurkan larutan atau suspensi. Mereka bisa berupa pengaduk berputar mekanis yang menggunakan motor untuk menghasilkan gerakan rotasi atau pengaduk berputar manual.\n\nPengaduk Berkecepatan Variabel: Alat ini memungkinkan pengaturan kecepatan pengadukan yang dapat diubah-ubah sesuai kebutuhan. Mereka seringkali dilengkapi dengan kontrol kecepatan yang dapat diatur untuk mengakomodasi berbagai jenis bahan dan kebutuhan pencampuran yang berbeda.\n\nPengaduk Berdaya Tinggi (High-Power Stirrer): Digunakan untuk mencampur bahan-bahan dengan viskositas tinggi atau ketebalan yang lebih besar. Mereka memiliki tenaga dan kekuatan yang lebih besar untuk menangani campuran yang sulit.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2343, 9, 1, '132080119062', 'Tablet Machine', 'alat penting di laboratorium farmasi yang digunakan untuk memproduksi tablet obat dengan dosis yang tepat dan konsisten', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2344, 9, 1, '132080119063', 'Pump Fiter', 'alat yang digunakan untuk menyaring larutan atau suspensi dengan menggunakan prinsip pompa untuk mendorong cairan melalui filter yang dapat menahan partikel-partikel yang lebih besar', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2345, 10, 1, '132080120001', 'Adaptor', 'Barang belum spesifik Adaptor dalam konteks laboratorium fisika bisa merujuk pada berbagai jenis perangkat yang digunakan untuk menghubungkan atau mengubah konfigurasi antara komponen alat atau instrumen fisika. Adaptor ini dapat berupa:\n\n\n\nAdaptor Listrik: Digunakan untuk mengubah jenis atau konfigurasi sambungan listrik agar sesuai dengan kebutuhan alat atau instrumen fisika tertentu.\n\n\n\nAdaptor Sambungan: Berfungsi untuk menghubungkan antara berbagai komponen atau bagian dari alat fisika. Misalnya, adaptor sambungan bisa digunakan untuk menghubungkan dua tabung dengan ukuran atau jenis yang berbeda.\n\n\n\nAdaptor untuk Pengukuran: Dapat merujuk pada alat atau perangkat yang memungkinkan perubahan format atau pengukuran dalam eksperimen fisika. Contohnya adalah adaptor untuk pengukuran sensor atau probe yang berbeda.\n\n\n\nAdaptor untuk Perlengkapan atau Aksesori: Misalnya, adaptor yang memungkinkan peralatan tambahan seperti kamera atau sensor lainnya untuk terhubung dengan alat fisika tertentu untuk tujuan pengukuran atau pengamatan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2346, 10, 1, '132080120002', 'Signal Generator (Alat Laboratorium Fisika)', 'alat yang umum digunakan dalam laboratorium fisika untuk menghasilkan sinyal listrik yang berbeda, seperti gelombang sinusoidal, gelombang segitiga, gelombang persegi, atau sinyal lainnya dengan frekuensi, amplitudo, dan bentuk gelombang tertentu', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2347, 10, 1, '132080120003', 'VU Meter', 'VU meter, singkatan dari Volume Unit meter, adalah alat yang digunakan untuk mengukur level atau intensitas suara dalam sistem audio', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2348, 10, 1, '132080120004', 'Kaca Plan Paralel', 'sebuah komponen optik yang terdiri dari dua permukaan datar kaca yang paralel satu sama lain Dalam konteks laboratorium fisika, kaca plan paralel sering digunakan sebagai bagian dari eksperimen optik untuk mengamati dan mempelajari interferensi cahaya', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2349, 10, 1, '132080120005', 'Rangkaian Hambatan Jembatan Seri', 'salah satu dari banyak jenis rangkaian yang digunakan dalam percobaan laboratorium fisika, terutama dalam pengukuran hambatan atau resistansi suatu komponen atau bahan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2350, 10, 1, '132080120006', 'Rangkaian Hukum', 'Rangkaian hukum, atau biasa disebut juga sebagai rangkaian hukum Kirchhoff, adalah aturan dasar dalam teori rangkaian listrik yang ditemukan oleh Gustav Kirchhoff.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2351, 10, 1, '132080120007', 'Hambatan Jembatan Wheatstome', 'alat yang digunakan dalam laboratorium fisika untuk mengukur resistansi atau hambatan suatu resistor yang tidak diketahui. Ini berdasarkan pada prinsip jembatan Wheatstone yang memanfaatkan pembagian tegangan dalam rangkaian jembatan yang seimbang', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2352, 10, 1, '132080120008', 'Garpu Tala', 'salah satu alat yang digunakan untuk mempelajari prinsip-prinsip getaran, gelombang, dan akustik', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2353, 4, 1, '132070106014', 'Pharyngoscope', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2354, 10, 1, '132080120009', 'Timer Switch', 'perangkat yang digunakan untuk mengatur waktu dalam proses percobaan atau eksperimen di laboratorium. Perangkat ini memungkinkan pengguna untuk mengatur durasi waktu tertentu untuk menjalankan atau menghentikan suatu percobaan secara otomatis.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2355, 10, 1, '132080120010', 'Magnet U', 'Magnet ini biasanya terbuat dari material magnet permanen, seperti magnet neodimium (NdFeB). Bentuk "U" pada magnet ini memiliki dua kutub magnetik yang mendekati satu sama lain di bagian ujung "U", dan di sisi lain, terdapat celah terbuka.\n\n\n\nMagnet U sering digunakan dalam berbagai eksperimen dan demonstrasi di laboratorium fisika, khususnya dalam konteks magnetisme.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2356, 4, 1, '132070106016', 'Nasofaringoscope', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2357, 10, 1, '132080120011', 'Kaca Prisma', 'alat optik yang terbuat dari kaca atau bahan transparan lainnya yang memiliki bentuk tiga sisi segitiga dan sering digunakan dalam laboratorium fisika untuk mempelajari cahaya dan optika. Prisma ini memungkinkan pemisahan cahaya menjadi spektrum warna dan berbagai percobaan optik lainnya', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2358, 10, 1, '132080120012', 'Lensa Cembung', 'lensa optik yang bagian tengahnya lebih tebal daripada tepinya, yang memiliki kemampuan untuk mengumpulkan cahaya dan memfokuskan sinar-sinar cahaya yang melewatinya', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2359, 4, 1, '132070106018', 'Minor Electro Surgery', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2360, 10, 1, '132080120013', 'Bangku Optik', 'alat atau setup yang terdiri dari berbagai komponen optik yang dirangkai secara sistematis. Bangku optik ini biasanya digunakan dalam laboratorium fisika untuk melakukan serangkaian eksperimen optik yang melibatkan berbagai jenis lensa, prisma, cermin, atau alat optik lainnya', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2361, 10, 1, '132080120014', 'Pipa Resonansi', 'alat yang digunakan dalam laboratorium fisika untuk mempelajari fenomena resonansi suara dalam pipa tertutup atau terbuka. Ini dapat terdiri dari tabung yang bisa diisi dengan air atau udara, dan sering digunakan dalam percobaan untuk memahami sifat gelombang suara', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2362, 10, 1, '132080120015', 'Audio Generator', 'alat yang digunakan dalam laboratorium fisika untuk menghasilkan sinyal audio dengan frekuensi yang dapat diatur. Ini memungkinkan pengguna untuk membuat sinyal suara dari rentang frekuensi yang bervariasi sesuai kebutuhan eksperimen', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2363, 10, 1, '132080120016', 'Battery Changer', 'perangkat yang digunakan untuk mengisi ulang daya pada baterai yang telah terpakai. Namun, dalam konteks laboratorium fisika, istilah "battery changer" mungkin mengacu pada alat yang digunakan untuk mengganti baterai pada perangkat atau alat dalam lingkungan laboratorium', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2364, 4, 1, '132070106022', 'Atrum Sonden', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2365, 10, 1, '132080120017', 'Power Supply (Alat Laboratorium Fisika)', 'perangkat yang menyediakan sumber daya listrik untuk menjalankan atau mengoperasikan berbagai peralatan dan instrumen di laboratorium. Perangkat ini umumnya dirancang untuk menyediakan tegangan listrik yang stabil dan dapat diatur sesuai dengan kebutuhan eksperimen atau pengujian yang dilakukan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2366, 10, 1, '132080121001', 'Carbatec Portable', 'Alat yang digunakan untuk mengebor sejenis kayu', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2367, 4, 1, '132070106024', 'Othoscope Maching Haline', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2368, 10, 1, '132080121002', 'Gas Analysis Apparatus (Alat Laboratorium Hidrodinamika)', 'digunakan untuk menganalisis komposisi gas yang terlarut dalam air atau dalam proses reaksi yang melibatkan gas-gas tertentu. Ini dapat melibatkan pengukuran berbagai parameter gas seperti oksigen terlarut, nitrogen, karbon dioksida, dan gas-gas lainnya dalam air atau fluida yang diamati', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2369, 10, 1, '132080121007', 'Bench Scale/Biooxidation System', 'Alat yang digunakan untuk menimbang benda dengan kapasitas tertentu dengan bentuk seperti bangku yang memiliki plat untuk meletakan benda dan memiliki tiang yang terseambung dengan plat untuk menghubungkan timbangan dengan indikator', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2370, 4, 1, '132070106026', 'Beitel Cekung/Datar', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2371, 10, 1, '132080121011', 'Martindale Wear And Abration Tester (Alat Laboratorium Hidrodinam', 'alat ini biasanya digunakan dalam industri tekstil atau material untuk mengukur keausan dan ketahanan abrasi pada berbagai jenis bahan tekstil, kain, atau bahan lainnya', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2372, 10, 1, '132080122007', 'Bench Scale/Bioxidation System', 'Alat yang digunakan dalam skala laboratorium, biasanya ditempatkan di atas meja (bench) atau permukaan kerja yang sepadan. Peralatan ini dirancang untuk digunakan dalam percobaan, penelitian, atau pengujian di laboratorium dengan volume atau ukuran yang relatif kecil, sesuai dengan skala laboratorium.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2373, 4, 1, '132070106028', 'Bond Curetage', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2374, 10, 1, '132080122010', 'Thermohigrograph (Alat Laboratorium Klimatologi)', 'alat yang digunakan dalam laboratorium klimatologi untuk merekam data suhu dan kelembaban udara secara kontinu dan dalam jangka waktu tertentu', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2375, 10, 1, '132080122016', 'Spectrophotometer', 'alat ini digunakan untuk mengukur seberapa banyak cahaya yang diserap atau dipantulkan oleh sampel berdasarkan panjang gelombang tertentu.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2376, 4, 1, '132070106030', 'Bugie Sinus', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2377, 10, 1, '132080122018', 'Zero Air Supply', 'sistem yang menghasilkan udara tanpa kontaminan tertentu, seperti hidrokarbon, oksigen, nitrogen oksida, sulfur dioksida, dan partikel lainnya. Sistem ini digunakan untuk menyediakan udara murni dan bebas dari kontaminasi untuk keperluan analisis yang memerlukan udara tanpa zat-zat tersebut', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2378, 4, 1, '132070106031', 'Cold Light Sumuk', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2379, 10, 1, '132080122019', 'Humidity Chamber', 'alat yang digunakan dalam laboratorium klimatologi untuk mensimulasikan dan mengontrol kondisi kelembaban udara tertentu di dalam ruang tertutup. Alat ini memungkinkan peneliti untuk mempelajari efek kelembaban pada berbagai sampel atau bahan dalam kondisi lingkungan yang dikendalikan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2380, 4, 1, '132070106032', 'Cold Well Luc', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2381, 10, 1, '132080123004', 'Fual Pump', 'Fuel pump adalah suatu komponen dalam sistem bahan bakar kendaraan yang berfungsi untuk memompa bahan bakar dari tangki ke mesin.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2382, 10, 1, '132080123009', 'Grinding Machine', 'Mesin penggilingan digunakan untuk menghaluskan atau mengurangi ukuran suatu benda kerja dengan menghapus material dari permukaannya menggunakan roda gerinda yang abrasif.\n\n\n\nDalam konteks proses peleburan logam di laboratorium, mesin-mesin utama yang terlibat adalah tungku peleburan dan peralatan lain yang terkait dengan memanaskan dan meleburkan logam', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2383, 4, 1, '132070106034', 'Canule Falif Tang', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2384, 10, 1, '132080123011', 'Work Bench (Alat Laboratorium Proses Peleburan)', 'sebuah meja yang digunakan di laboratorium atau workshop untuk menunjang berbagai kegiatan, termasuk proses peleburan logam', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2385, 4, 1, '132070106035', 'Canule Mulut', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2386, 10, 1, '132080123015', 'Hand Grinding Machine', 'peralatan yang digunakan untuk penggilingan manual pada material dengan menggunakan roda gerinda. Mesin ini memungkinkan operator untuk menghapus material dari permukaan benda kerja dengan presisi tertentu.\n\n\n\nDalam konteks laboratorium proses peleburan logam, mesin penggilingan tangan mungkin digunakan setelah proses peleburan untuk melakukan penghalusan atau pengubahan bentuk spesifik dari logam yang telah dilebur. Penggunaannya bisa untuk menghaluskan permukaan logam yang kasar atau untuk memberikan bentuk yang diinginkan pada logam yang masih dalam bentuk mentah', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2387, 4, 1, '132070106036', 'Canule Sachen Hidung', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2388, 10, 1, '132080123019', 'Digital Ce Meter', 'Alat ukur kandungan Carbon pada kandungan leburan besi', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2389, 4, 1, '132070106037', 'Canule Sachen Mulut', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2390, 10, 1, '132080123020', 'Steel Analysis Digital', 'Alat analisis logam digital (digital steel analysis tool) dapat merujuk pada berbagai perangkat atau peralatan yang digunakan untuk menganalisis sifat-sifat logam, khususnya baja, dengan menggunakan teknologi digital. Peralatan semacam ini seringkali digunakan dalam proses peleburan logam atau dalam laboratorium yang mempelajari sifat-sifat logam, termasuk baja', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2391, 4, 1, '132070106038', 'Canule Telinga', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2392, 10, 1, '132080124004', 'Central Controler', 'sistem pengendalian sentral yang mengatur atau mengelola berbagai fungsi dalam laboratorium tersebut. Laboratorium pasir bisa merujuk pada fasilitas pengujian atau riset yang berkaitan dengan analisis atau pengolahan pasir, misalnya dalam industri konstruksi, metalurgi, atau industri lainnya yang menggunakan pasir dalam proses mereka.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2393, 10, 1, '132080124011', 'Agitator', 'perangkat atau mesin yang digunakan untuk mencampur atau mengaduk pasir dalam skala laboratorium. Alat ini membantu dalam proses pencampuran bahan-bahan yang terkandung dalam pasir atau proses homogenisasi campuran. \nDalam konteks laboratorium, agitator pasir bisa berupa:\n\n\n\nMixer atau Pengaduk: Digunakan untuk mencampur pasir dengan bahan lainnya, seperti air, bahan kimia, atau bahan tambahan lainnya yang digunakan dalam pengujian atau proses laboratorium.\n\n\n\nPengocok atau Pemisah: Agitator juga dapat digunakan untuk pemisahan partikel dalam pasir. Ini dapat melibatkan proses pengayakan, pemisahan ukuran butir tertentu, atau proses penyaringan untuk memisahkan komponen-komponen tertentu dari pasir.\n\n\n\nPengaduk untuk Reaksi Kimia: Dalam laboratorium, agitator bisa juga digunakan untuk proses reaksi kimia yang melibatkan pasir atau bahan lain. Ini membantu dalam mencampurkan bahan kimia dengan pasir secara merata selama reaksi berlangsung', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2394, 4, 1, '132070106040', 'Cerumen Haak', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2395, 10, 1, '132080124021', 'Labo Mixer', 'perangkat atau mesin pengaduk yang umumnya digunakan dalam laboratorium untuk mencampur bahan-bahan dalam skala kecil atau sedang. Dalam konteks laboratorium pasir, Labo Mixer dapat digunakan untuk mencampur pasir dengan berbagai bahan lainnya yang terlibat dalam percobaan atau analisis tertentu.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2396, 4, 1, '132070106041', 'Comunicidal Protex', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2397, 10, 1, '132080125001', 'Sand Preparation', '"Sand Preparation" dalam konteks laboratorium proses pembuatan cekatan bisa merujuk pada serangkaian alat dan peralatan yang digunakan untuk menyiapkan pasir yang akan digunakan dalam proses pembuatan cekatan (moulding).\nIni dapat meliputi beberapa peralatan:\n\nSand Muller: Peralatan yang mengaduk dan mencampurkan pasir dengan bahan-bahan lainnya seperti agen pengikat atau bahan pengikat lainnya untuk membentuk campuran yang kohesif dan homogen.\n\nSand Sieve: Peralatan yang digunakan untuk menyaring atau memilah pasir agar memiliki ukuran butiran yang konsisten sebelum digunakan dalam proses pembuatan cekatan.\n\nMoisture Content Tester: Alat yang digunakan untuk mengukur kadar kelembaban pasir, yang penting untuk memastikan kekohesifan dan kualitas campuran pasir.\n\nEquipment for Sand Testing: Berbagai alat uji yang digunakan untuk memeriksa sifat-sifat pasir seperti kekuatan tekan, kekuatan tarik, kepadatan, kelembaban, ukuran butir, dan sifat-sifat lain yang relevan dengan proses pembuatan cekatan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2398, 4, 1, '132070106042', 'Corong Telinga', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2399, 10, 1, '132080125008', 'Pneumatic', 'penggunaan udara terkompresi untuk mengoperasikan peralatan atau mesin tertentu yang digunakan dalam proses tersebut. Pneumatik merupakan sistem yang menggunakan udara terkompresi untuk mengontrol gerakan atau aksi dalam peralatan atau mesin, seringkali melalui penggunaan silinder udara dan katup udara.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2400, 4, 1, '132070106043', 'Corpus Alienum Hak', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2401, 10, 1, '132080126002', 'Universal Milling Machine (Alat Laboratorium Proses Pembuatan Pola)', 'jenis mesin penggilingan yang serbaguna dan dapat digunakan untuk berbagai aplikasi penggilingan di industri manufaktur. Dalam konteks laboratorium proses pembuatan pola, mesin ini dapat digunakan untuk membuat pola atau cetakan dengan presisi tinggi untuk digunakan dalam proses pembuatan cekatan.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2402, 4, 1, '132070106044', 'Cerumen Hak', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2403, 10, 1, '132080126003', 'Combined Planning Machine', 'mesin yang serbaguna dan dapat digunakan dalam pembuatan pola di laboratorium atau workshop. Mesin ini biasanya memiliki berbagai fungsi yang mencakup perencanaan, pemotongan, dan pembentukan benda kerja dalam proses pembuatan pola.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2404, 4, 1, '132070106045', 'Desektor', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2405, 10, 1, '132080126005', 'Portable Router', 'alat yang sering digunakan dalam pembuatan pola atau cetakan di laboratorium atau workshop. Alat ini digunakan untuk memotong, mengukir, atau membentuk material seperti kayu, plastik, atau bahan komposit lainnya untuk menciptakan pola atau cetakan yang diperlukan dalam proses pembuatan cekatan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2406, 4, 1, '132070106046', 'Desopagus Cape', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2407, 10, 1, '132080126008', 'Abrasive Band Machines', 'peralatan yang digunakan dalam proses pembuatan pola di laboratorium. Mesin ini menggunakan pita abrasif yang berputar untuk melakukan pengikisan, pemotongan, atau penghalusan pada material seperti kayu, logam, atau plastik yang digunakan untuk pembuatan pola atau cetakan', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2408, 10, 1, '132080126009', 'Movable Dust Colector', 'perangkat yang sering digunakan di laboratorium pembuatan pola untuk mengumpulkan debu dan partikel kecil selama proses pembuatan cetakan atau pola. Mesin ini bertujuan untuk menjaga kebersihan lingkungan kerja dengan menangkap debu dan partikel yang dihasilkan oleh alat-alat seperti mesin pemotong, penggiling, atau alat lain yang menghasilkan debu saat memproses material seperti kayu, logam, atau plastik', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2409, 10, 1, '132080126011', 'Tools Grinding', 'digunakan untuk mengasah atau memoles berbagai jenis perkakas atau alat-alat yang digunakan dalam pembuatan pola atau cetakan. Ini mencakup alat-alat seperti mata bor, pahat, pisau, atau perkakas lain yang digunakan dalam proses pembentukan atau pengolahan material seperti kayu, logam, atau plastik', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2410, 4, 1, '132070106049', 'E N G', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2411, 10, 1, '132080126013', 'Drawing Equipment', 'beragam peralatan yang digunakan untuk membuat gambar, sketsa, atau desain pola yang akan digunakan dalam pembuatan cetakan atau pola. Ini termasuk alat-alat seperti:\n\n\n\nPensil: Berbagai jenis pensil dengan derajat kekerasan yang berbeda untuk membuat sketsa atau gambar awal.\n\n\n\nPenggaris: Digunakan untuk membuat garis lurus atau membantu dalam mengukur dan membingkai sketsa.\n\n\n\nMeteran: Untuk mengukur dimensi yang tepat dari pola atau cetakan yang akan dibuat.\n\n\n\nProtractor atau Busur: Untuk mengukur sudut yang tepat pada desain pola.\n\n\n\nCompasses: Untuk menggambar lingkaran atau lengkungan dengan diameter yang tepat.\n\n\n\nStensil: Untuk membuat pola yang berulang dengan presisi.\n\n\n\nSoftware Desain: Peralatan modern dapat mencakup perangkat lunak desain komputer seperti CAD (Computer-Aided Design) untuk membuat desain pola secara digital.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2412, 4, 1, '132070106050', 'Ear Curretes', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2413, 10, 1, '132080126016', 'Wood Lathe Machine', 'perangkat yang digunakan untuk membentuk kayu dengan memutar benda kerja kayu pada sumbu pusatnya', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2414, 10, 1, '132080126017', 'Hand Drill', 'alat yang digunakan untuk melakukan pengeboran pada berbagai material. hand drill sering digunakan untuk membuat lubang atau pengeboran pada pola atau cetakan dari bahan seperti kayu, plastik, atau logam.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2415, 4, 1, '132070106052', 'Ear Hook Jensen', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2416, 10, 1, '132080126018', 'Electric Band Saw', 'alat yang digunakan untuk memotong bahan-bahan seperti kayu, logam, atau plastik dalam proses pembuatan pola', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2417, 4, 1, '132070106053', 'Ear Spoon', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2418, 10, 1, '132080126019', 'Grinder Band Saw', 'Grinder adalah alat listrik yang digunakan untuk menggerinda atau menghaluskan permukaan suatu benda. Grinder umumnya dilengkapi dengan roda gerinda yang dapat memotong atau mengasah material seperti logam, kayu, atau plastik. Jenis grinder yang umum digunakan termasuk angle grinder (gerinda sudut) dan bench grinder (gerinda meja). Band saw adalah jenis gergaji yang menggunakan pita baja kontinyu dengan gigi-gigi yang memotong material. Gergaji pita ini dapat digunakan untuk memotong berbagai jenis material, termasuk logam, kayu, dan plastik. Band saw sering digunakan dalam pekerjaan kayu, logam, dan bengkel.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2419, 4, 1, '132070106054', 'Ear Syring Kaca', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2420, 10, 1, '132080127005', 'Polisishing Machine', 'alat yang digunakan untuk mempersiapkan sampel logam agar siap untuk pengamatan di bawah mikroskop metalografi. Proses polishing (penggosokan) pada sampel logam sangat penting untuk menghilangkan goresan, cacat permukaan, dan ketidaksempurnaan lainnya serta untuk menghasilkan permukaan yang halus dan reflektif', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2421, 4, 1, '132070106055', 'Echeel Cair (Englau) (PPM)', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2422, 10, 1, '132080127007', 'Electro Analysis App', 'berbagai perangkat yang digunakan untuk analisis logam menggunakan metode elektrokimia atau elektroanalisis. Metode ini sering digunakan untuk mempelajari sifat-sifat kimia dan struktur permukaan logam.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2423, 4, 1, '132070106056', 'Elevator-Langenbeck', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2424, 10, 1, '132080127010', 'Metallspectroskop', 'Spektroskopi logam adalah suatu metode analisis yang digunakan untuk memeriksa dan menganalisis spektrum cahaya yang dipancarkan atau diserap oleh suatu sampel logam', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2425, 4, 1, '132070106057', 'Endaural Curretes', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2426, 10, 1, '132080127016', 'Portable Ultrasonic Non Destruktive Digital (Pundit)', 'perangkat yang digunakan untuk pengujian non-destruktif dengan menggunakan gelombang ultrasonik. Alat ini sering digunakan dalam berbagai industri, termasuk industri material dan konstruksi', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2427, 10, 1, '132080127017', 'Flashlight Stroboscope', 'alat yang digunakan untuk memvisualisasikan gerakan atau kejadian berulang yang cepat dengan menciptakan efek stroboskopik. Dalam konteks metalografi, alat ini dapat digunakan untuk memeriksa dan mengamati struktur logam atau komponen yang bergerak atau bergetar dengan kecepatan tinggi', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2428, 4, 1, '132070106059', 'Entradmen Mint U 402/Yasju (PPM)', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2429, 10, 1, '132080127019', 'Carbon Sulfur', 'alat yang digunakan untuk mengukur kandungan karbon dan sulfur dalam sampel logam atau material lainnya. Dalam konteks metalografi dan analisis material, alat ini penting karena kandungan karbon dan sulfur dapat memengaruhi sifat-sifat material, seperti kekuatan, kekerasan, atau sifat korosi', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2430, 4, 1, '132070106060', 'Entreatmen Unit Pretty Model (Daichi)', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2431, 10, 1, '132080127020', 'Drumeter', 'Durometer adalah sebuah alat yang digunakan untuk mengukur tingkat kekerasan suatu bahan, khususnya kekerasan permukaan elastomer atau bahan karet. Pengukuran kekerasan ini dapat memberikan indikasi tentang sifat elastis dan deformabilitas bahan tersebut.', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2432, 4, 1, '132070106061', 'Excophagual Disposible Stetescope', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2433, 10, 1, '132080127025', 'Stereo Microskop', 'Alat ini memungkinkan pengamatan detail dari sampel logam pada tingkat pembesaran rendah hingga menengah. Dalam laboratorium metalografi, stereo mikroskop membantu dalam memeriksa struktur kristal, ukuran butir, pola distribusi fasa, dan cacat yang mungkin ada dalam bahan logam', NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2434, 4, 1, '132070106062', 'Galibrator', NULL, NULL, NULL, '2026-04-30 03:15:51', '2026-04-30 03:15:51'),
	(2435, 10, 1, '132080128001', 'Welding Rectifier (Alat Laboratorium Proses Pengelasan)', 'Welding rectifier adalah salah satu perangkat yang digunakan dalam proses pengelasan. Ini adalah jenis sumber daya listrik yang mengubah arus bolak-balik (AC) dari sumber listrik menjadi arus searah (DC) yang digunakan untuk proses pengelasan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2436, 4, 1, '132070106063', 'Haak Hidung', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2437, 10, 1, '132080128002', 'Welding Tranformat', 'perangkat yang digunakan dalam proses pengelasan untuk mengubah tegangan listrik dari sumber daya menjadi tingkat tegangan yang lebih sesuai untuk pengelasan. Ini bekerja pada prinsip transformasi elektromagnetik untuk mengubah tegangan listrik menjadi tingkat yang cocok untuk proses pengelasan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2438, 4, 1, '132070106064', 'Hand Dail Foat With 6 Pers Bumr 220 Volt', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2439, 10, 1, '132080128003', 'TIG Welding Machine', 'perangkat yang digunakan untuk melakukan proses pengelasan TIG. Proses TIG welding menggunakan busur listrik antara elektroda non-permanen dari tungsten dan logam yang akan disambungkan, sementara gas inert seperti argon atau helium digunakan untuk melindungi busur dan zona pengelasan dari kontaminasi', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2440, 10, 1, '132080128004', 'NIG/MAG Welding Machine', 'perangkat yang digunakan dalam proses pengelasan MIG/MAG. Kedua proses ini melibatkan penggunaan busur listrik yang terbentuk antara kawat pengisi logam yang terus menerus disuplai melalui pistol pengelasan dan logam yang akan disambungkan. Gas pelindung digunakan untuk melindungi busur dan zona pengelasan dari kontaminasi atmosfer.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2441, 4, 1, '132070106066', 'Impedance Meter', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2442, 10, 1, '132080128007', 'Spot Welding Machine', 'perangkat yang digunakan untuk melakukan proses pengelasan titik pada logam. Proses ini melibatkan penggunaan elektrode yang menekan dua lembar logam bersama-sama dan kemudian mengalirkan arus listrik tinggi melalui titik-titik yang diinginkan untuk mencairkan logam tersebut sehingga terbentuk sambungan titik', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2443, 4, 1, '132070106067', 'Irrigating Trocar', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2444, 10, 1, '132080128009', 'Oxy Acetileng Copier Cutting', 'Proses ini melibatkan penggunaan gas oksigen dan gas asetilen untuk melakukan pemotongan logam', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2445, 10, 1, '132080128010', 'Plasma Cutting', 'salah satu metode pemotongan logam yang menggunakan gas plasma yang sangat panas untuk melakukan pemotongan. Proses ini umumnya lebih cepat dan dapat memotong material dengan ketebalan yang bervariasi, mulai dari logam tipis hingga logam tebal', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2446, 10, 1, '132080128011', 'Manual Pipe Cutter Oxy Acetilence', 'alat yang digunakan untuk memotong pipa logam dengan menggunakan teknik yang melibatkan nyala panas dari campuran oksigen dan asetilen', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2447, 4, 1, '132070106070', 'Kikir Tulang Nasal', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2448, 10, 1, '132080128012', 'Plate Bending Machine', 'peralatan yang digunakan untuk membengkokkan dan membentuk plat logam menjadi berbagai bentuk lengkung atau sudut yang diinginkan sesuai kebutuhan spesifik dalam industri pengelasan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2449, 4, 1, '132070106071', 'Killian', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2450, 10, 1, '132080128013', 'Hydroulic Prosses Brake Machine', 'alat yang digunakan dalam proses pembentukan plat logam. Proses brake memungkinkan pengguna untuk membengkokkan plat logam dengan presisi dan kontrol yang tinggi sesuai dengan sudut atau bentuk yang diinginkan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2451, 4, 1, '132070106072', 'Knife Hand', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2452, 10, 1, '132080128014', 'Portal Press', 'mesin besar yang digunakan untuk melakukan pemadatan, pemotongan, atau pembentukan pada logam dengan menggunakan tekanan yang tinggi. Mesin ini terdiri dari struktur portal yang kuat dan sistem mekanis yang memungkinkan penggunaannya dalam berbagai aplikasi industri, termasuk pengelasan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2453, 4, 1, '132070106073', 'Laringos 4 Beadeomin Lookzeeter', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2454, 10, 1, '132080128016', 'Hand Putch Machine', 'alat yang digunakan untuk membuat lubang pada logam dengan menggunakan tekanan mekanis. Ini biasanya digunakan untuk membuat lubang yang presisi pada plat logam sebelum proses pengelasan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2455, 4, 1, '132070106074', 'Laringos Spatale 5380 And 133/mm', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2456, 10, 1, '132080128019', 'Hand Roll Machine', 'alat yang digunakan untuk membengkokkan plat logam dengan tangan atau dengan bantuan operator secara manual. Mesin ini sering digunakan dalam proses pengelasan untuk membentuk bagian-bagian logam yang membutuhkan lengkungan atau bentuk silinder', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2457, 4, 1, '132070106075', 'Mansifeder Defis', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2458, 10, 1, '132080129001', 'Universal Testing Machine (Alat Laboratorium Uji Proses Pengelasan)', 'alat yang digunakan untuk melakukan berbagai jenis uji kekuatan dan sifat material. Mesin ini sangat penting dalam industri pengelasan karena digunakan untuk menguji kekuatan, keuletan, dan karakteristik material yang digunakan dalam proses pengelasan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2459, 4, 1, '132070106076', 'Meadlight Halogen/Welak Allyn Usa (PPM)', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2460, 10, 1, '132080129002', 'Impact Test', 'salah satu metode pengujian yang umum dilakukan dalam laboratorium untuk mengevaluasi ketangguhan material, terutama dalam konteks pengelasan. Uji ini membantu dalam memahami sejauh mana material akan bertahan terhadap beban benturan atau kejut', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2461, 4, 1, '132070106077', 'Mikro Curitage', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2462, 10, 1, '132080129003', 'Magnetic Particle (Alat Laboratorium Uji Proses Pengelasan)', 'salah satu metode penting dalam uji non-destruktif yang sering digunakan dalam proses pengelasan untuk mendeteksi retakan atau cacat pada permukaan logam.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2463, 11, 1, '132080130001', 'Converntion Lathe', 'alat yang digunakan dalam proses pembuatan logam untuk memutar sebuah benda kerja dan melakukan operasi pemotongan, pemuluran, atau pembentukan pada material logam', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2464, 4, 1, '132070106079', 'Mikro Respatorium', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2465, 11, 1, '132080130002', 'Cnc - Lathe', 'mesin bubut yang dioperasikan secara otomatis dengan menggunakan kontrol numerik komputer. Mesin ini menggunakan program yang telah diprogram sebelumnya untuk mengatur pergerakan alat potong dan benda kerja dengan presisi tinggi.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2466, 11, 1, '132080130004', 'Boring & Milling Machine', 'alat yang digunakan dalam proses pembuatan logam untuk membuat lubang dengan presisi tinggi atau untuk menghilangkan material dari permukaan logam menggunakan proses penggilingan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2467, 11, 1, '132080130005', 'Press Machine', 'peralatan yang digunakan untuk membentuk atau memproses material logam dengan menerapkan tekanan yang tinggi. Mesin press hadir dalam berbagai jenis dan ukuran, yang masing-masing memiliki kegunaan dan kapasitas yang berbeda-beda.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2468, 4, 1, '132070106082', 'Mouth Speder (Devis)', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2469, 11, 1, '132080130008', 'Surface Grinding Machine', 'peralatan yang digunakan untuk menghasilkan permukaan yang rata dan halus pada material logam. Mesin ini menggunakan roda penggiling untuk menghilangkan material dari permukaan benda kerja secara presisi, menciptakan hasil yang akurat dan halus', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2470, 4, 1, '132070106083', 'Muadiatias Cape Benatoal (Loka)', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2471, 11, 1, '132080130009', 'Cylindrical Grinding Machine', 'yang digunakan untuk menggiling permukaan luar atau dalam silinder logam dengan presisi tinggi. Alat ini sering digunakan untuk mencapai dimensi yang tepat, kehalusan, dan akurasi pada bagian silinder yang membutuhkan toleransi yang ketat', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2472, 11, 1, '132080130010', 'Puch Electrode Shaping Machine', 'mesin yang digunakan untuk membentuk elektroda untuk proses EDM (Electrical Discharge Machining).\n\nProses EDM melibatkan penggunaan elektroda yang dibentuk dengan presisi untuk membentuk material dengan menggunakan percikan listrik. Mesin punch electrode shaping dapat membentuk elektroda dengan akurasi tinggi sesuai dengan geometri yang diinginkan untuk digunakan dalam proses EDM', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2473, 11, 1, '132080130013', 'Milling Machine (Alat Laboratorium Proses Pembuatan Logam)', 'alat yang digunakan untuk menghasilkan permukaan rata dengan menghilangkan material dari benda kerja dengan menggunakan pisau potong yang berputar. Mesin ini digunakan dalam proses pembuatan logam untuk membuat komponen dengan dimensi yang tepat, permukaan yang rata, dan profil yang diinginkan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2474, 11, 1, '132080130015', 'Hydraulic Handling Equipment', 'peralatan yang menggunakan prinsip hidrolik untuk menggerakkan atau mengangkat beban yang berat dalam proses pembuatan logam. Peralatan ini sering digunakan dalam industri manufaktur logam untuk mempermudah pengangkatan, pemindahan, atau penataan benda kerja yang besar atau berat', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2475, 11, 1, '132080130016', 'Tool Grinder Machine', 'alat yang digunakan dalam proses pembuatan logam untuk mengasah dan mempertajam perkakas seperti bor, pahat, mata pahat, atau alat pemotong lainnya yang digunakan dalam proses pembuatan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2476, 11, 1, '132080130017', 'Band Saw Machine', 'alat yang digunakan dalam proses pembuatan logam untuk memotong benda kerja logam dengan menggunakan pita gergaji yang panjang dan bergerak secara terus-menerus.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2477, 4, 1, '132070106089', 'Nashopharynx Spigel', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2478, 11, 1, '132080130019', 'Abrasive Cut Off Wheele', 'alat yang digunakan dalam proses pembuatan logam untuk memotong material logam dengan menggunakan roda potong abrasif yang diputar dengan kecepatan tinggi.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2479, 4, 1, '132070106090', 'Nosofaringoscope', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2480, 11, 1, '132080131001', 'Linear Measuring Tools', 'perangkat yang digunakan untuk mengukur panjang, jarak, atau dimensi linear lainnya dengan tingkat akurasi tertentu. Ini adalah komponen kunci dalam bidang metrologi yang mencakup pengukuran, pengujian, dan kalibrasi untuk memastikan keakuratan dan konsistensi dalam berbagai proses manufaktur dan pengukuran.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2481, 11, 1, '132080131004', 'Angle Measuring Tools (Jangka Sorong)', 'peralatan dalam metrologi yang digunakan untuk mengukur sudut dengan tingkat presisi tertentu. Salah satu alat yang sering digunakan untuk mengukur sudut adalah "Jangka Sorong" atau Vernier Caliper dengan skala sudut.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2482, 11, 1, '132080131006', 'Rougness Tester', 'perangkat yang digunakan dalam metrologi untuk mengukur kekasaran permukaan suatu benda atau material. Ini membantu dalam menentukan tingkat ketidakrataan atau kekasaran pada permukaan yang diukur', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2483, 4, 1, '132070106093', 'Operating Theter Light Antsrshi', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2484, 11, 1, '132080131007', 'Flatness Instrument And Tools Geare & Acrewa Threec', 'Tidak ditemukan foto spesifik barang\nBeberapa alat dan instrumen yang digunakan untuk mengukur ke dataran atau ke rataan termasuk:\n\nStraight Edge (Alat Datarkan): Ini adalah alat sederhana yang digunakan untuk memeriksa ke dataran permukaan dengan cara meletakkan alat ini di atas permukaan yang akan diukur.\n\nSquaring Block (Blok Persegi): Digunakan untuk memeriksa ke dataran dan ke segian suatu permukaan. Ini biasanya memiliki sisi yang sangat datar dan tegak lurus satu sama lain.\n\nOptical Flat (Datarkan Optik): Sebuah plat kaca dengan permukaan yang sangat rata dan halus, sering digunakan dalam pengukuran ke dataran dengan menggunakan metode optik.\n\nInterferometer (Interferometer): Alat yang menggunakan prinsip interferensi cahaya untuk mengukur perbedaan tingkat ke dataran antara permukaan yang diukur dengan permukaan referensi yang sangat rata.\n\nCoordinate Measuring Machine (CMM): Mesin ini menggunakan sensor untuk mengukur permukaan dan dapat memberikan informasi tentang ke dataran suatu benda kerja dalam koordinat tiga dimensi.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2485, 11, 1, '132080131010', 'Meusuring Machine', 'perangkat yang digunakan untuk mengukur dimensi, geometri, dan karakteristik suatu objek dengan tingkat akurasi yang tinggi\n\nAda beberapa jenis alat pengukur yang umum digunakan:\n\nCoordinate Measuring Machine (CMM): Mesin ini menggunakan sensor atau probe untuk mengukur posisi tiga dimensi dari suatu objek. CMM memungkinkan pengukuran yang sangat akurat terhadap geometri kompleks.\n\nOptical Measuring Machine: Mesin ini menggunakan teknologi optik, sering kali dengan kamera dan perangkat lunak pengolahan citra, untuk mengukur dimensi dan karakteristik permukaan objek dengan tingkat akurasi yang tinggi.\n\nRoundness Measuring Machine: Digunakan khusus untuk mengukur kebulatan atau sirkularitas dari suatu objek. Ini memberikan informasi tentang seberapa baik suatu lingkaran atau silinder sesuai dengan bentuk yang ideal.\n\nSurface Roughness Tester: Mesin ini mengukur tingkat kekasaran atau ketidakrataan permukaan suatu objek, memberikan informasi tentang pola atau tekstur permukaan.\n\nForm Measuring Machine: Digunakan untuk mengukur bentuk atau kontur yang lebih kompleks seperti profil lengkungan, sudut, atau bentuk-bentuk non-linier lainnya.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2486, 4, 1, '132070106095', 'Patologie Eqmopmanet', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2487, 11, 1, '132080132003', 'Bak Electronic', 'wadah atau bak yang digunakan dalam proses elektroplating, di mana pelapisan logam dilakukan pada benda kerja menggunakan proses elektrokimia. Bak ini berfungsi sebagai wadah tempat larutan elektrolit (yang mengandung ion logam yang ingin dilapis) dan tempat untuk melakukan proses elektroplating', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2488, 4, 1, '132070106096', 'Perios Patorium', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2489, 11, 1, '132080132005', 'Burner', 'salah satu perangkat penting yang digunakan untuk memanaskan larutan kimia atau cairan tertentu yang terlibat dalam proses pelapisan. Ini bisa berupa burner gas atau alat pemanas lainnya yang digunakan untuk mengatur suhu cairan elektrolit, larutan kimia, atau bahkan suhu substrat logam yang akan dilapisi', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2490, 11, 1, '132080132006', 'Heater (Alat Laboratorium Proses Pelapisan Logam)', 'digunakan untuk mengatur suhu pada berbagai tahapan proses pelapisan logam. Pemanasan adalah bagian penting dari banyak proses kimia dan elektrokimia, termasuk proses pelapisan logam', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2491, 11, 1, '132080133001', 'Dapur Pengerasan Induksi', 'alat yang digunakan dalam proses pengolahan panas untuk meningkatkan kekerasan permukaan logam dengan menggunakan prinsip pemanasan induksi', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2492, 4, 1, '132070106099', 'Polyplis', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2493, 11, 1, '132080133006', 'Bak Pendingin', 'wadah atau bak yang digunakan untuk pendinginan cepat atau tempering pada benda kerja setelah melalui proses pemanasan atau perlakuan panas.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2494, 11, 1, '132080133007', 'Crane (500 Kg)', 'digunakan untuk memindahkan atau mengangkat benda kerja, komponen, atau peralatan yang terlibat dalam proses pengolahan panas.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2495, 4, 1, '132070106101', 'Repatorium', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2496, 11, 1, '132080133008', 'Tempat Peyimpanan Garam', 'wadah atau ruang penyimpanan khusus yang digunakan untuk menyimpan garam yang digunakan dalam proses perlakuan panas atau perlakuan termal.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2497, 4, 1, '132070106102', 'Respatorium Dipal Lurus/Lengkung', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2498, 11, 1, '132080133010', 'Exhaust Fan', 'perangkat yang digunakan untuk mengalirkan udara panas, uap, asap, atau gas-gas yang dihasilkan selama proses pengolahan panas di laboratorium keluar dari ruangan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2499, 4, 1, '132070106103', 'Retractor Opula', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2500, 11, 1, '132080133011', 'Cleaning Instalation', 'sistem atau perangkat yang digunakan untuk membersihkan peralatan, komponen, atau lingkungan kerja yang terlibat dalam proses pengolahan panas.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2501, 4, 1, '132070106104', 'Rhinos Plastik', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2502, 11, 1, '132080134009', 'Mesin Pelubang Karton', 'Mesin ini digunakan untuk membuat lubang atau ventilasi pada kemasan karton, biasanya digunakan untuk kemasan produk-produk tertentu.\n\n\n\nDalam konteks laboratorium proses teknologi tekstil, fokusnya cenderung pada pengembangan dan pengujian bahan tekstil, proses pewarnaan, finishing, pengujian kualitas, dan inovasi dalam industri tekstil. Meskipun demikian, laboratorium tersebut mungkin juga memiliki mesin-mesin khusus yang digunakan untuk memproses, menguji, atau mengembangkan bahan tekstil.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2503, 4, 1, '132070106105', 'Rhinoscopy Mirror', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2504, 11, 1, '132080134017', 'Mesin Jahit Lockstitich', 'salah satu jenis mesin jahit yang umum digunakan dalam industri tekstil. Lockstitch mengacu pada jenis jahitan di mana benang atas dan benang bawah saling mengunci untuk membentuk jahitan yang kuat dan tahan lama. Mesin jahit ini memiliki penggunaan luas dalam pembuatan pakaian, tekstil rumah tangga, industri furnitur, dan berbagai aplikasi lainnya', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2505, 4, 1, '132070106106', 'Rinaural Stetoscope', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2506, 11, 1, '132080134018', 'Thread Overadge Stitch', 'mesin jahit yang digunakan untuk membuat jahitan tepi pada bahan tekstil untuk mencegah tepian kain agar tidak merajalela atau merobek. Jahitan tepi ini memberikan tampilan yang rapi dan melindungi tepi kain dari kerusakan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2507, 4, 1, '132070106107', 'Set Canule Besar', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2508, 11, 1, '132080134019', 'Mesin Overdeck', 'mesin jahit khusus yang melakukan jahitan overcasting atau jahitan tepi pada bahan tekstil. Mesin ini membuat jahitan yang lebih kuat dan rapi pada tepian kain, mencegah agar tepian tidak merajalela atau terurai', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2509, 4, 1, '132070106108', 'Septo Plastik', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2510, 11, 1, '132080134020', 'Mesin Potong Tegak', 'digunakan untuk memotong kain dalam pola yang diinginkan secara vertikal, sering kali digunakan dalam proses pembuatan pakaian atau produk tekstil lainnya. Mesin ini memastikan potongan kain yang akurat dan rapi sesuai dengan pola yang ditentukan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2511, 4, 1, '132070106109', 'Septo Respetorium', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2512, 11, 1, '132080134022', 'Mesin Jahit Chain Stitch', 'jenis mesin jahit yang menggunakan teknik jahitan chain stitch, di mana satu benang membentuk pola jahitan mirip dengan mata rantai atau gelang. Jahitan ini biasanya memiliki tampilan yang khas di bagian belakang kain, karena bentuknya yang seperti rantai', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2513, 11, 1, '132080134024', 'matter half', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2514, 4, 1, '132070106111', 'Septum Respetorium', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2515, 11, 1, '132080134025', 'Mesin Press Kain', 'peralatan yang digunakan untuk menyetrika atau memadatkan kain setelah berbagai proses seperti pewarnaan, pencelupan, atau penyelesaian tekstil lainnya.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2516, 4, 1, '132070106112', 'Septum Straightening', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2517, 11, 1, '132080134026', 'Mesin Strika Uap', 'alat yang digunakan untuk menyetrika dengan bantuan uap air. Alat ini memiliki tangki air yang menghasilkan uap, yang kemudian diaplikasikan ke kain saat menyetrika. Prosesnya membantu melunakkan serat kain dan membuat proses menyetrika menjadi lebih efisien dan memberikan hasil yang lebih rata', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2518, 4, 1, '132070106113', 'Single Famier Hapares Cape', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2519, 11, 1, '132080134027', 'Mesin Blowing', 'peralatan yang digunakan dalam proses pencelupan atau penyebaran zat kimia tertentu pada serat atau kain.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2520, 4, 1, '132070106114', 'Sinoscopy Trocar', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2521, 11, 1, '132080134028', 'Mesin Carding', 'digunakan untuk mempersiapkan serat dalam proses produksi benang. Proses carding ini membantu dalam membersihkan, menguraikan, dan melepaskan serat yang masih tersusun rapat sehingga dapat diubah menjadi benang yang lebih halus dan lentur', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2522, 4, 1, '132070106115', 'Sluder Balinger', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2523, 11, 1, '132080134031', 'Mesin Winding', 'peralatan yang digunakan untuk memindahkan benang dari bobin besar ke bobin kecil atau spindle yang lebih kecil. Proses penggulungan ini penting dalam proses produksi benang karena mempersiapkan benang untuk tahap selanjutnya dalam proses tekstil.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2524, 4, 1, '132070106116', 'Specullum Retractor Nasal', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2525, 11, 1, '132080134041', 'Mesin Sambung', 'mesin yang digunakan untuk menyambung dua ujung benang atau serat, umumnya dengan teknik tertentu seperti penggunaan lem, pemanasan, atau teknologi penyambungan khusus.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2526, 4, 1, '132070106117', 'Speculum Klian', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2527, 11, 1, '132080134044', 'Alat Tenun Reeling', 'perangkat yang digunakan untuk mengumpulkan atau melilit benang dari bobin besar atau konus besar ke dalam bentuk yang lebih mudah diatur, seperti konus kecil atau bobin yang digunakan dalam proses tekstil lebih lanjut.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2528, 4, 1, '132070106118', 'Speculum Telinga', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2529, 11, 1, '132080134047', 'Mesin Jahit Locksitik', 'jenis mesin jahit yang menggunakan teknik lockstitch. Jahitan ini terkenal karena kekuatannya, di mana benang atas dan benang bawah saling mengunci untuk membentuk jahitan yang kuat dan tahan lama pada kain', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2530, 4, 1, '132070106119', 'Spoon Telinga', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2531, 11, 1, '132080134048', 'Mesin Jahit Elastik 5 Benang 3 Jarum', 'jenis mesin jahit khusus yang memiliki kapabilitas untuk menjahit menggunakan lima benang sekaligus dengan tiga jarum. Mesin ini umumnya digunakan untuk menjahit kain atau produk yang memerlukan ketahanan elastisitas tambahan, seperti pada pakaian atau produk tekstil yang memerlukan jahitan yang kuat namun fleksibel', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2532, 4, 1, '132070106120', 'Stroboscopy Unit', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2533, 11, 1, '132080134049', 'Mesin Bordir Highspeed', 'mesin bordir yang dirancang untuk meningkatkan kecepatan dan efisiensi proses bordir. Mesin ini memiliki kemampuan untuk menjahit dengan kecepatan yang lebih tinggi dibandingkan dengan mesin bordir biasa, memungkinkan produksi bordir dalam volume yang lebih besar dalam waktu yang lebih singkat', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2534, 4, 1, '132070106121', 'Tang Bright', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2535, 11, 1, '132080134051', 'Mesin Jahit Pasang Kancing', 'peralatan khusus yang dirancang untuk memasang kancing pada pakaian atau tekstil dengan cepat dan presisi. Mesin ini memiliki fungsi khusus yang memungkinkan pengguna untuk memasang kancing dengan jahitan yang kuat dan rapi', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2536, 4, 1, '132070106122', 'Teaching Cape M 12 M', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2537, 11, 1, '132080134052', 'Mesin Jahit Overlock', 'jenis mesin jahit yang memiliki kemampuan untuk menjahit, menyelesaikan tepi kain, dan memotong secara bersamaan. Mesin ini sering digunakan dalam industri tekstil karena kemampuannya untuk membuat jahitan yang rapi dan tahan lama pada tepian kain', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2538, 11, 1, '132080134054', 'Mesin Knife Clath Cutting', 'peralatan yang digunakan untuk memotong kain atau bahan tekstil dengan menggunakan pisau atau pisau bergigi khusus yang berputar. Mesin ini dapat digunakan untuk memotong kain dalam jumlah besar dengan cepat dan presisi. Pisau yang digunakan dalam mesin ini dirancang untuk memotong berbagai jenis kain dengan tepi yang rapi dan presisi.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2539, 11, 1, '132080134055', 'Mesin Printing', 'mesin pencetak tekstil, yang digunakan untuk mentransfer pola atau desain ke kain atau tekstil lainnya. Mesin printing tekstil dapat memiliki berbagai jenis, termasuk:\n\nPrinting Digital: Menggunakan teknologi digital untuk menerapkan pola atau desain langsung ke kain dengan menggunakan printer khusus yang menggunakan tinta tekstil.\n\nScreen Printing (Sablon): Menggunakan layar khusus untuk menerapkan pola atau desain ke kain dengan menerapkan tinta melalui layar yang telah diberi pola.\n\nRotary Printing (Pencetakan Rotary): Menggunakan roller berpola untuk menerapkan pola atau desain ke kain secara berulang dengan presisi.\n\nHeat Transfer Printing (Pencetakan Transfer Panas): Mentransfer desain atau pola dari media transfer khusus ke kain melalui panas dan tekanan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2540, 11, 1, '132080134056', 'Mesin Pemasang Kain Screen', 'peralatan yang digunakan untuk memasang kain pada frame atau rangka yang digunakan dalam proses sablon (screen printing) pada tekstil. Pemasangan kain pada frame ini penting karena kain harus ditarik dengan rata dan kencang di atas frame agar proses sablon berjalan dengan baik', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2541, 11, 1, '132080134057', 'Mesin Steam Rol', 'peralatan yang digunakan untuk menyetrika atau menghaluskan kain atau tekstil dengan bantuan uap air. Mesin ini sering digunakan untuk memperbaiki atau menyempurnakan tekstil setelah proses pewarnaan, pencelupan, atau aplikasi bahan kimia tertentu.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2542, 4, 1, '132070106127', 'Tonsil Dissecting', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2543, 11, 1, '132080134058', 'Mesin Gulung Kaos', 'peralatan otomatis yang digunakan untuk melipat dan menggulung pakaian, khususnya kaos, dengan cara yang cepat dan efisien. Mesin ini umumnya digunakan dalam industri garmen, toko pakaian, dan pabrik tekstil untuk memudahkan proses penataan dan pengepakan pakaian', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2544, 11, 1, '132080134059', 'Mesin Lipat Kain', 'peralatan yang digunakan untuk melipat kain atau tekstil dengan cara otomatis dan sering kali dapat menyesuaikan lipatan sesuai dengan kebutuhan yang diatur', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2545, 4, 1, '132070106129', 'Tonsil Klem/Mess/Biasa', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2546, 11, 1, '132080134063', 'Ketel Pemasakan', 'peralatan yang digunakan untuk proses pemanasan dan pemasakan bahan-bahan tekstil. Biasanya, ketel ini dirancang untuk menjaga suhu dan tekanan yang sesuai untuk berbagai proses dalam laboratorium tekstil, seperti pewarnaan, pencelupan, atau pengolahan kimia lainnya', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2547, 11, 1, '132080134064', 'Mesin Curring', 'peralatan yang digunakan dalam industri tekstil untuk proses pengeringan dan perawatan bahan tekstil setelah melalui proses pewarnaan atau aplikasi bahan kimia tertentu', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2548, 11, 1, '132080134066', 'Mesin Peras', 'peralatan yang digunakan untuk mengekstraksi atau menghilangkan kelebihan air atau bahan kimia dari bahan tekstil setelah proses seperti pencucian, pencelupan, atau perlakuan lainnya', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2549, 11, 1, '132080134067', 'Mesin Pengering', 'peralatan yang digunakan untuk mengeringkan bahan tekstil setelah proses seperti pencucian, pewarnaan, atau perlakuan kimia lainnya. Mesin ini membantu dalam menghilangkan kelebihan air atau bahan kimia dari bahan tekstil sehingga bahan tersebut siap untuk tahap selanjutnya dalam proses produksi atau penelitian', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2550, 11, 1, '132080134069', 'Exomat Hydro Extrator', 'jenis mesin ekstraktor yang digunakan dalam industri tekstil untuk menghilangkan kelebihan air dari kain atau tekstil setelah proses pencucian. Mesin ini memanfaatkan prinsip sentrifugal untuk mengeluarkan air dari bahan tekstil yang telah dicuci', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2551, 4, 1, '132070106134', 'Tounge Depressor', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2552, 11, 1, '132080134072', 'Mesin Pemotong Serat', 'peralatan yang digunakan untuk memotong serat menjadi ukuran yang diinginkan dalam industri tekstil. Mesin ini memungkinkan pemotongan serat, seperti serat sintetis atau alami, menjadi panjang atau ukuran tertentu sesuai dengan kebutuhan produksi', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2553, 4, 1, '132070106135', 'Trachea Canula (Alat Kedokteran Tht)', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2554, 11, 1, '132080135002', 'Alat Uji Serat Sintetik', 'peralatan yang digunakan untuk menguji karakteristik fisik, kimia, atau mekanik dari serat sintetis seperti poliester, nilon, rayon, atau serat lainnya. Tujuan pengujian ini adalah untuk memahami dan mengevaluasi kualitas serta kinerja serat sebelum digunakan dalam proses produksi tekstil', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2555, 11, 1, '132080135003', 'Alat Uji Kekuatan Tarik Kain', 'peralatan yang digunakan untuk mengukur seberapa kuat atau tahan sebuah kain ketika ditarik pada arah tegak lurus terhadap seratnya. Pengujian ini penting untuk mengevaluasi kualitas dan kekuatan sebuah kain sebelum digunakan dalam pembuatan produk jadi. Beberapa alat uji yang umum digunakan untuk menguji kekuatan tarik kain meliputi:\n\nInstron Tester: Alat ini sering digunakan untuk mengukur kekuatan tarik kain. Kain dipegang di antara dua jerat dan ditarik hingga pecah. Instron dapat memberikan data tentang kekuatan maksimum yang diperlukan untuk merusak kain.\n\nGrab Testers: Jenis alat uji ini memberikan hasil kekuatan tarik dengan mengambil sampel kecil dari kain pada kedua ujungnya dan menariknya hingga terjadi pemisahan.\n\nElmendorf Tear Tester: Alat ini mengukur kekuatan retakan atau sobekan pada kain dengan memberikan tekanan pada sampel kain hingga terjadi sobekan.\n\nTensile Strength Testers: Merupakan perangkat yang mengukur kekuatan maksimum yang dapat ditahan oleh kain sebelum putus.\n\nInstrumen Digital untuk Uji Tekan: Digunakan untuk mengevaluasi stabilitas kain dengan memberikan tekanan pada sampel kain.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2556, 11, 1, '132080135005', 'Incline Plane Tester', 'perangkat uji yang digunakan untuk mengukur karakteristik gesekan dan kemampuan kain atau bahan untuk meluncur di permukaan miring. Perangkat ini membantu dalam mengevaluasi sifat gesekan dan kemampuan anti-luncur dari bahan tekstil atau material lainnya', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2557, 11, 1, '132080135010', 'Alat Crimp Tester', 'digunakan untuk mengukur atau mengevaluasi "crimp" pada serat tekstil, seperti kapas, wol, atau serat lainnya. Crimp merujuk pada lipatan atau kerutan alami dalam serat yang terbentuk selama proses pembuatan serat. Pengukuran crimp pada serat sangat penting karena dapat mempengaruhi karakteristik serat dan kain yang dihasilkan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2558, 4, 1, '132070106139', 'Troeitsch', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2559, 11, 1, '132080135012', 'Alat Uji Siram Air', 'perangkat yang digunakan untuk mengevaluasi tingkat perlindungan air atau ketahanan air pada kain atau bahan tekstil. Pengujian ini penting dalam menentukan seberapa baik kain atau pakaian dapat menahan atau menolak air dalam kondisi tertentu', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2560, 11, 1, '132080135013', 'Alat Uji Sobek Kain', 'perangkat yang digunakan untuk mengukur atau mengevaluasi ketahanan kain terhadap sobekan atau kerusakan. Pengujian ini membantu dalam menilai seberapa kuat atau tahan sebuah kain sebelum terjadi sobekan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2561, 11, 1, '132080135014', 'Crease Recovery', 'pengukuran yang mengevaluasi kemampuan sebuah kain untuk pulih setelah dilipat atau diberi lipatan tertentu. Alat uji crease recovery dalam laboratorium tekstil digunakan untuk mengukur seberapa baik kain atau bahan tekstil dapat mengembalikan bentuknya setelah dilipat atau dibentuk dalam suatu lipatan tertentu', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2562, 4, 1, '132070106142', 'Tuning Fork Set', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2563, 11, 1, '132080135020', 'Gloss Meter', 'alat yang umumnya digunakan dalam laboratorium uji tekstil untuk mengukur tingkat kilap atau kecerahan permukaan kain atau bahan tekstil. Alat ini memberikan pengukuran numerik terhadap tingkat refleksi cahaya dari permukaan kain.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2564, 11, 1, '132080135023', 'Tensio Meter', 'alat yang digunakan dalam laboratorium uji tekstil untuk mengukur tegangan permukaan atau tegangan antarmuka dari cairan di permukaan tekstil. Alat ini membantu dalam memahami interaksi antara cairan (seperti air) dengan permukaan kain atau tekstil.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2565, 4, 1, '132070106144', 'Tympanum Perdrotors Saver', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2566, 11, 1, '132080135025', 'Weather Meter', 'digunakan sebagai bagian dari pengujian untuk memahami bagaimana bahan tekstil bertahan atau berperilaku dalam kondisi cuaca eksternal atau lingkungan tertentu.\n\nPenggunaan Weather Meter dalam laboratorium tekstil dapat mencakup pengujian kebocoran air, ketahanan terhadap angin, penyerapan cahaya matahari, atau pengukuran lain yang relevan dengan sifat fisik dan kinerja bahan tekstil dalam kondisi cuaca eksternal atau lingkungan tertentu', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2567, 4, 1, '132070106145', 'Water Drages', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2568, 11, 1, '132080135026', 'Rain Tester', 'alat uji yang digunakan dalam laboratorium tekstil untuk mensimulasikan kondisi hujan pada kain atau bahan tekstil. Alat ini membantu dalam mengevaluasi ketahanan air atau kebocoran air dari kain dalam kondisi hujan atau paparan air.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2569, 11, 1, '132080135027', 'Tumble Dryer', 'alat yang digunakan dalam laboratorium tekstil untuk mensimulasikan proses pengeringan dengan menggunakan mesin pengering putar. Alat ini digunakan untuk menguji sifat atau kinerja bahan tekstil dalam kondisi pengeringan yang dipercepat dan terkendali, seperti yang terjadi dalam mesin pengering rumah tangga', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2570, 11, 1, '132080135028', 'Conedrop Test (Alat Laboratorium Uji Tekstil)', 'uji yang mengukur seberapa baik atau seberapa cepat suatu serat atau benang dapat melorot dari kon, konus, atau penggulung saat diberi beban tertentu.\n\nTes ini sering dilakukan untuk mengevaluasi karakteristik kekuatan dan kekakuan serat atau benang, serta kemampuannya untuk mendukung beban tertentu sebelum melorot. Pengujian semacam ini memberikan informasi penting tentang keandalan benang atau serat dalam berbagai aplikasi tekstil, misalnya dalam proses produksi kain atau pakaian.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2571, 11, 1, '132080135030', 'Brusting Tester', 'alat uji yang digunakan dalam laboratorium tekstil untuk mengukur kekuatan atau daya tahan kain atau bahan tekstil terhadap tekanan atau ekspansi internal. Pengujian ini berguna untuk mengetahui seberapa kuat kain atau bahan tersebut mampu menahan tekanan internal sebelum terjadinya kerusakan atau sobekan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2572, 4, 1, '132070107003', 'Aplanation Tonometer', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2573, 11, 1, '132080135032', 'Psychrometer (Alat Laboratorium Uji Tekstil)', 'alat yang digunakan untuk mengukur kelembapan relatif udara. Dalam konteks laboratorium uji tekstil, penggunaan psychrometer mungkin terkait dengan pengukuran kondisi lingkungan, seperti suhu dan kelembapan, yang mempengaruhi bahan tekstil.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2574, 11, 1, '132080135033', 'Martindale Wear And Arbartion Tester', 'alat uji yang digunakan dalam laboratorium tekstil untuk mengukur tahan lama atau ketahanan aus sebuah kain atau bahan tekstil terhadap gesekan dan keausan. Pengujian ini sering digunakan untuk menilai ketahanan material terhadap gesekan atau pemakaian yang terus-menerus, seperti yang terjadi pada pakaian, furnitur, atau tekstil yang digunakan dalam berbagai aplikasi.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2575, 4, 1, '132070107005', 'Three Mirror Contact Lenses', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2576, 11, 1, '132080135034', 'Alat Penomoran Benang', 'perangkat yang digunakan dalam industri tekstil untuk memberikan nomor atau pengidentifikasi pada benang. Alat ini penting dalam proses produksi benang karena membantu dalam memberikan label atau kode yang menentukan karakteristik khusus dari benang yang diproduksi.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2577, 4, 1, '132070107006', 'Opthalmoscope Suppy 220 V And Transformer', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2578, 11, 1, '132080135038', 'Line Test', 'berbagai jenis pengujian yang dilakukan untuk mengukur sifat-sifat atau kualitas suatu garis atau serat dalam bahan tekstil. Pengujian garis atau serat dalam tekstil biasanya melibatkan pengukuran kekuatan, kekakuan, elastisitas, ketahanan terhadap regangan, atau karakteristik lainnya yang relevan dengan penggunaan atau aplikasi bahan tersebut', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2579, 4, 1, '132070107007', 'Double Convaxoconcave Skiascope', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2580, 11, 1, '132080135040', 'Alat Uji Beda Warna', 'instrumen yang digunakan dalam laboratorium uji tekstil untuk menilai perbedaan atau keseragaman warna antara berbagai sampel tekstil. Alat ini membantu dalam menentukan sejauh mana perbedaan warna antara dua sampel atau kain. Beberapa alat yang umum digunakan untuk mengukur perbedaan warna di laboratorium tekstil meliputi:\n\nSpektrofotometer: Alat yang mengukur intensitas cahaya yang dipantulkan atau diserap oleh sampel tekstil pada berbagai panjang gelombang. Ini membantu dalam analisis warna dengan ketelitian tinggi.\n\nKromatometer: Alat yang digunakan untuk membandingkan dan mengevaluasi perbedaan warna antara dua sampel tekstil. Ini sering digunakan dalam menilai perbedaan warna yang lebih kasat mata.\n\nKomparator warna: Berbagai jenis komparator warna digunakan untuk membandingkan sampel tekstil dengan standar warna untuk menilai perbedaan warna dan keseragaman.\n\nSoftware pemrosesan warna: Alat lunak yang membantu dalam analisis warna, memungkinkan pengguna untuk memvisualisasikan, membandingkan, dan menganalisis data warna secara digital.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2581, 11, 1, '132080135044', 'Presslay Fiber Strengh Tester', 'Alat ini biasanya digunakan untuk mengukur kekuatan tarik serat dengan cara mengambil sampel serat tertentu, memasukkannya ke dalam alat, dan kemudian menerapkan gaya tarik hingga serat tersebut putus. Proses ini membantu menentukan seberapa kuat atau tahan serat terhadap gaya tarik.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2582, 11, 1, '132080135047', 'Crock Meter (Alat Laboratorium Uji Tekstil)', 'alat yang digunakan dalam laboratorium tekstil untuk mengukur ketahanan pewarnaan atau transfer warna dari suatu permukaan tekstil ke permukaan lain, biasanya dengan gesekan. Tes gesekan ini berguna untuk menentukan seberapa baik pewarnaan atau warna pada tekstil bertahan dan tidak mudah luntur atau transfer ke permukaan lain saat terjadi kontak', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2583, 11, 1, '132080135049', 'Flammeability Tester', 'alat laboratorium yang digunakan untuk mengukur ketahanan tekstil terhadap api atau kemampuan sebuah bahan untuk terbakar dan seberapa cepat bahan tersebut akan terbakar atau menyebarkan api', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2584, 11, 1, '132080135054', 'Fibrograph (Alat Laboratorium Uji Tekstil)', 'Alat untuk mengukur panjang kapas', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2585, 11, 1, '132080136003', 'Purometer Optik', 'alat yang digunakan dalam laboratorium proses teknologi keramik untuk mengukur suhu secara non-kontak. Purometer optik menggunakan cahaya yang dipancarkan oleh objek untuk menentukan suhu berdasarkan panjang gelombang radiasi yang dipancarkan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2586, 4, 1, '132070107013', 'Bailiart Dynamometer', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2587, 11, 1, '132080136005', 'Alat Pemadam Kapur', 'Belum dapat ditemukan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2588, 4, 1, '132070107014', 'Esthesiometer', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2589, 11, 1, '132080136009', 'Pengatur Tahanan Resistor', 'komponen elektronik yang dapat digunakan dalam berbagai aplikasi laboratorium, termasuk dalam proses teknologi keramik', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2590, 4, 1, '132070107015', 'Campimeter And Lancaster Screen With 4 Striks', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2591, 11, 1, '132080136010', 'Magnetic Ferofilter', 'alat atau sistem yang umumnya digunakan dalam proses industri, termasuk dalam proses teknologi keramik, untuk memisahkan partikel-logam atau benda-benda feromagnetik dari bahan cair atau suspensi', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2592, 4, 1, '132070107016', 'Holmes Steres Cope', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2593, 11, 1, '132080136012', 'Pyrometer Radiasi', 'alat yang digunakan untuk mengukur suhu benda tanpa kontak fisik langsung, berdasarkan radiasi elektromagnetik yang dipancarkan oleh benda tersebut', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2594, 4, 1, '132070107017', 'Amsler Chart', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2595, 11, 1, '132080136013', 'Electric Boiler', 'perangkat pemanas yang menggunakan listrik untuk memanaskan air atau cairan lainnya menjadi uap atau suhu yang dibutuhkan. Dalam konteks laboratorium proses teknologi keramik, electric boiler dapat digunakan untuk berbagai tujuan seperti pemanasan air untuk keperluan pencucian atau pembersihan, serta untuk menciptakan kondisi lingkungan yang diperlukan dalam proses produksi atau pengujian keramik.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2596, 4, 1, '132070107018', 'Ishiaras Atlas', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2597, 11, 1, '132080136014', 'Law Crusher', 'digunakan untuk mengurangi besar butiran pada tingkat pertama, untuk kemudian dipecah lebih lanjut oleh crusher lain.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2598, 4, 1, '132070107019', 'Stereo Tes From Holmes', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2599, 11, 1, '132080136018', 'Grinding Mill', 'alat yang digunakan untuk menggiling, menghancurkan, atau mengubah ukuran partikel dari berbagai bahan menjadi ukuran yang lebih kecil', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2600, 4, 1, '132070107020', 'Berens Prima Set', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2601, 11, 1, '132080136023', 'Friction Press', 'jenis mesin yang sering digunakan dalam industri keramik untuk pemadatan atau pemerasan bahan baku keramik yang berbentuk granular atau serbuk menjadi bentuk yang lebih padat sebelum proses selanjutnya', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2602, 4, 1, '132070107021', 'Eye Occulder', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2603, 11, 1, '132080136024', 'Hydrolic Press', 'alat yang sering digunakan dalam laboratorium proses teknologi keramik untuk melakukan pemadatan atau pemerasan bahan baku keramik dengan menggunakan tekanan hidrolik. Mesin ini menggunakan prinsip fluida yang terkandung dalam sistem hidrolik untuk menghasilkan tekanan yang tinggi, memampatkan atau membentuk bahan keramik ke dalam bentuk yang diinginkan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2604, 11, 1, '132080136027', 'Ban Berjalan', 'digunakan untuk memindahkan bahan atau sampel keramik dari satu titik ke titik lain dalam lingkungan laboratorium.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2605, 4, 1, '132070107023', 'Schuman Magnet Handtype', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2606, 11, 1, '132080136028', 'Motorized Kick Well', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2607, 11, 1, '132080136029', 'Mesin Bubut Isolator', 'digunakan untuk menghasilkan komponen keramik yang digunakan sebagai isolator dalam berbagai peralatan elektronik. Proses ini melibatkan penggunaan mesin bubut khusus yang dapat mengukir, memotong, atau membentuk bahan keramik dengan presisi sesuai dengan spesifikasi yang diinginkan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2608, 11, 1, '132080136030', 'Mesin Bor Pembuat Ulir', 'alat yang digunakan untuk membuat lubang dengan ulir pada bahan keramik. Proses pembuatan ulir pada keramik dapat menjadi bagian dari proses produksi di laboratorium teknologi keramik', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2609, 4, 1, '132070107026', 'Two Step Stand', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2610, 11, 1, '132080136032', 'Table Wheel', 'roda yang digunakan pada meja kerja, mesin, atau perangkat lain untuk tujuan tertentu.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2611, 4, 1, '132070107027', 'Maddox Crass', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2612, 11, 1, '132080136035', 'Tunnel Kiln (Gas Elpiji)', 'jenis tungku (kiln) yang digunakan dalam proses pembakaran dalam industri keramik. Kiln ini sering digunakan untuk memanaskan dan memproses berbagai produk keramik dalam jumlah besar secara terus-menerus.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2613, 11, 1, '132080136036', 'Tunnel Kiln (Listrik)', 'jenis tungku (kiln) yang digunakan dalam proses pembakaran dalam industri keramik. Sama seperti yang menggunakan gas, Tunnel Kiln listrik adalah jenis kiln yang memanaskan dan memproses berbagai produk keramik secara terus-menerus.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2614, 4, 1, '132070107029', 'Gonioscope Complete In Case', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2615, 11, 1, '132080137002', 'Mesin Setrika Kulit', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2616, 11, 1, '132080137006', 'Mesin Skrep', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2617, 11, 1, '132080137007', 'Mesin Shaving', 'perangkat yang umumnya digunakan dalam industri kulit untuk mengurangi ketebalan bahan kulit dengan cara mengikis atau mengupas lapisan luar kulit. Proses ini membantu dalam menciptakan kulit yang lebih tipis dan seragam secara tebal, sesuai dengan spesifikasi yang diinginkan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2618, 11, 1, '132080137015', 'Mesin Seser', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2619, 11, 1, '132080137017', 'Mesin Alur Jahitan', 'alur jahitan merupakan pola atau bentuk tertentu yang dihasilkan oleh mesin tersebut. Mesin jahit modern memiliki kemampuan untuk membuat berbagai jenis jahitan  termasuk pola yang dibuat melalui design komputer', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2620, 11, 1, '132080137019', 'Mesin Split', 'peralatan yang digunakan dalam industri kulit untuk membagi atau memisahkan bahan kulit menjadi lapisan yang lebih tipis. Proses splitting ini menghasilkan kulit dengan ketebalan yang lebih seragam dan dapat menyesuaikan ketebalan kulit sesuai dengan kebutuhan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2621, 11, 1, '132080137020', 'Mesin Vacum Trockner Dryne', 'peralatan yang digunakan dalam industri kulit, karet, atau plastik untuk mengeringkan bahan-bahan tersebut dengan menggunakan teknologi vakum. Mesin ini membantu dalam proses pengeringan bahan secara cepat dengan menghilangkan kelembaban dari bahan tersebut.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2622, 11, 1, '132080137022', 'Mesin Pemanas', 'Pada umumnya, mesin pemanas dalam konteks ini dapat mencakup beragam peralatan, seperti:\n\n\n\nPemanas Listrik: Oven atau alat pemanas listrik yang dapat diatur suhunya, digunakan untuk membakar atau memanaskan sampel bahan tertentu dalam pengaturan laboratorium untuk berbagai eksperimen atau proses percobaan.\n\n\n\nPemanas Vakum: Mesin pemanas yang bekerja di bawah tekanan vakum untuk memanaskan dan memproses bahan tertentu dalam kondisi lingkungan yang dikontrol.\n\n\n\nPemanas Inframerah: Alat pemanas yang menggunakan radiasi inframerah untuk memanaskan bahan dengan cepat dan merata.\n\n\n\nPemanas Induksi: Mesin pemanas yang menggunakan prinsip induksi elektromagnetik untuk memanaskan bahan dengan cepat, seringkali digunakan dalam pemrosesan logam atau material konduktif lainnya.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2623, 4, 1, '132070107037', 'Argonphoto Coagulator (Alat Kedokteran Mata)', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2624, 11, 1, '132080137024', 'Alat Press Sol Listrik', 'peralatan yang digunakan untuk mengekstrusi atau memproses bahan sol (yang digunakan sebagai lapisan luar atau bahan penutup pada sepatu) dengan menggunakan teknologi pemanasan listrik.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2625, 11, 1, '132080137028', 'Alat Potong Sol', 'peralatan yang digunakan untuk memotong bahan sol yang biasanya digunakan sebagai lapisan luar pada sepatu. Alat ini membantu dalam memotong sol sepatu dari bahan kulit, karet, atau material plastik yang digunakan untuk membuat bagian bawah sepatu.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2626, 11, 1, '132080137030', 'Mesin Finishing Combinasi', 'peralatan yang menggabungkan beberapa proses finishing dalam satu unit. Dalam industri kulit, karet, dan plastik, mesin ini sering digunakan untuk menggabungkan beberapa langkah penyelesaian atau finishing dalam satu operasi.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2627, 11, 1, '132080137034', 'Mesin Roll Press', 'peralatan yang digunakan untuk menekan dan membentuk bahan-bahan tertentu dalam industri kulit, karet, atau plastik. Mesin ini menggunakan dua atau lebih roll (gulungan) yang berputar bersama-sama untuk menekan bahan di antara mereka.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2628, 11, 1, '132080137036', 'Alat Press Angin', 'peralatan yang menggunakan tekanan udara untuk proses penekanan, pembentukan, atau pemrosesan bahan-bahan tersebut.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2629, 11, 1, '132080137037', 'Mesin Paku Sol Dalam', 'peralatan yang digunakan untuk memasang atau menancapkan bagian sol (bagian bawah sepatu) ke bagian atas sepatu. Proses ini memungkinkan pengikatan yang kuat antara sol dengan bagian atas sepatu.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2630, 11, 1, '132080137040', 'Mesin Trimming', 'peralatan yang digunakan untuk memotong, merapikan, atau menyelesaikan bagian-bagian tertentu dari bahan kulit, karet, atau plastik. Peralatan ini membantu dalam proses penyelesaian produk dengan menghilangkan bagian yang tidak diinginkan atau memberikan bentuk akhir yang diinginkan pada bahan tersebut.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2631, 4, 1, '132070107044', 'Kampimeter', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2632, 11, 1, '132080137043', 'Mesin Gergaji Pola Acuan', 'peralatan yang digunakan untuk memotong atau menyesuaikan pola acuan atau cetakan yang digunakan dalam proses pembuatan produk dari bahan-bahan tersebut.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2633, 11, 1, '132080137046', 'Hydrolic Ironing Embossing Press', 'peralatan yang digunakan dalam industri kulit, karet, dan plastik untuk melakukan proses ironing atau pelurusan dan embossing pada bahan tersebut dengan menggunakan tekanan hidrolik.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2634, 11, 1, '132080137052', 'Alat Press Laminasi', 'peralatan yang digunakan untuk menggabungkan beberapa lapisan bahan menjadi satu lapisan tunggal dengan menggunakan tekanan dan panas. proses laminasi sering digunakan untuk membuat material yang lebih kokoh, tahan air, atau untuk menciptakan tekstur atau pola tertentu pada bahan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2635, 11, 1, '132080137054', 'Alat Potong Plastik', 'Beberapa jenis alat potong plastik yang umum digunakan meliputi:\n\nMesin Pemotong CNC: Mesin dengan kontrol numerik komputer yang dapat diprogram untuk memotong bahan plastik dengan akurasi tinggi sesuai dengan desain yang diinginkan.\n\nPemotong Laser: Alat yang menggunakan teknologi laser untuk memotong bahan plastik dengan presisi tinggi.\n\nPemotong Pisau atau Cetakan: Alat potong manual atau semi-otomatis yang menggunakan pisau atau cetakan khusus untuk memotong plastik menjadi bentuk atau ukuran yang diinginkan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2636, 4, 1, '132070107048', 'Alat Enoscope Persipan Lazer', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2637, 11, 1, '132080137058', 'Mesin Potong Hardboard', 'peralatan yang dikhususkan untuk memotong bahan hardboard dengan presisi dan akurasi tinggi. Hardboard adalah bahan yang terbuat dari serat kayu yang dipadatkan menjadi lembaran yang kuat.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2638, 11, 1, '132080137060', 'Mesin Bending', 'peralatan yang digunakan untuk membentuk atau memanipulasi bahan-bahan tersebut menjadi bentuk tertentu dengan cara membengkokkannya atau melengkungkannya.\n\nPeralatan ini dapat mencakup berbagai jenis mesin, seperti:\n\nMesin Bending Logam: Untuk membengkokkan atau melengkungkan lembaran logam seperti baja atau aluminium, mesin ini menggunakan tekanan untuk membentuk material menjadi bentuk yang diinginkan.\n\nMesin Bending Plastik: Peralatan ini khusus digunakan untuk membengkokkan atau membentuk bahan plastik dengan presisi, dan bisa menggunakan teknologi pemanasan atau tekanan untuk membentuknya.\n\nMesin Bending Karet atau Kulit: Untuk membentuk material karet atau kulit menjadi bentuk yang diinginkan, mesin ini menggunakan teknik pemanasan atau tekanan sesuai dengan karakteristik khusus dari bahan tersebut.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2639, 11, 1, '132080137061', 'Mesin Granding Super Lince', 'peralatan yang umumnya digunakan untuk menghaluskan atau menggerinda bahan-bahan seperti logam, plastik, karet, atau kulit. Mesin ini menggunakan roda gerinda atau batu gerinda untuk menghilangkan material dari benda kerja dan mencapai tingkat kehalusan atau bentuk yang diinginkan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2640, 4, 1, '132070107051', 'Arhtimula Modul', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2641, 11, 1, '132080137063', 'Mesin Tanda / Cap', 'peralatan yang digunakan untuk mencetak atau menandai permukaan bahan tersebut dengan pola atau identifikasi tertentu.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2642, 4, 1, '132070107052', 'Aryttonia Control Diting System', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2643, 11, 1, '132080137064', 'Mesin Bording', 'peralatan yang digunakan dalam industri tekstil, terutama dalam proses pembuatan tekstil dan bahan kulit, untuk menambahkan atau mengaplikasikan dekorasi atau detail khusus pada bahan tersebut. Proses bording melibatkan penambahan elemen dekoratif seperti benang, pola, ornamen, atau detil lainnya ke permukaan bahan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2644, 11, 1, '132080137065', 'Mesin Mixer Coumpond', 'peralatan yang digunakan untuk mencampur bahan-bahan dalam jumlah yang tepat dan merata untuk menciptakan kompon atau campuran tertentu yang akan digunakan dalam produksi.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2645, 11, 1, '132080138001', 'Tensile Strength Tester', 'alat laboratorium yang umumnya digunakan dalam uji kulit, karet, dan plastik untuk mengukur kekuatan tarik atau kekuatan yang diperlukan untuk menarik atau meregangkan sampel bahan hingga pecah. Alat ini membantu untuk menentukan seberapa kuat atau tahan bahan tersebut terhadap tegangan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2646, 11, 1, '132080138002', 'Alat Uji Penyerapan Air / Udara', 'perangkat yang digunakan untuk mengukur kemampuan bahan tertentu dalam menyerap air atau udara.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2647, 11, 1, '132080138003', 'Contilever Tensiometer', 'alat laboratorium yang digunakan untuk mengukur kekuatan tarik bahan, seperti karet, kulit, atau plastik dengan menggunakan prinsip mekanika kontilever. Alat ini membantu dalam menentukan seberapa kuat atau seberapa tahan suatu bahan terhadap tegangan atau tarikan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2648, 4, 1, '132070107057', 'Chinrest For Above', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2649, 11, 1, '132080138008', 'Alat Uji Kebocoran Air Untuk Glove', 'perangkat yang digunakan untuk menguji kebocoran pada sarung tangan, khususnya yang digunakan dalam berbagai aplikasi seperti medis, laboratorium, atau industri.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2650, 11, 1, '132080138012', 'Melt Indexer (Alat Laboratorium Uji Kulit, Karet Dan Plastik)', 'alat laboratorium yang digunakan untuk mengukur laju aliran plastis atau viskositas material plastik saat dalam kondisi cair atau meleleh (melted). Alat ini digunakan khususnya dalam pengujian bahan plastik untuk menentukan seberapa baik atau seberapa mudah bahan tersebut bisa dicetak atau diproses dalam proses pembentukan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2651, 4, 1, '132070107059', 'Curve Catarac Fraco', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2652, 11, 1, '132080138014', 'Compression Set Apparatus', 'alat laboratorium yang digunakan untuk mengukur tingkat elastisitas dan perubahan dimensi pada bahan karet setelah terkena tekanan atau kompresi dalam jangka waktu tertentu. Biasanya, bahan karet atau bahan elastomer setelah dipadatkan atau ditekan dalam waktu tertentu cenderung mempertahankan bentuk baru tersebut atau kembali ke bentuk aslinya setelah tekanan dihilangkan. Kemampuan untuk kembali ke bentuk semula setelah kompresi merupakan sifat yang penting dalam aplikasi yang membutuhkan elastisitas atau peredaman seperti dalam peralatan teknik, otomotif, atau bahkan dalam produk-produk sehari-hari seperti segel atau peredam.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2653, 11, 1, '132080138016', 'Alat Uji Keretakan Kulit', 'perangkat laboratorium yang digunakan untuk mengevaluasi resistensi kulit terhadap keretakan atau retak. Dalam konteks laboratorium uji kulit, karet, dan plastik, alat ini membantu dalam menilai ketahanan kulit terhadap keretakan yang bisa disebabkan oleh tekanan, peregangan, atau penggunaan dalam kondisi tertentu.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2654, 4, 1, '132070107061', 'Fiber Optic Molary Autroscope', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2655, 11, 1, '132080138017', 'Alat Pelubang Mata Ayam', 'Alat Pemasang Mata ayam adalah peralatan yang berfungsi untuk memudahkan pemasangan mata ayam pada media kertas, kulit, kain, dan plastik dengan hasil yang rata dan bagus', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2656, 11, 1, '132080138020', 'Alat Uji Falling Weight', 'digunakan untuk mengukur resistensi atau kekuatan tertentu dari bahan terhadap dampak atau tekanan tertentu yang diberikan oleh benda yang jatuh (weight) dari ketinggian tertentu.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2657, 11, 1, '132080138022', 'Ross Plexing Machine', 'dirancang untuk menentukan ketahanan elastomer vulkanisir atau sintetis untuk memotong pertumbuhan. Sistem ini melakukannya di bawah pelenturan tekuk secara terus-menerus dalam 90°.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2658, 4, 1, '132070107064', 'Finohito Reb Pataktor', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2659, 11, 1, '132080138024', 'Smaal Mixing Test Roll', 'digunakan untuk mencampur dan meratakan bahan karet atau plastik dalam skala kecil sebelum proses produksi dalam skala besar.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2660, 4, 1, '132070107065', 'Grate Meter Opter', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2661, 11, 1, '132080138026', 'Alat Uji Pantul Bola', 'perangkat yang digunakan untuk mengukur tingkat elastisitas atau kekakuan dari bahan seperti karet, plastik, atau bahan elastomer lainnya.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2662, 4, 1, '132070107066', 'Handle Recor Cable Battery + Charge', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2663, 11, 1, '132080138027', 'Lestometer', 'alat pengukur yang digunakan untuk mengukur kekuatan lensa oftalmik. Alat ini umumnya digunakan dalam optometri atau optik untuk mengukur kekuatan lensa kacamata yang diperlukan oleh seseorang.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2664, 11, 1, '132080138029', 'Deal Tickness Gauge', 'digunakan dalam industri kulit, karet, dan plastik untuk mengukur ketebalan bahan dengan akurasi tertentu.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2665, 4, 1, '132070107068', 'Heberat Indu Optimalmik Photo Cucglator Hazer 930', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2666, 11, 1, '132080138030', 'Pompa Airasil', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2667, 4, 1, '132070107069', 'Hertel', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2668, 11, 1, '132080138032', 'Top Loading Balance (Alat Laboratorium Uji Kulit, Karet Dan Plastik)', 'perangkat yang digunakan untuk mengukur massa atau berat suatu benda dengan presisi tinggi', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2669, 4, 1, '132070107070', 'Iridectomy Instrument Set', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2670, 11, 1, '132080139002', 'Alat Uji Kejut Suhu', 'digunakan dalam laboratorium uji keramik untuk menguji ketahanan material terhadap perubahan suhu secara mendadak. Proses ini mensimulasikan kondisi ekstrem yang dapat terjadi pada material, seperti keramik, ketika terkena perubahan suhu yang drastis, misalnya dari suhu tinggi ke suhu rendah dengan cepat.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2671, 11, 1, '132080139005', 'Alat Uji Deviasi Optik', 'perangkat yang digunakan untuk mengukur kemampuan material optik (seperti kaca atau keramik) dalam mempertahankan sifat optiknya, seperti transparansi atau indeks bias cahaya, pada kondisi tertentu.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2672, 4, 1, '132070107072', 'Keratoplasty Instrument Set', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2673, 11, 1, '132080139008', 'Alat Uji Tegangan Dalam Gelas', 'perangkat yang digunakan untuk menguji kekuatan atau tahanan tarik dari material gelas. Proses pengujian ini bertujuan untuk mengetahui seberapa kuat gelas tersebut dan seberapa besar beban atau tegangan yang dapat ditahan sebelum pecah atau retak.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2674, 11, 1, '132080139010', 'Alat Uji Ketepatan Bentuk', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2675, 11, 1, '132080139011', 'Alat Uji Keausan Pasir Jatuh', 'perangkat yang digunakan untuk mengukur resistensi aus atau abrasi pada permukaan material seperti keramik. Proses pengujian ini mensimulasikan kondisi ketika material terkena abrasi atau gesekan konstan, seperti yang dapat terjadi dalam lingkungan yang keras atau saat digunakan dalam jangka waktu yang lama.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2676, 11, 1, '132080139012', 'Alat Uji Tembus Listrik', 'perangkat yang digunakan dalam laboratorium uji keramik untuk menguji kekuatan dielektrik atau kemampuan isolasi material keramik terhadap arus listrik atau tegangan tinggi.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2677, 11, 1, '132080139014', 'Alat Uji Refleksi Kaca', 'Gloss meter digunakan untuk mengukur tingkat kilap atau kecerahan permukaan material, termasuk marmer. Pengukuran kilap penting dalam industri marmer karena dapat mempengaruhi penampilan dan estetika produk akhir.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2678, 11, 1, '132080139016', 'Alat Uji Kekuatan Glasir (Glaze Strength Tester)', 'alat atau instrumen yang digunakan dalam industri keramik untuk mengukur kekuatan atau ketahanan glasur pada produk keramik. Glasur adalah lapisan kaca yang diterapkan pada keramik untuk memberikan permukaan yang halus, dekoratif, dan seringkali melindungi.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2679, 11, 1, '132080139017', 'Alat Uji Analisa Oksida Logam-Logam (Spektofotometer)', 'Alat untuk mengukur konsentrasi logam-logam tertentu dalam suatu larutan berdasarkan serapan cahaya yang dihasilkan oleh atom-atom logam tersebut.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2680, 4, 1, '132070107079', 'Opthalmic Micro Dia Therimy', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2681, 11, 1, '132080139018', 'Alat Uji Analisa Butiran Bahan (Laboratory Testing Screen)', 'Alat uji analisis butiran bahan yang sering digunakan adalah mikroskop. Mikroskop memungkinkan pengamatan butiran atau partikel bahan dalam detail tinggi di tingkat mikroskopis. Ada beberapa jenis mikroskop yang dapat digunakan untuk analisis butiran bahan, di antaranya: Mikroskop Optis (Mikroskop Cahaya), Mikroskop Elektron,Mikroskop Elektron:\n\n\n\n dan alata lainya', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2682, 11, 1, '132080139019', 'Alat Uji Kekentalan Bahan', 'Viskosimeter digunakan untuk mengukur viskositas atau kekentalan suatu bahan, termasuk bahan keramik dalam bentuk cairan. Kekentalan sangat penting dalam proses manufaktur keramik, karena dapat memengaruhi kemudahan pengolahan dan kualitas produk akhir.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2683, 12, 1, '132080140001', 'Hend Help Uv Lamp', 'lampu ultraviolet (UV) yang dapat dipegang atau dioperasikan dengan tangan. Lampu UV adalah lampu yang menghasilkan sinar ultraviolet, yang memiliki berbagai aplikasi dalam berbagai bidang.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2684, 12, 1, '132080140002', 'Alat Pemutih Pulp Dengan Oxygen', 'Alat pemutih pulp dengan oksigen adalah peralatan yang digunakan dalam industri kertas dan selulosa untuk memutihkan pulp kertas menggunakan oksigen sebagai bahan pemutih. Proses pemutihan pulp kertas sangat penting dalam menghasilkan produk kertas berkualitas tinggi.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
