	(2705, 12, 1, '132080141009', 'Alat Simulasi Transportasi', 'Transportasi merupakan salah satu aset pembangunan yang berperan penting dalam sektor pertanian. karena transportasi mampu meningkatkan akses masyarakat untuk memenuhi kebutuhan barang dan jasa, memperluas area pemasaran, dan meningkatkan kapabilitas serta perekonomian petani.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2706, 12, 1, '132080141010', 'Amino Acid Analyzer (AAA)', 'Amino Acid Analyzer (AAA) adalah instrumen laboratorium yang digunakan untuk mengidentifikasi dan mengukur konsentrasi asam amino dalam sampel. Asam amino adalah blok bangunan protein, dan analisis mereka adalah penting dalam berbagai bidang penelitian, seperti biologi molekuler, biokimia, nutrisi, dan ilmu farmasi.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2707, 12, 1, '132080141013', 'Anaerobic Jar Oxide', 'Anaerobic Jar Oxide adalah alat laboratorium pertanian yang digunakan untuk mengisolasi dan menkultur bakteri anaerob. Alat ini terdiri dari botol gelas tertutup yang dilengkapi dengan pompa vakum dan tabung reaksi berisi media kultur anaerob.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2708, 12, 1, '132080141014', 'Analitycal Balance', 'Analytical Balance (Analytical Scale atau Timbangan Analitik) adalah alat laboratorium yang digunakan untuk mengukur massa atau berat sampel dengan presisi tinggi. Alat ini biasanya digunakan dalam laboratorium pertanian, kimia, farmasi, dan bidang ilmiah lainnya di mana pengukuran yang sangat akurat diperlukan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2709, 12, 1, '132080141016', 'Atomic Absorption Spectrophotometer (AAS) (Alat Lab. Pertanian)', 'Analytical Balance (Analytical Scale atau Timbangan Analitik) adalah alat laboratorium yang digunakan untuk mengukur massa atau berat sampel dengan presisi tinggi. Alat ini biasanya digunakan dalam laboratorium pertanian, kimia, farmasi, dan bidang ilmiah lainnya di mana pengukuran yang sangat akurat diperlukan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2710, 12, 1, '132080141017', 'Auto Anylyzer', 'perangkat atau sistem otomatis yang digunakan untuk melakukan analisis kimia otomatis pada sampel air atau larutan. Ini biasanya digunakan di laboratorium pertanian, lingkungan, dan laboratorium kimia lainnya.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2711, 12, 1, '132080141019', 'Autoclave (Alat Laboratorium Pertanian)', 'Autoclave adalah perangkat atau alat yang sering digunakan di laboratorium pertanian dan laboratorium ilmiah lainnya. Ini adalah alat sterilisasi yang dapat membunuh mikroorganisme dan spora bakteri dengan menghasilkan kondisi panas dan tekanan tinggi. Autoclave biasanya digunakan untuk sterilisasi peralatan laboratorium, media pertumbuhan mikroba, dan sampel lainnya yang memerlukan keadaan steril.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2712, 12, 1, '132080141023', 'Biofreezer', 'alat yang digunakan untuk mendinginkan tanaman. Alat ini menggunakan cairan pendingin, seperti air atau nitrogen cair, untuk menurunkan suhu tanaman.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
