	(2827, 12, 1, '132080141162', 'Microscope Flourescence', 'Mikroskop Fluoresensi merupakan salah satu jenis mikroskop yang digunakan untuk visualisasi sampel dari sinyal fluoresensi.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
