	(2847, 4, 1, '132070108093', 'Gredesan', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2848, 12, 1, '132080141185', 'Oxigenmeter', 'Oxygen meter atau oksigen meter dalam konteks laboratorium pertanian digunakan untuk mengukur kadar oksigen dalam berbagai media, seperti air, tanah, atau larutan nutrisi. Pengukuran kadar oksigen dapat memberikan informasi penting terkait kesehatan lingkungan pertanian, khususnya di bidang akuakultur, hidroponik, atau penelitian tanah. Berikut beberapa tipe umum dari oksigen meter yang digunakan di laboratorium pertanian: Oxygen Meter Elektrokimia, Oxygen Meter Optik, Oxygen Meter Galvanik, Oxygen Meter Dissolved Oxygen (DO).', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
