	(2850, 12, 1, '132080141186', 'Pasteurisasi Unit', 'Dalam konteks laboratorium pertanian, pasteurisasi unit atau alat pasteurisasi sering digunakan untuk menghasilkan sampel pasteurisasi yang dapat digunakan dalam penelitian atau uji coba pertanian. Proses pasteurisasi pada umumnya melibatkan pemanasan bahan atau cairan pada suhu tertentu untuk membunuh atau mengurangi jumlah mikroorganisme patogen dan spoilage tanpa merusak sifat kimia atau nutrisi utama dari bahan tersebut. Beberapa contoh unit pasteurisasi meliputi: Pasteurisasi Susu, Pasteurisasi Jus, Pasteurisasi Telur', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2851, 12, 1, '132080141187', 'Pelleting Machine', 'Mesin Pelet atau Pelleting Machine adalah perangkat mekanis yang digunakan untuk menghasilkan pelet, yaitu bongkahan kecil atau bulat dari bahan baku serbuk kayu, jerami, biomassa, pakan ternak, atau bahan lainnya', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(2852, 12, 1, '132080141188', 'Penetrometer (Alat Laboratorium Pertanian)', 'Penetrometer adalah alat yang digunakan untuk mengukur kekuatan atau konsistensi suatu bahan dengan cara menusuk atau menekan bahan tersebut dengan ujung berbentuk kerucut', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
