	(3016, 12, 1, '132080141405', 'Alat Pengolahan Pupuk Organik', 'Alat Pengolah Pupuk Organik merupakan mesin atau alat pencacah pupuk organik, fungsinya memotong, menghancurkan dan menghaluskan jerami,daun dan bahan organik lain sebagai bahan pupuk organik ataupun pakan ternak', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3017, 12, 1, '132080141407', 'Rak Pengering', 'Rak Pengering Laboratorium adalah papan pasak laboratorium digunakan untuk menggantung dan melepaskan barang pecah belah di laboratorium', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3018, 12, 1, '132080141411', 'Vertical Continue Sealing Machine', 'Continuous Band Sealer Vertical Machine atau Mesin Band Sealer adalah mesin pengemas dan penyegel yang biasanya digunakan untuk menyegel produk yang kemasannya terbuat dari jenis bahan thermoplastik', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3019, 12, 1, '132080142001', 'Alat Ukur', 'Dalam laboratorium elektronika dan daya, terdapat berbagai alat ukur yang digunakan untuk mengukur dan menganalisis sinyal listrik, daya, dan karakteristik komponen elektronika', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3020, 12, 1, '132080142002', 'Perkakas', 'perkakas atau peralatan umum yang digunakan pada lab elektronika dan daya', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3021, 5, 1, '132070110047', 'Rubber Gloves 7-7,5', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3022, 12, 1, '132080143001', 'Fotovol (Sel Surya)', 'Fotovoltaik adalah perangkat pengubahan energi dari sinar matahari menjadi energi listrik secara langsung', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3023, 12, 1, '132080143002', 'Alat Pemanas Surya', 'Sistem Pemanas Air Energi surya atau Solar Water Heating System (SWHS) adalah perangkat yang menggunakan energi surya untuk menghasilkan air panas', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3024, 12, 1, '132080144001', 'Alat Pembakaran', 'Dalam konteks laboratorium yang bekerja dengan biomassa, ada beberapa alat pembakaran atau perangkat yang dapat digunakan untuk mempelajari karakteristik pembakaran, mengukur emisi, atau melakukan uji lainnya terkait biomassa', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3025, 12, 1, '132080144002', 'Alat Pencairan', 'Dalam konteks konversi batubara dan biomassa di laboratorium, beberapa alat dan perangkat mungkin digunakan untuk mempelajari proses pencairan atau konversi termal. Proses ini melibatkan pemanasan bahan baku seperti batubara atau biomassa pada suhu tinggi tanpa udara atau dengan oksigen terbatas untuk menghasilkan gas, cairan, dan residu padat.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3026, 12, 1, '132080145001', 'Turbidity Meter', 'Turbidity Meter adalah alat yang digunakan untuk mengukur kekeruhan air atau suatu larutan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3027, 12, 1, '132080145002', 'Radio Activity Demonstrator', 'Radioactivity Demonstrator adalah alat yang digunakan untuk mendemonstrasikan sifat-sifat radioaktivitas', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3028, 12, 1, '132080145003', 'Flow Analysis Sistem', 'Flow Analysis System dalam konteks oceanografi mungkin dirancang untuk memantau parameter lingkungan tambahan seperti suhu air, salinitas, atau kejernihan air. Sistem ini dapat digunakan untuk memahami perilaku air di berbagai kondisi dan dapat membantu dalam penelitian terkait dinamika laut, perubahan iklim, dan ekologi akuatik.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3029, 12, 1, '132080145005', 'Protector', 'Alat pelindung laboratorium kelautan adalah peralatan yang dirancang untuk melindungi peneliti dan sampel dari kontaminasi silang dan untuk memastikan keamanan selama eksperimen atau penelitian di laboratorium. Beberapa alat pelindung umum dalam laboratorium kelautan melibatkan kontrol lingkungan dan keamanan pribadi.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3030, 12, 1, '132080145009', 'Towing Depth Distance Recorder', 'Dalam konteks laboratorium oceanografi atau penelitian laut, "Towing Depth Distance" dapat merujuk pada jarak atau kedalaman tertentu dari permukaan laut di mana suatu instrumen atau sensor ditarik atau digunakan untuk mengumpulkan data. Ini sering kali terkait dengan kebutuhan untuk menyelidiki berbagai parameter atau kondisi di lapisan air tertentu.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3031, 12, 1, '132080145013', 'Theodolit', 'Theodolit adalah alat pengukur sudut yang biasanya digunakan dalam survei dan pemetaan. Di laboratorium kelautan, theodolit juga dapat memiliki beberapa fungsi, terutama terkait dengan pemetaan dan survei dalam konteks lingkungan laut. Beberapa fungsi theodolit di laboratorium kelautan melibatkan pengukuran sudut dan elevasi yang akurat untuk berbagai keperluan, seperti; dalam Penelitian Oseanografi: Theodolit dapat digunakan dalam penelitian oseanografi untuk mengukur elevasi dan sudut yang diperlukan untuk memahami arus laut, pola gelombang, dan fenomena lainnya di laut.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3032, 12, 1, '132080145014', 'Automatic Level', 'alat yang digunakan untuk mengukur elevasi atau perbedaan ketinggian di atas permukaan tanah atau laut. Ini adalah instrumen pengukuran yang umumnya digunakan di berbagai bidang, termasuk konstruksi, survei, dan dalam konteks ini, mungkin juga digunakan di laboratorium kelautan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3033, 5, 1, '132070110058', 'Ear Speculum Set', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3034, 12, 1, '132080145020', 'Thermometer Protected', 'alat ini digunakan untuk mengukur suhu air atau suhu udara di lingkungan laut.lingkungan yang keras dan korosif di laut. pada dasarnya berfungsi sama untuk mengukur suhu, yg  membedakan dengan temometer lain karena penggunannya di laut maka harus dirancang dan dilindungi dengan baik untuk mengatasi kondisi lingkungan yang keras dan korosif di laut.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3035, 12, 1, '132080145023', 'Kompas (Alat Laboratorium Oceanografi)', 'Kompas adalah alat navigasi yang digunakan untuk menentukan arah di laut', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3036, 5, 1, '132070110060', 'Rectal Magnifier With Lamp', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3037, 12, 1, '132080145024', 'Stereoscope', 'stereoscope dapat digunakan untuk memeriksa dan menganalisis sampel laut, seperti plankton atau organisme mikroskopis lainnya.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3038, 5, 1, '132070110061', 'Rectal Tougies Hegar Dilatator Set', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3039, 12, 1, '132080145027', 'Hand Auger Kit', 'alat bor yang dioperasikan secara manual tanpa menggunakan sumber daya listrik atau mesin. Alat ini biasanya digunakan untuk melakukan pengeboran lubang di tanah atau material lainnya. Hand auger memiliki desain yang sederhana, dan seringkali digunakan dalam pekerjaan lapangan, pertanian, penelitian tanah, atau kegiatan geologis.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3040, 12, 1, '132080145031', 'Hot Plate Stirrer', 'HJotplate Stirrer adalah alat laboratorium yang memiliki alas datar seperti piring yang digunakan untuk memanaskan atau mencampur bahan hingga homogen melalui proses pengadukan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3041, 5, 1, '132070110063', 'Stomach Irrigator', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3042, 12, 1, '132080145032', 'Sieve Shaker (Alat Laboratorium Oceanografi)', 'perangkat yang digunakan di laboratorium, termasuk dalam konteks oceanografi, untuk melakukan pengayakan atau penyaringan bahan-bahan seperti pasir, sedimen, batu, atau sampel lainnya dalam berbagai ukuran partikel.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3043, 12, 1, '132080145033', 'Cutting Machine', 'alat yang digunakan untuk memotong bahan secara presisi dan dalam jumlah besar.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3044, 12, 1, '132080145037', 'Diamond Saw', 'jenis gergaji yang menggunakan mata gergaji yang dilapisi dengan potongan-potongan berlian untuk memotong bahan yang sangat keras atau abrasif. Gergaji ini menggunakan berlian sebagai material potongnya karena kekerasan alami berlian yang sangat tinggi, membuatnya cocok untuk memotong bahan-bahan yang sulit diolah seperti batu, beton, keramik, kaca, logam keras, dan bahan komposit yang kuat.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3045, 12, 1, '132080146001', 'Flourometer', 'alat laboratorium yang digunakan untuk mengukur atau mendeteksi jumlah fluoresensi yang dihasilkan oleh suatu substansi atau sampel. Fluoresensi adalah fenomena di mana suatu zat menyerap energi cahaya pada satu panjang gelombang tertentu dan kemudian memancarkan energi tersebut sebagai cahaya pada panjang gelombang yang lebih panjang.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3046, 12, 1, '132080146002', 'Water Quality Checker', 'alat atau perangkat yang digunakan untuk menguji dan memantau kualitas air. Tujuan utamanya adalah untuk mengukur berbagai parameter dan komponen kimia, fisika, dan biologis dalam air guna menilai tingkat kebersihan, keamanan, dan kesesuaian air untuk berbagai keperluan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3047, 12, 1, '132080146003', 'Disolved Oksigen Analyzer', 'alat atau perangkat yang digunakan untuk mengukur konsentrasi oksigen terlarut (DO) dalam air atau larutan. Ketersediaan oksigen terlarut dalam air sangat penting bagi kehidupan organisme akuatik seperti ikan, plankton, dan makhluk hidup lainnya yang hidup di dalam air.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3048, 12, 1, '132080146004', 'Atomic Absorption Spectrophotometer (AAS) (Alat Lab. L. Perairan)', 'instrumen laboratorium yang digunakan untuk menganalisis konsentrasi unsur kimia dalam sampel larutan. Alat ini bekerja berdasarkan prinsip absorpsi atom, yang menggunakan cahaya untuk mengukur konsentrasi unsur-unsur spesifik dalam sampel cairan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3049, 12, 1, '132080146006', 'Conductivity Salinity Analyzer', 'alat atau perangkat yang digunakan untuk mengukur konduktivitas listrik dan konsentrasi garam (salinitas) dalam air atau larutan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3050, 12, 1, '132080146009', 'Radio Meter (Alat Laboratorium Lingkungan Perairan)', 'adalah instrumen kelas meteorologi kokoh yang mengukur radiasi matahari UVB berbobot eritema di luar ruangan dan di bawah air', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3051, 12, 1, '132080146010', 'Gas Chromatograph Mass Spectrometer System (GCMSS)', 'dalah sistem analitik yang menggabungkan dua teknik analisis kimia yang kuat: kromatografi gas (GC) dan spektrometri massa (MS).', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3052, 5, 1, '132070110073', 'Hi-Flow Antibiotic Nebulizer Solution Unit', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3053, 12, 1, '132080146013', 'Lux Meter (Alat Laboratorium Lingkungan Perairan)', 'perangkat pengukur intensitas cahaya atau iluminasi. Satuan pengukuran yang digunakan disebut lux, yang mengukur seberapa terang atau seberapa banyak cahaya yang mencapai suatu permukaan atau area tertentu.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3054, 12, 1, '132080146015', 'Zoo Bell Sampler Bacteriological', 'peralatan atau alat pengambil sampel air atau sampel lingkungan yang digunakan dalam studi bakteriologi di bidang ilmu lingkungan atau laboratorium. Namun, istilah ini tidak umum dan mungkin merujuk pada produk atau peralatan tertentu yang digunakan untuk mengumpulkan sampel air atau lingkungan tertentu.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3055, 12, 1, '132080146017', 'Light Weight Hand Winch With Boom', 'perangkat angkat yang ringan dengan siste', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3056, 12, 1, '132080146018', 'Productivity Kit', 'seperangkat alat, metode, panduan, atau strategi yang dirancang untuk meningkatkan produktivitas seseorang atau tim dalam lingkungan kerja atau dalam melakukan tugas tertentu. Kit ini biasanya terdiri dari kombinasi berbagai elemen yang dirancang untuk membantu individu atau tim mencapai hasil yang lebih baik atau meningkatkan efisiensi dalam melakukan pekerjaan mereka.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3057, 12, 1, '132080146019', 'Bak Aquarium', 'wadah transparan yang digunakan untuk menampung dan menampilkan kehidupan akuatik, seperti ikan, tanaman air, atau hewan-hewan kecil lainnya yang hidup di dalam air. Aquarium biasanya terbuat dari kaca atau akrilik dan dirancang untuk memberikan lingkungan yang cocok bagi makhluk-makhluk yang tinggal di dalamnya.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3058, 12, 1, '132080146020', 'Bak Porselin', 'wadah atau kontainer yang terbuat dari bahan porselen, yang merupakan jenis keramik yang sangat halus, tahan lama, dan sering digunakan dalam berbagai aplikasi di laboratorium, dapur, industri, atau pun keperluan rumah tangga.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3059, 12, 1, '132080146021', 'Bak Kultivasi', 'wadah atau tempat yang dirancang khusus untuk menumbuhkan atau membudidayakan organisme hidup, terutama dalam konteks pertanian atau akvakultur. Bak ini dapat digunakan untuk mengkultivasi berbagai jenis tanaman, mikroorganisme, atau organisme hidup lainnya sesuai dengan kebutuhan penelitian atau produksi. Bak kultivasi dapat dibuat dari berbagai bahan, termasuk plastik, beton, atau bahan lainnya yang sesuai dengan kebutuhan spesifik pertumbuhan organisme yang dibudidayakan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3060, 12, 1, '132080146022', 'Cage Net', 'struktur jaring atau rangka terbuka yang digunakan dalam berbagai konteks, terutama di bidang akuakultur atau penangkapan ikan di perairan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3061, 5, 1, '132070110081', 'Rectan Origator', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3062, 12, 1, '132080146023', 'Six Place Hydromanifolds', 'jaringan saluran atau pipa yang dirancang untuk mendistribusikan fluida dari satu sumber ke beberapa tujuan atau posisi. Keuntungan penggunaan Hydromanifolds di laboratorium perairan melibatkan efisiensi distribusi sampel, konsistensi dalam pengambilan sampel, dan kemampuan untuk mengoordinasikan atau mengarahkan aliran fluida sesuai dengan kebutuhan spesifik penelitian atau pengujian.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3063, 12, 1, '132080146024', 'Laminar Air Flow Cabinet', 'perangkat yang dirancang untuk menciptakan lingkungan kerja yang bersih dan bebas dari partikel-partikel kontaminan yang dapa', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3064, 12, 1, '132080146025', 'Rod Blower', 'SEHARUSNYA ROOT BLOWER, adalah jenis blower yang digunakan untuk memompa atau mengalirkan udara atau gas. Blower ini dikenal karena desainnya yang menggunakan lobus atau roda lobus untuk memindahkan udara atau gas melalui ruang blower. Dalam konteks laboratorium perairan atau kelautan, Roots Blower dapat digunakan untuk berbagai aplikasi; sistem pemurnian air atau instalasi pengolahan air limbah, digunakan untuk pengadukan dan pergerakan air dalam tangki eksperimen di laboratorium untuk simulasi kondisi lingkungan tertentu atau penelitian.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3065, 12, 1, '132080146027', 'Liquid Dispenser', 'perangkat yang dirancang khusus untuk mengukur dan mendistribusikan cairan dengan akurasi tinggi. Dispenser ini sering digunakan untuk menambahkan reagen, larutan standar, atau sampel ke dalam berbagai percobaan atau analisis di laboratorium perairan. Keuntungan menggunakan liquid dispenser di laboratorium perairan termasuk akurasi yang tinggi, pengulangan yang konsisten, dan mengurangi risiko kontaminasi silang.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3066, 12, 1, '132080146028', 'Rotation Evaporating', 'teknik yang umum digunakan di laboratorium untuk menghilangkan pelarut dari sampel cair dengan menggunakan evaporator rotasi atau rotary evaporator. Teknik ini digunakan terutama dalam pemurnian senyawa kimia, konsentrasi larutan, atau persiapan sampel untuk analisis lebih lanjut.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3067, 12, 1, '132080147002', 'Under Water Camera', 'Underwater Camera adalah kamera yang dirancang khusus untuk dirancang untuk penggunaan kegiatan di bawah laut', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3068, 12, 1, '132080147004', 'Alat Selam', 'Skindive atau Alat Selam Dasar adalah alat yang digunakan untuk membantu kegiatan menyelam', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3069, 5, 1, '132070111004', 'Basis Solution', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3070, 12, 1, '132080147005', 'Disecting Apparatus (Alat Laboratorium Biologi Perairan)', 'Dissecting Kit adalah seperangkat peralatan yang dirancang khusus untuk melakukan diseksi, yaitu proses pembedahan atau pembedahan pada benda atau organisme untuk tujuan penelitian atau pembelajaran', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3071, 12, 1, '132080148003', 'Tromol Herbarium', 'Vaskulum atau Kotak Botani adalah wadah keras yang digunakan oleh para ahli botani agar sampel yang diambil dari lokasi tetap hidup saat dipindahkan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3072, 12, 1, '132080148004', 'Aquarium (Alat Laboratorium Biologi)', 'Akuarium adalah sebuah wadah yang ditempatkan di sebuah tempat dengan sisi yang transparan, di dalamnya satwa dan tumbuhan air ditampung, dan digunakan untuk display publik.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3073, 12, 1, '132080148005', 'Alat Perangkap Binatang', 'berbagai alat perangkap binatang yang digunakan untuk menangkap, menyimpan, atau mengamati hewan hidup untuk tujuan penelitian atau pendidikan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3074, 12, 1, '132080148006', 'Alat Perekat Alumunium Foil', 'Pita Perekat Aluminium Foil adalah bahan tahan air-perekat yang memiliki daya rekat yang baik dan dapat menempel pada sebagian besar substrat dan mudah diaplikasikan pada saluran berserat dan lembaran logam pada permukaan yang tidak beraturan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3075, 12, 1, '132080148007', 'Counting Cel', 'Cell Counter atau Alat Penghitung Sel adalah alat yang digunakan untuk menghitung sel-sel darah', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3076, 5, 1, '132070111010', 'Suture Needle', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3077, 12, 1, '132080148013', 'Automatic Area Meter', 'GPS Land Meter merupakan perangkat yang menggunakan sistem GPS (Global Positioning System) untuk mengukur atau memetakan lahan atau area tertentu', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3078, 12, 1, '132080149001', 'Land Gravity Meter', 'Land Gravity Meter adalah alat untuk mengukur percepatan gravitasi bumi', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3079, 5, 1, '132070111012', 'Michel Wound Clips Steel To Container Record', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3080, 12, 1, '132080149004', 'Physical Property', 'Jika dikaitkan dengan BMD maka semua peralatan pada lab geofisika untuk mengukur ukuran massa batu, sifat batuan, Kekuatan atau ketahanan batuan, Ukuran respons magnetik suatu bahan terhadap medan magnet eksternal.\nDalam konteks laboratorium geofisika, beberapa physical property dari batuan atau bahan geologis yang sering diukur untuk memahami sifat-sifat fisiknya. Ini adalah sifat-sifat yang memberikan informasi tentang komposisi dan struktur batuan di dalam bumi.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3081, 5, 1, '132070111013', 'Syringe Container Stainless', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3082, 12, 1, '132080149006', 'Abem Sounding Cable', 'ABEM adalah salah satu perusahaan yang bergerak di bidang geofisika, jadi sounding cable merupakan produk dari ABEM yang digunakan untuk mentransfer sinyal arus dan ptensial dari pengukur resistivitas ke tanah', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3083, 5, 1, '132070111014', 'Syringe Tuberculine 1 ml', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3084, 12, 1, '132080149007', 'Densitylog Module', 'Modul yang menjelaskan tentang tehnik eksplorasi sumur minyak dan gas untuk mengukur densitas batuan di sekitar sumur. Log ini memberikan informasi penting tentang sifat-sifat batuan di sekitar sumur yang dapat membantu dalam evaluasi reservoir dan menentukan potensi produksi minyak dan gas.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3085, 5, 1, '132070111015', 'Case With Closing Handles 500X200X60 mm', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3086, 12, 1, '132080149008', 'Portable Digital Fluxgate Magnetometer', 'Portable Digital Fluxgate Magnetometer adalah alat yang digunakan untuk mengukur medan magnet di suatu lokasi. Fluxgate magnetometer adalah jenis magnetometer yang beroperasi berdasarkan prinsip perubahan medan magnet dalam suatu inti feromagnetik.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3087, 12, 1, '132080149009', 'Digital Thermometer', 'digital thermometer digunakan untuk mengukur suhu di sekitar peralatan atau instrumen geofisika, atau bahkan di lapangan selama pengambilan data.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3088, 5, 1, '132070111017', 'Container For Tuberculine Syringe', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3089, 12, 1, '132080149010', 'Tester Kit', 'berbagai peralatan dan instrumen yang digunakan untuk mengumpulkan data dan informasi di lapangan dalam konteks ilmu geofisika. Terdiri dari beberaoa perlatan teknis, salah satunya Seismic Refraction Kit, Ground Penetrating Radar (GPR) Kit, dll', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3090, 5, 1, '132070111018', 'Container For Syringe', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3091, 12, 1, '132080149012', 'Circuit Tester (Alat Laboratorium Geofisika)', 'peralatan atau alat yang digunakan untuk menguji sirkuit atau peralatan elektronika yang terkait dengan pengukuran geofisika. Peralatan ini membantu memastikan bahwa instrumen geofisika berfungsi dengan baik dan dapat memberikan hasil pengukuran yang akurat.\nBeberapa alat yang mungkin digunakan sebagai circuit tester di laboratorium geofisika termasuk; Digital Multimeter, Oscilloscope, Voltage and Current Source, dll', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3092, 12, 1, '132080149014', 'Magnetometer', 'Magnetometer adalah alat yang digunakan dalam laboratorium geofisika untuk mengukur medan magnetik di suatu lokasi atau area tertentu. Pengukuran medan magnetik ini dapat memberikan informasi tentang sifat-sifat magnetik batuan dan struktur bawah permukaan. Magnetometer umumnya digunakan dalam berbagai aplikasi geofisika, termasuk eksplorasi sumber daya alam, pemetaan geologi, dan penelitian lingkungan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3093, 12, 1, '132080149018', 'Proton Magnetometer Geometric', 'merupakan alat pengukur medan magnet Bumi yang bekerja berdasarkan precessional frekuensi proton-proton hidrogen dalam medan magnet eksternal.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3094, 12, 1, '132080149020', 'Portable Baoreholelogger', 'merupakan perangkat yang digunakan untuk mengukur berbagai parameter di dalam sumur bor (borehole) seperti litologi, sifat-sifat batuan, dan parameter hidrogeologi.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3095, 13, 1, '132080150002', 'Lab. Selective Mineral', 'merupakan alat yang dirancang untuk memilih atau mengisolasi mineral tertentu dari campuran mineral', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3096, 5, 1, '132070111023', 'Kelly Heam Forceps 14 cm', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3097, 13, 1, '132080150005', 'Sparator High', 'merupakan perangkat atau peralatan yang digunakan dalam industri minyak dan gas untuk memisahkan dan mengolah hidrokarbon dan fluida lainnya pada tekanan tinggi.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3098, 13, 1, '132080150006', 'Pulvarezer', 'merupakan perangkat yang digunakan di laboratorium untuk menghancurkan atau menggiling sampel-sampel bahan menjadi serbuk halus atau partikel-partikel yang lebih kecil.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3099, 13, 1, '132080150016', 'Milling Unit', 'merupakan perangkat atau sistem yang digunakan untuk melakukan proses penggilingan pada bahan atau objek tertentu.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3100, 9, 1, '132080113122', 'Cobas Chemistry Analyzer', 'merupakan alat yang digunakan untuk mengukur konsentrasi unsur kimia dalam suatu sampel larutan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3101, 5, 1, '132070111027', 'Probes 14,5 cm', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3102, 13, 1, '132080151001', 'Bucket Elevator', 'Bucket Elevator adalah alat pengangkut material curah yang ditarik oleh sabuk atau rantai tanpa ujung dengan arah lintasan yang biasanya vertikal, pada umumnya ditopang oleh casing atau rangka', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3103, 13, 1, '132080151005', 'Spray Dryer', 'Spray Dryer adalah alat yang digunakan untuk menghasilkan bubuk kering dari cairan dengan cara mengeringkannya dengan cepat menggunakan gas panas.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3104, 13, 1, '132080151008', 'Vibrating Screen (Alat Laboratorium Proses/teknik Kimia)', 'Vibrating Screen adalah alat yang digunakan untuk memisahkan ukuran material hasil proses peremukan berdasarkan besarnya ukuran dari lubang bukaan (opening) pada ayakan yang dinyatakan dengan satuan milimeter (mm) atau dapat juga dinyatakan dengan satuan mesh', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3105, 13, 1, '132080151009', 'Tungku', 'Furnace atau Tungku Pembakaran adalah sebuah perangkat yang digunakan untuk pemanasan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3106, 13, 1, '132080151011', 'Disk Mill', 'Disc Mill merupakan suatu alat penepung yang berfungsi untuk menggiling bahan kasar menjadi tepung halus, namun lebih banyak digunakan untuk menepungkan bahan yang sedikit mengandung serat dan juga suatu alat penepung yang menggunakan bahan dengan tekanan dan gesekan antara dua piringan yang satu berputar dan yang lainnya masih tetap', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3107, 13, 1, '132080151013', 'Bagging Conveyor', 'Bagging Conveyor atau Belt Conveyor adalah sebuah mesin yang digunakan untuk membantu manusia dalam mengangkut dan memindahkan barang-barang dalam jumlah yang besar menggunakan belt atau sabuk sebagai media pemindahan barangnya', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3108, 13, 1, '132080151015', 'Bag Closer', 'Bag Closer Sewing Machine adalah mesin jahit khusus yang digunakan untuk menutup atau menjahit bagian ujung kantong atau karung.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3109, 13, 1, '132080151016', 'Sterilizer (Alat Laboratorium Proses/teknik Kimia)', 'Sterilizer adalah perangkat atau sistem yang dirancang untuk melakukan sterilisasi, yaitu proses membunuh atau menghilangkan semua bentuk mikroorganisme, termasuk bakteri, virus, jamur, dan spora bakteri.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
