	(3111, 13, 1, '132080151022', 'Gentong Plastik', 'Gentong Plastik atau Tong Plastik adalah suatu wadah atau tempat yang terbuat dari bahan plastik', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3112, 13, 1, '132080151023', 'Drum Stainless Steel', 'Drum Stainless Steel merupakan drum atau tong yang terbuat dari bahan stainless steel', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3113, 13, 1, '132080151024', 'Wash Bak', 'Washback merupakan bak cuci atau tempat pencucian khusus yang digunakan dalam laboratorium dan memiliki fungsi untuk mencuci peralatan laboratorium dan bahan sampel', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
