	(3122, 13, 1, '132080152003', 'Controller Level', 'LCV atau Level Control Valve merupakan katup pengendali yang berfungsi untuk menjaga tingkat cairan dalam suatu tangki atau wadah dalam tingkatan tertentu', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3123, 13, 1, '132080152005', 'Controller Flow', 'Flow Control adalah komponen vital dalam sistem pneumatik dan hidrolik yang digunakan untuk mengontrol laju aliran fluida', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
