	(3130, 13, 1, '132080153001', 'Mobile Lab. Met System Data Logger', 'merupakan perangkat atau sistem yang dirancang untuk mencatat dan merekam data secara otomatis dari berbagai parameter atau instrumen.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
