	(3144, 13, 1, '132080153025', 'Mobile Lab. Safety Hard Hats (Topi Safety)', 'merupakan perlengkapan pelindung kepala yang dirancang untuk melindungi pekerja dari potensi bahaya di tempat kerja, seperti benda jatuh, benturan, atau tumpahan bahan kimia.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
