	(3151, 13, 1, '132080153031', 'Mobile Lab. Ph Meter Field', 'merupakan perangkat yang digunakan di lapangan atau di luar laboratorium untuk mengukur tingkat keasaman atau kebasaan (pH) suatu larutan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
