	(3155, 13, 1, '132080153037', 'Mobile Lab. Portable Refrigerator', 'merupakan lemari pendingin atau kulkas yang dirancang untuk keperluan laboratorium dan bersifat portabel, artinya dapat dipindahkan atau dibawa ke lokasi tertentu.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3156, 13, 1, '132080153039', 'Mobile Lab. Spare Bottles For Grab Samplers', 'merupakan botol cadangan yang digunakan dalam proses pengambilan sampel grab atau pengambilan sampel cepat.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3157, 13, 1, '132080153049', 'Mobile Lab. Laboratory Vehicle', 'merupakan kendaraan yang dirancang atau dimodifikasi untuk digunakan sebagai laboratorium bergerak.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3158, 13, 1, '132080153050', 'Laboratory Benching Regionals', '"Laboratory Benching" biasanya merujuk pada desain dan pengaturan meja atau bangku laboratorium untuk keperluan penelitian dan percobaan. Sementara itu, "Regionals" bisa merujuk pada suatu wilayah atau area tertentu', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3159, 13, 1, '132080153051', 'Laboratory Instrument Cabinet', 'merupakan lemari atau kabinet yang dirancang khusus untuk menyimpan dan mengorganisir instrumen laboratorium.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3160, 13, 1, '132080153052', 'Laboratory Air Conditioner 1 HP', 'merupakan sistem pendingin udara yang dirancang khusus untuk digunakan di dalam laboratorium.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3161, 13, 1, '132080153053', 'Laboratory Air Conditioner 1,50 HP', 'ni adalah unit AC yang dikhususkan untuk lingkungan laboratorium. Keberadaan laboratorium seringkali membutuhkan kontrol suhu yang ketat untuk menjaga kondisi eksperimen atau penyimpanan sampel.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3162, 13, 1, '132080153054', 'Laboratory Water Pressurising Systems', 'sistem yang dirancang untuk meningkatkan atau memberikan tekanan pada suplai air dalam konteks laboratorium. Sistem ini dapat digunakan untuk memberikan tekanan air yang stabil dan sesuai dengan kebutuhan eksperimen atau proses laboratorium tertentu', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3163, 13, 1, '132080153055', 'Laboratory Emergency Shower/Eyewash', 'perangkat darurat yang dipasang di laboratorium untuk memberikan bantuan cepat dalam situasi darurat jika seseorang terkena bahan kimia atau zat berbahaya di tubuh mereka, terutama pada mata atau tubuh bagian atas.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3164, 13, 1, '132080153056', 'Laboratory Fridge/Freezer', 'perangkat pendingin yang dirancang khusus untuk digunakan di laboratorium. Perangkat ini memiliki fungsi dasar yang mirip dengan kulkas dan freezer rumah tangga umum, yaitu untuk menyimpan bahan atau sampel dalam suhu tertentu untuk mempertahankan kestabilan dan keandalan bahan tersebut.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3165, 13, 1, '132080153057', 'Laboratory Flammable Storage Cabinets', 'perangkat penyimpanan khusus yang dirancang untuk menyimpan bahan-bahan yang mudah terbakar atau bersifat flammable di dalam laboratoriu', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3166, 13, 1, '132080153058', 'Laboratory Acid Storage Cupboard', 'kabinet penyimpanan yang dirancang khusus untuk menyimpan asam di laboratorium. Lemari ini dibuat dengan material yang tahan terhadap korosif, dan dirancang untuk memberikan perlindungan terhadap bahaya yang mungkin timbul akibat asam yang disimpan di dalamnya.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3167, 5, 1, '132070112021', 'Faradisasi', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3168, 13, 1, '132080153059', 'Laboratory Incubator', 'perangkat yang digunakan dalam laboratorium untuk menyediakan kondisi lingkungan yang terkendali untuk pertumbuhan dan perkembangan mikroorganisme, sel, atau kultur jaringan. Incubator ini dirancang untuk menciptakan suhu, kelembaban, dan kadaran karbon dioksida (CO2) yang optimal untuk keperluan khusus, seperti kultur sel, budidaya mikroorganisme, atau eksperimen biologi lainnya.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3169, 5, 1, '132070112022', 'Finger Exercise Table', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3170, 13, 1, '132080153060', 'Laboratory Bench Stand', 'perangkat yang digunakan dalam laboratorium untuk menyediakan kondisi lingkungan yang terkendali untuk pertumbuhan dan perkembangan mikroorganisme, sel, atau kultur jaringan. Incubator ini dirancang untuk menciptakan suhu, kelembaban, dan kadaran karbon dioksida (CO2) yang optimal untuk keperluan khusus, seperti kultur sel, budidaya mikroorganisme, atau eksperimen biologi lainnya.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3171, 13, 1, '132080153061', 'Laboratory Blender Warning', 'alat laboratorium yang digunakan untuk menghomogenkan media analis atau sampel laboratorium berbentuk padatan menjadi media cair melalui proses pengadukan dan pencacahan mekanis.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3172, 13, 1, '132080153062', 'Laboratory Hardware-General Items Standards Pack', 'Dalam konteks umum laboratorium, "Hardware-General Items" bisa mencakup berbagai peralatan dan perlengkapan laboratorium umum seperti corong, corong ayun, corong pisah, spatula, jangka sorong laboratorium, tabung uji, dan berbagai item lain yang digunakan dalam kegiatan harian laboratorium', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3173, 13, 1, '132080153063', 'Laboratory Safety Manual', 'dapat berupa flyer/Banner/ gambar yang berisikan informasi panduan penyimpanan, penanganan, identifikasi resiko bahan kimia (material safety data sheet-MSDS)', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3174, 5, 1, '132070112026', 'Isostations For Accurate', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3175, 13, 1, '132080153064', 'Laboratory Chemical Pack Standards', 'wadah atau tempat menyimpan cairan kimia', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3176, 13, 1, '132080154001', 'Mangkok Porselin', 'Mortar Porselen merupakan alat laboratorium berbentuk mangkuk yang terbuat dari porselen dan digunakan untuk menggerus atau menghaluskan sampel padatan/kristal menjadi serbuk', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3177, 13, 1, '132080154004', 'Cawan Porselin', 'Krus Porselen adalah sebuah peralatan laboratorium yang berbentuk seperti cawan yang digunakan untuk menampung senyawa kimia pada proses pemanasan yang menggunakan temperatur yang sangat tinggi', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3178, 13, 1, '132080154005', 'Lumpang Keramik', 'Mortar Keramik merupakan alat laboratorium berbentuk mangkuk yang terbuat dari keramik dan digunakan untuk menggerus atau menghaluskan sampel padatan/kristal menjadi serbuk', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3179, 13, 1, '132080154006', 'Elektrode', 'Elektroda Karbon adalah bahan yang biasa digunakan sebagai konduktor arus listrik di tungku listrik dan sel elektrolisis', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3180, 13, 1, '132080154007', 'Filter Photo Meter', 'alat yang digunakan untuk menentukan kadar suatu zat dalam jumlah kecil berdasarkan daya absorbsi zat tersebut terhadap sinar UV atau sinar visible', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3181, 13, 1, '132080154009', 'Kaki Tiga', 'Kaki Tiga merupakan alat penunjang di laboratorium yang digunakan untuk menopang atau menahan alat gelas kimia seperti beaker glass, erlenmeyer atau labu selama pemanasan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3182, 5, 1, '132070112033', 'Pulsa Erator Unit', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3183, 13, 1, '132080154010', 'Rustrak Recorders', 'Chart Recorder adalah perangkat yang membaca dan menarik input ke selembar kertas bergulir', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3184, 13, 1, '132080154012', 'Bulb', 'Lampu Pijar atau Bohlam adalah sumber cahaya buatan yang dihasilkan melalui penyaluran arus listrik melalui filamen yang kemudian memanas dan menghasilkan cahaya', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3185, 13, 1, '132080154013', 'Statip', 'Statif adalah alat yang terbuat dari logam berupa besi yang berfungsi untuk menempatkan penejepit buret atau penyangga alat seperti buret atau pendingin pada teknis destilasi', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3186, 13, 1, '132080154014', 'Tempat Prepara', 'Microscope Slide Box merupakan kotak tempat penyimpanan object glass atau kaca preparat dengan bilang - bilah untuk penempatan kaca preparat sehingga rapi dalam penyimpanan serta membuat kaca preparat lebih aman dari guncangan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3187, 13, 1, '132080154015', 'Time Control', 'Timer adalah alat yang digunakan untuk mengukur waktu dalam laboratorium', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3188, 13, 1, '132080154016', 'Eye Wash', 'Eye Washer adalah pembilas mata yang berfungsi untuk meredam pengaruh bahan berbahaya dan mencegah cidera yang semakin parah', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3189, 5, 1, '132070112039', 'Suspension & Pulley Equipment', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3190, 13, 1, '132080154017', 'Thermograph (Laboratorium Kearsipan)', 'Thermograph adalah alat yang digunakan untuk merekam dan memvisualisasikan perubahan suhu dalam suatu periode waktu tertentu. Ini adalah alat yang umumnya digunakan dalam pengawasan lingkungan, pengamatan iklim, dan dalam berbagai aplikasi industri dan ilmiah lainnya.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3191, 13, 1, '132080154018', 'Tang', 'Tang adalah peralatan bengkel yang khusus digunakan untuk memegang, memotong, melepas, dan memasang bahan kerja', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3192, 13, 1, '132080154022', 'Kawat Kasa', 'Kawat Kasa merupakan lembaran-lembaran kawat tipis yang dilengkapi dengan lapisan keramik pada bagian tengahnya', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3193, 13, 1, '132080154023', 'Klem (Laboratorium Kearsipan)', 'Klem atau Clamp merupakan salah satu alat dalam laboratorium yang digunakan untuk mengklem suatu alat agar lebih kuat', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3194, 13, 1, '132080155001', 'Centrifuge Heamatocrite', 'Hematocrit Centrifuge adalah alat laboratorium yang digunakan untuk memisahkan partikel - partikel dalam suatu larutan yaitu darah yang mempunyai berat molekul yang berbeda.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3195, 13, 1, '132080155002', 'Haemocitometer', 'Hemasitometer adalah suatu alat yang dapat digunakan untuk melakukan perhitungan sel secara cepat dan dapat digunakan untuk konsentrasi sel yang rendah', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3196, 13, 1, '132080155004', 'Heamtology Analyzer', 'Hematology Analyzer merupakan alat yang digunakan untuk memeriksa darah lengkap dengan cara menghitung dan mengukur sel darah secara otomatis berdasarkan impedansi aliran listrik atau berkas cahaya terhadap sel-sel yang di lewatkan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3197, 5, 1, '132070113002', 'Echo Encephalograph', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3198, 13, 1, '132080155005', 'Chemistry Analyzer', 'Chemistry Analyzer merupakan alat laboratorium yang dirancang untuk menentukan konsentrasi metabolit tertentu, elektrolit, protein, dan atau obat di dalam serum, plasma, urin, cairan serebrospinal dan atau cairan tubuh lain', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3199, 13, 1, '132080155006', 'Coagulation Timer (Laboratorium Hematologi & Urinalisis)', 'Coagulation Timer adalah perangkat atau sistem yang digunakan untuk mengukur waktu pembekuan atau koagulasi dalam darah', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3200, 13, 1, '132080155007', 'Laboratory Refrigerator', 'Laboratory Refrigerator adalah peralatan pendingin khusus untuk penyimpanan dingin obat-obatan serta produk biologi dan sebagainya', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3201, 13, 1, '132080155008', 'Rotator Shaker (Laboratorium Hematologi & Urinalisis)', 'Shaker Rotatoradalah alat yang digunakan untuk mengaduk atau mencampur suatu larutan dengan larutan yang lain sehingga bersifat homogen dengan gerakan satu arah', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3202, 5, 1, '132070113006', 'Brain Mapping', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3203, 13, 1, '132080155009', 'Hb. Meter', 'Hemoglobin Meter merupakan alat diagnosa untuk pengukuran kadar hemoglobin dalam darah', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3204, 13, 1, '132080155010', 'Washing Instrument (Laboratorium Hematologi & Urinalisis)', 'Washer Disinfector adalah alat yang digunakan untuk membersihkan dan mendisinfeksi instrumen medis, gigi, dan veteriner yang dapat digunakan kembali', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3205, 5, 1, '132070113008', 'Evoked Potensial System', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3206, 13, 1, '132080155011', 'Dry Sterilizer', 'Sterilisasi Panas Kering atau Dry Heat Sterilizer yaitu alat seperti oven yang digunakan untuk mensterilkan alat dari semua bakteri yang dikenal, spora, dan virus dengan menggunakan panas yang tinggi', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3207, 13, 1, '132080155013', 'Steam Sterilizer (Laboratorium Hematologi & Urinalisis)', 'Steam Sterilizer atau Autoclave merupakan alat pemanas tertutup yang biasanya digunakan untuk dapat membantu dalam mensterilisasi suatu benda dengan menggunakan uap bersuhu dan bertekanan tinggi selama kurang lebih dari 15 menit', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3208, 13, 1, '132080155014', 'Ultrasonic Cleaner (Laboratorium Hematologi & Urinalisis)', 'Ultrasonic cleaner merupakan alat pembersih yang memanfaatkan gelombang ultrasonic untuk memecah partikel yang menempel', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3209, 13, 1, '132080155015', 'Micro Plate Reader', 'Microplate Reader adalah alat untuk menganalisa virus atau bakteri tanaman berdasarkan densitas optik dimana antara referensi, buffer dan bahan yang diuji ditempatkan pada plate', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3210, 13, 1, '132080155016', 'Outomatic Microplate Laser', 'Automatic Microplate Washer adalah alat laboratorium yang dirancang untuk mengontrol prosedur pencucian eksperimental sampel yang diatur dalam plate berdasarkan format tertentu secara otomatis', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3211, 13, 1, '132080155017', 'Osmometer (Laboratorium Hematologi & Urinalisis)', 'Osmometer adalah alat untuk mengukur tekanan osmotik suatu larutan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3212, 13, 1, '132080155018', 'Altifity Water Meter', 'Watermeter atau Meter Air adalah perangkat pengukur yang digunakan untuk mengukur jumlah air yang mengalir melalui suatu pipa atau saluran', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3213, 13, 1, '132080155019', 'Oxigenmeter', 'Oximeter adalah alat medis yang digunakan untuk memantau tingkat oksigen dalam darah pasien', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3214, 13, 1, '132080155020', 'Alat Reasifikasi', 'Alat Regasifikasi adalah serangkaian komponen peralatan yang digunakan untuk mengubah gas alam cair (LNG) menjadi gas alam (NG)', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3215, 5, 1, '132070114009', 'Temperature Monitor (Alat Kedokteran Jantung)', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3216, 13, 1, '132080155023', 'Universal Noister Tesater', 'Universal Moisture Tester adalah alat atau perangkat yang digunakan untuk mengukur kadar air atau kelembaban dalam suatu bahan atau sampel', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3217, 5, 1, '132070114010', 'Arrytmia Monitor', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3218, 13, 1, '132080155026', 'Tabung Centrifugal', 'Tabung Centrifugal adalah tabung yang digunakan pada mesin sentrifugal untuk mempercepat endapan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3219, 13, 1, '132080155028', 'Detector HPLC', 'Detektor HPLC adalah alat yang digunakan untuk mendeteksi dan mengukur konsentrasi senyawa dalam campuran larutan yang telah dipisahkan oleh kromatografi cair kinerja tinggi (HPLC)', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3220, 13, 1, '132080155029', 'Electric Counter Fryer', 'Electric Deep Fryer adalah alat memasak listrik yang digunakan untuk menggoreng sampel makanan dalam jumlah kecil hingga sedang langsung di atas meja dapur di laboratorium', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3221, 5, 1, '132070114013', 'Cabinet Untuk EKG', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3222, 13, 1, '132080155032', 'Hallow Cathode Lamp', 'Hollow Cathode Lamp (HCL) adalah alat laboratorium yang digunakan untuk menghasilkan sinar atom', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3223, 5, 1, '132070114014', 'Capugraph Modul', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3224, 13, 1, '132080155034', 'Heating Mantle', 'Mantel Pemanas atau Isomantle adalah alat laboratorium yang digunakan untuk memberikan panas dan menerapkan panas pada suatu wadah atau bahan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3225, 5, 1, '132070114015', 'Cardiac Output Modul', NULL, NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3226, 13, 1, '132080155035', 'Anak Timbangan', 'Anak Timbangan atau Batu Timbangan merupakan satu kesatuan perangkat dari timbangan mekanik, neraca maupun timbangan bebek yang digunakan sebagai acuan pada penyetelan timbangan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3227, 13, 1, '132080155036', 'Wastle Water Terster', 'Wastewater Test Kit adalah alat uji kualitas air limbah yang berasal dari limbah rumah tangga, Industri, rumah sakit dan sebagainya', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3228, 13, 1, '132080155037', 'Alat Kalibrasi Thermometer', 'Alat kalibrasi thermometer digunakan untuk mengkalibrasi atau memeriksa akurasi thermometer. Kalibrasi diperlukan untuk memastikan bahwa thermometer memberikan pembacaan yang tepat dan akurat, sehingga hasil pengukuran yang diperoleh dari alat tersebut dapat diandalkan', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3229, 13, 1, '132080155038', 'Cawan Kwarsa', 'Cawan lebur adalah suatu wadah yang digunakan untuk melelehkan suatu zat yang memerlukan tingkat panas yang tinggi', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3230, 13, 1, '132080155039', 'Scuber Unit', 'Scrubber Unit merupakan seperangkat alat pemisahan suatu partikel solid (debu) yang ada di gas atau udara dengan menggunakan cairan sebagai alat bantu', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3231, 13, 1, '132080156001', 'Electrostatic Tester', 'perangkat yang dirancang untuk mengukur dan menilai tingkat elektrostatik pada suatu objek atau di suatu lingkungan. Elektrostatik merujuk pada fenomena muatan listrik yang ditemukan pada benda-benda yang tidak bergerak, yang dapat disebabkan oleh gesekan atau pemisahan muatan listrik.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3232, 13, 1, '132080156007', 'Mesin Penghilang Tinta', 'Mesin ini dapat digunakan dalam berbagai konteks, tergantung pada kebutuhan pengguna dan jenis tinta yang ingin dihilangkan.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3233, 13, 1, '132080156008', 'Alat Pengolah Lumpur Aktif', 'perangkat atau sistem yang dirancang khusus untuk mengolah lumpur aktif yang dihasilkan dalam proses pengolahan air limbah menggunakan sistem lumpur aktif. Proses lumpur aktif adalah metode pengolahan air limbah biologis yang melibatkan penggunaan mikroorganisme aktif untuk menguraikan bahan organik dalam air limbah', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3234, 13, 1, '132080156010', 'Alat Pengukur Massa Jenis', 'perangkat yang digunakan untuk mengukur massa jenis suatu zat. Massa jenis adalah besaran fisika yang mengukur jumlah massa dalam suatu volume tertentu dari suatu zat. Satuan umum untuk massa jenis dalam Sistem Satuan Internasional (SI) adalah kilogram per meter kubik (kg/m³).', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3235, 13, 1, '132080156011', 'Alat Uji Kuat Lentur', 'perangkat yang digunakan untuk mengukur atau menguji kekuatan lentur atau kekuatan bending suatu material. Pengujian kuat lentur umumnya dilakukan pada bahan-bahan seperti beton, kayu, logam, atau bahan komposit untuk mengevaluasi kemampuan material tersebut untuk menahan beban lentur tanpa mengalami kegagalan struktural.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3236, 13, 1, '132080156012', 'Alat Tangki Pengapungan', 'tangki yang digunakan dalam proses penyediaan air atau penanganan air limbah. Tangki ini dapat dilengkapi dengan sistem pelampung atau sensor untuk mengatur aliran air atau tingkat air di dalamnya.', NULL, NULL, '2026-04-30 03:15:52', '2026-04-30 03:15:52'),
	(3237, 13, 1, '132080156014', 'Alat Pengolah Lumpur Hasil Pengolahan Limbah (Dewa Tearing)', 'erangkat atau sistem yang digunakan untuk mengelola dan memproses lumpur yang dihasilkan dari unit pengolahan limbah. Lumpur yang dihasilkan dalam proses pengolahan air limbah atau limbah industri seringkali mengandung bahan-bahan organik, zat-zat kimia, dan bahan lain yang perlu diolah atau dihilangkan sebelum lumpur tersebut dapat dibuang atau digunakan kembali.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3238, 13, 1, '132080156016', 'Instron Bending Tester Attachment', 'untuk mendukung dan memegang spesimen material selama pengujian lentur. Bending fixtures dapat memiliki desain yang berbeda tergantung pada spesimen yang diuji dan persyaratan pengujian tertentu', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3239, 13, 1, '132080156017', 'Alat Pengolah Air Limbah', 'perangkat dan sistem yang dirancang untuk membersihkan, mengolah, dan mengurangi polutan dalam air limbah sebelum dibuang ke lingkungan atau dikembalikan ke sumber air', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3240, 13, 1, '132080156018', 'Handy Pump', 'pompa tangan portabel atau pompa genggam. Pompa ini dirancang untuk memindahkan cairan dari satu tempat ke tempat lain dengan menggunakan tenaga manusia. Handy pump umumnya ringkas, mudah dioperasikan, dan seringkali dapat dibawa dengan mudah, sehingga sering digunakan dalam berbagai situasi dan keperluan, terutama di tempat-tempat yang sulit dijangkau oleh pompa besar atau alat lainnya', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3241, 13, 1, '132080156020', 'Funce And Die Cutter', 'alat yang digunakan untuk memotong atau mengekstrak bentuk atau lubang tertentu dari material tertentu. Punch sering kali memiliki bentuk atau desain yang sesuai dengan hasil potongan yang diinginkan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3242, 5, 1, '132070114031', 'Haemodyalisis Unit', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3243, 13, 1, '132080156023', 'Directional Pendulum', 'alat sejenis yang digunakan dalam pengukuran arah atau orientasi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3244, 13, 1, '132080156024', 'Extractrion Heater', 'alat yang digunakan untuk pemanas yang digunakan dalam suatu proses ekstraksi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3245, 5, 1, '132070114033', 'Kg Sol - B III Japan', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3246, 13, 1, '132080156025', 'Colony Counter & Automatic Tally', 'alat yang digunakan dalam laboratorium mikrobiologi untuk membantu menghitung jumlah koloni bakteri atau mikroorganisme lainnya yang tumbuh pada suatu medium agar setelah suatu periode inkubasi', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3247, 5, 1, '132070114034', 'Master Test (Jepang)', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3248, 13, 1, '132080156027', 'Digital Pocket Oxygen Meter', 'alat yang digunakan untuk mengukur kadar oksigen dalam suatu sampel atau lingkungan tertentu. Alat ini umumnya dirancang untuk portabilitas sehingga dapat dengan mudah dibawa di saku atau di lapangan', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3249, 13, 1, '132080156028', 'Desintegrator', 'alat laboratorium yang digunakan untuk menguji kekuatan atau waktu disintegrasi tablet atau kapsul farmasi. Desintegrasi adalah proses di mana tablet atau kapsul hancur menjadi partikel yang lebih kecil. Metode ini membantu menilai sejauh mana tablet atau kapsul dapat terurai menjadi bentuk yang lebih mudah diserap oleh tubuh. Desintegrasi adalah salah satu parameter penting dalam pengembangan dan produksi obat.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3250, 5, 1, '132070114036', 'Oxator Head Complete', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3251, 13, 1, '132080156030', 'Smoothness Tester', 'perangkat laboratorium yang digunakan untuk mengukur kehalusan permukaan material. Ini adalah instrumen yang umumnya digunakan dalam industri, termasuk industri kertas, plastik, atau tekstil. Pengukuran kehalusan sangat penting dalam banyak aplikasi untuk memastikan kualitas permukaan yang memenuhi standar yang ditetapkan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3252, 13, 1, '132080156031', 'Presision Yarn Reel', 'Precision Yarn Reel (Gulungan Benang Presisi) adalah alat laboratorium yang digunakan dalam industri tekstil dan pabrik tekstil untuk mengukur panjang dan berat benang secara akurat. Alat ini digunakan untuk memastikan bahwa benang yang dihasilkan memiliki panjang dan berat yang sesuai dengan standar kualitas yang diinginkan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3253, 13, 1, '132080156035', 'Paper Scale', 'Paper scale bisa merujuk pada alat atau perangkat untuk mengukur berat atau massa kertas. Ini bisa menjadi jenis timbangan khusus yang digunakan untuk mengukur berat kertas dalam industri percetakan atau produksi kertas.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53');
REPLACE INTO `master_data_barang` (`id_data_barang`, `id_subjenis_barang`, `id_satuan`, `kode_data_barang`, `nama_barang`, `deskripsi`, `upload_foto`, `foto_barang`, `created_at`, `updated_at`) VALUES
	(3254, 5, 1, '132070114039', 'Survase 45,7 X 13', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3255, 13, 1, '132080156038', 'Bursting Tester Molen', 'Mullen Burst Tester adalah alat laboratorium yang digunakan untuk melakukan uji kekuatan peledakan pada bahan kemasan, terutama kertas dan karton. Alat ini penting dalam industri kemasan untuk memastikan bahwa kemasan dapat menahan tekanan internal tanpa pecah atau rusak. Uji kekuatan peledakan seperti ini berguna dalam menilai keandalan dan keamanan kemasan selama pengiriman dan penyimpanan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3256, 5, 1, '132070114040', 'S.9910 Cardiomonitor AC/SC Seward', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3257, 13, 1, '132080156039', 'Alat Press Kertas', 'Alat untuk mengemas obat puyer (obat serbuk yang dibungkus per lembar) secara lebih cepat dan rapi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3258, 13, 1, '132080156044', 'Mecanical Compresion Gauge', 'alat atau instrumen mekanis yang digunakan untuk mengukur tekanan atau kekuatan kompresi pada suatu objek atau bahan. Ini bisa mencakup berbagai jenis perangkat yang dirancang untuk mengukur kekuatan tekan pada berbagai bahan atau struktur, termasuk alat yang digunakan dalam uji material di laboratorium atau dalam aplikasi industri.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3259, 13, 1, '132080156045', 'Peeler Gauge', 'Feeler gauge yang berfungsi sebagai pengukur ketebalan atau kerenggangan celah yang sangat kecil dan akurat serta digunakan pada saat melakukan penyesuaian tappets pada mobil & motor, pemotong rumput, dan alat-alat yang menggunakan penggerak berbahan bakar bensin lainnya', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3260, 13, 1, '132080156047', 'Aparatus Dan Stirer', 'suatu set peralatan eksperimen atau sistem reaksi yang dilengkapi dengan perangkat pengaduk. Ini umumnya digunakan dalam percobaan kimia di laboratorium untuk memastikan pencampuran yang baik dan homogen dari berbagai bahan cair atau larutan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3261, 13, 1, '132080156048', 'Alat Box Compresion Test', 'prosedur pengujian laboratorium yang digunakan untuk mengevaluasi kekuatan struktural dan daya tahan kotak karton atau bahan kemasan lainnya. Pengujian ini umumnya dilakukan untuk memastikan bahwa kotak atau kemasan dapat menahan tekanan dan beban yang mungkin timbul selama pengiriman dan penyimpanan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3262, 13, 1, '132080156049', 'Alat Pembuat Lembaran Kertas', 'Alat pembuat lembaran kertas, atau lebih dikenal sebagai mesin pembuat kertas, adalah perangkat industri yang digunakan untuk memproduksi lembaran kertas dari bahan baku pulp. Mesin ini melibatkan serangkaian proses yang mencakup pencampuran bahan, pembentukan lembaran kertas, pengeringan, dan finishing.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3263, 13, 1, '132080156050', 'Ultra Filter Cell', 'Ultra Filter Cell (UFC) adalah suatu perangkat atau sel filtrasi yang digunakan dalam laboratorium atau industri untuk memisahkan partikel dan molekul berukuran mikroskopis dari larutan. Filter ini memanfaatkan prinsip filtrasi membran untuk menyaring dan memisahkan komponen berdasarkan ukuran mereka.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3264, 13, 1, '132080156052', 'Dreging And Sampling Equipment Complit', 'Ekman Grab dan Ekman Dredge Sampler adalah kedua alat serupa yang digunakan untuk mengumpulkan sampel sedimen dari dasar badan air seperti danau, sungai, atau laut', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3265, 13, 1, '132080156053', 'Fermentor (Alat Laboratorium Lainnya)', 'Fermentor adalah alat laboratorium yang digunakan untuk mengatur dan mengendalikan kondisi pertumbuhan mikroorganisme atau sel dalam suatu media cair. Ini adalah instrumen yang sering digunakan dalam bidang bioteknologi dan mikrobiologi untuk menghasilkan produk seperti enzim, antibiotik, atau protein rekombinan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3266, 13, 1, '132080156054', 'Noise Tester / DB Tester', 'Noise Tester atau DB Tester (sering juga disebut sebagai Sound Level Meter) adalah alat yang digunakan untuk mengukur tingkat kebisingan atau tekanan suara dalam suatu lingkungan atau pada suatu sumber suara. Alat ini umumnya digunakan di laboratorium, industri, atau di lapangan untuk menilai tingkat kebisingan dan memastikan kepatuhan terhadap standar kebisingan yang ditetapkan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3267, 13, 1, '132080156060', 'Prototip Pengolahan Air Limbah', 'Prototipe Pengolah Air Limbah adalah sistem pengolahan air limbah skala kecil yang digunakan untuk menguji teknologi pengolahan air limbah baru atau untuk mempelajari bagaimana teknologi pengolahan air limbah tertentu akan bekerja dalam kondisi tertentu', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3268, 5, 1, '132070115007', 'Film Processing Tank', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3269, 13, 1, '132080156063', 'Disseting Set', 'Dissecting set adalah seperangkat peralatan yang digunakan dalam proses disseksi, yaitu pemotongan dan pembedahan organisme atau jaringan untuk tujuan pengamatan dan analisis.\n\n\n\nSebuah dissecting set biasanya mencakup berbagai instrumen yang berguna untuk memotong, mengamati, dan mengidentifikasi struktur anatomi. Beberapa instrumen yang umumnya ada dalam dissecting set meliputi:\n\n\n\nPinset:\n\n\n\nDigunakan untuk menangani atau memegang jaringan dan organisme selama proses disseksi.\n\nScissors:\n\n\n\nGunting khusus yang dirancang untuk memotong jaringan atau organisme dengan presisi selama disseksi.\n\nForceps:\n\n\n\nSeperti pinset, forceps juga digunakan untuk memegang atau memanipulasi jaringan selama disseksi.\n\nScalpel:\n\n\n\nPisau bedah yang tajam digunakan untuk memotong jaringan atau organisme selama proses disseksi.\n\nNeedle Probe:\n\n\n\nJarum runcing di ujung pegangan yang digunakan untuk memisahkan atau menyelidiki struktur yang lebih kecil.\n\nBougie:\n\n\n\nInstrumen panjang dan lentur yang digunakan untuk menelusuri saluran tubuh, seperti pembuluh darah atau saluran pencernaan.\n\nMagnifying Glass:\n\n\n\nKaca pembesar untuk membantu dalam pengamatan struktur yang lebih kecil atau detail.\n\nDissecting Pan:\n\n\n\nWadah datar dengan dinding rendah tempat jaringan atau organisme ditempatkan selama proses disseksi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3270, 13, 1, '132080156064', 'Dynamic Hand Sheet', 'perangkat yang digunakan dalam industri kertas atau laboratorium untuk membuat lembaran kertas secara dinamis. Perangkat ini umumnya digunakan dalam penelitian dan pengembangan kertas untuk mengevaluasi sifat dan kualitas kertas yang dihasilkan', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3271, 13, 1, '132080156068', 'Elecyric Stabilizer', 'Electric Stabilizer atau Voltage Stabilizer adalah perangkat elektronik yang dirancang untuk menjaga tegangan listrik tetap stabil dan konstan. Ini berfungsi untuk melindungi peralatan listrik dan elektronik dari fluktuasi tegangan yang dapat merusaknya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3272, 13, 1, '132080156069', 'Bioflo Fermentor', 'BioFlo Fermentor adalah produk yang dikembangkan oleh New Brunswick Scientific (NBS), yang kemudian diakuisisi oleh Eppendorf. Ini adalah sistem fermentasi dan bioreaktor yang dirancang untuk keperluan penelitian dan pengembangan dalam bidang bioteknologi, mikrobiologi, dan rekayasa protein.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3273, 13, 1, '132080156071', 'Alat Uji Komperator', 'Alat uji komparator adalah perangkat yang digunakan untuk membandingkan warna atau kecerahan antara dua atau lebih benda atau substansi. Alat ini biasanya digunakan dalam berbagai aplikasi di berbagai industri, termasuk industri kimia, makanan, farmasi, dan lainnya. Berikut beberapa contoh alat uji komparator dan penggunaannya:\n\nKomparator Warna (Color Comparator):\n\nDigunakan untuk membandingkan warna suatu substansi dengan standar warna yang telah ditentukan. Ini sering digunakan dalam industri makanan, minuman, atau farmasi untuk memastikan konsistensi warna produk.\nKomparator Kecerahan (Brightness Comparator):\n\nDigunakan untuk mengukur dan membandingkan kecerahan atau tingkat reflektansi suatu bahan dengan standar yang telah ditetapkan. Ini dapat relevan dalam industri kertas, tekstil, atau cat.\nKomparator Turbiditas (Turbidity Comparator):\n\nDigunakan untuk mengukur tingkat kekeruhan dalam suatu cairan. Ini sering digunakan dalam pengujian kualitas air dan pengolahan air untuk memastikan air yang aman dan sesuai dengan standar.\nKomparator Klorin (Chlorine Comparator):\n\nDigunakan dalam pengujian air untuk mengukur kadar klorin. Ini penting dalam pemantauan kualitas air minum dan dalam proses pengolahan air.\nKomparator Besi (Iron Comparator):\n\nDigunakan untuk mengukur kadar besi dalam suatu larutan. Ini bisa berguna dalam industri air, pertanian, atau pengolahan limbah.\nKomparator Ammonia (Ammonia Comparator):\n\nDigunakan untuk mengukur kadar amonia dalam air. Ini sering digunakan dalam industri akuakultur dan pengelolaan kualitas air.\nKomparator pH (pH Comparator):\n\nDigunakan untuk membandingkan tingkat keasaman atau kebasaan (pH) suatu larutan dengan skala warna yang telah ditetapkan. Ini umum dalam pengujian air, laboratorium kimia, dan industri farmasi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3274, 13, 1, '132080156072', 'Gas Detector', 'Gas detector adalah perangkat atau instrumen yang dirancang untuk mendeteksi keberadaan gas tertentu di suatu lingkungan. Fungsi utama gas detector adalah memberikan peringatan atau alarm jika konsentrasi gas mencapai tingkat yang berbahaya atau di luar batas aman.\n\nBeberapa jenis gas detector yang umum digunakan termasuk:\n\nGas Detector untuk Gas Beracun:\n\nGas detector dapat dirancang untuk mendeteksi gas-gas beracun seperti karbon monoksida (CO), hidrogen sulfida (H2S), amonia (NH3), dan lainnya.\nGas Detector untuk Gas Mudah Terbakar:\n\nDigunakan untuk mendeteksi keberadaan gas yang mudah terbakar atau meledak, seperti metana (CH4), propana (C3H8), atau hidrogen (H2).\nGas Detector untuk Oksigen:\n\nMenyediakan pemantauan tingkat oksigen di suatu area. Terlalu tinggi atau terlalu rendahnya kadar oksigen bisa menjadi tanda bahaya.\nGas Detector Multi Gas:\n\nInstrumen yang dapat mendeteksi beberapa jenis gas secara bersamaan. Cocok untuk lingkungan di mana ada potensi paparan berbagai jenis gas.\nGas Detector Portabel:\n\nAlat yang mudah dibawa dan digunakan oleh individu, seperti pekerja lapangan atau petugas pemadam kebakaran, untuk memantau keberadaan gas di sekitar mereka.\nGas Detector Tetap atau Stasioner:\n\nDipasang pada lokasi tertentu untuk pemantauan terus menerus. Digunakan di fasilitas industri, pabrik, atau area yang memerlukan pemantauan gas konstan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3275, 5, 1, '132070115013', 'Spect', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3276, 13, 1, '132080156074', 'Alat Uji Permanensi Kertas', 'Alat uji permanensi kertas adalah peralatan yang digunakan untuk mengukur sejauh mana kertas atau bahan lainnya dapat mempertahankan kekuatan, warna, atau keadaan awalnya seiring waktu. Hal ini penting terutama dalam industri percetakan, pembuatan kertas, dan penyimpanan arsip di mana konservasi mutu bahan sangat diinginkan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3277, 13, 1, '132080156079', 'Head Lamp (Alat Laboratorium Lainnya)', 'Dalam situasi di mana pencahayaan standar tidak mencukupi, lampu kepala mungkin digunakan untuk membantu dalam inspeksi atau kerja di laboratorium gelap.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3278, 13, 1, '132080156080', 'Aneroid Barometerjar', 'jenis barometer yang menggunakan komponen mekanis, biasanya berbentuk logam tertentu yang peka terhadap perubahan tekanan atmosfer. Barometer jar sendiri umumnya mengacu pada suatu wadah atau container.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3279, 13, 1, '132080156081', 'Meja Kerja', 'Meja kerja laboratorium adalah perabotan khusus yang dirancang untuk kebutuhan kerja di lingkungan laboratorium. Meja tersebut dirancang untuk memenuhi standar kebersihan, ketahanan terhadap bahan kimia, dan fungsionalitas yang dibutuhkan oleh pekerja laboratorium.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3280, 13, 1, '132080156082', 'Screen Pembaras', 'kemungkinan nama barang ini adalah Screen Pembatas, dimana alat tersebut digunakan untuk membatasi ruang yang ada pada laboratorium', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3281, 5, 1, '132070115018', 'Mass Chest Unit', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3282, 13, 1, '132080156083', 'Thermometer Digital (Alat Laboratorium Lainnya)', 'alat laboratorium yang digunakan untuk mengukur suhu secara digital', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3283, 5, 1, '132070115019', 'Skul Unit (Cranio)', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3284, 13, 1, '132080156084', 'Tempat Air Suling', 'alat atau sistem yang digunakan untuk menghasilkan air suling atau air murni. Air suling digunakan dalam berbagai aplikasi laboratorium di mana kualitas air yang sangat tinggi dibutuhkan, seperti dalam persiapan larutan kimia, pengenceran, atau dalam eksperimen dan analisis yang memerlukan air bebas kontaminan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3285, 13, 1, '132080156085', 'Alat Penyaring', 'alat penyaring yang digunakan untuk memisahkan partikel padat dari cairan atau suspensi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3286, 13, 1, '132080156086', 'Aneroid Jar', 'SEHARUSNYA ANAEROBIC JAR, alat berpenutup kedap udara yang digunakan untuk menginkubasi mikroba anaerob.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3287, 13, 1, '132080156087', 'Automatic Pipet Dispenser', 'alat otomatis yang digunakan untuk mendistribusikan cairan dengan volume yang diukur secara akurat. Alat ini umumnya digunakan di laboratorium untuk meningkatkan presisi dan efisiensi dalam pengukuran dan transfer cairan, terutama ketika diperlukan volume yang seragam dan tolok ukur yang konsisten.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3288, 5, 1, '132070115023', 'Zonography Unit', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3289, 13, 1, '132080156088', 'Exicator', 'Desikator/Exicator, adalah wadah yang terbuat dari bahan gelas yang kedap udara dan mengandung desikan yang berfungsi menghilangkan air dan kristal hasil pemurnian. Desikator, bejana tertutup berisi zat pengering untuk mengeringkan zat-zat lain, yang biasa dipakai ialah asam sulfat pekat, kalsium klorida atau gel silika.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3290, 13, 1, '132080156089', 'Extraction Heater', 'alat yang digunakan untuk memanaskan media', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3291, 13, 1, '132080156090', 'Faden Thermometer', 'Faden Thermometer atau Thermometer Utas adalah alat laboratorium yang digunakan untuk mengukur suhu dengan menggunakan utas logam', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3292, 5, 1, '132070115026', 'Digital Subtract Angiong', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3293, 13, 1, '132080156091', 'Furne Hood', 'alat atau perangkat yang dirancang untuk menghilangkan atau mengurangi paparan terhadap gas, uap, debu, atau bahan kimia berbahaya saat digunakan di laboratorium atau lingkungan kerja yang melibatkan zat-zat berbahaya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3294, 13, 1, '132080156092', 'Mental Heater', 'Heating Mantle adalah alat laboratorium yang digunakan untuk memanaskan cairan atau larutan dalam labu atau gelas kimia', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3295, 13, 1, '132080156093', 'Mechanic Heater', 'alat pembersih yang menggunakan gelombang ultrasonik untuk membersihkan benda dengan efektif dan efisien', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3296, 13, 1, '132080156094', 'Neraca Analitis Kalibrator', 'jenis perangkat atau sistem yang digunakan untuk mengkalibrasi atau memastikan ketelitian neraca analitis.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3297, 13, 1, '132080156095', 'Standar Masa', 'benda atau bahan yang digunakan untuk mengukur massa suatu objek. Ini adalah benda atau substansi yang diketahui massa dan stabilitasnya, dan digunakan sebagai dasar untuk mengkalibrasi atau memverifikasi peralatan timbangan di laboratorium.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3298, 13, 1, '132080156096', 'Tabung Detruksi', 'Tabung Destruksi adalah alat laboratorium yang digunakan untuk mendestruksi sampel, biasanya sampel organik, untuk melepaskan senyawa yang terkandung di dalamnya', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3299, 5, 1, '132070115032', 'Medium Voltage Therapy', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3300, 13, 1, '132080156097', 'Karl Fiher', 'Karl Fischer adalah nama seorang ahli kimia Jerman yang menciptakan metode analisis untuk mengukur kadar air dalam suatu substansi. Metode ini dikenal sebagai metode Karl Fischer dan merupakan salah satu teknik yang paling umum digunakan untuk analisis kadar air dalam berbagai bahan kimia.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3301, 5, 1, '132070115033', 'Linier Accelarator', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3302, 13, 1, '132080156098', 'Altifity Water Meter', 'alat pengukur debit air yang digunakan untuk mengukur volume air yang mengalir dalam suatu periode waktu. Alat ini terdiri dari dua bagian utama, yaitu sensor dan pengukur. Sensor berfungsi untuk mendeteksi aliran air, sedangkan pengukur berfungsi untuk menghitung volume air yang mengalir.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3303, 5, 1, '132070115034', 'After Loading', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3304, 13, 1, '132080156099', 'Oxigen Meter', 'Oxygen Meter, atau yang dikenal juga sebagai dissolved oxygen meter, adalah alat yang digunakan untuk mengukur kadar oksigen terlarut dalam air', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3305, 13, 1, '132080156100', 'Alat Reasifikasi', 'Alat reasifikasi terdiri dari beberapa, salah satu yg digunakan berfungsi sbg  penyimpanan yang efisien dan pengelolaan sampel laboratorium, seperti freezer otomatis, ruang penyimpanan suhu terkendali, atau sistem manajemen sampel.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3306, 13, 1, '132080156102', 'Alat Detruksi', 'peralatan yang digunakan untuk menghancurkan atau memproses sampel atau bahan tertentu, Beberapa alat destruksi laboratorium melibatkan metode penghancuran atau pemecahan sampel untuk mempersiapkannya untuk analisis lebih lanjut. beberapa contoh alat destruksi lab: Homogenizer (Homogenisator), Homogenizer (Homogenisator), Freeze Mill (Penggiling Bebas)', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3307, 13, 1, '132080156103', 'Universal Noister Tesater', 'alat pengukur kelembaban digital yang dirancang untuk mengukur kadar air atau kelembaban dalam suatu materi atau zat. Alat ini dapat digunakan di berbagai bidang, termasuk pertanian, konstruksi, laboratorium, dan industri pengolahan makanan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3308, 13, 1, '132080156105', 'Handy Aspirator', 'alat laboratorium yang digunakan untuk menghisap atau mengeluarkan cairan dari suatu wadah atau bejana menggunakan tekanan udara. Alat ini sering digunakan untuk melakukan pemindahan cairan atau pengepakan kolom kromatografi dalam aplikasi laboratorium.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3309, 5, 1, '132070116002', 'Automatic Tisue Prosessor', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3310, 13, 1, '132080156109', 'Electric Counter Fryer', 'Alat ini digunakan untuk memanaskan dan mengeringkan sampel', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3311, 5, 1, '132070116003', 'Autopsi Set (Post Mortem Dissectiong Set)', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3312, 13, 1, '132080156114', 'Heating Mantle (Alat Laboratorium Lainnya)', 'alat laboratorium yang digunakan untuk memanaskan cairan atau zat dalam lab. Ini biasanya digunakan pada bejana tertutup atau erlenmeyer untuk menghindari penguapan atau kehilangan zat selama pemanasan. Heating mantle umumnya dirancang sebagai kantong yang terbuat dari bahan yang tahan panas, seperti kawat keramik, yang membungkus atau menyelimuti labu atau wadah lainnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3313, 13, 1, '132080156115', 'Anak Timbangan', 'batu timbangan selama ini dikenal sebagai salah satu kesatuan perangkat dari suatu timbangan yaitu pada timbangan mekanik, neraca maupun timbangan bebek yang dahulu umum digunakan untuk keperluan perdagangan di pasar tradisional.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3314, 5, 1, '132070116005', 'Cytopsin 2', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3315, 13, 1, '132080156116', 'Waste Water Tester', 'alat atau perangkat yang digunakan untuk mengukur parameter atau komponen tertentu dalam air limbah', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3316, 5, 1, '132070116006', 'Fluoeresenci Microscope', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3317, 13, 1, '132080156117', 'Alat Kalibrasi Thermometer', 'digunakan untuk memastikan bahwa thermometer atau alat pengukur suhu memberikan pembacaan yang akurat. Kalibrasi adalah proses memeriksa dan menyesuaikan kembali perangkat pengukur agar sesuai dengan standar referensi yang diketahui', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3318, 5, 1, '132070116007', 'Histoblok', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3319, 13, 1, '132080156118', 'Cawan Kwarsa', 'alat laboratorium yang digunakan untuk memanaskan, menyimpan, atau menggabungkan zat kimia pada suhu tinggi. Cawan ini terbuat dari bahan kwarsa atau sering kali terbuat dari porselen yang dilapisi dengan lapisan kwarsa', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3320, 13, 1, '132080156121', 'Logic Probe (Alat Laboratorium Lainnya)', 'alat laboratorium yang digunakan untuk memeriksa dan memonitor sinyal digital pada rangkaian logika. Ini adalah perangkat yang membantu teknisi atau insinyur elektronika dalam menganalisis dan memahami sinyal logika pada papan sirkuit atau sistem digital.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3321, 5, 1, '132070116009', 'Inverteed Microscope', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3322, 13, 1, '132080156123', 'Sensor Proxinity', 'sensor yang mampu mendeteksi kehadiran objek di sekitar tanpa melalui kontak fisik.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3323, 13, 1, '132080156124', 'handy Digital IC Tester', 'alat yang digunakan untuk menguji dan memverifikasi kinerja sirkuit terintegrasi digital (IC) atau chip dalam bentuk digital. Ini adalah perangkat portabel yang dirancang untuk memudahkan teknisi atau pengguna untuk menguji sejumlah IC yang berbeda dengan cepat dan mudah tanpa harus menghubungkannya ke sirkuit yang lebih besar.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3324, 5, 1, '132070116011', 'Magnetic Stifer Termolyne', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3325, 13, 1, '132080156126', 'Hand Held Logic Analyzer', 'Logic Analyzer adalah alat yang digunakan untuk menganalisis sinyal digital. Alat ini dapat digunakan untuk menganalisis sinyal yang berasal dari berbagai sumber, seperti mikroprosesor, mikrokontroler , dan lainnya. Alat ini dapat membantu dalam menganalisis masalah yang terjadi pada sistem digital.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3326, 5, 1, '132070116012', 'Minimash Millipore', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3327, 13, 1, '132080157004', 'Hygrometer (Alat Lab. Hermodinamika Motor Dan Sistem Propulasi)', 'Alat yang digunakan untuk mengukur suhu dan kelembaban.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3328, 13, 1, '132080158002', 'Harmoni Generator', 'Harmony Generator adalah perangkat atau software yang dirancang untuk menghasilkan harmoni musik secara otomatis. Ini dapat digunakan dalam berbagai konteks, mulai dari produksi musik digital hingga kebutuhan live performance.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3329, 13, 1, '132080158003', 'Standard Signal Generator', 'Generator sinyal menyediakan sinyal AC dari amplitudo dan frekuensi yang divariasikan untuk digunakan ketika mengoperasikan sebuah amplifier atau rangkaian linear lainnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3330, 13, 1, '132080158005', 'Timing Unit', 'Timer manual sebagai alat pengatur waktu di laboratorium, biasa digunakan untuk pengingat uji laboratorium, pemakaian dengan memutar jarum jam ke waktu yang ditentukan, stelah waktu habis, timer akan berbunyi \'kring\'. Timer 60 menit', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3331, 13, 1, '132080158008', 'General Radio Frequence Standard', 'RF (Radio Frekuensi) adalah komponen yang dapat mendeteksi sinyal gelombang elektromagnetik digunakan oleh sistem komunikasi untuk mengirim informasi melalui udara dari satu titik ke titik lainnya yang merambat di antara antena pemancar pengirim dan penerima.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3332, 13, 1, '132080158012', 'Fuse Generator', 'Fuse atau dalam bahasa Indonesia disebut dengan Sekering adalah komponen yang berfungsi sebagai pengaman dalam Rangkaian Elektronika maupun perangkat listrik. Fuse (Sekering) pada dasarnya terdiri dari sebuah kawat halus pendek yang akan meleleh dan terputus jika dialiri oleh Arus Listrik yang berlebihan ataupun terjadinya hubungan arus pendek (short circuit) dalam sebuah peralatan listrik / Elektronika. Dengan putusnya Fuse (sekering) tersebut, Arus listrik yang berlebihan tersebut tidak dapat masuk ke dalam Rangkaian Elektronika sehingga tidak merusak komponen-komponen yang terdapat dalam rangkaian Elektronika yang bersangkutan. Karena fungsinya yang dapat melindungi peralatan listrik dan peralatan Elektronika dari kerusakan akibat arus listrik yang berlebihan, Fuse atau sekering juga sering disebut sebagai Pengaman Listrik.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3333, 13, 1, '132080158017', 'Transistor Analyzer', 'transistor tester adalah sebuah pernagkat yang digunakan untuk menguji perilaku listrik transistor dan keadaan dioda dalam transistor.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3334, 13, 1, '132080158021', 'Antenna Relay', 'Dalam perancangan selektor antena monitoring ini menggunakan relay sebagai komponen yang berhubungan langsung ke antena dan sistem elektronik selektor. Relay juga berfungsi sebagai isolator antara sistem elektronik selektor antena monitoring frekuensi radio dan sistem antena dan receiver', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3335, 5, 1, '132070117002', 'Centrifuge MLA', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3336, 13, 1, '132080158025', 'Alternator Variable', 'Mengukur tegangan maju, tegangan balik, penurunan tegangan saturasi maju, faktor penguatan, arus bocor balik berbagai dioda kristal, audion, penyearah terkontrol silikon (SCR), transistor efek medan (FET). Mengukur tegangan kerja pengenal kapasitor kimia, kapasitor terylene, kapasitor DY294 Ta, kapasitor keramik multilayer artikulasi, kekurangan tegangan tinggi. Mengukur tegangan proteksi varistor.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3337, 13, 1, '132080158026', 'Auto Meter Stabilizer', 'Stabilizer/AVR (Automatic Voltage Regulator) didesign untuk menstabilkan listrik yang berfluktuasi, namun Stabilizer/AVR (Automatic Voltage Regulator) memiliki input tolerance berbeda-beda, atau biasa disebut dengan range input voltage. Contoh, Stabilizer/AVR (Automatic Voltage Regulator) dengan range input voltage 20% artinya voltase terendah yang bisa diterima adalah 176V untuk 1 phase dan 304V untuk 3 phase, dan voltase tertinggi yang bisa diterima adalah 264V untuk 1 phase dan 456V untuk 3 phase. Dengan begitu jika voltase turun terlalu ekstrim hingga mencapai 30% maka Stabilizer/AVR (Automatic Voltage Regulator) dengan range input voltage 20% tidak mencukupi, dibutuhkan Stabilizer/AVR (Automatic Voltage Regulator) dengan range input voltage 30% ke atas. Untuk itu pastikan dahulu dengan dilakukan pengetesan menggunakan Avo Meter untuk mengetahui berapa voltase naik atau turun tegangan agar Stabilizer/AVR (Automatic Voltage Stabilizer) bisa bekerja maksimal.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3338, 13, 1, '132080158028', 'Instrucure Control Display Unit', 'seharusnya "Instrument Control Display Unit, perangkat atau unit kontrol yang digunakan untuk memantau dan mengendalikan instrumen atau peralatan tertentu.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3339, 5, 1, '132070118001', 'After Loading', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3340, 13, 1, '132080158036', 'Maket Mesin Kapal', 'replika atau model dari mesin kapal yang digunakan untuk keperluan demonstrasi, pelatihan, atau penjelasan visual. Maket ini sering kali digunakan di industri maritim, pendidikan teknik kelautan, dan dalam kegiatan promosi atau pameran kapal. Maket tersebut biasanya mencakup berbagai komponen dan sistem mesin kapal yang diwakili dengan detail visual.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3341, 13, 1, '132080158047', 'Demonstration Vernier Callypear', 'Jangka sorong atau vernier caliper merupakan alat ukur yang sering digunakan dalam dunia otomotif karena mampu mengukur benda kerja dengan ketelitian hingga 0,02 mm dan 0,05 mm. Jangka sorong digunakan untuk mengukur Ketebalan, diameter dalam, diameter luar dan mengukur kedalaman suatu benda.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3342, 13, 1, '132080158048', 'Scrow Micrometer', 'Fungsi utama mikrometer sekrup adalah untuk memberikan pengukuran yang sangat akurat dan presisi terhadap dimensi suatu objek. Alat ini digunakan untuk mengukur ketebalan, diameter luar, diameter dalam, atau panjang benda dengan ketelitian yang jauh lebih tinggi daripada alat ukur konvensional seperti penggaris atau mistar.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3343, 5, 1, '132070118004', 'Blood Irradiator', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3344, 13, 1, '132080158050', 'Eye Picci Micro Meter', 'Eyepiece Micrometer (Mata Lensa Mikrometer) adalah alat yang biasa digunakan oleh peneliti untuk membuat pengukuran yang akurat dan specimen.Eyepiece Micrometer memiliki bentuk melingkar terbuat dari kaca dan pada bagian dalamnya terdapat garis-garis skala yang digunakan para peneliti untuk mengukur objek.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3345, 13, 1, '132080158056', 'Energy Transformation Apparatus', 'alat yang dirancang untuk mengilustrasikan dan memahamkan konsep transformasi energi. Perangkat ini sering digunakan di laboratorium pendidikan atau kelas sains untuk membantu siswa memahami bagaimana energi dapat diubah dari satu bentuk ke bentuk lain. Contoh Energy Transformation Apparatus; Generator Listrik, Dinamo, model turbin angin, Model Hidroelektrik, dll', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3346, 5, 1, '132070118006', 'Cineting Cable For Recorder Light 0,8 mm', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3347, 13, 1, '132080158058', 'Alat Percobaan Archimedes', 'Alat yang digunakan untuk mempelajari hukum archimedes. 1 set terdiri dari Alas statif besi, Batang statif 50 cm, Klem bosshead, Klem universal, Neraca pegas 3 N dan Gliserin 200 ml. Dilengkapi dengan petunjuk praktikum hukum archimedes.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3348, 13, 1, '132080158063', 'Griffin Dinamic Trolley', 'alat bantu pemindahan barang dari satu tempat ke tempat yang lain dalam kegiatan operasional', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3349, 13, 1, '132080158065', 'Mass Hanger', 'Alat yang berupa hanger untuk menyimpan beban massa', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3350, 13, 1, '132080158070', 'Boyle\'s Law Apparatus', 'Boyle\'s Law Apparatus is a scientific device used to investigate the relationship between the pressure and volume of a gas in a closed container. This apparatus plays a key role in studying thermodynamics and gas laws and is often used in scientific demonstrations and experiments.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3351, 13, 1, '132080159004', 'Dessicator Vacuum', 'Desikator vakum adalah desikator yang mampu mempertahankan kelembapan rendah pada tekanan tidak lebih dari 20 mmHg atau pada tekanan lain yang ditetapkan dalam monografi. Desikator Vacum pada bagian tutupnya ada katup yang bisa dibuka tutup, yang dihubungkan dengan selang ke pompa.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3352, 5, 1, '132070118011', 'Data Catridge', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3353, 13, 1, '132080159008', 'Thermocouple', 'Termokopel (Thermocouple) adalah jenis sensor suhu yang digunakan untuk mendeteksi atau mengukur suhu melalui dua jenis logam konduktor berbeda yang digabung pada ujungnya sehingga menimbulkan efek “Thermo-electric”.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3354, 13, 1, '132080159010', 'Sieke Shaker Mesh', 'Sieve Shaker adalah salah satu alat laboratorium yang digunakan untuk memisahkan partikel kasar dengan beberapa jenis mesh hingga memperoleh partikel halus.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3355, 13, 1, '132080159011', 'Electric Steam Generator', 'Steam generator didesain untuk menghasilkan steam dengan tekanan dan temperatur tertentu. Kualitas steam yang dihasilkan sangat dipengaruhi oleh performa kinerja dari steam generator.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3356, 5, 1, '132070118014', 'Film Hanger', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3357, 13, 1, '132080159012', 'Cool Chamber', 'teknologi penyimpanan yang tidak memerlukan listrik dan ramah lingkungan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3358, 5, 1, '132070118015', 'Film Marker', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3359, 13, 1, '132080159014', 'Acrylic', 'wadah berupa Piring Petri, tabung reaksi, dan wadah-wadah lainnya dari akrilik dapat digunakan untuk berbagai eksperimen dan analisis di laboratorium studi karakteristik enzim, pengembangan proses produksi enzim, atau aplikasi enzim dalam berbagai industri.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3360, 14, 1, '132080160005', 'Cetak Kubus Beton', 'Cetakan beton kubus merupakan alat pencetak beton precast dengan model kubus atau beton uji untuk selanjutnya dilakukan pengujian kekuatan, komposisi dan sebagainya sebelum membuat konstruksi beton sesungguhnya. Cetakan beton yang berguna sebagai alat uji kekuatan dan ketahanan dalam bentuk kubus', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3361, 5, 1, '132070118017', 'Flaw Directic Pacing Cathasen', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3362, 14, 1, '132080160007', 'Saringan Besi', 'peralatan yang digunakan untuk menyaring partikel besi dari suatu larutan. Saringan besi ini membantu memisahkan partikel-partikel besi yang dapat mempengaruhi kualitas air atau proses kimia yang sedang dilakukan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3363, 14, 1, '132080161001', 'Power Harmonic Analizer Fluke', 'Alat Power Quality Analyzer merupakan alat ukur untuk mengetahui kualitas daya dari tenaga listrik. Seperti yang telah disebutkan sebelumnya bahwa alat ini sangat kompleks dan memberikan manfaat untuk mengukur tegangan, arus listrik, daya kompleks, daya reaktif, daya aktif, dan juga factor daya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3364, 14, 1, '132080161006', 'Process Simulator Winsim Design', 'perangkat lunak simulasi proses yang digunakan di berbagai industri untuk mendesain, mengoptimalkan, dan menganalisis proses kimia dan pabrik. membutuhkan beberapa perlengkapan seperti ompa, kompresor, kolom distilasi, dan lainnya, untuk memudahkan pengguna dalam merancang sistem.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3365, 14, 1, '132080161008', 'Digital Anemometer', 'alat yang digunakan untuk mengukur kecepatan angin atau aliran udara. Alat ini dirancang untuk memberikan pembacaan yang akurat dan cepat menggunakan sensor-sensor digital. Digital anemometer sering digunakan di berbagai aplikasi, termasuk meteorologi, industri, pengukuran kualitas udara, dan olahraga aerodinamika.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3366, 5, 1, '132070118021', 'Linier Accelerator', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3367, 14, 1, '132080161011', 'Infra Red Exhaust Gas Analizer', 'perangkat yang digunakan untuk menganalisis komposisi gas buang kendaraan bermotor atau mesin lainnya. Perangkat ini menggunakan teknologi inframerah untuk mengidentifikasi dan mengukur jumlah gas tertentu dalam gas buang.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3368, 5, 1, '132070118022', 'Lisholm Grid', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3369, 14, 1, '132080161012', 'Instalasi Fiber Optic LCD Projector Multimedia', 'Sistem instalasi yang melibatkan fiber optik, LCD projector, dan perangkat multimedia di laboratorium sumber daya dan energi', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3370, 5, 1, '132070118023', 'Lisholm Ukuran 30 X 45', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3371, 14, 1, '132080162001', 'Decitating Cabinet', 'Desiccator (Desikator Kabinet) adalah alat untuk mengeringkan suatu bahan yang bebas dari kelembaban atau sebagai tempat mengeringkan bahan', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3372, 5, 1, '132070118024', 'Lisholm Ukuran 35 X 35', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3373, 14, 1, '132080162002', 'Digital Analitical Balance', 'perangkat laboratorium yang digunakan untuk mengukur massa benda dengan tingkat presisi tinggi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3374, 5, 1, '132070118025', 'Mediscape Star (USA)', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3375, 14, 1, '132080162006', 'Scimmer Crane', 'Skimmer Crane adalah alat yang digunakan untuk membersihkan minyak yang tumpah di air. Alat ini terdiri dari sebuah crane yang dilengkapi dengan lengan penyapu. Lengan penyapu ini dirancang untuk menampung minyak dan membawanya ke kapal atau tempat penampungan', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3376, 5, 1, '132070118026', 'Minitor 44 cm 625 Lines Siemens', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3377, 14, 1, '132080163002', 'Board Display', 'alat atau perangkat yang digunakan untuk menampilkan grafik atau data yang dihasilkan oleh alat pengukur gelombang, seperti osiloskop. Osiloskop adalah instrumen pengukuran elektronik yang digunakan untuk mengamati sinyal listrik secara visual dalam bentuk gelombang', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3378, 14, 1, '132080163003', 'Standard Compact', 'alat pengukur gelombang dengan nama Standard Compact tidak ada, akan tetapi Beberapa alat pengukur gelombang umum yang digunakan dalam konteks elektronika dan komunikasi melibatkan pengukuran sinyal gelombang radio atau mikro gelombang, diantaranya Oscilloscope, Spectrum Analyzer, Network Analyzer, Signal Generator:', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3379, 5, 1, '132070118028', 'X-Ray Medium Therapy', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3380, 15, 1, '132080201001', 'Conduktimeter', 'Conductivity Meter atau Konduktometer adalah alat ukur kualitas air yang digunakan untuk mengetahui kemampuan Daya Hantar Listrik (DHL) atau nilai konduktivitas listrik suatu larutan ataupun air dalam suatu perairan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3381, 5, 1, '132070118029', 'Monographie Device', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3382, 15, 1, '132080201003', 'Potentiometer', 'Potensiometer adalah resistor tiga terminal dengan sambungan geser yang membentuk pembagi tegangan dapat disetel. Potensiometer biasanya digunakan untuk mengendalikan peranti elektronik seperti pengendali suara pada penguat.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3383, 5, 1, '132070118030', 'Mould Room', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3384, 15, 1, '132080201006', 'Karl Fisher Water Tritator', 'Titrasi Karl Fischer adalah metode titrasi klasik yang menggunakan koulometri atau titrasi volumetrik untuk menentukan jumlah jejak air dalam sampel.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3385, 15, 1, '132080201013', 'Electrophoresis Analysis Equipment', 'Alat analisis elektroforesis adalah perangkat yang digunakan untuk memisahkan dan menganalisis molekul-molekul berdasarkan ukuran, muatan listrik, atau strukturnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3386, 5, 1, '132070118032', 'Selectron', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3387, 15, 1, '132080201014', 'Moisture Tester (Analytical Instrument)', 'Moisture Tester atau pengukur kelembaban adalah perangkat atau alat yang digunakan untuk mengukur jumlah kelembaban atau kadar air dalam sebuah bahan atau sampel.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3388, 15, 1, '132080201016', 'Leak Detector (Analytical Instrument)', 'perangkat atau instrumen yang dirancang untuk mendeteksi kebocoran atau kehilangan suatu zat atau substansi, terutama gas atau cairan, dari suatu sistem tertutup.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3389, 5, 1, '132070118034', 'Telegama Therapy', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3390, 15, 1, '132080201017', 'Ultraviolet Spectrophotometer', 'UV-VIS Spectrophotometer merupakan adalah instrumen analisis yang mengukur jumlah sinar ultraviolet (UV) dan cahaya tampak yang diserap oleh sampel . Ini adalah teknik yang banyak digunakan dalam bidang kimia, biokimia, dan bidang lainnya, untuk mengidentifikasi dan mengukur senyawa dalam berbagai sampel', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3391, 5, 1, '132070118035', 'Treatment Plan Computer', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3392, 15, 1, '132080201018', 'Visible Light Spectrophotometer', 'Spectrophotometer cahaya tampak (visible light spectrophotometer) adalah instrumen laboratorium yang digunakan untuk mengukur absorpsi atau transmisi cahaya pada berbagai panjang gelombang dalam rentang cahaya tampak. Instrumen ini umumnya digunakan dalam berbagai bidang, termasuk kimia, biologi, fisika, dan ilmu material.\n\n\n\nNamun, istilah "laboratorium nuklir" lebih umumnya berkaitan dengan alat dan eksperimen yang berfokus pada nuklir atau radiokimia, dan visible light spectrophotometer biasanya tidak termasuk dalam peralatan yang secara langsung terkait dengan nuklir. Instrumen yang terkait dengan nuklir mungkin melibatkan deteksi radiasi nuklir, pengukuran aktivitas nuklir, atau analisis radiokimia.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3393, 15, 1, '132080201019', 'Infrared Spectrophotometer', 'Infrared Spectrophotometer adalah alat laboratorium yang digunakan untuk menganalisis sampel berdasarkan interaksi antara sampel dengan radiasi inframerah.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3394, 15, 1, '132080201023', 'X-Ray Fluorescence(XRP)', 'X-Ray Fluorescence (XRF) adalah teknik analisis yang umum digunakan di laboratorium nuklir dan banyak bidang ilmiah lainnya. Ini adalah metode nondestruktif yang digunakan untuk menentukan komposisi unsur kimia dalam sampel. Meskipun istilah "fluorescence" digunakan dalam nama metode ini, teknik ini berbeda dari spektroskopi fluoresensi biasa.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3395, 15, 1, '132080201026', 'Polarimeter/Refractometer', 'Polarimeter adalah sebuah instrumen ilmiah yang digunakan untuk mengukur sudut rotasi yang disebabkan oleh lewat cahaya terpolarisasi melalui substansi optik aktif. Refraktometer atau refractometer adalah sebuah alat yang biasa digunakan untuk mengukur kadar/ konsentrasi bahan atau zat terlarut.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3396, 5, 1, '132070119002', 'Auto Well Gamma System', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3397, 15, 1, '132080201028', 'Thermoluminiscence Dosimeter (TLD) Reader', 'Thermoluminescence Dosimeter (TLD) Reader adalah peralatan yang digunakan untuk membaca dan mengukur dosis radiasi yang diterima oleh TLD, yaitu dosimeter yang menggunakan prinsip thermoluminescence untuk mendeteksi dan mengukur paparan radiasi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3398, 5, 1, '132070119003', 'Calibrator DST Kit', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3399, 15, 1, '132080201029', 'Uranium Ore Analyzer', 'Uranium Ore Analyzer atau analisis uranium adalah instrumen laboratorium yang dirancang khusus untuk mengukur dan menganalisis kandungan uranium dalam sampel mineral atau bijih uranium. Analisis uranium sangat penting dalam konteks industri nuklir, eksplorasi pertambangan, dan penelitian geologi. Beberapa metode yang umum digunakan untuk menganalisis uranium dalam sampel adalah spektrometri sinar gamma, spektrometri massa, atau teknik analisis lainnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3400, 5, 1, '132070119004', 'Complete Stese Test System With Bicycle', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3401, 15, 1, '132080201030', 'Amilograph Meter', 'Amylograph Meter adalah peralatan laboratorium yang digunakan untuk mengukur sifat viskoelastis dari tepung terigu dan produk-produk tepung lainnya saat proses pemanasan dan penggumpalan pati dalam suatu larutan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3402, 5, 1, '132070119005', 'Contaminator Monitor', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3403, 15, 1, '132080201031', 'Mass Spectrometer', 'Spektrometri massa (MS) adalah alat yang digunakan untuk menentukan massa atom atau molekul,. Prinsip kerja alat ini adalah pembelokan partikel bermuatan dalam medan magnet', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3404, 5, 1, '132070119006', 'CS 137 Chank Source 10 Micro', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3405, 15, 1, '132080201033', 'Magnetic Resonance Spectrometer', 'Spektroskopi resonansi magnetik nuklir, paling dikenal sebagai spektroskopi NMR atau spektroskopi resonansi magnetik, adalah teknik spektroskopi yang didasarkan pada reorientasi inti atom dengan putaran inti bukan nol dalam medan magnet luar.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3406, 5, 1, '132070119007', 'Currie Pie Survey Meter', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3407, 15, 1, '132080201036', 'Differential Thermal Analyzer', 'Differential Thermal Analyzer (DTA) adalah alat analisis termal yang digunakan untuk memahami sifat termal dari bahan atau sampel. Alat ini mengukur perbedaan suhu antara sampel dan referensi saat keduanya dipanaskan secara bersamaan dengan laju pemanasan yang konstan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3408, 5, 1, '132070119008', 'Deep Freezer (Alat Kedokteran Nuklir)', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3409, 15, 1, '132080201037', 'Thermo Analyzer', 'Thermo Analyzer adalah perangkat atau perangkat lunak yang digunakan untuk menganalisis data termal. Ini bisa merujuk pada berbagai jenis perangkat yang digunakan untuk mengukur, menganalisis, dan merekam informasi tentang suhu, konduktivitas termal, perubahan fasa, dan properti termal lainnya dari benda atau material tertentu.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3410, 15, 1, '132080201039', 'Thin Layer Chromatography(TLC) Drying Rack/ Desiccarator', 'Thin Layer Chromatography (TLC) Drying Rack atau Desiccator adalah peralatan yang digunakan dalam proses Thin Layer Chromatography (Kromatografi Lapis Tipis) untuk mengeringkan plat kromatografi lapis tipis setelah penerapan sampel dan fase gerak (biasanya larutan yang akan dipisahkan).', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3411, 5, 1, '132070119010', 'Film Formator', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3412, 15, 1, '132080201041', 'Gas Chromatograph(GC)', 'Kromatografi gas merupakan jenis kromatografi yang umum digunakan dalam analisis kimia untuk pemisahan dan analisis senyawa yang dapat menguap tanpa mengalami dekomposisi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3413, 5, 1, '132070119011', 'Gamma Cammera', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3414, 15, 1, '132080201042', 'Radio Chromatografic Scaner', 'Radio Thin Layer Chromatography (Radio-TLC) scanner adalah perangkat yang digunakan untuk mendeteksi dan mengukur senyawa yang telah diberi label radioaktif pada kromatografi lapis tipis (TLC) dengan menggunakan radiasi yang dipancarkan oleh senyawa tersebut.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3415, 5, 1, '132070119012', 'Generator TC', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3416, 15, 1, '132080201045', 'ICPMS (Inductively Complete Plasma Mass Spectometer)', 'Spektrometri massa plasma berpasangan induktif (ICP-MS) adalah teknik analisis yang dapat digunakan untuk mengukur unsur-unsur pada tingkat jejak dalam cairan biologis.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3417, 5, 1, '132070119013', 'Glove Box (Alat Kedokteran Nuklir)', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3418, 15, 1, '132080201047', 'Shileding', 'Perisai (shielding) adalah suatu bahan yang penting dalam laboratorium tegangan tinggi. Di mana perisai (shielding) berfungsi sebagai pelindung dari induksi tegangan yang ditimbulkan oleh pembangkitan tegangan tinggi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3419, 15, 1, '132080201055', 'Apron Dual Side', 'Double-Sided Apron merupakan alat perlindungan diri dari paparan Sinar Radiasi, Apron ini juga dapat melindungi bagian depan tubuh pengguna dengan kandungan timbal 0,5 mmPb.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3420, 5, 1, '132070119015', 'Hand Foot + Cloth Monitor', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3421, 15, 1, '132080201061', 'Senter Mini Standar Safety', 'Senter Mini Standard Safety adalah senter miniatur yang dirancang untuk memenuhi standar keamanan tertentu. Senter ini biasanya merupakan perangkat portabel dengan ukuran yang kecil namun kuat dalam menghasilkan cahaya yang cukup untuk keperluan penggunaan darurat atau tugas-tugas ringan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3422, 5, 1, '132070119016', 'Lab.Equipmen Techne Shaker', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3423, 15, 1, '132080201063', 'Flexible Waste Water Dam', 'Waste Water Dam (Bendungan Air Limbah) adalah struktur pembatas yang dirancang khusus untuk menahan aliran air limbah atau air buangan dari suatu sumber seperti pabrik, permukiman, atau industri lainnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3424, 5, 1, '132070119017', 'Low Energy Hight Resolution Collimator', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3425, 15, 1, '132080202001', 'Generalporpose Giass Thermometer', 'General Purpose Glass Thermometer adalah jenis termometer yang umum digunakan untuk mengukur suhu dalam berbagai konteks dan aplikasi umum. Biasanya terbuat dari kaca dan dilengkapi dengan skala pengukuran suhu.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3426, 5, 1, '132070119018', 'Mobil Unit Ditector System', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3427, 15, 1, '132080202004', 'Clinical Thermometer (Instrument Probe/sensor)', 'Termometer klinis atau termometer klinis adalah alat untuk mengukur suhu tubuh manusia atau hewan. Biasanya, termometer klinis digunakan untuk mengukur suhu tubuh manusia di klinik, rumah sakit, atau di rumah.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3428, 5, 1, '132070119019', 'Multi Format Cammera', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3429, 15, 1, '132080202007', 'Bimetal Thermometer', 'Bimetal  Thermometer adalah alat yang terdiri dari dua logam yang berbeda nilai koefisien muai panjangnya atau yang berbeda kecepatan pemuaiannya, direkatkan menjadi satu.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3430, 15, 1, '132080202008', 'Temperature Indicator', 'Temperature Indicator adalah sebuah perangkat atau instrumen yang digunakan untuk mengukur atau menunjukkan suhu dari suatu objek, lingkungan, atau sistem tertentu dalam satuan suhu yang relevan (seperti Celsius, Fahrenheit, atau Kelvin).', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3431, 5, 1, '132070119021', 'Optical Disk 800 Mb Front Loading Cartridge', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3432, 15, 1, '132080202009', 'Temperatur Recorder', 'Temperature recorder adalah perangkat yang digunakan untuk merekam dan memantau suhu dalam suatu lingkungan atau ruang selama periode waktu tertentu.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3433, 15, 1, '132080202013', 'UV/UV-VIS Radiometer', 'Radiometer UV/UV-VIS (Ultraviolet/Ultraviolet-Visible) adalah instrumen yang digunakan untuk mengukur intensitas radiasi elektromagnetik dalam rentang panjang gelombang UV dan/atau UV-VIS. Ini sering digunakan dalam laboratorium kimia dan spektroskopi untuk mengukur absorbansi atau transmisi sampel pada berbagai panjang gelombang.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3434, 15, 1, '132080202014', 'PH Meter/Indicator And Lon Meter', 'pH meter adalah alat yang digunakan untuk mengukur tingkat asam-basa suatu larutan. Alat ini digunakan di laboratorium untuk mengukur derajat keasaman (pH) suatu larutan, apakah larutan tersebut tergolong asam, basa atau netral.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3435, 15, 1, '132080202016', 'Dissolvel Oxygen Meter(DO)', 'Dissolved Oxygen Meter adalah alat ukur kualitas air yang digunakan untuk mengetahui kadar oksigen terlarut dalam suatu larutan atau air pada suatu perairan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3436, 5, 1, '132070119025', 'Renograph', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3437, 15, 1, '132080202017', 'Biologikal Oxygen Demand Monitor(BOD)', 'Biologikal Oxygen Demand Monitor (BOD Monitor) adalah alat yang digunakan untuk mengukur tingkat permintaan oksigen biologis (BOD) dalam air. BOD sendiri merupakan indikator penting untuk menilai kualitas air dan tingkat pencemaran organik.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3438, 5, 1, '132070119026', 'Serosym', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3439, 15, 1, '132080202018', 'Bourdan Vacuum Gauge', 'Bourdon Vacuum Gauge adalah alat pengukur tekanan vakum yang menggunakan prinsip mekanika Bourdon untuk mengukur tekanan di bawah tekanan atmosfer, seperti dalam kondisi vakum.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3440, 15, 1, '132080202019', 'Diaphragm Pressure/Vacuum Gauge', 'Diaphragm Pressure/Vacuum Gauge (Pengukur Tekanan/Vakum Membran) adalah alat ukur yang digunakan untuk mengukur tekanan dan vakum dalam berbagai aplikasi. Alat ini memanfaatkan prinsip elastisitas membran (diafragma) untuk mendeteksi perubahan tekanan dan menerjemahkannya menjadi nilai yang dapat dibaca pada skala atau layar digital.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3441, 5, 1, '132070119028', 'Cammera DST', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3442, 15, 1, '132080202022', 'Portable Flectronic Manometer', 'jenis manometer portabel yang digunakan dalam konteks laboratorium kimia atau lingkungan di mana pengukuran tekanan diperlukan.\n\n\n\nSebuah manometer adalah alat yang digunakan untuk mengukur tekanan dalam suatu sistem. "Flectronic" mungkin merujuk pada jenis sensor atau teknologi yang digunakan dalam manometer ini. Sebuah manometer elektronik (disebut juga sebagai transduser tekanan) dapat menggunakan sensor elektronik untuk mengukur tekanan dan mengonversinya menjadi sinyal elektronik yang dapat diukur.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3443, 5, 1, '132070119029', 'Spect Genesys + Accesoires', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3444, 15, 1, '132080202024', 'Vacuummeter', 'Vacuum meter adalah alat pengukur yang digunakan untuk mengukur tekanan vakum atau tekanan yang lebih rendah dari tekanan atmosfer', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3445, 5, 1, '132070119030', 'Surver Meter/Dosirate Meter', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3446, 15, 1, '132080202029', 'Piezoelectric Pressure Indicator', 'Sensor yang menggunakan efek piezoelektrik untuk mengukur perubahan tekanan, percepatan, suhu, regangan, atau gaya dengan mengubahnya menjadi muatan listrik. Awalan piezo- adalah bahasa Yunani untuk \'tekan\' atau \'meremas\'.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3447, 15, 1, '132080202031', 'Specific Gravitometer', 'Gravitometer adalah alat yang digunakan untuk mengukur percepatan gravitasi di suatu tempat tertentu.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3448, 5, 1, '132070119032', 'Thyroid Up Take', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3449, 15, 1, '132080202034', 'Densitometer General', 'Densitometer adalah alat atau perangkat yang digunakan untuk mengukur kepadatan suatu zat atau objek', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3450, 15, 1, '132080202036', 'Viscometer Viscosimeter', 'Viskometer adalah alat yang digunakan untuk mengukur viskositas fluida. Untuk cairan dengan viskositas yang berbeda dengan kondisi aliran, alat yang disebut Rheometer yang digunakan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3451, 5, 1, '132070119034', 'Scinlation Scanner', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3452, 15, 1, '132080202039', 'Orsat-Fischer Gas Analyzer', 'Orsat-Fischer Gas Analyzer adalah alat laboratorium yang digunakan untuk menganalisis komposisi gas dalam suatu sampel.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3453, 5, 1, '132070119035', 'Varios Collimatror', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3454, 15, 1, '132080202042', 'Dust Analyzer', 'Dust analyzer atau analisis debu adalah perangkat atau instrumen yang digunakan untuk mengukur konsentrasi debu atau partikel padat di udara atau lingkungan tertentu.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3455, 5, 1, '132070119036', 'Well Type Scintillatoin Counter Scale+Ratemate', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3456, 15, 1, '132080202043', 'Dust Sampler (Instrument Probe/sensor)', 'perangkat yang dirancang untuk mengumpulkan sampel debu atau partikulat di udara', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3457, 5, 1, '132070119037', 'Whole Body Cough', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3458, 15, 1, '132080202044', 'Gasmeter', 'Gasmeter adalah alat pengukur aliran yang dirancang khusus untuk mengukur volume gas bakar seperti natural gas dan Liquefied Petroleum Gas (LPG). Alat ini digunakan pada bangunan residensial, komersial, dan industrial yang mengonsumsi gas bakar dari perusahaan gas.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3459, 5, 1, '132070119038', 'Ria Equipment', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3460, 15, 1, '132080202045', 'Anemometer Flowmeter', 'Anemometer dan flowmeter adalah dua perangkat yang berbeda yang digunakan untuk mengukur aliran atau pergerakan fluida, tetapi keduanya memiliki tujuan yang berbeda.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3461, 15, 1, '132080202046', 'Venturumeter Flowmeter', 'Venturi Flow Meter adalah jenis flowmeter yang bekerja berdasarkan prinsip Persamaan Bernoulli. Perangkat ini banyak digunakan di industri air, kimia, farmasi, dan minyak & gas untuk mengukur laju aliran cairan di dalam pipa.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3462, 15, 1, '132080202049', 'Nozzlemeter Flowmeter', 'Flowmeter jenis nozzle meter adalah salah satu tipe alat yang digunakan untuk mengukur aliran fluida dalam pipa. Nozzle meter bekerja berdasarkan prinsip perubahan tekanan yang terjadi saat fluida mengalir melalui nozzle atau lubang penyempit di dalam flowmeter.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3463, 5, 1, '132070119041', 'Freezy Microtome (Cry Cut Microtome)', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3464, 15, 1, '132080202053', 'Tape Fioat Gage Level Indicator', 'alat yang digunakan untuk mengukur atau memantau tingkat atau level cairan dalam tangki atau wadah. Alat ini menggunakan prinsip pengapungan untuk menentukan tingkat cairan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3465, 5, 1, '132070119042', 'Microtomr Knife Sharpener', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3466, 15, 1, '132080202055', 'Bubble Tube Level Measumy System', 'Bubble tube level measurement system adalah sistem pengukuran level atau tingkat cairan yang menggunakan prinsip dasar dari pergerakan gelembung dalam tabung sebagai indikator tingkat cairan dalam tangki atau sistem tertentu.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3467, 5, 1, '132070119043', 'Automatic Tissue Processor (Alat Kedokteran Nuklir)', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3468, 15, 1, '132080202056', 'Flash Point Tester', 'Alat pengujian titik nyala (flash point tester) adalah perangkat yang digunakan untuk mengukur suhu minimum di mana cairan atau zat dapat menghasilkan uap yang cukup untuk membentuk campuran mudah terbakar dengan udara di dekat permukaannya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3469, 15, 1, '132080203002', 'Electronic Analytical Balance (General Laboratory Tool)', 'Analytical Balance adalah sebuah instrument laboratorium yang digunakan untuk mengukur massa suatu zat', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3470, 5, 1, '132070119045', 'Lamianir Air Flo', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3471, 15, 1, '132080203004', 'Electronic Microbalance', 'Electronic microbalance adalah alat laboratorium yang digunakan untuk mengukur massa dengan sangat presisi, bahkan dalam skala yang sangat kecil, seperti miligram atau mikrogram.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3472, 15, 1, '132080203007', 'Platform Scale (General Laboratory Tool)', 'Platform scale dalam konteks laboratorium adalah alat ukur yang digunakan untuk menimbang benda-benda dengan massa yang lebih besar atau untuk menimbang sejumlah besar sampel secara bersamaan', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3473, 15, 1, '132080203009', 'Table Balance', 'Table balance adalah alat pengukur berat atau timbangan yang digunakan di laboratorium untuk mengukur massa benda dengan presisi tinggi. Alat ini terdiri dari sebuah platform datar di atas sebuah pendulum atau sistem sensor yang sensitif terhadap perubahan massa', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3474, 5, 1, '132070119048', 'radiation Sterilizer', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3475, 15, 1, '132080203010', 'Electronic Control (General Laboratory Tool)', 'Electronic Control (Pengendali Elektronik) dalam konteks alat laboratorium umum mengacu pada berbagai perangkat elektronik yang digunakan untuk mengatur dan mengendalikan eksperimen, pengukuran, dan proses laboratorium. Ini mencakup berbagai alat, mulai dari yang sederhana hingga yang kompleks, yang memiliki peran penting dalam memastikan akurasi, presisi, dan keamanan dalam berbagai prosedur laboratorium', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3476, 15, 1, '132080203011', 'Balance Weight Set', 'Balance weight dalam konteks laboratorium merujuk pada serangkaian bobot standar yang digunakan untuk kalibrasi dan memeriksa keakuratan timbangan laboratorium. Mereka biasanya terbuat dari bahan yang tahan terhadap korosi, seperti stainless steel atau bahan logam lainnya yang memiliki kestabilan massa yang tinggi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3477, 15, 1, '132080203012', 'Rotator Heater Control', 'Rotator Heater Control dalam konteks laboratorium adalah perangkat yang digunakan untuk mengontrol putaran dan suhu pada peralatan rotasi, seperti perangkat rotasi untuk pencampuran, pengadukan, atau proses kimia tertentu.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3478, 5, 1, '132070119051', 'Microwave Cleaning Bath', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3479, 15, 1, '132080203013', 'UWFP Control Panel With HR', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3480, 15, 1, '132080203014', 'Recorder', 'Recorder (General Laboratory) adalah alat yang digunakan untuk merekam data dari berbagai sumber, seperti sensor, instrumen, dan mesin. Alat ini dapat merekam data dalam berbagai format, seperti grafik, tabel, dan data digital.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3481, 5, 1, '132070119053', 'Sereologi Bath', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3482, 15, 1, '132080203015', 'Water Sampler (General Laboratory Tool)', 'Water sampler adalah alat atau perangkat yang digunakan untuk mengambil sampel air dari berbagai sumber air seperti sungai, danau, atau laut untuk analisis laboratorium atau penelitian lingkungan', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3483, 15, 1, '132080203018', 'Wall Clock', 'Wall clock adalah jam dinding yang biasanya digunakan untuk menampilkan waktu pada dinding di berbagai ruangan, termasuk di laboratorium.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3484, 15, 1, '132080203019', 'Automatic On/Off Time Switch', 'Automatic On/Off Time Switch adalah perangkat yang secara otomatis mengontrol sumber daya listrik untuk menyalakan atau mematikan peralatan pada waktu tertentu.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3485, 5, 1, '132070119056', 'Growth Chanber', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3486, 15, 1, '132080203021', 'Tachometer (General Laboratory Tool)', 'alat yang digunakan untuk mengukur kecepatan rotasi atau putaran dalam percobaan atau penelitian tertentu', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3487, 15, 1, '132080203024', 'Battle Holder', 'perangkat atau alat yang dirancang khusus untuk menahan atau mendukung botol-botel berisi cairan, zat kimia, atau sampel dalam berbagai percobaan atau proses laboratorium', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3488, 15, 1, '132080203025', 'Team Heated Water Bath', 'Heated water bath adalah perangkat laboratorium yang digunakan untuk mempertahankan suhu yang stabil dan terkontrol dari air di dalam wadah yang dipanaskan', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3489, 15, 1, '132080203028', 'Sand Bath', 'Pemandian pasir (Sand Bath) adalah peralatan laboratorium umum yang terbuat dari wadah berisi pasir yang dipanaskan . Ini digunakan untuk memanaskan wadah lain secara merata, paling sering selama reaksi kimia.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3490, 15, 1, '132080203029', 'Thermostatic Water Bath', 'Thermostatic bath adalah perangkat laboratorium yang digunakan untuk menjaga suhu air secara konstan pada tingkat yang telah ditetapkan. Perangkat ini seringkali memiliki kontrol yang sangat presisi untuk mempertahankan suhu air pada tingkat yang diinginkan dengan tepat.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3491, 15, 1, '132080203030', 'Shaking Water Bath', 'Shaking Water Bath merupakan alat yang digunakan untuk proses pemanasan atau inkubasi sampel larutan sekaligus pencampuran.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3492, 15, 1, '132080203031', 'Test Tube Dry Bath', 'Test tube dry bath adalah perangkat yang digunakan untuk memanaskan atau menjaga suhu yang konstan pada tabung reaksi atau test tube.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3493, 5, 1, '132070119063', 'Air Flow Incubator', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3494, 15, 1, '132080203032', 'Cooling/Refregerating Bath', 'Cooling atau refrigeration bath adalah perangkat laboratorium yang digunakan untuk menjaga suhu sampel atau bahan pada tingkat pendinginan tertentu atau suhu rendah yang terkontrol.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3495, 15, 1, '132080203033', 'Cleaning Bath', 'Cleaning baths di laboratorium adalah perangkat yang digunakan untuk membersihkan dan menghilangkan kontaminan dari alat-alat laboratorium, seperti gelas laboratorium, tabung reaksi, atau instrumen lainnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3496, 5, 1, '132070119065', 'Hand Tally Counter', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3497, 15, 1, '132080203037', 'Thermostatic Refrigerating Cerculator', 'Thermostatic refrigerating circulator adalah perangkat laboratorium yang menggabungkan kemampuan untuk menjaga suhu yang tepat dengan fungsi pendinginan dalam satu sistem.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3498, 15, 1, '132080203040', 'Bunsen Gas Bumer', 'Pembakar Bunsen, dinamai dari Robert Bunsen, adalah sebuah peralatan laboratorium umum yang menghasilkan nyala api gas tunggal yang terbuka, yang digunakan untuk pemanasaan, sterilisasi, dan pembakaran.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3499, 5, 1, '132070119067', 'Blood Sedimentation Apparatus', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3500, 15, 1, '132080203045', 'Hot Plate (General Laboratory Tool)', 'Hot plate adalah alat yang umum digunakan di laboratorium untuk memanaskan sampel, cairan, atau bahan-bahan dalam wadah tertentu. Alat ini terdiri dari permukaan datar yang dipanaskan secara elektrik, biasanya terbuat dari logam tahan panas seperti aluminium atau tembaga, yang memungkinkan pengguna untuk mengatur suhu sesuai kebutuhan percobaan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3501, 15, 1, '132080203046', 'Cold Plate', 'Cold plate dalam konteks laboratorium adalah perangkat yang digunakan untuk mendinginkan atau menjaga suhu rendah dari sampel atau bahan yang ditempatkan di atasnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3502, 15, 1, '132080203049', 'Immersion Refrigerating Coil', 'Immersion cooler adalah perangkat yang digunakan untuk menurunkan suhu sampel atau cairan dalam suatu wadah dengan cara mencelupkan pendingin ke dalam cairan tersebut.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3503, 15, 1, '132080203050', 'Hot Plate With Magnetic Stiring (General Laboratory Tool)', 'Alat laboratorium yang digunakan untuk menghomogenkan larutan atau campuran larutan melalui proses pemanasan dan pengadukan secara mekanis.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3504, 5, 1, '132070119071', 'Haemachyto Meter', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3505, 15, 1, '132080203052', 'Water Percolator (Boiler)', 'Water percolator atau boiler dalam konteks laboratorium adalah perangkat yang digunakan untuk memanaskan air dengan tujuan tertentu dalam proses percobaan atau aplikasi laboratorium.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3506, 15, 1, '132080203053', 'Rotating Jig', 'Rotating jig adalah perangkat yang digunakan dalam proses fabrikasi, khususnya dalam pekerjaan logam atau kayu, untuk memegang dan memutar benda kerja secara tepat dan konsisten selama proses pemotongan, penggilingan, pengerolan, atau pemrosesan lainnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3507, 5, 1, '132070119073', 'Blood Calcium Analyzer', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3508, 15, 1, '132080203057', 'Heating Tape', 'Heating tape adalah sebuah perangkat pemanas fleksibel yang terbuat dari kawat resistif atau elemen pemanas yang tertanam di dalam bahan isolasi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3509, 5, 1, '132070119074', 'Blood ClorineAnalyzer', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3510, 15, 1, '132080203058', 'Kompor Listrik (General Laboratory Tool)', 'Kompor listrik dalam konteks laboratorium adalah perangkat yang digunakan untuk memanaskan atau mendidihkan cairan, melaksanakan reaksi kimia, atau melakukan proses pemanasan dalam berbagai percobaan atau kegiatan laboratorium', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3511, 15, 1, '132080203059', 'Infrared Lamp', 'Lampu inframerah adalah perangkat listrik yang memancarkan radiasi inframerah. Lampu inframerah umumnya digunakan dalam pemanasan berseri-seri untuk proses industri dan pemanas gedung', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3512, 15, 1, '132080203060', 'High Pressure Autoclave (W/Wo) Stirrer', 'Autoclave bertekanan tinggi dengan stirrer (disebut juga autoclave berpengaduk atau dengan pengaduk) adalah perangkat yang digunakan dalam proses laboratorium atau industri untuk melakukan reaksi kimia atau sintesis yang memerlukan tekanan tinggi dan pengadukan simultan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3513, 15, 1, '132080203061', 'High Pressure Shaking Autoclave', 'High Pressure Shaking Autoclave adalah alat laboratorium yang digunakan untuk melakukan proses autoklaf dengan tekanan tinggi sambil melakukan pengocokan atau pengadukan pada sampel di dalamnya', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3514, 15, 1, '132080203062', 'Pressure Vessel (General Laboratory Tool)', 'Pressure vessel atau wadah tekanan adalah alat atau perangkat yang digunakan dalam laboratorium untuk menampung bahan kimia, cairan, atau gas di bawah tekanan tertentu.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3515, 15, 1, '132080203066', 'Shaking Machine', 'Shaker adalah peralatan laboratorium yang digunakan untuk mencampur, memblender, atau mengaduk zat dalam tabung atau labu dengan cara dikocok.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3516, 15, 1, '132080203067', 'Test Tube Shaker', 'Shaker adalah peralatan laboratorium yang digunakan untuk mencampur, memblender, atau mengaduk zat dalam tabung atau labu dengan cara dikocok.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3517, 15, 1, '132080203071', 'Multiple Stining Unit', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3518, 15, 1, '132080203072', 'Magnetic Sterrer', 'Magnetic stirrer adalah perangkat laboratorium yang digunakan untuk mencampur larutan cair atau suspensi dengan menggunakan medan magnet yang menghasilkan putaran magnetik pada stir bar atau pengaduk magnetik di dalam wadah atau labu yang berisi bahan kimia.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3519, 15, 1, '132080203074', 'Ultrasonic Sceaner', 'Ultrasonography adalah sebuah alat medis dengan teknik pencitraan menggunakan suara ultra yang digunakan untuk mencitrakan organ internal dan otot ,ukuran mereka,struktur dan luka patologi membuat teknik ini berguna unutk memeriksa organ manusia dengan memanfaatkan gelombang ultrasonik(gelombang suara frekuensi tinggi)', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3520, 15, 1, '132080203076', 'Laboratory Sieve Set', 'Laboratory sieve set adalah kumpulan saringan yang biasanya digunakan dalam laboratorium untuk analisis ukuran partikel atau gradasi material.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3521, 15, 1, '132080203077', 'Vibrating Screen (General Laboratory Tool)', 'Laboratory vibrating screen, atau layar getar laboratorium, adalah alat yang digunakan dalam laboratorium untuk memisahkan partikel berdasarkan ukuran mereka. Ini sering digunakan dalam berbagai aplikasi di laboratorium, pengembangan produk, dan penelitian untuk menyaring dan mengklasifikasikan berbagai jenis bahan atau sampel.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3522, 15, 1, '132080203080', 'Laboratory Cylender Centrifuge', 'Laboratory Centrifuge (Sentrifuga Laboratorium):\n\nSentrifuga laboratorium adalah perangkat yang digunakan untuk memisahkan partikel dalam suatu larutan berdasarkan perbedaan massa jenis. Proses ini memanfaatkan gaya sentrifugal yang dihasilkan oleh rotasi tinggi dari wadah atau tabung yang berisi sampel.\nSentrifuga dapat digunakan untuk memisahkan sel, partikel padat, dan cairan dalam berbagai konteks laboratorium seperti biologi sel, kimia, dan bidang kesehatan.\nTerdapat berbagai jenis sentrifuga, termasuk sentrifuga umum, sentrifuga pendingin, dan sentrifuga ultrasisa.\nLaboratory Cylinder (Silinder Laboratorium):\n\nSilinder laboratorium adalah wadah berbentuk silinder yang digunakan untuk mengukur volume cairan atau zat padat. Silinder ini biasanya terbuat dari kaca atau plastik dan memiliki skala ukur yang terukir atau tercetak untuk membantu dalam pengukuran volumetri yang akurat.\nSilinder laboratorium sering digunakan dalam proses pengukuran volumetri dan pencampuran larutan. Berbagai jenis silinder laboratorium termasuk silinder beaker, silinder ukur, dan silinder pisah.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3523, 5, 1, '132070119087', 'Head Lamp (Alat Kedokteran Nuklir)', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3524, 15, 1, '132080203081', 'Laboratory Basket Centrifuge', 'Laboratory basket centrifuge adalah jenis centrifuge yang digunakan dalam lingkungan laboratorium untuk memisahkan suspensi atau cairan dengan kecepatan tinggi melalui gaya sentrifugal yang dihasilkan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3525, 15, 1, '132080203086', 'Muffie Furnace', 'Muffle furnace adalah salah satu instrumen laboratorium yang digunakan untuk memanaskan bahan ke suhu yang lebih tinggi dan menjaganya dari kontaminan eksternal atau bahan kimia', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3526, 5, 1, '132070119089', 'Thyroid Uptake System', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3527, 15, 1, '132080203087', 'Transformer', 'Transformator adalah perangkat elektromagnetik yang digunakan untuk mentransfer daya listrik antara dua atau lebih sirkuit melalui induksi elektromagnetik', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3528, 15, 1, '132080203090', 'Lab Water Purifier/Demmeralizer', 'Lab water purifier atau demineralizer adalah perangkat yang dirancang khusus untuk membersihkan air dari berbagai kontaminan seperti mineral, ion-ion, partikel, dan bahan organik lainnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3529, 5, 1, '132070119091', 'Whole Bode Scanner', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3530, 15, 1, '132080203095', 'Room Humidifier', 'Humidifier merupakan alat pelembap udara yang bekerja dengan cara menyemprotkan uap air ke udara.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3531, 5, 1, '132070119092', 'Wellytype Gamma Scanner', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3532, 15, 1, '132080203096', 'Room Dehudifier', 'Dehumidifier adalah alat yang bisa menjaga kelembapan udara di dalam ruangan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3533, 15, 1, '132080203097', 'Humadity Chamber (General Laboratory Tool)', 'Humidity chamber adalah perangkat yang digunakan dalam laboratorium untuk menciptakan lingkungan kontrol yang dapat mensimulasikan berbagai tingkat kelembaban atau humidity levels', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3534, 15, 1, '132080203098', 'Laboratory /Service Wagon/Cart', 'Laboratory service wagon atau cart adalah sebuah alat yang digunakan di lingkungan laboratorium untuk menyimpan, mengatur, dan mengangkut berbagai peralatan atau bahan yang digunakan dalam proses penelitian, percobaan, atau kegiatan laboratorium lainnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3535, 5, 1, '132070119095', 'Sutine Reedle', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3536, 15, 1, '132080203102', 'Vacuum System', 'Sistem vakum (vacuum system) dalam konteks laboratorium adalah sistem yang menciptakan tekanan vakum di dalam suatu ruang atau sistem tertentu. Sistem vakum sering digunakan dalam berbagai aplikasi laboratorium, termasuk evaporasi, distilasi, filtrasi vakum, dan proses-proses lain yang memerlukan pengaturan tekanan rendah.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3537, 5, 1, '132070119096', 'Sutine', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3538, 15, 1, '132080203104', 'Regulator Pemanas', 'Regulator pemanas adalah perangkat yang digunakan untuk mengatur suhu pada alat pemanas', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3539, 15, 1, '132080203105', 'Pemanas Jaket', 'Pemanas jaket atau jaket pemanas (heating mantle) adalah perangkat laboratorium yang dirancang untuk memberikan pemanasan merata dan kontrol suhu pada wadah laboratorium.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3540, 15, 1, '132080203107', 'Crystal Growing+Cutter Mach', 'merujuk kepada mesin pemotong atau alat pemotong yang digunakan dalam berbagai konteks, termasuk manufaktur, konstruksi, atau pengolahan material.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3541, 15, 1, '132080203108', 'Kandang Logam Untuk Penelitian', 'Kandang logam atau kandang penelitian dari logam dapat digunakan dalam berbagai konteks penelitian untuk menyediakan lingkungan terkendali untuk hewan percobaan atau eksperimen tertentu. Kandang ini dapat dirancang untuk memastikan keamanan hewan, kontrol suhu, ventilasi, dan pengamatan yang tepat.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3542, 15, 1, '132080203110', 'Rak Kandang Logam Untuk Penelitian', 'Rak Kandang logam atau kandang penelitian dari logam dapat digunakan dalam berbagai konteks penelitian untuk menyediakan lingkungan terkendali untuk hewan percobaan atau eksperimen tertentu. Kandang ini dapat dirancang untuk memastikan keamanan hewan, kontrol suhu, ventilasi, dan pengamatan yang tepat.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3543, 15, 1, '132080203112', 'Electric Digital', 'laboratorium yang menggunakan peralatan listrik digital. Laboratorium semacam ini menggunakan perangkat dan alat yang didukung oleh teknologi digital, seperti peralatan yang dioperasikan secara elektronik dan dapat dikendalikan melalui antarmuka digital.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3544, 15, 1, '132080203114', 'Manual Screen', 'layar atau screen yang dikendalikan secara manual, berlawanan dengan layar yang dikendalikan secara otomatis atau elektronik.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3545, 5, 1, '132070119103', 'Pectum Set', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3546, 15, 1, '132080203117', 'Panel Elevator', 'Panel elevator adalah bagian dari sistem kontrol dan tampilan di dalam lift atau elevator.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3547, 5, 1, '132070119104', 'Tracheotr Set', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3548, 15, 1, '132080203118', 'Test Tube Holder', 'Test tube holder atau pegangan tabung reaksi adalah alat laboratorium yang dirancang khusus untuk memegang tabung reaksi dengan aman dan nyaman. Alat ini sangat berguna ketika Anda perlu memanaskan atau menggoyangkan tabung reaksi, terutama saat tabung tersebut panas', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3549, 15, 1, '132080203120', 'Holder Beverance Thermo', 'Holder beverage thermometer adalah alat atau perangkat yang digunakan untuk menahan atau memegang termometer dalam konteks minuman. Umumnya, ini adalah perangkat yang dirancang khusus untuk menopang atau menyimpan termometer yang digunakan untuk mengukur suhu dalam minuman.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3550, 15, 1, '132080203121', 'Wall Screen', 'Wall screen dalam konteks laboratorium kimia nuklir mungkin mengacu pada layar dinding atau proyeksi yang digunakan untuk menampilkan data, informasi, atau hasil percobaan secara visual di dalam laboratorium tersebut. Penggunaan wall screen dapat memiliki beberapa tujuan dan aplikasi, tergantung pada kebutuhan laboratorium dan jenis eksperimen yang dilakukan', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3551, 5, 1, '132070119107', 'Blood Exchange Set (Alat Kedokteran Nuklir)', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3552, 15, 1, '132080204001', 'Burette', 'Burette adalah perangkat laboratorium yang digunakan untuk mengukur volume cairan dengan presisi tinggi. Buret dapat terbuat dari kaca (glassware) atau plastik, tergantung pada kebutuhan aplikasi atau preferensi pengguna.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3553, 15, 1, '132080204003', 'Pipetter Epperdort', 'Mikropipet adalah suatu alat yang digunakan untuk mengambil dan/atau memnidahkan cairan dalam jumlah kecil secara akurat .', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3554, 15, 1, '132080204006', 'Water Chiller', 'Water chiller adalah perangkat yang digunakan untuk menurunkan suhu air atau cairan lainnya menjadi suhu yang lebih rendah dari suhu ruangan atau dari suhu semula', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3555, 15, 1, '132080204008', 'Cendensor (Liebig Davis,Dimrot,Spiral Allhm)', 'Kondensor adalah perangkat yang digunakan untuk mengubah uap menjadi cairan dengan menghilangkan panas dari uap tersebut.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3556, 15, 1, '132080204009', 'Soxhlel Extractor', 'Ekstraktor Soxhlet adalah alat yang digunakan dalam kimia untuk mengekstraksi senyawa yang larut dalam pelarut tertentu dari sebuah sampel padat', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3557, 15, 1, '132080204010', 'Crucible (Quartz,Porcelain)', 'Crucible adalah wadah kecil yang tahan terhadap panas yang digunakan dalam laboratorium untuk memanaskan, mendidih, atau menguapkan bahan kimia', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3558, 15, 1, '132080204011', 'Curcible (Nickel. Etc)', 'Nickel crucible adalah wadah kecil yang terbuat dari nikel, yang digunakan dalam berbagai aplikasi laboratorium dan industri.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3559, 15, 1, '132080204014', 'Beaker', 'Gelas kimia (gelas beker) terbuat dari kaca dengan berbagai ukuran. Fungsi gelas kimia (gelas beker) yaitu sebagai tempat mereaksikan bahan, tempat menampung bahan kimia berupa larutan, padatan, pasta ataupun tepung, tempat melarutkan bahan dan tempat memanaskan bahan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3560, 6, 1, '132070120005', 'Air Jacketed Dry C02 Incubator', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3561, 15, 1, '132080204017', 'Retort (Glassware Plastic/utensils)', 'Retort adalah perangkat laboratorium yang digunakan untuk menguapkan atau mengembalikan cairan ke bentuk gas dan kemudian mengembalikannya ke bentuk cairan lagi. Retort umumnya terbuat dari kaca (glassware), logam, atau plastik, tergantung pada kebutuhan aplikasi atau eksperimen. Retort sering digunakan dalam berbagai proses laboratorium, termasuk distilasi dan pemurnian zat kimia.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3562, 6, 1, '132070120006', 'Anuscope & Rectoscope', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3563, 15, 1, '132080204018', 'Funnel', 'Funnel adalah alat laboratorium berbentuk corong yang umumnya digunakan untuk mentransfer cairan atau zat padat ke dalam wadah dengan lubang kecil. Funnels dapat memiliki berbagai desain dan ukuran untuk memenuhi berbagai kebutuhan eksperimen dan aplikasi di laboratorium', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3564, 15, 1, '132080204020', 'Safety Container/Jerrican', 'Safety containers atau jerrican laboratorium adalah wadah khusus yang dirancang untuk menyimpan, mentransfer, atau mengangkut bahan kimia dan zat berbahaya di lingkungan laboratorium. Desain dan bahan pembuatannya dirancang dengan memperhatikan keselamatan pengguna dan keamanan zat kimia yang disimpan di dalamnya', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3565, 6, 1, '132070120008', 'High Resolution Stereoscopic Documentation - Colposcopy Lengkap', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3566, 15, 1, '132080204021', 'Safety Container', 'Safety containers atau wadah keselamatan di laboratorium adalah perangkat yang dirancang khusus untuk menyimpan, mentransfer, atau mengolah bahan kimia dan zat berbahaya secara aman', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3567, 15, 1, '132080204023', 'Flat Bottom Flask', 'Flat-bottom flask atau labu datar adalah jenis labu yang memiliki dasar datar atau hampir datar sehingga bisa diletakkan dengan stabil pada permukaan datar. Labu ini sering digunakan di laboratorium untuk berbagai keperluan, termasuk pemanasan, reaksi kimia, dan pengukuran volumetri.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3568, 15, 1, '132080204024', 'Round Bottom Flask', 'Round bottom flask atau labu berbentuk bulat adalah jenis labu laboratorium yang memiliki dasar bulat dan tumpul. Labu ini umumnya digunakan dalam berbagai aplikasi di laboratorium, terutama dalam reaksi kimia yang melibatkan pemanasan atau destilasi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3569, 15, 1, '132080205001', 'Generator Set (Lab Scale)', 'Generator set (lab scale) adalah perangkat yang digunakan untuk menghasilkan listrik dalam skala laboratorium atau skala kecil. Ini bisa mencakup berbagai jenis generator, seperti generator DC (arus searah) atau generator AC (arus bolak-balik), tergantung pada tujuan dan eksperimen yang akan dilakukan di laboratorium.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3570, 15, 1, '132080205003', 'Eye Goggles', 'Eye goggles atau kacamata pelindung mata sangat penting digunakan dalam laboratorium kimia nuklir untuk melindungi mata dari potensi bahaya kimia dan partikel yang mungkin muncul selama eksperimen atau penanganan bahan nuklir. Kacamata pelindung yang digunakan di laboratorium kimia nuklir harus dirancang khusus untuk menanggulangi risiko yang terkait dengan radiasi dan bahan kimia yang digunakan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3571, 6, 1, '132070121001', 'Amnioscope (Alat Kedokteran Gawat Darurat)', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3572, 15, 1, '132080205005', 'Anti Dust & Toxic Fume Respirator', 'Respirator Anti Dust & Toxic Fume atau masker pernapasan dirancang khusus untuk melindungi saluran pernapasan dari debu dan asap yang berbahaya, seperti yang mungkin ditemui di lingkungan laboratorium. Pemilihan dan penggunaan respirator yang tepat sangat penting untuk mengurangi risiko terpapar zat berbahaya', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3573, 15, 1, '132080205006', 'Eyewash Station', 'Eyewash station adalah perangkat darurat yang disediakan di berbagai lokasi kerja, laboratorium, fasilitas industri, atau tempat-tempat di mana bahan-bahan kimia atau bahan berbahaya dapat menyebabkan iritasi atau cedera pada mata.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3574, 15, 1, '132080205008', 'Lead Glass Window', 'jendela kaca yang dirancang khusus untuk memberikan perlindungan terhadap radiasi ionisasi, seperti sinar-X atau sinar gamma, yang mungkin dihasilkan selama eksperimen atau prosedur di laboratorium', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3575, 15, 1, '132080205009', 'FPM Target Holder Assembly', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3576, 6, 1, '132070121005', 'Basic Diagnostic Kit (Alat Kedokteran Gawat Darurat)', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3577, 15, 1, '132080205011', 'Fire Extinguisher', 'Fire Extinguisher merupakan pemadam api portabel yang dapat mengeluarkan air, busa, gas, dan media lainnya yang mampu untuk memadamkan api penyebab dari kebakaran.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3578, 15, 1, '132080205013', 'Capsule Handlling Toll & LA', 'perangkat khusus yang digunakan di laboratorium nuklir untuk menangani kapsul radioaktif. Ini dirancang untuk memanipulasi dan mentransfer kapsul ini dengan aman dan efisien, meminimalkan risiko paparan radiasi.\n\nAlat tersebut terdiri dari lengan robot dengan gripper di ujungnya, yang dapat mengambil dan memindahkan kapsul. Lengan dipasang pada alas yang memberikan stabilitas dan mobilitas, memungkinkannya menjangkau berbagai lokasi di dalam laboratorium.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3579, 15, 1, '132080205017', 'Smoke Detecting System & Alarm', 'Smoke Detector merupakan salah satu jenis detektor alarm kebakaran yang sering digunakan dalam instalasi fire alarm system. Detektor kebakaran ini akan mendeteksi gejala-gejala yang dapat menyebabkan kebakaran dari asap yang timbul dalam suatu ruangan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3580, 15, 1, '132080205018', 'Fume/Gas Leak Detector (Laboratory Safety Equipment)', 'Fume/Gas Leak Detector (Laboratory Safety Equipment) yang digunakan di laboratorium kimia nuklir adalah alat yang dirancang khusus untuk mendeteksi kebocoran gas atau uap yang dapat menjadi ancaman terhadap keselamatan di lingkungan laboratorium yang terkait dengan penelitian nuklir atau kimia.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3581, 15, 1, '132080205020', 'Electronic Controls', 'komponen atau sistem kendali elektronik yang digunakan untuk mengontrol dan mengatur fungsi peralatan atau instrumen laboratorium yang menggunakan teknologi elektronika. Ini dapat mencakup berbagai jenis alat dan perangkat yang digunakan dalam berbagai aplikasi laboratorium. Berikut adalah beberapa contoh alat laboratorium yang umumnya menggunakan electronic controls:\n\nSpektrofotometer:\n\nAlat ini digunakan untuk mengukur intensitas cahaya pada berbagai panjang gelombang, digunakan dalam analisis kimia dan biokimia.\nKromatografi Gas atau Cair (GC atau HPLC):\n\nAlat ini menggunakan kontrol elektronik untuk mengatur aliran sampel dan fase gerak, serta mendeteksi dan menganalisis komponen-komponen dalam campuran.\nPCR (Polymerase Chain Reaction) Machine:\n\nMesin PCR menggunakan kontrol elektronik untuk mengatur suhu dan waktu dalam proses amplifikasi DNA.\nSpectrophotometer UV-Vis:\n\nAlat ini digunakan untuk mengukur absorbansi atau transmisi cahaya pada panjang gelombang tertentu dalam spektrum UV-Visible.\nAutoclave:\n\nPada autoclave, kontrol elektronik digunakan untuk mengatur suhu dan tekanan selama proses sterilisasi.\nIncubator:\n\nIncubator digunakan untuk memelihara kondisi lingkungan tertentu seperti suhu dan kelembaban untuk pertumbuhan mikroorganisme atau kultur sel.\nSpectrometer:\n\nAlat ini digunakan untuk menganalisis spektrum cahaya atau sinyal elektromagnetik dalam berbagai eksperimen fisika atau kimia.\nElectrophoresis Apparatus:\n\nKontrol elektronik digunakan untuk mengatur arus listrik, waktu, dan kondisi lainnya selama elektroforesis gel dalam analisis biokimia dan genetika.\nLaboratory Shakers dan Stirrers:\n\nAlat ini menggunakan kontrol elektronik untuk menghasilkan gerakan getar atau mengaduk dalam berbagai kecepatan atau pola, bergantung pada kebutuhan eksperimen.\nCentrifuge:\n\nCentrifuge menggunakan kontrol elektronik untuk mengatur kecepatan dan durasi putaran selama pemisahan bahan-bahan dalam sampel.\nLaboratory Ovens:\n\nOvens laboratorium menggunakan kontrol elektronik untuk mempertahankan suhu tertentu selama proses pemanasan atau pengeringan.\nData Acquisition Systems:\n\nSistem akuisisi data menggunakan kontrol elektronik untuk mengumpulkan, memproses, dan merekam data dari berbagai alat dan sensor di laboratorium.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3582, 15, 1, '132080205021', 'Glove Box (Laboratory Safety Equipment)', 'Glove Box adalah perangkat keamanan laboratorium yang dirancang untuk melindungi para peneliti atau teknisi dari bahan-bahan berbahaya atau sensitif yang mereka tangani di dalam laboratorium.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3583, 15, 1, '132080205022', 'Fume Hood (Laboratory Safety Equipment)', 'Fume hood atau dalam bahasa Indonesia dikenal sebagai kap ruang penghisap adalah perangkat yang digunakan di laboratorium untuk menghisap atau menyalurkan gas, uap, debu, atau bahan kimia berbahaya keluar dari lingkungan kerja', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3584, 15, 1, '132080205023', 'Acid Hood (Laboratory Safety Equipment)', 'Acid hood atau asam hood adalah salah satu peralatan keselamatan laboratorium yang dirancang khusus untuk penggunaan bahan kimia yang bersifat asam atau korosif.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3585, 6, 1, '132070121013', 'Colposcopy', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3586, 15, 1, '132080205024', 'Special Support Equip (Laboratory Safety Equipment)', 'peralatan khusus yang dirancang untuk memberikan dukungan dan perlindungan tambahan saat melakukan eksperimen atau pekerjaan di laboratorium.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3587, 6, 1, '132070121014', 'Crystoscope', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3588, 15, 1, '132080205026', 'High Volume Air Sampler', 'High Volume Air Sampler (HVAS) adalah perangkat yang digunakan untuk mengambil sampel udara dalam jumlah besar dan memungkinkan analisis lebih lanjut dari partikel-partikel yang terdapat dalam sampel tersebut.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3589, 16, 1, '132080301001', 'Alat Peraga Praktek Sekolah Bidang Studi : Bahasa Indonesia', 'Alat peraga praktek dalam bidang studi Bahasa Indonesia dapat membantu siswa memahami konsep-konsep bahasa, meningkatkan keterampilan membaca, menulis, mendengar, dan berbicara. Berikut adalah beberapa contoh alat peraga praktek yang dapat digunakan dalam pengajaran Bahasa Indonesia:', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3590, 16, 1, '132080301002', 'Kit Bahasa A', 'Kit Bahasa A merupakan alat peraga bantu bahasa indonesia untuk mengenalkan huruf dan kemampuan melafalkan alfabet dengan ucapan yang tepat, mendorong aktivitas siswa mengenal huruf dan bentuk kata secara interaktif', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3591, 16, 1, '132080301003', 'Papan Panel', 'Papan panel merupakan alat peraga sebagai sarana atau alat bantu guru untuk memperagakan topik-topik yang menggunakan peraga yang dibuat dari kain flanel atau berlapiskan busa tipis.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3592, 6, 1, '132070121018', 'Differential Leucocyte Counter', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3593, 16, 1, '132080301004', 'Kit SAS Individual', 'Kit SAS Individual (alat peraga) adalah serangkaian alat bantu yang dirancang untuk membantu orang-orang dengan kondisi kesehatan mental seperti kecemasan, depresi, dan gangguan stres pascatrauma (PTSD). Alat-alat ini dapat digunakan oleh individu, kelompok, atau profesional kesehatan mental.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3594, 16, 1, '132080301005', 'Kotak Alat-alat Peraga Metode SAS', 'Metode SAS adalah pembelajaran membaca permulaan menggunakan proses penguraian kalimat menjadi kata, kata menjadi suku kata, suku kata menjadi huruf/fonem itu kemudian dilanjutkan dengan proses sintetik.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3595, 16, 1, '132080301006', 'Gambar Total', 'Istilah "Gambar Total" terlalu umum dan tidak memberikan konteks yang jelas. Tanpa informasi tambahan atau konteks lebih lanjut, sulit untuk memberikan jawaban yang spesifik. Beberapa kemungkinan interpretasi dari "Gambar Total" bisa mencakup:Gambar Keseluruhan,Totalitas Gambar dan gambar lainya', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3596, 6, 1, '132070121021', 'Electronic Reading Balance (Alat Kedokteran Gawat Darurat)', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3597, 16, 1, '132080301007', 'Gambar Analitik', '"Gambar Analitik" terlalu umum dan tidak memberikan konteks yang jelas. "Analitik" dapat merujuk pada proses analisis atau pemahaman data, sedangkan "gambar" bisa merujuk pada visualisasi atau representasi grafis. contoh:Grafik atau Diagram Analitik,Gambaran Analitik dalam Konteks Bisnis: dan gambar lainya', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3598, 16, 1, '132080301008', 'Kotak Bahasa Untuk Kartu Kalimat Huruf Cetak dan Kartu Kalimat Huruf Tulis (nomor 66 dan nomor 6)', 'Kartu kalimat adalah media pembelajaran yang digunakan untuk membantu siswa dalam belajar membaca dan menulis. Kartu kalimat biasanya terdiri dari dua bagian, yaitu bagian depan yang berisi kalimat dan bagian belakang yang berisi gambar', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3599, 16, 1, '132080301009', 'Kartu Kalimat Huruf Cetak', 'Kartu kalimat dengan huruf cetak adalah alat pembelajaran yang dapat membantu anak-anak dalam mengembangkan keterampilan membaca dan menulis. Kartu-kartu ini biasanya berisi kalimat-kalimat sederhana yang disertai dengan huruf-huruf cetak untuk membantu anak mengenali kata-kata dan memahami struktur kalimat', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3600, 16, 1, '132080301010', 'Kartu Kalimat Dengan Huruf Cetak', 'Kartu kalimat dengan huruf cetak adalah alat pembelajaran yang dapat membantu anak-anak dalam mengembangkan keterampilan membaca dan menulis. Kartu-kartu ini biasanya berisi kalimat-kalimat sederhana yang disertai dengan huruf-huruf cetak untuk membantu anak mengenali kata-kata dan memahami struktur kalimat', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3601, 16, 1, '132080301011', 'Kotak Bahasa Untuk Kartu Kata Dan Kartu Suku Kata dan Kartu Huruf', 'Kotak bahasa adalah alat yang sering digunakan dalam pendidikan anak usia dini untuk membantu pengenalan huruf, kata, dan suku kata. \nKotak Huruf:\n\n\n\nIni adalah kotak yang berisi huruf-huruf alfabet. Setiap huruf dapat memiliki kotak atau tempat penyimpanan sendiri. Anak-anak dapat menggunakan huruf-huruf ini untuk membangun kata-kata.\n\n\nKotak Kata:\n\n\n\nKotak ini dapat berisi kartu-kartu dengan kata-kata. Kartu-kartu ini bisa memiliki gambar atau teks yang sesuai dengan kata tersebut.\n\nKotak Suku Kata:\n\n\n\nKotak ini berisi kartu-kartu dengan suku kata. Suku kata ini bisa digunakan untuk membantu anak-anak memahami struktur dan pembentukan kata.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3602, 6, 1, '132070121026', 'Hemorrhage Detection Unit', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3603, 16, 1, '132080301012', 'Kartu Kata dengan Huruf Cetak', 'sebagai alat peraga, kemungkinan besar merujuk pada kartu-kartu yang digunakan sebagai sarana pembelajaran untuk mengajarkan kata-kata atau membantu siswa memperluas kosa kata mereka.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3604, 16, 1, '132080301013', 'Kartu Suku Kata dengan Huruf Cetak', 'Kartu suku kata ini berisi abjad-abjad yang ditulis pada potongan media seperti karton, kertas, atau papan tulis', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3605, 16, 1, '132080301014', 'Kartu Huruf dengan Huruf Cetak', 'Kartu huruf dengan huruf cetak adalah kartu yang biasanya digunakan dalam pembelajaran awal membaca dan menulis. Kartu-kartu ini memiliki huruf cetak, yaitu huruf-huruf yang dicetak secara jelas dan besar pada kartu-kartu tersebut.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3606, 16, 1, '132080301015', 'Papan Alfabet', 'Papan alfabet adalah alat atau media pembelajaran yang digunakan dalam pendidikan anak usia dini atau untuk membantu dalam pembelajaran bahasa.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3607, 16, 1, '132080301016', 'Kain Panel', 'Kain flannel merupakan salah satu jenis kain yang banyak digunakan dalam pembuatan kerajinan tangan', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3608, 16, 1, '132080302001', 'Kit Matematika', 'Kit matematika bisa merujuk pada sejumlah peralatan atau bahan-bahan yang dirancang untuk membantu pembelajaran matematika', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3609, 16, 1, '132080302002', 'Roda Motor', 'Roda adalah objek berbentuk lingkaran, yang bersama dengan sumbu, dapat menghasilkan suatu gerakan dengan gesekan kecil dengan cara bergulir.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3610, 6, 1, '132070121033', 'Microcell Counter', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3611, 16, 1, '132080302003', 'Muka Jam', 'Tampilan jam atau muka jam (dalam bahasa Inggris disebut dial atau clock face) adalah bagian dari jam analog atau jam tangan yang menunjukkan waktu pada cakra angkanya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3612, 6, 1, '132070121034', 'Neonatal Monitor (Alat Kedokteran Gawat Darurat)', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3613, 16, 1, '132080302004', 'Rak Bilangan Dua Ruang', 'Timbangan bilangan adalah alat peraga matematika yang berbentuk seperti timbangan, biasanya digunakan untuk menjelaskan konsep operasi penjumlahan, pengurangan, perkalian, dan pembagian pada bilangan asli.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3614, 16, 1, '132080302005', 'Rak Bilangan Tiga Ruang', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3615, 16, 1, '132080302006', 'Papan Planel', 'Papan flanel adalah papan yang berlapis kain flanel sehingga gambar yang disajikan dapat dipasang, dilipat, dan dilepas dengan mudah dan juga dapat dilakukan berkali-kali.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3616, 16, 1, '132080302007', 'Papan Bergerak', 'Istilah "papan bergerak" dapat digunakan dalam berbagai konteks untuk merujuk pada suatu platform atau alat yang memungkinkan pergerakan, baik dalam hal promosi, pendidikan, permainan, atau teknologi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3617, 16, 1, '132080302008', 'Papan Berpaku', 'Papan berpaku dalam konteks matematika biasanya mengacu pada papan atau papan tulis yang memiliki grid atau jaring yang terbuat dari paku dan benang yang membentuk bidang koordinat atau ruang yang memungkinkan pengguna untuk melakukan eksplorasi matematika atau geometri.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3618, 16, 1, '132080302009', 'Papan Pasak', 'Papan pasak adalah papan keras dengan lubang-lubang merata yang sudah dibor sebelumnya. Lubang-lubang tersebut digunakan untuk pasak atau pengait guna mendukung pekerjaan berbagai macam peralatan, seperti alat dalam bengkel, elektronik, dan lainnya', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3619, 16, 1, '132080302010', 'Kubus Untuk Bilangan Berbaris Sepuluh', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3620, 6, 1, '132070121041', 'Othalpaedic Set', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3621, 16, 1, '132080302011', 'Abakus Untuk Bilangan Berbaris', 'Swipoa (dikenal pula sebagai sempoa, sipoa, dekak-dekak, atau abakus) adalah alat kuno untuk berhitung yang dibuat dari rangka kayu dengan sederetan poros berisi manik-manik yang bisa digeser-geserkan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3622, 16, 1, '132080302012', 'Pengukur Luas', 'alat peraga atau perangkat yang digunakan untuk membantu dalam mengajarkan konsep atau keterampilan pengukuran luas.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3623, 6, 1, '132070121043', 'Rectoscope', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3624, 16, 1, '132080302013', 'Blok Untuk Bilangan', 'Blok bilangan adalah alat peraga multiguna yang digunakan untuk merepresentasikan dan mengajarkan konsep-konsep matematika, terutama untuk anak usia dini dan sekolah dasar.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3625, 16, 1, '132080302014', 'Bangun-bangun Ruang', 'Bangun ruang adalah suatu bangunan tiga dimensi yang memiliki ruang atau volume dan juga sisi yang membatasinya', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3626, 16, 1, '132080302015', 'Pola Bangun Ruang', 'Pola bangun ruang merujuk pada susunan atau tata letak dari bentuk-bentuk geometris dalam ruang tiga dimensi yang diulang secara teratur atau terorganisir. Pola ini bisa terdiri dari berbagai bangun ruang yang diatur secara sistematis dan berulang', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3627, 16, 1, '132080302016', 'Kerangka Benda Ruang', 'Kerangka bangun ruang merujuk pada struktur dasar atau "rangka" yang membentuk sebuah bangun ruang tiga dimensi. Ini sering kali mencakup sisi-sisi, rusuk-rusuk, dan sudut-sudut yang membentuk kerangka dari suatu bangun ruang.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3628, 16, 1, '132080302017', 'Aritmatika Jam', 'Alat peraga aritmatika jam adalah alat yang biasanya digunakan dalam pengajaran atau pembelajaran untuk membantu siswa memahami konsep waktu, penjumlahan, pengurangan, dan konsep aritmatika dasar dengan menggunakan format jam analog atau digital.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3629, 16, 1, '132080302018', 'Garis dan Bangun Ruang', 'Garis dan bangun ruang adalah konsep dasar dalam matematika geometri yang membahas tentang objek dalam dimensi yang berbeda.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3630, 16, 1, '132080302019', 'Pengukur Panjang Kurva', 'Pengukur panjang kurva adalah alat atau metode yang digunakan untuk mengukur panjang dari suatu kurva atau garis yang tidak lurus, seperti lengkungan atau kurva matematis. Beberapa metode yang umum digunakan untuk mengukur panjang kurva melibatkan konsep integral dalam kalkulus', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3631, 16, 1, '132080302020', 'Simetri Cermin', 'Simetri cermin sering disebut juga dengan refleksi. Dikatakan simetri cermin karena kedua bangun tersebut dapat dilihat sebuah benda yang berhadapan dengan banyangannya di muka cermin.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3632, 16, 1, '132080302021', 'Blok Untuk Bilangan Berbaris', 'Media Block Dienes adalah salah satu media pembelajaran yang dapat digunakan untuk menanamkan konsep dasar bilangan,nilai tempat, selain itu juga dapat digunakan untuk operasi penjumlahan, pengurangan, perkalian dan pembagian kepada siswa sekolah dasar.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3633, 16, 1, '132080302022', 'Blok Simetri Putar', 'Simetri putar adalah tipe simetri dalam matematika yang terjadi ketika suatu objek atau bangun geometri terlihat sama setelah diputar sejumlah tertentu derajat terhadap sebuah pusat rotasi atau titik putar tertentu.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3634, 16, 1, '132080302024', 'Blok Untuk Bilangan Berbaris Lima', 'Nama barang yang ditemukan Block Dienes adalah salah satu media pembelajaran yang dapat digunakan untuk menanamkan konsep dasar bilangan,nilai tempat, selain itu juga dapat digunakan untuk operasi penjumlahan, pengurangan, perkalian dan pembagian kepada siswa sekolah dasar.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3635, 6, 1, '132070123001', 'Amputating Knife', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3636, 16, 1, '132080302025', 'Bangunan dan Daerah Bangun Datar', 'Bangunan dan daerah bangun datar adalah dua konsep yang saling berkaitan dalam geometri. Bangunan datar adalah suatu bentuk dua dimensi yang dibatasi oleh garis-garis. Daerah bangun datar adalah luas permukaan yang dibatasi oleh garis-garis tersebut.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3637, 16, 1, '132080302026', 'Kubus Satuan', 'Kubus satuan adalah kubus yang memiliki semua sisi dengan panjang sisi yang sama atau setara dengan 1 satuan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3638, 16, 1, '132080302027', 'Miter Ceser B', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3639, 16, 1, '132080302028', 'Blok Pytheagroras', 'Blok Pythagoras mengacu pada prinsip dan teorema Pythagoras, yang merupakan dasar dari geometri dalam matematika. Teorema Pythagoras menyatakan hubungan antara panjang sisi-sisi dalam segitiga siku-siku', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3640, 6, 1, '132070123005', 'Chisel And Tounges Obteotomi', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3641, 16, 1, '132080302029', 'Blok Logica', 'Blok logika adalah alat peraga yang digunakan untuk mengajarkan konsep-konsep logika, terutama untuk anak usia dini dan sekolah dasar.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3642, 6, 1, '132070123006', 'Dispector', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3643, 16, 1, '132080302030', 'Blok Segitiga ABC', 'Blok segitiga ABC mengacu pada bentuk tiga dimensi yang dibentuk oleh tiga segitiga yang berdampingan, biasanya dengan segitiga ABC sebagai sisi-sisinya', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3644, 16, 1, '132080302031', 'Pengukur Sudut Elevansi', 'Clinometer atau yang umum disebut Klinometer ialah alat sederhana di mana dipakai dalam mengukur sudut elevasi. Yakni sudut elevasi dari garis datar dan sebuah garis yang menghubungkan sebuah titik di garis datar tersebut dengan titik puncak suatu objek.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3645, 16, 1, '132080302032', 'Model Kubus', 'Model kubus adalah alat peraga geometri yang digunakan untuk memvisualisasikan dan mempelajari berbagai konsep yang terkait dengan bentuk kubus, seperti sisi, ruang diagonal, volume, dan area permukaan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3646, 16, 1, '132080302033', 'Model Balok', 'Model balok adalah alat peraga geometri yang memvisualisasikan konsep dan sifat-sifat yang terkait dengan bentuk balok.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3647, 6, 1, '132070123010', 'Osteotomi Knife', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3648, 16, 1, '132080302034', 'Model Prisma Segitiga Siku-siku', 'Prisma segitiga siku-siku adalah prisma yang memiliki alas berbentuk segitiga siku-siku, yang berarti salah satu sudut alasnya adalah sudut siku-siku. Alat peraga prisma ini adalah representasi visual dari bentuk prisma tersebut dan sering digunakan dalam pembelajaran matematika atau geometri.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3649, 6, 1, '132070123011', 'Pemotong Tulang', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3650, 16, 1, '132080302035', 'Model Prima Tegak Segi Tiga', 'Model prisma tegak segitiga adalah representasi tiga dimensi dari sebuah prisma yang memiliki alas berbentuk segitiga siku-siku. Prisma tegak segitiga memiliki dua segitiga yang identik sebagai alas dan atasnya, dengan kedua segitiga tersebut saling berhubungan oleh bidang sisi-sisi yang berbentuk persegi atau persegi panjang.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3651, 16, 1, '132080302036', 'Bidang Delapan Beraturan', 'Merupakan alat peraga bidang studi matematika yang memiliki sisi (segi) sebanyak delapan buah. Bangun ruang yang umum digunakan bernama octahedron', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3652, 6, 1, '132070123013', 'Respatories', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3653, 16, 1, '132080302037', 'Model Bidang Dua Belas Beraturan', 'Merupakan alat peraga bidang studi matematika yang memiliki sisi (segi) sebanyak dua belas buah. Bangun ruang yang umum digunakan bernama dodecahedron tidak dapat didefinisikan dengan sempurna jika merujuk ke dalam sub rincian objek, kemungkinan benda ini merupakan bangun ruang yang memiliki sisi 12 bidang, \n\ndan gambar yang disajikan umum nya digunakan di dalam bidang matematika', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3654, 16, 1, '132080302038', 'Model Tabung Jaring-jaring', 'Model tabung jaring-jaring adalah representasi visual dari sebuah tabung yang memiliki permukaan berbentuk jaring-jaring. Biasanya, ini merujuk pada model matematika atau geometri yang menggambarkan sisi-sisi, rusuk-rusuk, dan sudut-sudut tabung dengan detail jaring-jaring pada permukaannya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3655, 6, 1, '132070123015', 'Set Countering Bonef', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3656, 16, 1, '132080302039', 'Model Bola dan Setengah Bola', 'Model bola dan setengah bola adalah representasi tiga dimensi dari objek matematika yang disebut bola dan setengah bola.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3657, 6, 1, '132070123016', 'Set Stepper', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3658, 16, 1, '132080302040', 'Papan Paku Kecil', 'Papan paku kecil merupakan alat peraga yang digunakan untuk pengenalan macam-macam bangun datar seperti persegi panjang, persegi, segitiga, jajargenjang, trapesium, layang-layang maupun belah ketupat.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3659, 6, 1, '132070123017', 'Srwo Driver', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3660, 16, 1, '132080302041', 'Gawang Penghitung', 'Gawang penghitung, atau sering disebut papan skor, adalah sebuah alat yang digunakan untuk mencatat dan menampilkan skor atau jumlah pada sebuah permainan atau kegiatan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3661, 16, 1, '132080302042', 'Gawang Angka', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3662, 16, 1, '132080302043', 'Model Jam Bentuk Dasar', 'Model jam sebagai alat peraga umumnya dibuat untuk memvisualisasikan bagian-bagian dari jam dan cara kerjanya. Ini bisa berupa model yang dibuat secara lebih sederhana, dengan tangan jam yang bisa digerakkan, hingga model yang lebih kompleks yang menunjukkan mekanisme dalam jam yang sebenarnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3663, 16, 1, '132080302044', 'Bola Gelinding', 'Boling atau bola gelinding adalah jenis permainan dan olahraga yang kegiatannya hanya menggelindingkan bola boling dengan menggunakan satu tangan hingga mengenai pin segitiga yang berjumlah sepuluh buah.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3664, 16, 1, '132080302045', 'Lempar Galang', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3665, 16, 1, '132080302046', 'Detak-detak Tiang', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3666, 16, 1, '132080302047', 'Papan Tulis Berkotak', 'Papan tulis adalah papan dari kayu dengan motif kotak-kotak dengan permukaan yang bisa ditulis ulang dengan menggunakan kapur tulis.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3667, 16, 1, '132080302048', 'Model Bangun Ruang', 'Model bangun ruang adalah representasi visual dari objek tiga dimensi di ruang. Ini adalah alat pembelajaran yang berguna untuk memahami bentuk, ukuran, dan sifat geometris objek tiga dimensi seperti kubus, balok, prisma, kerucut, silinder, dan bentuk-bentuk lainnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3668, 16, 1, '132080302049', 'Alat Peraga Matematika', 'Alat peraga matematika adalah alat atau bahan yang digunakan dalam pembelajaran matematika untuk membantu siswa memahami konsep, prinsip, dan operasi matematika dengan cara yang lebih visual, konkret, dan praktis.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3669, 16, 1, '132080303001', 'Kotak Peti Lengkap', 'Alat yang digunakan untuk menyimpan alat praktek', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3670, 16, 1, '132080303002', 'Pembakar Spirtus', 'Pembakar spirtus termasuk alat pemanas dalam kegiatan praktikum kimia. Pembakar spirtus berbentuk labu kaca berisi alkohol, spirtus, atau sejenisnya', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3671, 16, 1, '132080303003', 'Gelas Kimia', 'Gelas kimia adalah sebagai tempat untuk melarutkan zat yang tidak butuh ketelitian tinggi, misalnya pereaksi/reagen untuk analisis kimia kualitatif atau untuk pembuatan larutan standar sekunder pada analisis titrimetri/volumetri.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3672, 16, 1, '132080303004', 'Pemegang', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3673, 16, 1, '132080303005', 'Kaca/Skala', 'Gelas ukur adalah peralatan laboratorium umum yang digunakan untuk mengukur volume cairan. Alat ini memiliki bentuk silinder dan setiap garis penanda yang ada pada gelas ukur mewakili jumlah cairan yang telah terukur.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3674, 6, 1, '132070126002', 'Diathermy Valley Lab', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3675, 16, 1, '132080303006', 'Batang Muai', 'Alat muai panjang digunakan untuk menentukan nilai koefisien muai panjang suatu bahan. Koefisien muai panjang diperoleh dari perubahan panjang batang dengan bahan tertentu yang dialiri uap panas', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3676, 6, 1, '132070126003', 'Gergaji Sternum', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3677, 16, 1, '132080303007', 'Langan Neraca', 'alat ukur berat seperti neraca, lengan neraca adalah salah satu bagian dari struktur alat itu sendiri. Neraca adalah alat yang digunakan untuk mengukur massa atau berat benda dengan membandingkannya dengan berat benda lain yang diketahui', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3678, 16, 1, '132080303008', 'Poros Neraca', 'poros neraca merupakan alat yang berada di antara dua berat yang akan di uji', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3679, 16, 1, '132080303009', 'Mangkok Neraca', 'Mangkok neraca adalah bagian penting dari neraca atau alat pengukur berat yang digunakan di laboratorium atau dalam pengukuran presisi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3680, 16, 1, '132080303010', 'Kubus Plastik', 'Kubus plastik adalah objek tiga dimensi dengan bentuk kubus yang terbuat dari plastik. Sebagai bentuk geometri tiga dimensi yang memiliki enam sisi persegi yang sama panjang dan 12 rusuk yang sama panjang juga, kubus plastik ini sering digunakan dalam berbagai aplikasi dan pembelajaran.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3681, 16, 1, '132080303011', 'Kubus Kayu', 'Kubus kayu sebagai alat peraga digunakan dalam konteks pembelajaran untuk memvisualisasikan dan mendemonstrasikan konsep-konsep geometri tiga dimensi kepada siswa.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3682, 16, 1, '132080303012', 'Bola Baja', 'Bola baja adalah bola yang terbuat dari baja atau logam lainnya. Bola baja sering digunakan dalam berbagai konteks, terutama dalam industri dan olahraga.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3683, 16, 1, '132080303013', 'Pipa Intai Bias', 'Pipa praktikum adalah pipa yang digunakan dalam percobaan atau eksperimen di laboratorium. Pipa ini biasanya terbuat dari kaca borosilikat atau bahan lain yang tahan terhadap perubahan suhu dan bahan kimia tertentu.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3684, 6, 1, '132070126010', 'Video Asisted Throcoscope Surgery', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3685, 16, 1, '132080303014', 'Kontrol Tunggal', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3686, 16, 1, '132080303015', 'Kontrol Ganda', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3687, 6, 1, '132070127002', 'Eav Dermatron With Variopit', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3688, 16, 1, '132080303016', 'Pegas', 'Pegas adalah perangkat mekanis yang digunakan untuk menyimpan energi dalam bentuk mekanis. Mereka memiliki kemampuan untuk meregang dan kembali ke bentuk semula saat beban yang diterapkan pada pegas dihilangkan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3689, 6, 1, '132070127003', 'Model W 10 A Multiple Electrik Akupuntur', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3690, 16, 1, '132080303017', 'Volume Konstan', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3691, 16, 1, '132080303018', 'Turbin Air', 'Turbin air adalah alat yang mengubah energi kinetik air menjadi energi mekanik. Generator turbin air adalah alat yang mengubah energi kinetik dari aliran air menjadi energi listrik', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3692, 16, 1, '132080303019', 'Tabung Reaksi', 'Tabung reaksi, adalah peralatan gelas yang umum ada di laboratorium berbentuk tabung sebesar kira-kira jari tangan manusia dewasa, terbuat dari kaca atau plastik, terbuka di bagian atasnya, biasanya alasnya berbentuk huruf-U', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3693, 7, 1, '132070201001', 'Alat-Alat Mikroklimat', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3694, 16, 1, '132080303020', 'Magnet', 'Magnet atau semberani adalah benda yang memiliki kemampuan menarik benda-benda lain yang ada di sekitarnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3695, 7, 1, '132070201002', 'Audimeter Computerized', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3696, 16, 1, '132080303021', 'Sistem Optik', 'Sistem optik adalah kajian fenomena cahaya berdasarkan instrumen yang digunakan seperti optik geomterik, fisis dan kuantum.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
