	(3706, 16, 1, '132080303029', 'Tutup Penyimpanan 21415', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3707, 16, 1, '132080303030', 'Kelompok Penyimpanan/Laci 8', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
