	(3709, 7, 1, '132070201013', 'Monoplane Chamber', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3710, 16, 1, '132080303032', 'Tutup Penyimpanan 7', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3711, 16, 1, '132080304001', 'Kerangka Karet', 'Peralatan peraga pendididkan berbentuk tengkorak manusia berbahan karet', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3712, 16, 1, '132080304002', 'Model Tengkarong', 'Model tengkorak sering digunakan sebagai alat peraga dalam berbagai bidang, termasuk ilmu biologi, kedokteran, kedokteran gigi, antropologi, dan pendidikan. Model-model ini dirancang untuk merepresentasikan struktur tengkorak manusia atau hewan dengan detail yang akurat.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3713, 16, 1, '132080304003', 'Model Lidah', 'Model lidah sering dibuat untuk menjelaskan struktur dan fungsi lidah dalam tubuh manusia. Biasanya, model-model ini menunjukkan bagian-bagian utama lidah seperti papila, ujung, sisi, dan pangkal, serta bagaimana lidah terhubung dengan bagian lain di dalam rongga mulut.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3714, 16, 1, '132080304004', 'Model Tarso Wanita', 'Model torso wanita adalah representasi tiga dimensi dari bagian tubuh atas wanita, biasanya dari bagian atas dada hingga panggul atau pinggang.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3715, 16, 1, '132080304005', 'Model Jantung', 'Model jantung adalah representasi tiga dimensi dari organ jantung manusia yang digunakan untuk tujuan pendidikan, demonstrasi, dan pemahaman lebih lanjut tentang anatomi serta fungsi jantung.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3716, 16, 1, '132080304006', 'Model Rahang Gigi', 'Model rahang merupakan benda tiruan yang dibuat untuk tujuan tertentu, biasanya model ini dipakai untuk menjelaskan cara menyikat gigi yang baik dan benar', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3717, 7, 1, '132070201020', 'Spirometer Bmr', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3718, 16, 1, '132080304007', 'Model Pencernaan Makanan', 'Model pencernaan makanan adalah representasi visual atau fisik dari sistem pencernaan manusia. Ini digunakan untuk mendemonstrasikan bagaimana makanan dipecah dan dicerna oleh tubuh kita, serta peran setiap bagian dari sistem pencernaan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3719, 7, 1, '132070201021', 'Spirometer VO Max', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3720, 16, 1, '132080304008', 'Model mata', 'Model mata adalah representasi tiga dimensi atau visual dari struktur anatomi mata manusia. Model-model ini digunakan untuk tujuan pendidikan, demonstrasi, dan pemahaman lebih lanjut tentang bagian-bagian, fungsi, dan kerja mata.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3721, 7, 1, '132070201022', 'Superlife 17B', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3722, 16, 1, '132080304009', 'Model Kuda', 'Model kuda sering digunakan sebagai alat peraga dalam berbagai konteks, mulai dari pendidikan hingga demonstrasi dan penelitian ilmiah. Model-model ini biasanya dirancang untuk merepresentasikan anatomi dan struktur tubuh kuda dengan tingkat detail yang relevan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3723, 7, 1, '132070201023', 'Telemeter', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3724, 16, 1, '132080304010', 'Model Lembu', 'Model sapi sering digunakan sebagai alat peraga di berbagai konteks, termasuk dalam pendidikan, pertanian, dan ilmu biologi. Model-model ini umumnya dirancang untuk merepresentasikan anatomi dan struktur tubuh sapi dengan detail yang relevan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3725, 7, 1, '132070201024', 'Vestibulator Test Equip', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3726, 16, 1, '132080304011', 'Model Torso Mini', 'Model torso mini adalah versi kecil dari model anatomi manusia yang mencakup bagian-bagian utama dari tubuh manusia, biasanya mulai dari leher hingga panggul.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3727, 16, 1, '132080304012', 'Gelas Ukur', 'Gelas ukur adalah peralatan laboratorium umum yang digunakan untuk mengukur volume cairan. Alat ini memiliki bentuk silinder dan setiap garis penanda yang ada pada gelas ukur mewakili jumlah cairan yang telah terukur.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3728, 7, 1, '132070201026', 'Walk In', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3729, 16, 1, '132080304013', 'Pipet Tetes', 'Pipet Pasteur atau pipet tetes merupakan jenis pipet yang digunakan untuk memindahkan larutan dari suatu wadah ke wadah lain dengan jumlah yang sangat sedikit dan dengan tingkat ketelitian pengukuran volume yang sangat rendah.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3730, 7, 1, '132070201027', 'Walk In Chamb Monocomp', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3731, 16, 1, '132080304014', 'Batu Timbangan', 'Anak timbangan atau sering disebut batu timbangan adalah alat uji / ukur yang digunakan sebagai standar acuan untuk penyetelan / kalibrasi timbangan baik itu pada timbangan mekanik maupun timbangan digital.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3732, 16, 1, '132080304015', 'Labu Erlen Mayer', 'Labu Erlenmeyer atau labu kerucut adalah jenis labu laboratorium yang terbuat dari kaca borosilikat yang banyak digunakan. Memiliki tubuh berbentuk kerucut, leher silinder dan dilengkapi dengan dasar yang datar.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3733, 16, 1, '132080304016', 'Corong', 'Corong adalah sebuah benda berbentuk kerucut dengan bentuk lubang di ujung benda yang lebar dan lubang sempit dan panjang di ujung lainnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3734, 16, 1, '132080304017', 'Pipa Plastik', 'Pipa PVC adalah pipa yang terbuat dari bahan polyvinyl chloride (PVC). PVC adalah bahan plastik yang kuat, tahan lama, dan tidak mudah terbakar', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3735, 16, 1, '132080304018', 'Bak Air', 'Bak air adalah wadah atau tempat yang dirancang khusus untuk menampung air. Bak air dapat memiliki berbagai bentuk, ukuran, dan bahan tergantung pada fungsinya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3736, 16, 1, '132080304019', 'Sumbat Erlemenyer', 'Sumbat Erlenmeyer adalah sebuah penutup yang terbuat dari karet atau bahan sintetis lainnya yang digunakan untuk menutup labu Erlenmeyer. Sumbat ini berfungsi untuk mencegah keluarnya cairan atau gas dari dalam labu, serta untuk menjaga agar larutan tetap steril.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3737, 16, 1, '132080304020', 'Bendera dan Gabus', 'Gabus merupakan suatu bahan apung yang mempunyai banyak kegunaan. Gabus digunakan sebagai penutup botol terutama minuman beralkohol seperti anggur.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3738, 16, 1, '132080304021', 'Cawan Alumunium', 'Cawan alumunium adalah wadah berbentuk cawan atau mangkuk yang terbuat dari aluminium', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3739, 16, 1, '132080304022', 'Thermometer Kamar', 'Thermometer kamar adalah alat pengukur suhu yang dirancang khusus untuk mengukur suhu di dalam ruangan atau lingkungan tertutup', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3740, 16, 1, '132080304023', 'Thermometer 0.0 - 100.0 C', 'Thermometer adalah alat yang digunakan untuk mengukur suhu. Thermometer Raksa (Mercury) yang terdiri dari tabung kaca yang diisi dengan raksa. Ketika suhu naik, raksa dalam tabung kaca melebar naik, menunjukkan nilai suhu pada skala yang tertera di tabung.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3741, 16, 1, '132080304024', 'Pengaduk', 'Batang pengaduk merupakan sebuah peralatan laboratorium yang digunakan untuk mencampur bahan kimia dan cairan untuk keperluan laboratorium', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3742, 16, 1, '132080304025', 'Thermometer Badan', 'Dalam bidang kedokteran, termometer berfungsi mengukur suhu tubuh manusia untuk mengetahui seseorang dalam kondisi demam atau tidak.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3743, 16, 1, '132080304026', 'Balok Berkait', 'Balok berkait adalah komponen struktural yang digunakan dalam konstruksi bangunan atau dalam struktur lainnya. Ini adalah jenis balok yang memiliki kait atau pelat pengait pada salah satu atau kedua ujungnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3744, 7, 1, '132070203008', 'Forensic Odontology Set', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3745, 16, 1, '132080304027', 'Silinder Berkait', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3746, 16, 1, '132080304028', 'Sumbat Pipa Runcing', 'Sumbat pipa runcing adalah perangkat yang digunakan untuk menutup atau menyumbat ujung pipa atau saluran dengan cara yang memungkinkan penyekatan yang aman dan erat', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3747, 16, 1, '132080304029', 'Pipet Isap', 'Pipet hisap adalah alat laboratorium yang digunakan untuk mengambil atau mentransfer volume cairan tertentu secara tepat. Pipet hisap ini biasanya terbuat dari kaca dan memiliki ukuran yang bervariasi sesuai dengan kebutuhan spesifik di laboratorium.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3748, 16, 1, '132080304030', 'Kaki Tiga', 'Alat Peraga Kaki tiga atau tripod adalah sebuah perlengkapan laboratorium berupa besi dengan tiga kaki. Kaki tiga berfungsi untuk menyangga ring dan digunakan untuk menahan kawat kasa dalam pemanasan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3749, 16, 1, '132080304032', 'Penjepit Tabung Reaksi Jembatan', 'Penjepit tabung reaksi jembatan adalah peralatan laboratorium yang digunakan untuk menjepit tabung reaksi pada jembatan atau rak penjepit yang biasa digunakan dalam pengaturan laboratorium kimia', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3750, 7, 1, '132070205001', 'Alat Vacasional Asessment IGVAT)', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3751, 16, 1, '132080304033', 'Jembatan', 'Jembatan merupakan alat peraga yang terbuat dari kayu', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3752, 16, 1, '132080304034', 'Batang Bambu/Besi', 'Batang bambu atau besi sering digunakan dalam berbagai konteks konstruksi dan pembuatan. Mereka digunakan sebagai material struktural untuk berbagai tujuan, tergantung pada kekuatan, ketahanan, dan kebutuhan penyangga atau struktur tertentu.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3753, 7, 1, '132070205003', 'Coordination Tester', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3754, 16, 1, '132080304035', 'Lampu Spirtus', 'Lampu spiritus merupakan salah satu alat yang diperlukan pada setiap percobaan kimia atau praktikum lainnya. Alat ini digunakan untuk membakar zat atau memanasi larutan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3755, 7, 1, '132070205004', 'Ring Inserting Tester', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3756, 16, 1, '132080304036', 'Batang Logam', 'Batang logam adalah logam dan paduan yang dirancang dengan pola batangan atau batang bulat, batangan persegi panjang atau datar, batangan persegi, segi enam, dan pola batangan lainnya', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3757, 16, 1, '132080304037', 'Batang Kuningan', 'Batang kuningan adalah benda seperti batang yang terbuat dari paduan tembaga dan seng', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3758, 7, 1, '132070205006', 'Form Board Tester', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3759, 16, 1, '132080304038', 'Batang Gelas', 'Batang Pengaduk Kaca/Gelas (Glass Stirring Rod) adalah salah satu jenis alat glassware untuk keperluan praktik di laboratorium dan lapangan guna membantu proses pencampuran larutan zat kimia dan cairan lain dengan cara diaduk.\n\nBatang pengaduk ini terbuat dari kaca borosilikat, sedikit lebih panjang dari sedotan namun padat (tidak berlubang). Ujung-ujungnya umumnya dibulatkan (dengan polesan api) untuk mencegah goresan dan retakan pada permukaan wadah yang digunakan', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3760, 7, 1, '132070205007', 'Mental Reaction Tester', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3761, 16, 1, '132080304039', 'Landasan Segi Tiga', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3762, 7, 1, '132070205008', 'Verbal Discrimination Tester', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3763, 16, 1, '132080304040', 'Pemberat', 'Pemberat alat peraga adalah sejenis beban atau massa yang digunakan dalam alat peraga untuk memperjelas atau menunjukkan prinsip-prinsip fisika tertentu.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3764, 7, 1, '132070205009', 'Vacational Aptitude Examination Tester', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3765, 16, 1, '132080304042', 'Gelas Horizontal', 'Gelas horizontal dapat merujuk pada beberapa hal tergantung pada konteks penggunaannya. Dalam beberapa kasus, istilah "gelas horizontal" dapat merujuk pada wadah atau bejana yang didesain dengan bentuk horizontal atau datar di bagian bawahnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3766, 7, 1, '132070205010', 'Coin Sorting Sortir', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3767, 16, 1, '132080304043', 'Layar', 'Layar alat peraga bisa merujuk pada berbagai jenis layar yang digunakan sebagai bagian dari alat peraga atau demonstrasi di berbagai konteks, seperti dalam pendidikan, presentasi, atau demonstrasi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3768, 7, 1, '132070205011', 'Digital Bach Muscle Dynamometer', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3769, 16, 1, '132080304044', 'Lensa', 'Lensa atau kanta adalah alat untuk mengumpulkan atau menyebarkan cahaya, biasanya dibentuk dari sepotong gelas yang dibentuk.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3770, 16, 1, '132080304046', 'Tabung Reaksi', 'Tabung reaksi, adalah peralatan gelas yang umum ada di laboratorium berbentuk tabung sebesar kira-kira jari tangan manusia dewasa, terbuat dari kaca atau plastik, terbuka di bagian atasnya, biasanya alasnya berbentuk huruf-U', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3771, 7, 1, '132070205013', 'Reaction Time Tester', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3772, 16, 1, '132080304047', 'Kompas', 'Kompas adalah alat navigasi yang digunakan untuk menentukan arah. Biasanya, kompas terdiri dari jarum magnet yang mengarah ke arah utara magnetik bumi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3773, 7, 1, '132070205014', 'Block Chaos Tester', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3774, 16, 1, '132080304049', 'Bel Listrik', 'Bel listrik adalah suatu alat yang mampu menghasilkan suara dari adanya perubahan energi listrik menjadi magnet (yang nantinya menimbulkan energi gerak yang berfungsi sebagai sumber pelaku timbulnya suara).', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3775, 16, 1, '132080304050', 'Alas Dengan Lampu + Kontak', 'Alat peraga praktik dengan alas, lampu, dan kontak dapat digunakan untuk mengilustrasikan konsep dalam berbagai bidang studi, terutama dalam Ilmu Pengetahuan (IP).', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3776, 16, 1, '132080304051', 'Pasangan Batu Baterai Seri', 'Komponen sebuah rangkaian listrik atau rangkaian elektronik dapat dihubungkan dengan berbagai cara atau disusun secara berderet dan berurutan', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3777, 7, 1, '132070205017', 'Wais', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3778, 16, 1, '132080304052', 'Pasangan Batu Baterai Paralel', 'Komponen sebuah rangkaian listrik atau rangkaian elektronik dapat dihubungkan dengan berbagai cara atau disusun secara sejajar', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3779, 16, 1, '132080304053', 'Cawan Patri', 'Cawan petri atau telepa petri adalah sebuah wadah yang bentuknya bundar dan terbuat dari plastik atau kaca yang digunakan untuk membiakkan sel.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3780, 16, 1, '132080304054', 'Pensil Kaca', 'Pensil kaca biasanya merujuk pada alat tulis yang terbuat dari kaca atau bahan transparan lainnya yang dapat digunakan untuk menulis atau menggambar pada permukaan non-papier, seperti papan tulis kaca atau lembaran plastik transparan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3781, 16, 1, '132080304055', 'Pot Plastik', 'Pot adalah sebuah wadah di mana bunga atau tanaman lain ditanam dan dibesarkan yang biasanya dibuat dari plastik atau tanah liat yang dikeraskan', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3782, 7, 1, '132070205021', 'Ketajaman Mata', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3783, 16, 1, '132080304056', 'Pipa Karet', 'Pipa karet adalah pipa yang terbuat dari bahan karet atau material karet yang fleksibel. Pipa ini biasanya digunakan dalam berbagai aplikasi di mana fleksibilitas dan tahan terhadap bahan kimia tertentu diperlukan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3784, 16, 1, '132080304057', 'Pipa Kaca Lurus', 'Pipa kaca lurus dapat digunakan sebagai alat peraga sekolah untuk mengilustrasikan konsep optika, khususnya perambatan cahaya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3785, 7, 1, '132070205023', 'Vital Lapacity', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3786, 16, 1, '132080304058', 'Statip Tabung Reaksi', 'Statif adalah struktur penopang yang digunakan di laboratorium untuk menahan alat gelas (biasanya berupa labu alas bulat atau Tabung reaksi pada posisi tertentu).', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3787, 16, 1, '132080304059', 'Gelas Piala', 'Gelas Piala adalah sebuah wadah penampung yang digunakan untuk mengaduk, mencampur, dan memanaskan cairan yang biasanya digunakan dalam laboratorium.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3788, 16, 1, '132080304060', 'Botol Spesiman', 'Botol spesimen adalah wadah yang digunakan untuk mengoleksi, menyimpan, dan mengangkut sampel biologis atau bahan kimia dalam konteks laboratorium, penelitian, atau pengujian medis.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3789, 16, 1, '132080304061', 'Sumbat Karet', 'Sumbat karet adalah alat peraga yang umumnya digunakan dalam berbagai konteks laboratorium dan industri. Mereka adalah perangkat karet yang digunakan untuk menutupi atau menutup bagian ujung dari alat laboratorium atau perangkat industri untuk mencegah kebocoran atau mengisolasi bahan yang disimpan di dalamnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3790, 16, 1, '132080304062', 'Sumbat Berlubang 2 (dua)', 'Sumbat karet adalah alat peraga yang umumnya digunakan dalam berbagai konteks laboratorium dan industri. Mereka adalah perangkat karet yang digunakan untuk menutupi atau menutup bagian ujung dari alat laboratorium atau perangkat industri untuk mencegah kebocoran atau mengisolasi bahan yang disimpan di dalamnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3791, 16, 1, '132080304063', 'Pinset Bengkok', 'Pinset bengkok adalah peralatan yang sering digunakan dalam berbagai konteks, seperti laboratorium, perawatan medis, atau kegiatan presisi seperti perhiasan', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3792, 16, 1, '132080304064', 'Alat Demonstrasi Pernapasan', 'Alat demonstrasi pernapasan adalah peralatan yang digunakan dalam pembelajaran atau demonstrasi untuk memvisualisasikan atau mengilustrasikan proses pernapasan manusia atau hewan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3793, 16, 1, '132080304065', 'Pipa Bentuk Y', 'Pipa dengan bentuk Y adalah komponen pipa yang terdiri dari dua saluran yang bergabung menjadi satu, membentuk sudut atau bifurkasi seperti huruf Y.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3794, 8, 1, '132080101006', 'Roffluk Bottle & Standar', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3795, 16, 1, '132080305001', 'Bejana Berhubungan', 'Alat peraga bejana berhubungan adalah model atau demonstrasi yang menggambarkan prinsip bekerja dari serangkaian bejana atau wadah yang terhubung satu sama lain melalui saluran atau pipa untuk mengalirkan cairan atau bahan dari satu wadah ke wadah lainnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3796, 16, 1, '132080305002', 'Pipa Kapiter', 'Alat peraga pipa kapiler adalah alat yang digunakan untuk memperlihatkan atau menjelaskan konsep pipa kapiler dalam konteks fisika atau ilmu kimia.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3797, 8, 1, '132080101008', 'Yart Test', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3798, 16, 1, '132080305004', 'Galangan Kapal', 'Galangan Kapal atau shipyard adalah sebuah tempat diperairan yang fungsinya untuk melakukan proses pembangunan kapal (New Building) dan perbaikan kapal (ship repair) dan juga melakukan pemeliharaan (maintainance).', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3799, 16, 1, '132080305005', 'Manometer Terbuka', 'Manometer terbuka adalah alat yang digunakan untuk mengukur tekanan fluida, seperti gas atau cairan. Alat ini memiliki satu ujung terbuka yang terbuka ke atmosfer dan ujung lainnya terhubung ke dalam sistem atau ruang yang tekanannya ingin diukur.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3800, 16, 1, '132080305006', 'Manometer Tertutup', 'Manometer merupakan alat yang digunakan untuk mengukur tekanan udara pada ruang tertutup (Manometer Tertutup)', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3801, 16, 1, '132080305007', 'Pompa Karet', 'Pompa karet adalah jenis pompa yang menggunakan karet atau bahan elastis serupa untuk menghasilkan aliran atau tekanan dalam mengalirkan cairan atau udara. Pompa ini umumnya memiliki bagian yang dapat ditekan atau diperlebar, yang ketika ditekan atau diperlebar secara manual, menghasilkan perubahan volume dalam ruang di dalamnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3802, 16, 1, '132080305009', 'Pipa Bengkok + Sumbat', 'Pipa bengkok + sumbat adalah kombinasi dari dua alat laboratorium yang digunakan untuk berbagai macam keperluan. Pipa bengkok biasanya terbuat dari kaca atau plastik, dan digunakan untuk mengalirkan cairan atau gas. Sumbat biasanya terbuat dari karet atau bahan sintetis lainnya, dan digunakan untuk menutup pipa.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3803, 16, 1, '132080305010', 'Batu Timbangan Berkait', 'Batu timbangan berkait adalah batu yang digunakan sebagai counterweight atau pelengkap dalam sistem timbangan atau neraca. Batu timbangan ini memiliki massa yang diketahui dan sering kali digunakan dalam pengaturan keseimbangan neraca.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3804, 16, 1, '132080305011', 'Alas Jungkitan', 'suatu bangunan yang dirancang untuk menahan beban jungkat jungkit dan juga membuat jungkat jungkit dapat berfungsi', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3805, 8, 1, '132080101015', 'Kjedhli Digestion APP', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3806, 16, 1, '132080305012', 'Katrol', 'Katrol atau kapi adalah sebuah roda di atas sebuah as roda atau penggerak roda yang dirancang untuk mendukung pergerakan dan mengubah arah dari kabel atau sabuk yang dipasang, atau mentransfer kekuatan antara penggerak roda dan kabel atau sabuk.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3807, 16, 1, '132080305014', 'Desimeter', 'Desimeter adalah unit SI untuk panjang kemudian alat peraga satuan panjang adalah alat yang digunakan dalam pembelajaran untuk mengajarkan dan memvisualisasikan konsep panjang atau jarak dalam satuan tertentu.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3808, 8, 1, '132080101017', 'Kjedhli Digestion APP', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3809, 16, 1, '132080305015', 'Alat Untuk Menunjukan Tekanan Dalam Kelema', 'Pressure Gauge adalah alat ukur yang digunakan untuk mengukur tingkat tekanan dalam suatu cairan atau gas, lintas industri.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3810, 16, 1, '132080305016', 'Tabung Resonansi', 'Tabung resonansi adalah tabung tertutup yang digunakan dalam eksperimen fisika untuk mengilustrasikan konsep gelombang suara dan resonansi. Mereka biasanya terbuat dari bahan yang keras dan berbentuk silinder atau tabung yang panjangnya dapat disesuaikan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3811, 16, 1, '132080305018', 'Lempeng Gelas', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3812, 16, 1, '132080305019', 'Galang Sandaran/Ring', 'Galang sandaran atau biasa disebut ring adalah suatu struktur lingkaran atau cincin yang digunakan sebagai penyangga atau pendukung dalam berbagai konteks teknis atau konstruksi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3813, 16, 1, '132080305020', 'Alat Menunjukan Aliran Zat Cair', 'Aerometer adalah sebuah alat yang digunakan untuk mengukur massa jenis suatu zat cair. Nilai massa jenis suatu zat cai dapat diketahui dengan membaca skala pada aerometer yang ditempatkan mengapung pada zat cair', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3814, 16, 1, '132080305021', 'Pipa Pendingin/Penyuling', 'Pipa pendingin atau pipa penyuling adalah bagian dari sistem penyulingan yang digunakan untuk mendinginkan uap atau gas panas menjadi cairan kembali.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3815, 8, 1, '132080102005', 'Sistem Quinching', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3816, 16, 1, '132080305023', 'Sumber Cahaya', 'Alat optik adalah alat yang memanfaatkan sifat cahaya, hukum pemantulan, dan hukum pembiasan sifat cahaya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3817, 8, 1, '132080102006', 'Alat Pelarut Pengendapan', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3818, 16, 1, '132080305024', 'Rangka Penjepit', 'Rangka penjepit adalah struktur atau kerangka yang biasanya terdiri dari logam atau bahan lain yang kuat dan digunakan untuk menopang atau menjepit benda dalam suatu posisi tertentu.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3819, 8, 1, '132080102007', 'Alat Dekantasi', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3820, 16, 1, '132080305025', 'Celah Satu Horisontal', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3821, 8, 1, '132080102008', 'Sistem Quinching', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3822, 16, 1, '132080305026', 'Layar', 'Layar alat peraga biasanya merujuk pada layar proyeksi atau layar yang digunakan untuk menampilkan gambar, teks, atau informasi kepada audiens dalam konteks presentasi, pelatihan, atau pembelajaran', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3823, 8, 1, '132080102009', 'Alat Pelarut Pengendapan', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3824, 16, 1, '132080305027', 'Cermin Datar Dan Skala', 'Cermin datar adalah cermin yang memiliki bagian pemantul berbentuk datar. Sifat bayangan yang dihasilkan adalah maya, tegak, dan sama besar.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3825, 16, 1, '132080305028', 'Klem Pegas', 'Klem pegas adalah alat yang umumnya terdiri dari dua bagian logam atau plastik yang dapat membuka dan menutup dengan gaya pegas', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3826, 16, 1, '132080305029', 'Lempeng Perpeks 1/2 Lingkaran', 'Perpeks 1/2 lingkaran mungkin merujuk pada bahan atau objek tertentu yang tidak umum atau istilah khusus dalam suatu konteks yang spesifik. Dalam matematika, "1/2 lingkaran" merujuk pada separuh dari lingkaran atau bentuk setengah bulat.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3827, 16, 1, '132080305030', 'Prisma (Lempeng)', 'Prisma lempeng atau prisma tegak adalah prisma yang memiliki salah satu dari dua alasnya berupa poligon yang sejajar dengan sisi atas dan bawah prisma.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3828, 16, 1, '132080305033', 'Lensa Pepeku Bikonfeks', 'Lensa merupakan sebuah benda bening yang dibatasi oleh dua bidang yang bias. Lensa cembung atau bikonveks merupakan jenis lensa yang pada bagian tengahnya lebih tebal dibandingkan pada bagian tepinya. Bisa dikatakan bahwa lensa cembung memiliki bagian tengah yang menggembung.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3829, 16, 1, '132080305034', 'Lensa Perpeku Konkaf', 'Lensa merupakan sebuah benda bening yang dibatasi oleh dua bidang yang \nbias. Lensa cekung atau konkaf merupakan jenis lensa yang pada \nbagian tengahnya lebih tipis dibandingkan pada bagian tepinya. Bisa \ndikatakan bahwa lensa cekung memiliki bagian tengah yang tipis.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3830, 16, 1, '132080305035', 'Lensa F+15', 'Lensa cembung memiliki bentuk menonjol ke luar dan mampu memusatkan sinar cahaya yang melewatinya untuk bertemu pada titik fokusnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3831, 16, 1, '132080305036', 'Lensa F+10', 'Lensa cembung berbentuk lingkaran dengan diameter 5 cm dan jarak fokus 10 cm. Dapat digunakan dalam percobaan optik', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3832, 8, 1, '132080103008', 'Rin Meter Unit', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3833, 16, 1, '132080305037', 'Lensa F+5', 'Lensa cembung memiliki bentuk menonjol ke luar dan mampu memusatkan sinar cahaya yang melewatinya untuk bertemu pada titik fokusnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3834, 16, 1, '132080305041', 'Magnit Batang', 'Magnet batang adalah magnet yang memiliki bentuk batang, biasanya terbuat dari bahan magnetik seperti besi, kobalt, nikel, atau paduan lainnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3835, 8, 1, '132080103010', 'Circulation Tank', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3836, 16, 1, '132080305042', 'Sebuk Besi', 'Serbuk besi adalah bagian dari hasil sisa potongan atau sisa pembubutan besi tuang yang merupakan hasil di pemakaian industri', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3837, 16, 1, '132080305043', 'Tombok Tekan', 'Tombol tekan adalah tombol yang digunakan untuk menghubungkan dan memutuskan rangkaian listrik dengan cara ditekan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3838, 8, 1, '132080103012', 'Ecosonder', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3839, 16, 1, '132080305044', 'Kumparan 300', 'Kumparan 300 lilitan mengacu pada kumparan atau gulungan kawat yang dibentuk menjadi lilitan sebanyak 300 putaran atau putaran lengkap. Kumparan dengan jumlah lilitan tertentu sering kali digunakan dalam berbagai aplikasi, terutama dalam elektronika dan fisika, untuk menciptakan medan magnet atau untuk pembuatan induktor.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3840, 16, 1, '132080305045', 'Inti Kumparan 300 Lilitan', 'Kumparan 300 lilitan mengacu pada kumparan atau gulungan kawat yang dibentuk menjadi lilitan sebanyak 300 putaran atau putaran lengkap. Kumparan dengan jumlah lilitan tertentu sering kali digunakan dalam berbagai aplikasi, terutama dalam elektronika dan fisika, untuk menciptakan medan magnet atau untuk pembuatan induktor.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3841, 16, 1, '132080305046', 'Ampermeter', 'Amperemeter adalah alat ukur listrik yang digunakan untuk mengukur nilai arus listrik yang mengalir dalam suatu rangkaian listrik. Pengukuran arus listrik harus memutuskan rangkaian terlebih dahulu lalu dihubungkan masing-masing ke terminal-terminal amperemeter.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3842, 16, 1, '132080305047', 'Batang Gelas/Plastik', 'Gelas plastik ukur adalah alat mengukur volume cairan kimia yang akan digunakan', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3843, 16, 1, '132080305048', 'Voltmeter', 'Voltmeter merupakan alat ukur yang berfungsi untuk mengukur besar tegangan listrik yang ada di suatu rangkaian listrik dalam besaran dan satuan tertentu.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3844, 8, 1, '132080103017', 'Delf Bottler', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3845, 16, 1, '132080305050', 'Lensa Tangan', 'Lensa tangan adalah alat kecil yang digunakan untuk memperbesar sesuatu yang dilihat oleh ahli entomologi (atau naturalis lainnya). Lensa tangan terdiri dari lensa yang terbuat dari potongan kaca atau plastik.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3846, 8, 1, '132080103018', 'Crosible Cours', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3847, 16, 1, '132080305051', 'Papan Pengempres', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3848, 16, 1, '132080305053', 'Gelas Objek', 'Objek glass merupakan suatu komponen dari mikroskop yang digunakan untuk meletakkan preparat. Objek glass berbentuk persegi panjang yang terbuat dari kaca transparan sehingga mempermudah anda dalam menggunakannya', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3849, 8, 1, '132080103020', 'Carbon Rod Auto Meter', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3850, 16, 1, '132080305054', 'Gelas Penutup', 'Gelas penutup adalah wadah gelas kecil yang digunakan untuk menutupi atau melindungi gelas atau cangkir saat tidak digunakan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3851, 8, 1, '132080103021', 'N A C C O L', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3852, 16, 1, '132080305055', 'Mikroskop', 'Mikroskop atau teropong tuma (serapan dari Belanda: microscoop) adalah alat laboratorium yang digunakan untuk mengamati benda yang sangat kecil dan benda yang tidak tampak oleh indra penglihatan secara langsung.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3853, 16, 1, '132080305056', 'Bronthymol Biru', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3854, 16, 1, '132080305058', 'Pipa Manometer', 'Pipa manometer adalah komponen utama dari sebuah manometer, alat yang digunakan untuk mengukur tekanan fluida (gas atau cair). Pipa manometer adalah tabung yang mengandung cairan atau fluida yang bergerak sebagai indikator tekanan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3855, 8, 1, '132080103024', 'Mechanical Mortar', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3856, 16, 1, '132080305059', 'Pipa Gelas', 'Pipa gelas adalah pipa yang terbuat dari kaca atau material kaca yang digunakan dalam berbagai konteks.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3857, 8, 1, '132080103025', 'Conedrop Test (Alat Laboratorium Hidrokimia)', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3858, 16, 1, '132080305060', 'Sepit Kayu', 'Sepit kayu adalah alat sederhana yang terbuat dari kayu atau bahan lain yang digunakan untuk menjepit atau menggenggam benda.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3859, 8, 1, '132080103026', 'Standar Warna Gardner', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3860, 16, 1, '132080305061', 'Mortir/Alu', 'Mortar dan alu adalah alat laboratorium yang bentuknya sangat mirip seperti lumpang. Mortar dan alu terbuat dari bahan porselin atau keramik yang membuatnya terlihat mirip dengan cawan porselin ataupun krusibel.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3861, 16, 1, '132080305062', 'Rak Tabung Reaksi', 'Rak tabung reaksi merupakan salah satu dari instrumen peralatan laboratorium non-gelas yang digunakan untuk menyimpan atau menata beberapa tabung reaksi', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3862, 8, 1, '132080104001', 'Rechbock', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3863, 16, 1, '132080305063', 'Sumbat Karet Berpipa', 'Sumbat pipa karet adalah perangkat yang terbuat dari bahan karet atau elastomer lainnya yang dirancang untuk menutup atau menyegel ujung pipa', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3864, 8, 1, '132080104002', 'Cipoletti', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3865, 16, 1, '132080305065', 'Sumbat Tabung Reaksi + Pipa Lurus', 'Sumbat tabung reaksi dengan pipa lurus adalah perangkat atau alat yang digunakan dalam laboratorium kimia untuk berbagai tujuan, terutama dalam proses reaksi kimia atau percobaan tertentu.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3866, 8, 1, '132080104003', 'Thompson', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3867, 16, 1, '132080305067', 'Pot Besar', 'wadah berukuran besar yang digunakan untuk menanam atau menumbuhkan tanaman, terutama dalam kegiatan berkebun atau pertanian.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
