	(3886, 16, 1, '132080306015', 'Motor Listrik', 'Motor listrik adalah alat untuk mengubah energi listrik menjadi energi mekanik. Alat yang berfungsi sebaliknya, mengubah energi mekanik menjadi energi listrik disebut generator atau dinamo.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
