	(3888, 16, 1, '132080306016', 'Ticker Limer', 'Ticker timer merupakan salah satu alat praktikum yang sering digunakan dalam percobaan materi GLB atau GLBB. Ticker timer (pengetik waktu) adalah alat yang digunakan untuk mencatat atau mendeteksi kecepatan suatu troli.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
