	(3891, 16, 1, '132080306019', 'Silinder Materi', 'Silinder materi mengacu pada sebuah objek silinder yang terbuat dari materi tertentu. Silinder adalah objek tiga dimensi yang memiliki bentuk silindris, dengan dua lingkaran sejajar yang disebut tutup silinder dan permukaan lengkung yang menghubungkannya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
