	(3951, 8, 1, '132080106019', 'Line Machine', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3952, 17, 1, '132080310016', 'Gendang', 'Kêndang atau sêndang adalah alat bunyi-bunyian berupa kayu bulat panjang, di dalamnya ada rongga dan salah satu lubangnya atau kedua-duanya diberi kulit', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3953, 17, 1, '132080310017', 'Rebana', 'Rebana adalah gendang berbentuk bundar dan pipih yang merupakan khas suku Melayu. Bingkai berbentuk lingkaran terbuat dari kayu yang dibubut, dengan salah satu sisi untuk ditepuk berlapis kulit kambing.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3954, 8, 1, '132080106021', 'Wolding Range', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3955, 17, 1, '132080310018', 'Perkusi', 'Perkusi pada dasarnya merupakan benda apapun yang dapat menghasilkan suara baik karena dipukul, dikocok, digosok, diadukan, atau dengan cara apapun yang dapat membuat getaran pada benda tersebut.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3956, 8, 1, '132080106022', 'Block Making Machine', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3957, 17, 1, '132080311001', 'Kayu Pemukul', 'Kayu pemukul adalah alat peraga olahraga yang digunakan untuk memukul benda/bola', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3958, 8, 1, '132080106023', 'Batako Press Test', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3959, 17, 1, '132080311002', 'Start Blok', 'Start block adalah alat yang digunakan dalam olahraga atletik oleh atlet sprint untuk menahan kaki mereka pada awal perlombaan sehingga mereka tidak tergelincir saat mereka mendorong pada suara pistol.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3960, 8, 1, '132080106024', 'Cell Unit', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3961, 17, 1, '132080311003', 'Pita Ukuran (Meteran)', 'Pita ukur merupakan perangkat pengukuran portabel yang digunakan untuk mengukur panjang, jarak dan sudut. Pita ukur biasa dikenal juga sebagai meteran, tape atau roll meter yang memiliki 2 satuan ukur yaitu satuan inggris (inch, feet, dan yard) dan satuan metrik (mm, cm, dan m)', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3962, 8, 1, '132080106025', 'Direcshear Unit', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3963, 17, 1, '132080312001', 'Lambang Negara (Garuda)', 'Lambang Garuda sering digunakan dalam berbagai alat peraga resmi negara Indonesia, seperti bendera, lambang negara, logo lembaga pemerintah, dan sebagainya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3964, 8, 1, '132080106026', 'Atterberg', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3965, 17, 1, '132080312002', 'Bendera Merah Putih', 'Alat peraga bendera merah putih sering kali digunakan sebagai simbol atau perlambangan dari suatu negara atau perayaan khusus yang melibatkan identitas nasional.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3966, 17, 1, '132080313001', 'Struktur Bumi 3 Dimensi Braille', 'Struktur Bumi 3 Dimensi Braille adalah representasi tiga dimensi dari struktur bumi yang dirancang khusus untuk orang dengan gangguan penglihatan. Ini adalah model yang menggambarkan lapisan-lapisan atau struktur bumi dalam format yang dapat dibaca dengan sentuhan, menggunakan huruf Braille atau sistem tanda-tangan khusus lainnya yang dapat dirasakan oleh jari.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3967, 8, 1, '132080106028', 'Zondering Machine Unit', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3968, 17, 1, '132080313002', 'Alat Peraga Tuna Netra Abakus', 'Abacus yang juga dikenal dengan “sempoa” adalah alat bantu berhitung; Di Indonesia, masyarakat mengenal etnik Tionghoa dahulu menggunakan sempoa untuk berhitung ketika mereka berdagang', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3969, 8, 1, '132080106029', 'Stroler Apparoat', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3970, 17, 1, '132080313003', 'Alat Peraga Tuna Netra Blokis', 'merupakan alat bantu tunanetra untuk berhitung yang dirancang khusus untuk membantu orang tunanetra atau memiliki gangguan penglihatan dalam belajar konsep matematika atau berhitung. Alat ini biasanya dirancang dengan fitur-fitur yang dapat diakses melalui indra peraba.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3971, 8, 1, '132080106030', 'Sticle Apparoat', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3972, 17, 1, '132080313004', 'Alat Peraga Tuna Netra Bola Kaki Bunyi', 'Audible ball, atau bola berbunyi, adalah alat bantu yang penting bagi orang tunanetra untuk berpartisipasi dalam olahraga. Bola ini berisi bola-bola kecil (bearing) atau lonceng kecil yang menghasilkan suara saat bola bergerak.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3973, 17, 1, '132080313005', 'Alat Peraga Tuna Netra Braille Text', 'Tuna Netra Braille Text adalah alat peraga untuk membantu tuna netra dalam hal baca-tulis', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3974, 17, 1, '132080313006', 'Alat Peraga Tuna Netra Busur Derajat Braille', 'Tuna Netra Busur Derajat merupakan alat ukur/ peraga/ bantu dalam pelajaran matematika bagi tunanetra. Bentuk setengah lingkaran, terdapat jarum penunjuk, titik-titik timbul setiap 10 derajat, dan angka-angka Braille pada sudut-sudut istimewa', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3975, 17, 1, '132080313008', 'Alat Peraga Tuna Netra Globe Timbul', 'Merupakan peraga bola dunia timbul dengan keterangan dalam Huruf Braille bagi penyandang tunanetra. Menggambarkan secara taktual keadaan geografis muka bumi. dilengkapi dengan garis lintang, garis bujur dan batas penanggalan internasional timbul.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3976, 17, 1, '132080314001', 'Alat Peraga Autotronik Actuators Of Engine Management System', 'Autotronik Actuators of Engine Management System merujuk pada komponen-komponen elektronik yang mengontrol atau menggerakkan sistem manajemen mesin pada kendaraan bermotor.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3977, 8, 1, '132080106035', 'Stressing & Manometer', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3978, 17, 1, '132080314002', 'Alat Peraga Autotronik Anti Lock Brake System (ABS)', 'Anti Lock Braking System yaitu sebuah komponen yang cukup penting bagi kendaraan. Pengertian rem ABS pada mobil yaitu sebuah teknologi yang mengusung inovasi terbaru dalam sistem pengereman yang tersedia pada kendaraan seperti halnya mobil.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3979, 17, 1, '132080314003', 'Alat Peraga Autotronik Digital Electronic Fundamental Trainer For Automotive', 'Alat Peraga Autotronik Digital Electronic Fundamental Trainer for Automotive merupakan suatu sistem pelatihan atau alat edukasi yang didesain khusus untuk membantu dalam pemahaman dasar teknologi elektronika yang berkaitan dengan industri otomotif.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3980, 17, 1, '132080314004', 'Alat Peraga Autotronik Electrical Fundamental Trainer For Automotive', 'Autotronik Electrical Fundamental Trainer for Automotive adalah perangkat pelatihan yang dirancang khusus untuk memberikan pemahaman dasar tentang sistem elektrikal dalam kendaraan bermotor, terutama pada bidang otomotif', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3981, 17, 1, '132080315001', 'Magnetik Angka', 'Magnetic Angka First Classroom adalah alat peraga pendidikan yang sering digunakan di lingkungan kelas untuk membantu guru dalam mengajarkan konsep matematika kepada anak-anak. Alat ini terdiri dari angka-angka yang terbuat dari bahan magnetik yang dapat ditempelkan ke papan tulis atau permukaan magnetik lainnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3982, 8, 1, '132080106039', 'Vibrating Unit', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3983, 17, 1, '132080315002', 'Magnetic Angka First Classroom', 'Magnetic Angka First Classroom adalah alat peraga pendidikan yang sering digunakan di lingkungan kelas untuk membantu guru dalam mengajarkan konsep matematika kepada anak-anak. Alat ini terdiri dari angka-angka yang terbuat dari bahan magnetik yang dapat ditempelkan ke papan tulis atau permukaan magnetik lainnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3984, 17, 1, '132080315004', 'Magnetic Learning Set', 'Magnetic Learning Set adalah alat peraga pendidikan untuk memberikan pengalaman belajar yang interaktif dan visual kepada pengguna, baik itu anak-anak di sekolah maupun individu yang sedang belajar konsep tertentu', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3985, 8, 1, '132080106041', 'Greep Appraat', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3986, 18, 1, '132080401001', 'Ge Detector (Planer + Coaxlal)', 'jenis detektor yang umumnya digunakan dalam bidang spektroskopi gamma untuk mendeteksi radiasi ionisasi tinggi, khususnya radiasi gamma. Detektor ini memanfaatkan sifat-sifat semikonduktor germanium sebagai bahan deteksi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3987, 18, 1, '132080401007', 'Vertical Dispstick Cryostat', 'Kriostat batang vertikal (vertical dipstick cryostat) adalah sebuah peralatan ilmiah yang digunakan untuk mencapai dan mempertahankan suhu sangat rendah, biasanya di bawah -196 derajat Celsius (-321 derajat Fahrenheit). Dinamakan "batang vertikal" karena sampel penelitian diturunkan secara vertikal ke dalam wadah berisi pendingin (refrigerant) melalui sebuah batang atau tabung panjang.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3988, 18, 1, '132080401020', 'Monitor Radiasi', 'perangkat yang dirancang untuk mendeteksi, mengukur, dan memantau tingkat radiasi di lingkungan tertentu. Monitor radiasi digunakan untuk melindungi manusia dan lingkungan dari paparan radiasi berlebih dan untuk memastikan keselamatan dalam berbagai konteks, seperti di fasilitas nuklir, laboratorium, industri, dan sektor medis.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3989, 8, 1, '132080106044', 'Alat Pemeriksa Semen', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3990, 18, 1, '132080401021', 'Fume/gas Leak Detector (Radiation Detector)', 'perangkat yang dirancang khusus untuk mendeteksi kebocoran gas atau asap di lingkungan tertentu. Detektor ini bekerja dengan cara mendeteksi adanya gas tertentu atau partikel asap dalam udara yang dapat menunjukkan kebocoran atau potensi bahaya lainnya. Detektor ini dapat digunakan dalam berbagai pengaturan dan aplikasi, termasuk di rumah, industri, atau fasilitas komersial.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3991, 8, 1, '132080106045', 'Vicat Apparatur', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3992, 18, 1, '132080401023', 'Electronic Control (Radiation Detector)', 'kendali elektronik yang terintegrasi dalam detektor radiasi. Detektor radiasi adalah perangkat yang dirancang untuk mendeteksi dan mengukur tingkat radiasi ionisasi atau non-ionisasi dalam suatu lingkungan. Radiasi dapat berasal dari berbagai sumber, termasuk sinar-X, sinar gamma, neutron, dan partikel bermuatan seperti proton atau beta.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3993, 18, 1, '132080401024', 'Glove Box (Radiation Detector)', 'sistem di mana detektor radiasi dipasang atau terintegrasi di dalam Glove Box. Ini dapat menjadi langkah keamanan tambahan dalam situasi di mana perlindungan dari radiasi dan isolasi lingkungan diperlukan, seperti dalam penanganan atau penelitian bahan-bahan radioaktif di dalam lingkungan kontrol Glove Box.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3994, 18, 1, '132080401031', 'Dose Area Product/Kerma Area Product', 'perangkat yang dirancang khusus untuk mengukur parameter-parameter tersebut selama pemeriksaan radiologi atau prosedur fluoroskopi. Detektor ini membantu dalam mengumpulkan data yang diperlukan untuk menilai dosis radiasi yang diterima oleh pasien selama pemeriksaan.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3995, 18, 1, '132080402001', 'Preamplifier Proportional Couter', 'preamplifier digunakan bersama dengan proportional counter. Preamplifier membantu menguatkan sinyal yang dihasilkan oleh proportional counter, memungkinkan deteksi dan pengukuran yang lebih akurat dari radiasi ionisasi yang terdeteksi.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3996, 18, 1, '132080402004', 'Preamplifier Semi Conductor Detactor', 'sistem penghitungan modular yang melibatkan perangkat elektronika ilmiah, khususnya preamplifier, yang digunakan bersama dengan detektor semikonduktor. Detektor semikonduktor dapat memberikan respons yang baik terhadap radiasi ionisasi, dan preamplifier digunakan untuk meningkatkan sensitivitas dan mengolah sinyal detektor sebelum langkah-langkah analisis lebih lanjut. Sistem semacam ini sering digunakan dalam penelitian nuklir dan aplikasi deteksi radiasi lainnya.', NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3997, 8, 1, '132080106050', 'Weight Percopit Yield & Air Content', NULL, NULL, NULL, '2026-04-30 03:15:53', '2026-04-30 03:15:53'),
	(3998, 18, 1, '132080402010', 'Biased Amplifier', 'jenis amplifier yang memiliki tegangan bias (bias voltage) yang diterapkan padanya. Tegangan bias ini diperlukan untuk menentukan atau menetapkan titik kerja (quiescent point) dari amplifier. Titik kerja ini sangat penting untuk memastikan amplifier bekerja secara optimal dan responsif terhadap sinyal input.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(3999, 18, 1, '132080402011', 'Preamp/Amp/Disc (PAD)', 'Preamplifier adalah perangkat elektronik yang berfungsi untuk memperkuat sinyal input sebelum mencapai amplifier utama. Preamp biasanya digunakan untuk meningkatkan sinyal yang lemah atau untuk mempersiapkan sinyal sebelum diproses lebih lanjut oleh perangkat audio atau elektronik lainnya. Amplifier adalah perangkat elektronik yang memperkuat sinyal listrik. Amplifier dapat digunakan dalam berbagai konteks, termasuk audio, radio frekuensi, atau bahkan dalam aplikasi lain seperti amplifier operasional (op-amp) dalam elektronika. Discriminator adalah perangkat atau rangkaian dalam elektronika yang digunakan untuk memproses atau membedakan sinyal berdasarkan karakteristik tertentu. Dalam konteks komunikasi atau modulasi, discriminator dapat digunakan untuk mendeteksi informasi dari sinyal yang dimodulasi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4000, 8, 1, '132080106052', 'Prganic Impuris Test Set', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4001, 18, 1, '132080402012', 'Timming Filter Amplifier', 'merujuk pada suatu jenis amplifier yang digunakan untuk memperkuat sinyal elektronik dengan fokus pada pemfilteran waktu. Filter waktu dapat mengacu pada proses di mana sinyal-sinyal dengan waktu tertentu diberi penekanan atau diredam.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4002, 8, 1, '132080106053', 'Soundeness Apparatus', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4003, 18, 1, '132080402013', 'Sum-Invert Amplifier', 'Sirkuit elektronik yang menjumlahkan dua atau lebih sinyal input dan menghasilkan output dengan polaritas terbalik.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4004, 18, 1, '132080402021', 'Analog To Digital Converter (ADC)', 'perangkat elektronika yang berfungsi mengubah sinyal analog menjadi sinyal digital. Dalam dunia elektronika, sinyal analog adalah sinyal yang dapat bervariasi secara kontinu, sedangkan sinyal digital adalah representasi diskrit dari sinyal analog, yang hanya dapat memiliki nilai-nilai tertentu.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4005, 18, 1, '132080402022', 'Linear Gate', 'elemen yang dapat mengontrol aliran arus listrik. "Linear Gate" bisa merujuk pada jenis gerbang logika yang memiliki karakteristik linier dalam hal keluaran terhadap masukan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4006, 8, 1, '132080106056', 'Slump Test Set', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4007, 18, 1, '132080402023', 'Linear Gate And Streteher', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4008, 18, 1, '132080402024', 'Live-Time Counector Pile Up Rejector', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4009, 18, 1, '132080402025', 'Spectrum Stabilyzer', 'alat elektronik yang digunakan dalam spektroskopi untuk meningkatkan stabilitas dan akurasi pengukuran spektrum.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4010, 18, 1, '132080402026', 'Logic Analyzer (Modular Counting And Scentific Electronic)', 'Ia bekerja dengan cara mengurangi noise listrik dan frekuensi radio yang dapat mengganggu sinyal spektrum yang sebenarnya, menstabilkan gain penguat sinyal spektrum, dan menyesuaikan baseline spektrum.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4011, 18, 1, '132080402027', 'Mixer Rauter', 'mixer audio dengan kemampuan perutean bawaan. Dalam bahasa Indonesia, Anda bisa menyebutnya sebagai "Mixer Ruter Audio" atau "Mixer Audio dengan Ruting".', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4012, 8, 1, '132080106061', 'Calibration Anvil For Concrette', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4013, 18, 1, '132080402030', 'Multi-Input -Multi Scaler', 'Kemampuan suatu perangkat untuk menerima sinyal dari banyak sumber input secara bersamaan. dan Perangkat atau sirkuit elektronik yang bisa mengubah skala (memperbesar atau memperkecil) amplitudo sinyal dengan faktor berbeda-beda untuk setiap input.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4014, 18, 1, '132080402031', 'Blind Scaler', 'Blind scaler adalah sebuah alat yang digunakan untuk mengukur jumlah neutron yang melewatinya. Blind scaler terdiri dari dua bagian utama\nBlind Scaler adalah sirkuit penting dalam sistem Modular Counting dan Elektronik Ilmiah yang berfungsi untuk meningkatkan resolusi waktu pengukuran kejadian (event) yang sangat rapat. /alat yang dapat melakukan pengukuran dengan skala yang sangat kecil', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4015, 18, 1, '132080402033', 'Paralel To Serial Converter', 'Perangkat atau sirkuit yang mengubah data dari mode paralel menjadi mode serial. Alat ini adalah konverter yang umumnya digunakan dalam komunikasi data dan pemrosesan informasi elektronik.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4016, 8, 1, '132080106064', 'Beaker Toll From Graduates', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4017, 18, 1, '132080402034', 'Paper Tape Scanner', 'perangkat yang digunakan untuk membaca atau memindai tape kertas. Tape kertas adalah medium penyimpanan informasi yang terdiri dari gulungan atau strip kertas dengan lubang-lubang yang diatur sedemikian rupa untuk merepresentasikan data.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4018, 18, 1, '132080402035', 'Teletype Scanner', 'perangkat yang digunakan untuk membaca dan merekam data dari dokumen tertulis ke dalam bentuk elektronik. Ini melibatkan penggunaan scanner untuk mengonversi teks dari dokumen fisik menjadi format digital yang dapat diproses oleh komputer.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4019, 8, 1, '132080106066', 'Bottle Wighing High', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4020, 18, 1, '132080402036', 'Blind Timer', 'Blind Timer dalam Modular Counting dan Elektronik Ilmiah berfungsi untuk mengukur durasi kejadian (event) yang berlangsung dalam jangka waktu tertentu, dan mirip dengan Blind Scaler dalam beberapa aspek,', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4021, 8, 1, '132080106067', 'Biling Flash', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4022, 18, 1, '132080402037', 'Timer/Scaler/Counter', 'timer adalah perangkat yang digunakan untuk mengukur interval waktu atau menghitung mundur waktu dari suatu kejadian.scaler (pembagi frekuensi) adalah perangkat elektronik yang digunakan untuk mengubah frekuensi sinyal menjadi frekuensi yang lebih rendah. Scaler seringkali digunakan dalam sistem pemrosesan sinyal dan pengukuran frekuensi. counter adalah perangkat elektronik yang digunakan untuk menghitung jumlah kejadian atau pulsa dalam suatu periode waktu. Counter dapat digunakan dalam berbagai aplikasi, seperti pengukuran kecepatan, sistem kendali, dan pemrosesan sinyal.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4023, 8, 1, '132080106068', 'Static With Rechtangular Base', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4024, 18, 1, '132080402039', 'Serial Scanner/Printer', 'kombinasi perangkat yang mencakup scanner dan printer yang terhubung melalui antarmuka serial, dan mungkin ada suatu perangkat atau sistem yang mengoordinasikan fungsi scanner untuk mendapatkan data dan kemudian mencetaknya menggunakan printer. Penggunaan antarmuka serial dapat memberikan fleksibilitas dan kompatibilitas dalam situasi di mana koneksi nirkabel atau USB mungkin tidak praktis atau tersedia. Sistem semacam ini dapat ditemui dalam beberapa lingkup seperti sistem pengolahan dokumen, perangkat POS (Point of Sale), atau aplikasi lain di mana dokumen fisik perlu diubah menjadi format digital dan dicetak kembali.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4025, 18, 1, '132080402040', 'Preamp Power Supply', 'Dalam Modular Counting dan Elektronik Ilmiah, Preamp Power Supply adalah modul atau sirkuit yang menyediakan daya dan sinyal kontrol untuk preamplifier.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4026, 18, 1, '132080402041', 'Bin/Power Supply', 'Power supply atau sumber daya adalah perangkat atau sistem yang menyediakan daya listrik untuk perangkat elektronik.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4027, 8, 1, '132080106071', 'Volume Metric Flash', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4028, 18, 1, '132080402044', 'DC Power Supply', 'DC Power Supply adalah perangkat atau sistem yang menyediakan tegangan listrik searah (Direct Current, DC) untuk menyuplai daya ke perangkat elektronik. DC Power Supply biasanya digunakan untuk menyediakan tegangan yang stabil dan terkendali untuk berbagai macam perangkat elektronik seperti rangkaian elektronik, peralatan pengukuran, komponen listrik, dan lainnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4029, 18, 1, '132080402046', 'Oscilator Modula', 'Oskilator adalah suatu rangkaian atau perangkat elektronik yang menghasilkan sinyal osilasi atau gelombang berulang-ulang. Modulasi merujuk pada proses mengubah karakteristik sinyal pembawa untuk membawa informasi. Ada berbagai jenis modulasi, seperti modulasi amplitudo (AM), modulasi frekuensi (FM), dan modulasi fase (PM), yang sering digunakan dalam komunikasi nirkabel dan penyiaran.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4030, 18, 1, '132080402049', 'Pulse Generator /Pulser', 'Pulse Generator, atau sering disebut sebagai Pulser, adalah perangkat atau sirkuit elektronik yang dirancang untuk menghasilkan sinyal pulsa atau gelombang berdenyut. Sinyal pulsa ini memiliki karakteristik waktu tertentu di mana sinyal beralih antara tingkat tinggi (on) dan tingkat rendah (off) secara periodik.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4031, 8, 1, '132080106074', 'Dial Flow', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4032, 18, 1, '132080402051', 'Function Generator (Modular Counting And Scentific Electronic)', 'Function Generator adalah perangkat atau instrumen di bidang elektronika yang dirancang untuk menghasilkan sinyal output elektrik yang dapat diatur dengan berbagai bentuk gelombang dan frekuensi tertentu. Ini merupakan alat yang umum digunakan dalam laboratorium elektronika, pendidikan, dan pengembangan sistem elektronik. Function Generator dapat menciptakan berbagai jenis gelombang, termasuk gelombang sinus, gelombang persegi, gelombang segitiga, dan gelombang pulsa.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4033, 8, 1, '132080106075', 'Cylinde Vorcelen', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4034, 18, 1, '132080402052', 'Signal Generator (Modular Counting And Scentific Electronic)', 'perangkat atau instrumen di bidang elektronika yang dirancang untuk menghasilkan sinyal listrik yang dapat diatur. Ini adalah alat yang sangat umum digunakan dalam berbagai pengaturan, termasuk laboratorium, industri, dan pengembangan sistem elektronik. Signal Generator dapat menghasilkan berbagai jenis sinyal, seperti sinusoidal, persegi, segitiga, pulsa, dan lainnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4035, 8, 1, '132080106076', 'Extensic Meter', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4036, 18, 1, '132080402056', 'Logic Pulser', 'Logic Pulser adalah perangkat elektronika yang digunakan untuk menghasilkan pulsa elektrik pada level logika tertentu, baik tinggi (1) atau rendah (0), pada sirkuit logika digital. Biasanya, Logic Pulser digunakan dalam pengujian dan pemecahan masalah (troubleshooting) pada rangkaian digital, terutama pada sirkuit berbasis logika seperti gerbang logika, flip-flop, atau register.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4037, 8, 1, '132080106077', 'Le Chatelier Flash', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4038, 18, 1, '132080402057', 'Nuclear Counter', 'perangkat atau instrumen yang digunakan untuk mendeteksi dan menghitung partikel nuklir, seperti foton gamma atau partikel beta, yang dilepaskan selama peluruhan nuklir atau proses radiasi lainnya. Instrumen ini umumnya digunakan dalam eksperimen dan pengukuran radiasi di berbagai bidang, termasuk fisika nuklir, ilmu kedokteran nuklir, dan penelitian lingkungan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4039, 18, 1, '132080403002', 'Multi Channel Analyzer', 'Multi-Channel Analyzer (MCA) adalah perangkat elektronik yang digunakan dalam pengukuran spektrum nuklir dan analisis data. Ini adalah bagian dari sistem penghitungan dan pengaturan (assembly/counting system) yang digunakan dalam eksperimen nuklir dan penelitian radiasi. MCA bekerja dengan menghitung jumlah deteksi partikel atau foton di berbagai saluran energi yang berbeda, membentuk distribusi energi atau spektrum energi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4040, 8, 1, '132080106079', 'Lantai Uji', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4041, 18, 1, '132080403003', 'Multi Parameter System', 'Sistem Multi-Parameter adalah jenis sistem di mana lebih dari satu parameter atau variabel diukur dan dimonitor secara bersamaan. Ini dapat mencakup berbagai jenis data atau informasi yang diukur dalam satu sistem untuk memberikan gambaran yang lebih lengkap dan komprehensif tentang situasi atau lingkungan tertentu. Sementara itu, Assembly/Counting System menunjukkan sistem yang dirancang untuk menghitung peristiwa atau objek tertentu.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4042, 8, 1, '132080106080', 'Rig Uji Universal', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4043, 18, 1, '132080403004', 'Scanner (Assembly/counting System)', 'perangkat yang digunakan untuk mendeteksi atau mengukur objek atau peristiwa tertentu secara otomatis.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4044, 18, 1, '132080403005', 'Ultra Low Level / Counting System', 'sistem yang dirancang khusus untuk mendeteksi dan menghitung aktivitas nuklir pada tingkat yang sangat rendah atau ultra rendah. Sistem ini biasanya digunakan dalam penelitian nuklir, pengukuran radiasi lingkungan, dan aplikasi lain di mana perluasan dan analisis data pada tingkat aktivitas yang sangat rendah menjadi kritis.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4045, 8, 1, '132080106082', 'Mesin Uji Getar', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4046, 18, 1, '132080403012', 'Logger', 'perangkat atau sistem perekam data. Logger digunakan untuk mengumpulkan dan merekam data secara otomatis dari berbagai sensor atau sumber pengukuran dalam suatu sistem. Perekam data ini biasanya dapat digunakan untuk menganalisis dan memantau kinerja sistem, mencatat peristiwa khusus, atau menyimpan informasi yang diperlukan untuk audit atau keperluan dokumentasi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4047, 18, 1, '132080404001', 'Single Channel Recorder', 'perangkat yang dirancang untuk merekam dan menampilkan data dari satu sumber atau saluran. Fungsinya adalah memonitor dan merekam perubahan atau variabel dalam satu parameter atau sumber informasi tunggal. Perangkat ini sering digunakan dalam berbagai aplikasi di mana pemantauan dan pencatatan data dari satu sumber kritis untuk keperluan analisis atau dokumentasi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4048, 18, 1, '132080404002', 'Dual Channel Recorder', 'perangkat atau sistem yang dirancang untuk merekam dan menampilkan data dari dua sumber atau dua saluran secara bersamaan. Ini memungkinkan pengguna untuk memonitor dan merekam perubahan atau variabel dalam dua parameter atau dari dua sumber informasi secara bersamaan. Sistem ini sering digunakan dalam situasi di mana pemantauan dan pencatatan data dari dua sumber atau parameter sangat penting untuk analisis atau dokumentasi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4049, 18, 1, '132080404004', 'Cathode Ray Osciloscope', 'jenis oscilloscope yang menggunakan tabung sinar katoda (CRT) sebagai bagian utamanya. CRO digunakan untuk memvisualisasikan sinyal listrik dalam bentuk gelombang pada layar CRT.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4050, 8, 1, '132080106086', 'Aktuator', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4051, 18, 1, '132080404005', 'Camera Scope', 'perangkat yang menggabungkan kamera dengan kemampuan pengukuran atau observasi lainnya, mungkin ini dapat merujuk pada suatu jenis perangkat yang digunakan dalam aplikasi khusus seperti pengukuran industri atau pemantauan teknis.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4052, 18, 1, '132080404006', 'GO Recorder', 'aplikasi untuk merekam kegiatan apa pun di layar Android Anda dengan cara yang mudah -bersamaan dengan melakukan kegiatan lain- dengan alat yang sangat bermanfaat', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4053, 18, 1, '132080404007', 'Hybrid Recorder', 'jenis perekam yang menggabungkan karakteristik dari dua atau lebih jenis rekaman yang berbeda. Ini bisa mencakup kombinasi antara perekaman analog dan digital, atau kombinasi fitur-fitur lainnya yang umumnya terdapat dalam rekaman berbeda.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4054, 18, 1, '132080405001', 'Generator Set(Lab Scale)', 'suatu sistem pembangkit listrik yang dirancang untuk skala laboratorium atau skala percobaan. Generator set, juga dikenal sebagai genset, umumnya terdiri dari sebuah generator dan mesin penggerak (biasanya motor pembakaran dalam) yang berfungsi menghasilkan listrik. Di skala laboratorium, generator set ini digunakan untuk mensimulasikan kondisi penggunaan generator pada skala yang lebih kecil dan terkendali.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4055, 18, 1, '132080405002', 'Uninterupted Power Supply (UPS)', 'Uninterruptible Power Supply (UPS), atau Sistem Pasokan Daya yang Tidak Terputus, adalah perangkat elektronik yang menyediakan sumber daya listrik cadangan dalam situasi ketika pasokan daya utama terputus atau mengalami fluktuasi. Tujuannya adalah untuk melindungi perangkat elektronik yang terhubung ke UPS dari pemadaman listrik atau gangguan listrik lainnya. UPS memberikan waktu tambahan untuk menyelamatkan pekerjaan atau mematikan perangkat secara aman.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4056, 8, 1, '132080107002', 'Visibility Yar Bath', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4057, 18, 1, '132080405003', 'Single Phase Transformer Step Up/Down', 'Single-Phase Transformer Step Up/Down adalah transformator satu fasa yang dirancang untuk mengubah tegangan listrik dari tingkat yang lebih rendah (step-down) ke tingkat yang lebih tinggi atau sebaliknya (step-up). Transformator ini umumnya digunakan pada sistem distribusi listrik satu fasa, seperti yang sering ditemui di rumah-rumah atau aplikasi industri ringan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4058, 18, 1, '132080405004', 'Three Phase Transformer Step Up/Down', 'Three-Phase Transformer Step Up/Down adalah transformator tiga fasa yang dirancang untuk mengubah tegangan listrik dari tingkat yang lebih rendah (step-down) ke tingkat yang lebih tinggi atau sebaliknya (step-up). Transformator ini beroperasi pada sistem tiga fasa, yang umumnya digunakan dalam distribusi listrik dan industri untuk mentransformasi tegangan listrik dalam skala besar.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4059, 18, 1, '132080405005', 'Constant Voltage Transformer', 'Constant Voltage Transformer (CVT) adalah jenis transformator yang dirancang untuk memberikan keluaran tegangan yang relatif konstan meskipun terjadi fluktuasi besar pada tegangan masukan. Tujuan utama dari CVT adalah untuk melindungi perangkat elektronik dan peralatan sensitif dari fluktuasi tegangan yang dapat merusak atau mempengaruhi kinerja peralatan tersebut.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4060, 8, 1, '132080107005', 'Penctrometer', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4061, 18, 1, '132080405007', 'Sliding Riostats', 'Rheostat sendiri adalah suatu jenis resistor yang nilai resistansinya dapat diubah-ubah dengan cara memutar atau menggeser. Ketika istilah "sliding" digunakan, itu merujuk pada kemampuan elemen resistif di dalam rheostat yang bisa digeser atau disetel.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4062, 8, 1, '132080107006', 'Surface Tension', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4063, 18, 1, '132080405008', 'Cable Drum', 'Cable Drum (drum kabel) adalah suatu perangkat atau struktur yang dirancang untuk menyimpan dan membawa gulungan kabel. Ini biasanya digunakan di berbagai lingkungan dan aplikasi, terutama di bidang konstruksi, industri, penyiaran, dan pengaturan acara live di mana kabel listrik atau kabel sinyal sering kali harus digulung dan diatur untuk memudahkan instalasi dan pengelolaan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4064, 18, 1, '132080405009', 'Altenator', 'Alternator adalah komponen kunci dalam sistem pengisian kendaraan, dan keberhasilannya memastikan bahwa sistem listrik kendaraan tetap beroperasi dengan baik dan baterai tetap terisi penuh.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4065, 18, 1, '132080405012', 'Sample Changer', 'perangkat atau sistem otomatis yang dirancang untuk menggantikan atau mengelola sampel secara otomatis dalam suatu instrumen atau sistem analisis. Ini digunakan dalam berbagai aplikasi laboratorium, penelitian, dan industri di mana analisis berulang dari berbagai sampel diperlukan. Sample Changer membantu meningkatkan efisiensi, akurasi, dan reproduktibilitas dalam proses analisis.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4066, 8, 1, '132080107009', 'Rectitice', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4067, 18, 1, '132080405013', 'Liquid N2 Productions System', 'sistem produksi nitrogen cair (Liquid Nitrogen atau LN2). Nitrogen cair adalah bentuk nitrogen yang berada dalam keadaan cair pada suhu sangat rendah, yaitu di bawah -196 derajat Celsius (-321 derajat Fahrenheit). Proses produksi nitrogen cair melibatkan pemisahan dan pendinginan nitrogen dari udara atmosfer.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4068, 18, 1, '132080405017', 'Auto Pcb Processor', 'perangkat atau sistem otomatis yang dirancang untuk memproses atau memanipulasi Printed Circuit Boards (PCB) secara otomatis. PCB adalah papan sirkuit elektronik yang digunakan untuk menyusun dan menghubungkan berbagai komponen elektronik pada suatu perangkat.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4069, 8, 1, '132080107011', 'Mantel Destilasi', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4070, 18, 1, '132080405020', 'Neutron Transmutation Doped Liquid Nitrogen (NTD LN2)', 'Neutron Transmutation Doped Liquid Nitrogen (NTD LN2) adalah teknologi yang melibatkan penggunaan neutron untuk menghasilkan perubahan dalam sifat-sifat nitrogen cair (liquid nitrogen atau LN2). Proses ini terkait dengan transmutasi nuklir, yaitu perubahan isotop unsur melalui paparan neutron.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4071, 8, 1, '132080107012', 'Hand Operated Extrator', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4072, 18, 1, '132080406001', 'Analog Volmeter', 'Analog Voltmeter adalah alat pengukur tegangan listrik yang menggunakan indikator analog, seperti jarum atau meter pergeser. Alat ini dirancang untuk mengukur tegangan listrik dalam sirkuit dan memberikan pembacaan dalam bentuk analog, yang ditunjukkan oleh pergerakan jarum di sepanjang skala yang tercetak pada layar meter.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4073, 8, 1, '132080107013', 'Fitter', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4074, 18, 1, '132080406002', 'Digital Volmeter', 'Digital Voltmeter adalah alat pengukur tegangan listrik yang menggunakan teknologi digital untuk memberikan pembacaan tegangan dalam bentuk angka digital. Alat ini mengonversi tegangan menjadi sinyal digital dan menampilkan hasilnya pada layar LED, LCD, atau tampilan digital lainnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4075, 18, 1, '132080406003', 'Amperemeter', 'alat pengukur yang digunakan untuk mengukur arus listrik dalam suatu rangkaian listrik. Arus listrik diukur dalam satuan ampere, dan amperemeter memberikan pembacaan langsung dari besarnya arus yang mengalir melalui rangkaian tersebut.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4076, 18, 1, '132080406004', 'Ohmmeter', 'alat pengukur resistansi listrik atau hambatan dalam suatu rangkaian listrik. Resistansi diukur dalam satuan ohm, dan ohmmeter memberikan pembacaan langsung dari besarnya resistansi suatu komponen atau rangkaian.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4077, 18, 1, '132080406005', 'Frequency Meter', 'alat pengukur yang digunakan untuk mengukur frekuensi sinyal listrik atau gelombang osilasi dalam suatu rangkaian. Frekuensi diukur dalam satuan hertz (Hz), dan frequency meter memberikan pembacaan langsung dari besarnya frekuensi sinyal yang diukur.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4078, 18, 1, '132080406006', 'Multifrequency LCR Meter', 'alat pengukur dan pengujian yang dirancang khusus untuk mengukur parameter dasar komponen listrik, yaitu induktansi (L), kapasitansi (C), dan resistansi (R). LCR merupakan singkatan dari ketiga parameter tersebut. Alat ini memiliki kemampuan untuk melakukan pengukuran pada berbagai frekuensi, sehingga disebut sebagai "multifrequency" LCR Meter.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4079, 8, 1, '132080107018', 'Destilasi Flux', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4080, 18, 1, '132080406011', 'Digital LCR Meter', 'alat pengukur dan pengujian yang dirancang untuk mengukur parameter dasar dari komponen listrik, yaitu induktansi (L), kapasitansi (C), dan resistansi (R), menggunakan teknologi digital. Berbeda dengan LCR Meter tradisional yang menggunakan tampilan analog, Digital LCR Meter memiliki tampilan digital yang menunjukkan nilai pengukuran dengan jelas dan akurat.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4081, 18, 1, '132080406012', 'Meter', 'alat yang digunakan untuk mengukur besaran arus dengan satuan ampere', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4082, 18, 1, '132080406013', 'High Resistence Meter', 'alat pengukur atau pengujian yang dirancang khusus untuk mengukur resistansi yang tinggi dalam suatu rangkaian atau komponen elektrik. Resistansi tinggi biasanya diukur dalam rentang nilai yang sangat besar, umumnya dalam megohm (juta ohm) atau bahkan gigohm (miliar ohm).', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4083, 8, 1, '132080107021', 'Linongeless', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4084, 18, 1, '132080406014', 'Milliohm', 'satuan ukur resistansi elektrik yang setara dengan seribu ohm atau 1/1000 ohm. Simbolnya adalah mΩ (menggunakan huruf "m" kecil diikuti oleh simbol ohm "Ω"). Satuan ini digunakan untuk mengukur resistansi yang sangat rendah, khususnya dalam konteks perangkat listrik, sirkuit elektronik, atau sistem daya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4085, 18, 1, '132080406017', 'Semiconductor Tester', 'perangkat atau alat yang digunakan untuk menguji dan memeriksa kinerja semikonduktor, seperti transistor, diode, IC (Integrated Circuit), dan komponen semikonduktor lainnya. Pengujian semikonduktor sangat penting dalam proses manufaktur, pemeliharaan peralatan elektronik, dan pengembangan sirkuit.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4086, 18, 1, '132080406018', 'Integrater Ciscuit Tester', 'Integrated Circuit Tester adalah perangkat atau sistem yang digunakan untuk menguji dan memverifikasi kinerja sirkuit terpadu (IC) atau chip semikonduktor. IC Tester memastikan bahwa IC berfungsi dengan benar dan sesuai dengan spesifikasi yang ditentukan sebelum dipasarkan atau digunakan dalam suatu aplikasi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4087, 8, 1, '132080107024', 'Hand Extraction', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4088, 18, 1, '132080406019', 'AC Ammeter', 'alat pengukur arus listrik bolak-balik (alternating current). Ammeter sendiri adalah perangkat pengukur arus listrik, dan ketika disebut sebagai "AC Ammeter," itu menunjukkan bahwa alat tersebut dirancang khusus untuk mengukur arus bolak-balik, yang sering disingkat sebagai AC.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4089, 18, 1, '132080406020', 'Tachometer (Measuring/testing Device)', 'alat pengukur kecepatan putar suatu objek, terutama dalam konteks mesin atau peralatan yang melibatkan rotasi, seperti mesin kendaraan, mesin industri, atau motor listrik. Tachometer digunakan untuk mengukur jumlah putaran per menit (RPM) dari poros atau bagian yang berputar dari suatu peralatan. Ini memberikan informasi penting tentang kecepatan operasi dan kinerja suatu sistem mekanik.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4090, 18, 1, '132080406022', 'Power Meter', 'alat pengukur yang digunakan untuk mengukur daya listrik dalam suatu sirkuit. Daya listrik (P) dihitung sebagai produk dari tegangan (V) dan arus (I) yang mengalir melalui sirkuit, dan dapat diukur dengan menggunakan power meter. Umumnya, daya listrik diukur dalam watt (W).', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4091, 18, 1, '132080406024', 'Electrometer (Measuring/testing Device)', 'alat pengukur kecil dan sangat sensitif yang digunakan untuk mengukur muatan listrik atau potensial listrik dalam suatu sistem. Electrometer digunakan dalam berbagai aplikasi di bidang ilmu fisika, kelistrikan, dan penelitian ilmiah untuk mengukur arus listrik yang sangat kecil atau untuk mendeteksi muatan listrik yang sangat kecil pada suatu benda.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4092, 18, 1, '132080406026', 'Curve Tacer', 'alat pengukur atau pemantau yang digunakan untuk menampilkan dan menganalisis karakteristik kurva dari komponen semikonduktor, terutama transistor dan diode. Dengan menggunakan Curve Tracer, pengguna dapat melihat dan memahami bagaimana suatu komponen semikonduktor merespons terhadap variasi tegangan dan arus.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4093, 18, 1, '132080406028', 'Differential Comparator', 'alat pengukur dan perangkat uji yang digunakan untuk membandingkan dua sinyal atau tegangan dan menghasilkan sinyal output yang mencerminkan perbedaan antara keduanya. Fungsi utama Differential Comparator adalah mendeteksi perbedaan tegangan atau sinyal antara dua input dan menghasilkan sinyal output yang sesuai dengan perbedaan tersebut.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4094, 8, 1, '132080107030', 'Centriguge Hemsine Eq.App', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4095, 18, 1, '132080406030', 'Transister Tester', 'alat pengukur atau perangkat uji yang dirancang khusus untuk menguji transistor. Fungsi utamanya adalah untuk memeriksa karakteristik dan parameter dari transistor, seperti jenis transistor, hfe (faktor penguatan), tegangan batas, dan lainnya. Dengan menggunakan Transistor Tester, pengguna dapat mengidentifikasi dan memeriksa kinerja transistor dengan cepat dan mudah.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4096, 18, 1, '132080406031', 'Tube Tester (Measuring/testing Device)', 'Tube Tester atau Valve Tester adalah alat pengukur dan pengujian yang digunakan untuk menguji tabung vakum atau tabung elektronik (valve) yang digunakan dalam perangkat elektronika kuno, seperti radio tabung, penguat audio tabung, dan perangkat elektronik lain yang menggunakan tabung vakum.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4097, 8, 1, '132080107032', 'Stability Mold Ap. 169', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4098, 18, 1, '132080406033', 'DC Calibration Set', 'seperangkat peralatan yang digunakan untuk mengkalibrasi atau memverifikasi peralatan pengukuran DC. Set ini mungkin mencakup sumber tegangan DC yang stabil, resistor kalibrasi, dan perangkat lain yang diperlukan untuk memastikan akurasi dan keandalan pengukuran.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4099, 18, 1, '132080406034', 'AC Calibration Set', 'seperangkat peralatan yang digunakan untuk mengkalibrasi atau memverifikasi peralatan pengukuran AC (Arus Bolak-Balik) agar sesuai dengan standar atau referensi yang diketahui.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4100, 8, 1, '132080107034', 'Swimming Ginding Mils', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4101, 18, 1, '132080406036', 'Component Tester', 'perangkat pengukur dan pengujian yang dirancang untuk mengidentifikasi dan menganalisis berbagai komponen elektronik. Fungsinya melibatkan pengukuran berbagai parameter listrik dan pengujian karakteristik komponen seperti resistor, kapasitor, induktor, dioda, transistor, dan lainnya. Component Tester dirancang untuk menyederhanakan proses pengujian dan identifikasi komponen elektronik dengan cepat dan mudah.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4102, 8, 1, '132080107035', 'Wet Test Analysis', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4103, 18, 1, '132080406037', 'Tranceiver Test Equipment', 'Tranceiver Test Equipment adalah perangkat pengukuran dan pengujian yang dirancang khusus untuk menguji dan memeriksa kinerja transceiver (transmitter-receiver) dalam sistem komunikasi. Transceiver adalah perangkat komunikasi yang memiliki kemampuan untuk mentransmisikan dan menerima sinyal, sering digunakan dalam berbagai aplikasi, seperti radio komunikasi, peralatan telekomunikasi, dan peralatan nirkabel lainnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4104, 8, 1, '132080107036', 'Strohlen Aas For Rafid Determination', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4105, 18, 1, '132080406039', 'Infrared Thermometer', 'Infrared Thermometer, atau sering disebut sebagai termometer infrared atau termometer suhu non-kontak, adalah alat pengukur suhu yang bekerja dengan mengukur radiasi inframerah dari suatu objek. Alat ini dapat mengukur suhu permukaan objek tanpa perlu kontak fisik dengan objek tersebut. Infrared Thermometer umumnya digunakan dalam berbagai aplikasi, termasuk industri, perawatan kesehatan, dan rumah tangga.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4106, 8, 1, '132080107037', 'Poetable Glass Meter', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4107, 18, 1, '132080406042', 'Block Calibration', 'Blok kalibrasi, atau yang juga dikenal sebagai kalibrasi blok gauge, adalah proses menggunakan sekumpulan blok yang dibuat dengan presisi tinggi dan memiliki dimensi yang diketahui untuk memverifikasi ketepatan alat ukur seperti jangka sorong, mikrometer, dan alat ukur panjang lainnya', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4108, 8, 1, '132080107038', 'Sybro/Thermolyne', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4109, 18, 1, '132080406046', 'Phantom Abdomen', 'suatu model atau phantom yang digunakan dalam eksperimen atau pengujian yang melibatkan radiografi atau pemindaian berbasis nuklir pada bagian abdomen atau perut manusia. Phantom adalah benda atau model yang mensimulasikan sifat fisik atau geometri dari objek yang sebenarnya dan sering digunakan untuk kalibrasi atau pengujian peralatan pengukuran.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4110, 8, 1, '132080107039', 'Flash Point Bay Pensky Martens Closed Tester', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4111, 18, 1, '132080406052', 'Test Object Image', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4112, 8, 1, '132080107040', 'Tag Closed Tester', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4113, 18, 1, '132080407001', 'Scanning Electron Microscope(SEM)', 'Scanning Electron Microscope (SEM) adalah sebuah perangkat yang digunakan dalam bidang optoelektronika dan mikroskopi elektron. Meskipun istilah ini tidak secara langsung terkait dengan optoelektronika, SEM memanfaatkan prinsip-prinsip optika elektron untuk menghasilkan gambar resolusi tinggi dari permukaan sampel.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4114, 8, 1, '132080107041', 'Wet Film Trickness Gege Dan Keona Tator Surface Profit', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4115, 18, 1, '132080407002', 'Transmission Electron Microscope (TEM)', 'Transmission Electron Microscope (TEM) adalah suatu alat yang digunakan untuk mengamati struktur dan detail benda sangat kecil, bahkan pada tingkat atom. TEM adalah salah satu jenis mikroskop elektron yang menggunakan berkas elektron untuk membentuk gambar, dan dapat memberikan resolusi yang sangat tinggi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4116, 8, 1, '132080107042', 'Dew Point Calculator', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4117, 18, 1, '132080407003', 'Scanning Transmission Electron Microscope(STEM)', 'Scanning Transmission Electron Microscope (STEM) adalah jenis mikroskop elektron yang menggabungkan prinsip-prinsip mikroskop transmisi elektron (TEM) dan pemindaian elektron. Berbeda dengan TEM yang fokus pada mendapatkan gambar transmisi dari sampel tipis, STEM memungkinkan pemindaian permukaan sampel menggunakan berkas elektron.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4118, 8, 1, '132080107043', 'Surface Steel Temperature', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4119, 18, 1, '132080407008', 'Laser CO2', 'Laser CO2 adalah jenis laser yang menggunakan gas karbon dioksida (CO2) sebagai medium aktif untuk menghasilkan cahaya laser. Laser CO2 memiliki sejumlah karakteristik khusus yang membuatnya berguna dalam berbagai aplikasi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4120, 8, 1, '132080107044', 'Flaw Cup', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4121, 18, 1, '132080407012', 'Piranti Optik', 'Piranti optik adalah alat yang menggunakan prinsip-prinsip optika untuk menghasilkan, memfokuskan, atau memproyeksikan cahaya. Piranti optik dapat dikelompokkan menjadi dua kategori utama, yaitu alat optik alami dan alat optik buatan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4122, 8, 1, '132080107045', 'Dip Viscosity Cup', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4123, 18, 1, '132080408003', 'Linear Accelerator', 'Linear Accelerator (linac) adalah jenis akselerator partikel yang menggunakan medan listrik bertahap untuk mempercepat partikel bermuatan, seperti elektron atau proton, sepanjang lintasan lurus atau linear. Linear Accelerator sering digunakan dalam penelitian fisika partikel, pengobatan kanker radiasi, dan aplikasi teknologi lainnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4124, 8, 1, '132080107046', 'Grindometer', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4125, 18, 1, '132080408007', 'Van Dan Graof Generator', 'Van de Graaff Generator adalah suatu perangkat yang digunakan untuk menghasilkan tegangan listrik tinggi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4126, 18, 1, '132080408009', 'Pneumatic Transfer', 'sistem transfer atau transportasi yang menggunakan udara bertekanan atau gas bertekanan untuk menggerakkan atau memindahkan bahan dari satu tempat ke tempat lain.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4127, 18, 1, '132080409002', 'In-Pile Loop', 'fasilitas eksperimental yang terletak di dalam inti (core) reaktor nuklir. Loop ini didesain untuk melakukan eksperimen dan penelitian terkait bahan bakar nuklir, material, dan komponen lainnya di bawah kondisi lingkungan yang mendekati kondisi di dalam inti reaktor', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4128, 8, 1, '132080107049', 'Demulsibility Chracter Labricating Oils', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4129, 18, 1, '132080409005', 'Neutron Deffraction System', 'Difraksi neutron atau hamburan neutron elastis adalah penerapan hamburan neutron untuk menentukan struktur atom dan/atau magnet suatu material. Sampel yang akan diperiksa ditempatkan pada berkas neutron termal atau dingin untuk memperoleh pola difraksi yang memberikan informasi tentang struktur material', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4130, 8, 1, '132080107050', 'Dase Rate Measuring Device Graets', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4131, 18, 1, '132080409006', 'In Bean (Fast) Neutron Analysis System', 'In-Beam Neutron Analysis System merujuk pada sistem atau fasilitas yang digunakan untuk melakukan analisis neutron cepat pada suatu bahan atau target selama terpapar radiasi neutron cepat, yang dihasilkan oleh fasilitas penelitian nuklir seperti reaktor nuklir atau akselerator partikel.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4132, 8, 1, '132080107051', 'Bendix Personal Monitoring', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4133, 18, 1, '132080409010', 'Pneumatic Transfer System', 'sistem transfer atau transportasi yang menggunakan udara bertekanan (pneumatik) untuk memindahkan bahan dari satu lokasi ke lokasi lain. Sistem ini umumnya melibatkan penggunaan udara bertekanan untuk menghasilkan gaya atau aliran yang dapat membawa partikel atau material melalui pipa atau saluran udara.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4134, 18, 1, '132080409011', 'Digital Cerenkov Viewing Device', 'perangkat pengamatan Cerenkov dapat digunakan untuk mendeteksi atau mengukur radiasi Cerenkov yang dihasilkan oleh partikel bermuatan yang bergerak dengan kecepatan tinggi. Penggunaan kata "Digital" mungkin menunjukkan bahwa perangkat ini memiliki kemampuan untuk merekam dan memproses data secara digital.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4135, 8, 1, '132080108001', 'Unconfinet Soil Test', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4136, 19, 1, '132080410004', 'Low Background Chamber (Pb)', 'Low Background Chamber (Pb) adalah suatu jenis ruangan atau kamar yang dirancang khusus untuk melakukan eksperimen atau pengukuran dengan tingkat latar belakang radiasi yang sangat rendah. Ruang ini sering kali dibuat dari bahan pemadam radiasi seperti timbal (Pb) untuk meminimalkan paparan radiasi latar belakang dari sumber-sumber eksternal.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4137, 20, 1, '132080501001', 'Hand Monitor', 'suatu alat ukur yang digunakan untuk memonitor tingkat paparan radiasi pada tangan atau lengan seseorang yang bekerja di lingkungan di mana terdapat paparan radiasi. Alat ini dapat digunakan oleh pekerja di bidang kesehatan, laboratorium radiologi, atau industri nuklir di mana risiko paparan radiasi mungkin ada.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4138, 8, 1, '132080108003', 'Linear Shikage', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4139, 20, 1, '132080501003', 'B.Y. Whole Body Monitor', 'jenis alat pengukur atau monitor tubuh keseluruhan yang spesifik untuk pengukuran dosis radiasi pada tubuh manusia.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4140, 8, 1, '132080108004', 'Barntand & Termometer', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4141, 20, 1, '132080501005', 'Xenon Area Monitor', 'Xenon Area Monitor adalah suatu perangkat atau sistem yang digunakan untuk memonitor tingkat keberadaan atau konsentrasi xenon di suatu area tertentu. Xenon adalah gas mulia yang dapat digunakan dalam berbagai aplikasi, termasuk di bidang kedokteran nuklir dan industri nuklir.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4142, 20, 1, '132080501007', 'Pocket Dosimeter (For X,Y, Thermain)', 'Pocket Dosimeter adalah alat ukur radiasi yang dirancang untuk digunakan oleh individu, terutama mereka yang bekerja di lingkungan di mana paparan radiasi mungkin terjadi. Pocket Dosimeter biasanya dirancang agar mudah dibawa dan ditempatkan di saku pakaian atau dipasang pada pakaian kerja. Alat ini membantu dalam memantau dosis radiasi yang diterima oleh individu selama periode waktu tertentu.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4143, 8, 1, '132080108006', 'Exstoder/Extruder', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4144, 20, 1, '132080501018', 'Isotop Calibrator', 'Isotope Calibrator adalah alat ukur yang digunakan untuk mengkalibrasi atau menyesuaikan peralatan yang digunakan dalam pengukuran aktivitas isotop radioaktif, khususnya dalam konteks kedokteran nuklir. Alat ini memastikan bahwa instrumen yang digunakan untuk mengukur aktivitas isotop radioaktif pada pasien atau dalam proses diagnostik atau terapeutik memiliki akurasi dan presisi yang tinggi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4145, 8, 1, '132080108007', 'Unconfined Air & Manometer', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4146, 20, 1, '132080501020', 'Gate/Protal Monitor', 'Gate/Portal Monitor adalah perangkat atau sistem yang digunakan untuk memantau tingkat radiasi pada orang atau benda yang masuk atau keluar dari suatu area tertentu, seperti pintu gerbang atau portal. Tujuan utama dari alat ini adalah untuk memastikan bahwa objek atau individu tersebut tidak membawa atau terpapar radiasi di atas batas keamanan yang ditetapkan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4147, 20, 1, '132080501023', 'Total Body Monitor', 'Total Body Monitor adalah perangkat atau sistem yang digunakan untuk mengukur atau memantau distribusi dan retensi bahan radioaktif di seluruh tubuh seseorang. Tujuan utama dari alat ini adalah untuk mengukur dosis radiasi total yang diterima oleh tubuh, terutama dalam konteks pemberian terapi radioaktif atau dalam penelitian ilmu kesehatan yang melibatkan penggunaan bahan radioaktif.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4148, 8, 1, '132080108009', 'Triaxal CBR', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4149, 20, 1, '132080502003', 'Lead Waster Container', 'wadah atau kontainer yang dirancang khusus untuk mengelola dan menyimpan limbah yang mengandung timbal (lead), terutama limbah yang dihasilkan dalam lingkungan pekerjaan atau industri tertentu.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4150, 20, 1, '132080502005', 'Lead Aperon', 'pelindung yang umumnya digunakan oleh tenaga medis atau radiografer selama prosedur pencitraan medis yang melibatkan radiasi ionisasi, seperti sinar-X atau CT scan. Pelindung ini terbuat dari bahan yang mengandung timbal dan dirancang untuk mengurangi paparan radiasi bagi tenaga kesehatan yang berada di sekitar pasien selama prosedur tersebut.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4151, 8, 1, '132080108011', 'Swell Pressure App', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4152, 20, 1, '132080502008', 'Mini Monitor', 'perangkat kecil atau alat yang digunakan untuk memantau parameter kesehatan atau kondisi fisik tertentu. Contohnya termasuk mini monitor detak jantung, mini monitor tekanan darah, atau alat pemantauan lainnya yang portabel dan mudah digunakan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4153, 8, 1, '132080108012', 'Dial Propping Ring', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4154, 20, 1, '132080502011', 'Master Slave', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4155, 20, 1, '132080502012', 'Electronic Robot', 'Robot elektronik dapat digunakan untuk pemantauan keselamatan kerja di lingkungan industri. Mereka dapat memonitor kondisi lingkungan kerja, mendeteksi bahaya, atau bahkan berinteraksi dengan pekerja untuk memberikan informasi atau bantuan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4156, 8, 1, '132080108014', 'Dispersion Cups', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4157, 20, 1, '132080502019', 'Countaiment Boxes (Single C)', 'kotak penyimpanan kedap yang digunakan untuk menyimpan bahan berbahaya, seperti bahan kimia, radioaktif, atau biologis. Kotak ini biasanya terbuat dari bahan yang kuat dan tahan lama, seperti baja atau plastik. Kotak ini juga memiliki fitur-fitur keamanan, seperti kunci dan gasket, untuk mencegah bahan berbahaya keluar dari kotak.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4158, 20, 1, '132080502020', 'Countaiment Boxes (Double C)', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4159, 8, 1, '132080108016', 'Proctor Modified', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4160, 20, 1, '132080502024', 'Transfer Bucket 4', 'Transfer Bucket 4 adalah perangkat keselamatan kerja yang digunakan untuk memindahkan limbah dan bahan berbahaya dari satu wadah ke wadah lain dengan aman. Perangkat ini terdiri dari dua ember, satu ember untuk limbah dan satu ember untuk bahan bersih. Ember limbah memiliki tutup yang rapat untuk mencegah tumpahan, dan ember bersih memiliki penahan yang mencegah bahan bersih bercampur dengan limbah.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4161, 8, 1, '132080108017', 'Wash Bottle Purex', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4162, 20, 1, '132080502027', 'Intercell Conveyor System CE', 'sistem mekanis yang digunakan untuk mentranspor barang atau bahan dari satu lokasi ke lokasi lain dalam suatu fasilitas atau pabrik. Sistem konveyor dapat terdiri dari berbagai jenis konveyor, seperti konveyor bergerak, rantai, atau sabuk.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4163, 20, 1, '132080502028', 'Top Barier Lead Shield', 'Top Barier Lead Shield adalah perangkat keselamatan kerja yang umumnya terbuat dari timbal (lead) dan digunakan sebagai penghalang utama untuk melindungi pekerja dari paparan radiasi ionisasi. Alat ini sering digunakan dalam lingkungan medis, seperti ruang radiologi atau laboratorium di mana prosedur-prosedur radiologis dilakukan, untuk meminimalkan risiko paparan radiasi pada pekerja kesehatan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4164, 8, 1, '132080108019', 'Walton Humidifier', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4165, 20, 1, '132080503002', 'Sound Monitor/ Sirine', 'Sound Monitor atau Sirine adalah perangkat yang digunakan untuk memonitor atau memberikan peringatan terkait tingkat kebisingan di lingkungan. Ini membantu dalam melindungi lingkungan dengan mendeteksi dan memberikan peringatan jika ada tingkat kebisingan yang melebihi ambang batas yang ditetapkan untuk menjaga kesehatan manusia dan lingkungan sekitarnya. Perangkat ini sering digunakan di area industri, perkotaan, atau tempat-tempat di mana kontrol kebisingan penting untuk menjaga keseimbangan lingkungan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4166, 20, 1, '132080503004', 'Unit Siementasi', 'Tangki sedimentasi: Tangki sedimentasi adalah jenis unit sedimentasi yang paling umum. Tangki ini memiliki bagian bawah yang datar, sehingga partikel-partikel dapat mengendap di bagian bawah tanki.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4167, 20, 1, '132080504001', 'Barometer (Meteorological Equipment)', 'Barometer adalah perangkat meteorologi yang digunakan untuk mengukur tekanan atmosfer di suatu lokasi pada suatu waktu tertentu. Ini memberikan informasi penting tentang perubahan cuaca.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4168, 20, 1, '132080504005', 'Thermo- Hygrograph', 'Thermo-Hygrograph adalah perangkat meteorologi yang dirancang untuk mencatat suhu dan kelembaban udara secara terus-menerus selama periode waktu tertentu. Perangkat ini biasanya digunakan untuk memantau variasi harian atau periode waktu tertentu dalam suhu dan kelembaban, memberikan data yang penting untuk analisis cuaca dan pemahaman iklim di suatu lokasi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4169, 20, 1, '132080504009', 'Rainfall Sensor', 'Rainfall Sensor adalah perangkat meteorologi yang dirancang untuk mendeteksi dan mengukur jumlah curah hujan di suatu lokasi. Perangkat ini menggunakan berbagai teknologi, seperti kantong karet atau sensor optik, untuk menghitung volume air yang jatuh ke permukaan sensor. Data yang dihasilkan oleh Rainfall Sensor dapat memberikan informasi yang penting untuk memahami pola curah hujan, memonitor musim kemarau atau musim hujan, dan mendukung pemantauan iklim dan analisis cuaca. Perangkat ini umumnya digunakan di stasiun meteorologi, sistem irigasi, dan aplikasi lain yang membutuhkan pemantauan curah hujan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4170, 20, 1, '132080504011', 'Wind Sensor Set', 'Wind Sensor Set adalah kelompok perangkat meteorologi yang dirancang untuk mengukur dan merekam kecepatan serta arah angin di suatu lokasi. Set ini biasanya terdiri dari dua komponen utama: anemometer untuk mengukur kecepatan angin dan wind vane atau windsock untuk mengukur arah angin. Data yang dihasilkan oleh Wind Sensor Set membantu dalam memahami pola angin, yang penting untuk analisis cuaca, navigasi penerbangan, dan pemantauan lingkungan. Sensor angin ini dapat digunakan di berbagai aplikasi, termasuk stasiun meteorologi, bandara, dan instalasi industri.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4171, 8, 1, '132080108025', 'Gravity Oven', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4172, 20, 1, '132080504013', 'Temperature Sensor Set', 'Temperature Sensor Set adalah seperangkat peralatan meteorologi yang dirancang khusus untuk mengukur suhu di lingkungan tertentu. Ini mungkin terdiri dari sensor suhu yang sensitif, perekam data, dan perangkat lainnya yang diperlukan untuk mengumpulkan informasi akurat tentang suhu udara atau suhu permukaan. Penggunaan set ini dapat membantu dalam pemantauan kondisi cuaca dan perubahan iklim.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4173, 20, 1, '132080504014', 'Electric', 'Meteorological equipment yang menggunakan tenaga listrik atau Electric Meteorological Equipment melibatkan berbagai perangkat yang digunakan untuk mengukur dan merekam parameter cuaca, dan perangkat ini dioperasikan dengan menggunakan tenaga listrik. Beberapa contoh perangkat meteorologis listrik melibatkan sensor-sensor dan instrumen-instrumen yang membantu dalam pengumpulan data cuaca.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4174, 20, 1, '132080504021', 'Seismeter Sensor', 'Seismeter Sensor adalah perangkat meteorologi yang dirancang khusus untuk mendeteksi dan mengukur gempa bumi atau getaran tanah. Sensor ini sensitif terhadap perubahan kecepatan atau percepatan gerakan tanah yang dihasilkan oleh gempa bumi atau aktivitas seismik lainnya. Data yang diperoleh dari seismeter membantu ilmuwan dan peneliti memahami pola seismik, memonitor aktivitas tektonik, dan meningkatkan pemahaman tentang gempa bumi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4175, 20, 1, '132080504022', 'Seismograph Recorder', 'Seismograph Recorder adalah perangkat meteorologi yang digunakan untuk merekam dan mereproduksi data seismik. Ini mencatat gerakan tanah yang dihasilkan oleh gempa bumi atau aktivitas seismik lainnya dalam bentuk grafik atau rekaman digital. Seismograf membantu dalam menganalisis intensitas, durasi, dan sifat gelombang gempa bumi, yang penting untuk pemahaman risiko gempa dan penelitian geofisika.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4176, 20, 1, '132080504029', 'Aviation Metereologi Observasing System', 'Aviation Meteorological Observing System (AMOS) adalah jaringan peralatan dan prosedur yang digunakan untuk mengumpulkan dan menyebarkan data cuaca yang penting bagi keselamatan dan efisiensi penerbangan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4177, 20, 1, '132080505001', 'Standar AM-2411', 'Standar AM-2411 adalah standar internasional yang menetapkan persyaratan keselamatan untuk sumber radiasi. Standar ini diterbitkan oleh American Society for Nondestructive Testing (ASNT) dan diakui secara luas oleh industri NDT.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4178, 21, 1, '132080601001', 'Gamma Camera', 'Gamma Camera adalah peralatan yang digunakan dalam bidang kedokteran nuklir untuk mendeteksi dan menciptakan gambar dari radiasi gamma yang dipancarkan oleh bahan radioaktif di dalam tubuh pasien. Peralatan ini membantu dokter dalam mendiagnosis dan memantau kondisi medis dengan melihat distribusi radiofarmaka dalam organ atau jaringan. Gamma Camera digunakan dalam pemeriksaan seperti scintigraphy atau scintimammography, membantu visualisasi fungsi organ dan struktur anatomi dengan tingkat detail yang tinggi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4179, 21, 1, '132080601002', 'X-Ray Machine & Control', 'X-Ray Machine & Control adalah peralatan aplikasi radiasi yang digunakan untuk menghasilkan sinar-X dalam berbagai konteks medis dan diagnostik. Ini terdiri dari mesin X-ray yang menghasilkan sinar-X dan sistem kontrol yang memungkinkan pengaturan dan pemantauan proses radiografi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4180, 21, 1, '132080601003', 'Device (Radiation Application Equipment)', 'Device (Radiation Application Equipment) adalah perangkat yang digunakan untuk menerapkan radiasi dalam berbagai konteks, termasuk di bidang medis, industri, dan penelitian. Contoh perangkat ini meliputi mesin sinar-X, alat terapi radiasi dalam pengobatan kanker, dan perangkat deteksi radiasi. Penggunaan peralatan ini harus diawasi dengan ketat untuk memastikan keamanan dan kepatuhan dengan pedoman radiasi yang berlaku.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4181, 21, 1, '132080601004', 'X-Ray Penetration', 'X-Ray Penetration mengacu pada kemampuan sinar-X untuk menembus atau melewati benda atau jaringan. Semakin tinggi tingkat penetrasi sinar-X, semakin mudah sinar-X dapat menembus materi dan mencapai detektor atau permukaan belakang objek tersebut. Ini adalah sifat penting dari sinar-X dalam konteks penggunaan di bidang medis, keamanan, dan industri.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4182, 8, 1, '132080108035', 'C E N C', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4183, 21, 1, '132080602002', 'Portable Testing Magnet', 'Portable Testing Magnet adalah perangkat uji non-destruktif (NDT) yang digunakan untuk mendeteksi cacat atau ketidaksempurnaan dalam material logam, khususnya pada logam ferromagnetik seperti besi dan baja. Perangkat ini menggunakan prinsip dasar magnetisme untuk mengidentifikasi anomali dalam struktur logam.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4184, 8, 1, '132080108036', 'Cenc Meinzer Sieve Shaker', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4185, 21, 1, '132080602005', 'Accustic Emmisim Device', 'Acoustic Emission (AE) Device, atau yang dikenal sebagai Acoustic Emission Testing (AET), adalah perangkat uji non-destruktif (NDT) yang digunakan untuk mendeteksi dan menganalisis gelombang bunyi atau gelombang akustik yang dihasilkan oleh material saat mengalami deformasi atau perubahan struktural.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4186, 21, 1, '132080602011', 'Hydraulic Ester', 'Hydraulic Ester (HE) adalah metode NDT yang menggunakan cairan bertekanan tinggi untuk mendeteksi cacat internal dalam material. Cairan bertekanan tinggi ini biasanya berupa oli atau air, dan dialirkan melalui jaringan pipa dan tabung yang ditempatkan pada permukaan material yang diuji.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4187, 8, 1, '132080108038', 'Auger Machine', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4188, 21, 1, '132080602014', 'Alat Uji Taktik', 'Alat Uji Taktik pada NON DESTRUCTIVE TEST (NDT) DEVICE adalah alat atau sistem yang digunakan untuk meningkatkan akurasi dan efisiensi pengujian', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4189, 8, 1, '132080108039', 'Visibility Jarbath', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4190, 21, 1, '132080602015', 'Bending Tester (Non Destructive Test (ndt) Device)', 'Bending Tester dalam konteks Non-Destructive Testing (NDT) adalah perangkat yang digunakan untuk melakukan pengujian lentur atau bending pada suatu material tanpa menyebabkan kerusakan permanen. Pengujian ini membantu mengidentifikasi kekuatan dan elastisitas material serta dapat mendeteksi potensi retak atau cacat.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4191, 21, 1, '132080602016', 'Surface Rounghnes Measuring Device', 'Surface Roughness Measuring Device adalah perangkat yang digunakan untuk mengukur ketidakhalusan permukaan suatu benda tanpa merusak materialnya. Perangkat ini umumnya menggunakan berbagai metode, seperti sentuhan mekanis atau sensor optik, untuk menilai tekstur dan profil permukaan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4192, 8, 1, '132080108041', 'Matrial (Warna Kuning)', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4193, 21, 1, '132080602018', 'High Resolution Pressure Difractometer', 'High Resolution Pressure Diffractometer adalah perangkat uji non-destruktif (NDT) yang digunakan untuk menganalisis struktur kristal material dengan memanfaatkan difraksi sinar-X atau neutron pada kondisi tekanan tinggi. Perangkat ini memungkinkan penelitian terhadap perubahan struktural pada tingkat atomik yang terjadi ketika suatu material dikenakan tekanan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4194, 8, 1, '132080108042', 'Deluxe Asphalt', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4195, 21, 1, '132080603004', 'Electromagnetic Prospecting Device', 'Electromagnetic Prospecting Device dalam konteks peralatan hidrologi digunakan untuk studi dan pemetaan sumber daya air bawah tanah dengan memanfaatkan prinsip elektromagnetik. Perangkat ini bekerja dengan mengirimkan sinyal elektromagnetik ke dalam tanah dan mendeteksi respons medan elektromagnetik yang diproduksi oleh material di bawah permukaan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4196, 21, 1, '132080603009', 'Falling Cone Panatro Meter', 'Falling Cone Panatro Meter adalah alat yang digunakan untuk mengukur kekuatan penetrasi tanah. Alat ini terdiri dari sebuah kerucut baja yang dijatuhkan dari ketinggian tertentu ke dalam tanah. Kecepatan penetrasi kerucut diukur menggunakan sensor, dan data ini kemudian digunakan untuk menghitung kekuatan penetrasi tanah.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4197, 21, 1, '132080603014', 'Soil PH Meter', 'Soil pH Meter adalah peralatan hidrologi yang digunakan untuk mengukur tingkat keasaman atau kebasaan tanah. Alat ini membantu dalam menentukan nilai pH tanah, yang mempengaruhi ketersediaan nutrisi bagi tanaman dan pertumbuhan tanaman secara keseluruhan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4198, 8, 1, '132080108045', 'Harvard Tripple Balance', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4199, 21, 1, '132080603017', 'Optical Clinometer', 'Optical Clinometer adalah peralatan hidrologi yang digunakan untuk mengukur kemiringan atau sudut lereng dari suatu bidang atau lereng. Peralatan ini menggunakan prinsip optik untuk mengukur sudut kemiringan dengan tingkat presisi yang tinggi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4200, 21, 1, '132080603020', 'Theodolite (Peralatan Hidrologi)', 'Theodolite adalah peralatan hidrologi yang digunakan untuk mengukur sudut horizontal dan vertikal dengan tingkat presisi tinggi. Peralatan ini terdiri dari teleskop yang dipasang di atas instrumen yang dapat diputar di sekitar dua sumbu yang saling tegak lurus: sumbu horizontal (azimuth) dan sumbu vertikal (elevasi). Theodolite sering digunakan dalam survei, konstruksi, dan penelitian geografis, termasuk dalam konteks pekerjaan hidrologi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4201, 8, 1, '132080108047', 'Stability Mold', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4202, 21, 1, '132080603021', 'Water Pass', 'pengukuran tingkat air, mungkin Anda merujuk pada alat pengukur tingkat air permukaan air, seperti Water Level Meter.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4203, 8, 1, '132080108048', 'Versa Tester', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4204, 21, 1, '132080603022', 'Geological Compas', 'sebuah kompas yang dirancang khusus untuk digunakan dalam pekerjaan geologi. Geological Compass memiliki fitur khusus yang memungkinkan ahli geologi atau peneliti untuk mengukur orientasi, kemiringan, dan struktur geologis di lapangan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4205, 21, 1, '132080603023', 'Tripod Compas', 'Tripod kompas adalah alat yang digunakan dalam survei hidrologi untuk menentukan arah dan ketinggian. Alat ini terdiri dari tiga kaki yang dapat diatur untuk menopang kompas. Kompas adalah alat yang digunakan untuk menentukan arah.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4206, 21, 1, '132080603030', 'Geological Hammer', 'Geological Hammer, juga dikenal sebagai rock hammer atau geologist\'s hammer, adalah peralatan penting dalam pekerjaan lapangan geologi dan hidrologi. Alat ini dirancang khusus untuk memungkinkan geolog atau ahli hidrologi memeriksa dan memahami karakteristik batuan di lapangan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4207, 8, 1, '132080108051', 'Mechanical Leading Press', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4208, 21, 1, '132080603031', 'Scoop', 'Scoop dalam konteks peralatan hidrologi biasanya merujuk pada sekop atau alat penggali yang digunakan untuk mengambil contoh tanah, pasir, atau material sedimen dari sungai, danau, atau lokasi lainnya yang terkait dengan penelitian hidrologi. Scoop dapat memiliki berbagai bentuk dan ukuran tergantung pada kebutuhan pengguna dan jenis pekerjaan lapangan yang dilakukan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4209, 8, 1, '132080108052', 'Unci Fined Apparatus', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4210, 22, 1, '132080701001', 'DO Meter (Alat Laboratorium Kwalitas Air Dan Tanah)', 'alat yang digunakan di laboratorium untuk mengukur kadar oksigen terlarut (DO) dalam air. Kadar oksigen terlarut adalah jumlah oksigen yang larut dalam air. Penentuan kadar oksigen terlarut merupakan salah satu parameter penting dalam mengevaluasi kualitas air. Penggunaan DO Meter sangat penting dalam pengelolaan sumber daya air, budidaya perikanan, pengelolaan lingkungan, dan bidang-bidang lain yang terkait dengan kualitas air dan tanah.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4211, 22, 1, '132080701002', 'Conductivity Meter (Alat Laboratorium Kwalitas Air Dan Tanah)', 'alat yang digunakan untuk mengukur konduktivitas listrik dalam suatu larutan. Alat ini umumnya digunakan di laboratorium untuk mengukur konduktivitas air dan larutan tanah. Selain itu kemampuan suatu larutan untuk menghantarkan arus listrik. Dalam konteks kualitas air dan tanah, pengukuran konduktivitas seringkali berkaitan dengan kandungan garam, mineral, dan zat terlarut lainnya dalam larutan. Penggunaan alat ini membantu dalam pemantauan dan penilaian kualitas air, pengelolaan sumber daya alam seperti air dan tanah, serta berbagai aplikasi industri yang memerlukan pemahaman akan konduktivitas larutan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4212, 22, 1, '132080701003', 'Salino Meter', 'alat yang digunakan untuk mengukur tingkat salinitas dalam suatu larutan, khususnya dalam konteks pengukuran salinitas air.Salinitas adalah ukuran dari konsentrasi garam dalam air atau larutan. Alat ini sangat penting dalam bidang kelautan, akuakultur, dan penelitian lingkungan. Salinity Meter umumnya memberikan hasil pengukuran dalam satuan psu (practical salinity units) atau ppt (parts per thousand), yang mengukur jumlah garam per seribu bagian air.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4213, 8, 1, '132080108055', 'Field Scale', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4214, 22, 1, '132080701004', 'TOC Analyzer', 'alat laboratorium yang digunakan untuk mengukur jumlah karbon organik total dalam suatu sampel air atau larutan. Karbon organik ini bisa berasal dari berbagai sumber, termasuk senyawa-senyawa organik yang larut dalam air. Cara kerja TOC Analyzer melibatkan pembakaran atau oksidasi sampel organik menjadi karbon dioksida (CO2) yang kemudian diukur atau dihitung sebagai konsentrasi karbon organik total. Terdapat beberapa metode yang digunakan dalam TOC Analyzer, seperti pembakaran termal atau oksidasi katalitik, namun prinsip umumnya adalah untuk mengubah karbon organik menjadi CO2 dan mengukurnya sebagai indikator konsentrasi karbon organik. Penggunaan TOC Analyzer memberikan informasi penting terkait dengan kebersihan dan kesehatan lingkungan, kualitas air, serta efektivitas proses pemurnian air. Ini merupakan alat yang penting dalam pemantauan dan pengelolaan sumber daya air serta perlindungan lingkungan hidup.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4215, 22, 1, '132080701005', 'Oil Analyzer', 'sebuah alat atau sistem yang digunakan untuk menganalisis kualitas dan kondisi minyak, terutama dalam konteks industri, mesin, atau kendaraan. Tujuannya adalah untuk memonitor dan mengevaluasi kesehatan minyak dengan cara mendeteksi kontaminasi, adanya partikel, perubahan suhu, keausan, oksidasi, dan komponen lain yang dapat mempengaruhi kinerja minyak dalam penggunaannya. sering digunakan dalam industri permesinan, pabrik, kendaraan bermotor, pesawat, dan sektor-sektor lainnya di mana minyak berperan penting dalam menjaga kinerja mesin atau peralatan. Oil Analyzer dapat membantu dalam menjaga performa optimal, mencegah kerusakan pada mesin, menurunkan biaya perawatan, dan memperpanjang umur pakai minyak dan mesin itu sendiri dengan memungkinkan deteksi dini terhadap perubahan atau masalah pada minyak yang digunakan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4216, 22, 1, '132080701006', 'Klorin Meter', 'alat atau perangkat yang digunakan untuk mengukur konsentrasi klorin dalam air atau larutan. Klorin merupakan zat kimia yang sering digunakan sebagai desinfektan untuk membunuh mikroorganisme yang ada dalam air, seperti bakteri, virus, dan parasit, untuk membuat air aman untuk dikonsumsi atau digunakan dalam berbagai aplikasi industri.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4217, 8, 1, '132080108058', 'Asphalt Density Recorder', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4218, 22, 1, '132080701007', 'Water Quality Analyzer System', 'alat yang digunakan untuk mengukur, memantau, dan menganalisis berbagai parameter kualitas air secara terus-menerus atau berkala. Sistem ini terdiri dari serangkaian instrumen, sensor, perangkat lunak, dan perangkat keras lainnya yang bekerja bersama untuk mengevaluasi kondisi air.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4219, 22, 1, '132080701008', 'Mercury Analyzer (Alat Laboratorium Kwalitas Air Dan Tanah)', 'perangkat laboratorium yang digunakan untuk mengukur konsentrasi merkuri dalam sampel air atau tanah. penggunaan dan penanganan alat ini harus dilakukan dengan hati-hati karena merkuri memiliki efek berbahaya terhadap kesehatan manusia dan lingkungan. Pemakaian alat semacam ini harus mengikuti prosedur keselamatan yang ketat untuk mencegah paparan merkuri kepada operator maupun lingkungan sekitarnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4220, 22, 1, '132080701009', 'Test Kit', 'perangkat atau paket yang berisi alat-alat sederhana yang digunakan untuk melakukan uji atau tes tertentu di lapangan atau di rumah tanpa memerlukan peralatan laboratorium yang canggih atau keahlian khusus.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4221, 8, 1, '132080108061', 'Hydrometer Jarbath', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4222, 22, 1, '132080701011', 'Plankton Net (Alat Laboratorium Kwalitas Air Dan Tanah)', 'perangkat laboratorium yang digunakan untuk mengumpulkan dan memisahkan organisme plankton dari air laut atau air tawar. Alat ini biasanya digunakan dalam studi ekologi perairan dan ilmu kelautan untuk mengidentifikasi dan menganalisis komunitas plankton', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4223, 22, 1, '132080701014', 'Core Sampler', 'pengambil inti, adalah alat yang digunakan untuk mengambil inti atau sampel dari benda padat seperti tanah, es, batuan, atau sedimentasi laut. Pengambilan inti ini memungkinkan peneliti untuk memeriksa sejarah geologis dan lingkungan, menganalisis komposisi, dan mendapatkan pemahaman yang lebih baik tentang formasi dan proses yang terjadi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4224, 8, 1, '132080109001', 'Test For Hunmudity', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4225, 22, 1, '132080701015', 'Current Meter (Alat Laboratorium Kwalitas Air Dan Tanah)', 'alat atau perangkat yang digunakan untuk mengukur kecepatan dan arah aliran air di dalam sungai, laut, dan perairan lainnya. Alat ini memungkinkan para ilmuwan, ahli oseanografi, hidrologi, dan insinyur yang terlibat dalam studi dan proyek terkait air untuk mengukur dan memahami pola pergerakan air.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4226, 22, 1, '132080701016', 'Jar Tester', 'alat laboratorium yang digunakan dalam proses pengujian untuk mengidentifikasi dan mengoptimalkan dosis bahan kimia yang digunakan dalam pengolahan air, khususnya dalam tahap koagulasi dan flokulasi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4227, 8, 1, '132080109003', 'Test For Wind/Flow', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4228, 22, 1, '132080701019', 'Autoclay', 'sebuah perangkat yang digunakan untuk melakukan sterilisasi peralatan dan bahan dengan menggunakan uap air bertekanan tinggi. Alat ini umumnya digunakan dalam berbagai bidang seperti kedokteran, laboratorium, dan industri untuk menghilangkan bakteri, virus, fungi, dan kontaminan lainnya yang dapat menyebabkan infeksi atau merusak keandalan bahan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4229, 8, 1, '132080109004', 'Test For Pressure', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4230, 22, 1, '132080701021', 'COD Reaktor', 'perangkat yang digunakan dalam analisis kimia untuk mengukur jumlah zat-zat organik dan bahan-bahan kimia yang dapat dioksidasi dalam suatu sampel air. Metode COD digunakan untuk menentukan seberapa banyak bahan organik yang ada dalam sampel tersebut dengan cara mengukur jumlah oksigen yang dibutuhkan untuk mengoksidasi bahan-bahan tersebut secara kimia.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4231, 8, 1, '132080109005', 'Test Presipitation', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4232, 22, 1, '132080702001', 'Portable SO2 Analyzer', 'alat yang digunakan untuk mengukur konsentrasi sulfur dioksida dalam sebuah sampel gas. SO2 adalah gas yang umumnya dihasilkan dari berbagai proses industri, terutama dari pembakaran bahan bakar fosil yang mengandung belerang, seperti batu bara dan minyak bumi. Gas ini juga bisa berasal dari aktivitas vulkanik dan beberapa proses alami lainnya', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4233, 8, 1, '132080109006', 'Test Evaporation', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4234, 22, 1, '132080702003', 'Portable CO Analyzer', 'alat portabel yang digunakan untuk mendeteksi dan mengukur kadar karbon monoksida dalam udara di sekitar kita. Karbon monoksida adalah gas beracun yang tidak berwarna, tidak berbau, dan tidak berasa yang dapat membahayakan kesehatan manusia jika terhirup dalam jumlah yang tinggi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4235, 8, 1, '132080109007', 'Test Sunshine', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4236, 22, 1, '132080702004', 'Portable HC Analyzer', 'alat yang digunakan untuk mengukur konsentrasi hidrokarbon dalam sebuah sampel gas. Analisis hidrokarbon sering kali penting dalam berbagai industri, termasuk industri minyak dan gas, lingkungan, otomotif, dan manufaktur, karena hidrokarbon merupakan komponen utama dalam gas buang kendaraan bermotor dan proses-produksi industri.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4237, 22, 1, '132080702005', 'Container', 'ruang yang dibuat khusus untuk pengembangan, pengujian, dan eksperimen dengan teknologi kontainer. Kontainer dalam konteks ini mengacu pada teknologi kontainerisasi, seperti yang digunakan dalam platform seperti Docker atau Kubernetes.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4238, 22, 1, '132080702006', 'Data Logger (Alat Laboratorium Kwalitas Udara)', 'perangkat yang digunakan untuk memantau dan merekam parameter-parameter tertentu yang berkaitan dengan kualitas udara di suatu lokasi. Data logger ini umumnya digunakan di laboratorium atau lingkungan eksternal untuk mengukur berbagai faktor yang mempengaruhi kualitas udara.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4239, 22, 1, '132080702007', 'Automatic SO2 Analyzer', 'alat yang digunakan untuk secara otomatis mengukur konsentrasi sulfur dioksida dalam sampel gas', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4240, 22, 1, '132080702008', 'Automatic NOX Analyzer', 'alat yang digunakan untuk mengukur konsentrasi nitrogen oksida dalam sampel gas secara otomatis. Nitrogen oksida adalah kelompok gas yang terdiri dari nitrogen monoksida (NO) dan dioksida nitrogen (NO2), yang sering diukur karena peran mereka dalam polusi udara dan dampaknya terhadap lingkungan dan kesehatan manusia.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4241, 22, 1, '132080702009', 'Automatic CO Analyzer', 'alat atau perangkat yang digunakan untuk mengukur kecepatan dan arah aliran air di dalam sungai, laut, dan perairan lainnya. Alat ini memungkinkan para ilmuwan, ahli oseanografi, hidrologi, dan insinyur yang terlibat dalam studi dan proyek terkait air untuk mengukur dan memahami pola pergerakan air.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4242, 22, 1, '132080702010', 'Automatic SPM Analyzer', 'alat yang digunakan untuk secara otomatis menganalisis Suspended Particulate Matter (SPM) dalam sampel udara atau air. Partikulat tergantung pada konteks dapat merujuk pada berbagai jenis partikel padat atau cair yang terapung dalam medium seperti udara atau air. Alat ini dirancang untuk memberikan pengukuran yang cepat, otomatis, dan akurat terkait konsentrasi SPM dalam sampel yang dianalisis.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4243, 22, 1, '132080702011', 'Automatic HC Analyzer', 'alat yang digunakan untuk secara otomatis menganalisis kandungan hidrokarbon (HC) dalam sampel gas atau udara. Hidrokarbon adalah senyawa kimia yang terdiri dari unsur hidrogen dan karbon, dan mereka bisa hadir dalam berbagai bentuk yang termasuk gas, cair, atau padat.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4244, 22, 1, '132080702012', 'Automatic Ozon Analyzer', 'alat yang dirancang untuk secara otomatis mengukur konsentrasi ozon dalam udara atau air.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4245, 22, 1, '132080702013', 'Dust Sampler (Alat Laboratorium Kwalitas Udara)', 'alat laboratorium yang dirancang khusus untuk mengumpulkan sampel debu atau partikel padat dari udara. Tujuan utama dari alat ini adalah untuk mengukur konsentrasi partikel-partikel tersebut di udara dan menganalisis komposisi serta karakteristiknya. Ada beberapa jenis Dust Sampler yang berbeda, tetapi umumnya, alat ini bekerja dengan menghisap udara melalui filter atau kolektor yang menangkap partikel debu yang ada di udara.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4246, 22, 1, '132080702014', 'Air Polution Tester', 'alat yang digunakan untuk mengukur berbagai parameter dan komponen yang ada dalam udara untuk menentukan tingkat polusi udara. Alat ini dirancang untuk mendeteksi, memantau, dan mengukur berbagai zat yang bisa menjadi polutan udara, seperti partikel debu, ozon, nitrogen dioksida (NO2), sulfur dioksida (SO2), karbon monoksida (CO), hidrokarbon, dan lain sebagainya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4247, 9, 1, '132080110010', 'Tilting Tester', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4248, 22, 1, '132080702015', 'Mini Pump Air Tester', 'perangkat kecil yang digunakan untuk menguji tekanan udara dalam suatu sistem atau objek. Perangkat ini umumnya digunakan dalam berbagai konteks, seperti industri otomotif, teknik penerbangan, atau peralatan yang memerlukan pengukuran tekanan udara yang akura', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4249, 22, 1, '132080702018', 'Vehicle Emission Gas Analyzer', 'alat atau perangkat yang digunakan untuk mengukur dan menganalisis komponen gas buang dari kendaraan bermotor. Alat ini dirancang untuk mengevaluasi berbagai gas yang dihasilkan oleh mesin kendaraan, seperti karbon dioksida (CO2), karbon monoksida (CO), hidrokarbon (HC), nitrogen oksida (NOx), dan partikel-partikel lainnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4250, 22, 1, '132080702019', 'Automatic Gas Burner Exhaust Gas Analyzer', 'alat yang digunakan untuk mengukur dan menganalisis gas buang dari pembakaran bahan bakar pada sistem pemanas, tungku, atau peralatan lain yang menggunakan pembakaran gas. Alat ini umumnya digunakan untuk mengevaluasi kinerja pembakaran dan efisiensi sistem pemanas atau tungku.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4251, 22, 1, '132080702020', 'Higt Volume Air Sampler', 'aalat atau perangkat yang digunakan untuk mengumpulkan sampel udara dalam jumlah besar di lingkungan tertentu. Alat ini dirancang untuk menarik volume udara yang signifikan melalui filter atau media penangkap selama periode waktu tertentu. Tujuannya adalah untuk mengumpulkan partikel-partikel terutama polutan udara, seperti debu, polen, partikel halus, logam, dan bahan kimia lainnya yang terdapat di udara.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4252, 22, 1, '132080702025', 'Portable Wind System', 'turbin angin yang dirancang untuk portabilitas. Sistem ini dibuat untuk menghasilkan energi listrik dari energi angin dan dapat dipindahkan dari satu tempat ke tempat lain dengan relatif mudah.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4253, 22, 1, '132080702027', 'Syphon Type Recording Rain Gauge', 'Rain Gauge adalah alat pengukur curah hujan. Siphon Type Recording Rain Gauge adalah salah satu jenis rain gauge yang mendokumentasikan curah hujan secara otomatis dengan menggunakan prinsip sifon.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4254, 22, 1, '132080702028', 'Precition Gas Detector', 'alat atau perangkat deteksi gas yang dirancang untuk memberikan pengukuran yang akurat dan presisi terhadap kadar gas tertentu di lingkungan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4255, 22, 1, '132080702029', 'Solar Radiation Meter', 'alat yang digunakan untuk mengukur tingkat radiasi matahari yang mencapai suatu lokasi pada rentang waktu tertentu. Alat ini penting dalam pemantauan energi matahari yang diterima di suatu area atau lokasi tertentu dalam rentang waktu tertentu. Solar Radiation Meter dapat digunakan dalam berbagai aplikasi, seperti dalam bidang meteorologi, energi terbarukan, pertanian, dan penelitian ilmiah.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4256, 22, 1, '132080702031', 'Gas Sampler', 'alat yang dirancang khusus untuk mengumpulkan contoh gas dari lingkungan atau proses tertentu. Tujuan utamanya adalah untuk mengambil sampel gas dengan akurat dan representatif agar bisa dianalisis di laboratorium atau di tempat lain untuk berbagai tujuan seperti analisis kualitas udara, pemantauan lingkungan, pemantauan proses industri, penelitian ilmiah, atau untuk keperluan pengujian.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4257, 22, 1, '132080702032', 'Stack Sampler', 'alat atau perangkat khusus yang digunakan untuk mengumpulkan sampel gas yang keluar dari cerobong (stack) atau saluran pembuangan dari proses industri atau instalasi lainnya. Tujuan utamanya adalah untuk mengukur komposisi gas, konsentrasi polutan, dan emisi yang dihasilkan dari suatu proses atau fasilitas industri.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4258, 22, 1, '132080702034', 'Zero Gas Generator', 'perangkat atau alat yang digunakan dalam laboratorium atau industri untuk menghasilkan gas nol atau gas referensi yang memiliki komposisi yang diketahui dan stabil. Gas nol ini penting dalam analisis gas untuk kalibrasi instrumen pengukuran gas atau sebagai referensi untuk membandingkan sampel gas yang diukur.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4259, 22, 1, '132080702035', 'Standard Gas Generator', 'perangkat atau sistem yang digunakan untuk menghasilkan gas standar dengan komposisi yang diketahui dan diukur dengan presisi. Gas standar ini digunakan sebagai referensi atau titik acuan dalam pengukuran gas untuk kalibrasi instrumen analisis gas.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4260, 22, 1, '132080702037', 'Gas Cylinder', 'wadah tekanan yang digunakan untuk menyimpan gas dalam bentuk kompresi yang tinggi. Tabung-tabung ini dibuat dari logam yang kuat dan tahan tekanan untuk menahan gas dalam kondisi yang aman.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4261, 22, 1, '132080702038', 'Oil Pump', 'perangkat mekanis yang digunakan untuk menggerakkan minyak dari satu tempat ke tempat lain dalam sebuah sistem mesin atau kendaraan. Pompa ini bertanggung jawab atas pergerakan minyak pelumas yang diperlukan untuk melumasi komponen-komponen mesin guna mengurangi gesekan, mendinginkan, dan melindungi bagian-bagian mesin dari keausan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4262, 9, 1, '132080110024', 'Cam Angle Tester', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4263, 22, 1, '132080702039', 'Air Compressor (Alat Laboratorium Kwalitas Udara)', 'perangkat mekanis yang berfungsi untuk mengubah udara atau gas lainnya menjadi udara bertekanan atau gas bertekanan yang digunakan untuk berbagai keperluan. Prinsip kerjanya mirip dengan pompa, namun, air compressor bekerja dengan kompresi udara atau gas hingga mencapai tekanan yang lebih tinggi dari tekanan atmosfer.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4264, 22, 1, '132080702042', 'Standard Voltage Generator', 'perangkat atau sistem yang dirancang khusus untuk menghasilkan tegangan atau voltase yang diketahui dan stabil sesuai dengan standar yang telah ditetapkan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4265, 9, 1, '132080110026', 'Coil Condeser Tester', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4266, 22, 1, '132080702044', 'Ozone Gas Generator', 'adalah perangkat yang dirancang untuk menghasilkan ozon (O3) dengan cara memanipulasi molekul oksigen (O2). Ozon adalah bentuk yang sangat reaktif dari oksigen dan digunakan dalam berbagai aplikasi, terutama untuk tujuan pemurnian air dan udara.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4267, 9, 1, '132080110027', 'Plug Scope', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4268, 22, 1, '132080702045', 'Hydrogen Gas Generator', 'perangkat yang digunakan untuk menghasilkan gas hidrogen (H2) melalui proses elektrolisis air atau reaksi kimia. Gas hidrogen yang dihasilkan oleh generator ini biasanya digunakan dalam berbagai aplikasi industri, laboratorium, atau penggunaan komersial lainnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4269, 22, 1, '132080702046', 'Air Purlier', 'perangkat yang dirancang untuk membersihkan udara atau air dari kontaminan, partikel-partikel kecil, zat kimia, bau, dan polutan lainnya yang dapat berbahaya atau mengganggu kesehatan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4270, 22, 1, '132080702049', 'Oxygen Analyzer', 'alat yang digunakan untuk mengukur konsentrasi oksigen dalam suatu gas atau lingkungan tertentu. Alat ini bekerja dengan menganalisis persentase atau jumlah oksigen dalam campuran gas yang diuji.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4271, 22, 1, '132080702050', 'Alat Sampling Emisi Sumber Tidak Bergerak', 'alat atau perangkat yang digunakan untuk mengumpulkan sampel emisi gas atau partikel dari sumber polusi udara yang tidak bergerak, seperti cerobong asap dari pabrik, kilang minyak, pembangkit listrik, dan instalasi industri lainnya. Alat ini membantu dalam pemantauan dan pengukuran emisi yang dihasilkan oleh proses industri.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4272, 22, 1, '132080702051', 'Alat Uji Emisi Sumber Bergerak', 'alat atau perangkat yang digunakan untuk mengukur dan menganalisis emisi gas buang dari kendaraan bermotor atau sumber lain yang bergerak, seperti truk, mobil, bus, kapal, atau pesawat. Alat ini dirancang untuk melakukan pengukuran langsung terhadap gas buang yang dihasilkan oleh kendaraan saat beroperasi di jalan atau di tempat lain.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4273, 9, 1, '132080110032', 'Altenator Scope', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4274, 22, 1, '132080702052', 'Air Quality Monitoring System', 'jaringan perangkat yang digunakan untuk mengukur, memantau, dan menganalisis parameter kualitas udara di berbagai lokasi dalam suatu wilayah. Tujuannya adalah untuk memantau komposisi udara terkait dengan polutan tertentu dan parameter lingkungan lainnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4275, 9, 1, '132080110033', 'L.P Gas Detector', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4276, 22, 1, '132080702053', 'Air Sampler', 'perangkat yang dirancang untuk mengumpulkan sampel udara dari lingkungan tertentu dengan tujuan menganalisis komposisi udara, deteksi polutan udara, atau pemantauan kualitas udara. Ini adalah alat yang digunakan dalam berbagai konteks, mulai dari laboratorium, pengawasan lingkungan, hingga keperluan industri.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4277, 22, 1, '132080702055', 'Particulate Sampler/Analyzer/Counter', 'Particulate Sampler adalah alat atau perangkat yang digunakan untuk mengumpulkan dan mengukur materi partikulat (PM) di udara. Materi partikulat ini mencakup partikel-partikel kecil atau tetesan di udara yang dapat mencakup debu, kotoran, jelaga, asap, dan tetesan cair. Partikel ini dapat memiliki ukuran dan komposisi yang beragam dan dapat memiliki dampak kesehatan dan lingkungan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4278, 22, 1, '132080703001', 'Tape Recorder (Alat Laboratorium Kebisingan Dan Getaran)', 'tape recorder atau perekam kaset mungkin digunakan untuk merekam instruksi, catatan, atau data dalam bentuk suara yang terkait dengan percobaan atau penelitian tertentu. Meskipun penggunaannya telah berkurang seiring dengan berkembangnya teknologi digital, tape recorder masih memiliki nilai sejarah dan dalam beberapa kasus masih digunakan untuk tujuan khusus atau koleksi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4279, 9, 1, '132080110036', 'Alat Penguji Keretakan', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4280, 22, 1, '132080703002', 'Precition Integrating Sound Level Meter', 'Alat ini merupakan perangkat pengukur tingkat kebisingan atau suara yang dirancang untuk memberikan pengukuran yang akurat dan terintegrasi dari tingkat tekanan suara atau kebisingan dalam lingkungan tertentu selama periode waktu yang ditentukan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4281, 22, 1, '132080703005', '1/3 Octave Band Real Time Analyzer', '1/3 Octave Band Real-Time Analyzer (RTA) adalah perangkat khusus yang digunakan untuk menganalisis dan mengukur spektrum frekuensi dari sinyal audio secara langsung dalam bentuk pita 1/3 oktaf. Pemecahan spektrum frekuensi menjadi pita 1/3 oktaf memberikan analisis yang lebih terperinci dibandingkan dengan pita oktaf biasa.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4282, 22, 1, '132080703006', 'Vibration Level Meter', 'perangkat yang digunakan untuk mengukur dan menganalisis tingkat getaran yang dihasilkan oleh mesin, peralatan, atau struktur tertentu. Pengukuran getaran penting dalam berbagai industri dan aplikasi teknik untuk memastikan operasi yang aman, mendiagnosis masalah mekanis, dan menjaga kinerja optimal peralatan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4283, 22, 1, '132080703009', 'Data Processing Unit', 'komponen perangkat keras atau software yang bertanggung jawab untuk melakukan pemrosesan data dalam sistem komputer atau jaringan. DPUs memproses data dari berbagai sumber, melakukan berbagai operasi pemrosesan, dan menghasilkan output sesuai dengan kebutuhan pengguna', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4284, 9, 1, '132080110040', 'Upper Leather Water Proff Ness Tester', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4285, 22, 1, '132080703010', 'Extention Code (10M)', 'kabel listrik panjang dengan soket di salah satu ujungnya dan steker di ujung lainnya. Fungsi utamanya adalah memperpanjang jangkauan sumber listrik dari stop kontak ke perangkat listrik atau alat yang membutuhkan daya, biasanya saat stop kontak tidak berada dalam jarak yang mudah dijangkau.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4286, 22, 1, '132080703012', 'Transceiver', 'perangkat elektronik yang memiliki kemampuan untuk melakukan transmisi (mengirim) dan penerimaan (menerima) sinyal atau informasi. Ini adalah perangkat gabungan yang menggabungkan kemampuan dari transmitter (pengirim) dan receiver (penerima) dalam satu unit.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4287, 22, 1, '132080703014', 'Hand Held Sound Intensity System', 'sistem portabel yang dirancang untuk mengukur tingkat intensitas suara di berbagai lingkungan', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4288, 9, 1, '132080110043', 'Adhesion Of Finish Tester', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4289, 22, 1, '132080703017', 'Advanced Vibration and Overpressure Monitor', 'perangkat canggih yang dirancang khusus untuk mengukur dan memantau getaran serta tekanan berlebih (overpressure) dalam berbagai lingkungan. Monitor ini umumnya digunakan dalam industri konstruksi, pertambangan, peledakan, dan kegiatan militer di mana getaran atau tekanan berlebih dapat memiliki dampak signifikan terhadap keselamatan, integritas struktural, dan dampak lingkungan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4290, 22, 1, '132080703020', 'Acoustic Analyzer', 'perangkat lunak atau perangkat keras yang digunakan untuk menganalisis sinyal suara atau audio. Perangkat ini digunakan untuk memeriksa, mengukur, dan menganalisis berbagai parameter yang terkait dengan suara, seperti', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4291, 22, 1, '132080704002', 'Sieve Shaker (Laboratorium Lingkungan)', 'perangkat yang digunakan di laboratorium lingkungan untuk menyaring atau memisahkan bahan berbeda berdasarkan ukuran partikel mereka. Alat ini biasanya digunakan dalam berbagai industri seperti pertambangan, konstruksi, kimia, dan lingkungan untuk menganalisis distribusi ukuran partikel dalam sampel.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4292, 9, 1, '132080110046', 'Tearing Tester', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4293, 22, 1, '132080704005', 'Hot Air Drying Oven', 'alat atau perangkat laboratorium yang digunakan untuk mengeringkan sampel atau bahan dengan menggunakan udara panas yang diatur suhunya. Oven ini dirancang khusus untuk memberikan lingkungan pemanasan yang konsisten dan terkontrol untuk mengeringkan sampel secara efisien.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4294, 22, 1, '132080704011', 'Kjedahl Nitrogen Digestion & Distilling Apparatus', 'Kjeldahl Nitrogen Digestion and Distilling Apparatus merupakan perangkat laboratorium yang digunakan untuk menentukan kandungan nitrogen dalam sampel organik.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4295, 22, 1, '132080704012', 'Gas Chromatography High Resolution Time of Flight Mass Spectometer', 'alat pengukur hujan yang dirancang untuk mengumpulkan dan merekam curah hujan dalam periode waktu tertentu. Alat ini memanfaatkan prinsip syfon untuk mencatat jumlah presipitasi atau hujan yang jatuh selama suatu periode.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4296, 9, 1, '132080110049', 'Starain Tester', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4297, 22, 1, '132080704013', 'Oxoid Air Sampler', 'alat yang digunakan dalam bidang mikrobiologi untuk mengumpulkan sampel udara dengan tujuan memantau kualitas udara dalam lingkungan tertentu. Alat ini memungkinkan pengambilan sampel udara yang representatif untuk analisis mikrobiologis guna mengetahui keberadaan dan konsentrasi mikroorganisme yang mungkin terdapat dalam udara.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4298, 22, 1, '132080705001', 'Kromatografi Gas', 'alat penting dalam menganalisis senyawa organik dan anorganik yang ada dalam sampel gas untuk tujuan identifikasi dan kuantifikasi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4299, 9, 1, '132080110051', 'Drop Test', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4300, 22, 1, '132080705002', 'High Performance Liquid Cramotograph', 'sebuah metode analisis kimia yang digunakan untuk memisahkan campuran senyawa dalam suatu larutan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4301, 9, 1, '132080110052', 'Alat Penguji Kekuatan Pengeras Depan Sepatu', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4302, 22, 1, '132080705003', 'Ion Crhomatograph', 'teknik analisis kromatografi yang digunakan untuk memisahkan dan menganalisis ion-ion dalam sampel larutan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4303, 22, 1, '132080705004', 'Polarograph', 'alat yang digunakan dalam teknik analisis kimia yang dikenal sebagai polarografi. Polarografi adalah metode elektrokimia yang digunakan untuk menganalisis senyawa kimia dalam larutan berdasarkan pada pengukuran arus listrik yang dihasilkan oleh reaksi elektrokimia di antara elektroda dengan larutan sampel.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4304, 9, 1, '132080110054', 'Finish Fastness', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4305, 22, 1, '132080705005', 'UV/VIS Spectrophotometer', 'perangkat laboratorium yang digunakan untuk melakukan analisis kuantitatif dan kualitatif terhadap sampel larutan dengan menganalisis interaksi cahaya ultraviolet (UV) dan cahaya tampak (VIS) dengan sampel tersebut.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4306, 9, 1, '132080110055', 'Alat Tera Sastra', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4307, 22, 1, '132080705006', 'IR Spectrophotometer', 'alat laboratorium yang digunakan untuk menganalisis spektrum inframerah dari sampel zat kimia. Alat ini bekerja dengan mengukur penyerapan radiasi inframerah oleh suatu substansi dalam spektrum elektromagnetik.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4308, 22, 1, '132080705007', 'Fluorescence Spectrophotometer', 'alat laboratorium yang digunakan untuk menganalisis fluoresensi suatu sampel. Prinsip dasar dari alat ini adalah untuk mengukur cahaya yang dipancarkan oleh molekul-molekul dalam sampel setelah mereka menyerap cahaya pada panjang gelombang tertentu.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4309, 22, 1, '132080705008', 'Spectrophotometr Serapan Atom', 'alat laboratorium yang digunakan untuk menganalisis komposisi unsur dalam suatu sampel dengan mengukur serapan cahaya pada panjang gelombang khusus oleh atom-atom dari unsur-unsur tertentu.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4310, 9, 1, '132080110058', 'Handle Strenght', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4311, 22, 1, '132080705009', 'Quadrupole Spectrometer', 'jenis spektrometer yang digunakan dalam analisis massa untuk memisahkan, mengukur, dan menganalisis ion berdasarkan rasio massa terhadap muatan mereka. Ini adalah bagian penting dari spektrometri massa yang menggunakan prinsip medan listrik dan medan magnet untuk mengelompokkan dan memisahkan ion-ion berdasarkan karakteristik massa-terhadap-charge (m/z) mereka.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4312, 9, 1, '132080110059', 'Alat Pelobang (Cork Borer)', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4313, 22, 1, '132080705010', 'Scanning Electron Microscope (Alat Laboratorium Penunjang)', 'alat laboratorium yang kuat dan penting dalam berbagai bidang ilmu, termasuk sains material, biologi, ilmu kedokteran, geologi, dan lainnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4314, 22, 1, '132080705011', 'X-Ray Fluorrescence Analyzer', 'analisis yang digunakan untuk menentukan komposisi unsur kimia dalam suatu sampel. Prinsip kerjanya didasarkan pada efek fluoresensi yang dihasilkan ketika sampel terkena sinar-X.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4315, 22, 1, '132080705013', 'Mercury Analyzer (Alat Laboratorium Penunjang)', 'alat laboratorium yang digunakan untuk mengukur konsentrasi merkuri dalam berbagai jenis sampel. Alat ini penting dalam pemantauan lingkungan, keamanan pangan, dan industri, karena merkuri merupakan zat beracun yang bisa memiliki dampak serius terhadap kesehatan manusia dan lingkungan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4316, 22, 1, '132080705015', 'Biological Microscope', 'alat yang digunakan untuk mengamati dan mempelajari struktur mikroskopis dari sampel biologis. Alat ini memungkinkan pengguna untuk melihat benda-benda kecil yang tidak dapat dilihat dengan mata telanjang.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4317, 22, 1, '132080705018', 'Gas Regulator', 'alat atau perangkat yang digunakan untuk mengontrol tekanan gas dalam tabung gas atau sistem gas yang lebih besar menjadi tekanan yang lebih rendah yang aman dan sesuai dengan kebutuhan penggunaan tertentu. Fungsinya adalah menjaga tekanan gas tetap stabil dan sesuai dengan kebutuhan yang diinginkan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4318, 9, 1, '132080110064', 'Extenso Meter', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4319, 22, 1, '132080705019', 'Centrifuge (Alat Laboratorium Penunjang)', 'alat laboratorium yang digunakan untuk memisahkan komponen-komponen dalam suatu larutan atau campuran berdasarkan perbedaan massa jenis atau kecepatan sedimentasi. Alat ini bekerja dengan memutar sampel dengan cepat di sekitar sumbu pusat rotasi, menghasilkan gaya sentrifugal yang menyebabkan partikel dalam sampel bergerak menjauh dari sumbu rotasi dan terpisah berdasarkan massa jenisnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4320, 9, 1, '132080110065', 'Torsimeter', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4321, 22, 1, '132080705021', 'Electric Oven', 'perangkat khusus yang digunakan di laboratorium untuk tujuan tertentu seperti pemanasan, pengeringan, sterilisasi, atau pengolahan sampel dengan menggunakan sumber panas listrik. Oven ini didesain untuk keperluan laboratorium dengan kontrol suhu yang lebih akurat dan presisi dibandingkan dengan oven rumah tangga biasa.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4322, 22, 1, '132080705022', 'Vacuum Drying Oven', 'perangkat laboratorium yang digunakan untuk mengeringkan sampel atau bahan dengan menggunakan tekanan rendah atau kondisi vakum. Oven ini beroperasi dengan mengurangi tekanan di dalam ruang pengering, yang memungkinkan proses penguapan dan penghilangan air atau zat volatil lainnya pada suhu yang lebih rendah daripada metode pengeringan konvensional.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4323, 9, 1, '132080110067', 'Fatique Tester (Alat Laboratorium Logam, Mesin Dan Listrik)', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4324, 22, 1, '132080705023', 'Bod Incubator', 'perangkat laboratorium yang dirancang khusus untuk menampung dan memelihara kondisi lingkungan yang terkontrol untuk pertumbuhan mikroorganisme dan pengujian biokimia, terutama dalam konteks tes Biological Oxygen Demand (BOD).', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4325, 9, 1, '132080110068', 'Thickness Tester For Metal', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4326, 22, 1, '132080705024', 'Evaporator', 'alat atau perangkat yang digunakan untuk mengubah cairan menjadi gas atau uap. Proses ini disebut sebagai evaporasi. Dalam berbagai konteks, evaporator dapat merujuk pada beragam perangkat yang melakukan proses penghilangan zat cair dari suatu larutan atau campuran, meninggalkan zat tersebut dalam bentuk gas atau padatan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4327, 22, 1, '132080705025', 'Water Circulation Bath', 'perangkat laboratorium yang digunakan untuk menjaga suhu konstan pada sampel atau wadah tertentu yang terendam dalam air. Perangkat ini menggunakan sistem sirkulasi air yang dipanaskan atau didinginkan untuk menjaga suhu air konstan sesuai dengan pengaturan yang diinginkan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4328, 22, 1, '132080705028', 'Rotary Culti-Shaker', 'perangkat laboratorium yang menggabungkan fungsi dari rotary shaker (pengaduk berputar) dengan fungsi incubator (inkubator) dalam satu perangkat. Perangkat ini biasanya digunakan dalam pengkultur sel, pertumbuhan mikroorganisme, biologi molekuler, atau berbagai proses penelitian yang memerlukan pengadukan lembut dan kondisi inkubasi yang terkendali.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4329, 22, 1, '132080705030', 'Homogenizer (Alat Laboratorium Penunjang)', 'perangkat laboratorium yang digunakan untuk menggabungkan, mencampur, atau meratakan sampel dengan membuat partikel-partikel menjadi lebih kecil dan homogen (seragam) dalam suatu larutan atau suspensi. Proses homogenisasi ini membantu dalam mempersiapkan sampel untuk analisis, menghasilkan konsistensi yang lebih baik, dan mencapai distribusi yang seragam dari berbagai bahan kimia atau partikel dalam larutan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4330, 22, 1, '132080705031', 'Pengaduk Magnet', 'perangkat laboratorium yang digunakan untuk mencampur atau mengaduk larutan cair atau suspensi dengan menggunakan medan magnet dan pengaduk magnetik di bawah wadah atau labu reaksi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4331, 22, 1, '132080705032', 'Ultrasonic Cleaner (Alat Laboratorium Penunjang)', 'perangkat yang menggunakan gelombang ultrasonik untuk membersihkan dan menghilangkan kotoran dari permukaan benda atau sampel dengan menggunakan efek cavitasi. Efek cavitasi terjadi ketika gelombang ultrasonik yang dihasilkan oleh perangkat menciptakan gelembung-gelembung mikroskopis dalam cairan pembersih di dalam bak atau wadah.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4332, 22, 1, '132080705033', 'Peralatan Distilasi', 'merujuk pada seperangkat alat yang digunakan dalam proses distilasi, suatu teknik pemisahan yang memanfaatkan perbedaan titik didih komponen dalam campuran untuk memisahkan atau menyuling zat-zat tersebut. Distilasi digunakan dalam berbagai aplikasi di laboratorium, industri kimia, farmasi, dan lainnya untuk memurnikan, memisahkan, atau mengkonsentrasikan bahan kimia.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4333, 22, 1, '132080705034', 'Ice Cube Maker', 'mesin yang dirancang khusus untuk membuat es batu dengan cara membekukan air secara cepat dan efisien. Mesin ini umumnya digunakan di berbagai tempat seperti rumah, restoran, kafe, hotel, bar, dan tempat-tempat lain yang memerlukan suplai es batu dalam jumlah besar secara teratur.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4334, 22, 1, '132080705035', 'Refrigerator/Freezer', 'perangkat khusus yang dirancang untuk digunakan dalam lingkungan laboratorium untuk menyimpan sampel-sampel dan bahan-bahan yang memerlukan suhu yang terkendali dan stabil.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4335, 22, 1, '132080705037', 'Perlatan Extraksi Sochlet', 'perangkat laboratorium yang digunakan untuk mengekstraksi senyawa-senyawa yang larut dalam pelarut tertentu dari bahan padat. Proses ekstraksi Soxhlet sering digunakan dalam kimia analitik untuk memisahkan senyawa-senyawa tertentu dari sampel padat yang akan dianalisis.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4336, 9, 1, '132080110078', 'Schoper Folding Enduranche', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4337, 22, 1, '132080705038', 'Automatic Dispenser', 'perangkat otomatis yang digunakan untuk mendistribusikan bahan kimia, larutan, atau cairan lainnya dalam skala laboratorium. Perangkat ini membantu dalam memberikan volume yang tepat dan terkontrol dari bahan kimia atau zat dalam kegiatan penelitian, analisis, atau eksperimen di laboratorium.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4338, 22, 1, '132080705039', 'Automatic Pure Water System', 'alat atau sistem yang dirancang untuk menghasilkan air murni atau bersih secara otomatis tanpa kehadiran kontaminasi yang dapat merugikan. Sistem ini biasanya digunakan dalam berbagai konteks, seperti laboratorium, industri farmasi, industri elektronik, dan bidang-bidang lain di mana air yang sangat murni diperlukan untuk keperluan kritis.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4339, 22, 1, '132080705040', 'Pompa Peristaltik', 'jenis pompa yang menggerakkan cairan melalui tabung fleksibel dengan cara meremas tabung tersebut secara berulang. Prinsip kerjanya mirip dengan gerakan peristaltik pada usus manusia, di mana gerakan perut membantu mendorong makanan melalui usus.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4340, 22, 1, '132080705042', 'Autoclave Draine Pump', 'autoclave yang merupakan peralatan yang digunakan untuk sterilisasi alat-alat medis, laboratorium, dan bahan lainnya dengan menggunakan panas dan tekanan. Drain pump pada autoclave bertugas untuk mengeluarkan cairan (biasanya air atau cairan steril) dari chamber atau ruang sterilisasi setelah siklus sterilisasi selesai.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4341, 23, 1, '132080801003', 'Current Conductor Busbars', 'komponen penting dalam sistem distribusi daya listrik. Mereka berfungsi sebagai penghantar arus listrik yang didesain untuk membawa arus listrik dari satu titik ke titik lain dalam suatu sistem listrik. Busbar biasanya terbuat dari logam konduktif seperti tembaga atau aluminium karena sifat konduktifitasnya yang baik terhadap arus listrik.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4342, 23, 1, '132080802002', 'Clamp Apparatus', 'alat yang digunakan dalam laboratorium atau setting eksperimental untuk menjaga atau menahan suatu objek atau peralatan tertentu agar tetap dalam posisi yang diinginkan selama proses percobaan atau pengujian.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4343, 23, 1, '132080802008', 'Line Pump', 'Pompa ini digunakan untuk mentransfer beton dari tempat pencampuran (biasanya truk mixer beton) ke lokasi proyek konstruksi yang diinginkan dengan menggunakan pipa atau saluran.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4344, 9, 1, '132080110085', 'Specimen Mount Press', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4345, 23, 1, '132080802017', 'Accelerometers', 'alat ini untuk mengukur percepatan pada suatu benda dalam tiga dimensi ruang (akselerasi linear) atau memahami orientasi dan perubahan gerakan (akselerasi sudut).', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4346, 23, 1, '132080803004', 'Software DAAS MOD', 'Sofware Data Acquisition and Analysis (DAA) merujuk pada proses mengumpulkan data dari berbagai sumber dan kemudian menganalisis data tersebut untuk mendapatkan informasi atau wawasan yang berharga', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4347, 23, 1, '132080803007', 'Hardware Conf Off-Line Computer', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4348, 23, 1, '132080803008', 'Software Conf Off-Line Computer', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4349, 23, 1, '132080804003', 'Pressure Control System', 'alat atau sistem yang dirancang untuk memantau, mengatur, dan menjaga tekanan pada suatu sistem atau peralatan yang membutuhkan pengendalian tekanan tertentu. Sistem ini berperan dalam menjaga tekanan fluida atau gas dalam batas-batas yang ditetapkan untuk memastikan operasi yang aman dan efisien.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4350, 9, 1, '132080110090', 'Acoustic Emmission', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4351, 23, 1, '132080804006', 'Control Panel', 'bagian dari sistem elektrik atau mekanik yang berfungsi sebagai pusat kontrol untuk mengoperasikan, mengawasi, dan mengatur berbagai fungsi dalam suatu sistem. Control panel dapat ditemukan dalam berbagai lingkup, mulai dari industri, bangunan komersial, kendaraan, hingga perangkat elektronik rumah tangga.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4352, 9, 1, '132080110091', 'Level Recorder', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4353, 23, 1, '132080804010', 'Pressure Tranducer', 'perangkat elektronik yang digunakan untuk mengukur tekanan dalam berbagai sistem dan mengubahnya menjadi sinyal listrik yang dapat diukur atau diproses lebih lanjut. Transduser tekanan biasanya digunakan dalam aplikasi industri, kendaraan, pengukuran lingkungan, dan banyak lagi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4354, 23, 1, '132080805001', 'Towing Crane', 'peralatan berat yang digunakan untuk mengangkat, memindahkan, dan menarik beban yang besar dan berat, seperti kendaraan yang rusak atau muatan yang memerlukan pemindahan menggunakan tali atau kabel. Derek pengangkut ini biasanya digunakan di industri otomotif, konstruksi, pemulihan kendaraan, serta di area industri atau konstruksi lainnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4355, 23, 1, '132080805004', 'Model Preparation And Storage', 'penyimpanan model sering kali merujuk pada penyimpanan sampel, bahan, atau hasil eksperimen yang telah diproses atau disimpan untuk penggunaan atau analisis selanjutnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4356, 23, 1, '132080806002', 'Frequency Counter (Peralatan Umum)', 'alat atau perangkat elektronik yang digunakan untuk mengukur frekuensi sinyal yang masuk dalam suatu sistem elektronik. Frekuensi merupakan jumlah siklus per detik dari gelombang sinusoidal atau sinyal periodik lainnya dan diukur dalam satuan hertz (Hz).', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4357, 23, 1, '132080806003', 'Multi Tester', 'alat pengukur listrik yang serbaguna, yang juga dikenal sebagai multimeter atau multitester. Alat ini dapat digunakan untuk mengukur berbagai parameter listrik dan elektronik seperti tegangan (Volt), arus (Ampere), dan resistansi (Ohm). Multimeter juga sering dilengkapi dengan fungsi tambahan, seperti pengukuran kapasitansi, pengujian kontinuitas, pengukuran frekuensi, dan kadang-kadang dapat mengukur suhu serta mengukur komponen semikonduktor.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4358, 9, 1, '132080110096', 'Yarn Friction & Rubbing Tester', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4359, 23, 1, '132080806004', 'Digital Multi Tester', 'alat pengukur elektronik serbaguna yang digunakan untuk mengukur berbagai parameter listrik dalam bentuk digital. DMM adalah versi digital dari multitester yang menggunakan tampilan LCD atau layar digital untuk menampilkan hasil pengukuran dengan angka-angka.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4360, 9, 1, '132080110097', 'Coloumetric Planting', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4361, 23, 1, '132080806005', 'Weighing Scale', 'Weighing scale, atau sering disebut timbangan, adalah perangkat yang digunakan untuk mengukur massa atau berat suatu objek. Timbangan digunakan di berbagai aplikasi, mulai dari kebutuhan rumah tangga hingga kegiatan industri dan laboratorium.  contoh Timbangan Mekanis,Timbangan Digital,Timbangan Platform dan timbangan lainya', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4362, 23, 1, '132080807001', 'Marking Plate; 3D Meas & Mark Out Machine', 'sebuah mesin khusus yang dirancang untuk mencetak logo dalam tiga dimensi (3D) dan melakukan berbagai tugas seperti date coding pada PCB, penandaan nomor telepon pada pelat, branding hadiah, dan engraving pada material logam', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4363, 23, 1, '132080807005', 'Circular Saw', 'mesin gergaji yang menggunakan pisau bundar berputar untuk melakukan pemotongan pada berbagai bahan, seperti kayu, plastik, logam, dan lainnya. Alat ini digunakan untuk memotong dengan cepat dan presisi, dan cocok untuk berbagai proyek konstruksi, kerajinan, dan pekerjaan kayu.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4364, 23, 1, '132080807006', 'Thicknessing Planer', 'mesin perkakas yang digunakan untuk meratakan dan menipiskan permukaan bahan kayu untuk mendapatkan ketebalan yang seragam dan presisi yang diinginkan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4365, 23, 1, '132080807007', 'High Precision Surface Planer Aang Jointer', 'perangkat yang digunakan dalam proses penghalusan atau penyesuaian permukaan kayu atau bahan lainnya dalam proses pengolahan kayu atau pembuatan furnitur.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4366, 23, 1, '132080807008', 'Wood Lather', 'mesin yang digunakan untuk memahat, memutar, dan membentuk kayu dengan cara memanfaatkan putaran. Ini adalah alat yang sangat berguna dalam proses pembuatan berbagai produk kayu seperti piringan, mangkuk, pahat, atau karya seni dari kayu.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4367, 23, 1, '132080807009', 'Spindle Shaper', 'mesin perkakas yang digunakan dalam industri kayu untuk membentuk profil atau membuat potongan dengan akurasi dan presisi tinggi pada kayu, plastik, atau bahan lainnya. Mesin ini memiliki spindel yang berputar dan berbagai jenis alat potong yang dapat diubah-ubah untuk membuat profil atau bentuk tertentu pada bahan kerja.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4368, 23, 1, '132080807011', 'Mobile Disc And Belt Sanding Machine', 'peralatan perkayuan yang serbaguna digunakan untuk melakukan proses penghalusan dan pengikisan pada permukaan kayu. Peralatan ini biasanya terdiri dari dua komponen utama: disc sander (pengikis cakram) dan belt sander (pengikis sabuk), keduanya terpasang pada satu unit.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4369, 23, 1, '132080807012', 'Band Saw', 'alat perkayuan yang digunakan untuk memotong berbagai bahan seperti kayu, logam, dan plastik. Alat ini menggunakan pita pisau yang tipis dan panjang, terbuat dari logam, yang membentuk lingkaran terus-menerus dan terpasang di dua atau lebih roda yang berputar untuk menggerakkan pita tersebut.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4370, 9, 1, '132080110106', 'Uniterup Tible Supply', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4371, 23, 1, '132080807013', 'Table Drilling Machine (Pemesinan : Model Ship Workshop)', 'peralatan pemesinan yang digunakan dalam workshop untuk melakukan proses pengeboran pada berbagai jenis material dengan presisi yang tinggi. Ini adalah alat yang sangat berguna dalam membuat model kapal atau konstruksi model lainnya karena dapat membuat lubang-lubang dengan kedalaman, ukuran, dan ketelitian yang konsisten.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4372, 23, 1, '132080807014', 'Dust Exhaust System', 'sistem pengeluaran debu atau sistem ventilasi yang dirancang khusus untuk mengumpulkan dan menghilangkan debu, partikel kecil, dan kontaminan lainnya dari udara di lingkungan kerja, bengkel, atau pabrik. Tujuannya adalah untuk menjaga lingkungan kerja agar tetap bersih, sehat, dan aman dari debu yang dihasilkan selama proses produksi atau kerja.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4373, 23, 1, '132080807015', 'Working Table For Ship Model', 'khusus yang digunakan untuk membangun, merakit, dan membuat model kapal secara detail dan akurat. Meja ini dirancang khusus untuk mendukung proses pembuatan model kapal dengan memberikan ruang kerja yang luas, stabil, dan terorganisir dengan baik.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4374, 23, 1, '132080807016', 'Hoistbeam With 2 Rollable Rubber Bands', 'struktur atau perangkat yang dirancang untuk mendukung dan memfasilitasi penggunaan dua hoist (alat pengangkat) pada satu struktur utama', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4375, 23, 1, '132080807019', 'Complete Set Of Handtools', 'umumnya terdiri dari berbagai macam alat yang digunakan untuk pekerjaan tangan atau perbaikan di rumah, bengkel, atau proyek-proyek konstruksi kecil. Set ini sering kali dirancang untuk mencakup berbagai jenis alat dasar yang diperlukan untuk melakukan sebagian besar tugas-tugas sehari-hari.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4376, 23, 1, '132080808001', 'Propeller Forming Unit', 'bagian dari sistem propulsi yang digunakan untuk menghasilkan dorongan pada kapal, pesawat, atau kendaraan lainnya', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4377, 23, 1, '132080808003', 'Drying Chamber', 'sebuah ruangan atau tempat khusus yang dirancang untuk menghilangkan kelembaban atau mengeringkan bahan tertentu. Ruang pengering ini memiliki kontrol suhu dan ventilasi yang memungkinkan pengaturan lingkungan kering yang sesuai untuk proses pengeringan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4378, 23, 1, '132080808008', 'Workshop Ascessories (Hand And Electronic Tools)', 'alat dan perlengkapan yang digunakan dalam workshop, baik itu alat tangan (hand tools) maupun alat elektronik (electronic tools), yang mendukung berbagai proses perakitan, perbaikan, atau pembuatan suatu produk.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4379, 9, 1, '132080110114', 'Vibrating Test Equipment', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4380, 23, 1, '132080809002', 'Precision Lather (250 mm Centre Height)', 'alat yang digunakan untuk memutar dan memotong benda kerja yang berputar. Mesin ini dirancang untuk membuat benda kerja dalam toleransi yang sangat tinggi dan memiliki akurasi yang baik. Lathe (atau bubut) ini digunakan untuk membuat bagian yang presisi dalam proses manufaktur.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4381, 23, 1, '132080809003', 'Universal Milling Machine (Pemesinan: Mechanical Workshop)', 'jenis mesin perkakas yang digunakan dalam proses pemesinan untuk memproduksi komponen dengan tingkat presisi yang tinggi. Mesin ini memiliki kemampuan untuk melakukan berbagai jenis operasi pemesinan seperti penggilingan (milling), pengeboran (drilling), penyalinan bentuk (contouring), dan membuat lubang-lubang dengan posisi dan ukuran yang tepat.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4382, 23, 1, '132080809004', 'Vertical Bandsaw', 'jenis mesin pemotong yang memiliki pisau pita vertikal yang dirancang untuk melakukan pemotongan presisi pada benda kerja yang lebih besar atau lebih tebal. Alat ini terdiri dari sebuah meja kerja yang bisa diatur tingginya, pisau pita yang tegak lurus (vertikal) terhadap meja kerja, dan mekanisme pemotongan yang dapat diatur sesuai kebutuhan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4383, 9, 1, '132080110117', 'Refletance', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4384, 23, 1, '132080809005', 'Column Drilling Machine', 'mesin bor yang memiliki struktur utama berupa kolom yang tegak lurus atau vertikal. Mesin ini digunakan untuk melakukan proses pengeboran pada benda kerja dengan presisi yang tinggi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4385, 9, 1, '132080110118', 'Bondet Searing Jig For Disk Pad', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4386, 23, 1, '132080809006', 'Table Drilling Machine (Pemesinan: Mechanical Workshop)', 'mesin perkakas yang digunakan untuk membuat lubang-lubang pada benda kerja dengan presisi tinggi. Mesin ini terdiri dari meja yang mendukung benda kerja dan spindle yang membawa alat pemotong (bor) yang dapat diatur ke berbagai tingkat kecepatan dan kedalaman bor.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4387, 9, 1, '132080110119', 'Sperometer For Mirror', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4388, 23, 1, '132080809007', 'Hacksawing Mwchine', 'mesin yang digunakan untuk melakukan pemotongan atau pemisahan logam, plastik, atau bahan lainnya dengan menggunakan pisau gergaji bergerak maju-mundur. Mesin ini umumnya terdiri dari kerangka atau rangkaian yang menopang benda kerja, pisau gergaji, dan mekanisme yang memungkinkan pisau gergaji bergerak untuk melakukan pemotongan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4389, 9, 1, '132080110120', 'Pressure Relaxtion For Iror', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4390, 23, 1, '132080809008', 'Double End Grinder', 'sebuah mesin penggiling (grinder) yang memiliki dua buah roda penggiling (grinding wheel) yang terletak di kedua ujungnya. Mesin ini digunakan untuk mengasah atau menghaluskan permukaan benda kerja dengan presisi yang tinggi dan dapat menyelesaikan dua bagian benda kerja secara bersamaan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4391, 23, 1, '132080809010', 'Sheet Metal Roller', 'alat atau mesin yang digunakan untuk membentuk lembaran logam menjadi bentuk yang diinginkan dengan menggunakan prinsip penggulungan (rolling). Mesin ini sering disebut juga sebagai plate rolling machine atau slip roll machine.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4392, 9, 1, '132080110122', 'Pressurizing Jig For Brake Linning', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4393, 23, 1, '132080809011', 'Laver Shear', 'jenis alat potong yang dioperasikan dengan tuas (lever) untuk memotong bahan logam atau bahan lainnya dengan cara menekan benda kerja antara dua mata pisau atau pisau potong.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4394, 9, 1, '132080110123', 'Peeling Force For Disk Pads', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4395, 23, 1, '132080809012', 'Turning Tool Grinding Machine', 'mesin yang digunakan untuk mengasah atau merapikan alat potong (tool) yang digunakan dalam proses pengerjaan benda kerja pada mesin bubut (lathe). Mesin ini dirancang khusus untuk mengasah alat potong seperti pahat bubut (turning tool), yang biasanya terbuat dari bahan keras seperti baja potong atau karbida.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4396, 23, 1, '132080809014', 'Automatic Sharpening Machine', 'sebuah mesin otomatis yang dirancang khusus untuk mengasah alat potong atau tool secara otomatis tanpa memerlukan intervensi manusia secara langsung selama proses pengasahan. Mesin ini digunakan untuk mengoptimalkan tepi potong alat, memperbaharui geometri alat, dan memastikan bahwa alat potong tetap dalam kondisi optimal untuk melakukan fungsi pemotongan dengan presisi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4397, 23, 1, '132080809015', 'Welding Table', 'meja khusus yang dirancang untuk mendukung proses pengelasan. Meja ini memiliki konstruksi yang kokoh dan dirancang untuk menahan panas, percikan logam cair, dan beban berat yang terkait dengan proses pengelasan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4398, 23, 1, '132080809016', 'Exhaust System', 'Alat untuk mengarahkan gas buang dari mesin kendaraan dan memprosesnya sebelum dilepaskan ke lingkungan luar.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4399, 23, 1, '132080809017', 'Welding Rectifier (Pemesinan: Mechanical Workshop)', 'perangkat yang digunakan dalam proses pengelasan untuk mengubah arus listrik bolak-balik (AC) menjadi arus searah (DC) yang lebih stabil dan mudah dikontrol untuk keperluan pengelasan. Rectifier ini mengonversi arus AC menjadi arus DC menggunakan komponen diode atau teknologi semikonduktor lainnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4400, 23, 1, '132080809018', 'MIC/MAG Welding Unit', 'sebuah perangkat atau unit yang digunakan dalam proses pengelasan logam dengan menggunakan metode pengelasan gas terproteksi. Metode ini juga dikenal sebagai Gas Metal Arc Welding (GMAW).', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4401, 9, 1, '132080110129', 'Hot Water Hosty Type 50', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4402, 23, 1, '132080809019', 'Gas Welding Unit (Acetylene)', 'sebuah perangkat yang digunakan dalam proses pengelasan dengan menggunakan gas sebagai bahan bakar utama untuk menciptakan panas yang diperlukan untuk melelehkan logam yang akan disambungkan. Teknik ini dikenal dengan sebutan gas welding atau oxy-fuel welding.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4403, 24, 1, '132080810002', 'Precision Bench Drilling Machine', 'jenis mesin bor yang digunakan untuk melakukan proses pengeboran dengan tingkat presisi yang tinggi pada benda kerja. Mesin ini dirancang untuk keperluan pemboran yang memerlukan ketelitian dan keakuratan dalam pengeboran lubang pada material.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4404, 9, 1, '132080110131', 'Cylotex Sample Min', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4405, 24, 1, '132080810004', 'Set Of Measuring Equipment And Handtools', 'kumpulan atau set peralatan pengukuran dan alat tangan yang digunakan dalam berbagai aplikasi seperti workshop, industri, perbaikan, dan konstruksi. Set ini terdiri dari berbagai alat pengukur dan alat tangan yang digunakan untuk berbagai tujuan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4406, 24, 1, '132080812001', 'Lifting Table', 'perangkat mekanik yang digunakan untuk mengangkat, menurunkan, atau mengatur tinggi suatu beban atau barang secara vertikal. Perangkat ini sering digunakan di berbagai industri, gudang, bengkel, atau fasilitas logistik untuk mempermudah proses pengangkatan barang dengan aman dan efisien.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4407, 24, 1, '132080812002', 'Mobile Exhaust System', 'sistem knalpot mobil adalah komponen penting dalam kendaraan bermotor yang bertanggung jawab untuk mengarahkan dan mengelola gas buang dari mesin kendaraan ke atmosfer. Fungsi utamanya adalah untuk mengurang', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4408, 9, 1, '132080110134', 'Transpol', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4409, 24, 1, '132080813001', 'Eart Tester', 'Earth Tester adalah perangkat atau alat yang digunakan untuk mengukur resistansi atau resistivitas tanah pada sistem grounding atau pengegroundan. Sistem grounding yang baik sangat penting dalam instalasi listrik untuk memastikan keamanan dan melindungi peralatan serta penghuni dari bahaya arus bocor atau lonjakan tegangan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4410, 24, 1, '132080813002', 'Table Drilling Machine (Pemesinan: Electical Workshop)', 'mesin bor atau drill press yang dirancang untuk melakukan proses pengeboran pada benda kerja dengan akurasi tinggi dan konsisten. Mesin ini terdiri dari meja datar yang dapat diatur ketinggiannya dan dilengkapi dengan motor yang menggerakkan spindle (poros) yang memegang pahat bor.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4411, 24, 1, '132080813003', 'Electrical Handdrilling Machine', 'perangkat listrik yang digunakan untuk melakukan pengeboran lubang pada berbagai jenis material seperti kayu, logam, plastik, atau beton ringan. Mesin ini memiliki desain yang ringkas dan portabel yang memungkinkan pengguna untuk melakukan pekerjaan bor dengan mudah di berbagai lokasi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4412, 24, 1, '132080813004', 'Battery Operated Handdrilling Machine', 'alat bor portabel yang menggunakan tenaga dari baterai untuk melakukan proses pengeboran. Ini adalah versi portabel dari mesin bor yang dapat digunakan di berbagai lokasi tanpa ketergantungan pada sumber daya listrik yang tetap.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4413, 24, 1, '132080814002', 'Hydraulic Power Units', 'perangkat atau sistem yang digunakan untuk menghasilkan tenaga hidrolik dengan mengubah energi mekanik menjadi energi hidrolik. HPU sering digunakan dalam berbagai aplikasi industri, mesin, dan sistem yang memerlukan daya hidrolik untuk melakukan berbagai fungsi, seperti mengoperasikan silinder hidrolik, menggerakkan motor hidrolik, atau mengontrol sistem hidrolik lainnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4414, 9, 1, '132080110139', 'Boresscope', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4415, 24, 1, '132080814003', 'Cooling Tower', 'Cooling Tower biasanya digunakan dalam proses-proses industri seperti pembangkit listrik, pabrik kimia, pabrik pengolahan minyak, dan fasilitas manufaktur lainnya yang menghasilkan panas dalam jumlah besar.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4416, 24, 1, '132080814005', 'Wind Generator', 'Wind Generator dikenal sebagai turbin angin atau wind turbine, adalah perangkat yang menggunakan energi kinetik dari angin untuk menghasilkan listrik. Prinsip dasarnya adalah menggunakan angin yang mengalir untuk memutar baling-baling atau bilah-bilah pada turbin, yang kemudian menggerakkan generator untuk mengonversi energi mekanik menjadi energi listrik.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4417, 9, 1, '132080110141', 'Preccision Thermocouple Calibration Standard', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4418, 24, 1, '132080814006', 'Wireless Control System For Ship Model', 'Sistem kontrol yang digunakan dalam mengoperasikan atau mengontrol model kapal secara nirkabel tanpa koneksi kabel fisik. Sistem ini memungkinkan pengendalian kapal model dari jarak jauh dengan menggunakan teknologi nirkabel.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4419, 9, 1, '132080110142', 'Constat Temperatur Calibration Ice Batth', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4420, 24, 1, '132080814007', 'Wireless Data Tranmission System', 'merujuk pada teknologi yang memungkinkan pengiriman atau transmisi data antara perangkat atau sistem tanpa menggunakan kabel fisik. Ini berbeda dari transmisi data tradisional yang mengandalkan kabel atau konektor fisik untuk mengirim informasi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4421, 24, 1, '132080814008', 'Model Posistion Measuring Unit And Cadmes', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4422, 9, 1, '132080110144', 'Vioce Grioppe', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4423, 24, 1, '132080814009', 'Interface', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4424, 9, 1, '132080110145', 'Rochhet Driver Vessel', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4425, 24, 1, '132080814011', 'Rails', 'alat atau perangat yang digunakan untuk jalur lintas kereta', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4426, 24, 1, '132080815001', 'Photo Equipment', 'Peralatan foto (photography equipment) merujuk kepada segala perlengkapan dan perangkat yang digunakan dalam fotografi untuk mengambil gambar, baik itu untuk keperluan profesional, hobi, atau kebutuhan pribadi. Peralatan fotografi bisa beragam tergantung pada kebutuhan dan tujuan penggunaannya, mulai dari pemotretan profesional, fotografi hobi, dokumentasi peristiwa, sampai penggunaan sehari-hari.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4427, 9, 1, '132080110147', 'Alat Uji Perendam Gas Buang', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4428, 24, 1, '132080815004', 'Video Anf Vedeo Editing Equipment', 'Video dan peralatan pengeditan video merujuk pada berbagai perangkat yang digunakan dalam produksi, pengambilan gambar, pengeditan, dan pengolahan video. Beberapa peralatan yang umum digunakan dalam industri produksi video dan pengeditan', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4429, 9, 1, '132080110148', 'Alat Uji Crack', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4430, 24, 1, '132080815005', 'Lighting Equipment', 'Lighting Equipment merujuk pada beragam perangkat yang digunakan untuk menciptakan cahaya dalam berbagai konteks. Ini mencakup berbagai jenis peralatan yang digunakan untuk pencahayaan, baik di dalam ruangan maupun di luar ruangan, untuk tujuan komersial, industri, hiburan, atau keperluan domestik', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4431, 25, 1, '132080901001', 'Electrical Safety Analyzer', 'Electrical Safety Analyzer adalah perangkat yang digunakan untuk menguji dan memastikan keamanan peralatan medis dan elektronik. Alat ini dirancang untuk melakukan serangkaian pengujian dan evaluasi terhadap peralatan medis untuk', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4432, 25, 1, '132080901002', 'Ventilator Tester', 'Ventilator Tester adalah perangkat yang digunakan untuk menguji dan memeriksa kinerja ventilator medis. Perangkat ini dirancang khusus untuk memastikan bahwa ventilator atau alat bantu pernapasan yang digunakan dalam perawatan medis', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4433, 25, 1, '132080901003', 'Infus Device Analyzer', 'Infusion Device Analyzer adalah perangkat khusus yang digunakan untuk menguji, memeriksa, dan memastikan kinerja yang benar dari alat infus atau perangkat infus medis. Perangkat ini digunakan untuk mengevaluasi dan memverifikasi fungsi infus yang tepat, memastikan keakuratan dan keamanan dalam memberikan obat atau cairan ke pasien.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4434, 25, 1, '132080901004', 'Defibrillator And Pacer Analyzer / Tester', 'alat atau perangkat yang digunakan dalam bidang medis untuk menguji dan menganalisis kinerja defibrilator dan pacemaker. Ini adalah alat yang kritis untuk memastikan bahwa perangkat medis tersebut berfungsi secara tepat sebelum digunakan dalam pengobatan atau perawatan pasien.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4435, 9, 1, '132080110153', 'Reflection Polariscope', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4436, 25, 1, '132080901006', 'Ultra Sound Wattmeter', 'perangkat yang baru atau khusus, kemungkinan itu adalah kombinasi antara teknologi ultrasound (gelombang suara dengan frekuensi tinggi di luar batas pendengaran manusia) dengan kemampuan untuk mengukur daya atau watt dalam konteks tertentu.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4437, 25, 1, '132080901009', 'Mili Ampere / Mili Ampere Second Meter', 'ukur arus listrik yang lebih kecil dari ampere. Biasanya, ini digunakan untuk mengukur arus yang sangat kecil dalam skala milidari ampere. Satuan ini seringkali ditemui dalam pengukuran arus elektrik dalam skala yang sangat kecil, seperti dalam rangkaian elektronik, peralatan medis, atau pengukuran sensor.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4438, 25, 1, '132080901011', 'Bio Pressure Meter', 'alat atau perangkat untuk mengukur tekanan darah atau tekanan dalam tubuh manusia. Secara umum, Bio Pressure Meter sering kali merujuk kepada alat pengukur tekanan darah yang menggunakan teknologi modern dan terkini untuk memberikan pengukuran tekanan darah yang akurat.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4439, 25, 1, '132080901012', 'Electrocardiograph Simulator', 'sebuah perangkat lunak atau perangkat keras yang dirancang untuk mensimulasikan atau meniru sinyal-sinyal elektrik yang dihasilkan oleh jantung manusia. Perangkat ini digunakan untuk melatih profesional medis, teknisi, atau siswa dalam membaca dan menginterpretasikan data elektrokardiogram (EKG atau ECG).', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4440, 25, 1, '132080901013', 'Multi Parameter / Patient Simulator', 'perangkat medis yang dirancang untuk mensimulasikan berbagai kondisi fisiologis pada manusia. Alat ini digunakan dalam pelatihan medis, pengujian perangkat medis, serta kalibrasi dan pengujian peralatan medis.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4441, 25, 1, '132080901014', 'Ultra Violet / Visible Spectrometers Standards', 'Standar spektrometer ultraviolet (UV) / terlihat (visible) digunakan sebagai referensi atau patokan untuk mengukur dan memastikan akurasi serta konsistensi alat spektrometer UV/Vis. Standar ini berperan penting dalam memvalidasi kinerja perangkat lunak dan perangkat keras spektrometer UV/Vis.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4442, 9, 1, '132080110159', 'Parker Magnetic Yoke', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4443, 25, 1, '132080901015', 'Anaesthetic Monitor / Analyzer', 'Alat pemantauan atau analisis anestesi (anaesthetic monitor/analyzer) adalah perangkat medis yang digunakan untuk memantau dan mengukur berbagai parameter vital saat seseorang sedang dalam anestesi selama operasi atau prosedur medis.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4444, 9, 1, '132080110160', 'Crack Depth Detector', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4445, 25, 1, '132080901016', 'Fluorosence Meter', 'alat yang digunakan untuk mengukur fluoresensi, yaitu cahaya yang dihasilkan oleh suatu zat saat tereksitasi oleh cahaya yang masuk ke dalamnya. Alat ini bekerja dengan mendorong suatu sampel untuk memancarkan cahaya fluoresen yang kemudian diukur untuk mendapatkan informasi tentang sifat fisik atau kimia dari zat tersebut.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4446, 25, 1, '132080901018', 'Universal Biometer', 'alat atau perangkat atau instrumen yang digunakan dalam berbagai konteks ilmiah, terutama dalam bidang biologi, optik, atau teknologi medis.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4447, 25, 1, '132080901019', 'Oxygen Monitor', 'Oxygen monitor adalah suatu alat yang digunakan untuk mengukur kandungan unsur oksigen dalam suatu output gas. Oxygen analyzer memiliki peran yang penting untuk mendeteksi apakah output dari alat tersebut sesuai dengan pengaturan atau tidak.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4448, 9, 1, '132080110163', 'Vertical Stang For Bernouli And Losestest', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4449, 25, 1, '132080901021', 'Photo Theraphy Radiometer', 'alat yang digunakan untuk mengukur intensitas cahaya yang dihasilkan oleh lampu phototherapy, khususnya dalam pengobatan terapi cahaya (phototherapy) untuk pengobatan kondisi medis seperti jaundice neonatal (kuning pada bayi baru lahir).', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4450, 25, 1, '132080901023', 'Syringe Pump Calibrator', 'perangkat yang digunakan untuk mengkalibrasi atau memverifikasi pengukuran yang dilakukan oleh pompa suntik (syringe pump) dalam memberikan dosis obat atau cairan ke pasien dalam pengaturan medis.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4451, 9, 1, '132080110165', 'Flow Table (Alat Laboratorium Logam, Mesin Dan Listrik)', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4452, 25, 1, '132080901024', 'Parabolic Flow Adaptor', 'Parabolic Flow Adaptor merupakan sebuah alat atau adaptor yang digunakan dalam pengaliran fluida, biasanya digunakan dalam laboratorium atau industri untuk mengatur atau mengarahkan aliran cairan dengan lebih terfokus dan terkontrol.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4453, 25, 1, '132080902002', 'AC/DC Volt & Current Amplifier', 'perangkat elektronik yang dirancang untuk memperkuat atau menguatkan sinyal tegangan (volt) dan arus listrik (current) dalam berbagai mode, baik secara searah (DC) maupun bolak-balik (AC). Amplifier ini digunakan untuk memperbesar sinyal listrik sehingga dapat memberikan keluaran yang lebih besar dari inputnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4454, 9, 1, '132080110167', 'Variale Gradient Chn', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4455, 25, 1, '132080902006', 'Resistance Standard', 'resistor yang telah dikalibrasi dengan nilai resistansi yang sangat tepat dan diketahui secara pasti. Resistor ini digunakan sebagai referensi atau patokan dalam pengukuran resistansi pada berbagai peralatan atau aplikasi yang memerlukan nilai resistansi yang akurat dan diketahui.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4456, 25, 1, '132080902008', 'DC / AC Standard', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4457, 9, 1, '132080110169', 'Adjustable Bel Flw Channel', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4458, 25, 1, '132080902010', 'Electro & Pneumatic Calibrator', 'perangkat yang digunakan untuk mengkalibrasi atau memeriksa ulang instrumen pengukuran tekanan, aliran, suhu, atau parameter lain yang terkait dengan sistem pneumatik dan elektronik.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4459, 25, 1, '132080902012', 'Programmable Automatic RCL Meter', 'alat yang digunakan untuk mengukur resistansi (R), kapasitansi (C), dan induktansi (L) dari komponen elektronik secara otomatis. Alat ini dilengkapi dengan kemampuan pemrograman yang memungkinkan pengguna untuk mengatur dan mengukur nilai-nilai ini dengan presisi sesuai kebutuhan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4460, 9, 1, '132080110171', 'Explotion Engine', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4461, 25, 1, '132080902013', 'Logic Analyzer (Alat Laboratorium Standard Dan Kalibrator)', 'Logic Analyzer dapat menangkap data digital dari berbagai sumber, seperti mikrokontroler, bus komunikasi, memori, atau rangkaian digital lainnya. Alat ini membantu dalam mendiagnosis masalah, memeriksa kebenaran logika (logic correctness), dan memahami perilaku sinyal digital dalam sistem elektronik.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4462, 9, 1, '132080110172', 'Digimatic Callipers', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4463, 25, 1, '132080902014', 'Digital Trouble Shooter', 'Digital Troubleshooter adalah sebuah perangkat lunak, alat, atau sistem yang digunakan untuk mengidentifikasi, menganalisis, dan memecahkan masalah teknis dalam lingkungan digital. Ini dapat digunakan dalam berbagai konteks, termasuk dalam pemeliharaan perangkat keras dan perangkat lunak komputer, jaringan komputer, sistem elektronik, dan aplikasi perangkat lunak.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4464, 25, 1, '132080902015', 'Board Analyzer & Diagnostic System', 'Board Analyzer & Diagnostic System (BADS) adalah sistem yang dirancang untuk mendiagnosis dan menganalisis kerusakan atau masalah pada berbagai jenis papan sirkuit atau printed circuit board (PCB). Sistem ini membantu dalam mengidentifikasi masalah elektronik pada papan sirkuit yang digunakan dalam berbagai perangkat elektronik, mulai dari perangkat rumah tangga hingga peralatan industri yang lebih kompleks.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4465, 9, 1, '132080110174', 'Bech Work', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4466, 25, 1, '132080902016', 'Digital & Analog Oscilloscope', 'Oscilloscope adalah alat ukur elektronik yang digunakan untuk mengamati dan menganalisis sinyal listrik dalam domain waktu. Oscilloscope dapat menampilkan sinyal listrik dalam bentuk gelombang, yang memungkinkan pengguna untuk memeriksa karakteristik sinyal seperti amplitudo, frekuensi, waktu, dan bentuk gelombang.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4467, 9, 1, '132080110175', 'Ward Leonard Motor', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4468, 25, 1, '132080902018', 'Sound Level Calibrator', 'Sound Level Calibrator adalah perangkat yang digunakan untuk mengkalibrasi dan memastikan keakuratan perangkat pengukur tingkat suara, seperti sound level meter. Perangkat ini penting untuk menjaga keandalan dan keakuratan perangkat pengukuran tingkat suara.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4469, 25, 1, '132080902019', 'Digital Caliper', 'Digital caliper adalah alat pengukur presisi yang digunakan untuk mengukur dimensi suatu objek dengan tingkat akurasi yang tinggi. Ini adalah perangkat pengukur yang umum digunakan dalam berbagai aplikasi', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4470, 9, 1, '132080110177', 'D\'Alhendred Motor', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4471, 25, 1, '132080902020', 'Thermocouple Calibrator', 'thermocouple calibrator adalah presisi sumber kalibrasi dan alat ukur untuk mengukur suhu atau output analog melalui termokopel soket mengukur kategori termasuk °C, °F dan mV sinyal.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4472, 9, 1, '132080110178', 'Motor Induksi', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4473, 25, 1, '132080903001', 'Lux Meter (Alat Laboratorium Cahaya, Optik Dan Akustik)', 'Lux meter adalah alat pengukur intensitas cahaya yang digunakan untuk mengukur tingkat pencahayaan dalam suatu ruangan atau lingkungan tertentu. Alat ini bekerja dengan mengukur jumlah cahaya yang diterima di suatu area tertentu, yang diukur dalam satuan lux.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4474, 9, 1, '132080110179', 'Electric Network', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4475, 25, 1, '132080903002', 'Optical Power Meter', 'Optical power meter adalah perangkat yang digunakan untuk mengukur daya optik dalam suatu sistem transmisi atau jaringan serat optik. Alat ini digunakan untuk mengukur daya cahaya yang dipancarkan atau diterima oleh serat optik dan memberikan informasi tentang kekuatan atau intensitas cahaya dalam bentuk nilai numerik.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4476, 9, 1, '132080110180', 'Universal Programmer and Testor', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4477, 25, 1, '132080903003', 'Photo Meter', 'Photometer adalah alat atau perangkat yang digunakan untuk mengukur intensitas cahaya atau transmisi cahaya dari suatu sumber cahaya atau melalui medium tertentu. Ini digunakan dalam berbagai aplikasi, termasuk dalam ilmu pencahayaan, fotometri, analisis kimia, dan bidang lainnya di mana pengukuran intensitas cahaya atau penyerapan cahaya adalah penting.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4478, 25, 1, '132080903004', 'Sound Level Meter (Alat Laboratorium Cahaya, Optik Dan Akustik)', 'Sound Level Meter (SLM) adalah alat yang digunakan untuk mengukur tingkat tekanan suara atau intensitas suara di lingkungan tertentu. Alat ini penting dalam mengukur kebisingan di tempat kerja, lingkungan perkotaan, area konstruksi, dan bidang lain di mana pengukuran tingkat kebisingan atau keamanan lingkungan akustik diperlukan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4479, 9, 1, '132080110182', 'Anc Milling Machine', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4480, 25, 1, '132080904001', 'Multi Meter / AVO Meter', 'Multimeter atau AVO meter (Ampere-Volt-Ohm meter) adalah alat ukur serba guna yang digunakan untuk mengukur beberapa parameter listrik seperti arus (ampere), tegangan (volt), dan resistansi (ohm). Alat ini sangat berguna dalam pemecahan masalah, perbaikan, instalasi, dan pemeliharaan sistem listrik, serta aplikasi di bidang elektronika, industri, dan laboratorium.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4481, 9, 1, '132080110183', 'Boat Light', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4482, 25, 1, '132080904002', 'Ampere Meter / Clamp Meter', 'Ampere Meter atau Clamp Meter adalah jenis khusus dari alat pengukur yang dirancang untuk mengukur arus listrik dalam sebuah konduktor tanpa perlu menyentuh atau memutus sirkuit listrik tersebut. Alat ini sering disebut juga sebagai tongkat ampere atau penjepit ampere karena bentuknya yang dapat menggenggam atau menggenggam konduktor.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4483, 9, 1, '132080110184', 'Surface And Pore Size Analyzer', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4484, 25, 1, '132080904003', 'Tacho Meter', 'alat pengukur yang digunakan untuk mengukur kecepatan rotasi suatu objek atau putaran per menit (RPM) dari suatu mesin atau peralatan yang berputar. Alat ini umumnya digunakan untuk mengukur kecepatan rotasi dari mesin-mesin yang berputar seperti mesin-mesin industri, mesin kendaraan, atau peralatan berputar lainnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4485, 9, 1, '132080110185', 'Echo Sonder Trenduser', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4486, 25, 1, '132080904004', 'Phase Detector', 'perangkat atau sirkuit elektronik yang digunakan untuk mendeteksi perbedaan fase antara dua sinyal atau gelombang. Detektor fase sangat berguna dalam berbagai aplikasi dalam bidang elektronika, telekomunikasi, dan sistem kontrol.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4487, 9, 1, '132080110186', 'Steam House Mala', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4488, 25, 1, '132080904005', 'Earth / Ground Tester', 'alat yang digunakan untuk mengukur resistansi atau impedansi sistem penghantar tanah pada instalasi listrik. Alat ini dirancang untuk memastikan bahwa sistem grounding atau penangkaran tanah berfungsi dengan baik, yang sangat penting untuk keamanan listrik pada berbagai aplikasi seperti bangunan, situs industri, jaringan distribusi daya, dan lainnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4489, 9, 1, '132080110187', 'Buoysmoke Similar', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4490, 25, 1, '132080904007', 'Cable Tester', 'Cable Tester adalah alat yang digunakan untuk menguji konektivitas dan integritas kabel. Ini digunakan untuk memeriksa apakah kabel jaringan, kabel listrik, atau kabel lainnya berfungsi dengan baik atau tidak, serta untuk mengetahui apakah ada gangguan, kerusakan, atau gangguan dalam kabel tersebut.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4491, 25, 1, '132080904008', 'Insulation Tester (Alat Laboratorium Listrik Dan Mekanik)', 'Insulation Tester, juga dikenal sebagai Megger (merk dagang yang umum digunakan untuk peralatan semacam ini), adalah alat yang digunakan untuk mengukur resistansi isolasi pada kabel, peralatan listrik, atau sistem listrik lainnya. Alat ini menguji kekuatan isolasi untuk memastikan bahwa tidak ada kebocoran arus yang dapat terjadi antara konduktor yang terisolasi dan ground atau antara konduktor yang berbeda dalam rangkaian.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4492, 25, 1, '132080904009', 'DC / AC Power Supply', 'alat atau perangkat yang mengubah arus listrik dari bentuk searah (DC) menjadi arus bolak-balik (AC) atau sebaliknya. Ini penting dalam banyak aplikasi di berbagai industri dan kebutuhan teknologi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4493, 25, 1, '132080904011', 'Electric Measuring', 'alat dan instrumen khusus untuk mengukur tegangan, arus, resistansi, daya, dan parameter listrik lainnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4494, 25, 1, '132080904013', 'Pipe And Cable Locator', 'alat yang digunakan untuk menemukan lokasi dan kedalaman pipa bawah tanah, kabel, atau infrastruktur tersembunyi lainnya. Alat ini digunakan dalam industri konstruksi, instalasi kabel, perbaikan pipa, dan pekerjaan infrastruktur lainnya untuk membantu dalam menemukan dan memetakan jaringan pipa atau kabel sebelum melakukan penggalian atau pekerjaan konstruksi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4495, 25, 1, '132080904015', 'Vibration Meter', 'alat yang digunakan untuk mengukur dan menganalisis getaran dalam berbagai konteks, seperti mesin industri, struktur bangunan, kendaraan, peralatan listrik, dan lainnya. Alat ini memonitor tingkat getaran dan membantu dalam menentukan apakah tingkat getaran tersebut normal atau menunjukkan adanya masalah pada suatu sistem atau perangkat.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4496, 25, 1, '132080904016', 'Multi Function Counter', 'perangkat yang dapat melakukan beberapa fungsi penghitungan atau pengukuran dalam satu perangkat. Perangkat ini dapat membantu peneliti atau ahli laboratorium dalam mengumpulkan data dengan lebih efisien dan akurat.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4497, 25, 1, '132080904017', 'LCR Meter', 'perangkat yang digunakan untuk mengukur induktansi (L), kapasitansi (C), dan resistansi (R) dalam suatu komponen atau rangkaian listrik. Istilah "LCR" berasal dari simbol-simbol komponen dasar dalam elektronika: L untuk induktor (dalam henry), C untuk kapasitor (dalam farad), dan R untuk resistor (dalam ohm).', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4498, 25, 1, '132080905001', 'Temperature Tester', 'alat yang digunakan untuk mengukur suhu suatu objek atau lingkungan. Alat ini seringkali dirancang untuk memberikan pembacaan suhu yang akurat dan dapat digunakan dalam berbagai konteks, termasuk industri, laboratorium, rumah tangga, dan lainnya', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4499, 9, 1, '132080111007', 'Nessler', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4500, 25, 1, '132080905005', 'Thermometer Analog / Digital', 'Thermometer analog menggunakan skala yang tercetak pada dial atau layar fisik untuk menunjukkan suhu. Thermometer digital menampilkan suhu sebagai angka digital pada layar elektronik. Mereka menggunakan sensor elektronik yang mengonversi suhu menjadi sinyal listrik yang kemudian ditampilkan sebagai nilai numerik.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4501, 9, 1, '132080111008', 'Penagas', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4502, 25, 1, '132080905006', 'Thermocouple Switch Box', 'alat atau perangkat yang digunakan untuk mengelola dan menghubungkan beberapa thermocouple ke sistem pengukuran atau pemantauan. Ini membantu dalam mengukur suhu pada banyak titik dengan menggunakan thermocouple yang berbeda secara bersamaan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4503, 25, 1, '132080905007', 'Water Bath (Alat Laboratorium Tekanan Dan Suhu)', 'alat laboratorium yang digunakan untuk mempertahankan suhu konstan pada sampel yang ditempatkan di dalamnya. Alat ini terdiri dari wadah atau bak yang diisi dengan air yang dipanaskan atau didinginkan untuk mencapai dan mempertahankan suhu yang diinginkan. Umumnya, water bath memiliki kontrol suhu yang akurat untuk menjaga suhu secara konsisten.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4504, 25, 1, '132080905008', 'Pressure Gauge (Alat Laboratorium Tekanan Dan Suhu)', 'alat yang digunakan untuk mengukur tekanan dalam suatu sistem atau lingkungan. Alat ini memberikan pembacaan berdasarkan gaya tekanan yang diterima, yang kemudian ditampilkan sebagai nilai tekanan pada skala yang terbaca.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4505, 25, 1, '132080906001', 'Alat Uji Audit System', 'Perangkat atau instrumen yang digunakan untuk mengukur, memeriksa, dan menyesuaikan timbangan agar akurat dan sesuai dengan standar yang ditetapkan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4506, 25, 1, '132080906002', 'COD Meter', 'alat yang digunakan untuk mengukur Chemical Oxygen Demand dalam sampel air. Chemical Oxygen Demand (COD) merupakan parameter yang mengukur jumlah bahan organik teroksidasi kimia dalam suatu larutan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4507, 25, 1, '132080906010', 'Tang Ampere', 'tang ampere atau klip ampere, adalah alat yang digunakan untuk mengukur arus listrik yang mengalir melalui sebuah kawat atau sirkuit tanpa memutusnya. Tang ampere digunakan dalam bidang listrik dan elektronika untuk mengukur arus AC (arus bolak-balik) atau DC (arus searah) tanpa memerlukan pemutusan jalur listrik.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4508, 25, 1, '132080906011', 'Thermohygraph', 'alat pengukur yang menggabungkan fungsi pengukuran suhu (thermo) dan kelembaban (hygro). Alat ini dirancang untuk merekam dan memantau perubahan suhu dan kelembaban dalam suatu lingkungan atau ruang tertentu.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4509, 25, 1, '132080906012', 'Electromotor', 'perangkat yang mengubah energi listrik menjadi energi mekanik, yang menghasilkan gerakan berputar. Ini adalah salah satu jenis motor listrik yang paling umum digunakan di berbagai aplikasi, dari peralatan rumah tangga hingga industri besar.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4510, 25, 1, '132080906015', 'X-Y Recorder (Alat Laboratorium Standarisasi Kalibrasi & Instrumenstasi Lainnya)', 'X-Y Recorder digunakan dalam berbagai aplikasi, seperti laboratorium, industri, dan penelitian ilmiah, untuk merekam hubungan antara dua variabel yang berbeda.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4511, 25, 1, '132080906016', 'Kontrol Elektronik', 'teknologi yang melibatkan penggunaan sistem elektronik untuk mengatur atau mengontrol fungsi, operasi, atau perilaku suatu perangkat, sistem, atau proses tertentu.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4512, 25, 1, '132080906017', 'Data Loger', 'Data Logger adalah perangkat elektronik yang digunakan untuk merekam, menyimpan, dan memonitor data dari berbagai sensor atau sumber dalam jangka waktu tertentu. Alat ini dirancang untuk mengumpulkan informasi dalam waktu nyata atau sesuai dengan interval waktu yang telah ditentukan dan kemudian dapat menganalisis atau mengunduh data tersebut ke perangkat lain untuk evaluasi lebih lanjut.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4513, 25, 1, '132080906018', 'Magnetic Tape Recorder', 'Magnetic Tape Recorder adalah perangkat yang merekam dan memainkan suara atau data menggunakan pita magnetik. Pita magnetik adalah media penyimpanan yang digunakan untuk merekam informasi dalam bentuk sinyal magnetik pada permukaan pita yang sensitif terhadap medan magnet.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4514, 25, 1, '132080906019', 'Digital Multimeter (Alat Lab. Standarisasi Kalibrasi & Instrumenstasi Lainnya)', 'alat ukur listrik serbaguna yang digunakan untuk mengukur berbagai parameter listrik seperti tegangan (voltase), arus listrik, dan resistansi. Selain itu, beberapa multimeter digital juga dapat digunakan untuk mengukur kapasitansi, frekuensi, temperatur, dan pengujian transistor.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4515, 25, 1, '132080906021', 'Digital Indicator (Alat Lab. Standarisasi Kalibrasi & Instrumenstasi Lainnya)', 'Perangkat ini digunakan untuk mengukur dan menampilkan nilai-nilai yang diinginkan secara akurat dan presisi tinggi dalam lingkungan laboratorium atau industri yang memerlukan pengukuran yang tepat dan dapat diandalkan. Mereka sering digunakan dalam berbagai aplikasi pengukuran, termasuk pengukuran suhu, tekanan,', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4516, 25, 1, '132080906022', 'Deadweight Tester', 'Deadweight Tester adalah alat kalibrasi yang digunakan untuk mengukur tekanan dengan tingkat keakuratan yang tinggi. Alat ini menggunakan prinsip hukum Hooke dan prinsip Pascal untuk menghasilkan tekanan yang diketahui dan dikalibrasi dengan memanfaatkan gaya yang diterapkan oleh beban yang diketahui pada piston dan silinder yang diketahui pula.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4517, 9, 1, '132080111023', 'Bunson Burner', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4518, 25, 1, '132080906024', 'Temperatur Probe', 'Temperature probe adalah perangkat atau sensor yang digunakan untuk mengukur suhu dalam berbagai aplikasi. Probe ini berbentuk sensor atau elemen yang ditempatkan di area yang akan diukur suhunya. Ada berbagai jenis temperature probe yang digunakan tergantung pada lingkungan, aplikasi, dan akurasi yang dibutuhkan.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4519, 9, 1, '132080111024', 'Support Sheet Round', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4520, 25, 1, '132080906025', 'Paralel Control Network', 'Paralel Control Network" mungkin merujuk pada jaringan kontrol yang memungkinkan beberapa perangkat atau unit kontrol bekerja secara paralel untuk mengelola proses atau sistem tertentu.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4521, 25, 1, '132080906027', 'Logic Analizer', 'perangkat elektronik yang digunakan untuk memonitor dan menganalisis sinyal digital dalam sistem elektronik. Alat ini berguna untuk menangkap dan menganalisis pola sinyal digital pada berbagai saluran secara bersamaan. Fungsinya mirip dengan oscilloscope, tetapi lebih terfokus pada sinyal-sinyal digital.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4522, 25, 1, '132080907009', 'echo Sounder Portable', 'perangkat yang digunakan untuk mengukur kedalaman air di perairan seperti sungai, danau, atau laut. Alat ini menggunakan prinsip pengiriman sinyal suara ke dasar perairan dan kemudian merekam waktu yang diperlukan bagi sinyal tersebut untuk memantul kembali ke permukaan. Dari informasi ini, kedalaman air dapat dihitung.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4523, 25, 1, '132080907010', 'Altimeter (Alat Laboratorium Natius)', 'perangkat yang digunakan untuk mengukur ketinggian di atas permukaan tertentu, seperti pengukur ketinggian dalam penerbangan atau navigasi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4524, 25, 1, '132080908002', 'Lux Metter', 'alat yang digunakan untuk mengukur tingkat pencahayaan atau intensitas cahaya di suatu area. Alat ini memiliki sensor cahaya yang dapat mendeteksi berbagai tingkat intensitas cahaya dalam satuan lux.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4525, 25, 1, '132080908004', 'Multi Channel Radio Tester', 'perangkat yang digunakan untuk menguji berbagai fitur dan kinerja dari perangkat-perangkat radio atau komunikasi nirkabel. Ini mencakup pengujian untuk sejumlah saluran atau kanal radio dalam satu periode pengujian.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4526, 25, 1, '132080908007', 'Signal Generator (Alat Lab. Elektronika & Telekomunikasi Pelayaran)', 'alat yang digunakan untuk menghasilkan sinyal listrik dalam berbagai bentuk, seperti gelombang sinus, gelombang persegi, gelombang segitiga, atau sinyal lainnya dengan karakteristik tertentu seperti frekuensi, amplitudo, dan bentuk gelombang yang dapat disesuaikan. Dalam konteks "Elektronika & Telekomunikasi Pelayaran," Signal Generator digunakan untuk tujuan pengujian, pemeliharaan, atau pengembangan sistem komunikasi dan navigasi yang digunakan di kapal atau pelayaran.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4527, 25, 1, '132080908008', 'Deep Meter', 'alat yang digunakan dalam elektronika untuk mengukur frekuensi resonansi suatu rangkaian osilasi atau untuk mengukur induktansi atau kapasitansi dari sebuah komponen, seperti induktor atau kapasitor.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4528, 25, 1, '132080909003', 'Gas Leakage And Comsumtion Test', 'alat yang dapat digunakan untuk memeriksa kebocoran gas', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4529, 9, 1, '132080111033', 'Container Gas Chlorine', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4530, 25, 1, '132080909006', 'Laser Tester For Lenses', 'alat yang digunakan untuk menguji atau memeriksa lensa menggunakan teknologi laser. Ini merupakan perangkat khusus yang dirancang untuk memeriksa dan mengevaluasi karakteristik atau kualitas lensa dengan menggunakan prinsip-prinsip optik dan teknologi laser.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4531, 25, 1, '132080909010', 'Hygrometer Tester', 'perangkat yang digunakan untuk mengukur kelembaban atau kadar air dalam udara. Ini membantu dalam menentukan tingkat kelembaban relatif di lingkungan tertentu.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4532, 9, 1, '132080111035', 'Brightness Tester', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4533, 26, 1, '132080910001', 'Callibraion And Metrology', 'Kalibrasi dan metrologi adalah dua konsep yang penting dalam ilmu pengukuran dan pengujian. Keduanya memiliki peran vital dalam memastikan akurasi, keandalan, dan konsistensi perangkat ukur, instrumen, dan sistem.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4534, 26, 1, '132080910002', 'Standard Resistors Set', 'kumpulan resistor dengan nilai-nilai resistansi yang diketahui dan dikalibrasi dengan cermat. Kumpulan ini biasanya digunakan sebagai referensi atau standar dalam pengukuran resistansi dalam berbagai aplikasi teknik, laboratorium, industri, atau dalam proses kalibrasi peralatan pengukuran.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4535, 26, 1, '132080910005', 'Measurement Coprocessor Board Pc', 'papan atau kartu perangkat keras yang digunakan dalam sistem komputer untuk memproses data pengukuran atau informasi sensor yang diterima dari berbagai alat atau perangkat pengukuran.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4536, 26, 1, '132080910006', 'Type Approval Laboratorium', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4537, 26, 1, '132080910007', 'Power Sensor', 'Power sensor adalah perangkat yang digunakan untuk mengukur daya (power) yang dihasilkan oleh sumber daya atau perangkat elektronik. Perangkat ini memiliki fungsi khusus untuk mengukur parameter-parameter seperti daya listrik, tegangan, arus, dan faktor daya dalam suatu sistem elektronik.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4538, 26, 1, '132080910013', 'Foot Pedal', 'Perangkat yang dioperasikan dengan menggunakan kaki atau kaki dan kaki secara bersamaan. Foot pedal dirancang dengan berbagai bentuk dan ukuran, tergantung pada keperluan penggunaannya. Biasanya, foot pedal terhubung ke perangkat atau mesin yang dikontrolnya melalui kabel atau konektor nirkabel untuk mentransfer sinyal atau tekanan yang dihasilkan oleh kaki.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
