	(4669, 9, 1, '132080113033', 'Diyer', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4670, 27, 1, '132100101001', 'Mainframe (Komputer Jaringan)', 'Mainframe komputer adalah komputer yang digunakan terutama oleh organisasi besar untuk aplikasi kritis; pengolahan data massal, seperti sensus, industri dan statistik konsumen, perencanaan sumber daya perusahaan; dan pemrosesan transaksi. Mereka lebih besar dan memiliki kekuatan pemrosesan lebih dari beberapa kelas komputer lain: minicomputer, server, workstation, dan komputer pribadi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4671, 27, 1, '132100101002', 'Mini Komputer', 'Mini Komputer memiliki ukuran yang jauh lebih kecil, ukuran tinggi dan panjangnya hanya 12cm, daya yg dibutuhkan dari Mini PC hanya 10-12 watt saja sedangkan desktop memakan daya 20watt lebih. Performa MIni Komputer lebih rendah daripada Desktop, karena tidak memiliki kartu grafis sehingga tidak bisa digunakan untuk kegiatan gaming berat, desain grafis dan video editing.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4672, 27, 1, '132100101003', 'Local Area Network (LAN)', 'LAN singkatan dari Local Area Network (LAN) merupakan suatu jaringan komputer yang cakupannya wilayah lokal saja. LAN menghubungkan perangkat ke jaringan internet lewat perangkat jaringan yang sederhana.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4673, 9, 1, '132080113037', 'Chromato Jar', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4674, 27, 1, '132100101004', 'Internet', 'Internet adalah sistem jaringan komputer yang saling terhubung secara global dengan menggunakan paket protokol internet (TCP/IP) untuk menghubungkan perangkat di seluruh dunia.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4675, 9, 1, '132080113038', 'Chromatography Oven', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4676, 27, 1, '132100101005', 'Komputer Wedis', 'perangkat lunak yang digunakan di bidang medis untuk berbagai tujuan, seperti diagnosis, manajemen data pasien, pencatatan medis, pemantauan, penelitian medis, dan lain-lain. Ini adalah teknologi yang memainkan peran penting dalam transformasi perawatan kesehatan modern.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4677, 9, 1, '132080113039', 'Chromatogram Developping Apparatus/Chambler', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4678, 27, 1, '132100101006', 'Komputer Synergie', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4679, 27, 1, '132100101007', 'PC Workstation', 'PC workstation adalah komputer pribadi (personal computer) yang dirancang khusus untuk tugas-tugas berat atau profesional, seperti desain grafis, pengembangan perangkat lunak, rekayasa, dan keperluan komputasi intensif lainnya. Workstation biasanya dilengkapi dengan spesifikasi tinggi, termasuk prosesor yang kuat, memori besar, kartu grafis yang canggih, dan penyimpanan berkapasitas tinggi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4680, 9, 1, '132080113041', 'TLC Drying Rachs', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4681, 27, 1, '132100101008', 'Digital Signage', 'Digital signage adalah bentuk tampilan informasi digital yang digunakan untuk menampilkan konten multimedia, seperti teks, gambar, video, atau informasi grafis lainnya. Sistem ini umumnya terdiri dari layar digital besar atau beberapa layar yang terhubung ke jaringan komputer atau server pusat.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4682, 27, 1, '132100102001', 'P.C Unit', 'PC unit merujuk pada satu unit atau satu set sistem komputer pribadi (Personal Computer). Ini mencakup semua komponen yang diperlukan untuk menjalankan sebuah komputer, seperti CPU (Central Processing Unit), motherboard, RAM (Random Access Memory), penyimpanan (hard drive atau SSD), kartu grafis, power supply, , Mouse dan keyboard', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4683, 9, 1, '132080113043', 'Netrogin Analyzer', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4684, 27, 1, '132100102002', 'Lap Top', 'Laptop adalah komputer portabel dengan spesifikasi\n- prosesor kencang, contohnya: Intel seri Core i3, i5, i7 atau lebih besar lagi. \n- ukuran layar mulai dari 11 – 17 inci. \n- memiliki VGA diskrit\n- kapasitas RAM laptop lebih besar mulai dari 8GB sampai 32GB \n- Memiliki dua buah kipas yang masing-masing diletakan di prosesor dan VGA.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4685, 9, 1, '132080113044', 'Preasure Sterilizer', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4686, 27, 1, '132100102003', 'Note Book', 'Note Book adalah komputer portabel dengan spesifikasi\n- Prosesor yg digunakan biasanya menggunakan seri Celeron atau Pentium. Sedangkan untuk AMD biasanya menggunakan AMD Athlon \n- ukuran layar mulai dari 8 – 13 inci. \n- Memiliki VGA integrated dari prosesor.\n- kapasitas RAM 4gb\n- Daya tahan baterai tinggi', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4687, 9, 1, '132080113045', 'Melt Indexer (Alat Laboratorium Kimia)', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4688, 27, 1, '132100102004', 'Palm Top', 'PalmTop PC adalah komputer bertenaga baterai seukuran kalkulator yang muat untuk masuk saku. komputer ini didesain sepertihalnya kulit kerang dengan keyboard dan layar terintegrasi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4689, 9, 1, '132080113046', 'Westover Type Frioctono Meter', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4690, 27, 1, '132100102005', 'Code Breaker Super Komputer', 'jenis komputer zaman dahulu, barangnya sudah langka dan sudah tidak memungkinkan untuk digunakan', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4691, 9, 1, '132080113047', 'Brannock', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4692, 27, 1, '132100102006', 'Thinclient', 'Thinclient adalah istilah yang merujuk pada komputer ringan atau aplikasi perangkat lunak yang sangat bergantung pada server pusat untuk menjalankan tugas pemrosesan. Secara umum, thin client tidak memiliki daya pemrosesan atau penyimpanan yang kuat, sehingga sebagian besar beban kerja pemrosesan dilakukan oleh server.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4693, 27, 1, '132100102007', 'Net Book', 'Netbook adalah komputer portabel dengan spesifikasi:\n- Ukuran layar netbook biasanya 7-10inchi\n- Memiliki prosesor yang lebih rendah, \n- Memiliki RAM lebih sedikit\n- Untuk penggunaan dipakai untuk mengerjakan tugas-tugas ringan,video. \n- Menggunakan sistem operasi yang lebih ringan seperti Windows 10 S atau sistem operasi berbasis web seperti Chrome OS.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4694, 9, 1, '132080113049', 'E N T K A S', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4695, 27, 1, '132100102008', 'Ultra Mobile P.C.', 'Ultra Mobile Personal Computer (UMPC) Komputer ini tenar pada tahun 2000 dengan spesifikasi: \n- Beratnya ringan dengan ukuran layar 5-7 inch\n- Penggunaanya untuk kegiatan ringan seperti membuka browser\n- Ukuranya kecil sehingga mudah dibawa kemana-mana', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4696, 27, 1, '132100102009', 'Tablet PC', 'perangkat yang menggabungkan elemen dari laptop dan tablet dalam satu perangkat yang serbaguna. Mereka memiliki kemampuan untuk berfungsi sebagai laptop tradisional dengan keyboard yang terpisah, namun juga dapat diubah menjadi mode tablet dengan cara melipat layarnya atau melepas keyboardnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4697, 9, 1, '132080113051', 'Dry Blending', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4698, 28, 1, '132100201001', 'Card Reader (Peralatan Mainframe)', 'Card reader adalah perangkat keras atau pembaca kartu yang digunakan untuk membaca data dari kartu magnetik, kartu chip, atau kartu berkode pita. Beberapa card reader juga dapat membaca kartu memori seperti Secure Digital (SD) atau microSD yang umum digunakan pada kamera, ponsel, atau perangkat digital lainnya. Card reader biasanya terhubung ke komputer atau perangkat lain melalui USB atau jenis konektor lainnya. Card Reader Mainframe berukuran cenderung lebih besar dibanding Card Reader Mini Komputer dan digunakan dalam lingkungan bisnis atau organisasi besar yang membutuhkan pemrosesan data dalam skala besar', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4699, 28, 1, '132100201002', 'Magnetic Tape Unit (Peralatan Mainframe)', 'Magnetic tape adalah media penyimpanan yang menggunakan lapisan tipis yang dapat dibuat menjadi magnet pada seutas pita plastik. Ini sering digunakan untuk cadangan data dan penyimpanan arsip karena kapasitasnya yang tinggi dan efisiensinya secara ekonomis. Magnetic Tape Unit dalam konteks mainframe digunakan untuk membaca dan menulis data pada pita magnetik dalam sistem komputer besar atau mainframe', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4700, 9, 1, '132080113053', 'Hide Prosessor', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4701, 28, 1, '132100201003', 'Floppy Disk Unit (Peralatan Mainframe)', 'Floppy disk adalah media penyimpanan magnetik, terdiri dari cakram tipis dan fleksibel yang dilapisi bahan magnetik dan ditempatkan dalam casing plastik. Ukuran yang umum adalah 8 inch. Floppy disk digunakan untuk menyimpan dan mentransfer data pada awal perkembangan komputer. Floppy Disk Unit dalam konteks mainframe digunakan untuk membaca dan menulis data pada floppy disk dalam sistem komputer besar atau mainframe.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4702, 28, 1, '132100201004', 'Storage Modul Disk (Peralatan Mainframe)', 'Storage modul disk dapat berupa berbagai bentuk, seperti hard disk drives (HDD), solid-state drives (SSD), atau bahkan modul penyimpanan khusus yang dirancang untuk keperluan tertentu.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4703, 28, 1, '132100201005', 'Console Unit (Peralatan Mainframe)', 'Console unit mainframe adalah bagian dari sistem komputer besar yang berfungsi sebagai antarmuka pengguna dan kontrol utama. Ini adalah tempat di mana operator atau pengguna dapat berinteraksi dengan sistem, memberikan perintah, dan memantau berbagai informasi terkait dengan kinerja sistem. Console unit biasanya dilengkapi dengan layar monitor, keyboard, dan mungkin perangkat masukan lainnya untuk memudahkan pengoperasian dan pemantauan sistem secara langsung.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4704, 9, 1, '132080113056', 'Alat Untuk Mensol Fenasi Minyak Pelumas', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4705, 28, 1, '132100201006', 'CPU (Peralatan Mainframe)', 'Central Processing Unit adalah komponen utama dalam sebuah komputer yang bertanggung jawab untuk mengeksekusi instruksi-instruksi program. CPU berfungsi sebagai "otak" komputer, melakukan operasi aritmetika, logika, dan kontrol yang diperlukan untuk menjalankan program-program perangkat lunak. Ini merupakan pusat pengolahan data dalam sistem komputer, dan kinerjanya memiliki dampak langsung pada kecepatan dan efisiensi komputer secara keseluruhan. CPU terletak di motherboard dan sering dianggap sebagai inti dari sistem komputer.  CPU mainframe dapat diatur untuk bekerja secara paralel dengan multipleksing instruksi-instruksi untuk pemrosesan yang lebih cepat dan efisien.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4706, 28, 1, '132100201007', 'Disk Pack (Peralatan Mainframe)', 'Disk pack adalah media penyimpanan data yang terdiri dari beberapa piringan datar (disk) yang disusun bersama dalam satu paket atau kumpulan. Setiap piringan dalam disk pack biasanya dapat berputar secara independen. Setiap sisi piringan dapat digunakan untuk menyimpan data, dan kepala pembaca-penulis bergerak di atas permukaan piringan untuk membaca atau menulis informasi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4707, 9, 1, '132080113058', 'SPI Flame Ability (Alat Laboratorium Kimia)', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4708, 28, 1, '132100201008', 'Hard Copy Console', 'Peralatan Hard Copy Console ini memungkinkan pengguna untuk menghasilkan salinan fisik dari dokumen atau data yang ada pada komputer, menyediakan output yang dapat dilihat atau dipegang secara fisik. Berikut adalah beberapa peralatannya; printer, Scanner dengan Fungsi Pencetakan (All-in-One Printer), Plotter, Mesin Pencetakan Offset, Konsol Pencetakan (Print Console).', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4709, 28, 1, '132100201009', 'Serial Printer', 'Printer serial adalah jenis printer yang menerima data secara berurutan, satu byte atau karakter pada satu waktu, melalui koneksi serial. Koneksi serial ini dapat menggunakan antarmuka seperti RS-232 atau USB (meskipun USB lebih umum digunakan untuk printer modern). Printer serial digunakan untuk mencetak dokumen atau teks secara berurutan tanpa perlu menyimpan seluruh dokumen dalam memori printer.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4710, 9, 1, '132080113060', 'Laboratory Spry Dryer', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4711, 28, 1, '132100201010', 'Line Printer', 'Line printer adalah jenis printer yang mencetak satu baris teks atau grafik pada suatu waktu. Printer ini bekerja dengan cara membentuk satu baris penuh pada setiap siklus cetakannya. Line printer biasanya digunakan untuk mencetak dokumen dengan volume yang besar dan seringkali digunakan dalam lingkungan bisnis atau industri.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4712, 9, 1, '132080113061', 'Lacto Meter', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4713, 28, 1, '132100201011', 'Plotter (Peralatan Mainframe)', 'Plotter komputer adalah perangkat keras yang digunakan untuk mencetak grafik vektor dengan presisi tinggi. Perbedaan utama antara plotter dan printer konvensional adalah bahwa plotter menggunakan pena atau alat serupa untuk menggambar garis secara langsung pada kertas, sedangkan printer tradisional mencetak gambar dengan cara memindahkan tinta atau toner ke permukaan kertas. Plotter yang digunakan dalam lingkungan mainframe cenderung memiliki skala dan kapabilitas yang lebih besar. Mereka sering digunakan untuk tugas-tugas yang membutuhkan presisi tinggi dalam pemetaan, desain rekayasa, atau aplikasi teknis yang kompleks dalam lingkungan industri atau bisnis yang besar. Plotter pada mainframe bisa memiliki kecepatan, presisi, dan resolusi yang sangat tinggi karena sering digunakan untuk tugas-tugas profesional yang memerlukan akurasi tinggi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4714, 28, 1, '132100201012', 'Hard Disk', 'Hard disk adalah perangkat penyimpanan data magnetik yang digunakan dalam komputer untuk menyimpan informasi secara permanen. Hard disk digunakan untuk menyimpan sistem operasi, program aplikasi, dan data pengguna. Keuntungan utama hard disk adalah kapasitas penyimpanan yang besar dan kecepatan akses yang cukup tinggi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4715, 28, 1, '132100201013', 'Keyboard (Peralatan Mainframe)', 'Keyboard adalah perangkat input yang digunakan untuk memasukkan data ke dalam komputer atau perangkat lainnya. Ini terdiri dari sejumlah tombol yang mewakili karakter, angka, simbol, dan fungsi khusus. Pengguna menggunakan keyboard untuk mengetik teks, perintah, atau memasukkan data numerik ke dalam komputer. Kabel yang digunakan untuk alat ini adalah kabel usb', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4716, 28, 1, '132100201014', 'Steamer', 'Sebuah perangkat keras yang berfungsi sebagai kontroler untuk mempermudah pengoperasian selama streaming. Stream Deck menyediakan tombol konfigurasi yang dapat diatur dengan berbagai fungsi dan perintah.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4717, 9, 1, '132080113065', 'Road Coater', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4718, 28, 1, '132100201015', 'Data Patch Panel', 'Patch panel adalah suatu perangkat dalam sistem jaringan yang berfungsi sebagai titik pusat untuk mengelola dan menghubungkan kabel. Data patch panel digunakan khususnya untuk mengelola kabel data dalam konteks jaringan komputer.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4719, 9, 1, '132080113066', 'Alat Pemisah Buih(Foam Seperator)', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4720, 28, 1, '132100201017', 'Panaboard', 'Papan tulis interaktif yang dikembangkan oleh perusahaan elektronik Jepang, Panasonic. Panaboard dirancang untuk meningkatkan pengalaman presentasi dan kolaborasi di ruang rapat atau kelas dengan memadukan teknologi digital dan papan tulis tradisional.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4721, 28, 1, '132100202001', 'Card Reader (Peralatan Mini Komputer)', 'Card reader adalah perangkat keras atau pembaca kartu yang digunakan untuk membaca data dari kartu magnetik, kartu chip, atau kartu berkode pita. Beberapa card reader juga dapat membaca kartu memori seperti Secure Digital (SD) atau microSD yang umum digunakan pada kamera, ponsel, atau perangkat digital lainnya. Card reader biasanya terhubung ke komputer atau perangkat lain melalui USB atau jenis konektor lainnya', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4722, 28, 1, '132100202002', 'Magnetic Tape Unit (Peralatan Mini Komputer)', 'Magnetic tape adalah media penyimpanan yang menggunakan lapisan tipis yang dapat dibuat menjadi magnet pada seutas pita plastik. Ini sering digunakan untuk cadangan data dan penyimpanan arsip karena kapasitasnya yang tinggi dan efisiensinya secara ekonomis', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4723, 28, 1, '132100202003', 'Floppy Disk Unit (Peralatan Mini Komputer)', 'Floppy disk adalah media penyimpanan magnetik yang digunakan pada masa lalu, terdiri dari cakram tipis dan fleksibel yang dilapisi bahan magnetik dan ditempatkan dalam casing plastik. Ukuran yang umum adalah 3,5 inci dan 5,25 inci. Floppy disk digunakan untuk menyimpan dan mentransfer data pada awal perkembangan komputer pribadi sebelum ditinggalkan karena kemunculan teknologi penyimpanan yang lebih canggih.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4724, 28, 1, '132100202004', 'Storage Modul Disk (Peralatan Mini Komputer)', 'Storage modul disk dapat berupa berbagai bentuk, seperti hard disk drives (HDD), solid-state drives (SSD), atau bahkan modul penyimpanan khusus yang dirancang untuk keperluan tertentu.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4725, 9, 1, '132080113071', 'Gas Orsat Apparatus', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4726, 28, 1, '132100202005', 'Console Unit (Peralatan Mini Komputer)', 'Console unit adalah bagian dari sistem komputer besar yang berfungsi sebagai antarmuka pengguna dan kontrol utama. Ini adalah tempat di mana operator atau pengguna dapat berinteraksi dengan sistem, memberikan perintah, dan memantau berbagai informasi terkait dengan kinerja sistem. Console unit biasanya dilengkapi dengan layar monitor, keyboard, dan mungkin perangkat masukan lainnya untuk memudahkan pengoperasian dan pemantauan sistem secara langsung.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4727, 28, 1, '132100202006', 'CPU (Peralatan Mini Komputer)', 'Central Processing Unit adalah komponen utama dalam sebuah komputer yang bertanggung jawab untuk mengeksekusi instruksi-instruksi program. CPU berfungsi sebagai "otak" komputer, melakukan operasi aritmetika, logika, dan kontrol yang diperlukan untuk menjalankan program-program perangkat lunak. Ini merupakan pusat pengolahan data dalam sistem komputer, dan kinerjanya memiliki dampak langsung pada kecepatan dan efisiensi komputer secara keseluruhan. CPU terletak di motherboard dan sering dianggap sebagai inti dari sistem komputer.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4728, 9, 1, '132080113073', 'Alat Ultra Filtrasi', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4729, 28, 1, '132100202007', 'Disk Pack (Peralatan Mini Komputer)', 'Disk pack adalah media penyimpanan data yang terdiri dari beberapa piringan datar (disk) yang disusun bersama dalam satu paket atau kumpulan. Setiap piringan dalam disk pack biasanya dapat berputar secara independen. Setiap sisi piringan dapat digunakan untuk menyimpan data, dan kepala pembaca-penulis bergerak di atas permukaan piringan untuk membaca atau menulis informasi.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4730, 28, 1, '132100202008', 'Plotter (Peralatan Mini Komputer)', 'Plotter adalah perangkat output khusus yang digunakan untuk mencetak gambar besar atau rencana teknik dengan tingkat presisi tinggi. Plotter ini dapat terhubung ke personal computer (PC) dan digunakan untuk mencetak gambar berukuran besar dengan detail yang tinggi, seringkali digunakan dalam bidang seperti desain grafis, arsitektur, atau ilustrasi teknis.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4731, 9, 1, '132080113075', 'Melting Point Apparatus Thermolyn', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4732, 28, 1, '132100202009', 'Scanner (Peralatan Mini Komputer)', 'Scanner komputer adalah perangkat keras yang digunakan untuk mengonversi gambar atau dokumen fisik menjadi data digital. Dengan menggunakan teknologi optik, scanner memindai gambar atau teks pada dokumen dan mengubahnya menjadi file digital yang dapat disimpan, diedit, atau dibagikan melalui komputer.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4733, 9, 1, '132080113076', 'Portable Oil Counter Meter', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4734, 28, 1, '132100202010', 'Computer Compatible', 'Computer Compatible adalah personal computer atau PC yang kompatibel dengan perangkat keras dan perangkat lunak intel x86 yang digunakan oleh PC IBM dan mampu menggunakan perangkat keras yang dapat diganti-ganti.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4735, 9, 1, '132080113077', 'Soxtec System (TECATOR)', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4736, 28, 1, '132100202011', 'Viewer (Peralatan Mini Komputer)', 'Menampilkan atau memproyeksikan konten visual dengan kualitas dan resolusi yang sesuai.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4737, 28, 1, '132100202012', 'Digitizer (Peralatan Mini Komputer)', 'Digitizer adalah perangkat keras atau teknologi yang digunakan untuk mengonversi input analog menjadi data digital. Fungsi utama digitizer adalah mengubah sinyal analog, seperti gerakan pena atau sentuhan pada permukaan tertentu, menjadi data digital yang dapat dipahami oleh komputer atau perangkat digital lainnya.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4738, 9, 1, '132080113079', 'T I T R A T O R', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4739, 28, 1, '132100202013', 'Keyboard (Peralatan Mini Komputer)', 'Keyboard adalah perangkat input yang digunakan untuk memasukkan data ke dalam komputer atau perangkat lainnya. Ini terdiri dari sejumlah tombol yang mewakili karakter, angka, simbol, dan fungsi khusus. Pengguna menggunakan keyboard untuk mengetik teks, perintah, atau memasukkan data numerik ke dalam komputer. Perbedaan keyboard pada masa ini adalah kabel yang digunakan KVM Kabel', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4740, 28, 1, '132100202014', 'Auto Switch/Data Switch', 'Auto switch atau data switch adalah perangkat yang memungkinkan pengguna untuk mengalihkan atau berbagi sumber data, seperti komputer, printer, atau perangkat lain, antara beberapa tujuan tanpa harus menyambung dan melepaskan kabel secara manual. Fungsi utama dari auto switch atau data switch adalah memudahkan pengguna dalam berpindah antara berbagai perangkat atau tujuan dengan cepat dan mudah.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4741, 28, 1, '132100202016', 'Speaker Komputer', 'Speaker computer adalah perangkat suara yang terhubung ke komputer untuk memainkan suara, musik, atau audio dari perangkat tersebut. Speaker komputer dapat berupa speaker internal yang terpasang di dalam casing komputer atau speaker eksternal yang terhubung melalui port audio pada komputer. Fungsinya adalah menghasilkan output suara untuk mendengarkan audio dengan kualitas yang lebih baik.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4742, 28, 1, '132100203001', 'CPU (Peralatan Personal Komputer)', 'Central Processing Unit adalah komponen utama dalam sebuah komputer yang bertanggung jawab untuk mengeksekusi instruksi-instruksi program. CPU berfungsi sebagai "otak" komputer, melakukan operasi aritmetika, logika, dan kontrol yang diperlukan untuk menjalankan program-program perangkat lunak. Ini merupakan pusat pengolahan data dalam sistem komputer, dan kinerjanya memiliki dampak langsung pada kecepatan dan efisiensi komputer secara keseluruhan. CPU terletak di motherboard dan sering dianggap sebagai inti dari sistem komputer.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4743, 28, 1, '132100203002', 'Monitor', 'Monitor adalah perangkat output visual yang digunakan untuk menampilkan informasi atau gambar yang dihasilkan oleh komputer atau perangkat elektronik lainnya. Monitor biasanya memiliki layar datar dan berbagai ukuran, dan dapat menampilkan teks, gambar, video, atau antarmuka grafis pengguna. Monitor dapat terhubung ke komputer melalui berbagai jenis koneksi, seperti HDMI, DisplayPort, atau VGA, dan merupakan bagian penting dari setup komputer untuk menampilkan informasi kepada pengguna.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4744, 28, 1, '132100203003', 'Printer (Peralatan Personal Komputer)', 'Printer adalah perangkat output yang digunakan untuk mencetak dokumen atau gambar dari komputer ke media cetak, seperti kertas. Printers dapat menggunakan berbagai teknologi, termasuk inkjet, laser, atau dot matrix, dan mereka mampu mencetak teks, grafik, atau foto sesuai dengan instruksi yang diberikan oleh komputer atau perangkat lainnya', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4745, 28, 1, '132100203004', 'Scanner (Peralatan Personal Komputer)', 'Scanner komputer adalah perangkat keras yang digunakan untuk mengonversi dokumen fisik atau gambar menjadi data digital yang dapat diolah oleh komputer. Scanner bekerja dengan cara memindai atau menangkap gambar dan mengubahnya menjadi format digital.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4746, 9, 1, '132080113086', 'Freenes Tester', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4747, 28, 1, '132100203005', 'Plotter (Peralatan Personal Komputer)', 'Plotter adalah perangkat output khusus yang digunakan untuk mencetak gambar besar atau rencana teknik dengan tingkat presisi tinggi. Plotter ini dapat terhubung ke personal computer (PC) dan digunakan untuk mencetak gambar berukuran besar dengan detail yang tinggi, seringkali digunakan dalam bidang seperti desain grafis, arsitektur, atau ilustrasi teknis.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4748, 28, 1, '132100203006', 'Viewer (Peralatan Personal Komputer)', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4749, 9, 1, '132080113088', 'Ink Huber Tester', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4750, 28, 1, '132100203007', 'External', 'Peralatan eksternal komputer merujuk pada berbagai perangkat keras atau aksesori yang dapat dihubungkan ke komputer dari luar untuk meningkatkan fungsionalitas atau memberikan pengalaman yang lebih luas.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4751, 9, 1, '132080113089', 'Hydropulper', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4752, 28, 1, '132100203008', 'Digitizer (Peralatan Personal Komputer)', 'Digitizer dalam konteks peralatan komputer dapat merujuk pada perangkat keras atau perangkat lunak yang memungkinkan pengguna untuk mengonversi input analog menjadi data digital.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4753, 9, 1, '132080113090', 'Niagara Beater', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4754, 28, 1, '132100203009', 'Keyboard (Peralatan Personal Komputer)', 'Keyboard adalah perangkat input yang digunakan untuk memasukkan data ke dalam komputer atau perangkat lainnya. Ini terdiri dari sejumlah tombol yang mewakili karakter, angka, simbol, dan fungsi khusus. Pengguna menggunakan keyboard untuk mengetik teks, perintah, atau memasukkan data numerik ke dalam komputer.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4755, 28, 1, '132100203010', 'CD Writter', 'CD writer, atau sering disebut juga sebagai CD burner, adalah perangkat keras yang digunakan untuk menulis atau merekam data ke dalam CD (Compact Disc). CD writer memungkinkan pengguna untuk membuat salinan data, membuat CD musik, atau membuat CD yang dapat dibaca di berbagai perangkat CD player.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4756, 9, 1, '132080113092', 'HCL Burner', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4757, 28, 1, '132100203011', 'DVD Writer', 'DVD writer adalah perangkat keras yang digunakan untuk menulis atau merekam data ke dalam DVD (Digital Versatile Disc). Mirip dengan CD writer, DVD writer memungkinkan pengguna untuk membuat salinan data, membuat DVD video, atau menyimpan data yang besar.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4758, 9, 1, '132080113093', 'Packing Test', NULL, NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4759, 28, 1, '132100203012', 'Firewire Card', 'Firewire card adalah kartu ekspansi yang menambahkan konektivitas Firewire (juga dikenal sebagai IEEE 1394 atau i.LINK) ke komputer. Firewire adalah standar transfer data serial berkecepatan tinggi yang umum digunakan untuk menghubungkan perangkat digital seperti kamera video, hard drive eksternal, antarmuka audio, dan perangkat multimedia lainnya ke komputer.', NULL, NULL, '2026-04-30 03:15:54', '2026-04-30 03:15:54'),
	(4760, 9, 1, '132080113094', 'Concora Unit', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4761, 28, 1, '132100203013', 'Capture Card', 'Capture card adalah perangkat keras yang digunakan untuk menangkap sinyal audio dan video dari perangkat eksternal, seperti konsol permainan, kamera, atau perangkat pemutar video. Capture card memungkinkan pengguna untuk merekam, mengedit, atau melakukan streaming langsung dari sumber-sumber ini ke komputer atau perangkat lainnya.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4762, 28, 1, '132100203014', 'LAN Card', 'LAN Card, atau sering disebut juga dengan Network Interface Card (NIC) atau Ethernet Card, adalah perangkat keras yang memungkinkan komputer untuk terhubung ke jaringan lokal (Local Area Network atau LAN). Fungsinya adalah mengelola komunikasi antara komputer dan jaringan, memungkinkan pertukaran data dan sumber daya antar komputer dalam jaringan tersebut.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4763, 9, 1, '132080113096', 'Phase Conterase', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4764, 28, 1, '132100203015', 'External CD/ DVD Drive (ROM)', 'External CD dapat merujuk pada perangkat eksternal yang digunakan untuk membaca dan menulis CD (Compact Disc). Ini sering kali berupa drive CD eksternal yang terhubung ke komputer atau perangkat lain melalui port USB. External CD drives berguna jika perangkat Anda tidak memiliki drive CD internal.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4765, 28, 1, '132100203016', 'External Floppy Disk Drive', 'External floppy disk drive adalah perangkat keras eksternal yang digunakan untuk membaca dan menulis data ke dalam floppy disk. External floppy disk drive bisa terhubung ke komputer atau perangkat lain melalui port USB, memberikan kemampuan membaca dan menulis data dari atau ke floppy disk.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4766, 28, 1, '132100203017', 'External/ Portable Hardisk', 'External portable hard disk adalah perangkat penyimpanan eksternal yang kompak dan dapat dibawa ke mana-mana. Biasanya terhubung ke komputer atau perangkat lain melalui port USB atau Thunderbolt. Portable hard disk digunakan untuk menyimpan dan mentransfer data, seperti file, foto, video, atau cadangan sistem.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4767, 9, 1, '132080113099', 'Densitometer For Protein', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4768, 28, 1, '132100203018', 'Mouse (Peralatan Personal Komputer)', 'Mouse adalah perangkat input komputer yang digunakan untuk mengontrol gerakan kursor di layar.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4769, 28, 1, '132100203019', 'Flash Disk/ Memory Card', 'Flashdisk adalah perangkat portabel kecil yang disambungkan ke port USB pada komputer Anda. Drive USB biasanya digunakan untuk penyimpanan, pencadangan data, serta transfer file antar perangkat.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4770, 28, 1, '132100204001', 'Server', 'Server adalah sebuah komputer atau sistem komputer yang menyediakan layanan, sumber daya, atau fungsi tertentu kepada komputer-komputer lainnya, yang disebut klien. Server dapat mengelola akses ke berbagai jenis sumber daya seperti file, printer, basis data, atau layanan jaringan lainnya.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4771, 28, 1, '132100204002', 'Router', 'Router adalah perangkat jaringan yang digunakan untuk mengarahkan lalu lintas data antara dua atau lebih jaringan. Fungsi utama router adalah memutuskan jalur terbaik untuk mengirim paket data dari satu jaringan ke jaringan lainnya.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4772, 28, 1, '132100204003', 'Hub', 'Hub adalah perangkat jaringan yang berfungsi sebagai simpul penyambung untuk menghubungkan beberapa perangkat dalam suatu jaringan lokal (LAN).', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4773, 28, 1, '132100204004', 'Modem', 'Modem adalah perangkat yang mengubah sinyal digital dari komputer atau perangkat lainnya menjadi sinyal analog yang dapat dikirimkan melalui jalur komunikasi seperti jalur telepon atau kabel koaksial, dan sebaliknya.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4774, 28, 1, '132100204005', 'Netware Interface External', 'antarmuka jaringan eksternal atau perangkat keras tambahan yang digunakan untuk menyediakan konektivitas jaringan pada suatu sistem atau perangkat. Ini dapat mencakup berbagai perangkat keras atau metode koneksi yang memungkinkan perangkat terhubung ke jaringan eksternal.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4775, 9, 1, '132080113106', 'Iso Enzym Electrophoresis', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4776, 28, 1, '132100204006', 'Repeater and Transciever', 'Repeater dan transceiver adalah dua perangkat yang umumnya digunakan dalam konteks jaringan dan komunikasi. Repeater digunakan untuk memperpanjang jarak jaringan atau sinyal komunikasi dengan menguatkan kembali atau mengulang sinyal yang lemah. Lalu Transceiver (transmitter-receiver) adalah perangkat yang menyatukan fungsi pengirim dan penerima dalam satu unit.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4777, 9, 1, '132080113107', 'Imono Electrophoresis', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4778, 28, 1, '132100204010', 'Head Copy Printer', 'Printer head adalah komponen penting yang menyemprotkan tinta ke kertas untuk mencetak gambar atau teks. Printer head ini bisa berupa bagian terpisah yang dapat diganti atau bagian yang terintegrasi dengan cartridge tinta.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4779, 9, 1, '132080113108', 'Imono Chemistry', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4780, 28, 1, '132100204011', 'Character Terminal', 'Terminal komputer adalah perangkat keras elektronik atau elektromekanis yang dapat digunakan untuk memasukkan data ke dalam, dan menyalin [1] data dari, komputer atau sistem komputasi . [2] Teletype adalah contoh terminal hard copy masa awal [ 3] dan mendahului penggunaan layar komputer selama beberapa dekade. Dimulai pada pertengahan tahun 1970-an dengan mesin seperti Sphere 1 , Sol-20 , dan Apple I , sirkuit terminal mulai diintegrasikan ke dalam sistem komputer pribadi dan stasiun kerja , dengan komputer menangani pembuatan karakter dan menghasilkan output ke tampilan CRT seperti a monitor komputer atau, terkadang, TV konsumen.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4781, 28, 1, '132100204012', 'Graphic Terminal', 'Graphic terminal adalah jenis terminal komputer yang dapat menampilkan grafik dan karakter teks. Graphic terminal memungkinkan tampilan visual yang lebih kaya, termasuk gambar, grafik, dan antarmuka pengguna berbasis grafis.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4782, 28, 1, '132100204013', 'Terminal', 'Terminal listrik berguna untuk menghubungkan semua perangkat elektronik dengan arus listrik. Melalui kabel listrik, maka arus listrik akan dihantarkan ke alat-alat elektronik sehingga dapat digunakan.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4783, 28, 1, '132100204014', 'Rak Server', 'Rak server adalah struktur fisik yang dirancang untuk menampung dan menyusun perangkat server dan peralatan jaringan lainnya dalam sebuah pusat data atau ruang server.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4784, 28, 1, '132100204015', 'Firewall', 'Firewall adalah perangkat lunak atau perangkat keras yang dirancang untuk mengamankan jaringan komputer dari akses yang tidak diinginkan, serangan, atau lalu lintas berbahaya. Fungsinya mirip dengan tembok yang melindungi suatu bangunan dari bahaya luar.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4785, 28, 1, '132100204016', 'Switch Rak', 'Switch rak, atau sering disebut sebagai "rack-mounted switch," adalah perangkat switch jaringan yang dirancang untuk dipasang di dalam rak server atau pusat data. Ini memungkinkan pengelolaan konektivitas dan distribusi lalu lintas data di dalam ruang server atau pusat data secara efisien.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4786, 9, 1, '132080113114', 'Trombelastograph', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4787, 28, 1, '132100204017', 'Wanscaller', 'WANScaler adalah produk Citrix yang dikembangkan untuk mempercepat pengiriman aplikasi melalui WAN dengan memanfaatkan teknologi kompresi, caching, dan deduplikasi data.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4788, 28, 1, '132100204018', 'E-Mail Security', 'Email security, atau keamanan surel, merujuk pada langkah-langkah dan teknologi yang diimplementasikan untuk melindungi komunikasi melalui email dari ancaman keamanan dan risiko kebocoran informasi.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4789, 28, 1, '132100204019', 'Client Clearing House', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4790, 9, 1, '132080113117', 'Pengukur Dissolution', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4791, 28, 1, '132100204020', 'CAT 6 Cable', 'CAT 6 (Category 6) cable adalah jenis kabel jaringan yang digunakan untuk menghubungkan perangkat dalam jaringan komputer. Kabel ini merupakan versi yang ditingkatkan dari CAT 5e (Category 5e) dan dirancang untuk mendukung kecepatan transfer data yang lebih tinggi.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4792, 9, 1, '132080113118', 'Detection (Alat Uni Katalis dan Bio katalis)', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4793, 28, 1, '132100204021', 'Kabel UTP', 'Kabel UTP (Unshielded Twisted Pair) adalah jenis kabel yang digunakan untuk menghubungkan perangkat dalam jaringan komputer.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4794, 28, 1, '132100204022', 'Wireless PCI Card', 'Wireless PCI Card adalah perangkat kartu yang terpasang pada slot PCI (Peripheral Component Interconnect) di dalam komputer, yang memungkinkan komputer tersebut terhubung ke jaringan nirkabel. PCI Card ini menyediakan konektivitas Wi-Fi dan memungkinkan komputer untuk berkomunikasi dengan jaringan Wi-Fi, seperti hotspot atau router nirkabel.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4795, 28, 1, '132100204023', 'Wireless Access Point', 'Wireless Access Point (WAP) adalah perangkat keras yang memungkinkan perangkat nirkabel, seperti komputer atau smartphone, untuk terhubung ke jaringan kabel yang ada melalui teknologi Wi-Fi.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4796, 28, 1, '132100204024', 'Switch', 'Switch adalah perangkat keras dalam jaringan komputer yang digunakan untuk menghubungkan perangkat-perangkat dalam jaringan dan memfasilitasi pertukaran data di antara mereka. Fungsi utama switch adalah untuk mengirimkan data hanya ke perangkat tujuan yang sesuai, bukan ke seluruh jaringan, sehingga meningkatkan efisiensi penggunaan bandwidth dan mengoptimalkan kinerja jaringan.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4797, 28, 1, '132100204025', 'Hubbel UTP', 'UTP merupakan singkatan dari "Unshielded Twisted Pair" atau dalam Bahasa Indonesia dikenal sebagai "Pasangan Berpilin Tidak Dilapisi." UTP adalah jenis kabel jaringan yang terdiri dari sepasang kawat tembaga yang diisolasi dan dililit bersama untuk membentuk pasangan berpilin. Kabel UTP digunakan untuk menghubungkan perangkat jaringan seperti komputer, switch, router, atau perangkat lainnya dalam jaringan lokal.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4798, 28, 1, '132100204026', 'Acces Point', 'Access Point (AP) adalah perangkat keras dalam jaringan nirkabel yang berfungsi sebagai titik akses atau pintu masuk untuk perangkat nirkabel, seperti laptop, smartphone, atau tablet, untuk terhubung ke jaringan kabel atau jaringan nirkabel yang lebih besar.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4799, 9, 1, '132080114003', 'Thin Layer Chromatography Apparatus', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4800, 28, 1, '132100204027', 'Rackmount', 'Desain perangkat keras atau perangkat elektronik yang dirancang untuk dipasang di rak (rack) standar. Rack ini biasanya digunakan dalam pusat data, ruang server, atau lingkungan IT lainnya. Desain rackmount memungkinkan perangkat tersebut untuk ditempatkan secara terorganisir dalam ruang yang terbatas, dengan memanfaatkan ukuran standar dan penempatan yang seragam.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4801, 28, 1, '132100204028', 'KVM Keyboard Video Monitor', 'KVM Keyboard Video Monitor adalah sebuah solusi atau perangkat yang memungkinkan pengguna untuk mengontrol beberapa komputer atau server menggunakan satu set perangkat input (keyboard, mouse, dan monitor).', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4802, 28, 1, '132100204029', 'Mobile Modem GSM/ CDMA', '"Mobile Modem GSM/CDMA" adalah perangkat modem seluler yang mendukung konektivitas jaringan GSM (Global System for Mobile Communications) dan/atau CDMA (Code Division Multiple Access). Modem seluler ini memungkinkan perangkat seperti laptop atau komputer tablet untuk terhubung ke internet menggunakan jaringan seluler nirkabel.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4803, 28, 1, '132100204030', 'Network Cable Tester', 'Network Cable Tester adalah perangkat yang digunakan untuk menguji dan memeriksa kabel jaringan guna memastikan bahwa instalasi kabel tersebut berfungsi dengan baik. Alat ini membantu teknisi atau administrator jaringan dalam mengidentifikasi masalah kabel seperti koneksi yang rusak, kabel yang putus, atau penyambungan yang tidak benar.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4804, 9, 1, '132080114007', 'Refrigerator Bath', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4805, 28, 1, '132100204031', 'Jaringan Satpas', 'Jaringan yang digunakan khusus oleh Satuan Penyelenggara Administrasi SIM', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4806, 28, 1, '132100204032', 'NComputing', 'NComputing adalah sebuah perangkat thinclient dengan dimensi kecil dan hemat daya yang di lengkapi dengan desktop virtualization software.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4807, 28, 1, '132100205001', 'Software/Aplikasi Lainnya', 'Perangkat lunak, atau yang biasa disebut "software," merujuk pada serangkaian instruksi atau program komputer yang dirancang untuk melaksanakan tugas-tugas tertentu, mengendalikan operasi perangkat keras komputer, atau memberikan fungsionalitas spesifik kepada pengguna.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4808, 9, 1, '132080114012', 'Clorida Meter', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4809, 9, 1, '132080114020', 'Cryout Microtoma', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4810, 9, 1, '132080114023', 'Flotation Bath', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4811, 9, 1, '132080114027', 'Prothrombin Timer', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4812, 9, 1, '132080114033', 'Automatic Dilluter Complete', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4813, 9, 1, '132080114041', 'Microgasometer', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4814, 29, 1, '132150101001', 'Radiasi Panas', 'Perangkat yang digunakan untuk mendeteksi atau mengukur tingkat radiasi panas atau suhu suatu objek atau lingkungan.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4815, 29, 1, '132150101002', 'Radiasi Radioaktif', 'Alat yang digunakan untuk mengukur atau mendeteksi keberadaan radiasi ionisasi dalam lingkungan.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4816, 29, 1, '132150101003', 'Radiasi Medan Magnit', 'Alat deteksi radiasi medan magnet atau alat ukur medan magnet, umumnya dikenal sebagai magnetometer, digunakan untuk mengukur intensitas atau kekuatan medan magnet di suatu lokasi atau dalam suatu ruangan.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4817, 30, 1, '132150201001', 'Baju Anti Panas', 'Baju anti panas atau baju pelindung panas adalah jenis pakaian pelindung yang dirancang khusus untuk melindungi pemakainya dari panas, api, atau bahaya suhu tinggi.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4818, 9, 1, '132080115005', 'Electrophoresis Chamber', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4819, 30, 1, '132150201002', 'Baju Anti Radiasi', 'Baju anti radiasi adalah pakaian pelindung yang dirancang untuk mengurangi atau memblokir paparan radiasi terhadap tubuh manusia.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4820, 30, 1, '132150202002', 'Masker Debu', 'Masker debu, juga dikenal sebagai masker partikulat atau masker N95, adalah alat perlindungan pernapasan yang dirancang untuk melindungi penggunanya dari paparan partikel debu, serbuk, dan partikel-partikel kecil lainnya yang dapat membahayakan kesehatan pernapasan.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4821, 30, 1, '132150203002', 'Tambang Terbuka', 'Topi kerja yang dapat memberikan perlindungan dan kenyamanan di lingkungan yang terbuka dan terkena sinar matahari. Topi kerja khusus untuk pertambangan terbuka biasanya memiliki beberapa fitur yang dirancang untuk mengakomodasi kondisi kerja di lapangan, terutama untuk menjaga keselamatan.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4822, 9, 1, '132080115008', 'Electrophoresis Market', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4823, 30, 1, '132150203004', 'Helmet', 'Helmet (helm) adalah alat pelindung yang dirancang untuk melindungi kepala dari potensi cedera atau bahaya lainnya.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4824, 30, 1, '132150205002', 'Sepatu Tahan Tekanan', 'Sepatu Safety adalah jenis sepatu pelindung yang dirancang khusus untuk memberikan perlindungan terhadap tekanan atau beban eksternal yang dapat merusak kaki. Sepatu ini umumnya digunakan dalam lingkungan kerja di mana risiko terkena tekanan atau benturan pada pekerjaan kontruksi', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4825, 9, 1, '132080115010', 'Absorbant Pads And Trips', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4826, 30, 1, '132150205003', 'Sepatu Anti Arus Listrik', 'Sepatu anti arus listrik, juga dikenal sebagai sepatu anti-estatis, adalah jenis sepatu pelindung yang dirancang khusus untuk mengurangi risiko kejutan listrik atau elektrik. Mereka digunakan dalam lingkungan kerja di mana terdapat risiko paparan terhadap listrik statis atau sumber arus listrik.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4827, 30, 1, '132150205004', 'Sepatu Anti Licin', 'Sepatu anti licin atau sepatu pelindung anti-slip adalah sepatu yang dirancang khusus untuk memberikan perlindungan terhadap risiko licin dan membantu mencegah kecelakaan tergelincir.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4828, 30, 1, '132150205005', 'Sepatu Boot', 'Fire Boots adalah jenis sepatu yang di rancang untuk memberikan perlindungan terutama di sekitar pergelangan kaki dan betis. sepatu ini dapat mengurangi radiasi panas dan aman terhadap bahan kimia', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4829, 31, 1, '132150301001', 'Rescue Seat/Winch', 'Kursi penyelamat adalah alat untuk membantu memindahkan pasien dalam jarak dekat. Kursi Penyelamat terbuat dari vinil bertulang kuat yang mudah dibersihkan dan tahan terhadap darah dan cairan tubuh.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4830, 31, 1, '132150301002', 'Rescue Jaring Harnes', 'Alat yang digunakan untuk mengurangi risiko cedera fatal akibat terjatuh dari ketinggian. Didesain untuk melindungi seluruh bagian tubuh pekerja seperti bahu, paha bagian atas, dada, dan panggul, sehingga lebih aman saat melakukan penyelamatan.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4831, 9, 1, '132080115015', 'Immunodiffusion Puch Set', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4832, 31, 1, '132150301004', 'Life Jacket', 'Baju pelampung merupakan perangkat yang dirancang untuk membantu pemakai, baik secara sadar atau di bawah sadar, untuk tetap mengapung dengan mulut dan hidung berada di atas permukaan air atau pada saat berada dalam air.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4833, 9, 1, '132080115016', 'Consist Of', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4834, 31, 1, '132150301005', 'Lifebuoy', 'Lifebuoy adalah alat keselamatan kapal berupa ban pelampung. Fungsinya adalah untuk dilemparkan ke laut ketika ada yang jatuh dari kapal. life buoy ini juga memiliki standar internasional sesuai dengan regulasi SOLAS alias Safety of Life at Sea.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4835, 31, 1, '132150301006', 'Inflatable Life Craft', 'Liferaft adalah sebutan untuk perahu karet dengan tenda pelindung dan dilengkapi obat-obatan, perbekalan makanan dan minuman untuk keadaan darurat. Bahkan liferaft dilengkapi beberapa benda untuk memberi tanda signal, dan alat-alat keselamatan lainnya. Liferaft dan semua perlengkapannya itu biasanya dirancang agar pemakainya dapat bertahan hidup selama satu minggu sebelum regu penolong datang.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4836, 31, 1, '132150301010', 'Nylon Rope', 'Tali karamantel yaitu tali yang terbuat dari serat sintetis alias serat buatan yaitu nilon.Tali jenis ini populer karena lentur dan kuat, serta tahan gesekan.Tali ini digunakan sebagai alat keselamatan untuk mengikat atau sebagai sabuk keselamatan yang dipakai bersamaan dengan alat-alat lainnya.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4837, 9, 1, '132080115019', 'Dye Set And 2,5 mm Wrech', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4838, 31, 1, '132150301013', 'Bright Descender', 'Descender adalah perangkat yang digunakan untuk mengontrol atau mengatur laju turun selama kegiatan panjat tebing, pekerjaan ketinggian, atau dalam konteks SAR.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4839, 31, 1, '132150301014', 'Carabiner Kecil', 'Carabiner adalah alat penolong yang umum digunakan dalam berbagai kegiatan outdoor dan industri. Carabiner adalah cincin logam dengan pintu pengunci yang dapat dibuka dan ditutup untuk mengaitkan atau menggantung peralatan', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4840, 9, 1, '132080115021', 'Immuno Frame Holder', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4841, 31, 1, '132150301015', 'Ranger Boots', 'Sepatu pelindung kaki yang digunakan saat bekerja di lokasi ekstrem. Penggunaan rscuer boots harus sesuai dengan tujuan desainnya karena tidak semua rescue boots memiliki fitur keamanan yang sama. Pastikan untuk memilih model yang sesuai dengan kebutuhan dan aktivitas dan perlu untuk mematuhi petunjuk penggunaan serta panduan keselamatan yang diberikan oleh produsen.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4842, 9, 1, '132080115022', 'Immuno Leveling Table Set', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4843, 31, 1, '132150301020', 'Back Pack/Ransel', 'Backpack penyelamatan dapat digunakan untuk menyimpan peralatan dan perlengkapan yang diperlukan dalam situasi darurat atau penyelamatan. Biasanya, backpack ini dirancang khusus untuk keperluan penyelamatan di air, seperti kecelakaan perahu atau keadaan darurat di sekitar perairan. Isinya dapat mencakup pelampung, alat sinyal, peralatan medis kecil, dan barang-barang penting lainnya yang dapat membantu dalam situasi darurat saat berada di lingkungan air.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4844, 9, 1, '132080115023', 'Stainless Steel Tongs', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4845, 31, 1, '132150301021', 'Tandu', 'Tandu penyelamatan adalah perangkat yang dirancang khusus untuk membawa atau mengangkut orang yang terluka atau membutuhkan bantuan darurat dari suatu lokasi ke lokasi lain dengan aman. Tandu penyelamatan umumnya digunakan dalam berbagai konteks, termasuk penyelamatan di perairan, pendakian gunung, evakuasi dari gedung bertingkat, dan situasi darurat lainnya. Mereka biasanya ringan, mudah dibawa, dan sering dilengkapi dengan fasilitas pengikat atau pengaman untuk menjaga keamanan pasien selama pemindahan.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4846, 9, 1, '132080115024', 'Suction Needless (2,6 mm dia)', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4847, 31, 1, '132150302004', 'Sleeping Bag', 'Sleeping bag, atau kantung tidur, adalah peralatan camping yang dirancang untuk memberikan tempat tidur yang nyaman dan hangat di lingkungan outdoor. Sleeping bag terdiri dari kantong berbentuk tabung yang diisi dengan bahan isolasi untuk menjaga tubuh tetap hangat.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4848, 9, 1, '132080115025', 'Staining And Rising Tanks', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4849, 31, 1, '132150302005', 'Tenda', 'Tenda merupakan salah satu item penting dalam survival kit, terutama jika Anda berada di alam terbuka atau menghadapi situasi darurat di luar ruangan.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4850, 31, 1, '132150302006', 'Fire Starter', 'Pemantik api adalah alat penting dalam perlengkapan bertahan hidup, membantu Anda menyalakan api dengan cepat dan andal dalam berbagai kondisi.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4851, 9, 1, '132080115027', 'Measuring Magnifier', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4852, 31, 1, '132150302007', 'Alat Pendaki/Mountainering', 'Alat pendaki atau peralatan pendakian dirancang untuk memberikan keamanan, kenyamanan, dan dukungan selama kegiatan pendakian gunung atau hiking.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4853, 31, 1, '132150302009', 'Topi Pengaman', 'Topi pengaman atau helm keamanan adalah bagian penting dari peralatan keselamatan dalam kegiatan SAR (Search and Rescue) atau pencarian dan penyelamatan. Helm ini dirancang untuk melindungi kepala dari potensi cedera akibat benturan, serpihan, atau bahaya lainnya yang dapat terjadi selama operasi SAR.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4854, 9, 1, '132080115029', 'Measuring Magnifier Microtiterkit', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4855, 31, 1, '132150302011', 'Scuba', 'Peralatan Selam atau "scuba" (self-contained underwater breathing apparatus) mencakup serangkaian alat yang memungkinkan penyelam untuk bernapas di bawah air. Alat selam berfungsi sebagai alat bantu pernapasan, memungkinkan penyelam menghirup udara dari tabung tekanan yang dibawa oleh penyelam.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4856, 9, 1, '132080115030', 'Titration Plates U Wells', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4857, 31, 1, '132150302012', 'Tenda Pleton', 'Tenda Pleton mungkin mengacu pada tenda yang digunakan oleh kelompok besar atau pasukan militer, terutama untuk kegiatan pelatihan atau lapangan. Tenda peloton biasanya dirancang untuk menampung sejumlah besar orang dalam satu unit.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4858, 9, 1, '132080115031', 'Titration Plates V Wells', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4859, 31, 1, '132150302013', 'Tenda Sangga', 'Tenda sangga (atau kadang-kadang disebut juga sebagai tenda puncak) adalah jenis tenda yang umumnya digunakan untuk acara-acara luar ruangan atau pameran. Tenda ini memiliki kerangka yang kokoh dan sangga (tiang penyangga) di tengah, memberikan ruang tanpa tiang di bagian tengah tenda', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4860, 31, 1, '132150302014', 'Tenda Pelampang', 'Tenda ini merupakan tenda yang menggunakan bahan terpaulin dan bahan polister D600 dengan rangka besi tebal berkualitas sebagai rangkanya. Tenda plampang jenis ini juga banyak digunakan untuk berbagai kegiatan pesta, hajatan, promosi, bazar dan lain-lain', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4861, 31, 1, '132150302017', 'Thermal Imaging Camera', 'Thermal imaging cameras adalah perangkat yang dapat mendeteksi radiasi inframerah (panas) dari objek dan membuat gambar berdasarkan perbedaan suhu. Berbeda dengan kamera tradisional, kamera thermal imaging dapat "melihat" dan menghasilkan gambar dalam kegelapan total atau melalui penghalang seperti asap atau kabut.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4862, 31, 1, '132150302018', 'Peralatan Life Detector', 'Peralatan Life Detector adalah alat atau perangkat yang dirancang khusus untuk mendeteksi keberadaan manusia atau makhluk hidup lainnya dalam situasi darurat atau bencana. Peralatan ini biasanya digunakan oleh tim penyelamat atau petugas keamanan untuk mencari dan mengevakuasi orang yang mungkin terjebak di bawah reruntuhan bangunan, bencana alam, atau kondisi darurat lainnya.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4863, 9, 1, '132080115035', 'Filter Cartigges', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4864, 31, 1, '132150303002', 'Wet Suit', 'Wetsuit adalah pakaian khusus yang dirancang untuk digunakan di dalam air, terutama di air yang dingin. Fungsi utama dari wetsuit adalah untuk menyediakan perlindungan dan menjaga suhu tubuh ketika berada di dalam air dingin.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4865, 9, 1, '132080115036', 'Suction Bulb', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4866, 31, 1, '132150303003', 'Mesh Bag', 'Mesh bag dirancang khusus untuk membawa atau menyimpan peralatan penyelamatan atau barang yang relevan dengan tugas pencarian dan penyelamatan. Penggunaan mesh bag misalnya sebagai tas penyimpanan peralatan sar, penyimpanan alat medis, penyimpanan alat komunikasi, penyimpanan pakaian khusus, dan sebagainya.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4867, 31, 1, '132150303004', 'Fins', 'Sirip membantu penyelam bergerak lebih efisien di bawah air dan meningkatkan manuverabilitas.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4868, 9, 1, '132080115038', 'Deliveri Tester25 ul', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4869, 31, 1, '132150303005', 'Snorkel', 'Snorkel adalah peralatan selam berupa selang berbentuk huruf J dengan pelindung mulut di bagian ujung sebelah bawah. Alat ini berfungsi sebagai jalan masuk udara ketika bernapas dengan mulut tanpa harus mengangkat muka dari permukaan air.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4870, 31, 1, '132150303006', 'Regulator', 'Regulator menyediakan udara dari tangki selam ke penyelam melalui selang dan mouthpiece, memungkinkan penyelam untuk bernapas di bawah air.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4871, 31, 1, '132150303007', 'Dept Pressure Gauge', 'Depth gauge mengukur kedalaman penyelaman, sementara komputer selam memberikan informasi tambahan seperti waktu penyelaman, kecepatan penurunan, dan batas waktu penyelaman yang aman.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4872, 31, 1, '132150303008', 'Masker', 'Masker menyelam yang pas dan kedap air, dengan lensa yang memberikan penglihatan yang jelas di bawah air.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4873, 9, 1, '132080115042', 'Test Reading Mirror', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4874, 31, 1, '132150303009', 'Regulator Gauge', 'Regulator gauge adalah alat atau perangkat yang digunakan dalam penyelaman untuk mengukur tekanan udara di dalam tabung atau tangki selam. Regulator gauge ini memberikan informasi kepada penyelam tentang sisa udara yang tersedia dalam tangki selam, yang sangat penting untuk mengelola konsumsi udara dan menjaga keamanan selama penyelaman.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4875, 31, 1, '132150303011', 'Dive Boots', 'Dive boots adalah sepatu khusus yang dirancang untuk digunakan oleh penyelam selama kegiatan menyelam. Sepatu ini memberikan perlindungan dan kenyamanan saat berada di dalam atau di sekitar air. Sepatu selam memberikan perlindungan bagi kaki dan memberikan kenyamanan saat berada di dasar laut atau di atas permukaan yang kasar.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4876, 31, 1, '132150303013', 'Under Water Light', 'Underwater light atau lampu bawah air adalah perangkat pencahayaan yang dirancang khusus untuk digunakan di bawah air. Underwater lights sangat berguna dalam meningkatkan visibilitas di bawah air dan membantu penyelam atau fotografer bawah air melihat dengan lebih jelas di lingkungan yang gelap atau terbatas cahayanya.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4877, 31, 1, '132150303017', 'Compressor Udara', 'Compressor udara adalah perangkat mekanis yang digunakan untuk meningkatkan tekanan udara dengan mengompres atau memadatkan udara.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4878, 9, 1, '132080115046', 'Staining Jar', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4879, 31, 1, '132150303021', 'Alat Las Bawah Air', 'Alat las bawah air adalah peralatan yang digunakan untuk melakukan proses pengelasan di bawah air. Pengelasan bawah air sering kali diperlukan dalam proyek-proyek konstruksi bawah air, perbaikan struktur di bawah air, atau kegiatan maritim lainnya.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4880, 31, 1, '132150303025', 'Tabung Udara dg K Valve (Luxfer AL 80 cft)', 'Tabung yang berisi udara bersih yang digunakan oleh petugas penyelamat seperti tim pemadam kebakaran ketika memadamkan kobaran si jago merah, atau pun digunakan tim penyelamat lainnya.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4881, 31, 1, '132150303028', 'Fingerprint Kits', 'Fingerprint kits" adalah perangkat atau set alat yang digunakan untuk mengambil dan memproses sidik jari. Kit ini dapat digunakan untuk berbagai tujuan, termasuk keamanan, identifikasi personal, atau investigasi forensik.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4882, 31, 1, '132150303030', 'Pelampung Pribadi (PFD)', 'Pelampung Pribadi (Personal Flotation Device atau PFD) adalah peralatan keselamatan yang dirancang untuk membantu mengapungkan seseorang di air. Tujuan utama PFD adalah memberikan bantuan penyelamatan dan mencegah tenggelam bagi orang yang memakainya, terutama dalam situasi darurat atau kecelakaan di perairan.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4883, 31, 1, '132150303032', 'OHP 3 M', 'OHP 3M bisa merujuk pada Overhead Projector (OHP) yang diproduksi oleh perusahaan 3M. Overhead Projector adalah perangkat audiovisual yang digunakan untuk menampilkan gambar atau teks pada layar atau permukaan lain dengan memproyeksikan cahaya melalui transparansi khusus ke layar atau permukaan tersebut.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4884, 31, 1, '132150303034', 'Back Pack and Miller Harnes U/Tabung Udara', 'Sistem pengikat atau sabuk yang membentuk mekanisme pengangkutan pada sebuah ransel atau tas ransel. Komponen ini membantu agar tas ransel dapat dipakai di punggung pengguna dengan nyaman sambil mendistribusikan beban secara merata untuk menjaga keseimbangan dan mengurangi tekanan pada bahu dan punggung.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4885, 31, 1, '132150303035', 'Tas, Peralatan (Oceanic)', 'Tas peralatan selam yang dirancang khusus untuk membawa dan melindungi peralatan selam, seperti masker, tabung udara, kaki katak, dan perlengkapan selam lainnya. Sedangkan oceanic adalah nama merk.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4886, 31, 1, '132150303037', 'Alas, Tabung Udara Tangki 80 cft', 'Perangkat SCUBA akan menghasilkan mobilitas yang tinggi, namun mempunyai keterbatasan waktu tergantung dengan jumlah udara yang dimasukan kedalam tabung SCUBA. Umumnya tabung SCUBA terbuat dari bahan baja dan alumunium Alloys. Volume dan tekanan dari tabung SCUBA terdiri dari berbagai ukuran anatara lain dengan volume 50, 71, 80, 100 cuft (cubic feet).', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4887, 9, 1, '132080116001', 'Albuminometer', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4888, 31, 1, '132150303039', 'Kamera/Video dengan tempatnya U/ Bawah Air (Sea & Sea)', 'Perangkat fotografi atau video yang dirancang khusus untuk digunakan di dalam air. Kamera ini dirancang agar tahan terhadap air, sehingga dapat digunakan untuk mengambil gambar atau merekam video di bawah permukaan air.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4889, 31, 1, '132150303041', 'Tas Laptop, Kedap Air Untuk Membawa Laptop', 'Tas laptop waterproof adalah tas yang dirancang khusus untuk melindungi laptop Anda dari air dan elemen-elemen lainnya. Tas ini umumnya terbuat dari bahan tahan air atau dilengkapi dengan lapisan pelindung yang mencegah air masuk ke dalam tas.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4890, 31, 1, '132150303042', 'Clip, Selang & Octopus', 'Klip atau pengait yang digunakan untuk menempelkan selang octopus pada peralatan penyelaman.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4891, 31, 1, '132150303043', 'Overhaul Compresor', 'Proses perawatan menyeluruh yang dilakukan pada kompresor untuk memulihkan, memperbaiki, atau meningkatkan kinerjanya. Proses ini mencakup pemeriksaan menyeluruh, pemulihan, dan penggantian komponen-komponen yang mungkin mengalami keausan atau kerusakan selama penggunaan jangka panjang.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4892, 31, 1, '132150303049', 'Baju Dalam Dry Suite, Loong \'T\' dan Jhon (Whites MK 1)', 'Baju dalam drysuit (atau dikenal sebagai undergarment) adalah pakaian yang dikenakan di bawah drysuit untuk memberikan isolasi termal dan kenyamanan. Drysuit sendiri adalah pakaian yang dirancang untuk melindungi tubuh dari air, tetapi tidak memberikan isolasi termal secara signifikan. Oleh karena itu, baju dalam drysuit sangat penting untuk menjaga suhu tubuh dan memberikan kenyamanan selama penggunaan di lingkungan air dingin.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4893, 31, 1, '132150303051', 'Tube Sinyal Darurat', 'Dapat merujuk pada perangkat seperti tabung komunikasi portabel atau sistem komunikasi darurat yang digunakan untuk berkomunikasi dalam situasi darurat di mana sinyal telepon atau jaringan komunikasi lainnya tidak tersedia.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4894, 31, 1, '132150303052', 'Bantal Filter, Cadangan untuk Kompresor Bauner', 'Elemen filter udara atau filter cartridge yang digunakan dalam sistem filter udara kompresor. Filter udara sangat penting dalam menjaga kualitas udara yang masuk ke dalam kompresor, sehingga elemen filter ini perlu diganti secara berkala untuk memastikan kinerja yang optimal.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4895, 31, 1, '132150303056', 'Sepatu Katak, Baju Selam Kering / Dry Suite', 'Alat yang dikenakan pada kaki penyelam untuk membantu pergerakan di bawah air. Fins dirancang untuk meningkatkan efisiensi dan daya dorong penyelam dalam air, mengizinkan mereka berenang lebih cepat dan dengan lebih sedikit usaha.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4896, 31, 1, '132150303057', 'P3K, Advanced / Extended Care', 'P3K (Pertolongan Pertama pada Kecelakaan) atau juga dikenal sebagai alat pertolongan pertama, adalah peralatan yang digunakan untuk memberikan pertolongan awal pada situasi kecelakaan atau keadaan darurat. P3K berfungsi untuk memberikan perawatan pertama sebelum bantuan medis lebih lanjut tiba.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4897, 31, 1, '132150303058', 'Senter, Under Water Kinetic', 'Alat penerangan yang dirancang khusus untuk digunakan di bawah air. Senter ini biasanya tahan terhadap tekanan air dan dirancang untuk memberikan penerangan yang efektif dalam kondisi penyelaman.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4898, 31, 1, '132150303062', 'Harness, Safty (NZ Safety)', 'Penggunaan harness keselamatan atau alat pengikat tubuh yang dirancang khusus untuk penggunaan bawah air. Alat ini memiliki beberapa aplikasi, baik dalam kegiatan penyelaman rekreasi maupun pekerjaan bawah air.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4899, 9, 1, '132080116012', 'Water Distilation Apparatus (Alat Laboratorium Hematologi)', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4900, 31, 1, '132150303064', 'Hose Protectors (Pelindung Selam)', 'Hose protectors, atau pelindung selang selam, adalah aksesoris atau perlengkapan tambahan yang digunakan untuk melindungi selang selam dari kerusakan akibat gesekan, abrasi, atau kerusakan mekanis lainnya yang mungkin terjadi selama penyelaman. Pelindung selang ini dirancang untuk meningkatkan umur pakai selang dan mengurangi risiko kerusakan selama kegiatan penyelaman.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4901, 31, 1, '132150303065', 'Selang 65 cm LP', 'Bagian vital dari peralatan pemadam kebakaran yang digunakan untuk menyediakan air atau agen pemadam lainnya ke sumber api untuk memadamkan atau mengendalikan kebakaran.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4902, 31, 1, '132150303068', 'Selang Power Inflator Tekanan Rendah', 'Komponen yang umumnya ditemukan pada sistem buoyancy control device (BCD) atau vest penyelaman. Ini adalah salah satu komponen yang menghubungkan inflator (alat pemompa) pada BCD dengan sumber udara rendah, seperti tangki penyelam. Dalam konteks selam, "low pressure" mengacu pada tekanan yang lebih rendah, biasanya pada rentang 200 hingga 300 psi (pound per square inch).', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4903, 31, 1, '132150303069', 'Selang Tekanan Tinggi', 'Selang tekanan tinggi adalah jenis selang yang dirancang untuk menahan dan mengalirkan fluida atau gas di tekanan yang tinggi. Selang ini umumnya digunakan dalam berbagai industri, termasuk industri minyak dan gas, konstruksi, pertanian, serta dalam sistem hidrolik dan pneumatik. Selang tekanan tinggi harus dirancang dengan cermat untuk menangani tekanan yang tinggi sesuai dengan kebutuhan aplikasinya.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4904, 9, 1, '132080117001', 'Mesin Cuci B.W Negatif', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4905, 31, 1, '132150303070', 'Pisau Selam Mata Pisau Bergigi', 'Pisau selam mata pisau bergigi mengacu pada jenis pisau selam yang dirancang khusus untuk digunakan oleh penyelam di dalam air. Pisau ini sering digunakan sebagai alat multifungsi yang dapat membantu penyelam dalam berbagai tugas, seperti memotong tali, membersihkan ikan, atau mengatasi situasi darurat.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4906, 31, 1, '132150303074', 'Manifol Bail - Out Block (PCDS)', 'Manifold adalah sistem pengatur aliran gas yang menghubungkan dua tabung (cylinder) atau lebih. Manifold memungkinkan penyelam untuk mengelola aliran gas dari dua tabung yang terhubung. Bail-out block adalah komponen yang dapat terhubung ke manifold dan menyediakan jalur tambahan atau cadangan untuk penyelam. Ini biasanya digunakan sebagai cara untuk beralih ke tabung cadangan (bail-out cylinder) jika terjadi masalah dengan salah satu tabung utama. Manifold bail-out block dengan PCDS memungkinkan penyelam untuk mengelola persediaan gas mereka dengan lebih efisien dan memberikan cadangan tekanan udara yang dapat diakses dengan mudah dalam situasi darurat.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4907, 9, 1, '132080117003', 'Mesin Cuci Color ECA', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4908, 31, 1, '132150303075', 'Masker (Tusa Liberator)', 'Masker penyelaman adalah bagian penting dari peralatan penyelaman yang memberikan pelindung dan memungkinkan penyelam melihat dengan jelas di bawah air. Sedangkan Tusa Liberator merupakan salah satu merek dan model masker penyelaman yang diproduksi oleh Tusa, sebuah perusahaan peralatan selam ternama.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4909, 9, 1, '132080117004', 'Mesin Cuci Color ECP', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4910, 31, 1, '132150303078', 'Mouth Piece Dengan Cadangannya', 'Mouthpiece adalah bagian yang dimasukkan ke dalam mulut penyelam. Ini biasanya terbuat dari silikon atau bahan karet yang lembut dan fleksibel untuk kenyamanan. Mouthpiece dirancang untuk memudahkan penyelam dalam menahan dan melepaskan alat bernapas.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4911, 9, 1, '132080117005', 'Mesin Cuci Color CRI', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4912, 31, 1, '132150303082', 'O-Ring for Standart LP Hose', 'O-Ring untuk "Standard Tank Neck" (leher tangki standar) merujuk pada segel karet tipe O-ring yang digunakan pada leher atau leher tangki udara selam. Leher tangki adalah bagian yang menonjol dari tangki udara yang menyambungkan tangki ke regulator selam. O-Ring digunakan untuk memastikan kebocoran udara dan menjaga segel antara regulator dan tangki.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4913, 31, 1, '132150303085', 'Gulungan Tali Penetrasi 45 M', 'Gulungan tali penetrasi 45 meter adalah peralatan penyelaman yang digunakan oleh penyelam tek atau penyelam khusus yang melakukan penetrasi atau eksplorasi dalam lingkungan bawah air yang memiliki kompleksitas dan risiko tinggi. Gulungan tali ini merupakan bagian dari sistem tali penetrasi atau guideline reel yang memungkinkan penyelam untuk mengukur jarak dan memastikan jalur kembali selama penetrasi di dalam gua, reruntuhan kapal, atau lingkungan bawah air lainnya yang kompleks.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4914, 31, 1, '132150303088', 'Regulator Set (Scuba Pro MK 17/R)', 'ScubaPro MK17/R adalah sebuah set regulator penyelaman yang terdiri dari regulator MK17 dan regulator kedua (second stage) model R. Regulator ini merupakan perangkat kritis dalam peralatan penyelaman yang memastikan penyelam mendapatkan pasokan udara dengan aman dan efisien di bawah air.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4915, 31, 1, '132150303090', 'Pelumas Silikon 16 oz (Packet of 20)', 'Paket pelumas silikon seberat 16 oz (ounce) yang berjumlah 20 adalah kemasan yang cukup besar dan dapat berisi sejumlah besar pelumas silikon dalam bentuk cair atau semprotan. Pelumas silikon umumnya digunakan sebagai pelumas dan perlindungan pada alat-alat kerja bawah air.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4916, 31, 1, '132150303094', 'Swivel Universal HP', 'Swivel Universal HP (High Pressure) adalah perangkat yang digunakan dalam peralatan penyelaman untuk menghubungkan regulator tinggi tekanan (HP) dengan tabung penyelaman atau tangki penyelam. Fungsi utama dari swivel ini adalah memberikan fleksibilitas dan kenyamanan bagi penyelam dengan mengurangi tekanan pada selang HP dan regulator, sehingga memudahkan pergerakan kepala dan tubuh selama penyelaman.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4917, 31, 1, '132150303098', 'Jam Tangan Penyelam', 'Jam tangan penyelam adalah jam tangan yang digunakan oleh penyelam dan di desain untuk penyelaman dalam air, cocok untuk menyelam dengan pernapasan bawah air di kedalaman 100m (330 ft) atau lebih.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4918, 9, 1, '132080117011', 'Chemical Mixing', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4919, 32, 1, '132150401001', 'Automatic Message Switching Centre (AMSC)', 'Automatic Message Switching Centre (AMSC) adalah pusat yang mengoordinasikan dan mengelola pengiriman pesan dalam sistem telekomunikasi. Ini berfungsi untuk mengarahkan, menyaring, dan mengelola pesan yang dikirim antara berbagai titik dalam jaringan telekomunikasi.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4920, 32, 1, '132150401003', 'Teleprinter', 'Teleprinter merupakan alat perangkat elektromekanis yang dapat digunakan untuk mengirim dan menerima pesan yang diketik melalui berbagai saluran komunikasi. Perangkat ini digunakan sebelum era komputer modern dan merupakan metode utama untuk mengirim dan menerima pesan jarak jauh dalam bentuk teks.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4921, 9, 1, '132080117013', 'Destilasi', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4922, 32, 1, '132150401004', 'Direct Speech (DS)', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4923, 9, 1, '132080117014', 'Analistic Balance', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4924, 32, 1, '132150401005', 'Sistem Transmisi (Radio Link, VSAT)', 'Sistem Transmisi (Radio Link, VSAT) merupakan  stasiun penerima sinyal dari satelit dengan antena penerima berbentuk piringan untuk menerima dan mengirim data ke satelit', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4925, 32, 1, '132150401007', 'VHF Data Link', 'VHF Data Link atau VHF Digital Link (VDL) adalah sarana pengiriman informasi antara pesawat dan stasiun bumi (dan dalam kasus VDL Mode 4, pesawat lain)', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4926, 32, 1, '132150401008', 'Integrated Remote Control and Monitoring System (IRCMS)', 'IRCMS (Integrated Remote Control and Monitoring System) adalah sistem yang menggabungkan kontrol dan pemantauan dari jarak jauh untuk berbagai perangkat atau sistem. Biasanya digunakan dalam lingkungan di mana perangkat atau sistem tersebar luas atau berada di lokasi yang sulit diakses secara langsung.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4927, 9, 1, '132080117017', 'Tensitometer', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4928, 32, 1, '132150401012', 'Voice Recorder', 'black box" merujuk pada rekaman penerbangan atau flight data recorder dan cockpit voice recorder, dua perangkat yang terletak di bagian belakang pesawat dan digunakan untuk merekam data penerbangan serta percakapan di dalam kokpit.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4929, 32, 1, '132150402002', 'Very High Frequency Omni Directional Range (VOR)', 'Very High Frequency Omni Directional Range (VOR) adalah sistem navigasi udara yang digunakan oleh pesawat untuk menentukan arah dan posisi relatif terhadap stasiun pemancar darat. Sistem ini sangat penting dalam navigasi penerbangan, terutama sebelum era navigasi satelit.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4930, 32, 1, '132150402003', 'Distance Measuring Equipmnet (DME)', 'DME bekerja dengan menggunakan sinyal radio frekuensi tinggi untuk berkomunikasi antara pesawat dan stasiun tanah DME. Saat pesawat menerima sinyal dari stasiun DME, sistem tersebut mengukur waktu yang diperlukan untuk sinyal pergi dan kembali. Dengan mengetahui waktu tempuh sinyal, DME dapat menghitung jarak antara pesawat dan stasiun tanahnya.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4931, 32, 1, '132150402010', 'Flight Data Processing System/FPDS', 'suatu sistem yang memproses semua elemen informasi rencana penerbangan seperti antara lain : menerbitkan atau mencetak strip data penerbangan, informasi data, radar track, sistem penagihan (billing system) dan kebutuhan terkait dengan pelayanan lalu lintas udara. Dalam pemberian pelayanan lalu lintas udara, sistem harus dapat menerima, mengolah, menyalurkan dan menampilkan data-data.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4932, 32, 1, '132150404001', 'X-Ray Inspection Machine', 'Mesin inspeksi sinar-X memiliki berbagai ukuran dan kapasitas yang sesuai dengan kebutuhan spesifik dari aplikasi di berbagai industri. Mereka menjadi alat yang sangat penting untuk mengungkap detail internal yang tidak terlihat secara langsung, membantu dalam keamanan, kualitas produk, dan bidang-bidang lain yang memerlukan visualisasi struktur internal', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4933, 32, 1, '132150404003', 'Public Address Branch Exchange (PABX)', 'Alat untuk melakukan panggilan internal antar ekstensi di dalam organisasi tanpa memerlukan jalur eksternal. Selain itu, dengan PABX, ada fitur dan fungsi tambahan yang dapat diakses, seperti transfer panggilan, penyimpanan pesan suara, konferensi panggilan, dan sebagainya. Hal ini membantu dalam meningkatkan efisiensi komunikasi internal suatu organisasi.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4934, 32, 1, '132150404004', 'Closed Circuit Television (CCTV)', 'Closed Circuit Television (CCTV) adalah sistem pengawasan yang menggunakan kamera untuk merekam dan mengirimkan sinyal video ke monitor atau perangkat perekam tertentu. Sistem ini umumnya digunakan untuk tujuan keamanan dan pengawasan di berbagai tempat, seperti area publik, bisnis, rumah, dan lembaga.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4935, 32, 1, '132150404008', 'Fire Alarm System', 'Fire Alarm System adalah sistem yang dirancang untuk mendeteksi adanya kebakaran atau asap di suatu area dan memberikan peringatan kepada penghuni atau petugas keamanan agar mereka dapat mengambil tindakan pencegahan atau evakuasi.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4936, 9, 1, '132080117025', 'Phospor Image', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4937, 32, 1, '132150405001', 'Genset', 'perangkat yang dirancang untuk memberikan pasokan listrik yang stabil dan terputus selama gangguan pasokan listrik utama. Tujuan utamanya adalah melindungi perangkat elektronik sensitif seperti komputer, server, perangkat jaringan, sistem telekomunikasi, dan peralatan lainnya dari gangguan listrik yang bisa merusak atau mengganggu operasinya.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4938, 32, 1, '132150405002', 'Automatic Transfer Switch (ATS) dan Automatic Change Oer Swi', 'Automatic Transfer Switch (ATS) dan Automatic Change Over Switch ATS sering digunakan dalam sistem cadangan untuk memastikan bahwa pasokan listrik terus berjalan tanpa gangguan saat terjadi pemadaman listrik dari sumber daya utama. Sementara ACOS bisa digunakan dalam berbagai konteks, baik untuk tujuan cadangan maupun untuk mengalihkan daya antara sumber daya yang berbeda pada suatu sistem.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4939, 32, 1, '132150405003', 'Power Control System', 'Power Control System merujuk pada sistem yang mengatur atau mengontrol distribusi dan penggunaan daya listrik dalam suatu sistem atau lingkungan. Sistem ini mencakup perangkat keras dan perangkat lunak yang memantau, mengontrol, dan mengelola aliran daya listrik untuk memastikan distribusi yang efisien, stabil, dan aman.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4940, 32, 1, '132150405006', 'Air Conditioning (AC)', 'Pendingin udara (Air Conditioning/AC) adalah sistem yang digunakan untuk mengontrol suhu, kelembaban, dan kualitas udara di dalam ruangan. Tujuan utamanya adalah menciptakan kondisi udara yang nyaman dan sehat bagi penghuni ruangan Bandara', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4941, 32, 1, '132150405007', 'Traction Equipments (Elevator, Escalator, Conveyor, Garbarata)', 'Peralatan traksi adalah mesin utama yang diperlukan untuk menggerakkan Elevator, Escalator, Conveyor, Garbarata', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4942, 32, 1, '132150405009', 'Solar cell', 'Solar cell, atau sel surya, adalah sebuah alat elektronik semikonduktor yang mengubah energi matahari langsung menjadi energi listrik dengan menggunakan efek fotovoltaik. Ketika cahaya matahari mengenai sel surya, foton-foton dari cahaya tersebut menghasilkan aliran listrik dengan melepaskan elektron dari bahan semikonduktor dalam sel surya. Proses ini menghasilkan arus listrik yang dapat digunakan sebagai sumber energi untuk berbagai keperluan, mulai dari penggunaan rumah tangga hingga aplikasi industri yang lebih besar. Sel surya sering digunakan dalam panel surya, yang merupakan kumpulan dari beberapa sel surya yang bekerja bersama-sama untuk menghasilkan jumlah energi yang lebih besar.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4943, 32, 1, '132150406001', 'RF Field Strenght analyzer', 'RF Field Strength Analyzer (analisator kekuatan medan RF) adalah perangkat yang digunakan untuk mengukur kekuatan atau intensitas medan radio frekuensi (RF) di sekitar suatu area. Ini berguna dalam memantau dan menganalisis tingkat radiasi RF dari berbagai sumber, seperti stasiun basis nirkabel, perangkat Wi-Fi, pemancar radio, atau perangkat lain yang menghasilkan gelombang elektromagnetik.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4944, 32, 1, '132150406003', 'Portable Spektrum Analizer', 'Sebuah Portable Spectrum Analyzer adalah alat yang digunakan untuk menganalisis spektrum frekuensi dari sinyal elektromagnetik di berbagai rentang frekuensi. Perangkat ini dapat menampilkan informasi tentang bagaimana energi di dalam spektrum frekuensi dibagi dalam suatu rentang tertentu.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4945, 32, 1, '132150406005', 'Osciloscope 400 Mhz', 'Oscilloscope (atau osiloskop) adalah alat pengukur elektronik yang digunakan untuk mengamati dan menganalisis sinyal listrik dalam bentuk gelombang. Oscilloscope 400 MHz mengacu pada oscilloscope yang memiliki bandwidth atau kapasitas untuk menangkap sinyal-sinyal dengan frekuensi hingga 400 megahertz (MHz).', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4946, 9, 1, '132080118008', 'Rotary Evaporator (Alat Laboratorium Makanan)', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4947, 32, 1, '132150406009', 'Object Test Piece (OTP)', 'Object Test Piece OTP sering kali digunakan untuk memverifikasi atau mengkalibrasi perangkat tersebut. OTP dapat memiliki berbagai fitur seperti pola, struktur, bahan, atau karakteristik geometris yang didesain sedemikian rupa sehingga saat dipindai atau dideteksi oleh peralatan tersebut, hasilnya dapat digunakan untuk mengukur atau memverifikasi kinerja sistem tersebut.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4948, 32, 1, '132150406010', 'Digital Sound Level', 'Digital Sound Level merupakan alat pengukur tingkat kebisingan atau intensitas suara secara digital. Alat ini digunakan untuk mengukur level tekanan suara dalam desibel (dB) dengan menggunakan sensor mikrofon atau transduser suara untuk mendeteksi dan mengonversi tekanan gelombang suara menjadi sinyal listrik yang kemudian diukur dan ditampilkan secara digital.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4949, 32, 1, '132150406012', 'Laser Beam Temperature Meter', 'Laser Beam Temperature Meter adalah alat pengukur suhu non-kontak yang menggunakan sinar laser untuk mengukur suhu suatu objek dari jarak tertentu. Alat ini juga dikenal sebagai infrared thermometer atau pyrometer.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4950, 32, 1, '132150406014', 'Digital LUX Meter + Acc', 'Digital LUX Meter + Acc adalah sebuah alat pengukur intensitas cahaya yang menggunakan sensor cahaya untuk mengukur tingkat pencahayaan atau kecerahan dalam satuan lux secara digital. "Acc" mungkin merupakan singkatan dari "Accuracy" yang menunjukkan akurasi dari alat tersebut', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4951, 32, 1, '132150406019', 'GPS Survey', 'GPS Survey adalah proses penggunaan sistem Global Positioning System (GPS) dalam survei atau pemetaan. Teknologi GPS memanfaatkan satelit untuk menentukan posisi secara akurat di permukaan bumi.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4952, 32, 1, '132150406020', 'GPS Mapper Counter', 'GPS Mapper Counter adalah sebuah alat atau perangkat lunak yang digunakan untuk menghitung jumlah pemetaan yang dilakukan oleh sistem GPS. Alat ini dapat melacak dan mencatat informasi seperti jumlah lokasi yang dipetakan, jarak yang telah ditempuh, waktu yang dihabiskan dalam pemetaan, atau informasi lainnya terkait aktivitas pemetaan yang dilakukan dengan menggunakan GPS. Dengan GPS Mapper Counter, pengguna dapat memantau dan menganalisis data pemetaan untuk berbagai keperluan, seperti navigasi, survei, pemantauan perjalanan, dan banyak lagi.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4953, 9, 1, '132080118014', 'Cooking Range', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4954, 32, 1, '132150406021', 'Compass Magnetic', 'Kompass magnetik adalah alat navigasi sederhana yang menggunakan magnet untuk menunjukkan arah utara, selatan, barat, dan timur. Ini berdasarkan pada prinsip bahwa jarum magnet akan selalu menunjuk ke arah utara magnetik Bumi yang dikenal sebagai utara magnetik.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4955, 32, 1, '132150406024', 'Power Quality Analyzer-Plus Measurement', 'Power Quality Analyzer (PQA) adalah perangkat yang digunakan untuk memonitor dan menganalisis berbagai parameter kualitas daya listrik dalam suatu sistem tenaga listrik. Ini mencakup berbagai pengukuran seperti tegangan, arus, frekuensi, harmonisa, gelombang, dan faktor daya untuk mengevaluasi keandalan, kestabilan, dan efisiensi sistem daya.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4956, 32, 1, '132150406025', 'Teropong Observasi', 'Teropong observasi adalah alat optik yang dirancang untuk memperbesar gambar objek yang jauh, sehingga memungkinkan pengguna untuk melihat dengan lebih jelas dan detail pada jarak yang jauh. Teropong ini sering digunakan dalam berbagai konteks, mulai dari pengamatan alam, kegiatan luar ruangan, pemantauan lingkungan, hingga keperluan militer dan keamanan.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4957, 32, 1, '132150406026', 'Electronic Altimeter - Barometer', 'Altimeter elektronik digunakan untuk mengukur ketinggian relatif terhadap permukaan laut atau referensi tertentu. Mereka menggunakan teknologi seperti sensor tekanan untuk mengukur perubahan tekanan atmosfer saat ketinggian berubah. Dengan melacak perubahan tekanan, alat ini dapat memperkirakan ketinggian. Versi elektroniknya sering kali memiliki tampilan digital yang menampilkan ketinggian dalam satuan seperti meter atau kaki.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4958, 9, 1, '132080118025', 'Kompor Minyak Tanah', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4959, 9, 1, '132080118027', 'Alat Pelecet Kedelai', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4960, 9, 1, '132080118032', 'Alat Perajang Kerupuk', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4961, 9, 1, '132080118034', 'Chopper', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4962, 9, 1, '132080118038', 'Alat Pembuka Sabut Kelapa', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
