	(4995, 33, 1, '132190101001', 'Lempar Cakram', 'Cakram adalah benda logam bundar dan pipih yang biasanya terbuat dari paduan logam dan memiliki berat tertentu. Para atlet melemparkan cakram dari area lemparan yang disebut "lingkaran lempar, pada umujhmnya terbuat dari kayu atau fiberglass', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4996, 33, 1, '132190101002', 'Lempar Lembing', 'Lembing merupakan pelaratan atletik berbentuk seperti tombak dengan sudut tajam di salah satu ujungnya. Lembing terbuat dari kayu, bambu, atau alumunium', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4997, 33, 1, '132190101003', 'Tolak Peluru', 'Peluru dalam tolak peluru berupa bola bulat yang terbuat dari besi cor, kuningan dan baja tahan karat dengan permukaan halus. Peluru (bola) untuk perlombaan memiliki berat dan diameter tertentu sesuai kelas perlombaan', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4998, 10, 1, '132080121003', 'Law Volume Dust Sampler (Alat Laboratorium Hidrodinamika)', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(4999, 33, 1, '132190101004', 'Alat Lari Gawang', 'Gawang Penghalang adalah sejenis alat yang digunakan dalam perlombaan lintasan atletik. Lari gawang merupakan salah satu cabang olahraga atletik yang melibatkan lari cepat sambil melompati serangkaian rintangan atau gawang. Alat lari gawang terdiri dari gawang-gawang yang diletakkan sepanjang lintasan lari dengan jarak tertentu di antara satu gawang dan gawang berikutnya. Biasanya, gawang-gawang ini terbuat dari kayu atau logam dan diletakkan pada ketinggian tertentu sesuai dengan kategori perlombaan yang diikuti', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5000, 10, 1, '132080121004', 'Middle Volume Air Sampler (Alat Laboratorium Hidrodinamika)', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5001, 33, 1, '132190101005', 'Galah', 'galah berbentuk Tiang adalah tiang panjang dan fleksibel yang biasanya terbuat dari serat karbon/ fiberglass/ bambu/ kayu. olahraga atletik lompat tinggi dengan bantuan galah atau tongkat fleksibel untuk melompati palang horizontal setinggi 4,5 meter Tiang yang digunakan dalam lompat galah bisa memiliki panjang atau diameter berapa pun tergantung pada preferensi atlet, Lompat galah (pole vault) adalah salah satu cabang', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5002, 10, 1, '132080121005', 'Multi Shihet Filter Press', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5003, 33, 1, '132190101006', 'Martil', 'Martil adalah sebuah alat yang dipasangi kawat baja yang disambungkan ke bola logam di satu ujung dan pegangan di ujung lainnya.Bola ini berisi besi padat, kuningan atau logam yang keras dari kuningan.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5004, 10, 1, '132080121006', 'Thin Layer Chromatography (Alat Laboratorium Hidrodinamika)', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5005, 33, 1, '132190101007', 'Mistar Lompat Tinggi', 'Mistar lompat tinggi adalah tongkat panjang yang berfungsi sebagai penanda ketinggian yang harus dilewati oleh atlit, biasanya terbuat dari bahan fiberglass berwarna kuning dan merah.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5006, 33, 1, '132190101008', 'Matras Lari', 'Matras lari adalah permukaan yang digunakan dalam olahraga atletik, terutama untuk latihan atau kompetisi lari. Matras ini dirancang khusus untuk memberikan perlindungan saat atlet berlatih atau berkompetisi dalam berbagai jenis lari, seperti lari cepat, lari jarak menengah, atau lari gawang.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5007, 10, 1, '132080121008', 'Disolved Solid Mater Por (Alat Laboratorium Hidrodinamika)', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5008, 33, 1, '132190101009', 'Start Block', 'Start block atau starting block merupakan benda tetap dengan permukaan miring yang digunakan atlet lari sebagai pijakan', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5009, 10, 1, '132080121009', 'Hydrothermograph (Alat Laboratorium Hidrodinamika)', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5010, 33, 1, '132190101010', 'Meter Line', 'mesin marka dengan sistem roll yang digunakan untuk membuat garis lapangan, selain itu mesin marka ini juga dapat diaplikasikan di atas rumput, beton, aspal, keramik dan menghasilkan garis marka dengan ukuran lebar garis 5 – 10 cm yang bersifat permanen dan merekat dengan baik.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5011, 10, 1, '132080121010', 'Thermohigrograph (Alat Laboratorium Hidrodinamika)', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5012, 33, 1, '132190101011', 'Pull Master', '"Pull Master" mungkin merujuk pada beberapa hal berbeda tergantung pada konteksnya. Dalam dunia teknologi, terutama pengembangan perangkat lunak dengan menggunakan Git (sistem kontrol versi), "Pull Master" bisa merujuk pada proses menggabungkan perubahan kode dari branch "master" ke dalam branch yang sedang aktif atau dalam pengembangan. Ini biasanya dilakukan dengan perintah "git pull origin master" untuk menarik perubahan terbaru dari branch master ke branch yang sedang digunakan.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5013, 33, 1, '132190101012', 'Bak Lompat Tinggi', 'Bak lompat tinggi adalah struktur yang digunakan dalam olahraga atletik untuk disiplin lompat tinggi. Fungsi bak lompat tinggi adalah memberikan tempat bagi atlet untuk melompat dengan tujuan melewati palang lompat pada ketinggian tertentu. Bak lompat tinggi adalah elemen penting dalam lompat tinggi dan menyediakan kondisi yang memungkinkan atlet untuk bersaing dengan adil dan aman. Fungsinya tidak hanya terbatas pada memberikan tempat untuk melompat, tetapi juga dalam menyediakan standar yang konsisten untuk olahraga atletik ini.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5014, 10, 1, '132080122001', 'Carbotec Portable', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5015, 33, 1, '132190101013', 'Bak Lompat Jauh', 'Bak lompat jauh adalah struktur atau area yang digunakan dalam olahraga lompat jauh. Fungsi utamanya adalah memberikan tempat bagi atlet untuk melakukan lompatan sejauh mungkin. Fungsi utama bak lompat jauh adalah memberikan fasilitas yang aman dan terstruktur untuk atlet melakukan lompatan jauh. Selain itu, bak ini juga digunakan untuk memfasilitasi proses pengukuran panjang lompatan atlet.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5016, 10, 1, '132080122002', 'Gas Analysis Apparatus (Alat Laboratorium Klimatologi)', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5017, 33, 1, '132190102001', 'Alat Tenis Meja', 'Alat Tenis meja adalah peralatan yang digunakan dalam permainan tenis meja terdiri dari : meja tenis meja, net tenis meja, bola tenis meja, dan bet tenis meja,', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5018, 10, 1, '132080122003', 'Law Volume Dust Sampler (Alat Laboratorium Klimatologi)', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5019, 33, 1, '132190102002', 'Alat Volley', 'Alat volley merupakan peralatan yang sangat penting dalam bermain voli', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5020, 10, 1, '132080122004', 'Middle Volume Air Sampler (Alat Laboratorium Klimatologi)', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5021, 33, 1, '132190102004', 'Alat Badminton', 'Alat yang digunakan dalam permainan bulutangkis terdiri dari : net bulu tangkis, raket bulutangkis, dan Shuttlecock', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5022, 10, 1, '132080122005', 'Multi Sheet Filter Press', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5023, 33, 1, '132190102006', 'Alat Basket', 'alat basket adalah peralatan yang digunakan dalam permainan basket terdiri dari : bola basket, dan ring basket', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5024, 10, 1, '132080122006', 'Thin Layer Chromatography (Alat Laboratorium Klimatologi)', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5025, 33, 1, '132190102007', 'Keranjang Bola/Ring', 'Ring basket adalah salah satu perlengkapan dalam permainan bola basket yang berfungsi sebagai sasaran bagi pemain untuk mencetak angka saat menyerang', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5026, 33, 1, '132190102008', 'Raket Tenis', 'Raket Tenis adalah alat untuk memukul bola dalam permainan tenis', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5027, 10, 1, '132080122008', 'Disolved Solid Mater Por (Alat Laboratorium Klimatologi)', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5028, 33, 1, '132190102009', 'Net Tenis', 'Net bertujuan untuk pembatas antara area lapangan antar pemain. Net terbuat dari tali yang disusun untuk membentuk jaring', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5029, 10, 1, '132080122009', 'Hydrothermograph (Alat Laboratorium Klimatologi)', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5030, 33, 1, '132190102010', 'Root', 'Road antena adalah tongkat atau batang lentur yang dijadikan sebagai pembatas samping dari area penyebarangan bola. Ukuran road antena adalah panjang 1,80 meter dan bergaris tengah 10 milimeter.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5031, 33, 1, '132190102011', 'Alat Golf', 'Golf adalah jenis olahraga yang dimainkan di lapangan luas yang bertujuan berkompetisi memasukkan bola kecil ke dalam lubang menggunakan stik', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5032, 10, 1, '132080122011', 'Martindale Wear And Abration Tester (Alat Laboratorium Klimatolog', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5033, 33, 1, '132190102012', 'Gawang', 'gawang adalah dua tiang yang dihubungkan dengan palang. dalam sepak bola gawang adalah tempat sasaran memasukkan bola', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5034, 10, 1, '132080122012', 'Rain Gauge Transfer Calibrator', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5035, 33, 1, '132190102013', 'Backstop Net', 'Backstop net adalah jaring atau net yang biasanya digunakan di berbagai olahraga untuk menahan atau menangkap bola, terutama dalam olahraga seperti baseball, softball, atau golf.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5036, 10, 1, '132080122013', 'Pressure Chamber', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5037, 33, 1, '132190102014', 'Trampolin', 'Trampolin adalah perangkat melompat yang terbuat dari kawat baja dan kain yang tertegang, yang terpasang pada bingkai dengan menggunakan pegas. Mereka digunakan untuk melompat, berloncat, dan melakukan gerakan akrobatik atau senam udara di atas permukaan yang elastis.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5038, 10, 1, '132080122014', 'Rain Gauge Laboratorium Calibrator', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5039, 33, 1, '132190102015', 'Playground Ball Pool', 'Playground ball pool adalah area bermain di taman bermain atau ruang bermain anak-anak yang diisi dengan banyak bola plastik berwarna-warni. Area ini didesain untuk memberikan pengalaman bermain yang menyenangkan bagi anak-anak.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5040, 10, 1, '132080122015', 'Ion Chromatography', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5041, 33, 1, '132190102016', 'Ayunan (Playground)', 'Ayunan adalah sebuah kursi gantung yang sering ditemukan di taman bermain untuk anak-anak', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5042, 33, 1, '132190102018', 'Gelas Putar (Playground)', 'Gelas Putar adalah permainan yang umumnya ditemukan di taman bermain atau playground. Ini adalah permainan yang sering disukai oleh anak-anak. Gelas putar biasanya terdiri dari platform bundar yang dipasang pada poros tengahnya sehingga dapat berputar saat dinaiki.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5043, 10, 1, '132080122017', 'Humidity Meter Standard', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5044, 33, 1, '132190102019', 'Jembatan Titan (Playground)', 'Jembatan Titian adalah elemen permainan yang umumnya ditemukan di area bermain anak-anak di taman atau fasilitas rekreasi. Jembatan ini dirancang untuk memberikan anak-anak pengalaman bermain yang menyenangkan sambil mengembangkan keterampilan motorik dan keseimbangan', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5045, 33, 1, '132190102020', 'Jungkat Jungkit (Playground)', 'Jungkat-jungkit merupakan salah satu permainan yang ada di taman bermain, dimainkan oleh 2 orang atau lebih yang memerlukan kerja sama antar 2 sisi untuk dapat memainkannya', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5046, 33, 1, '132190102021', 'Kuda-kudaan (Playground)', 'Kuda-kudaan  ini merupakan mainan klasik yang akan memberikan waktu bermain imajinatif juga mengembangkan keseimbangan dasar dan keterampilan koordinasi untuk anak-anak', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5047, 10, 1, '132080123001', 'Cupola', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5048, 33, 1, '132190102022', 'Panjatan (Playground)', 'Panjat Playground outbound & panjat tebing merupakan (mainan anak-anak)', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5049, 10, 1, '132080123002', 'Shot Blast', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5050, 33, 1, '132190102023', 'Perosotan (Playground)', 'perosotan playground hiburan untuk anak-anak yang dapat digunakan di outdoor maupun indoor', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5051, 10, 1, '132080123003', 'Shake Out', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5052, 33, 1, '132190102024', 'Playhouse (Playground)', 'Playhouse merupakan miniatur rumah yang skalanya disesuaikan dengan tubuh balita', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5053, 33, 1, '132190102025', 'Swing Fiesta Combo (Playground)', '"Swing Fiesta Combo (Playground)" mungkin merujuk pada suatu produk atau layanan yang terkait dengan area bermain, seperti taman bermain atau fasilitas rekreasi. Istilah ini bisa mengacu pada kombinasi permainan ayunan dan elemen-elemen lainnya dalam suatu area bermain.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5054, 10, 1, '132080123005', 'Ladle Heating', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5055, 33, 1, '132190102026', 'Terowongan Titian (Playground)', 'Terowongan titian dalam konteks playground adalah salah satu elemen permainan yang umumnya ditemukan di taman bermain untuk anak-anak. Ini adalah struktur terowongan yang terbuat dari bahan yang aman dan tahan lama, seperti plastik keras atau logam yang dilengkapi dengan elemen pegangan atau pegangan untuk anak-anak agar dapat melintasinya', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5056, 10, 1, '132080123006', 'Induction Furnace (Alat Laboratorium Proses Peleburan)', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5057, 33, 1, '132190103001', 'Palang Sejajar', 'Palang sejajar terdiri dari dua palang horizontal yang sejajar satu sama lainnya dan tinggi yang dapat disesuaikan. Palang ini biasanya terbuat dari baja atau logam yang kokoh dan dilengkapi dengan tangan pegangan atau grip untuk atlet saat melakukan rutinitas gimnastik', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5058, 10, 1, '132080123007', 'Bale Out Furnace', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5059, 33, 1, '132190103002', 'Palang Kuda', 'Senam palang tunggal adalah salah satu cabang olahraga senam artistik yang melibatkan rutinitas yang dilakukan oleh satu atlet pada palang tunggal. Palang tunggal adalah perangkat yang terdiri dari dua palang kayu paralel yang ditempatkan sejajar dan biasanya dipasang di atas platform yang lebih tinggi.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5060, 10, 1, '132080123008', 'Tilting Furnace', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5061, 33, 1, '132190103003', 'Matras', 'Matras senam adalah permukaan yang digunakan dalam olahraga senam, Matras ini dirancang khusus untuk memberikan perlindungan saat atlet berlatih atau berkompetisi dalam berbagai jenis senam.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5062, 33, 1, '132190103004', 'Gelang-Gelang', 'Gelang-gelang merupakan alat pendukung pada senam lantai yang memiliki bentuk yang besar. Ukuran dari gelang-gelang biasa memiliki tinggi 2,8 meter hingga tiga meter dan diameternya sekitar 13 cm. Gelang-gelang ini digunakan dengan dihubungkan menggunakan tali dan atlet bisa bergelantung pada gelang-gelang tersebut', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5063, 10, 1, '132080123010', 'Ghanematic Grinding Machine', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5064, 33, 1, '132190103005', 'Peralatan Fitnes', 'Peralatan fitness dapat bervariasi tergantung pada jenis latihan yang ingin dilakukan. Beberapa peralatan umum yang sering digunakan di pusat kebugaran atau untuk latihan di rumah seperti Treadmill,Mesin Eliptis dan Pijakan Tangga,Smith Machine,Rowing Machine (Mendayung) ,Cable Machine,Squat Rack,Lat Pulldown Machine,\nPec Deck Machine.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5065, 33, 1, '132190103006', 'Kuda Pelana', 'Alat  ini memliki bentuk yang mirip seperti dudukan yang ada di punggung kuda. Biasanya alat ini akan digunakan untuk melatih lompatan pada senam lantai. Alat ini memiliki panjang 1,2 meter dengan tinggi 1,35 meter dengan fungsi yang sama seperti kuda-kuda pelana', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5066, 10, 1, '132080123012', 'Gantry Crane', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5067, 33, 1, '132190103007', 'Balance Beem', 'Balance beam adalah salah satu peralatan penting dalam senam artistik. Ini adalah palang sempit dan panjang yang terbuat dari kayu atau bahan lain yang memberikan permukaan yang kuat namun sedikit elastis.Biasanya, balance beam memiliki panjang sekitar 5 meter, lebar sekitar 10 sentimeter, dan ditinggikan sekitar 1,25 meter dari permukaan lantai. Tujuannya adalah untuk memberikan atlet senam area sempit untuk menunjukkan keterampilan keseimbangan, kekuatan, kelenturan, dan ketepatan gerakan.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5068, 10, 1, '132080123013', 'Rotary Furnace', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5069, 33, 1, '132190103008', 'Multi Station', 'Multi-Station  Ini bisa mencakup mesin latihan atau alat kebugaran yang dirancang untuk memungkinkan berbagai latihan di satu unit. Contohnya adalah multi-station gym yang memiliki stasiun untuk latihan beban, pull-up, dip, dan latihan lainnya yang dapat diakses dari satu perangkat.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5070, 10, 1, '132080123014', 'Small Grinding Machine', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5071, 33, 1, '132190103009', 'Argocycle', 'Ergocycle adalah jenis sepeda statis yang dirancang khusus untuk penggunaan dalam pengujian fisik, pemulihan cedera, atau latihan kardiovaskular di dalam lingkungan medis atau olahraga. Ergocycle sering digunakan dalam uji kebugaran untuk mengukur kapasitas kardiorespirasi seseorang atau untuk rehabilitasi fisik.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5072, 33, 1, '132190103010', 'Treadmill', 'Treadmill adalah alat fitness yang digunakan untuk berjalan, berlari, atau berjalan cepat di tempat. Alat ini terdiri dari sebuah ban berjalan yang bergerak dengan cara yang mirip dengan berjalan atau lari di jalanan atau lintasan', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5073, 10, 1, '132080123016', 'Pyrometer Digital', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5074, 33, 1, '132190103011', 'Orbitrek', 'Orbitrek adalah jenis alat fitness yang menggabungkan berbagai alat, \nbisa digunakan duduk untuk gerakan sepeda ataupun berdiri untuk gerakan lari dan steper\nalat bantu sit up push up, dilengkapi twister untuk mengecilkan perut, 4 buah dumble untuk aerobik ,pemberat untuk kayuhan berat/ringan, 2 handle tangan bergerak dan diam tempat duduk bisa diatur naik/turun, monitor latihan : pulse jantung, kalori, jarak, waktu, kecepatan tali untuk gerakan tangan, dan lainya', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5075, 10, 1, '132080123017', 'Carbon Aquipment Metic', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5076, 33, 1, '132190103013', 'Sit Up Board', 'Sit-up board adalah alat fitness yang dirancang khusus untuk melatih otot perut, khususnya saat melakukan sit-up atau crunches. Alat ini biasanya terbuat dari bahan yang kuat dan dilengkapi dengan penyangga atau penopang untuk kaki yang memungkinkan penggunanya untuk melakukan sit-up dengan stabil.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5077, 10, 1, '132080123018', 'Tentip/Tectip', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5078, 33, 1, '132190103014', 'Beck Up Board', 'Back extension adalah latihan kebugaran yang ditujukan untuk melatih otot-otot punggung bagian bawah, terutama otot-otot erector spinae yang membentang sepanjang tulang belakang.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5079, 33, 1, '132190103015', 'Damble Set', 'Set dumbbell bisa terdiri dari beberapa pasang dumbbell dengan berat yang berbeda, biasanya mulai dari berat yang lebih ringan hingga berat yang lebih berat. Ini memungkinkan seseorang untuk melakukan berbagai latihan kekuatan dengan intensitas yang bervariasi sesuai dengan kemampuan dan kebutuhan mereka', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5080, 33, 1, '132190103016', 'Barble Set', 'Barbel set adalah kumpulan beban atau bobot yang digunakan untuk latihan angkat beban. Set ini terdiri dari beberapa piring atau disk logam yang dapat dilepas dan dipasang pada batang yang biasanya terbuat dari baja atau logam', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5081, 10, 1, '132080124001', 'Lab Sifter', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5082, 33, 1, '132190103017', 'Rak Damble Set', 'rak atau tempat penyimpanan yang dirancang khusus untuk menyimpan dan mengorganisir dumbbell set', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5083, 10, 1, '132080124002', 'Jolt Aqueeze App', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5084, 33, 1, '132190103018', 'Rak Darble Set', 'Rak barbell adalah perangkat penyimpanan yang dirancang khusus untuk menyimpan dan mengorganisir barbell. Barbell adalah batang panjang yang digunakan sebagai beban dalam latihan kekuatan dan kebugaran', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5085, 10, 1, '132080124003', 'Wet Tensile Strength', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5086, 33, 1, '132190103019', 'Massage Chair', 'Meskipun massage chair (kursi pijat) tidak secara khusus digunakan sebagai peralatan senam, namun memiliki peran dalam pemulihan dan relaksasi otot setelah latihan atau olahraga. Kursi pijat dirancang untuk memberikan pijatan pada berbagai bagian tubuh, membantu meredakan ketegangan otot, meningkatkan sirkulasi darah, dan mengurangi stres.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5087, 33, 1, '132190103020', 'Massage Foot', 'alat untuk melakukan pijat pada kaki erdapat berbagai jenis alat pijat kaki elektrik dengan berbagai fitur, seperti pijatan getar, pijatan shiatsu, atau kombinasi dari keduanya. Alat ini dapat membantu mengurangi kelelahan pada kaki dan meningkatkan peredaran darah.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5088, 10, 1, '132080124005', 'Compresive Stress', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5089, 33, 1, '132190103021', 'Palang Bertingkat', 'Palang bertingkat (uneven bars) adalah salah satu peralatan dalam senam artistik khususnya untuk wanita. Ini terdiri dari dua palang yang terletak pada ketinggian yang berbeda, yang memungkinkan atlet untuk melakukan berbagai gerakan yang menampilkan keterampilan teknis, kekuatan, dan kelenturan.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5090, 10, 1, '132080124006', 'Testing App', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5091, 33, 1, '132190103022', 'Palang Tunggal', 'Palang tunggal, atau juga dikenal sebagai palang ganda (parallel bars), adalah peralatan dalam senam artistik. Ini terdiri dari dua palang paralel yang terbuat dari baja atau kayu yang ditempatkan sejajar satu sama lain, biasanya dipasang pada ketinggian tertentu.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5092, 10, 1, '132080124007', 'Universal Strenght Machine', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5093, 33, 1, '132190103023', 'Vaulting Table', 'Vaulting table adalah perangkat yang digunakan dalam olahraga senam artistik untuk melakukan latihan melompat atau "vaulting". Ini adalah meja datar yang kuat dengan permukaan yang dipesan untuk membantu atlet melakukan gerakan melompat yang kompleks dan teknis.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5094, 10, 1, '132080124008', 'Assesories Universal Strength', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5095, 33, 1, '132190103024', 'Rotator Twisting Belts', '"Rotator" mengacu pada suatu mekanisme atau alat yang berputar atau bergerak dalam pola putaran tertentu, sementara "Twisting Belts" mungkin merujuk pada sabuk atau belt yang dapat melakukan torsi atau perputaran.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5096, 10, 1, '132080124009', 'Sintering Furnace', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5097, 33, 1, '132190103025', 'Tumbling Belts', 'Tumbling belts merujuk pada sabuk atau ikat pinggang yang digunakan dalam seni bela diri, terutama dalam olahraga gulat (wrestling). Sabuk ini umumnya terbuat dari bahan yang kuat dan fleksibel, seperti nilon atau kain bertekstur yang tahan lama.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5098, 10, 1, '132080124010', 'Cheking Device', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5099, 33, 1, '132190104001', 'Ski Air', 'Ski air adalah olahraga air yang pemainnya meluncur di atas air menggunakan papan yang ditarik dengan perahu. Ski air menjadi salah satu cabang olimpiade pada tahun 1972. Ski air membutuhkan peralatan antara lain papan ski, tali penarik beserta peganggan, sarung tangan, pelampung, dan perahu penarik', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5100, 33, 1, '132190104002', 'Ski Diving', 'skydiving) adalah kegiatan olahraga di udara dilakukan dengan cara lepas landas dari pesawat kecil', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5101, 10, 1, '132080124012', 'Rammer', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5102, 33, 1, '132190104004', 'Perahu Karet (Paralatan Olah Raga Air)', 'Perahu karet, juga dikenal sebagai perahu karet atau boat karet, adalah jenis perahu yang terbuat dari bahan karet atau bahan sintetis lainnya. Mereka biasanya digunakan untuk rekreasi atau olahraga air di sungai, danau, atau laut yang tenang', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5103, 10, 1, '132080124013', 'Assesories Sand Rammer', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5104, 33, 1, '132190104007', 'Alat Dayung', 'Alat dayung merupakan peralatan yang digunakan untuk menggerakkan perahu atau kapal melalui air dengan cara mendorong air ke belakang', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5105, 10, 1, '132080124014', 'Permeability Tester', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5106, 33, 1, '132190104008', 'Kaca Mata Air', 'Kacamata olahraga air merupakan perlengkapan penting saat beraktivitas di perairan kacamata olahraga air dapat bervariasi tergantung pada kegiatan yang dilakukan. Misalnya, untuk renang, snorkeling, selancar, atau olahraga air lainnya, terdapat jenis kacamata yang dirancang secara khusus untuk keperluan tersebut. Memilih kacamata yang sesuai dengan kebutuhan dan nyaman dipakai akan mendukung pengalaman berolahraga air yang lebih menyenangkan dan aman', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5107, 10, 1, '132080124015', 'Infra Red Rapid Dryer', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5108, 33, 1, '132190104010', 'Alat Ukur Kedalaman', 'merupakan alat pengukur yang digunakan untuk mengukur kedalaman suatu objek dengan akurasi tinggi. Alat ini umumnya terdiri dari dua bagian utama, yaitu batang pengukur dan indikator kedalaman. Batang pengukur biasanya terbuat dari logam atau bahan lain yang kuat dan tahan lama', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5109, 10, 1, '132080124016', 'Stereoscopic Microopic', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5110, 33, 1, '132190104013', 'Kompas Selam', 'Kompas selam adalah alat penting yang digunakan oleh penyelam untuk membantu navigasi di bawah air. Ini adalah versi khusus dari kompas yang dirancang untuk digunakan di lingkungan air', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5111, 10, 1, '132080124017', 'Mould Hardness Tester', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5112, 33, 1, '132190104015', 'Perayu Kayak 1', 'Kayak adalah sebuah perahu kecil bertenaga manusia, biasanya dengan bagian depan dan belakang tertutup, sehingga hanya menyisakan lubang seukuran awak. Desain yang tertutup ini bertujuan untuk mencegah masuknya air ke dalam perahu. Kayak dilengkapi dengan dayung berkepala tunggal atau ganda', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5113, 10, 1, '132080124018', 'Labo Firniture', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5114, 33, 1, '132190104017', 'Perahu Cano Canadian 1', 'Kano atau wangkang adalah sebuah perahu kecil dan sempit, yang biasanya digerakkan dengan tenaga manusia, namun ada juga yang menggunakan layar. Bentuk kano umumnya lancip pada kedua ujungnya dan terbuka di bagian atasnya, tetapi bagian ini dapat diberi tutup.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5115, 10, 1, '132080124019', 'Mettler Balance', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5116, 33, 1, '132190104019', 'Perahu Tradisional/Perahu Naga', 'perahu yang sangat panjang dan sempit yang digerakkan oleh tenaga manusia dan digunakan pada olahraga dayung perlombaan perahu naga', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5117, 10, 1, '132080124020', 'Flow Ability Test', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5118, 33, 1, '132190104022', 'Papan Jumping + Tali + Helm', 'ketiga peralatan ini biasanya digunakan pada olahraga wakeboarding atau ski air. Jumping board atau papan jumping adalah papan khusus yang digunakan untuk wakeboarding biasanya memiliki permukaan yang lebih besar dan boot yang dipasang di atasnya untuk mengikat kaki pengendara. Tali biasanya terhubung dengan perahu atau kabel tali tetap. Pengendara memegang tali ini untuk menarik diri mereka di atas permukaan air. Helm dirancang khusus untuk melindungi kepala pengendara dari benturan saat melakukan aktivitas air seperti wakeboarding.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5119, 33, 1, '132190104025', 'Jamping Track', 'Ini adalah perangkat yang digunakan di kolam renang atau di perairan untuk meluncur atau melompat ke dalam air. Biasanya digunakan dalam olahraga seperti loncat indah atau dalam atraksi di taman air.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5120, 10, 1, '132080124022', 'Sand Sample & Sand Container', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5121, 33, 1, '132190104026', 'Motor penarik/Speed Boat', 'Speedboat merupakan jenis perahu motor yang dirancang untuk kecepatan tinggi di atas permukaan air', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5122, 10, 1, '132080124023', 'Continous Clay Washer', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5123, 33, 1, '132190104027', 'Pelampung Lintasan', 'pelampung lintasan merupakan Pembatas Kolam Renang  Di arena perlombaan renang', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5124, 10, 1, '132080124024', 'Foundry Sand Pycnometer', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5125, 33, 1, '132190104029', 'Enterprise', 'Tali lintasan itu lah yang digunakan oleh para atlet para-renang sebagai panduan mereka untuk tetap berenang lurus di lintasan.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5126, 10, 1, '132080124025', 'Turbo Mixer', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5127, 33, 1, '132190104031', 'Kelas 470', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5128, 10, 1, '132080124026', 'Ditato Meter', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5129, 33, 1, '132190104033', 'Selancar Angin', 'Selancar angin, atau yang juga dikenal sebagai windsurfing, merupakan olahraga air yang menggabungkan elemen dari surfing dan berlayar. Pada dasarnya, windsurfing melibatkan penggunaan papan yang dilengkapi dengan layar dan dipropulsikan oleh angin.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5130, 10, 1, '132080124027', 'Green Tensile Strength', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5131, 33, 1, '132190105004', 'Alat Terbang Layang', 'Alat terbang layang, atau yang lebih dikenal sebagai glider atau pesawat tanpa mesin, adalah pesawat yang terbang tanpa bantuan mesin pembakaran dalam. Mereka mengandalkan gaya angkat yang dihasilkan oleh udara yang bergerak melalui sayap pesawat', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5132, 10, 1, '132080124028', 'Core Hardness Tester', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5133, 33, 1, '132190106001', 'Catur', 'Papan catur adalah jenis papan permainan yang digunakan dalam permainan catur, dan terdiri atas 64 kotak persegi yang disusun dalam 2 warna berselang-seling berwarna hitam dan putih', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5134, 33, 1, '132190106002', 'Sarung Tinju', 'Sarung tinju adalah sarung tangan kulit dilapisi busa atau kapas yang dipakai dalam olahraga tinju, berfungsi untuk mengurangi lesi di tangan selama pertandingan tinju.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5135, 10, 1, '132080125002', 'Moulding Machine', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5136, 33, 1, '132190106003', 'Sepeda Olah Raga', 'Sepeda khusus yang dirancang untuk kecepatan dan efesiensi pada saat digunakan', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5137, 10, 1, '132080125003', 'Ribon Flow Mixer', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5138, 33, 1, '132190106004', 'Alat Samapta', 'samapta adalah suatu keadaan siap siaga yang dimiliki oleh seseorang baik secara fisik, mental, maupun sosial dalam menghadapi situasi kerja yang beragam. sehingga peralatan olahraganya bisa bermacam-macam', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5139, 10, 1, '132080125004', 'Mixer Zarnic', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5140, 33, 1, '132190106005', 'Samsak', 'Samsak adalah salah satu peralatan yang digunakan dalam latihan seni bela diri, terutama dalam pukulan dan tendangan. Ini adalah tas yang terbuat dari bahan yang kokoh dan diisi dengan bahan yang dapat menyerap kekuatan pukulan atau tendangan.', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5141, 10, 1, '132080125005', 'Core Making Machine', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5142, 33, 1, '132190106006', 'Body Protector (Beladiri)', 'Pelindung tubuh (body protector) dalam beladiri adalah peralatan perlindungan yang dipakai oleh praktisi beladiri untuk mengurangi risiko cedera saat latihan atau bertanding. Pelindung ini dirancang untuk melindungi bagian tubuh tertentu dari benturan atau serangan yang mungkin terjadi selama sesi latihan atau pertandingan', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5143, 10, 1, '132080125006', 'Core Work Banch', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5144, 6, 1, '132070124005', 'Patient Monitor', 'perangkat medis yang digunakan untuk memantau parameter kesehatan dan fungsi tubuh pasien secara terus-menerus, dirancang untuk memberikan informasi real-time kepada tim medis tentang kondisi pasien selama perawatan di rumah sakit, klinik, atau bahkan di lingkungan perawatan di rumah', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5145, 10, 1, '132080125007', 'Sand Drying', NULL, NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5146, 22, 1, '132080702056', 'Air Purifier', 'Pembersih udara untuk laboratorium adalah perangkat yang dirancang khusus untuk menghilangkan kontaminan udara yang bisa memengaruhi kebersihan lingkungan laboratorium', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
	(5147, 6, 1, '132070124006', 'Medical Pendant', 'Medical pendant, atau juga dikenal sebagai bed pendant atau hospital pendant, adalah perangkat yang digunakan di lingkungan rumah sakit atau fasilitas perawatan medis lainnya. Ini adalah sistem suspensi yang biasanya dipasang di langit-langit atau dinding dan digunakan untuk menyalurkan berbagai layanan dan peralatan medis yang dibutuhkan selama perawatan pasien', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
