	(5149, 9, 1, '132080111209', 'Vaccine Refrigerator', 'Vaccine Refrigerator atau lemari pendingin vaksin adalah perangkat khusus yang dirancang untuk menyimpan vaksin dalam kondisi suhu yang stabil dan terkendali', NULL, NULL, '2026-04-30 03:15:55', '2026-04-30 03:15:55'),
