	(6602, 31, 1, '132150302026', 'Rigging Plate', 'alat yang berfungsi sebagai pengorganisasian stasiun kerja dan pengaturan sistem multi-jangkar tali', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6603, 2, 1, '132050207019', 'Digital Eletromagnetic Flowpress Meter (Portable)', 'alat yang berfungsi sebagai alat pengukur aliran listrik', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6604, 2, 1, '132050207020', 'Drat Adaptor', 'alat yang berfungsi sebagai drat penyambung', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6605, 2, 1, '132050207021', 'Ifex / Impulse Gun', 'alat yang berfungsi sebagai senapan pemadam kebakaran untuk membantu pemadam api', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6606, 2, 1, '132050201066', 'Meja Lipat', 'meja yang dirancang untuk mudah dilipat dan disimpan ketika tidak digunakan, menjadikannya solusi praktis untuk ruang terbatas atau kebutuhan temporer', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6607, 1, 1, '132050105094', 'Scanner buku', 'perangkat yang dirancang khusus untuk memindai buku dengan cara yang lebih efisien daripada scanner dokumen biasa', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6608, 2, 1, '132050206084', 'Glue Gun', 'alat yang digunakan untuk menyambung atau merekatkan berbagai bahan dengan menggunakan lem panas. Lem yang digunakan dalam glue gun berbentuk stik yang dipanaskan hingga mencair di dalam alat tersebut. Ketika lem cair tersebut diaplikasikan ke permukaan yang ingin direkatkan, ia akan mengeras dan membentuk ikatan yang kuat saat suhu turun.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6609, 2, 1, '132050203010', 'Kontainer Bak Sampah', 'wadah besar yang digunakan untuk mengumpulkan dan menyimpan sampah atau limbah sebelum diangkut ke tempat pembuangan akhir atau fasilitas pengolahan. Kontainer ini dirancang untuk menangani volume sampah yang besar dan biasanya digunakan di lingkungan komersial, industri, dan area publik. Berikut adalah beberapa fitur dan jenis kontainer bak sampah:', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6610, 1, 1, '132050105095', 'Keranjang Penyimpanan', 'tempat untuk menyimpan, mengangkut, atau menampung berbagai barang.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6611, 2, 1, '132050201067', 'Meja Payung', 'meja yang dirancang dengan payung terintegrasi atau yang memiliki tempat khusus untuk memasang payung, biasanya digunakan di luar ruangan seperti di teras, taman, atau area kolam renang.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6612, 1, 1, '132050105096', 'Mesin EDC', 'perangkat yang digunakan untuk memproses transaksi pembayaran menggunakan kartu kredit atau kartu debit. Mesin ini sering ditemukan di toko-toko, restoran, dan berbagai tempat usaha lainnya sebagai alat untuk menerima pembayaran dari pelanggan.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6613, 1, 1, '132050105021', 'Perforator Besar', 'Alat kantor yang digunakan untuk membuat lubang pada kertas dalam jumlah banyak atau pada kertas yang tebal. Alat ini sering digunakan untuk:', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6614, 1, 1, '132050105097', 'Barcode Scanner', 'perangkat yang digunakan untuk membaca dan menginterpretasikan kode batang (barcode) yang tertera pada produk atau item.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6615, 2, 1, '132050201068', 'Kursi keramas', 'jenis kursi khusus yang dirancang untuk digunakan di salon atau tempat perawatan rambut saat melakukan proses keramas. Kursi ini dirancang untuk memberikan kenyamanan dan kemudahan baik bagi pelanggan maupun stylist.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6616, 28, 1, '132100205002', 'Game Console', 'perangkat elektronik yang dirancang khusus untuk memainkan video game. Berbeda dengan komputer pribadi atau perangkat mobile, game console biasanya terhubung langsung ke televisi atau monitor, dan menggunakan kontroler khusus untuk bermain game.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6617, 6, 1, '132070121052', 'True CPR', 'sebuah alat atau sistem yang dirancang untuk meningkatkan efektivitas resusitasi jantung paru (CPR)', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6618, 2, 1, '132050206085', 'Sealer Cup', 'mesin press gelas plastik adalah alat yang digunakan untuk menutup permukaan atas gelas plastik dengan segel plastik.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6619, 4, 1, '132070101175', 'Printer USG', 'perangkat khusus yang digunakan untuk mencetak gambar hasil pemeriksaan ultrasonografi (USG). Printer ini memiliki kemampuan untuk mencetak gambar dengan kualitas tinggi dan detail yang jelas, sehingga dapat membantu dokter dalam mendiagnosis dan memantau kondisi pasien.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6620, 9, 1, '132080111212', 'Precision Air Conditioning', 'dirancang untuk memberikan kontrol suhu yang sangat akurat dan stabil. Ini sering digunakan di lingkungan yang membutuhkan kondisi suhu yang sangat presisi, seperti pusat data, laboratorium, atau ruang server.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6621, 4, 1, '132070101176', 'Bed Head Panel Unit', 'komponen penting dalam desain interior ruang tidur, terutama di lingkungan perawatan kesehatan seperti rumah sakit atau panti jompo. Panel ini sering dipasang di dinding di belakang tempat tidur dan berfungsi untuk mengintegrasikan berbagai fasilitas dan peralatan yang diperlukan di area tersebut.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6622, 2, 1, '132050206086', 'Lampu Perangkap Serangga (Insect Killer Lamp)', 'perangkat yang dirancang untuk menarik dan membunuh serangga seperti nyamuk, lalat, dan kutu dengan menggunakan cahaya.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6623, 2, 1, '132050207024', 'Digital Eletromagnetic Flowpress Meter (Portable)', 'alat yang berfungsi sebagai alat pengukur aliran listrik', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6624, 4, 1, '132070101177', 'Tulup', 'alat yang digunakan untuk membius hewan dengan cara ditiupkan', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6625, 2, 1, '132050201069', 'Lemari Peta Horizontal', 'Lemari gambar horizontal adalah jenis lemari penyimpanan khusus yang dirancang untuk menyimpan gambar atau dokumen berukuran besar secara datar atau horizontal. Laci-laci pada lemari ini jauh lebih pipih dan rata dibandingkan dengan lemari arsip biasa, sehingga gambar atau dokumen tidak akan terlipat atau rusak akibat tekanan.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6626, 4, 1, '132070101178', 'Bubble CPAP', 'Continuous Positive Airway Pressure. Ini adalah alat medis yang dirancang khusus untuk membantu bayi baru lahir, terutama bayi prematur, yang mengalami kesulitan bernapas. Alat ini bekerja dengan memberikan aliran udara yang stabil dan bertekanan positif melalui hidung bayi, sehingga membantu menjaga jalan napas tetap terbuka dan memudahkan bayi bernapas.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6627, 4, 1, '132070101179', 'Sistem kultur otomatis (automated culture system)', 'alat medis canggih yang digunakan untuk mendeteksi keberadaan bakteri atau jamur dalam darah pasien secara cepat dan akurat. Alat ini sangat penting dalam diagnosis infeksi dalam darah, yang seringkali menjadi penyebab penyakit serius seperti sepsis.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6628, 2, 1, '132050206087', 'Trolley Barang Lipat', 'perangkat transportasi yang dirancang untuk memudahkan pengangkutan barang dan beban berat, dan dapat dilipat untuk memudahkan penyimpanan saat tidak digunakan. Troli ini sangat berguna dalam berbagai situasi, baik di lingkungan industri, ritel, maupun penggunaan sehari-hari.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6629, 9, 1, '132080111213', 'Vortex Mixer', 'alat laboratorium yang digunakan untuk mencampurkan larutan atau sampel secara cepat dan efisien. Alat ini bekerja dengan prinsip getaran atau vibrasi yang tinggi, sehingga menciptakan pusaran (vortex) di dalam tabung reaksi atau wadah sampel lainnya.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6630, 2, 1, '132050201070', 'Meja Kaca', 'Meja kaca adalah jenis meja yang menggunakan kaca sebagai permukaan utama. Meja ini sering dipilih karena desainnya yang modern dan estetis, serta memberikan kesan ruang yang lebih luas dan terang.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6631, 2, 1, '132050206091', 'Catokan Rambut', 'Catokan rambut, atau sering disebut sebagai alat pelurus rambut, adalah perangkat yang digunakan untuk meluruskan atau mengubah tekstur rambut. Alat ini biasanya memiliki dua pelat yang dipanaskan dan digunakan untuk menjepit rambut agar menjadi lebih lurus dan halus.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6632, 2, 1, '132050205027', 'Electric Chocolate Melter', 'Electric chocolate melter adalah alat listrik yang dirancang khusus untuk melelehkan coklat dengan mudah dan cepat. Alat ini biasanya dilengkapi dengan pengatur suhu, sehingga coklat dapat meleleh secara merata tanpa risiko terbakar.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6633, 4, 1, '132070101180', 'Tempat Tidur Bayi (Baby Bassinet)', 'tempat tidur bayi yang dirancang khusus untuk bayi baru lahir hingga usia beberapa bulan. Biasanya berukuran lebih kecil dan lebih rendah dibandingkan tempat tidur bayi biasa, sehingga lebih aman dan nyaman bagi bayi yang baru belajar mengontrol gerakannya.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6634, 2, 1, '132050206093', 'Plafon Gantung', 'Plafon gantung, atau yang sering disebut sebagai ceiling hanging, adalah elemen desain interior yang berfungsi untuk menambah estetika', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6635, 4, 1, '132070101181', 'Mesin Penyegel Kantong Darah (Blood bag tube sealer)', 'Alat ini merupakan perangkat medis khusus yang digunakan untuk menyegel tabung pada kantong darah setelah proses pengambilan atau pemindahan darah selesai dilakukan.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6636, 1, 1, '132050105098', 'Gerbang Turnstile', 'Gerbang yang dirancang untuk mengontrol lalu lintas orang dengan cara hanya mengizinkan satu orang melewati pada satu waktu', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6637, 2, 1, '132050206092', 'Steamer Rambut', 'Steamer rambut adalah alat kecantikan yang digunakan untuk menguapkan air dan menghasilkan uap panas yang lembut. Uap ini kemudian diarahkan ke rambut dan kulit kepala untuk memberikan berbagai manfaat bagi kesehatan dan penampilan rambut.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6638, 6, 1, '132070121050', 'Head Immobilizer', 'Alat yang berfungsi sebagai peralatan rescue pada emergency. Head immobilizer ini digunakan bersama dengan tandu stretcher pada bagian head untuk menopang kepala korban. Dengan head immobilizer, kepala korban akan stabil (terkunci dari gerakan ke samping maupun ke depan).', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6639, 6, 1, '132070121051', 'Splint Kit (Bidai Patah Tulang)', 'alat yang berfungsi sebagai alat bantu ortopedi yang diperuntukkan kepada pasien yang sedang mengalami gangguan pada tulang tangan, bahu, atau pun pergelangan kaki. Memiliki belat tungkai serbaguna yang dapat digunakan di sisi kiri atau kanan', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6640, 31, 1, '132150302019', 'Distress Signal Unit', 'alat yang berfungsi sebagai perangkat keselamatan pribadi yang digunakan terutama oleh petugas pemadam kebakaran yang memasuki lingkungan yang berbahaya atau Berbahaya bagi Kehidupan dan Kesehatan seperti gedung yang terbakar', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6641, 31, 1, '132150302020', 'Pice Hoist System', 'alat yang berfungsi sebagai alat pengungkit pertolongan misalkan pada lubah yang tidak dapat dijangkau manusia', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6642, 31, 1, '132150302021', 'Sambungan Selang Pemadam', 'alat yang berfungsi sebagai pipa cabang yang digunakan sebagai penyambung hydrant', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6643, 31, 1, '132150302022', 'Rescue Lifting Bag', 'alat yang berfungsi sebagai Alat Pengangkat reruntuhan', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6644, 31, 1, '132150302023', 'Penyangga Bangunan Runtuh', 'alat yang berfungsi sebagai alat pertolongan untuk menyangga reruntuhan bangunan', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6645, 31, 1, '132150302024', 'Operated Cutter Set', 'alat yang berfungsi sebagai alat pemotong Rintangan', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6646, 2, 1, '132050207018', 'Alat Pemadam Kebakaran (APAR)', 'alat yang berfungsi sebagai alat pemadam api bertekanan tinggi digunakan bahan padat non-logam', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6647, 2, 1, '132050207022', 'Oscillating Ground Monitor', 'alat yang berfungsi sebagai alat monitor terhadap area berbahaya', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6648, 2, 1, '132050207023', 'Foam Inductor', 'alat yang berfungsi sebagai perangkat pencampur busa yaitu untuk mencampur air dan konsentrat busa', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6649, 2, 1, '132050206088', 'Vynil Lantai', 'Vinyl lantai adalah lapisan lantai yang terbuat dari polivinil klorida (PVC). Bahan ini digunakan sebagai pelapisan lantai sehingga memiliki tampilan yang elegan dan menarik.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6650, 2, 1, '132050206089', 'Parket Lantai', 'Parket lantai yang terbuat dari potongan-potongan kayu solid atau kayu olahan yang disusun dan direkatkan menjadi satu kesatuan. Potongan-potongan kayu ini merupakan lapisan lantai untuk menciptakan tampilan lantai yang elegan dan klasik.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6651, 2, 1, '132050206090', 'Panel Dinding (Wall Panel)', 'Panel dinding (wall panel) adalah elemen desain interior yang digunakan untuk menutupi dan menghias permukaan dinding. Mereka tersedia dalam berbagai material, seperti kayu, PVC, dan metal, serta dalam berbagai gaya dan warna.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6652, 2, 1, '132050206094', 'Kandang Hewan', 'Kandang yang terbuat dari bahan logam, biasanya besi atau baja ringan, yang digunakan untuk memelihara berbagai jenis hewan.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6653, 4, 1, '132070101182', 'Meja Makan Pasien  (Overbed Table)', 'sebuah meja yang dirancang khusus untuk digunakan oleh pasien yang sedang dirawat di tempat tidur', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6654, 7, 1, '132070205026', 'Boneka Simulasi Pertolongan Pertama', 'alat bantu belajar yang dirancang menyerupai tubuh manusia. Boneka ini digunakan untuk melatih keterampilan pertolongan pertama secara praktis. Dengan menggunakan boneka simulasi, seseorang dapat berlatih memberikan pertolongan pertama pada berbagai kondisi darurat', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6655, 1, 1, '132050102013', 'Mesin Penyusun Kertas (Mesin Collator)', 'sebuah perangkat yang digunakan dalam industri percetakan dan perkantoran untuk mengurutkan, menyusun, atau mengelompokkan kertas dalam urutan tertentu.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6656, 2, 1, '132050206095', 'Tanaman Artifisial', 'tanaman yang dibuat dengan bahan sintetis seperti plastik, kain, atau silikon untuk meniru penampilan tanaman hidup. Tanaman ini dirancang agar menyerupai tanaman asli, namun tidak memerlukan perawatan seperti penyiraman, pemupukan, atau pencahayaan tertentu, sehingga menjadi pilihan yang praktis dan mudah dipelihara.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6657, 4, 1, '132070101183', 'Intra Aortic Balloon Pump', 'alat medis yang digunakan untuk memberikan dukungan sementara pada jantung yang mengalami kesulitan memompa darah. Alat ini berfungsi dengan cara membantu jantung memompa darah lebih efisien, sehingga dapat meningkatkan aliran darah ke seluruh tubuh, terutama ke jantung itu sendiri.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6658, 4, 1, '132070101184', 'Dispenser Obat (pharmaceutical dispencer)', 'alat khusus yang dirancang untuk mengukur dan memberikan dosis obat secara akurat dan aman.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6659, 7, 1, '132070205027', 'Urinal Carriages (Rak Pispot)', 'sebuah perangkat medis yang digunakan untuk menampung urin pasien yang tidak dapat berjalan ke kamar mandi atau menggunakan toilet secara mandiri. Alat ini sangat berguna untuk pasien yang sedang sakit, lansia, atau memiliki keterbatasan mobilitas.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6660, 2, 1, '132050206096', 'Pengering Rambut (Hair Dryer)', 'alat elektronik yang digunakan untuk mengeringkan rambut dengan cepat. Alat ini bekerja dengan cara mengubah energi listrik menjadi energi panas yang kemudian dialirkan melalui udara untuk menguapkan air pada rambut.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6661, 7, 1, '132070205028', 'Steamer Wajah (Facial Steamer)', 'alat kecantikan yang digunakan untuk menguapkan air menjadi uap panas, lalu diarahkan ke wajah. Uap air panas ini memiliki berbagai manfaat bagi kulit wajah, sehingga sering digunakan sebagai bagian dari rutinitas perawatan kulit.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6662, 2, 1, '132050204016', 'AC Cassette', 'Jenis pendingin ruangan yang unik karena unit indoor-nya terpasang di dalam plafon ruangan.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6663, 2, 1, '132050204017', 'Tirai udara (Air Curtain)', 'sebuah perangkat yang menciptakan penghalang udara berupa tirai tak kasat mata di antara dua ruangan atau area yang berbeda suhu atau kondisi udaranya.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6664, 1, 1, '132050103017', 'Mesin Printer Wide Format (Digital Printing)', 'Jenis printer yang dirancang khusus untuk mencetak pada media dengan lebar yang jauh lebih besar dibandingkan printer konvensional. Printer ini mampu menghasilkan cetakan berkualitas tinggi dengan ukuran yang sangat bervariasi, mulai dari poster, banner, hingga gambar cetak berukuran besar.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6665, 1, 1, '132050105099', 'Meja Tripod Projector', 'alat penunjang yang digunakan untuk menempatkan proyektor pada ketinggian yang diinginkan dan posisi yang stabil. Alat ini terdiri dari tiga kaki yang dapat diatur panjangnya (tripod) dan sebuah platform di bagian atas untuk meletakkan proyektor.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6666, 1, 1, '132050105100', 'Alat Penempel Label (Labeller Machine Coding)', 'lat yang digunakan untuk mempermudah proses penempelan label pada produk atau kemasan. Alat ini sering digunakan dalam industri manufaktur, pengemasan, atau logistik untuk meningkatkan efisiensi dan kecepatan dalam menempelkan label dengan rapi dan akurat.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6667, 2, 1, '132050201071', 'Kursi Santai (Chaise longue )', 'Jenis furnitur yang didesain khusus untuk memberikan kenyamanan maksimal saat bersantai. Kursi ini biasanya memiliki bagian sandaran kaki yang dapat dipanjangkan atau dinaikkan, sehingga Anda bisa meregangkan kaki dengan nyaman.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6668, 1, 1, '132050105101', 'Alat Peniup Udara (Blower)', 'alat atau mesin yang digunakan untuk mengalirkan udara atau gas dalam volume besar dengan tekanan yang relatif rendah. Blower sering digunakan untuk tujuan pembersihan, ventilasi, atau untuk menghasilkan aliran udara yang kuat.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6669, 17, 1, '132080310019', 'Alat Peraga Praktek Kesenian', 'alat atau media yang digunakan untuk mendukung proses pembelajaran dan praktik seni, baik itu seni rupa, seni musik, seni tari, seni teater, atau seni lainnya. Alat peraga ini membantu siswa atau peserta untuk lebih memahami teknik, konsep, dan keterampilan yang diperlukan dalam berkesenian.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6670, 1, 1, '132050105102', 'Lantai panggung (Raised Floor)', 'lantai yang terdiri dari panel atau ubin yang dipasang di atas struktur penopang vertikal, membentuk ruang kosong di bawahnya. Sistem ini umumnya digunakan di gedung komersial, pusat data, ruang server, atau fasilitas lain yang membutuhkan akses fleksibel untuk sistem kelistrikan, kabel jaringan, serta distribusi udara HVAC (pemanasan, ventilasi, dan pendinginan).', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6671, 4, 1, '132070101185', 'Konektor Oksigen', 'Alat yang berfungsi untuk menghubungkan berbagai komponen dalam sistem tersebut, seperti tabung oksigen, regulator, dan selang oksigen. Konektor oksigen memastikan aliran oksigen yang lancar dan aman ke pasien.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6672, 4, 1, '132070102136', 'Apex Locator', 'Apex locator adalah perangkat medis yang digunakan untuk membantu dalam menentukan posisi atau letak apeks akar gigi (titik ujung akar gigi) saat prosedur perawatan saluran akar (root canal treatment). Perangkat ini sangat penting dalam endodontik, terutama untuk memastikan bahwa instrumen yang digunakan dalam perawatan saluran akar tidak melukai jaringan sekitar dan mencapai ujung akar gigi dengan tepat.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6673, 2, 1, '132050201072', 'Meja Formulir', 'sebuah perabot kantor yang dirancang khusus untuk menyimpan dan mengorganisir berbagai jenis formulir. Meja ini biasanya memiliki beberapa rak, laci, atau kompartemen yang dapat disesuaikan untuk menampung berbagai ukuran dan jenis formulir.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6674, 1, 1, '132050105103', 'Tenda Lipat', 'Tenda festival adalah jenis tenda yang digunakan untuk acara di luar ruangan. Tenda ini dirancang untuk memberikan perlindungan dari cuaca (terutama matahari atau hujan) selama berlangsungnya acara. Tenda festival sering dipasang di area terbuka seperti lapangan, taman, atau bahkan di kawasan perkotaan.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6675, 28, 1, '132100205003', 'E-Book Reader', 'perangkat elektronik khusus yang dirancang untuk membaca buku digital atau e-book. Perangkat ini memiliki layar khusus yang menyerupai kertas, sehingga mata tidak cepat lelah saat membaca dalam waktu yang lama. E-book reader ini biasanya memiliki bentuk yang tipis dan ringan, sehingga mudah dibawa ke mana saja.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6676, 1, 1, '132050105104', 'Sistem Voting Elektronik', 'sebuah sistem pemungutan suara yang menggunakan teknologi elektronik untuk menggantikan metode tradisional yang menggunakan kertas suara. Dalam sistem ini, pemilih memberikan suara mereka melalui perangkat elektronik seperti komputer, tablet, atau mesin voting khusus.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6677, 17, 1, '132080310021', 'Gawangan Batik', 'alat yang sangat penting dalam proses pembuatan batik. Fungsinya adalah untuk menggantung kain batik yang sedang dikerjakan, baik saat proses pewarnaan maupun saat proses penjemuran', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6678, 17, 1, '132080310020', 'Alat Tenun', 'perangkat atau mesin yang digunakan untuk mengubah benang menjadi kain', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6679, 4, 1, '132070104190', 'Koagulator Dingin Serviks (Cervical Cold Coagulator )', 'alat medis yang digunakan dalam prosedur ginekologi untuk mengobati berbagai kondisi pada serviks (leher rahim). Alat ini bekerja dengan cara membekukan jaringan yang abnormal pada serviks sehingga jaringan tersebut mati dan kemudian akan luruh dengan sendirinya.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6680, 16, 1, '132080301017', 'Alat Peraga Praktek Sekolah Bidang Studi : Bahasa Asing', 'Alat peraga praktek dalam bidang studi Bahasa Asing dapat membantu siswa memahami konsep-konsep bahasa, meningkatkan keterampilan membaca, menulis, mendengar, dan berbicara.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6681, 5, 1, '132070118038', 'Tabir X Ray', 'Tabir X-ray adalah perlengkapan penting dalam dunia radiologi yang berfungsi sebagai penghalang atau perisai untuk melindungi petugas medis, pasien, dan orang-orang di sekitar ruangan radiologi dari paparan radiasi sinar-X', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6682, 2, 1, '132050201073', 'Kabinet Tahan Api (Flameable Cabinet)', 'jenis penyimpanan khusus yang dirancang untuk melindungi dokumen penting, data elektronik, atau benda berharga lainnya dari kerusakan akibat panas yang ekstrem, seperti kebakaran', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6683, 2, 1, '132050206097', 'Setrika Uap Press', 'mesin yang dirancang khusus untuk melicinkan dan merapikan berbagai jenis pakaian dan tekstil dalam jumlah besar dan waktu yang relatif singkat.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6684, 4, 1, '132070107098', 'Allergan HandPiece Phaco', 'Sebuah alat bedah khusus yang digunakan dalam prosedur operasi mata, terutama untuk operasi katarak. Handpiece ini merupakan bagian integral dari sistem phacoemulsifikasi, sebuah teknologi yang digunakan untuk memecah dan mengisap lensa mata yang keruh (katarak) sehingga dapat diganti dengan lensa buatan.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6685, 9, 1, '132080113123', 'Turbovap', 'alat laboratorium yang dirancang khusus untuk proses penguapan pelarut dari sampel secara cepat dan efisien', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6686, 13, 1, '132080155040', 'Mesin Analisa Urine (Urine Analizyer)', 'alat medis yang digunakan untuk menganalisis sampel urine. Alat ini bekerja dengan membaca dan menginterpretasikan perubahan warna pada strip tes urine yang telah dicelupkan ke dalam sampel urine', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6687, 17, 1, '132080311004', 'Alat Peraga Praktek Sekolah Bidang Studi : Olahraga', 'Alat untuk praktek di sekolah dalam bidang studi Ilmu Olahraga yang berfungsi untuk membantu siswa melakukan praktek kegiatan olahraga', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6688, 4, 1, '132070102137', 'Pena Obturasi (Obturation Pen)', 'Alat dokter gigi yang disebut "obturation pen" atau "pena obturasi" digunakan untuk memadatkan (mengisi) bahan obturasi, seperti gutta percha, ke dalam saluran akar gigi yang telah dibersihkan dan dibentuk.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6689, 33, 1, '132190106007', 'Air Walker', 'Alat olahraga yang dirancang untuk meniru gerakan berjalan atau berlari, namun dengan beban yang lebih ringan pada persendian. Alat ini umumnya terdiri dari dua pedal yang bergerak naik turun secara bergantian, mirip seperti tangga berjalan mini.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6690, 2, 1, '132050205028', 'Mesin Pengering Piring (Electric Dish Dryer)', 'Alat elektronik rumah tangga yang digunakan untuk mengeringkan piring, gelas, dan peralatan makan lainnya dengan cepat dan efisien.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6691, 17, 1, '132080313009', 'Buku Digital Bicara (Digital Talking Books)', 'Buku elektronik khusus yang dirancang untuk memudahkan orang-orang tunanetra atau memiliki kesulitan membaca untuk mengakses informasi. Buku ini berisi teks yang telah direkam dalam bentuk suara, sehingga dapat didengarkan melalui perangkat pemutar khusus.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6692, 2, 1, '132050204018', 'Chiller Meja', 'Permukaan kerja berpendingin yang umum ditemukan di dapur komersial seperti restoran, bakery, dan tempat katering. Fungsinya utama adalah menjaga suhu makanan tetap dingin, sehingga mencegah pertumbuhan bakteri dan menjaga kesegaran bahan makanan.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6693, 2, 1, '132050204019', 'Kotak Pendingin (Cooler Box)', 'Wadah terisolasi yang dirancang untuk menjaga suhu makanan dan minuman tetap dingin selama jangka waktu tertentu. Kotak ini sangat berguna untuk berbagai aktivitas, mulai dari piknik, berkemah, hingga perjalanan jauh', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6694, 1, 1, '132050105105', 'Anjungan Percetakan Elektronik', 'Mesin atau perangkat yang memungkinkan pengguna mencetak dokumen atau kartu secara mandiri. Alat ini biasanya dilengkapi dengan layar sentuh, printer, dan berbagai fitur lain yang memudahkan pengguna dalam mengoperasikannya.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6695, 4, 1, '132070107099', 'Phoroptor Digital (Digital Phoropter)', 'Alat untuk mengukur ametropias, phorias dan amplitudo akomodasi mata, yang terdiri dari berbagai lensa coba yang berbeda digunakan untuk menilai refraksi mata selama pengujian penglihatan, sehingga diketahui kesalahan bias pasien dan menentukan resep kacamata secara otomatis', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6696, 7, 1, '132070205029', 'Keranda', 'sebuah wadah yang digunakan untuk membawa jenazah menuju tempat peristirahatan terakhir. Keranda biasanya terbuat dari kayu, logam, atau bahan komposit lainnya, dan dirancang untuk memberikan penghormatan terakhir kepada orang yang telah meninggal.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6697, 17, 1, '132080313010', 'Tongkat Mobilitas (White Cane)', 'Alat bantu mobilitas yang memungkinkan orang tuna netra atau yang memiliki gangguan penglihatan untuk melakukan aktivitas sehari-hari saat bepergian, terutama di tempat yang tidak dikenal', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6698, 17, 1, '132080313011', 'Video Magnifier', 'Perangkat pembesar video yang menggunakan kamera, monitor, dan lampu untuk memperbesar gambar. Alat ini dirancang untuk membantu orang dengan gangguan penglihatan untuk mempermudah aktivitas sehari-hari seperti membaca atau bekerja', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6699, 28, 1, '132100203020', 'Printer Braille', 'Perangkat yang mencetak teks dalam format Braille, yaitu sistem tulisan taktil yang menggunakan titik-titik timbul untuk membaca. Perangkat ini memungkinkan penyandang tunanetra dan mereka yang memiliki gangguan penglihatan untuk membaca dan menulis, serta mengakses informasi yang dicetak dalam format ini.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6700, 17, 1, '132080313012', 'Alat Peraga Luar Biasa (Tuna Netra, Terapi Fisik, Tuna Daksa, Tuna Rungu)', 'Alat atau media yang digunakan untuk mendukung aktifitas bagi tuna netra, tuna daksa, tuna rungu, ataupun terapi fisik', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6701, 17, 1, '132080310022', 'Tongkat Mayoret', 'Tongkat yang digunakan oleh seorang mayoret dalam pertunjukan drumb band atau marching band. Tongkat ini digunakan untuk melakukan gerakan tarian dan atraksi, serta untuk memandu formasi anggota drumb band.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6702, 4, 1, '132070101186', 'Lemari Pengering CSSD', 'Peralatan yang digunakan dalam Central Sterile Supply Department (CSSD) untuk mengeringkan dan menyimpan peralatan medis dan bedah setelah proses sterilisasi. Lemari pengering menggunakan udara hangat yang terkontrol dan filter HEPA untuk memastikan pengeringan yang efisien dan penyimpanan yang aseptik, mengurangi risiko kontaminasi ulang.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6703, 34, 1, '132130202005', 'Shaver Handpiece', 'Alat yang digunakan untuk memotong dan membuang jaringan seperti tulang rawan, sinovium, dan jaringan lunak lainnya dalam sendi selama operasi artroskopi', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6704, 6, 1, '132070123022', 'Irrigation Console', 'Mesin yang diindikasikan untuk mengebor atau memotong tulang atau gigi dan memasang sekrup dan/atau pin dan kabel ke dalam tulang, dalam hubungannya dengan prosedur bedah rekonstruksi gigi, kraniofasial, ortognatik, mandibula, tangan, kaki, pergelangan tangan, dan ekstremitas', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6705, 22, 1, '132080704014', 'Analisa Kualitas Sanitasi Lingkungan (Sanitarian Kit)', 'proses pemeriksaan cepat (rapid test) terhadap parameter sanitasi di lingkungan menggunakan peralatan portabel yang tergabung dalam satu paket bernama Sanitarian Kit. Tujuan utamanya adalah untuk menilai kondisi sanitasi secara langsung di lapangan, terutama terkait air, makanan, udara, dan kebersihan fasilitas umum.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6706, 5, 1, '132070116019', 'Meja Kerja Khusus Histopatologi (Ergonomic Histopathology Workstation)', 'workstation histopatologi ergonomis yang dirancang khusus untuk proses persiapan, pemotongan, dan pengukuran sampel.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6707, 4, 1, '132070108158', 'Lithotriptor', 'Alat penghancur batu ginjal atau saluran kemih, bekerja dengan gelombang kejut, laser, udara, atau ultrasonik tergantung jenisnya.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6708, 2, 1, '132050206098', 'Troli Barang', 'Alat bantu beroda yang digunakan untuk mengangkut barang dari satu tempat ke tempat lain, sehingga memudahkan pekerjaan dan mengurangi beban angkut secara manual.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6709, 4, 1, '132070104191', 'Pompa Irigasi Medis (Irrigation Console)', 'Alat ini digunakan dalam prosedur bedah, khususnya untuk irigasi dan pembersihan area operasi', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6710, 5, 1, '132070114045', 'EnSite X EP System', 'Alat untuk menavigasi anatomi jantung secara tiga dimensi (3D) secara real-time, EnSite X EP System memberikan hasil yang lebih cepat dan akurat dalam prosedur ablasi jantung yang kritis. Alat ini digunakan dalam prosedur kateter ablasi jantung untuk diagnosis dan terapi gangguan irama jantung', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6711, 4, 1, '132070101187', 'Alat Pengukur C02 (Smokerlyzer)', 'Alat ukur kandungan karbon monoksida (CO) dalam hembusan napas seseorang.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6712, 5, 1, '132070114046', 'Portable Hemodynamic Monitor', 'Alat medis portabel yang digunakan untuk memantau fungsi jantung dan kondisi peredaran darah (hemodinamik) pasien secara real-time tanpa perlu selalu terhubung dengan mesin besar di ICU atau ruang operasi.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6713, 27, 1, '132100101009', 'Kios Interaktif (Interactive Kiosk)', 'Perangkat elektronik dengan layar sentuh yang menyediakan akses informasi atau layanan secara mandiri kepada pengguna melalui perangkat keras dan perangkat lunak khusus. Pengguna dapat berinteraksi langsung dengan kios untuk mendapatkan berbagai informasi atau melakukan transaksi, seperti membayar tagihan, membeli tiket, atau mengakses informasi produk', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6714, 1, 1, '132050105106', 'Pintu Otomatis Berbasis RFID (RFID Gate System)', 'Berfungsi untuk mendeteksi, mengontrol, dan mencatat pergerakan orang atau barang yang melewati gate.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6715, 2, 1, '132050201074', 'Kursi Barbershop', 'Kursi khusus yang digunakan di tempat cukur rambut atau barbershop, dirancang agar nyaman, fleksibel, dan ergonomis untuk pelanggan sekaligus memudahkan barber dalam bekerja.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6716, 2, 1, '132050206099', 'Mesin Penipis Adonan (Dough sheeter)', 'Mesin bakery yang digunakan untuk meratakan dan menipiskan adonan dengan ketebalan yang seragam.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6717, 2, 1, '132050206100', 'Mesin Pengembang Adonan (Dough proofer)', 'Peralatan bakery yang digunakan untuk mempercepat dan mengoptimalkan proses pengembangan adonan roti sebelum dipanggang.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6718, 4, 1, '132070101188', 'Alat Pemindah Pasien', 'Peralatan medis yang dirancang untuk membantu proses memindahkan pasien dari satu tempat ke tempat lain dengan aman, nyaman, dan efisien, baik bagi pasien maupun petugas kesehatan.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6719, 1, 1, '132050104029', 'Tas Koper', 'wadah atau kotak yang biasanya terbuat dari bahan keras atau semi-keras seperti plastik, logam, atau bahan sintetis yang kuat. Koper digunakan untuk menyimpan dan membawa barang-barang pribadi', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6720, 1, 1, '132050105088', 'Kompresor Udara Pernafasan (compressor breathing apparatus)', 'Alat yang digunakan untuk melakukan pengisian ulang terhadap tabung oksigen', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6721, 1, 1, '132050105089', 'Scan RFID', 'teknologi yang digunakan untuk secara otomatis mengidentifikasi dan melacak objek menggunakan gelombang radio', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6722, 1, 1, '132050105090', 'Blower Vacuum', 'alat yang dirancang untuk mengembuskan udara dan menyedot debu atau daun kering. Biasanya digunakan di luar ruangan, alat ini dapat berfungsi sebagai blower untuk meniupkan daun dan kotoran dari halaman atau jalan, serta sebagai vacuum untuk mengumpulkan kotoran yang telah ditiup.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6723, 1, 1, '132050105091', 'Pusat Pengaturan Listrik (Control Panel)', 'perangkat yang digunakan untuk mengelola, memonitor, dan mengendalikan berbagai sistem atau proses dalam berbagai aplikasi, baik di industri, gedung, maupun sistem rumah tangga', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6724, 1, 1, '132050105092', 'Blanket Warmer', 'Perangkat yang dirancang untuk menghangatkan selimut atau perlengkapan lain sebelum digunakan, memberikan kenyamanan tambahan di lingkungan yang dingin.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6725, 1, 1, '132050105093', 'Scan Iris mata (iris scanner)', 'Perangkat yang digunakan untuk mengidentifikasi atau memverifikasi identitas seseorang dengan menganalisis pola unik pada iris mata mereka. Iris adalah bagian berwarna dari mata di sekitar pupil, dan pola pada iris bersifat unik untuk setiap individu, mirip dengan sidik jari.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6726, 2, 1, '132050201050', 'Meja Bersekat', 'Meja bersekat adalah jenis meja yang dirancang dengan partisi atau sekat di antara ruang kerjanya.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6727, 2, 1, '132050201051', 'Kursi Bermeja', 'Jenis kursi yang dirancang khusus dengan tambahan meja kecil diiatasnya', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6728, 2, 1, '132050201052', 'Kursi Auditorium', 'jenis kursi yang dirancang khusus untuk digunakan di tempat-tempat seperti auditorium, teater, atau ruang konferensi.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6729, 2, 1, '132050201053', 'Kursi Susun (stacking chair)', 'jenis kursi yang dirancang untuk dapat ditumpuk satu di atas yang lain, sehingga memudahkan penyimpanan dan pengaturan ruang. Kursi ini sangat berguna dalam berbagai konteks di mana fleksibilitas dan efisiensi ruang sangat dibutuhkan.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6730, 2, 1, '132050201054', 'Lemari Kabinet (dry Camera)', 'lat penyimpanan khusus yang dirancang untuk melindungi barang-barang sensitif dari kerusakan akibat kelembapan atau kelembaban udara.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6731, 2, 1, '132050201055', 'Meja Kayu', 'jenis meja yang terbuat dari bahan utama kayu, yang digunakan dalam berbagai aplikasi rumah tangga, kantor, dan komersial. Meja ini dapat memiliki berbagai desain, ukuran, dan fungsi tergantung pada kebutuhan dan preferensi pengguna.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6732, 2, 1, '132050205029', 'Tempat Cuci Piring (Kitchen Sink)', 'Untuk mencuci peralatan makan, memasak, dan bahan makanan dengan air bersih.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6733, 2, 1, '132050206083', '3D Signage', 'jenis papan atau tanda yang memiliki elemen tiga dimensi, yang memberi efek visual tambahan dibandingkan dengan tanda dua dimensi. Berbeda dengan tanda datar yang hanya terlihat dari satu sisi, signage 3D memiliki kedalaman dan tekstur yang membuatnya tampak lebih menonjol dan menarik.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6734, 2, 1, '132050206101', 'Koper Makeup (Beauty Case)', 'Kotak penyimpanan yang dirancang khusus untuk membawa perlengkepan makeup/ merias wajah', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6735, 4, 1, '132070101170', 'ALAT CEK VENA / VEIN VIEWER / Portable Vein Finder', 'alat untuk melihat posisi vena dengan memanfaatkan prinsip penyerapan cahaya inframerah oleh darah sehingga darah (pembuluh darah) terlihat jelas dan diproyeksikan secara real time pada kulit', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6736, 4, 1, '132070101171', 'Thermometer Infrared Tubuh', 'perangkat medis yang digunakan untuk mengukur suhu tubuh seseorang tanpa perlu kontak langsung dengan kulit', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6737, 4, 1, '132070101172', 'Kasur Pasien (Hospital Bed)', 'peralatan rumah sakit yang dapat digunakan untuk menyediakan tempat bagi pasien untuk tidur atau beristirahat.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6738, 4, 1, '132070101173', 'Blood Roller Mixer', 'Blood Roller Mixer adalah alat yang digunakan dalam laboratorium untuk mencampur dan menggulingkan sampel darah atau bahan cair lainnya. Alat ini penting untuk memastikan homogenisasi sampel secara efektif dan konsisten. Biasanya digunakan dalam penelitian medis, diagnostik klinis, dan aplikasi laboratorium lainnya.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6739, 4, 1, '132070101174', 'High Flow Nasal Cannula', 'perangkat medis yang menyediakan aliran udara berkecepatan tinggi dengan konsentrasi oksigen yang tinggi melalui selang nasal (cannula) ke pasien yang mengalami kesulitan bernapas.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6740, 4, 1, '132070104192', 'Syringe Pump Docking Station', 'Perangkat tambahan (accessory/stand) khusus untuk pompa infus tipe syringe pump yang berfungsi sebagai tempat pemasangan / penyangga beberapa unit syringe pump sekaligus agar terorganisir, stabil, dan lebih mudah dioperasikan.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6741, 5, 1, '132070115038', 'Printer Film Radiografi', 'perangkat yang digunakan untuk mencetak gambar radiografi dari film atau sistem digital ke media film fisik.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6742, 5, 1, '132070118039', 'SpaceStation MRI', 'SpaceStation MRI adalah alat medis berupa stasiun docking (tempat dudukan dan penghubung) untuk pompa infus yang dirancang khusus agar aman digunakan di ruang MRI (Magnetic Resonance Imaging).', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6743, 6, 1, '132070123024', 'Probe Extracorporeal Shock Wave', 'alat medis yang digunakan dalam terapi gelombang kejut ekstrakorporeal (Extracorporeal Shock Wave Therapy / ESWT), yaitu teknologi non-invasif yang dipakai untuk mengobati nyeri, mempercepat penyembuhan jaringan, atau memecah struktur padat seperti batu ginjal menggunakan gelombang tekanan tinggi yang dihasilkan di luar tubuh dan diarahkan ke target melalui probe', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6744, 7, 1, '132070205030', 'Meja Memandikan Jenazah (Mortuary Washing Table)', 'Tempat khusus untuk membersihkan dan memandikan jenazah sebelum proses pemulasaran atau pemakaman.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6745, 7, 1, '132070205031', 'Meja Status Pasien (Meja Flowsheet)', 'Meja tempat pencatatan data pasien atau kegiatan medis', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6746, 7, 1, '132070205032', 'Kursi Perawatan Kaki (Podiatry Chair)', 'Kursi khusus yang digunakan untuk tindakan pemeriksaan atau perawatan area kaki.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6747, 8, 1, '132080109009', 'Media Tanam Hidroponik', 'Media tanam hidroponik adalah bahan yang digunakan sebagai pengganti tanah dalam sistem pertanian hidroponik. Hidroponik adalah metode menanam tanaman dengan menggunakan larutan nutrisi dalam air, tanpa memerlukan tanah.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6748, 9, 1, '132080111210', 'TLD Mata Dosimeter Radiasi Mata', 'alat yang digunakan untuk mengukur dosis radiasi yang diterima oleh area sekitar mata, khususnya dalam lingkungan kerja yang berpotensi terpapar radiasi.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6749, 9, 1, '132080111211', 'ultraviolet box heliox', 'alat yang menggunakan teknologi sinar ultraviolet untuk sterilisasi atau disinfeksi berbagai objek atau ruang. Teknologi UV, khususnya UV-C, efektif membunuh atau menonaktifkan mikroorganisme seperti bakteri, virus, dan jamur', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6750, 9, 1, '132080113124', 'Thermo Scientific Luminoskan Ascent Microplate Luminometer', 'alat laboratorium yang digunakan untuk mengukur cahaya (luminesensi) yang dihasilkan oleh reaksi kimia atau biologis dalam microplate (pelat mikrotiter).', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6751, 9, 1, '132080114043', 'Meja Pathology (Pathology Table)', 'Meja potong jaringan yg sudah di fiksasi dari formalin', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6752, 9, 1, '132080119064', 'Automatic Medicine Packaging And Dispensing System', 'alat yang dirancang untuk otomatisasi proses pengemasan dan pendispensan obat. Sistem ini memiliki berbagai aplikasi dan manfaat dalam lingkungan medis, farmasi, dan rumah sakit.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6753, 12, 1, '132080146029', 'Bor Biopori', 'Bor biopori adalah alat yang digunakan untuk membuat lubang-lubang kecil di tanah dengan tujuan meningkatkan penyerapan air dan pengelolaan air hujan melalui teknik biopori.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6754, 13, 1, '132080156127', 'FTIR Oil Analyzer (Fourier Transform Infrared)', 'alat khusus untuk mengukur kandungan minyak & lemak dalam air.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6755, 16, 1, '132080304066', 'Alat Peraga Praktek Sekolah Bidang Studi : IPA', 'Alat peraga untuk praktek di sekolah dalam bidang studi Ilmu Pengetahuan Alam (IPA) ialah alat bantu untuk membantu siswa memahami konsep-konsep ilmiah dengan cara yang lebih interaktif dan praktis.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6756, 17, 1, '132080314005', 'Alat Peraga Otomotif', 'Alat peraga otomotif merupakan media yang dapat digunakan untuk mengongkritkan pemahaman yang masih abstrak terkait kendaraan bermotor.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6757, 31, 1, '132150301022', 'CPR Manikin Kit', 'alat latihan yang digunakan untuk melatih teknik resusitasi jantung paru (CPR). Kit ini biasanya mencakup manikin (boneka) yang dirancang khusus untuk mensimulasikan tubuh manusia dan memungkinkan peserta latihan untuk berlatih kompresi dada dan pernapasan buatan dengan benar', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6758, 31, 1, '132150302027', 'Senter Pencarian (searchlight)', 'senter yang dirancang untuk tahan lama, efisien, dan memiliki fitur seperti tahan air, tahan goncangan, serta berbagai mode pencahayaan. senter ini sering digunakan untuk keperluan outdoor, kegiatan camping, hiking, serta dalam situasi darurat atau pencarian.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6759, 31, 1, '132150302028', 'Alat Uji Sifat Bakar (Non Combustibility Apparatus)', 'Peralatan ini menentukan kinerja tidak mudah terbakar dibawah kondisi tertentu, homogen produk dan substansial komponen tidak homogen produk bangunan. Tes ini adalah bagian dari persyaratan tersebut produk konstruksi eropa klasifikasi regulasi reaksi untuk menembakan kinerja untuk pelapis dinding dan produk atap dan penutup lantai. Klasifikasi lengkap dan kriteria kinerja dapat ditemukan dalam dokumen terpisah "Reaksi Menembakan Instrumen untuk Pengujian menurut Api Eropa Baru Pengujian dan Klasifikasi untuk Produk Konstruksi"', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6760, 33, 1, '132190102027', 'Tiang Net', 'Tiang net adalah salah satu alat penting dalam berbagai olahraga yang melibatkan permainan dengan jaring atau net.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
	(6761, 33, 1, '132190106008', 'Ring Tinju', 'Arena berbentuk persegi yang digunakan sebagai tempat pertandingan olahraga tinju.', NULL, NULL, '2026-04-30 03:15:57', '2026-04-30 03:15:57'),
